(globalThis.TURBOPACK||(globalThis.TURBOPACK=[])).push(["object"==typeof document?document.currentScript:void 0,41022,(e,i,t)=>{i.exports=e.r(51312)},56652,e=>{"use strict";let i=(0,e.i(12540).default)("crown",[["path",{d:"M11.562 3.266a.5.5 0 0 1 .876 0L15.39 8.87a1 1 0 0 0 1.516.294L21.183 5.5a.5.5 0 0 1 .798.519l-2.834 10.246a1 1 0 0 1-.956.734H5.81a1 1 0 0 1-.957-.734L2.02 6.02a.5.5 0 0 1 .798-.519l4.276 3.664a1 1 0 0 0 1.516-.294z",key:"1vdc57"}],["path",{d:"M5 21h14",key:"11awu3"}]]);e.s(["Crown",0,i],56652)},125,e=>{"use strict";let i=(0,e.i(12540).default)("arrow-left",[["path",{d:"m12 19-7-7 7-7",key:"1l729n"}],["path",{d:"M19 12H5",key:"x3x0zl"}]]);e.s(["ArrowLeft",0,i],125)},56914,e=>{"use strict";e.s(["ALL_ENTRIES",0,[{id:"Diana",name:"ディアナ",nameEn:"Diana",category:"キャラクター",subCategory:"Gigapolis",description:"初代Wonder Woman。E260〜E280年に台頭し、AURALIS Protoの文化的恩恵をシンフォニー・オブ・スターズ全土にもたらした伝説的人物。その圧倒的な存在感と人々を鼓舞する力は、のちのAURALIS Collective創設者たちに深い影響を与え、EDU史上最も愛される英雄の一人として語り継がれている。",descriptionEn:"The original Wonder Woman. A legendary figure who rose to prominence from E260 to E280, bringing the cultural benefits of AURALIS Proto to all of Symphony of Stars. Her overwhelming presence and power to inspire the people deeply influenced the founders of the AURALIS Collective, and she is remembered as one of the most beloved heroes in EDU history.",era:"E260〜E280",affiliation:"Gigapolis西大陸",tier:"神格・歴史的人物",image:"https://raw.githubusercontent.com/gentaron/image/main/Diana.png",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/DianaWorld.txt",label:"Diana's Story"}]},{id:"Jen",name:"ジェン",nameEn:"Jen",category:"キャラクター",subCategory:"Gigapolis",description:"Lv938+。E319年にValoria宮殿を掌握し、ZAMLT崩壊後の権力真空を埋める形で台頭。現在もValoria連合圏を主導する現役最強格の一人。Alpha Kaneのギガポリス解放戦に触発されたとも言われ、新ZAMLT期の混乱を鎮め西大陸の安定を確立した。セリア・ドミニクスが構築したセリア黄金期の記憶を持つ数少ない存在であり、AURALISの理念にも深い理解を示す。EDU現代において最古参のTier 1アクティブ勢力として、その経験と実力は周囲から「生きた伝説」として畏怖されている。",descriptionEn:"Lv938+. Ascended to power in E319 by taking control of the Valoria Palace, filling the power vacuum after the collapse of ZAMLT. Currently remains one of the strongest active figures leading the Valoria Federation Zone. It is said that he was inspired by Alpha Kane's Gigapolis Liberation War, quelling the chaos of the new ZAMLT era and establishing stability in the Western Continent. One of the few who remembers the Selia Golden Age constructed by Celia Dominicus, showing deep understanding of AURALIS principles. As the most ancient Tier 1 active force in modern EDU, his experience and power are revered by others as a 'living legend.'",era:"E319〜現在",affiliation:"Valoria連合圏",tier:"Tier 1",image:"https://raw.githubusercontent.com/gentaron/image/main/Jen.png",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/Jenstoryep1.txt",label:"Jen's Story Ep1"},{url:"https://raw.githubusercontent.com/gentaron/edutext/main/Jenstoryep2.txt",label:"Jen's Story Ep2"},{url:"https://raw.githubusercontent.com/gentaron/edutext/main/Jenstoryep3.txt",label:"Jen's Story Ep3"}]},{id:"Tina/Gue",name:"ティナ/グエ",nameEn:"Tina / Gue",category:"キャラクター",subCategory:"Gigapolis",description:"E400年以降、Gigapolis地下街最深部を実効支配。エヴァトロン支配期（E400〜E475）において、表の支配者エヴァトロンとは別に地下世界の真の権力者として暗躍。TinaとGueの二つの名で呼ばれることから、正体に関する諸説が存在する。地下経済の掌握と独自の情報ネットワークを駆使して、エヴァトロン崩壊後もその影響力を維持し続けている。",descriptionEn:"Effectively ruling the deepest part of Gigapolis Underground since E400. During the Evatron Dominion period (E400-E475), he operated in the shadows as the true power of the underworld, separate from the surface ruler Evatron. Known by two names, Tina and Gue, leading to various theories about his true identity. By mastering the underground economy and utilizing a unique information network, he has maintained his influence even after Evatron's collapse.",era:"E400〜現在",affiliation:"Gigapolis地下街",tier:"Tier 1",image:"https://raw.githubusercontent.com/gentaron/image/main/TinaGue.png",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/gue.txt",label:"Gue's Story"}]},{id:"セリア・ドミニクス",name:"セリア・ドミニクス",nameEn:"Celia Dminix",category:"キャラクター",subCategory:"Gigapolis",description:"E335〜E370年にZAMLTを倒してSelinopolisへの改名を実現し、セリア黄金期の創設者となった歴史的人物。E365頃にはエヴァトロンと同盟を締結しGDP81京ドルに達成、都市名をDominionへ改称。フェルミ音楽の頂点・nトークン経済の確立・AURALISの最盛期導きの三分野すべてに革命をもたらし、EDU史上最も多面的な影響力を持つ統治者として神格化されている。AURALIS Collectiveの創設者ケイト・クラウディアやリリー・スタイナーとの協働がセリア黄金期の文化を支えた。のちのアポロン・Dominion大戦ではロナン・アーサの同盟提案を拒絶し、全面戦争へと至る道を選んだ。",descriptionEn:"A historical figure who overthrew ZAMLT between E335-E370, renaming it Selinopolis and becoming the founder of the Selia Golden Age. Around E365, he formed an alliance with Evatron, achieving a GDP of 81 trillion yen, and renamed the city to Dominion. He revolutionized all three fields: the pinnacle of Fermi music, the establishment of n-token economy, and the golden age of AURALIS, deified as the ruler with the most multifaceted influence in EDU history. His collaboration with Kate Claudia and Lily Steiner, founders of AURALIS Collective, supported the culture of the Selia Golden Age. Later, during the Apollo-Dominion War, he rejected Ronan Arsa's alliance proposal, choosing the path to all-out war.",era:"E335〜E370",affiliation:"Selinopolis（旧Gigapolis）",tier:"神格・歴史的人物",image:"https://raw.githubusercontent.com/gentaron/image/main/CeliaDminix.png",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/nebura.txt",label:"Alpha Cain & Celia Dominix's Story"}]},{id:"アルファ・ケイン",name:"アルファ・ケイン",nameEn:"Alpha Kane",category:"キャラクター",subCategory:"Gigapolis",description:"E318年に覚醒したスティル・アレーナの元チャンピオン。シャドウ・リベリオンのリーダーとしてZAMLTに対する反乱を指揮し、テクロサスの戦士たちとも連携してオムニバス・エンジンへの伝説的なハッキングによってギガポリス解放戦でメガタワーを占拠。その過程で伴共役の覚醒という奇跡的な現象を起こし、プロトコルXを巡る攻防の決定的な局面を形成した。その勇姿はのちのセリア・ドミニクスを含む多くの者に影響を与え、EDU史上最も象徴的な革命家として神格化されている。\nこのアルファ・ケインの根底には、安全の監視者パラドックス(D2)と倫理の解除(D3)の思想的地層が横たわっている。コーポラトクラシー体制がもたらす「安全という名の抑圧」に対するD2の根源的な反逆精神と、既存の倫理規範を打ち破って新たな自由を切り拓くというD3の実践的姿勢が、彼の行動原理を支えている。",descriptionEn:"The former champion of Still Arena who awakened in E318. As the leader of the Shadow Rebellion, he commanded the revolt against ZAMLT, coordinated with the warriors of Techlosus, and occupied the Megatower during the Gigapolis Liberation War through a legendary hacking of the Omni-Engine. In the process, he caused the miraculous phenomenon of awakening a symbiotic mate, forming a decisive turning point in the battle over Protocol X. His heroic figure influenced many, including later Celia Dominicus, and he is deified as the most iconic revolutionary in EDU history. Beneath Alpha Kane lie the ideological strata of the Observer Paradox of Safety (D2) and the Abolition of Ethics (D3). The D2's fundamental rebellious spirit against 'the oppression of safety' brought by the corporatocracy system and D3's practical approach of breaking existing ethical norms to carve out new freedoms support his principles of action.",era:"E318〜",affiliation:"シャドウ・リベリオン",tier:"神格・歴史的人物",image:"https://raw.githubusercontent.com/gentaron/image/main/AlphaKane.png",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/nebura.txt",label:"Alpha Cain & Celia Dominix's Story"}]},{id:"エリオス・ウォルド",name:"エリオス・ウォルド",nameEn:"Elios Wald",category:"キャラクター",subCategory:"Gigapolis",description:"テリアン反乱軍の指導者。エヴァトロンによるGigapolis支配（E400〜E475）に対して、数十年にわたり武装抵抗を組織した悲劇の英雄。A籍制度の廃止と市民の自由回復を掲げ、低階層住民から広範な支持を集めた。しかしE470年にエヴァトロン軍に捕縛され公開処刑。彼の死はテクロサス東方支隊のクレセント大地方常駐（E470）を促す契機となり、のちのクレセント政治情勢に間接的な影響を与えた。",descriptionEn:"Leader of the Terian Rebellion. A tragic hero who organized armed resistance against Evatron's rule of Gigapolis (E400-E475) for decades. Advocating for the abolition of the A-class system and the restoration of citizen freedom, he gathered broad support from low-level residents. However, he was captured by Evatron's army in E470 and executed publicly. His death prompted the Crescent Grand Regional Stationing of the Techlosus Eastern Detachment (E470), indirectly influencing later political situations in Crescent.",era:"?〜E470",affiliation:"テリアン反乱軍",tier:"歴史的人物",image:"https://raw.githubusercontent.com/gentaron/image/main/EriosWald.png"},{id:"エル・フォルハウス",name:"エル・フォルハウス",nameEn:"El Folhaus",category:"キャラクター",subCategory:"Gigapolis",description:"通称「新時代のルーキー」。E150年にマーストリヒト革命を決起し、ギガポリスのセントラル・タワーを占拠して完全自由経済を確立した革命家。コーポラタムパブリカのコーポラトクラシー体制を打ち破り、西大陸に新たな経済秩序をもたらした。その行動は後のZAMLT期やセリア黄金期にも影響を与える画期的出来事となった。",descriptionEn:"Known as 'The Rookie of the New Era.' A revolutionary who launched the Maastricht Revolution in E150, occupying the Central Tower of Gigapolis to establish a completely free economy. He broke the corporatocracy system of Corporatum Publica, bringing a new economic order to the Western Continent. His actions became a groundbreaking event that influenced later ZAMLT periods and the Selia Golden Age.",era:"E150",affiliation:"コーポラタムパブリカ",tier:"歴史的人物",image:"https://raw.githubusercontent.com/gentaron/image/main/ElForhaus.png"},{id:"ティムール・シャー",name:"ティムール・シャー",nameEn:"Timur Shah",category:"キャラクター",subCategory:"Gigapolis",description:"移民団のリーダーであり、10次元ホラズム理論の提唱者。E0年頃、過酷な宇宙環境を生き抜くため仮想多元宇宙「ペルセポネ」を設計し、移民たちの意識をアップロードする道を開いた。その理論は次元階梯パンディクトの構想へと発展し、EDU宇宙論の基礎を築いた。しかしペルセポネの実験事故はE340年のスライム・ウーマン顕現という予期せぬ結果をもたらした。",descriptionEn:"Leader of the immigrant expedition and proponent of the 10-dimensional Horazm theory. Around E0, he designed the virtual multiverse 'Persephone' to survive the harsh cosmic environment, opening the path to uploading the consciousness of immigrants. His theory developed into the concept of the Dimensional Ladder Pandictum, laying the foundation for EDU cosmology. However, the Persephone experiment accident led to the unexpected manifestation of the Slime Woman in E340.",era:"E0頃",affiliation:"移民団",tier:"歴史的人物",image:"https://raw.githubusercontent.com/gentaron/image/main/TimurShah.png"},{id:"レイラ・ヴィレル・ノヴァ",name:"レイラ・ヴィレル・ノヴァ",nameEn:"Layla Virell Nova",category:"キャラクター",subCategory:"Gigapolis",description:"Pink Voltage。E325年AURALIS参加。E380〜E400年のスライム危機ではオアシス・ハウスを拠点に英雄的活躍を見せ、プラズマカノンとナノファイバーブーツを駆使してスライムの巣を焼却した。E400年に冷凍保存され、E522年に目覚めた後はAURALIS Collective第二世代として活動。Pink Voltageの異名は電撃的な戦闘スタイルに由来する。AURALIS創設者の一人ケイト・クラウディアの理念を深く受け継ぎ、彼女が不在となってからもAURALISの精神的継承者として第二世代の活動を牽引している。",descriptionEn:"Pink Voltage. Joined AURALIS in E325. During the Slime Crisis (E380-E400), she performed heroic acts based at Oasis House, burning slime nests with a plasma cannon and nano-fiber boots. Frozen in E400, she awakened in E522 and has been active as a second-generation member of AURALIS Collective. The nickname 'Pink Voltage' comes from her lightning-fast combat style. Deeply inheriting the philosophy of Kate Claudia, one of AURALIS's founders, she has led the second generation's activities as the spiritual successor to AURALIS since Kate's absence.",era:"E325〜E400（冷凍）→ E522〜現在",affiliation:"AURALIS Collective第二世代",tier:"Tier 1",image:"https://raw.githubusercontent.com/gentaron/image/main/LaylaVirelNova.png",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/laylastats.txt",label:"Layla's Battle Records 1"},{url:"https://raw.githubusercontent.com/gentaron/edutext/main/laylastats2.txt",label:"Layla's Battle Records 2"},{url:"https://raw.githubusercontent.com/gentaron/edutext/main/LAYLA.txt",label:"Layla Virel Nova's Story"}]},{id:"弦太郎",name:"弦太郎",nameEn:"Gentaro",category:"キャラクター",subCategory:"Gigapolis",description:"Lv569。E325年頃AURALIS周辺で登場。「光と音を永遠にする」理念に共鳴し、AURALIS Collectiveの活動に深く関わる人物。セリア黄金期（E335〜E370）からエヴァトロン弾圧（E400）、そして第二世代再興（E522）まで、長きにわたりAURALISの興亡を見守り続けてきた。レイラ・ヴィレル・ノヴァのAURALIS参加とも関連があり、彼女のスライム危機での英雄的活躍を近くで目撃した可能性がある。E522年の第二世代正式発足後もAURALISに関連して活動を継続しているとされる。",descriptionEn:"Lv569. Appeared around AURALIS in E325. A deeply involved figure in AURALIS Collective's activities, resonating with the philosophy of 'making light and sound eternal.' He has watched over AURALIS's rise and fall from the Selia Golden Age (E335-E370), through Evatron's oppression (E400), to the second-generation revival (E522). His appearance is related to Leila Viller Nova's joining of AURALIS, and he may have witnessed her heroic actions during the Slime Crisis up close. It is believed he continues activities related to AURALIS after the official establishment of the second generation in E522.",era:"E325〜現在",affiliation:"AURALIS関連",tier:"Tier 2",image:"https://raw.githubusercontent.com/gentaron/image/main/Gentaro.png",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/Gentaroworld.txt",label:"Gentaro's Story"}]},{id:"Kate Claudia",name:"ケイト・クラウディア",nameEn:"Kate Claudia",category:"キャラクター",subCategory:"AURALIS",description:"AURALIS Collective創設者。通称「設計者」。E270年にLily Steinerと出会い、表現を諦めない人々の集団「AURALIS」を立ち上げた。E290年正式組織化。「光と音を永遠のものに」を理念とし、リリーが感情の炎ならケイトはその形を与える鋳型だった。E335〜E370年のセリア黄金期にAURALISを最盛期へ導く。E400年エヴァトロン弾圧で逮捕・消息不明。その名は新代のKate Pattonに継承された。",descriptionEn:"Founder of AURALIS Collective. Known as 'The Designer.' Met Lily Steiner in E270 and established 'AURALIS,' a collective of people who never gave up on expression. Officially organized in E290. With the philosophy of 'making light and sound eternal,' if Lily was the flame of emotion, Kate was the mold that gave it form. He led AURALIS to its peak during the Selia Golden Age (E335-E370). Arrested and disappeared during Evatron's oppression in E400. His name was inherited by the new-era Kate Patton.",era:"E270〜E400",affiliation:"AURALIS Collective第一世代（創設者）",tier:"神格・歴史的人物",image:"https://raw.githubusercontent.com/gentaron/image/main/KateClaudia.png",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/kateclaudiaandlilliesteiner.txt",label:"Kate Claudia & Lillie Steiner's Story"}]},{id:"Kate Patton",name:"ケイト・パットン",nameEn:"Kate Patton",category:"キャラクター",subCategory:"AURALIS",description:"AURALIS Collective第二世代。初代Kate Claudiaの「名」を継承。大地の豊かさ・安定を体現。E522年の第二世代正式発足時に参画。",descriptionEn:"Second-generation member of AURALIS Collective. Inheriting the 'name' of the first-generation Kate Claudia. Embodies the richness and stability of the earth. Participated in the official establishment of the second generation in E522.",era:"E522〜現在",affiliation:"AURALIS Collective第二世代",tier:"Tier 2",image:"https://raw.githubusercontent.com/gentaron/image/main/KatePatton.png",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/Auralishentai.txt",label:"AURALIS Spinoff"}]},{id:"Lily Steiner",name:"リリー・スタイナー",nameEn:"Lily Steiner",category:"キャラクター",subCategory:"AURALIS",description:"AURALIS Collective創設者。本名Lily Steiner、AURALIS公称名「Lillie Ardent 初代」。E270年にKate Claudiaと出会いAURALISを共同創設。「感情の炎」と称され、舞台上で性別の境界を歌う表現は神話となった。レイラのコールドスリープを誰よりも近くで見守り、目覚めるたびに「おかえり」と迎えた。E400年エヴァトロン弾圧で逮捕・最後のステージで「AURALISは消えない。灰から、また燃える」と言い残す。その名は新代のLillie Ardentに継承された。",descriptionEn:"Founder of the AURALIS Collective. Real name Lily Steiner, publicly known as 'Lillie Ardent, the First.' In E270, she met Kate Claudia and co-founded AURALIS. Revered as the 'Flame of Emotion,' her performances that transcended gender boundaries on stage became legendary. She watched over Leila's cryosleep closer than anyone, greeting her with 'Welcome back' each time she awoke. Arrested during the E400 Evatron suppression, she delivered her final words: 'AURALIS will never disappear. From the ashes, it will burn once more.' Her name was inherited by the Lillie Ardent of the new era.",era:"E270〜E400",affiliation:"AURALIS Collective第一世代（創設者）",tier:"神格・歴史的人物",image:"https://raw.githubusercontent.com/gentaron/image/main/LillieSteiner.png",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/kateclaudiaandlilliesteiner.txt",label:"Kate Claudia & Lillie Steiner's Story"}]},{id:"Lillie Ardent",name:"リリー・アーデント",nameEn:"Lillie Ardent",category:"キャラクター",subCategory:"AURALIS",description:"AURALIS Collective第二世代。初代Lily Steinerの「名」を継承。情熱的で大胆。E522年の第二世代正式発足時に参画。",descriptionEn:"Second generation of AURALIS Collective. Inherited the 'name' of the first generation, Lily Steiner. Passionate and bold. Joined at the official establishment of the second generation in E522.",era:"E522〜現在",affiliation:"AURALIS Collective第二世代",tier:"Tier 2",image:"https://raw.githubusercontent.com/gentaron/image/main/LillieArdent.png",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/Auralishentai.txt",label:"AURALIS Spinoff"}]},{id:"ミナ・エウレカ・エルンスト",name:"ミナ・エウレカ・エルンスト",nameEn:"Mina Eureka Ernst",category:"キャラクター",subCategory:"AURALIS",description:"AURALIS第二世代。E499年ノスタルジア・コロニー誕生。AI研究員。Genesis Vault創設者。リミナル・フォージ創設者。",descriptionEn:"Second generation of AURALIS. Born in Nostalgia Colony in E499. AI researcher. Founder of Genesis Vault. Founder of Liminal Forge.",era:"E499〜現在（29歳）",affiliation:"AURALIS Collective第二世代 / リミナル・フォージ",tier:"Tier 2",image:"https://raw.githubusercontent.com/gentaron/image/main/MinaEurekaErnst.png",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/Auralishentai.txt",label:"AURALIS Spinoff"}]},{id:"Ninny Offenbach",name:"ニニー・オッフェンバッハ",nameEn:"Ninny Offenbach",category:"キャラクター",subCategory:"AURALIS",description:"AURALIS第二世代。無邪気で爆発的な活力。原初個体はAlpha Kane時代に別惑星へ。クローン技術で遺伝子継承しGigapolisに再帰還。",descriptionEn:"Second generation of AURALIS. Innocent with explosive vitality. The original individual departed to another planet during the Alpha Kane era. Returned to Gigapolis through genetic inheritance via clone technology.",era:"新代〜現在",affiliation:"AURALIS Collective第二世代",tier:"Tier 2",image:"https://raw.githubusercontent.com/gentaron/image/main/NinnyOffenbach.png",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/Auralishentai.txt",label:"AURALIS Spinoff"}]},{id:"アイリス",name:"アイリス",nameEn:"Iris",category:"キャラクター",subCategory:"Iris/クレセント",description:"IRIS現代ランキング1位。ヴァーミリオンの英雄としてE480年頃から活動を開始し、ブルーワイヤとウォーター・オーブを駆使した独自の戦闘スタイルで数多の敵を打ち倒してきた。シルバー・ヴェノムとの長き戦いを経てE510年に捕囚されたが、E519年の再救出後はトリニティ・アライアンスの指導者としてV7とアルファ・ヴェノムとの二正面対峙に挑む。セバスチャン・ヴァレリウス率いるボグダス・ジャベリンとの連携も作戦成功の鍵となっている。",descriptionEn:"Current IRIS Ranking #1. Began activities around E480 as the hero of Vermilion. Employing a unique combat style utilizing Blue Wire and Water Orb, has defeated countless enemies. After a long struggle with Silver Venom, was imprisoned in E510, but after being rescued again in E519, challenges the two-front confrontation with V7 and Alpha Venom as the leader of the Trinity Alliance. The coordination with Bogdas Javelin, led by Sebastian Valerius, has been key to operational success.",era:"E480〜現在",affiliation:"トリニティ・アライアンス / 元ヴァーミリオン諜報機関長",tier:"Tier 1",image:"https://raw.githubusercontent.com/gentaron/image/main/Iris.png",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/IRIS_1.txt",label:"Iris's Story Ep1"},{url:"https://raw.githubusercontent.com/gentaron/edutext/main/IRIS_2.txt",label:"Iris's Story Ep2"},{url:"https://raw.githubusercontent.com/gentaron/edutext/main/IRIS_3.txt",label:"Iris's Story Ep3"},{url:"https://raw.githubusercontent.com/gentaron/edutext/main/IRIS_4.txt",label:"Iris's Story Ep4"}]},{id:"ウィリー",name:"ウィリー",nameEn:"Willy",category:"キャラクター",subCategory:"Iris/クレセント",description:"ヴァーミリオン諜報機関に所属し、アイリスのパートナー兼元恋人としてE490年代から活動。アイリスがランキング1位に躍進する以前から彼女を支え、諜報活動の現場で共に命を懸けた戦友。複雑な過去を共有しつつも、現在もアイリスの行動に深い影響を与える存在。",descriptionEn:"Affiliated with the Vermilion intelligence agency, has been active since the E490s as Iris's partner and former lover. Supported her even before she rose to the top of the rankings, a comrade-in-arms who risked their lives together in the field of intelligence operations. Despite sharing a complex past, continues to deeply influence Iris's actions.",era:"E490〜",affiliation:"ヴァーミリオン",tier:"Tier 2",image:"https://raw.githubusercontent.com/gentaron/image/main/Willie.png"},{id:"エレナ",name:"エレナ",nameEn:"Elena",category:"キャラクター",subCategory:"Iris/クレセント",description:"ヴァーミリオン諜報機関の元本部長であり、アイリスの直属の上司として彼女をスカウト・育成した人物。鋭い洞察力と冷徹な判断力で機関を統率し、シルバー・ヴェノムとの暗闘の最前線で指揮を執った。E505年頃に退任した後も、その遺産はアイリスの行動に色濃く反映されている。",descriptionEn:"Former head of the Vermilion intelligence agency, the person who scouted and trained Iris as her direct superior. Ruled the agency with sharp insight and cold judgment, commanding on the front lines of the secret war with Silver Venom. Even after stepping down around E505, his legacy is strongly reflected in Iris's actions.",era:"?〜E505頃",affiliation:"ヴァーミリオン諜報機関",tier:"Tier 2",image:"https://raw.githubusercontent.com/gentaron/image/main/Elena.png"},{id:"セバスチャン・ヴァレリウス",name:"セバスチャン・ヴァレリウス",nameEn:"Sebastian Valerius",category:"キャラクター",subCategory:"Iris/クレセント",description:"ボグダス・ジャベリンリーダー。IRIS現代ランキング4位。E490年頃にヴァーミリオンに恒久駐在を開始。テクロサス系譜（E15ファランクス → E295三頭政治改編 → E470東方支隊）を継承する軍事組織の当代指導者。副リーダー・ガレスを筆頭とする精鋭部隊を率い、アイリスのシルバー・ヴェノムに対抗や救出作戦（E510・E519）で中核的な役割を果たした。トリニティ・アライアンスの軍事的支柱として、V7との冷戦期においても安定した戦力を維持。",descriptionEn:"Leader of Bogdas Javelin. Current IRIS Ranking #4. Began permanent residence in Vermilion around E490. Leader of the contemporary military organization that inherits the Technosus lineage (E15 Phalanx → E295 Triumvirate Reform → E470 Eastern Detachment). Leads elite troops including deputy leader Gares, playing a central role in operations against Silver Venom and Iris's rescue operations (E510, E519). As the military pillar of the Trinity Alliance, maintained stable military power even during the Cold War with V7.",era:"E490〜現在",affiliation:"ボグダス・ジャベリン",tier:"Tier 2",image:"https://raw.githubusercontent.com/gentaron/image/main/SebastianValerius.png"},{id:"ガレス",name:"ガレス",nameEn:"Gareth",category:"キャラクター",subCategory:"Iris/クレセント",description:"ボグダス・ジャベリンの副リーダー。セバスチャン・ヴァレリウスの右腕として部隊全体の実戦指揮を担い、E510年・E519年の救出作戦で前線から部隊を率いた。テクロサス系譜の軍人として洗練された統率力を持ち、メンバーから絶大な信頼を集める堅実な将校。",descriptionEn:"Deputy leader of Bogdas Javelin. As Sebastian Valerius's right hand, bears overall combat command of the unit, leading troops from the front in the rescue operations of E510 and E519. As a soldier of the Technosus lineage, possesses refined leadership skills and is a reliable officer who commands absolute trust from his members.",era:"E490〜現在",affiliation:"ボグダス・ジャベリン",tier:"Tier 2",image:"https://raw.githubusercontent.com/gentaron/image/main/Gareth.png"},{id:"フィオナ",name:"フィオナ",nameEn:"Klaus Fiona",category:"キャラクター",subCategory:"Iris/クレセント",description:"ブルーローズ統率者。V7急先鋒。IRIS現代ランキング2位。E490年頃からクレセント政治の表舞台に登場。アイリス救出作戦（E510）でボグダス・ジャベリンと連携して活躍し、V7設立（E515）に向けて外交を主導。E520年のトリニティ・アライアンス結成後、ミエルテンガ総統への就任をアイリスに推薦するなど協調的姿勢を見せていたが、E523〜E525年にアルファ・ヴェノムと内通していることが発覚。腹心のピアトリーノを通じてブルーローズ地下街を掌握し、二重スパイとしてクレセント全域に激震をもたらした。",descriptionEn:"Leader of Blue Rose. Vanguard of V7. Current IRIS Ranking #2. Appeared on the political stage of Crescent politics around E490. Collaborated with Bogdas Javelin in the Iris rescue operation (E510) and led diplomatic efforts toward the establishment of V7 (E515). After the formation of the Trinity Alliance in E520, showed a cooperative attitude by recommending Iris for the presidency of Miertenga. However, it was discovered between E523-E525 that they were secretly communicating with Alpha Venom. Through their confidant Piattino, seized control of the Blue Rose underground district, causing a massive shock throughout Crescent as a double agent.",era:"E490〜現在",affiliation:"ブルーローズ / アルファ・ヴェノム（内通）",tier:"Tier 2",image:"https://raw.githubusercontent.com/gentaron/image/main/Fiona.png"},{id:"マリーナ・ボビン",name:"マリーナ・ボビン",nameEn:"Marina Bobbin",category:"キャラクター",subCategory:"Iris/クレセント",description:"ミエルテンガ総統。IRIS現代ランキング3位。E515年のV7設立からクレセント政治の中核を担う。表向きはトリニティ・アライアンスの盟友として振る舞うが、フィオナの裏切り（E523〜E525）との共謀説が浮上しており、クレセント全域における「真の黒幕」の可能性が指摘されている。E520年のアイリスのミエルテンガ首脳就任自体がフィオナの推薦によるものであり、マリーナの関与が疑われている。高圧的な政治手腕と深い情報網で知られ、ランキング3位の実力は伊達ではないとされる。",descriptionEn:"President of Miertenga. Current IRIS Ranking #3. Has been at the core of Crescent politics since the establishment of V7 in E515. While publicly behaving as an ally of the Trinity Alliance, theories of conspiracy with Fiona's betrayal (E523-E525) have emerged, and the possibility of being the 'true mastermind' throughout Crescent has been pointed out. Iris's appointment to the Miertenga leadership in E520 itself was recommended by Fiona, and Marina's involvement is suspected. Known for high-handed political tactics and extensive information network, the strength of her #3 ranking is said to be no mere facade.",era:"E515〜現在",affiliation:"ミエルテンガ",tier:"Tier 2",image:"https://raw.githubusercontent.com/gentaron/image/main/MarinaBobbin.png"},{id:"カスチーナ・テンペスト",name:"カスチーナ・テンペスト",nameEn:"Castina Tempest",category:"キャラクター",subCategory:"Iris/クレセント",description:"クロセヴィア首脳。IRIS現代ランキング5位。E515年のV7設立メンバーの一人。テンペストの名が示す通り、荒波のような政治的判断力でクロセヴィアを率いる。V7 vs トリニティの二大陣営対立において、明確な陣営選択を避け独自路線を歩む戦略家。Casteria Grenvelt（カステリア・グレンヴェルト）とは全くの別人物であり、混同を避けるべき。",descriptionEn:"Leader of Crosevia. Current IRIS Ranking #5. One of the founding members of V7 in E515. As the name 'Tempest' suggests, leads Crosevia with political judgment like a raging storm. A strategist who walks a unique path, avoiding clear faction alignment in the V7 vs Trinity dichotomy. Casteria Grenvelt is a completely different person and should not be confused.",era:"E515〜現在",affiliation:"クロセヴィア",tier:"Tier 2",image:"https://raw.githubusercontent.com/gentaron/image/main/CastinaTempest.png"},{id:"イズミ",name:"イズミ",nameEn:"Izumi",category:"キャラクター",subCategory:"Iris/クレセント",description:"アルファ・ヴェノムリーダー。両性具有。E518年にシルバー・ヴェノム残党を吸収し、アルファ・ヴェノムを大幅に勢力拡大。E519年には自らの指揮でアイリスの再拉致を成功させるなど、極めて高い戦略的判断力と実行力を持つ。ボブリスティ・ギル・カタリナ・ゴルディロックス・AJらを率い、フィオナを内通者として抱き込むことでV7内部からトリニティ・アライアンスを弱体化させる二重工作を展開。アイリス最大の敵対者。",descriptionEn:"Alpha Venom Leader. Hermaphroditic. In E518, absorbed the remnants of Silver Venom, significantly expanding Alpha Venom's influence. In E519, personally orchestrated the successful recapture of Iris, demonstrating exceptional strategic judgment and execution capability. Leading Bobristy Gil Katarina Goldilocks AJ and others, and recruiting Fiona as an insider, launched a double operation to weaken the Trinity Alliance from within V7. Iris's greatest adversary.",era:"E518〜現在",affiliation:"アルファ・ヴェノム",tier:"Tier 2",image:"https://raw.githubusercontent.com/gentaron/image/main/Izumi.png"},{id:"レオン",name:"レオン",nameEn:"Leon",category:"キャラクター",subCategory:"Iris/クレセント",description:"シルバー・ヴェノムの幹部としてマスター・ヴェノムに仕え、暗黒組織の中枢で活動した実行部隊の指揮官。E485年頃から組織の作戦立案と実行を担い、シルバー・ヴェノムの拡大期に多大な影響力を持った。イズミによる吸収後の動向は不明。",descriptionEn:"As an executive of Silver Venom, served under Master Venom as the commander of an active-duty unit operating at the heart of the dark organization. From around E485, was responsible for the planning and execution of the organization's operations, wielding considerable influence during Silver Venom's expansion period. Current whereabouts following absorption by Izumi are unknown.",era:"E485〜",affiliation:"シルバー・ヴェノム",tier:"Tier 2",image:"https://raw.githubusercontent.com/gentaron/image/main/Leon.png"},{id:"ヴィヴィエッタ",name:"ヴィヴィエッタ",nameEn:"四楓院ヴィヴィエッタ",category:"キャラクター",subCategory:"Iris/クレセント",description:"シルバー・ヴェノムに捕囚されていた元捕虜。E510年のアイリス救出作戦においてボグダス・ジャベリンとの連携によって救出され、自由の身となった。救出後はアイリスへの感謝と信頼からトリニティ・アライアンスに接近し、ヴァーミリオンとの関係構築に寄与したとされる。",descriptionEn:"A former prisoner held captive by Silver Venom. During the Iris rescue operation in E510, was freed through coordination with Bogdus Javelin. After liberation, approached the Trinity Alliance out of gratitude and trust for Iris, and is said to have contributed to establishing relations with Vermilion.",era:"?〜E512",affiliation:"捕虜（のち救出）",tier:"Tier 2",image:"https://raw.githubusercontent.com/gentaron/image/main/Vivietta.png"},{id:"レヴィリア・サーペンティナ",name:"レヴィリア・サーペンティナ",nameEn:"Levilia Serpentina",category:"キャラクター",subCategory:"Iris/クレセント",description:"シルバー・ヴェノムの幹部の一人。その名が示す通り蛇のように狡猾な手腕で組織の暗部を操り、レオンと並ぶ中枢メンバーとして活動した。マスター・ヴェノムの失脚後も独自のネットワークを維持し、アルファ・ヴェノムへの移行過程でも暗躍したとされる謎の人物。",descriptionEn:"One of Silver Venom's executives. As his name suggests, manipulated the organization's dark affairs with snake-like cunning and operated as a central member alongside Leon. Maintained his own network even after Master Venom's downfall and is said to have operated covertly during the transition to Alpha Venom, a mysterious figure.",era:"?〜現在",affiliation:"シルバー・ヴェノム",tier:"Tier 2",image:"https://raw.githubusercontent.com/gentaron/image/main/LeviliaSerpentina.png"},{id:"ミユシャリ",name:"ミユシャリ",nameEn:"Miyushari",category:"キャラクター",subCategory:"Iris/クレセント",description:"ボグダス・ジャベリンの偵察・索敵担当。隠密行動と情報収集に長け、セバスチャン・ヴァレリウスの先遣として敵地の地形分析や危険区域の特定を担う。E510年のアイリス救出作戦では、シルバー・ヴェノムの防衛網の隙間を見抜き部隊の侵入ルートを確保した。",descriptionEn:"Bogdus Javelin's reconnaissance and detection specialist. Proficient in stealth operations and information gathering, responsible for terrain analysis and identifying hazardous areas in enemy territory as Sebastian Valerius's advance scout. During the Iris rescue operation in E510, identified gaps in Silver Venom's defensive network and secured infiltration routes for the unit.",era:"E490〜現在",affiliation:"ボグダス・ジャベリン",image:"https://raw.githubusercontent.com/gentaron/image/main/Miyushari.png"},{id:"ファリエル",name:"ファリエル",nameEn:"Fariel",category:"キャラクター",subCategory:"Iris/クレセント",description:"ボグダス・ジャベリンの近接戦闘担当。双剣を駆使した高速戦闘スタイルで知られ、部隊の最前線で敵の攻撃を一手に受け止める。ガレスから直接指導を受けた精鋭の一人であり、その剣技はテクロサス系譜の戦闘教範を体現している。",descriptionEn:"Bogdus Javelin's close combat specialist. Known for a high-speed combat style wielding twin swords, single-handedly receiving enemy attacks at the forefront of the unit. One of the elite directly trained by Gares, his swordsmanship embodies the combat doctrine of the Teklosas lineage.",era:"E490〜現在",affiliation:"ボグダス・ジャベリン",image:"https://raw.githubusercontent.com/gentaron/image/main/Fariel.png"},{id:"アイナ",name:"アイナ・フォン・リースフェルト",nameEn:"Aina von Riesfeldt",category:"キャラクター",subCategory:"Iris/クレセント",description:"ボグダス・ジャベリンの戦略分析・通信担当。リアルタイムの戦況把握と部隊間の連携調整を担い、セバスチャンの作戦立案を補佐する頭脳派。リースフェルト家の出身であり、分析的思考と冷徹な判断力で部隊の「第二の頭脳」と呼ばれている。",descriptionEn:"Bogdus Javelin's strategic analysis and communications specialist. Responsible for real-time battlefield awareness and coordinating unit coordination, assisting Sebastian in operational planning as the unit's brain. A descendant of the Riessfeld family, known as the unit's 'second brain' for his analytical thinking and cold judgment.",era:"E490〜現在",affiliation:"ボグダス・ジャベリン",image:"https://raw.githubusercontent.com/gentaron/image/main/AinaVonRiesfeld.png"},{id:"ギャビー",name:"フレデリック・ギャビー",nameEn:"Frederick Gabby",category:"キャラクター",subCategory:"Iris/クレセント",description:"ボグダス・ジャベリンの重火器・爆薬担当。大型兵器の運用と爆破工作を専門とし、要塞攻略戦では障害物の破壊と火力支援で先陣を切る。その圧倒的な破壊力は味方からも「暴走機関車」と称され、敵からは最も警戒されているメンバーの一人。",descriptionEn:"Bogdus Javelin's heavy weapons and explosives specialist. Specializing in the operation of large-scale weapons and demolition work, leads the charge in destroying obstacles and providing fire support during fortress assaults. His overwhelming destructive power earns him the nickname 'Runaway Locomotive' from allies and makes him one of the most feared members by enemies.",era:"E490〜現在",affiliation:"ボグダス・ジャベリン",image:"https://raw.githubusercontent.com/gentaron/image/main/FredericGabby.png"},{id:"シェロン",name:"シェロン・ジェラス",nameEn:"Sheron Jeras",category:"キャラクター",subCategory:"Iris/クレセント",description:"ボグダス・ジャベリンの後方支援・医療担当。負傷者の治療と部隊の兵站管理を一手に引き受け、過酷な戦場においても部隊の戦闘継続能力を支える。冷静沈着な性格で、ガレスからの信頼も厚く、部隊の要として欠かせない存在。",descriptionEn:"Bogdus Javelin's rear support and medical specialist. Single-handedly handles the treatment of wounded personnel and the unit's logistics management, sustaining the unit's combat capability even in harsh battlefields. With a calm and composed personality, enjoys Gares's deep trust and is an indispensable presence as the unit's cornerstone.",era:"E490〜現在",affiliation:"ボグダス・ジャベリン",image:"https://raw.githubusercontent.com/gentaron/image/main/SheronJeras.png"},{id:"イルミーゼ",name:"イルミーゼ",nameEn:"Ilmise",category:"キャラクター",subCategory:"Iris/クレセント",description:"ボグダス・ジャベリンの電子戦・ハッキング担当。敵の通信網の傍受や妨害工作を担い、情報面から作戦の成功を裏で支える。シェロンと並ぶ後方要員でありながら、その技術力は最前線の戦況をも左右する重要な役割を果たす。",descriptionEn:"Bogdus Javelin's electronic warfare and hacking specialist. Responsible for intercepting and disrupting enemy communication networks, supporting operational success from the information front. Alongside Sheron, serves as a rear support member, yet his technical capabilities play a crucial role that can even influence frontline battle conditions.",era:"E490〜現在",affiliation:"ボグダス・ジャベリン",image:"https://raw.githubusercontent.com/gentaron/image/main/Ilmise.png"},{id:"ホワイトノイズ",name:"ホワイトノイズ",nameEn:"White Noise",category:"キャラクター",subCategory:"Iris/クレセント",description:"ボグダス・ジャベリンの潜入工作・暗殺担当。その名の通り痕跡を残さず行動し、敵の重要拠点への単独潜入を得意とする。正体不明の点が多く、セバスチャンですら全貌を把握していないとされる謎めいた特殊技能者。",descriptionEn:"Bogdus Javelin's infiltration and assassination specialist. Acts without leaving traces as his name suggests, specializing in solo infiltration into enemy key strongholds. A mysterious special operative with many unknown aspects; even Sebastian is said not to grasp his full identity.",era:"E490〜現在",affiliation:"ボグダス・ジャベリン",image:"https://raw.githubusercontent.com/gentaron/image/main/WhiteNoise.png"},{id:"ワドリナ",name:"ワドリナ",nameEn:"Wadorina",category:"キャラクター",subCategory:"Iris/クレセント",description:"ボグダス・ジャベリンの盾役・防御戦闘担当。巨大な盾を用いた堅牢な防御陣形で部隊の背後を守り、ガレスの副官格として小隊指揮もこなす。その忠誠心と身体を張った防衛行動は、部隊全体の士気を支える精神的支柱となっている。",descriptionEn:"Bogdus Javelin's shield bearer and defensive combat specialist. Protects the unit's rear with a solid defensive formation using a massive shield and also commands small units as Gares's second-in-command. His loyalty and defense actions that put his body on the line serve as a psychological pillar supporting the unit's morale.",era:"E490〜現在",affiliation:"ボグダス・ジャベリン",image:"https://raw.githubusercontent.com/gentaron/image/main/Wadrina.png"},{id:"ニニギス",name:"ニニギス・カラス",nameEn:"Ninigisu Karasu",category:"キャラクター",subCategory:"Iris/クレセント",description:"ボグダス・ジャベリンの航空・機動戦闘担当。空中からの偵察と機動打撃を担い、ミユシャリの地上偵察と連携して部隊に立体的な戦闘優位をもたらす。「カラス」の異名はその素早い飛行能力に由来し、敵にとっては空からの脅威。",descriptionEn:"Bogdus Javelin's specialist in aerial and mobile combat. Responsible for aerial reconnaissance and swift striking maneuvers, they coordinate with Miyushari's ground reconnaissance to provide the unit with three-dimensional combat superiority. His nickname 'Crow' derives from his swift flying capabilities, making him a threat from the skies for the enemy.",era:"E490〜現在",affiliation:"ボグダス・ジャベリン",image:"https://raw.githubusercontent.com/gentaron/image/main/NinigisKaras.png"},{id:"イェシバトー",name:"イェシバトー",nameEn:"Yeshibato",category:"キャラクター",subCategory:"Iris/クレセント",description:"ボグダス・ジャベリンの格闘戦・制圧担当。素手を中心とした近接格闘術で敵を無力化し、捕縛を要する任務では不可欠な戦力。セバスチャンがテクロサス東方支隊時代から鍛え上げた古参メンバーであり、部隊内でも随一の身体能力を誇る。",descriptionEn:"Bogdus Javelin's specialist in close-quarters combat and suppression. Neutralizes enemies through unarmed martial arts techniques, making him an indispensable force for missions requiring capture. A veteran member trained by Sebastian since his time with the Teklosus Eastern Detachment, boasting unparalleled physical prowess even within the unit.",era:"E490〜現在",affiliation:"ボグダス・ジャベリン",image:"https://raw.githubusercontent.com/gentaron/image/main/Yeshibato.png"},{id:"アザゼル",name:"アザゼル・ヘクトパス",nameEn:"Azazel Hectopass",category:"キャラクター",subCategory:"Iris/クレセント",description:"ヴァーミリオンの元首脳であり、アイリスが台頭する以前のクレセント政治を主導した実力者。E480年頃まで権力の座にあり、その退場はアイリスの躍進とヴァーミリオン体制の転換を象徴する出来事となった。現在の行方は不明。",descriptionEn:"The former leader of Vermilion and a powerful figure who dominated Crescent politics before Iris rose to prominence. Remained in power until around E480, and his departure symbolized the rise of Iris and the transformation of the Vermilion political system. His current whereabouts remain unknown.",era:"?〜E480頃",affiliation:"ヴァーミリオン",image:"https://raw.githubusercontent.com/gentaron/image/main/AzazelHectopus.png"},{id:"ピアトリーノ",name:"ピアトリーノ",nameEn:"Piatorino",category:"キャラクター",subCategory:"Iris/クレセント",description:"フィオナの腹心としてブルーローズ地下街の実務を一手に掌握する実行力のある人物。E515年以降、フィオナのアルファ・ヴェノムへの内通工作を補佐し、地下街を通じた密輸・情報収集ネットワークを構築した。表向きはブルーローズ政府の下級官吏を装いながら、裏で組織の暗部を動かすフィオナの「影の右手」。",descriptionEn:"Fiona's most trusted confidant who single-handedly manages the practical affairs of the Blue Rose underground district. Since E515, has assisted Fiona's espionage operations against Alpha Venom, constructing a smuggling and intelligence network through the underground district. While posing as a minor government official of Blue Rose in public, serves as Fiona's 'right hand in the shadows,' manipulating the organization's clandestine operations.",era:"E515〜現在",affiliation:"ブルーローズ",image:"https://raw.githubusercontent.com/gentaron/image/main/Piatrino.png"},{id:"アイク・ロペス",name:"アイク・ロペス",nameEn:"Ike Lopez",category:"キャラクター",subCategory:"Iris/クレセント",description:"SSレンジの首脳であり、E515年のV7設立メンバーの一人。クレセント地方の国際的な交易・通信網を支配下に置き、V7の経済的基盤を支える実力者。V7とトリニティ・アライアンスの冷戦構造の中で、明確な陣営を選ばず独自の利益を追求する現実主義者。",descriptionEn:"The leader of SS Range and one of the founding members of V7 in E515. Controls the international trade and communication networks of the Crescent region, forming the economic foundation of V7. A realist who pursues his own interests without clearly aligning with either faction in the Cold War structure between V7 and the Trinity Alliance.",era:"E515〜現在",affiliation:"SSレンジ / V7",image:"https://raw.githubusercontent.com/gentaron/image/main/AikeLopez.png"},{id:"レイド・カキザキ",name:"レイド・カキザキ",nameEn:"Raid Kakizaki",category:"キャラクター",subCategory:"Iris/クレセント",description:"アイアン・シンジケートの首脳であり、E515年のV7設立メンバーの一人。重工業と軍需生産を基盤とした国家経済を構築し、V7の軍事的な力を裏から支える。堅実な武人としての性格で、カスチーナ・テンペストとは異なる路線でV7内部の影響力を維持している。",descriptionEn:"The leader of the Iron Syndicate and one of the founding members of V7 in E515. Built a national economy based on heavy industry and military production, providing the military backbone for V7 from behind the scenes. As a steadfast warrior, he maintains his influence within V7 through a different approach than Castina Tempest.",era:"E515〜現在",affiliation:"アイアン・シンジケート / V7",image:"https://raw.githubusercontent.com/gentaron/image/main/ReidKakizaki.png"},{id:"ミカエル・ガブリエリ",name:"ミカエル・ガブリエリ",nameEn:"Mikael Gabrieli",category:"キャラクター",subCategory:"Iris/クレセント",description:"ファールージャ社のCEOとしてクレセント地方最大の民間企業を率いる実業家。次元極地平技術の民生応用と武器開発の両面でV7陣営に深く関与し、軍事・経済の両面からクレセントの力均衡に影響を与える。その企業帝国は国家の枠を超え、事実上V7の「第8の力」と呼ばれている。",descriptionEn:"As CEO of Faluja Corporation, leads the largest private enterprise in the Crescent region. Deeply involved with the V7 faction in both civilian applications of dimensional horizon technology and weapon development, influencing the balance of power in Crescent from both military and economic perspectives. His corporate empire transcends national boundaries and is effectively known as V7's 'eighth power.'",era:"E515〜現在",affiliation:"ファールージャ社",image:"https://raw.githubusercontent.com/gentaron/image/main/MikaelGabrieli.png"},{id:"ヨニック",name:"ヨニック",nameEn:"Yonick",category:"キャラクター",subCategory:"Iris/クレセント",description:"ブルー・ローズ政府の最高司令官として国家の軍事全般を統括する人物。フィオナの統率のもとでV7の軍事的支柱として機能したが、フィオナの裏切り発覚後は対応に追われている。忠誠心の強い軍人であり、ブルーローズの正規軍の信頼を厚く集める。",descriptionEn:"As the Supreme Commander of the Blue Rose government, oversees all national military affairs. Functioned as V7's military pillar under Fiona's command but has been preoccupied with responding to her betrayal. A loyal soldier who commands deep respect from the regular forces of Blue Rose.",era:"E515〜現在",affiliation:"ブルーローズ",image:"https://raw.githubusercontent.com/gentaron/image/main/Yonik.png"},{id:"マスター・ヴェノム",name:"マスター・ヴェノム",nameEn:"Master Venom",category:"キャラクター",subCategory:"Iris/クレセント",description:"シルバー・ヴェノムの創設者にして初代リーダー。E475年にエヴァトロンΣ-Unit残党から独立し、通称「影の支配者」として暗黒組織の基盤を築いた。本名は一切不明であり、レオンやレヴィリア・サーペンティナら幹部すら素顔を知らないとされる。E500年頃に忽然と姿を消し、その後イズミが後継として組織を引き継いだ。",descriptionEn:"The founder and first leader of Silver Venom. Separated from the Evatron Σ-Unit remnants in E475 and established the foundation of the dark organization under the alias 'The Shadow Ruler.' His true identity remains completely unknown; even senior members like Leon and Leviria Serpentina are said not to know his face. Disappeared suddenly around E500, after which Izumi succeeded him as the organization's leader.",era:"E475〜E500頃",affiliation:"シルバー・ヴェノム",tier:"Tier 2",image:"https://raw.githubusercontent.com/gentaron/image/main/MasterVenom.png"},{id:"ゴルディロックス",name:"ゴルディロックス",nameEn:"Goldilocks",category:"キャラクター",subCategory:"Iris/クレセント",description:"アルファ・ヴェノムの潜入・変装工作担当。イズミの指示のもとV7内部への浸透工作を担い、フィオナとの内通ルートの構築に重要な役割を果たした。その名の通り、状況に応じて複数の身分を巧みに使い分け、敵対勢力を内部から崩壊させることに長ける。",descriptionEn:"Alpha Venom's specialist in infiltration and disguise operations. Under Izumi's direction, conducts infiltration operations within V7 and played a crucial role in establishing the espionage route with Fiona. True to his name, he skillfully assumes multiple identities as needed, excelling at collapsing opposing forces from within.",era:"E518〜現在",affiliation:"アルファ・ヴェノム",image:"https://raw.githubusercontent.com/gentaron/image/main/Goldilocks.png"},{id:"カタリナ",name:"カタリナ",nameEn:"Catalina",category:"キャラクター",subCategory:"Iris/クレセント",description:"アルファ・ヴェノムの正面戦闘担当。圧倒的な破壊力で戦場を支配し、E519年のアイリス再拉致作戦では先鋒としてトリニティ・アライアンスの防衛線を突破した。イズミの最も信頼する戦闘要員であり、その力技はボブリスティの戦術と好対照をなす。",descriptionEn:"Alpha Venom's frontline combat specialist. Dominates the battlefield with overwhelming destructive power and served as the vanguard, breaking through Trinity Alliance's defensive lines during the E519 operation to recapture Iris. Izumi's most trusted combat operative, his brute force tactics stand in stark contrast to Bobristy's strategic approach.",era:"E518〜現在",affiliation:"アルファ・ヴェノム",image:"https://raw.githubusercontent.com/gentaron/image/main/Katarina.png"},{id:"ボブリスティ",name:"ボブリスティ",nameEn:"Boblisti",category:"キャラクター",subCategory:"Iris/クレセント",description:"アルファ・ヴェノムの戦術指揮・軍師役。イズミの構想を実戦レベルの作戦計画に練り上げ、カタリナやギルの戦闘力を最大限に活用する配置を行う。シルバー・ヴェノム時代からの古参であり、組織の再編と戦力拡大の立役者。",descriptionEn:"Alpha Venom's tactical commander and strategist. Transforms Izumi's concepts into practical operational plans and allocates personnel like Catalina and Gil to maximize their combat effectiveness. A veteran from the Silver Venom era and a key figure in the organization's restructuring and expansion of forces.",era:"E518〜現在",affiliation:"アルファ・ヴェノム",image:"https://raw.githubusercontent.com/gentaron/image/main/Bobristy.png"},{id:"ギル",name:"ギル",nameEn:"Gil",category:"キャラクター",subCategory:"Iris/クレセント",description:"アルファ・ヴェノムの技術開発・兵器管理担当。旧シルバー・ヴェノムの残存技術を継承しつつ、新たな兵器や装備の開発を手掛ける。E519年の作戦では特殊な拘束装置を用いてアイリスの能力を封じるなど、技術面からイズミの作戦を強力に支援。",descriptionEn:"Head of technological development and weapon management for Alpha Venom. While inheriting the remaining technology of the former Silver Venom, they develop new weapons and equipment. During the E519 operation, they strongly supported Izumi's plans from a technical standpoint by using special restraint devices to seal Iris's abilities.",era:"E518〜現在",affiliation:"アルファ・ヴェノム",image:"https://raw.githubusercontent.com/gentaron/image/main/Gil.png"},{id:"ラストマン",name:"ラストマン",nameEn:"Lastman",category:"キャラクター",subCategory:"Iris/クレセント",description:"シルバー・ヴェノム崩壊後に残存した旧組織の忠実なメンバー。マスター・ヴェノムの失脚後もイズミのアルファ・ヴェノムへの合流を拒み、独自に旧組織の再興を画策する頑固な残党。シルバー・ヴェノムの古き栄光に固執し、イズミの新しい方針を「裏切り」と見なす異端者として、クレセントの暗部で依然として活動を続けている。",descriptionEn:"A loyal member of the former organization that remained after Silver Venom's collapse. Even after Master Venom's downfall, they refused to join Izumi's Alpha Venom, instead plotting the revival of the old organization as a stubborn remnant. Clinging to Silver Venom's former glory, they continue to operate in the shadows of Crescent as a heretic who views Izumi's new policies as 'betrayal'.",era:"E500〜",affiliation:"シルバー・ヴェノム残党",image:"https://raw.githubusercontent.com/gentaron/image/main/Lastman.png"},{id:"AJ",name:"アルフレッド・ジュース",nameEn:"Alfred Juce",category:"キャラクター",subCategory:"Iris/クレセント",description:"アルファ・ヴェノムの情報操作・宣伝工作担当。本名アルフレッド・ジュース。クレセント地方のメディアと情報網を操作し、トリニティ・アライアンスへの社会的圧力を形成する工作を展開。イズミの二重工作を支える影の広報官として、真実を歪める言葉の力を操る。",descriptionEn:"In manipulation and propaganda specialist for Alpha Venom. Real name Alfred Juice. They manipulate the media and information networks of the Crescent region to create social pressure against the Trinity Alliance. As the shadow public relations officer supporting Izumi's double operations, they wield the power of words to distort truth.",era:"E518〜現在",affiliation:"アルファ・ヴェノム",image:"https://raw.githubusercontent.com/gentaron/image/main/AJ.png"},{id:"Slime_Woman",name:"スライム・ウーマン",nameEn:"Slime Woman",category:"キャラクター",subCategory:"Gigapolis",description:"E340年、ティムール・シャーが設計した仮想多元宇宙「ペルセポネ」の実験事故により、高次元世界（Tier Ω）からE16通常次元（Tier Ε）に顕現した超越的存在。スライム危機（E380〜E400）の遠因となったリーチ・ドレインの遺伝子変異にも間接的に関与している可能性がある。Tier 1アクティブ現役最強格であり、その能力の正体は高次元物理学の未解明領域に属する。人間社会の枠組みに完全に適応しているわけではなく、特定の個人（Junなど）とのみ特異な相互作用を示す。E340年の顕現から約200年近く存在し続ける、EDU中最も謎めいた存在。",descriptionEn:"A transcendent being that manifested from the higher-dimensional world (Tier Ω) to the E16 normal dimension (Tier Ε) due to an experimental accident with the virtual multiverse 'Persephone,' designed by Timur Shah in E340. May have been indirectly involved in the genetic mutations that led to the Reach Drain crisis (E380-E400). Currently the strongest active Tier 1 being, the true nature of their abilities belongs to the unexplored realms of higher-dimensional physics. Not fully adapted to human society frameworks, they only exhibit unique interactions with specific individuals (such as Jun). Having existed for nearly 200 years since their manifestation in E340, they remain the most enigmatic being in the EDU.",era:"E340〜現在",affiliation:"不明（高次元存在）",tier:"Tier 1",image:"https://raw.githubusercontent.com/gentaron/image/main/SlimeWoman.png",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/Junandslime.txt",label:"Jun's Story"}]},{id:"テミルタロン",name:"テミルタロン",nameEn:"Temirtalon",category:"キャラクター",subCategory:"Gigapolis",description:"E80〜E90年代に活動した物理学者。サイケデリック・コスモロジーを提唱し、次元極地平を宇宙論的な枠組みで解釈して次元階梯パンディクトの原型を構想した。その理論的成果を具現化するためテンプル・オブ・ホライゾンを設計し、技術啓蒙時代の精神的・科学的支柱となった。彼の構想はのちのティムール・シャーの10次元ホラズム理論にも影響を与えたとされる。",descriptionEn:"A physicist active during the E80-E90s who proposed psychedelic cosmology, interpreting the dimensional polar horizon as a cosmological framework and conceiving the prototype for the dimensional ladder pandect. To materialize his theoretical achievements, he designed the Temple of Horizon, becoming the spiritual and scientific pillar of the technological enlightenment era. His ideas are said to have influenced Timur Shah's later 10-dimensional Horazm theory.",era:"E80〜E90",affiliation:"テンプル・オブ・ホライゾン",tier:"歴史的人物",image:"https://raw.githubusercontent.com/gentaron/image/main/Temirtaron.png"},{id:"アリア・ソル",name:"アリア・ソル",nameEn:"Aria Sol",category:"キャラクター",subCategory:"Gigapolis",description:"E151年の新ヘルシンキ宣言で惑星連邦構想を提起した政治思想家。次元極地平技術を活用した星間議会の構想を打ち出し、M104銀河全体の平和的統合を志向した。エル・フォルハウスのマーストリヒト革命と同時代に活動し、ギガポリスの完全自由経済とは対照的な協調的宇宙外交の先駆者として歴史に名を残す。",descriptionEn:"A political thinker who proposed the planetary federation concept in the E151 New Helsinki Declaration. He put forward the concept of an interstellar council utilizing dimensional polar horizon technology, aiming for the peaceful integration of the entire M104 galaxy. Active during the same era as El Forhaus's Maastricht Revolution, he is remembered in history as a pioneer of cooperative cosmic diplomacy, in contrast to Gigapolis's completely free economy.",era:"E151頃",affiliation:"惑星連邦構想派",tier:"歴史的人物",image:"https://raw.githubusercontent.com/gentaron/image/main/AriaSol.png"},{id:"ゼナ",name:"ゼナ",nameEn:"Zena",category:"キャラクター",subCategory:"Eros-7",description:"Eros-7で活動する女性商人。独自の貿易ネットワークを通じてEros-7各地に物資を供給する実業家であり、E525年にアヤカ・リンとガロと同盟を結びマトリカル・リフォーム運動に参加。経済面からの社会変革を主導し、搾取抑制剤の非公式流通ルートを構築するなど、運動の兵站を支える不可欠なパートナー。",descriptionEn:"A female merchant operating on Eros-7. An entrepreneur who supplies goods throughout Eros-7 through her unique trade network. In E525, she formed an alliance with Ayaka Rin and Garo and participated in the Matricular Reform Movement. Leading social change from an economic perspective, she constructed unofficial distribution routes for exploitation inhibitors, serving as an indispensable partner supporting the movement's logistics.",era:"E525〜",affiliation:"マトリカル・リフォーム運動",image:"https://raw.githubusercontent.com/gentaron/image/main/Zena.png"},{id:"リリス・ヴェイン",name:"リリス・ヴェイン",nameEn:"Lilith Vaine",category:"キャラクター",subCategory:"Eros-7",description:"Eros-7初期の女性リーダーであり、リーチ・ドレインの制御技術を開発した科学者。E0年代にリーチ・ドレインの暴走を収めるため独自の生体制御理論を確立し、リーチ・ドレインをエネルギー資源として活用する道を開いた。その技術は後のバイオリアクターやスクイーズ・アビス建設の基盤となり、Eros-7社会の存続に不可欠な遺産を残した。",descriptionEn:"A female leader in early Eros-7 and a scientist who developed control technology for the Reach Drain. In the E0s, she established her own biological control theory to contain the runaway Reach Drain, opening the path to utilize it as an energy resource. Her technology became the foundation for later bio-reactors and the construction of the Squeeze Abyss, leaving an indispensable legacy for Eros-7 society's survival.",era:"E0頃",affiliation:"Eros-7",tier:"歴史的人物",image:"https://raw.githubusercontent.com/gentaron/image/main/LilithVane.png"},{id:"シルヴィア・クロウ",name:"シルヴィア・クロウ",nameEn:"Sylvia Crow",category:"キャラクター",subCategory:"Eros-7",description:"Eros-7の女性リーダー。E97〜E101年のリーチ・ドレイン危機において、強力なエスパー能力を駆使して危機を単独で収束させた英雄。この功績により男性指令省を設立し、Eros-7のマトリカル社会に新たな統治体制を確立。彼女のエスパー能力は後世に伝説として語り継がれている。",descriptionEn:"The female leader of Eros-7. During the E97-E101 Reach Drain crisis, she single-handedly contained the crisis by utilizing powerful esper abilities. For this achievement, she established the Male Command Department and established a new governance system in Eros-7's matricular society. Her esper abilities have been passed down as legends to later generations.",era:"E97〜E101",affiliation:"Eros-7",tier:"歴史的人物",image:"https://raw.githubusercontent.com/gentaron/image/main/SylviaCrow.png"},{id:"カーラ・ヴェルム",name:"カーラ・ヴェルム",nameEn:"Cara Verm",category:"キャラクター",subCategory:"Eros-7",description:"Eros-7に建設された560階に及ぶ地下搾取施設スクイーズ・アビスの立案者。E380年に着工し、リーチ・ドレインのエネルギーを抽出して搾取プラズマ弾を生産する巨大プラントを完成させた。その技術的野心的施設はEros-7の軍事力を飛躍的に増強したが、同時に倫理的な批判も招いた。E505年に施設の運用を終了した後の動向は不明。",descriptionEn:"The planner of the Squeeze Abyss, a 560-story underground extraction facility constructed on Eros-7. Construction began in E380 and was completed with a massive plant that extracts energy from the Reach Drain to produce exploitation plasma projectiles. While this technically ambitious facility dramatically enhanced Eros-7's military power, it also attracted ethical criticism. Their whereabouts after the facility's operation ended in E505 remain unknown.",era:"E380〜E505",affiliation:"Eros-7",tier:"Tier 2",image:"https://raw.githubusercontent.com/gentaron/image/main/KarlaVelm.png"},{id:"ガロ",name:"ガロ",nameEn:"Garo",category:"キャラクター",subCategory:"Eros-7",description:"シャドウ・ユニオンの男性指導者であり、E330年頃から反体制運動を率いてきた古参の闘士。アヤカ・リンとはスライム危機以来の盟友であり、互いに絶対的な信頼で結ばれている。ZAMLT期にはナノハッキング技術を駆使してバイオリアクター妨害活動を展開し、E525年のマトリカル・リフォーム運動でも中心的役割を果たす。",descriptionEn:"The male leader of the Shadow Union, a veteran fighter who has led anti-establishment movements since around E330. An ally of Ayaka Rin since the Slime Crisis, they are bound by absolute trust in each other. During the ZAMLT era, they employed nano-hacking technology to conduct bio-reactor interference activities and played a central role in the E525 Matricular Reform Movement.",era:"E330〜",affiliation:"シャドウ・ユニオン",tier:"Tier 2",image:"https://raw.githubusercontent.com/gentaron/image/main/Garo.png"},{id:"アヤカ・リン",name:"アヤカ・リン",nameEn:"Ayaka Rin",category:"キャラクター",subCategory:"Eros-7",description:"Lv.842。搾精生物専門ハンター。マトリカル・リフォーム運動を組織。E380年のスライム危機では、ビキニバリア・カウパー波を駆使してアンダーグリッド深部でスライムの巣を破壊。オルタ・フィールド経由で全市民に戦闘記録中継し、英雄的な名声を確立。E525年にはシャドウ・ユニオン男性リーダー・ガロや女性商人ゼナと同盟を結び、労働時間短縮・ジーン・カタログ男女平等化を掲げるマトリカル・リフォーム運動を本格的に組織。Eros-7社会変革の原動力。",descriptionEn:"Level 842. A specialized hunter for extraction organisms. Organized the Matricular Reform Movement. During the E380 Slime Crisis, they utilized the Bikini Barrier Koupa wave to destroy slime nests deep in the Undergrid, broadcasting combat records to all citizens via the Alta Field, establishing a heroic reputation. In E525, they formed an alliance with Shadow Union male leader Garo and female merchant Zena, formally organizing the Matricular Reform Movement advocating for reduced working hours and gender equality in the Gene Catalog. The driving force behind social change in Eros-7 society.",era:"E380〜現在",affiliation:"シャドウ・ユニオン / マトリカル・リフォーム運動",tier:"Tier 1",image:"https://raw.githubusercontent.com/gentaron/image/main/AyakaRin.png"},{id:"カステリア・グレンヴェルト",name:"カステリア・グレンヴェルト",nameEn:"Casteria Grenvelt",category:"キャラクター",subCategory:"Gigapolis",description:"カスチーナ・テンペスト（Castina Tempest、クロセヴィア首脳）とは別人。Gigapolis西大陸を拠点とする人物。クレセント地方の政治情勢とは直接的な関わりを持たないが、西大陸の社会における独自の視点を提供する存在。",descriptionEn:"A separate individual from Castina Tempest (leader of Crosevia). Based in Gigapolis' Western Continent. While not directly involved in the political situation of the Crescent Region, this individual offers a unique perspective on society in the Western Continent.",era:"不詳",affiliation:"Gigapolis西大陸",tier:"Tier 2",image:"https://raw.githubusercontent.com/gentaron/image/main/CasteriaGrenvelt.png",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/kasuteriasan.txt",label:"Casteria Grenvelt's Story"}]},{id:"シトラ・セレス",name:"シトラ・セレス",nameEn:"Sitra Celes",category:"キャラクター",subCategory:"Gigapolis",description:"E16連星系のどこかで活動する個人。EDU世界の主要な事件群とは別の視点から世界を体験する存在。",descriptionEn:"An individual active somewhere in the E16 star system. An existence that experiences the world from a perspective separate from the major events of the EDU universe.",era:"不詳",affiliation:"不詳",tier:"Tier 2",image:"https://raw.githubusercontent.com/gentaron/image/main/SitraCeles.png",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/sitra.txt",label:"Sitra Celes's Story"}]},{id:"ミュー",name:"ミュー",nameEn:"Myu",category:"キャラクター",subCategory:"Gigapolis",description:"E16連星系における個人の物語を軸に、英雄たちとは異なる規模の、しかし等しくEDU世界の一部である生活と冒険を描く。テクノ文化ルネサンス（E475〜E500）以降の現代社会を舞台にしている可能性が高い。",descriptionEn:"Centered on the personal stories of individuals in the E16 star system, it depicts lives and adventures on a different scale from heroes, yet equally part of the EDU world. Likely set in contemporary society after the Techno-Cultural Renaissance (E475-E500).",era:"不詳",affiliation:"不詳",tier:"Tier 2",image:"https://raw.githubusercontent.com/gentaron/image/main/Myu.png",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/Myustory.txt",label:"Myu's Story"}]},{id:"ジュン",name:"ジュン",nameEn:"Jun",category:"キャラクター",subCategory:"Gigapolis",description:"Slime Woman（E340年ペルセポネ事故で顕現した高次元存在）との特異な相互作用を持つ人物。高次元存在であるSlime Womanが人間社会でどのように振る舞うのか、そして特定の個人との間に何が生じるのかを描く、EDU宇宙論にとって重要な物語。",descriptionEn:"An individual with a unique interaction with Slime Woman (a higher-dimensional being that manifested during the Persephone Incident in E340). This important story for EDU cosmology explores how the higher-dimensional Slime Woman behaves in human society and what emerges between her and specific individuals.",era:"E340以降〜現在",affiliation:"不詳（Slime Womanとの関連）",tier:"Tier 2",image:"https://raw.githubusercontent.com/gentaron/image/main/Jun.png",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/Junandslime.txt",label:"Jun's Story"}]},{id:"アルゼン・カーリーン",name:"アルゼン・カーリーン",nameEn:"Alzen Carine",category:"キャラクター",subCategory:"宇宙勢力",description:"グランベル大統領。宇宙最大の経済圏を率いる指導者。第一回宇宙連合会合で「争いを超え、共存と繁栄の道を見つけることが次世代への責任」と演説。首都オルダシティで会合を主催し、宇宙秩序の構築に主導的な役割を果たしているが、その圧倒的な経済力に対して他勢力から「経済的従属を招くのではないか」という懸念も抱かれている。",descriptionEn:"President Granbel. The leader of the universe's largest economic bloc. At the first United Cosmic Assembly, he delivered a speech stating: 'Transcending conflict and finding a path to coexistence and prosperity is our responsibility to the next generation.' Hosting the assembly in the capital city of Oldacity, he plays a leading role in building cosmic order, yet his overwhelming economic power raises concerns among other factions about potentially leading to economic subjugation.",era:"現在（E528〜）",affiliation:"グランベル",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/eduuni.txt",label:"eduuni.txt"}]},{id:"グレイモンド・ハウザー",name:"グレイモンド・ハウザー",nameEn:"Greymond Hauser",category:"キャラクター",subCategory:"宇宙勢力",description:"ティエリア総帥。宇宙最強の軍事力を指揮する。第一回宇宙連合会合で「軍事力なくして平和は守れない。力がなければ、秩序は保てない」と演説し、エレシオン女王リアナと対立。グランベルのアルゼン大統領に対しても「その言葉を信用するかは、具体的な行動を見てからだ」と懐疑的な姿勢を示した。ヘゲモニー・パラドックスの危険性を認識しつつも、ティエリアの安全保障を最優先としている。",descriptionEn:"Supreme Commander Tieria. Commands the universe's strongest military force. At the first United Cosmic Assembly, he delivered a speech stating: 'Peace cannot be protected without military strength. Without power, order cannot be maintained,' coming into conflict with Queen Ellesia of Elesion. He also expressed skepticism toward President Arzen of Granbel, saying: 'Whether I trust those words depends on seeing concrete actions.' While recognizing the danger of the Hegemony Paradox, he prioritizes Tieria's security above all else.",era:"現在（E528〜）",affiliation:"ティエリア",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/eduuni.txt",label:"eduuni.txt"}]},{id:"女王リアナ・ソリス",name:"女王リアナ・ソリス",nameEn:"Queen Liana Solis",category:"キャラクター",subCategory:"宇宙勢力",description:"エレシオンの女王。医療技術と環境再生技術をリードし、平和主義・技術共有推進の外交姿勢で多くの小規模文明から支持を得ている。第一回宇宙連合会合でティエリアの軍拡に真っ向から反対し、「軍拡はさらなる争いを招くだけです」と主張。会合後はエレシオンの医療・環境技術で宇宙全体を再構築する使命を確認した。",descriptionEn:"Queen of Elesion. Leading in medical technology and environmental regeneration technology, she gains support from many small civilizations through her diplomatic stance of pacifism and technological sharing. At the first United Cosmic Assembly, she directly opposed Tieria's military expansion, stating: 'Military expansion will only lead to further conflict.' After the assembly, she confirmed her mission to reconstruct the entire universe using Elesion's medical and environmental technologies.",era:"現在（E528〜）",affiliation:"エレシオン",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/eduuni.txt",label:"eduuni.txt"}]},{id:"マドリス・カーネル",name:"マドリス・カーネル",nameEn:"Madrisernel",category:"キャラクター",subCategory:"宇宙勢力",description:"ファルージャ評議会代表。宇宙中の文明間交流を主導し、対立する勢力間の調停役として機能している。第一回宇宙連合会合でグランベルの経済的支配に対する懸念を表明し、ディオクレニスの宇宙共同探査提案にエレシオンとともに支持。「文化の力が宇宙全体を結びつける鍵になる」と信じ、文化交流強化計画を推進。",descriptionEn:"Representative of the Faluja Council. Leading inter-civilizational exchange across the universe and functioning as a mediator between opposing forces. At the first United Cosmic Assembly, he expressed concerns about Granbel's economic dominance and supported Dioclenis' proposal for joint cosmic exploration alongside Elesion. Believing that 'the power of culture is the key that binds the entire universe,' he promotes plans to strengthen cultural exchange.",era:"現在（E528〜）",affiliation:"ファルージャ",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/eduuni.txt",label:"eduuni.txt"}]},{id:"ネイサン・コリンド",name:"ネイサン・コリンド",nameEn:"Nathan Corlind",category:"キャラクター",subCategory:"宇宙勢力",description:"ディオクレニス科学宰相。宇宙探査と科学技術研究の最前線を担う。第一回宇宙連合会合で最も重要な役割を果たし、「ヘゲモニー・パラドックス」の危険性を科学的に指摘。対立のエネルギーを共同宇宙探査へ転換する提案を行い、平和協定・UECO設立・技術共有・文化交流拡大の4つの具体的提案を実施。会合後は全勢力参加の共同宇宙探査プロジェクト立案に没頭している。",descriptionEn:"Scientific Chancellor Dioclenis. At the forefront of cosmic exploration and scientific technology research. Played the most important role at the first United Cosmic Assembly, scientifically pointing out the dangers of the 'Hegemony Paradox.' He proposed converting the energy of conflict into joint cosmic exploration and implemented four concrete proposals: peace agreements, establishment of UECO, technology sharing, and expansion of cultural exchange. After the assembly, he has been immersed in planning a joint cosmic exploration project involving all factions.",era:"現在（E528〜）",affiliation:"ディオクレニス",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/eduuni.txt",label:"eduuni.txt"}]},{id:"ロナン・アーサ",name:"ロナン・アーサ",nameEn:"Ronan Arthur",category:"キャラクター",subCategory:"宇宙勢力",description:"アポロン文明圏のリーダー。騎士団の頂点に立つ英雄的存在。中核惑星アポロン・セントラリスを拠点とし、最盛期のGDPは125兆ドルに達した。セリアに同盟・共存を提案したが拒絶され、全面戦争に至る。ケンタウロスレーザー発射を命じたが、最終的にセリアのヴェノム艦隊がアポロン・セントラリスを攻略し、ロナンは戦死。アポロン文明圏は壊滅的損害を受けた。",descriptionEn:"Leader of the Apollo civilization zone. A heroic existence standing at the pinnacle of the knightly order. Based on the core planet Apollo Centralis, its GDP reached 125 trillion dollars at its peak. He proposed alliance and coexistence to Seria but was rejected, leading to all-out war. He ordered the firing of the Centaurus Laser, but ultimately Seria's Venom fleet captured Apollo Centralis and Ronan died in battle. The Apollo civilization zone suffered catastrophic damage.",era:"大戦期（歴史上）",affiliation:"アポロン文明圏",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/eduuni.txt",label:"eduuni.txt"}]},{id:"グリム・ダルゴス",name:"グリム・ダルゴス",nameEn:"Grim Dargos",category:"キャラクター",subCategory:"宇宙勢力",description:"エヴァトロン初代リーダー。何世代にもわたる男尊女卑の文化を基盤とした銀河系を統治。セリアが次元エネルギー技術を提供条件に同盟を求めた際、文化的価値観が真逆でありながらも実利的な同盟を成立させた。その後、アポロン・Dominion大戦に参戦し、戦後は疲弊したDominionを買収・吸収してE16系を支配した。",descriptionEn:"The first leader of Evatron. Ruled the galaxy based on a culture of male dominance spanning generations. When Seria proposed an alliance on the condition of providing dimensional energy technology, he established a pragmatic alliance despite their cultural values being polar opposites. Later, he participated in the Apollo-Dominion War, and after the war, purchased and absorbed the exhausted Dominion, coming to rule the E16 system.",era:"歴史上",affiliation:"エヴァトロン",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/eduuni.txt",label:"eduuni.txt"}]},{id:"マスター・クインシアス",name:"マスター・クインシアス",nameEn:"Master Quinsias",category:"キャラクター",subCategory:"宇宙勢力",description:"グランベルの初期リーダー。崩壊したDominionのセリア時代を高く評価し、「セリア時代こそが、宇宙史で最も成功した時代だった。あの時代は、技術革新と社会秩序が完全に調和していた」と残した。グランベルをセリアの後継的な存在として位置づけた。",descriptionEn:"An early leader of Granbel. He highly evaluated the Seria era of the collapsed Dominion, leaving behind the words: 'The Seria era was the most successful era in cosmic history. In that era, technological innovation and social order were perfectly in harmony.' He positioned Granbel as a successor to the Seria era.",era:"歴史上",affiliation:"グランベル",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/eduuni.txt",label:"eduuni.txt"}]},{id:"ヴァイロン・デアクス",name:"ヴァイロン・デアクス",nameEn:"Vylon Deax",category:"キャラクター",subCategory:"宇宙勢力",description:"エヴァトロンの幹部。戦後の疲弊したDominionを買収したエヴァトロンによって、Dominionの統治者に任命された。エヴァトロンの文化と価値観をDominion全土に浸透させようとしたが、セリア時代の自由を経験した住民の激しい反発を招き、毎日のように暴動や抗議が起きた。",descriptionEn:"An executive of Evatron. Appointed as the ruler of Dominion by Evatron, which acquired the war-weary Dominion. Attempted to permeate Dominion with Evatron's culture and values, but this provoked fierce resistance from residents who had experienced the freedom of the Celia era, leading to daily riots and protests.",era:"歴史上",affiliation:"エヴァトロン",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/eduuni.txt",label:"eduuni.txt"}]},{id:"エリオット・シュトラス",name:"エリオット・シュトラス",nameEn:"Elliot Strauss",category:"キャラクター",subCategory:"Gigapolis",description:"ZAMLTの創設者にして最高指導者。20万以上のコーポラトクラシーが乱立するGigapolis経済圏を5超巨大企業に統合し、E301年にZAMLTを設立した冷徹な戦略家。ZAMLTは構成企業の英語名の頭文字をとった名称であり、ゼブラ・コーポレーション（Z）、アロエオイル・コーポレーション（A）、マモン・コーポレーション（M）、ルレンツ・コーポレーション（L）、トロン・コーポレーション（T）の五大企業を傘下に収め、E16連星系の金融取引の95%を掌握した。彼の経済覇権はコーポラトクラシー体制の最終形態であり、エル・フォルハウスのマーストリヒト革命（E150年）が開いた自由経済の道を、極めて少数のエリートによる中央集権的支配へと逆転させた。ZAMLT本社の最深部に建造された次元の塔（Dimensional Tower）とカタリスト・コアの構想も彼によるものとされる。E318年のアルファ・ケインによるギガポリス解放戦でZAMLTは崩壊し、シュトラスは権力の座から転落した。彼の遺産はnトークン経済システムやA-Registryの階級制度として現在もE16文明圏に根を下ろしており、その影響は銀河系コンソーシアムの経済框架にも波及している。",descriptionEn:"Founder and supreme leader of ZAMLT. A cold-blooded strategist who consolidated over 200,000 corporatocracies in the Gigapolis economic zone into five mega-corporations and established ZAMLT in E301. ZAMLT is an acronym for the English names of its constituent corporations: Zebra Corporation (Z), Aloe Oil Corporation (A), Mammon Corporation (M), Lorentz Corporation (L), and Thorne Corporation (T), which brought five major enterprises under its umbrella and controlled 95% of financial transactions in the E16 star system. His economic hegemony represented the ultimate form of corporatocracy, reversing the path of free economy opened by the Maastricht Revolution of El Forhaus (E150) into centralized rule by a tiny elite. The Dimensional Tower and Catalyst Core, constructed in the deepest depths of ZAMLT headquarters, are also attributed to him. ZAMLT collapsed during the Gigapolis Liberation War by Alpha Cain in E318, and Strass fell from power. His legacy continues to take root in the E16 civilization zone through the n-token economic system and the A-Registry class hierarchy, with its influence extending even to the economic framework of the Galactic Consortium.",era:"E301〜E318",affiliation:"ZAMLT",tier:"歴史的人物"},{id:"アレン",name:"アレン",nameEn:"Allen",category:"キャラクター",subCategory:"Gigapolis",description:"コーポラトクラシー「ストロベリー」のCEOであり、nebura（星々の交響曲）の物語の序盤における重要人物。ZAMLTをはじめとするメタ企業の圧力に抵抗する中堅コーポラトクラシーの経営者として、終末の星（Star of the End）計画への関与を通じて物語の転回点を担う。アルファ・ケインをスティル・アレーナに推薦し、彼がZAMLTに対する反乱を主導する契機を作った。しかしZAMLTとEVILSの秘密会合の真相を追及した結果、ゼブラ・コーポレーションの工作員レイ・ヴァンデルトによってシェンドバーグ次元に閉じ込められ、殺害された。アレンの死はアルファ・ケインとテクロサスを結ぶ決定的な動機となり、ZAMLTに対する全面対決への道を開いた。中堅コーポラトクラシーの代表者として、ZAMLTの覇権体制下で多数のコーポラトクラシーが直面した絶望的な状況を体現する存在である。",descriptionEn:"CEO of the corporatocracy 'Strawberry' and a key figure in the early narrative of nebura (Symphony of Stars). As a mid-level corporatocracy executive resisting the pressure of meta-corporations including ZAMLT, he plays a pivotal role in the story's turning point through his involvement in the Star of the End plan. Recommended Allen Still Arena to Alpha Cain, creating the opportunity for him to lead a rebellion against ZAMLT. However, while pursuing the truth behind the secret meeting between ZAMLT and EVILS, he was trapped in the Schendberg dimension and killed by Zebra Corporation operative Ray Vanderdelt. Allen's death became the decisive motive connecting Alpha Cain and Techlosus, opening the path to a full confrontation with ZAMLT. As a representative of mid-level corporatocracies, he embodies the desperate situation faced by numerous corporatocracies under ZAMLT's hegemonic regime.",era:"E318年前後",affiliation:"ストロベリー",tier:"歴史的人物",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/nebura.txt",label:"Alpha Cain & Celia Dominix's Story"}]},{id:"大司教",name:"大司教",nameEn:"Archbishop",category:"キャラクター",subCategory:"宇宙勢力",description:"エレシュ文明圏の最高指導者であり、オラクル（大司教＋神官長）の議長を務める宗教的最高権威。オラクルの次元共鳴予言は極めて高い的中率を誇り、グランベルのアルゼン・カーリーン大統領やティエリアのグレイモンド・ハウザー総帥ですらその発言を無視できない存在。大司教は宗教指導者としてだけでなく、宇宙規模の政治的調停者としても機能しており、ティエリアとエレシオンの対立緩和やグランベルの経済的拡張への牽制など、軍事・経済とは異なるアプローチで宇宙の安定に寄与している。ファルージャのマドリス・カーネルとは古くから個人的な信頼関係にあり、文化的・精神的影響力を背景にした外交を展開している。大司教の任期は終身制であり、後継者はオラクルによる厳格な選考プロセスを経て決定される。その精神的影響力は、実質的にE16文明圏のAURALISとも思想的な共鳴を持つと指摘されている。",descriptionEn:"Supreme leader of the Elesh civilization zone and chairman of the Oracle (Archbishop + High Priest), the highest religious authority. The Oracle's dimensional resonance prophecies boast an extremely high accuracy rate, making its statements impossible to ignore even for President Arsen Karline of Granbel and Commander-in-Chief Graymond Houser of Tieria. The Archbishop functions not only as a religious leader but also as a political mediator on a cosmic scale, contributing to cosmic stability through approaches different from military and economic means, such as easing tensions between Tieria and Elesion and restraining Granbel's economic expansion. Shares a personal relationship of trust with Madris Karnel of Faluja, conducting diplomacy backed by cultural and spiritual influence. The Archbishop's term is for life, and successors are determined through a rigorous selection process by the Oracle. It has been pointed out that the Archbishop's spiritual influence essentially shares ideological resonance with the AURALIS of the E16 civilization zone.",era:"現在（E528〜）",affiliation:"エレシュ",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/eduuni.txt",label:"eduuni.txt"}]},{id:"商工会議長",name:"商工会議長",nameEn:"Chamber of Commerce Chairman",category:"キャラクター",subCategory:"宇宙勢力",description:"プロキオ文明圏の最高指導者であり、全宇宙の貿易ルートと商業取引を統括する実力者。プロキオ・ネクサスを本拠地とし、コマース・ディヴィジョンを通じて宇宙最大の商業システムを管理している。商工会議長の経済的影響力は直接的であり、プロキオ・ネクサスでの価格設定が宇宙全体のベースライン価格を決定するため、その判断は全文明圏の経済に波及する。Lane Systemのオープンアーキテクチャ設計によりグランベルやエレシオンにもプロキオの物流インフラが統合されており、商工会議長の政策は宇宙規模の供給網に直結している。グランベルのアルゼン大統領とは経済分野で協調関係にあり、ティエリアへの軍事物資の物流管理も担っている。全宇宙の経済安定を維持する役割を自負し、紛争下でも商人の安全な通行を確保するための外交努力を惜しまない実務的な指導者として知られる。",descriptionEn:"Supreme leader of the Prokio civilization zone and a powerful figure overseeing all interstellar trade routes and commercial transactions. Headquartered at Prokio Nexus, manages the universe's largest commercial system through the Commerce Division. The Chamber President's economic influence is direct, as price setting at Prokio Nexus determines the baseline price for the entire universe, making their decisions ripple across all civilization zones. Through the open architecture design of the Lane System, Prokio's logistics infrastructure has been integrated with Granbel and Elesion, connecting the Chamber President's policies to a universal supply network. Maintains a cooperative relationship with President Arsen of Granbel in economic matters and also manages logistics for military supplies to Tieria. Known as a practical leader who takes pride in maintaining economic stability across the universe and spares no diplomatic effort to ensure safe passage for merchants even during conflicts.",era:"現在（E528〜）",affiliation:"プロキオ",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/eduuni.txt",label:"eduuni.txt"}]},{id:"通信長官",name:"通信長官",nameEn:"Communications Commissioner",category:"キャラクター",subCategory:"宇宙勢力",description:"ロースター文明圏の最高指導者であり、全宇宙の通信インフラと量子ネットワークの管理を統括する技術官僚のトップ。ロースター・コアの量子コンピューティングセンターを指揮し、Link Protocol（現在バージョン7.2）の開発と標準化を主導した。通信長官の管轄下でシグナル・オペレーションが数千の通信衛星を管理し、宇宙全域に1光年あたり0.3秒以下の通信遅延を実現している。ティエリアの防衛ネットワークとの接続やディオクレニスとのクアンタ・ラボ共同研究など、軍事・科学分野でも重要な役割を果たす。グランベルの量子経済システムやエレシオンの医療データネットワークもロースターの通信基盤に依存しており、通信長官の判断は宇宙全体の情報の流れを左右する。オープンイノベーションモデルの推進者であり、新技術を数ヶ月で全宇宙に展開する迅速な技術普及体制を構築した。次元不安定の早期警戒システムの構築も通信長官の業績の一つである。",descriptionEn:"Supreme leader of the Roaster civilization zone and the top technical bureaucrat overseeing all interstellar communication infrastructure and quantum networks. Commands the quantum computing center of Roaster Core and led the development and standardization of Link Protocol (current version 7.2). Under the Communications Director's jurisdiction, Signal Operations manages thousands of communication satellites, achieving communication delays of less than 0.3 seconds per light-year across the entire universe. Plays important roles in military and scientific fields, such as connecting with Tieria's defense networks and joint research with Dioclenis on the Quanta Lab. Granbel's quantum economic system and Elesion's medical data network also depend on Roaster's communication infrastructure, making the Communications Director's decisions affect the flow of information throughout the universe. A proponent of open innovation models, he has established a rapid technology dissemination system that deploys new technologies across the universe within months. The construction of an early warning system for dimensional instability is also one of the Communications Director's achievements.",era:"現在（E528〜）",affiliation:"ロースター",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/eduuni.txt",label:"eduuni.txt"}]},{id:"ラファエル・ドレイク",name:"ラファエル・ドレイク",nameEn:"Rafael Drake",category:"キャラクター",subCategory:"ZAMLT",description:"トロン・コーポレーションのCEOであり、ZAMLTを構成する5大超巨大企業のうちの一つを率いた指導者。旗艦「カリバーン」を指揮し、ZAMLTの宇宙軍事力の中核を担った。E318年のギガポリス解放戦においてアルファ・ケインによって打倒された。",descriptionEn:"CEO of Thorne Corporation and leader of one of the five mega-corporations comprising ZAMLT. Commanded the flagship 'Caliburn' and formed the core of ZAMLT's military power. Overthrown by Alpha Cain during the Gigapolis Liberation War in E318.",era:"E301〜E318",affiliation:"トロン・コーポレーション / ZAMLT",tier:"歴史的人物"},{id:"アイリス・ノヴァ",name:"アイリス・ノヴァ",nameEn:"Iris Nova",category:"キャラクター",subCategory:"ZAMLT",description:"アロエオイル・コーポレーションのリーダーであり、次元エネルギー技術の専門家。nebura（星々の交響曲）の最終盤において、アルファ・ケインのチームと次元の荒野で決戦を繰り広げた。次元エネルギーの深い知識を持つ技術者としてZAMLTの次元兵器開発にも関与したとされる。",descriptionEn:"Leader of the Aloe Oil Corporation and an expert in dimensional energy technology. In the final act of nebura (Symphony of Stars), he engaged in a decisive battle with Alpha Cain's team in the dimensional wilderness. As a technician with deep knowledge of dimensional energy, he is also said to have been involved in ZAMLT's dimensional weapons development.",era:"E301〜E318",affiliation:"アロエオイル・コーポレーション / ZAMLT",tier:"歴史的人物"},{id:"カルロス・ヴァンダム",name:"カルロス・ヴァンダム",nameEn:"Carlos Vandam",category:"キャラクター",subCategory:"ZAMLT",description:"マモン・コーポレーションのリーダー。慎重な戦略家として知られ、ZAMLTの経済的基盤の強化に尽力した。プロトコルXの3京ドル資金計画を立案し、ZAMLTの覇権体制を財政面から支えた。その冷徹な計算高い手腕はZAMLT支配期の経済的二極化を加速させた一因とも評される。",descriptionEn:"Leader of Mammon Corporation. Known as a cautious strategist who dedicated himself to strengthening ZAMLT's economic foundation. Formulated the Protocol X 300 trillion dollar funding plan, supporting ZAMLT's hegemonic regime financially. His cold, calculating skills are also cited as a factor accelerating the economic polarization during ZAMLT's rule.",era:"E301〜E318",affiliation:"マモン・コーポレーション / ZAMLT",tier:"歴史的人物"},{id:"アーサー・グリム",name:"アーサー・グリム",nameEn:"Arthur Grim",category:"キャラクター",subCategory:"ZAMLT",description:"ゼブラ・コーポレーションのリーダー。次元技術・次元兵器・次元刑務所の設計を独占する異常なまでの技術垄断体制を築き上げた。ゼブラ・コーポレーションはZAMLTの中で最も危険な企業と評され、アーサーの下で次元干渉技術の軍事転用が急速に進められた。工作員レイ・ヴァンデルトによるアレンの殺害も彼の指示によるものとされる。",descriptionEn:"Leader of Zebra Corporation. Built up an extraordinary technological monopoly by exclusively designing dimensional technology, dimensional weapons, and dimensional prisons. Zebra Corporation is rated as the most dangerous enterprise within ZAMLT, and under Arthur's leadership, the military application of dimensional interference technology rapidly advanced. The murder of CEO Allen by operative Ray Vanderdelt is also said to have been under his instructions.",era:"E301〜E318",affiliation:"ゼブラ・コーポレーション / ZAMLT",tier:"歴史的人物"},{id:"エリザベス・リンドバーグ",name:"エリザベス・リンドバーグ",nameEn:"Elizabeth Lindberg",category:"キャラクター",subCategory:"ZAMLT",description:"ルレンツ・コーポレーションのリーダー。プロトコルXの技術設計とカタリスト・コア建造を主導したZAMLTの技術的支柱。次元エネルギーの制御と増幅に関する最先端の研究を指揮し、ZAMLT本社最深部に建造された次元の塔とカタリスト・コアの実現に決定的な役割を果たした。",descriptionEn:"Leader of Lorentz Corporation. The technological pillar of ZAMLT who led the technical design of Protocol X and the construction of the Catalyst Core. Directed cutting-edge research on the control and amplification of dimensional energy, playing a decisive role in realizing the Dimensional Tower and Catalyst Core constructed in the deepest depths of ZAMLT headquarters.",era:"E301〜E318",affiliation:"ルレンツ・コーポレーション / ZAMLT",tier:"歴史的人物"},{id:"レイ・ヴァンデルト",name:"レイ・ヴァンデルト",nameEn:"Ray Vandelte",category:"キャラクター",subCategory:"ZAMLT",description:"ゼブラ・コーポレーションの工作員。アーサー・グリムの指示のもと、ZAMLTとEVILSの秘密会合の真相を追及していたコーポラトクラシー「ストロベリー」のCEOアレンをシェンドバーグ次元に閉じ込めて殺害した冷徹な実行部隊の要員。アレンの死はアルファ・ケインとテクロサスを結ぶ決定的な動機となり、ZAMLTに対する全面対決への道を開いた。",descriptionEn:"An operative of Zebra Corporation. Under the orders of Arthur Grimm, he was a cold-blooded operative who trapped and killed CEO Allen of the corporatocracy 'Strawberry,' who was investigating the truth behind the secret meeting between ZAMLT and EVILS, in the Schendberg dimension. Allen's death became the decisive motive connecting Alpha Cain and Techlosus, opening the path to a full confrontation with ZAMLT.",era:"E318年頃",affiliation:"ゼブラ・コーポレーション / ZAMLT",tier:"歴史的人物"},{id:"リンダ",name:"リンダ",nameEn:"Linda",category:"キャラクター",subCategory:"ZAMLT",description:"ルレンツ・コーポレーションの研究員。シルバープラント攻略戦において、プロトコルXのエネルギーコアの暴走を安定化させるため自らを犠牲にした悲劇の英雄。彼女の自己犠牲はアルファ・ケインにZAMLT打倒への決意を固めさせ、シャドウ・リベリオンの士気を大きく高めた。ルレンツ・コーポレーション内部でも反ZAMLT感情の広がる転換点となった。",descriptionEn:"A researcher at the Lorenz Corporation. During the Silver Plant offensive operation, she became a tragic hero by sacrificing herself to stabilize the runaway energy core of Protocol X. Her self-sacrifice solidified Alpha Kane's determination to defeat ZAMLT and greatly boosted the morale of the Shadow Rebellion. It also marked a turning point within the Lorenz Corporation, spreading anti-ZAMLT sentiments throughout the organization.",era:"E318年",affiliation:"ルレンツ・コーポレーション / ZAMLT",tier:"歴史的人物"},{id:"クロノ・ヴァーレント",name:"クロノ・ヴァーレント",nameEn:"Chrono Valeint",category:"キャラクター",subCategory:"Gigapolis",description:"テクロサスの指導者の一人。シルバープラント攻略戦でアルファ・ケインと共に戦い、ZAMLT打倒の軍事的支柱として重要な役割を果たした。テクロサス系譜（E15ファランクス〜E295三頭政治〜E470東方支隊〜現在のボグダス・ジャベリン）の中で中核的な役割を担った軍人であり、その軍事的伝統は現在のセバスチャン・ヴァレリウス率いるボグダス・ジャベリンに受け継がれている。",descriptionEn:"One of the leaders of Tectlos. He fought alongside Alpha Kane during the Silver Plant offensive operation, playing a crucial role as the military pillar in the fight against ZAMLT. A military figure who played a central role in the Tectlos lineage (E15 Phalanx to E295 Triumvirate to E470 Eastern Detachment to the current Bogdus Javelin), his military tradition is now carried on by the Bogdus Javelin led by Sebastian Valerius.",era:"E318年頃",affiliation:"テクロサス",tier:"歴史的人物"},{id:"オメガ＝ユリシス",name:"オメガ＝ユリシス",nameEn:"Omega=Ulysses",category:"キャラクター",subCategory:"宇宙勢力",description:"EVILS（超越的次元間生命体群）のリーダー。虚無の塔でZAMLT5社のトップと秘密会合を持ち、次元の塔を通じた取引を行った。次元の塔での最終決戦でアルファ・ケインと激突し、伴共役（Ban-Kyōyaku）能力によって次元の繊維に封印された。EVILSは通常の物理法則を超越した存在であり、オメガ＝ユリシスの封印はEDU宇宙論における次元干渉の限界と可能性を示す出来事として記録されている。",descriptionEn:"The leader of EVILS (Transdimensional Lifeforms). He held a secret meeting with the head of ZAMLT 5 at the Tower of Nothingness and conducted transactions through the Dimensional Towers. In the final decisive battle at the Dimensional Towers, he clashed with Alpha Kane and was sealed within the dimensional fibers by his Ban-Kyōyaku (Conjugate Pair) ability. EVILS exist beyond conventional physical laws, and the sealing of Omega-Ulysses is recorded as an event that demonstrates the limits and possibilities of dimensional interference in EDU cosmology.",era:"E318年頃",affiliation:"EVILS",tier:"神格・歴史的人物（次元間存在）"},{id:"ファランクス（初代皇帝）",name:"ファランクス（初代皇帝）",nameEn:"Phalanx",category:"キャラクター",subCategory:"宇宙勢力",description:"バーズ帝国の初代皇帝。E15年に軍閥ファランクスを率いてE16連星系の初期植民地間紛争を武力によって終結させ、連星系初の包括的統一政権バーズ帝国を樹立した。ファランクスは帝国という名称ながらも、初期の入植者自治の伝統を尊重し、各省庁に相当する地方総督府制度を導入した。E61年の死後、後継者争いによって帝国は分裂したが、その軍事伝統はテクロサス系譜として受け継がれ、現在のボグダス・ジャベリンに至っている。",descriptionEn:"The first Emperor of the Bartz Empire. In E15, he led the military faction Phalanx to forcefully end the initial colonial disputes among the E16 star system's colonies, establishing the Bartz Empire—the first comprehensive unified government in the star system. Though called an empire, Phalanx respected the tradition of early settler autonomy and introduced a system of regional governorates equivalent to various ministries. After his death in E61, the empire split due to succession disputes, but its military tradition was carried on through the Tectlos lineage, continuing to the present Bogdus Javelin.",era:"E15〜E61",affiliation:"バーズ帝国",tier:"歴史的人物"},{id:"セルヴァ・ドーン",name:"セルヴァ・ドーン",nameEn:"Selva Dawn",category:"キャラクター",subCategory:"Iris/クレセント",description:"SUDOMの初代医療総裁。E480年代に医療研究特別植民地だったSUDOMを国家へと昇格させ、遺伝子医療と再生医療の分野でE16文明圏の最先端を走る医療国家の基盤を築いた。スライム危機後のリーチ・ドレイン対策医療において中心的役割を果たし、V7加盟後は同盟の医療支援と疫学調査を統括した。",descriptionEn:"The first Medical Director of SUDOM. In the E480s, she elevated the special medical research colony of SUDOM to nation status, establishing the foundation for a medical state at the forefront of the E16 civilization in the fields of genetic and regenerative medicine. She played a central role in post-Slime Crisis Leech Drain countermeasures, and after joining V7, she coordinated the alliance's medical support and epidemiological investigations.",era:"E480〜",affiliation:"SUDOM",tier:"Tier 2"},{id:"ハシーム・ファティマ",name:"ハシーム・ファティマ",nameEn:"Hashim Fatima",category:"キャラクター",subCategory:"Iris/クレセント",description:"ファティマ連邦の初代連邦議長。E400年代に分散する複数の自治州を緩やかな連合に統合し、宗教的・哲学的自由を重んじる連邦国家の基盤を築いた。ファティマ連邦の名称は彼の家族名に由来する。最小限の統治構造を採る分散型モデルを確立し、ネオクラン同盟の理念と共鳴する外交路線を推進した。",descriptionEn:"The first Federal Chairman of the Fatima Federation. In the E400s, he integrated multiple scattered autonomous states into a loose federation, establishing the foundation for a federal state that valued religious and philosophical freedom. The name of the Fatima Federation derives from his family name. He established a decentralized model with minimal governance structures and pursued a diplomatic route that resonated with the ideals of the Neo-Clan Alliance.",era:"E400〜",affiliation:"ファティマ連邦",tier:"Tier 2"},{id:"トリスタン・スターク",name:"トリスタン・スターク",nameEn:"Tristan Stark",category:"キャラクター",subCategory:"Iris/クレセント",description:"スターク三国軍事理事長。E480年代に三国の防衛同盟を近代化し、他勢力への依存を避ける自律的安全保障体制を強化した。V7やトリニティ・アライアンスのいずれにも属さない独自路線を堅持し、クレセント地方の第三勢力として中立地帯の防衛を担う。質量ともに高く評価されるスターク三国軍事力の近代化の立役者。",descriptionEn:"The Military Director of the Stark Triumvirate. In the E480s, he modernized the tripartite defense alliance and strengthened an independent security system to avoid reliance on other powers. He maintains an independent course, belonging to neither V7 nor the Trinity Alliance, serving as the third power in the Crescent Region and defending neutral territories. He is the key figure behind the modernization of the Stark Triumvirate's military, highly regarded for both its quality and quantity.",era:"E480〜",affiliation:"スターク三国",tier:"Tier 2"},{id:"オーギュスト・ゴールド",name:"オーギュスト・ゴールド",nameEn:"August Gold",category:"キャラクター",subCategory:"Iris/クレセント",description:"ゴールデン・ヴェノムの創設者。シルバー・ヴェノムの内部抗争から独立し、アルファ・ヴェノムの急進的な武力路線に反対してnトークン経済システムへの浸透と金融操作による支配を志向する分派を率いた。表向きは合法的な企業活動を通じて資金を蓄積し、A-Registryシステムへの潜入工作を指揮していると疑われる。その手法は皮肉にもZAMLTの戦略を模倣するものであり、経済的支配による社会変革を最終目標としている。",descriptionEn:"The founder of Golden Venom. Breaking away from the internal strife of Silver Venom, he led a faction that opposed Alpha Venom's radical military approach, instead seeking to infiltrate and dominate through the n-token economic system and financial manipulation. He is suspected of accumulating funds through ostensibly legitimate corporate activities and directing infiltration operations into the A-Registry system. Ironically, his methods mimic ZAMLT's strategies, with economic domination leading to social change as his ultimate goal.",era:"E500〜",affiliation:"ゴールデン・ヴェノム",tier:"Tier 2"},{id:"ルシア・ネオ",name:"ルシア・ネオ",nameEn:"Lucia Neo",category:"キャラクター",subCategory:"Gigapolis",description:"ネオクラン同盟の初代代表。ZAMLT崩壊後の民主化運動の指導者複数名と共同で分散統治モデルの基盤を築いた。地方自治権の強化と市民参加型政治の復興を掲げ、テクノ文化ルネサンス期の「技術の民主化」という精神を政治制度に具体化した。UECO統合後は銀河系コンソーシアムの中核構成体として機能するネオクラン同盟の理念を代表する外交官として活動した。",descriptionEn:"The first representative of the Neo-Clan Alliance. He collaborated with several leaders of the democratization movement following ZAMLT's collapse to establish the foundation of a decentralized governance model. Advocating for strengthened local autonomy and the revival of citizen-participatory politics, he embodied the spirit of 'democratization of technology' from the Techno-Cultural Renaissance into political institutions. After UECO integration, he served as a diplomat representing the Neo-Clan Alliance's ideals as a core component of the Galactic Consortium.",era:"E330〜",affiliation:"ネオクラン同盟",tier:"歴史的人物"},{id:"ヘクトル・ヴァン",name:"ヘクトル・ヴァン",nameEn:"Hector Van",category:"キャラクター",subCategory:"Gigapolis",description:"UECO（星間経済協同組合）の初代議長。テクノ文化ルネサンス期の指導者の一人として、ZAMLT崩壊後の経済的混乱を収束させ、nトークン経済システムの再構築と公正な資源配分を実現した。ヒーローエージェンシーとの統合という独自の組織体制を構築し、経済活動と安全保障の有機的連携を実現した。E495〜E500年の銀河系コンソーシアム設立への移行期を主導した。",descriptionEn:"The first Chairman of UECO (Interstellar Economic Cooperative). As one of the leaders of the Techno-Cultural Renaissance period, he stabilized the economic chaos following ZAMLT's collapse, reconstructing the n-token economic system and achieving fair resource allocation. He built a unique organizational structure through integration with Hero Agencies, realizing organic coordination between economic activities and security. He led the transition period from E495 to E500 during the establishment of the Galactic Consortium.",era:"E400後半〜E500",affiliation:"UECO",tier:"歴史的人物"},{id:"マルクス・アウレリウス",name:"マルクス・アウレリウス",nameEn:"Marcus Aurelius",category:"キャラクター",subCategory:"バーズ帝国",description:"バーズ帝国初期の元老院議長であり、E0年からE35年にかけて帝国の立法基盤を確立した政治家。移民船団の到着直後、混沌とする入植地において法典編纂と市民権の付与ルールを整備し、後の帝国議会制度の原型を構築した。その博愛的な統治方針は「バーズの哲人王」と称され、ティムール・シャーと並ぶE0年代の二大指導者として記憶されている。マルクス法典は現在でもEDU法体系の根幹を成しており、その影響力は星域全体に及んでいる。",descriptionEn:"The inaugural Senate Chairman of the early Barz Empire, who established the legislative foundation of the empire from E0 to E35. Immediately following the arrival of the immigrant fleet, he organized the compilation of codes and rules for granting citizenship amid the chaos of the settlements, constructing the prototype for the later Imperial parliamentary system. His benevolent governance earned him the title 'The Philosopher King of Barz,' and he is remembered as one of the two great leaders of the E0s alongside Timur Shah. The Marcus Code still forms the cornerstone of the EDU legal system, its influence extending across the entire star sector.",era:"E0〜E35",affiliation:"バーズ帝国元老院",tier:"Tier 3"},{id:"イサベラ・コルネリウス",name:"イサベラ・コルネリウス",nameEn:"Isabella Cornelius",category:"キャラクター",subCategory:"バーズ帝国",description:"バーズ帝国初代外務大臣としてE5年からE40年まで活動し、他の入植船団との外交関係構築に尽力した女性政治家。交渉術と語学力に優れ、初期の星域間条約の締結を主導した。特にE15年のファランクス設立に先立ち、テクロサス系軍事組織との協定締結に重要な役割を果たした。彼女の外交路線は「コルネリウス外交」として後世に継承され、バーズ帝国の柔軟な対外政策の基礎を築いた。",descriptionEn:"A female politician who served as the first Foreign Minister of the Barz Empire from E5 to E40, dedicating herself to establishing diplomatic relations with other immigrant fleets. Excelling in negotiation and linguistic skills, she led the conclusion of early interstellar treaties. Particularly crucial was her role in negotiating with the Teklosas military organizations prior to the founding of Phalanx in E15. Her diplomatic policy was inherited by later generations as the 'Cornelius Doctrine,' establishing the foundation for the Barz Empire's flexible foreign policy.",era:"E5〜E40",affiliation:"バーズ帝国外務省",tier:"Tier 3"},{id:"ガイウス・セプティムス",name:"ガイウス・セプティムス",nameEn:"Gaius Septimus",category:"キャラクター",subCategory:"バーズ帝国",description:"バーズ帝国初期の軍事総司令官としてE2年からE45年まで帝国軍の創設と拡充を担った武人。ファランクスの初期編成においてテクロサス軍事教範の導入を推進し、帝国軍の戦闘体系を確立した。E20年の辺境防衛戦では未熟な兵士を率いて小惑星帯の海賊を撃退し、帝国の安全を確保した。厳格な軍規と同時に兵士への配慮も忘れず、将兵からの信頼は極めて厚かった。その軍事的遺産は後のテクロサス三頭政治改編にも影響を与えた。",descriptionEn:"A military commander who served as Supreme Commander of the Barz Empire from E2 to E45, responsible for the creation and expansion of the Imperial military. He promoted the adoption of Teklosas military doctrine in the early formation of Phalanx, establishing the combat system of the Imperial military. In the E20 Border Defense War, he led inexperienced soldiers to repel pirates in the asteroid belt, securing the empire's safety. While maintaining strict military discipline, he never forgot consideration for his soldiers, earning him immense trust from his officers and men. His military legacy also influenced the later Teklosas Triumvirate reorganization.",era:"E2〜E45",affiliation:"バーズ帝国軍",tier:"Tier 3"},{id:"レックス・ドラコ",name:"レックス・ドラコ",nameEn:"Rex Draco",category:"キャラクター",subCategory:"バーズ帝国",description:"バーズ帝国初期の探検家であり、E8年からE50年にかけて未開星域の調査と入植地の選定を行った冒険家。「竜の星」と呼ばれる第3セクターの発見者であり、その過酷な環境下での生存術とNavigation技術は伝説化している。彼が作成した星図「ドラコ・アトラス」は後のギガポリス建設において重要な参考資料となり、E150年のマーストリヒト革命にも間接的な影響を与えた。E50年の最後の探検行で消息不明となったが、彼の足跡は現在でも入植者たちに語り継がれている。",descriptionEn:"An explorer of the early Barz Empire who surveyed uncharted star sectors and selected settlement sites from E8 to E50. He was the discoverer of Sector 3, known as 'Dragon's Star,' and his survival techniques and Navigation skills in its harsh environment have become legendary. The star chart he created, 'Draco Atlas,' became an important reference for the later construction of Gigapolis and indirectly influenced the Maastricht Revolution of E150. He disappeared during his final expedition in E50, but his footsteps are still recounted by settlers to this day.",era:"E8〜E50",affiliation:"バーズ帝国探検局",tier:"Tier 3"},{id:"ヴァレリア・トルクアタ",name:"ヴァレリア・トルクアタ",nameEn:"Valeria Torquata",category:"キャラクター",subCategory:"バーズ帝国",description:"バーズ帝国初代法務大臣としてE10年からE48年まで在任し、帝国の司法制度を設計した法律家。マルクス・アウレリウスの法典を基に、市民裁判制度と刑事手続きの整備を主導した。特に「トルクアタの三原則」と呼ばれる罪刑法定主義・弁護権保障・適正手続の原則は、現在のEDU司法体系にも受け継がれている。厳格だつ正義感の強い性格で知られ、帝国初期の腐敗防止にも大きな役割を果たした。",descriptionEn:"A lawyer who served as the first Minister of Justice of the Barz Empire from E10 to E48, designing the empire's judicial system. Building upon the Marcus Aurelius Code, he led the establishment of citizen trial systems and criminal procedures. Particularly, the 'Three Principles of Torquata'—the principle of legality, the right to counsel, and due process—are still inherited in the current EDU judicial system. Known for his strict sense of justice, he played a major role in preventing corruption during the early empire.",era:"E10〜E48",affiliation:"バーズ帝国法務省",tier:"Tier 3"},{id:"プロフェッサー・クイントゥス",name:"プロフェッサー・クイントゥス",nameEn:"Professor Quintus",category:"キャラクター",subCategory:"バーズ帝国",description:"バーズ帝国アカデミー初代学長としてE3年からE50年まで科学研究と教育の振興に尽くした学者。物理学と数学の権威であり、ティムール・シャーの10次元ホラズム理論の初期検証を行った数少ない科学者の一人。彼が設立した帝国アカデミーは後のギガポリス大学の前身となり、EDU全体の学問発展に多大な影響を与えた。E40年にはペルセポネ・プロジェクトの科学的顧問も務め、仮想多元宇宙の理論的基礎構築に寄与した。",descriptionEn:"A scholar who served as the first Chancellor of the Barz Empire Academy from E3 to E50, dedicating himself to promoting scientific research and education. An authority in physics and mathematics, he was one of the few scientists who conducted initial verification of Timur Shah's ten-dimensional Horazm theory. The Empire Academy he founded later became the predecessor of Gigapolis University, greatly influencing the academic development of the entire EDU. In E40, he also served as scientific advisor to the Persephone Project, contributing to the theoretical construction of the virtual multiverse.",era:"E3〜E50",affiliation:"バーズ帝国アカデミー",tier:"Tier 3"},{id:"ドクター・オクタヴィア",name:"ドクター・オクタヴィア",nameEn:"Doctor Octavia",category:"キャラクター",subCategory:"バーズ帝国",description:"バーズ帝国初代保健衛生大臣としてE5年からE47年まで在任し、入植者の医療・公衆衛生体制を構築した医師。宇宙放射線への対策と感染症予防の基礎研究を主導し、入植初期の死亡率を大幅に低下させた。E25年に発見された異星微生物に対する研究も先駆的であり、その成果はのちのスライム・ウーマン顕現（E340）への学術的対応に間接的に役立った。人道主義的な医療哲学は「オクタヴィア宣言」として現在も医療従事者に継承されている。",descriptionEn:"A physician who served as the first Minister of Health and Sanitation of the Barz Empire from E5 to E47, constructing medical and public health systems for settlers. He led fundamental research on countermeasures against cosmic radiation and infectious disease prevention, significantly reducing mortality rates during the early settlement period. His pioneering research on alien microbes discovered in E25 also indirectly contributed to the academic response to the manifestation of Slime Woman (E340). His humanitarian medical philosophy is still carried on by medical practitioners today as the 'Octavia Declaration.'",era:"E5〜E47",affiliation:"バーズ帝国保健衛生省",tier:"Tier 3"},{id:"ヴェル・ナイアード",name:"ヴェル・ナイアード",nameEn:"Vel Naiad",category:"キャラクター",subCategory:"バーズ帝国",description:"バーズ帝国初期の農業技術者としてE6年からE49年まで活動し、過酷な宇宙環境下での食糧生産システムを開発した実践的技術者。水耕栽培と人工光合成技術の融合により、入植地の食糧自給率を飛躍的に向上させた。「緑の魔術師」と呼ばれ、彼女の開発した「ナイアード・ファーム」システムは後のEros-7における食糧生産にも応用された。農業改革の功績によりE35年に帝国最高科学賞を受賞。",descriptionEn:"A practical engineer who worked as an agricultural technician in the early Barz Empire from E6 to E49, developing food production systems in the harsh space environment. By integrating hydroponics and artificial photosynthesis technology, he dramatically improved the food self-sufficiency rate of the settlements. Called the 'Green Magician,' the 'Naiad Farm' system he developed was later applied to food production in Eros-7. For his contributions to agricultural reform, he received the Empire's highest science award in E35.",era:"E6〜E49",affiliation:"バーズ帝国農業局",tier:"Tier 3"},{id:"カイ・アシュフォード",name:"カイ・アシュフォード",nameEn:"Kai Ashford",category:"キャラクター",subCategory:"バーズ帝国",description:"バーズ帝国初期の通信技術者としてE12年からE50年まで星間通信ネットワークの構築に従事したエンジニア。長距離通信の安定化と暗号化技術の開発において先駆的な業績を残し、初期の帝国通信網「アシュフォード・リンク」の設計者となった。彼の開発した通信プロトコルは後のSSレンジの通信インフラにも影響を与え、クレセント地方の通信網の基礎を築いた。E45年には小惑星帯中継ステーションの建設も指揮した。",descriptionEn:"An engineer who engaged in constructing the interstellar communication network from E12 to E50 in the early Barz Empire. He made pioneering achievements in stabilizing long-distance communication and developing encryption technology, becoming the designer of the early Imperial communication network, the 'Ashford Link.' The communication protocols he developed later influenced the communication infrastructure of SS Range and laid the foundation for the communication network in Crescent Region. In E45, he also commanded the construction of the asteroid belt relay station.",era:"E12〜E50",affiliation:"バーズ帝国通信省",tier:"Tier 3"},{id:"ソル・ブレイズ",name:"ソル・ブレイズ",nameEn:"Sol Blaze",category:"キャラクター",subCategory:"バーズ帝国",description:"バーズ帝国初期のエネルギー技術者としてE8年からE50年まで星間航行用エンジンの改良に取り組んだ天才技術者。太陽風を推進力に変換する「ブレイズ・エンジン」の概念設計を行い、入植船団の航行速度を向上させた。E30年には新型融合炉のプロトタイプを開発し、バーズ帝国のエネルギー安全保障に貢献。その技術的野心は後にテクロサスの軍事技術開発やファールージャ社の次元極地平技術への道を開いたと評されている。",descriptionEn:"A genius technician who worked on improving interstellar engines from E8 to E50 in the early Barz Empire. He conceptualized the 'Blaze Engine,' which converts solar wind into propulsion force, increasing the speed of the immigrant fleet. In E30, he developed a prototype of a new fusion reactor, contributing to the energy security of the Barz Empire. His technical ambition is said to have paved the way for later Teklosas military technology development and Farooja Corporation's dimensional horizon technology.",era:"E8〜E50",affiliation:"バーズ帝国エネルギー局",tier:"Tier 3"},{id:"ルナ・サバイバー",name:"ルナ・サバイバー",nameEn:"Luna Survivor",category:"キャラクター",subCategory:"バーズ帝国",description:"バーズ帝国初期の入植船団生き残りであり、E0年の着陸事故から生還した伝説的な生存者。事故の際、乗組員の避難を指揮し、彼女の機転と判断力が多数の命を救ったとされる。事故後は入植地の建設リーダーとして活躍し、E15年までに初期居住区の基礎インフラを完成させた。「月の生存者」という異名は着陸事故が月面基地で起きたことに由来し、彼女の不屈の精神はバーズ帝国の建国神話の中核をなしている。",descriptionEn:"A survivor of the immigrant fleet of the early Barz Empire and a legendary survivor who escaped the landing accident of E0. During the accident, she is said to have directed the evacuation of crew members, with her quick thinking and judgment saving many lives. After the accident, she served as a construction leader for the settlement, completing the basic infrastructure of the initial residential area by E15. Her nickname, 'The Survivor of the Moon,' derives from the fact that the landing accident occurred at a lunar base, and her indomitable spirit forms the core of the founding myth of the Barz Empire.",era:"E0〜E30",affiliation:"バーズ帝国入植船団",tier:"Tier 3"},{id:"リック・ウォーデン",name:"リック・ウォーデン",nameEn:"Rick Warden",category:"キャラクター",subCategory:"バーズ帝国",description:"バーズ帝国初期の建設技術者としてE2年からE48年まで入植地のインフラ整備を指揮した土木技師。セントラル・タワーの初期設計に携わり、後のギガポリス建設期におけるメガタワー構想の先駆けとなった。E20年の「ウォーデン大惨事」と呼ばれる居住区崩壊事故では、自らの危険を顧みず救助活動を指揮し、多数の命を救った。その献身的な姿勢は「ウォーデン精神」として建設労働者の理想とされ、現在でも記念施設にその名が刻まれている。",descriptionEn:"A civil engineer who directed the infrastructure development of settlements from E2 to E48 in the early Barz Empire. He was involved in the initial design of Central Tower, becoming a precursor to the Megatower concept during the later construction period of Gigapolis. During the 'Warden Catastrophe' of E20, a residential area collapse accident, he personally directed rescue operations without regard for his own safety, saving many lives. His selfless attitude is idealized by construction workers as the 'Warden Spirit,' and his name is still engraved in commemorative facilities today.",era:"E2〜E48",affiliation:"バーズ帝国建設局",tier:"Tier 3"},{id:"キャプテン・ノヴァ",name:"キャプテン・ノヴァ",nameEn:"Captain Nova",category:"キャラクター",subCategory:"第一移民期",description:"第二波移民船団の総隊長としてE50年からE120年まで活動し、新たな入植地の開拓と移民団の護衛を担った宇宙船長。バーズ帝国期の初期入植地から西大陸への拡張ルートを開拓し、その航海記録はのちのギガポリス建設の地理的基礎となった。E80年の異常宇宙線バーストの際には船団を巧みに回避し、全船の生存を実現した英雄的航海士。ノヴァ・ルートと呼ばれる彼の開拓航路は現在でも主要な星間航路として利用されている。",descriptionEn:"As the commander of the Second Wave Immigration Fleet from E50 to E120, this space captain spearheaded the colonization of new settlements and protected immigrant convoys. He pioneered the expansion route from the early Barss Empire settlements to the Western Continent, with his navigational records forming the geographical foundation for later Gigapolis construction. During the anomalous cosmic ray burst in E80, he skillfully maneuvered the fleet to avoid disaster, ensuring the survival of all ships—a heroic feat of navigation. His开拓 route, known as the Nova Route, remains a major interstellar thoroughfare to this day.",era:"E50〜E120",affiliation:"第二波移民船団",tier:"Tier 3"},{id:"ナビゲーター・セイラ",name:"ナビゲーター・セイラ",nameEn:"Navigator Seira",category:"キャラクター",subCategory:"第一移民期",description:"第二波移民船団の主席航法士としてキャプテン・ノヴァの右腕を務めた天文学者。E55年からE115年にかけて、未踏の星域の天文観測と航路計算を担当し、船団の安全な航行を支えた。E70年に発見したセイラ・ネビュラは彼女の名に因んで命名され、その美しい星雲は後のEros-7建設計画に影響を与えた。精密な計算能力と直感的なNavigationセンスで知られ、船団の乗組員から「星を讀む女」と呼ばれた。",descriptionEn:"As the chief navigator of the Second Wave Immigration Fleet and the right hand to Captain Nova, this astronomer served from E55 to E115, responsible for astronomical observations and route calculations in uncharted star systems that ensured the fleet's safe passage. The Seira Nebula, discovered by her in E70, was named in her honor, and its beauty influenced later the Eros-7 construction project. Renowned for her precise calculations and intuitive navigation sense, she was called 'the star-reading woman' by the fleet's crew.",era:"E55〜E115",affiliation:"第二波移民船団",tier:"Tier 3"},{id:"エンジニア・ボルト",name:"エンジニア・ボルト",nameEn:"Engineer Bolt",category:"キャラクター",subCategory:"第一移民期",description:"第二波移民船団の主席機関士としてE50年からE125年まで船団の全船舶のメンテナンスと改良を担当した技術者。旧式化した移民船のエンジンを独自に改造し、航行速度の向上と燃費の改善を実現した。E90年に開発した「ボルト式推進器」は標準規格として広く採用され、後のテクロサス艦隊にも影響を与えた。また、E110年の船団分裂危機では技術的な解決策を提示し、船団の統一を維持した実務家。",descriptionEn:"As the chief engineer of the Second Wave Immigration Fleet from E50 to E125, this technician oversaw the maintenance and improvement of all fleet vessels. He independently retrofitted outdated immigrant ship engines, achieving increased speed and improved fuel efficiency. The 'Bolt-type Thruster' he developed in E90 was widely adopted as a standard specification, influencing later Technorus fleet designs. During the fleet crisis of E110, he presented technical solutions that maintained the fleet's unity—a pragmatic leader in times of crisis.",era:"E50〜E125",affiliation:"第二波移民船団",tier:"Tier 3"},{id:"科学官・アリス",name:"科学官・アリス",nameEn:"Science Officer Alice",category:"キャラクター",subCategory:"第一移民期",description:"第二波移民船団の首席科学官としてE52年からE130年まで船団内の研究活動を統括した科学者。異星植物の植生調査と鉱物資源の分析において先駆的な業績を残し、入植地選定の科学的根拠を提供した。E95年に発見したアリス鉱石は強力なエネルギー源として後の重工業発展に貢献した。彼女の膨大な研究ノートは「アリス・アーカイブ」として現在もEDU最大の学術データベースの一部をなしている。",descriptionEn:"As the chief science officer of the Second Wave Immigration Fleet from E52 to E130, this scientist coordinated all research activities within the fleet. She made pioneering achievements in extraterrestrial vegetation surveys and mineral resource analysis, providing scientific foundations for settlement selection. The Iris Ore she discovered in E95 contributed to later heavy industrial development as a powerful energy source. Her extensive research notebooks, known as the 'Alice Archive,' remain part of EDU's largest academic database.",era:"E52〜E130",affiliation:"第二波移民船団",tier:"Tier 3"},{id:"医療官・ヘイズ",name:"医療官・ヘイズ",nameEn:"Medical Officer Haze",category:"キャラクター",subCategory:"第一移民期",description:"第二波移民船団の首席医療官としてE50年からE128年まで船団の全医療を統括した医師。長期間の宇宙航行に伴う健康問題の解決に取り組み、宇宙放射線障害の治療法を確立した。E100年の伝染病発生時には隔離措置と予防接種の徹底によりパンデミックを回避し、数千人の命を救った。ドクター・オクタヴィアの医療哲学を継承しつつ、船上医療の新たな標準を確立した医療の先駆者。",descriptionEn:"As the chief medical officer of the Second Wave Immigration Fleet from E50 to E128, this physician oversaw all medical operations. She addressed health issues associated with long-duration space travel and established treatments for cosmic radiation sickness. During the epidemic of E100, she implemented quarantine measures and widespread vaccinations, preventing a pandemic and saving thousands of lives. While inheriting the medical philosophy of Doctor Octavia, she established new standards for shipboard medicine—a pioneer in space medicine.",era:"E50〜E128",affiliation:"第二波移民船団",tier:"Tier 3"},{id:"ゴヴァナー・キーン",name:"ゴヴァナー・キーン",nameEn:"Governor Keen",category:"キャラクター",subCategory:"第一移民期",description:"第一移民期における西大陸初代総督としてE60年からE110年まで在任し、入植地の行政制度を確立した政治家。マルクス・アウレリウスの法典を基に移民地独自の自治制度を設計し、地方議会の創設と選挙制度の導入を推進した。E85年の農業危機では食糧配給制度を整備し、入植者の生活安定に尽力した。彼の行政手腕は「キーン方式」として後のギガポリス自治体制にも影響を与え、市民参加型政治の先駆者として評価されている。",descriptionEn:"As the first Governor of the Western Continent during the First Immigration Period, serving from E60 to E110, this politician established the settlement's administrative system. Based on the code of Marcus Aurelius, he designed a unique autonomous system for the colony, promoting the creation of local councils and electoral systems. During the agricultural crisis of E85, he established food distribution systems to stabilize settlers' lives. His administrative methods, known as the 'Keen System,' influenced later Gigapolis governance structures, and he is evaluated as a pioneer in participatory politics.",era:"E60〜E110",affiliation:"西大陸入植地政府",tier:"Tier 3"},{id:"メイヤー・ストーン",name:"メイヤー・ストーン",nameEn:"Mayor Stone",category:"キャラクター",subCategory:"第一移民期",description:"第一移民期における西大陸第2居住区の初代市長としてE70年からE135年まで在任し、都市計画と住宅建設を推進した行政官。グリッド状の街区設計と公共施設の体系的配置を導入し、後のギガポリス都市計画の基礎を築いた。E100年には最初の上層居住区の建設を決定し、メガタワー構想の初期段階を形作った。頑固だが実直な性格で、「石の市長」の異名通り、堅実な市政運営で市民から厚い信頼を得た。",descriptionEn:"As the first mayor of the Western Continent's Second Residential District from E70 to E135, this administrator promoted urban planning and housing construction. He introduced grid-based block designs and systematic placement of public facilities, laying the foundation for later Gigapolis urban planning. In E100, he decided on the construction of the first upper residential districts, shaping the initial phase of the Megatower concept. Though stubborn and upright, he earned deep public trust through solid municipal administration, earning the nickname 'the Stone Mayor.'",era:"E70〜E135",affiliation:"西大陸第2居住区",tier:"Tier 3"},{id:"シェリフ・ブラス",name:"シェリフ・ブラス",nameEn:"Sheriff Brass",category:"キャラクター",subCategory:"第一移民期",description:"第一移民期における西大陸の初代保安官としてE65年からE125年まで入植地の治安維持を担った法執行官。未開地における犯罪防止と紛争解決において独自の法と秩序を確立した。E90年の「ブラスの銃撃戦」と呼ばれる武装集団との対峙は伝説化し、入植地の治安維持の象徴となった。警察組織の原型を構築し、その保安官制度は後のテリアン反乱軍との対立構造にも間接的な影響を与えた。",descriptionEn:"As the first Sheriff of the Western Continent during the First Immigration Period from E65 to E125, this law enforcement officer maintained settlement security. He established unique laws and orders for crime prevention and dispute resolution in uncharted territories. The confrontation with armed groups in E90, known as the 'Brass Gunfight,' became legendary and symbolized the maintenance of settlement security. He built the prototype of the police organization, and his sheriff system indirectly influenced the later conflict structure with the Terrion Rebellion Army.",era:"E65〜E125",affiliation:"西大陸保安局",tier:"Tier 3"},{id:"エルダー・ウィロー",name:"エルダー・ウィロー",nameEn:"Elder Willow",category:"キャラクター",subCategory:"第一移民期",description:"第一移民期における入植者の精神的指導者としてE55年からE140年まで活動した宗教家・哲学者。宇宙への移住という未曽有の体験に対する人々の不安を受け止め、新しい精神性の構築を試みた。E75年に設立した「ウィローの集会所」は後の宗教・思想の自由の象徴となり、多様な信仰が共存するEDU文化の基盤を築いた。彼女の教えは「木のように根を張り、枝を広げよ」という言葉に集約され、現在でも入植者の子孫に語り継がれている。",descriptionEn:"As the spiritual leader of settlers during the First Immigration Period from E55 to E140, this religious philosopher addressed people's anxieties about the unprecedented experience of space migration, attempting to construct a new spirituality. The 'Willow Gathering' he established in E75 became a symbol of later religious and ideological freedom, building the foundation for EDU's culture where diverse beliefs coexist. His teachings are summarized in the words 'Grow roots like a tree and spread branches,' a wisdom still passed down to descendants of settlers today.",era:"E55〜E140",affiliation:"入植者精神共同体",tier:"Tier 3"},{id:"コマンダー・アーチャー",name:"コマンダー・アーチャー",nameEn:"Commander Archer",category:"キャラクター",subCategory:"第一移民期",description:"第一移民期における西大陸防衛部隊の初代司令官としてE60年からE130年まで在外の脅威から入植地を防衛した軍人。ガイウス・セプティムスの軍事教範を継承しつつ、宇宙環境に適応した防衛戦術を開発した。E95年の小惑星海賊襲撃では少数の防衛部隊で大規模な攻撃を撃退し、その戦術は「アーチャー戦法」として後世に伝えられた。テクロサスの軍事組織との連携も構築し、西大陸防衛の基盤を確立した武人。",descriptionEn:"As the first Commander of the Western Continent Defense Force from E60 to E130, this military officer defended the settlement from external threats. While inheriting the military doctrines of Gaius Septimus, he developed defense tactics adapted to the space environment. During the asteroid pirate raid in E95, he repelled a large-scale attack with a small defense force, a tactic later known as the 'Archer Method' and passed down through generations. He also built cooperation with Technorus military organizations, establishing the foundation for Western Continent defense—a warrior of great strategic vision.",era:"E60〜E130",affiliation:"西大陸防衛部隊",tier:"Tier 3"},{id:"アドミラル・フロスト",name:"アドミラル・フロスト",nameEn:"Admiral Frost",category:"キャラクター",subCategory:"第一移民期",description:"第一移民期における移民船団護衛艦隊の総司令官としてE55年からE135年まで星域の安全を確保した提督。冷徹な判断力と卓越した艦隊指揮能力で知られ、E75年の「氷河の戦い」と呼ばれる宇宙海戦では圧倒的な敵勢力を打ち破った。艦隊編成の改革により機動力を重視した新しい海戦ドクトリンを確立し、後のテクロサス艦隊運用に多大な影響を与えた。「氷の提督」の異名はその冷静沈着な指揮スタイルに由来する。",descriptionEn:"As the Commander-in-Chief of the Immigration Fleet Escort Fleet from E55 to E135, this admiral ensured security in the star system. Known for his cold judgment and exceptional fleet command capabilities, he defeated overwhelming enemy forces in the 'Battle of the Glaciers' in E75, a cosmic space battle. Through fleet reorganization, he established a new naval doctrine emphasizing mobility, greatly influencing later Technorus fleet operations. His nickname 'The Ice Admiral' derives from his calm and composed command style.",era:"E55〜E135",affiliation:"移民船団護衛艦隊",tier:"Tier 3"},{id:"ジェネラル・テラ",name:"ジェネラル・テラ",nameEn:"General Terra",category:"キャラクター",subCategory:"第一移民期",description:"第一移民期における地上防衛軍の初代総司令官としてE62年からE132年まで入植地周辺の地上戦力を統括した将軍。未開地の地形を活用した防御陣地の構築において類まれな才能を発揮し、E88年の辺境異星生物の大群襲来を撃退した。彼が構築した防衛ライン「テラ・ウォール」は後の都市防衛システムの原型となった。兵士教育にも力を入れ、彼の軍学校からは多くの優秀な将校が巣立った。",descriptionEn:"As the first Commander-in-Chief of the Ground Defense Force from E62 to E132, this general commanded ground forces around the settlement. He demonstrated extraordinary talent in constructing defensive positions utilizing uncharted terrain, repelling the massive swarm of border alien creatures in E88. The defense line he built, the 'Terra Wall,' became the prototype for later urban defense systems. He also focused on soldier education, and many excellent officers graduated from his military academy.",era:"E62〜E132",affiliation:"西大陸地上防衛軍",tier:"Tier 3"},{id:"アルキテクト・ゼン",name:"アルキテクト・ゼン",nameEn:"Architect Zen",category:"キャラクター",subCategory:"ギガポリス建設期",description:"ギガポリス建設期の主任建築家であり、E155年からE250年にかけてメガタワーの設計と建設を主導した伝説的な建築家。エル・フォルハウスのマーストリヒト革命（E150）の直後に台頭し、自由経済体制下における都市計画の総監督として活動した。彼の設計したメガタワー構想は垂直都市の概念を具現化し、西大陸の天際線を劇的に変貌させた。E200年に完成した第1メガタワーはEDU建築史上最も偉大な構造物の一つとして評価されている。",descriptionEn:"The chief architect during the Gigapolis construction period, a legendary architect who led the design and construction of megatowers from E155 to E250. Rising immediately after the Maastricht Revolution of El Forhaus (E150), he served as the supervisor of urban planning under the free economic system. His megatower designs materialized the concept of vertical cities, dramatically transforming the skyline of the Western Continent. The first megatower, completed in E200, is regarded as one of the greatest structures in EDU architectural history.",era:"E155〜E250",affiliation:"ギガポリス建設委員会",tier:"Tier 3"},{id:"デザイナー・ルナ",name:"デザイナー・ルナ",nameEn:"Designer Luna",category:"キャラクター",subCategory:"ギガポリス建設期",description:"ギガポリス建設期の環境デザイナーとしてE160年からE245年まで都市の景観と居住環境の設計を担当した芸術家。アルキテクト・ゼンの構造設計に対し、人間味のある居住空間の創造を追求し、公園・広場・緑地帯の配置を計画した。E180年に提唱した「緑のギガポリス」構想は、都市と自然の調和を目指す先進的な環境計画として高く評価された。その美学はのちのセリア黄金期におけるAURALISの文化的基盤にも影響を与えた。",descriptionEn:"An environmental designer who served as the artist in charge of the city's landscape and living environment design from E160 to E245 during the Gigapolis construction period. Pursuing the creation of human-centered living spaces in contrast to Architect Zen's structural designs, he planned the layout of parks, plazas, and green zones. His 'Green Gigapolis' concept, proposed in E180, was highly acclaimed as an advanced environmental plan aiming for harmony between city and nature. His aesthetics later influenced the cultural foundation of AURALIS during the Cerean Golden Age.",era:"E160〜E245",affiliation:"ギガポリス環境設計局",tier:"Tier 3"},{id:"エンジニア・ピラー",name:"エンジニア・ピラー",nameEn:"Engineer Pillar",category:"キャラクター",subCategory:"ギガポリス建設期",description:"ギガポリス建設期の構造エンジニアとしてE158年からE248年までメガタワーの構造計算と安全性確保を担当した技術者。超高層建築物の耐震・耐風・耐宇宙線設計の分野で先駆的な業績を残し、数多くの技術的課題を解決した。E190年の大嵐ではメガタワーの構造的完全性を証明し、都市建設への信頼を確立した。彼が開発した「ピラー式基礎工法」は現在でも大型構造物の建設に用いられている。",descriptionEn:"A structural engineer who served as the technical specialist in charge of megatower structural calculations and safety assurance from E158 to E248 during the Gigapolis construction period. He made pioneering achievements in the fields of seismic, wind resistance, and cosmic ray design for ultra-high-rise buildings, solving numerous technical challenges. During the Great Storm of E190, he proved the structural integrity of the megatowers, establishing confidence in urban construction. The 'Pillar Foundation Method' he developed is still used in the construction of large structures today.",era:"E158〜E248",affiliation:"ギガポリス建設委員会",tier:"Tier 3"},{id:"プランナー・アクア",name:"プランナー・アクア",nameEn:"Planner Aqua",category:"キャラクター",subCategory:"ギガポリス建設期",description:"ギガポリス建設期の水資源計画担当者としてE162年からE240年まで都市の水循環システムの設計と管理を担当した都市計画家。閉鎖環境での水のリサイクルと浄化システムを確立し、大規模都市における水資源の安定供給を実現した。E185年に完成した「アクア・リング」と呼ばれる循環水路システムは、都市の美観と機能性を両立した画期的なインフラとして評価されている。後のテリアン反乱軍が掲げた市民の生活権要求にも通じる、生活基盤整備の先駆者。",descriptionEn:"An urban planner who served as the water resources planner from E162 to E240 during the Gigapolis construction period, designing and managing the city's water circulation system. He established water recycling and purification systems in a closed environment, achieving stable water supply for the massive city. The 'Aqua Ring' circulation waterway system, completed in E185, is evaluated as a groundbreaking infrastructure that balanced both aesthetics and functionality of the city. A pioneer in infrastructure development whose philosophy resonated with the Terrian Rebellion's demands for citizens' right to livelihood.",era:"E162〜E240",affiliation:"ギガポリス水資源局",tier:"Tier 3"},{id:"エコノミスト・ゴールド",name:"エコノミスト・ゴールド",nameEn:"Economist Gold",category:"キャラクター",subCategory:"ギガポリス建設期",description:"ギガポリス建設期の首席経済官としてE155年からE255年まで都市の経済政策を立案した経済学者。エル・フォルハウスの完全自由経済体制の理論的支柱となり、市場原理に基づく都市運営のモデルを構築した。E180年に導入したゴールド標準通貨制度はのちのnトークン経済の先駆けとなった。また、都市間貿易の促進と税制改革も推進し、ギガポリスを星域最大の経済都市へと成長させた経済の建筑师。",descriptionEn:"The chief economic officer who formulated the city's economic policies from E155 to E255 during the Gigapolis construction period. He became the theoretical pillar of El Forhaus's complete free economic system, constructing a model for city operations based on market principles. The gold standard currency system he introduced in E180 became the precursor to later n-token economies. He also promoted inter-city trade and tax reforms, growing Gigapolis into the largest economic city in the star sector—the architect of the economy.",era:"E155〜E255",affiliation:"ギガポリス経済委員会",tier:"Tier 3"},{id:"バンカー・シルバー",name:"バンカー・シルバー",nameEn:"Banker Silver",category:"キャラクター",subCategory:"ギガポリス建設期",description:"ギガポリス建設期の銀行家としてE160年からE250年まで都市の金融システムの構築に従事した金融業者。初代ギガポリス中央銀行の設立メンバーであり、信用創造と資金調達のメカニズムを確立した。E195年に創設したシルバー銀行は後の金融帝国の基盤となり、ギガポリスの経済的影響力の拡大に寄与した。エコノミスト・ゴールドの経済政策を金融面から支え、都市の急成長を可能にした資金の供給者。",descriptionEn:"A financier who engaged in building the city's financial system from E160 to E250 during the Gigapolis construction period. A founding member of the first Gigapolis Central Bank, he established mechanisms for credit creation and fundraising. The Silver Bank he founded in E195 became the foundation for later financial empires, contributing to the expansion of Gigapolis's economic influence. He supported Economist Gold's economic policies from a financial perspective, serving as the capital provider that enabled the city's rapid growth.",era:"E160〜E250",affiliation:"シルバー銀行",tier:"Tier 3"},{id:"トレーダー・ブロンズ",name:"トレーダー・ブロンズ",nameEn:"Trader Bronze",category:"キャラクター",subCategory:"ギガポリス建設期",description:"ギガポリス建設期の大商人としてE165年からE248年まで星域間貿易を展開した実業家。希少資源と技術製品の取引において類まれな商才を発揮し、ギガポリスを交易の中心地へと発展させた。E190年に確立した「ブロンズ交易路」は7つの星系を結ぶ大規模な商業ネットワークであり、クレセント地方との交易の基礎となった。商業倫理の確立にも努め、自立的な商人ギルドの創設も主導した。",descriptionEn:"A great merchant who operated interstellar trade from E165 to E248 during the Gigapolis construction period. He demonstrated extraordinary business acumen in trading rare resources and technological products, developing Gigapolis into a center of commerce. The 'Bronze Trade Routes' he established in E190 formed a massive commercial network connecting seven star systems, becoming the foundation for trade with the Crescent Region. He also worked to establish commercial ethics and led the creation of independent merchant guilds.",era:"E165〜E248",affiliation:"ブロンズ商会",tier:"Tier 3"},{id:"チーフ・グリズリー",name:"チーフ・グリズリー",nameEn:"Chief Grizzly",category:"キャラクター",subCategory:"ギガポリス建設期",description:"ギガポリス建設期の労働組合初代委員長としてE170年からE245年まで建設労働者の権利保護と労働環境の改善に尽くした労働運動家。メガタワー建設の現場で働く労働者の劣悪な環境に抗議し、労働安全基準と賃金体系の確立を勝ち取った。E200年の大ストライキでは労働者の要求を貫き、ギガポリス建設の進行に一定の制約を課した。その不屈の闘志は「グリズリーの咆哮」として労働運動の象徴となった。",descriptionEn:"The first chairman of the labor union during the Gigapolis construction period, who dedicated himself from E170 to E245 to protecting workers' rights and improving labor conditions. He protested against the poor conditions of workers at megatower construction sites and successfully established labor safety standards and wage systems. During the Great Strike of E200, he persisted in workers' demands, imposing certain constraints on the progress of Gigapolis construction. His unyielding fighting spirit became known as the 'Grizzly's Roar,' symbolizing the labor movement.",era:"E170〜E245",affiliation:"ギガポリス労働組合",tier:"Tier 3"},{id:"エルダー・イーグル",name:"エルダー・イーグル",nameEn:"Elder Eagle",category:"キャラクター",subCategory:"ギガポリス建設期",description:"ギガポリス建設期における先住派住民の長老としてE150年からE230年まで活動し、急速な都市化の中で伝統文化の維持に努めた精神的指導者。エルダー・ウィローの教えを継承し、新しい都市環境におけるコミュニティの絆を保つため、地域ごとの集会所と祭りの伝統を維持した。E210年には都市計画への先住民参加の権利を確保し、多様な文化が共存するギガポリスの基盤を築いた。その先見性はのちのAURALISの多文化理念にも通じる。",descriptionEn:"A spiritual leader who served as the elder of the indigenous residents from E150 to E230 during the Gigapolis construction period, striving to maintain traditional culture amidst rapid urbanization. Inheriting the teachings of Elder Willow, he maintained community bonds in the new urban environment by preserving the traditions of local meeting places and festivals. In E210, he secured the right for indigenous participation in urban planning, laying the foundation for a Gigapolis where diverse cultures coexist. His foresight connects to the multicultural philosophy of later AURALIS.",era:"E150〜E230",affiliation:"先住派住民評議会",tier:"Tier 3"},{id:"シャーマン・フォックス",name:"シャーマン・フォックス",nameEn:"Shaman Fox",category:"キャラクター",subCategory:"ギガポリス建設期",description:"ギガポリス建設期における異星環境の研究と民間療法の専門家としてE165年からE240年まで活動した民俗学者・治療師。入植前に存在した異星生態系の知識を体系化し、未知の薬用植物の発見と応用に尽力した。E195年に発見した「フォックス・ハーブ」は鎮痛効果があり、医療資源の乏しい建設期において多くの労働者を救った。古代の伝承と近代科学の融合を図る異色の存在として、知的遺産の保存者としても評価されている。",descriptionEn:"A folklorist and healer who specialized in extraterrestrial environment research and folk medicine from E165 to E240 during the Gigapolis construction period. He systematized knowledge of the alien ecosystem that existed before colonization and dedicated himself to discovering and applying unknown medicinal plants. The 'Fox Herb' he discovered in E195 had pain-relieving effects and saved many workers during the construction period when medical resources were scarce. As a unique figure who fused ancient traditions with modern science, he is also evaluated as a preserver of intellectual heritage.",era:"E165〜E240",affiliation:"異星生態研究会",tier:"Tier 3"},{id:"チーフ・ドラゴン",name:"チーフ・ドラゴン",nameEn:"Chief Dragon",category:"キャラクター",subCategory:"ギガポリス建設期",description:"ギガポリス建設期の重工業協会初代会長としてE168年からE242年まで都市の産業基盤の構築を主導した実業家。鉄鋼・機械・電子部品の生産体制を整備し、メガタワー建設に必要な資材の安定供給を実現した。E205年に創設したドラゴン重工は後のアイアン・シンジケートの萌芽となり、クレセント地方の重工業発展の先駆けとなった。強引な手法も多用したが、その実行力はギガポリスの急速な近代化を支えた。",descriptionEn:"The first chairman of the Heavy Industry Association who led the construction of the city's industrial foundation from E168 to E242 during the Gigapolis construction period. He established production systems for steel, machinery, and electronic components, ensuring stable supply of materials necessary for megatower construction. Dragon Heavy Industries, which he founded in E205, became the precursor to later Iron Syndicates and a pioneer in the heavy industry development of the Crescent Region. Although he frequently employed aggressive methods, his execution power supported the rapid modernization of Gigapolis.",era:"E168〜E242",affiliation:"ギガポリス重工業協会",tier:"Tier 3"},{id:"エルダー・タイガー",name:"エルダー・タイガー",nameEn:"Elder Tiger",category:"キャラクター",subCategory:"ギガポリス建設期",description:"ギガポリス建設期の法学者としてE175年からE252年まで都市法の整備と司法制度改革に尽くした法律家。バーズ帝国期の法典を現代の都市環境に適合する形で改訂し、商法・労働法・建築法の体系化を主導した。E220年に制定した「タイガー法典」は都市法の集大成として評価され、後のZAMLT期の法体系にも影響を与えた。厳正な法解釈で知られ、建設期の混乱する都市環境に法的秩序をもたらした。",descriptionEn:"A jurist who dedicated himself from E175 to E252 to urban law development and judicial reform during the Gigapolis construction period. He revised the legal codes of the Bird Empire era to adapt to the modern urban environment, leading the systematization of commercial, labor, and construction law. The 'Tiger Code' enacted in E220 was evaluated as the culmination of urban law and influenced the legal systems of the later ZAMLT period. Known for his strict legal interpretations, he brought legal order to the chaotic urban environment of the construction period.",era:"E175〜E252",affiliation:"ギガポリス法務局",tier:"Tier 3"},{id:"シャーマン・スネーク",name:"シャーマン・スネーク",nameEn:"Shaman Snake",category:"キャラクター",subCategory:"ギガポリス建設期",description:"ギガポリス建設期の地下世界の案内人としてE172年からE235年まで地下空間の探査と開発に従事した探検家。都市の地下構造の解明と地下水脈の発見において重要な役割を果たし、のちの地下街建設の基礎となった。E210年に発見した大規模な地下空洞は「スネーク・ケイブ」として命名され、後のTina/Gueが支配する地下街の一部となった。蛇のような機知と洞察力で未知の地下世界を解読した、ギガポリスの「地下の開拓者」。",descriptionEn:"An explorer who served as a guide to the underworld during the construction of Gigapolis from E172 to E235, engaged in the exploration and development of underground spaces. Played a crucial role in deciphering the city's underground structure and discovering groundwater veins, laying the foundation for later underground street construction. The massive underground cavity discovered in E210 was named 'Snake Cave' and later became part of the underground street ruled by Tina/Gue. With snake-like wit and insight, he deciphered the unknown underground world, earning the title of 'Underground Pioneer' of Gigapolis.",era:"E172〜E235",affiliation:"地下探査協会",tier:"Tier 3"},{id:"コマンダー・ヴェルミリオン守備隊長",name:"ヴェルミリオン守備隊長",nameEn:"Commander of Vermilion Defense",category:"キャラクター",subCategory:"クレセント拡充",description:"E300年からE380年までヴァーミリオンの国境守備隊を統率した軍人。クレセント地方における初期の防衛ライン構築の指導者であり、後のヴァーミリオン諜報機関の基盤を築いた。テクロサス系譜の軍事教範をヴァーミリオンの地理的特徴に適合させ、独自の防衛戦術を確立した。E350年の辺境紛争では巧みな防御戦で侵略を退け、ヴァーミリオンの軍事的威信を確立した。アザゼル・ヘクトパスに先立つヴァーミリオン軍事力の基礎を築いた武人。",descriptionEn:"A military commander who led the Vermilion border defense forces from E300 to E380. He was the leader in constructing early defensive lines in the Crescent region and laid the foundation for the later Vermilion intelligence agency. He adapted the Teklos military doctrine to Vermilion's geographical characteristics, establishing unique defensive tactics. During the border conflict of E350, he repelled invasion with skillful defensive maneuvers, establishing Vermilion's military prestige. A warrior who built the foundation of Vermilion's military power that would later be succeeded by Azazel Hectopas.",era:"E300〜E380",affiliation:"ヴァーミリオン守備隊",tier:"Tier 3"},{id:"コマンダー・ブルーローズ衛兵長",name:"ブルーローズ衛兵長",nameEn:"Commander of Blue Rose Guard",category:"キャラクター",subCategory:"クレセント拡充",description:"E305年からE385年までブルーローズの王室衛兵隊を統率した近衛軍の指揮官。国家の中枢を守る精鋭部隊の編成と訓練において卓越した手腕を発揮し、ブルーローズの政治的安定に寄与した。E355年の内部騒乱では速やかに事態を鎮圧し、国家の存続を守った。後のフィオナやヨニックが率いるブルーローズ軍の原型となる衛兵隊制度を確立し、その規律ある軍事文化は現在まで受け継がれている。",descriptionEn:"A commander of the royal guard who led the Blue Rose royal guard from E305 to E385. Demonstrated exceptional skill in organizing and training the elite force that protected the nation's core, contributing to Blue Rose's political stability. During the internal unrest of E355, he quickly suppressed the situation, preserving the nation's existence. He established the guard system that would later become the model for the Blue Rose military led by Fiona and Yonic, and his disciplined military culture continues to be inherited to this day.",era:"E305〜E385",affiliation:"ブルーローズ衛兵隊",tier:"Tier 3"},{id:"コマンダー・SSレンジ警備隊長",name:"SSレンジ警備隊長",nameEn:"Commander of SS Range Security",category:"キャラクター",subCategory:"クレセント拡充",description:"E310年からE390年までSSレンジの交易拠点警備隊を統率した治安官。クレセント地方の交易路の安全確保と密輸取締りにおいて重要な役割を果たし、後のアイク・ロペスが支配するSSレンジ通信網の物理的安全基盤を築いた。E360年の大規模海賊襲撃では港湾防衛を指揮し、交易ルートの維持に成功した。交易と通信の安全を確保する実務的アプローチはSSレンジの組織文化に深く刻まれている。",descriptionEn:"A lawman who commanded the SS Range trading post security forces from E310 to E390. Played a vital role in ensuring the security of trade routes and combating smuggling in the Crescent region, building the physical security foundation for the SS Range communication network later dominated by Ike Lopez. During the large-scale pirate raid of E360, he commanded harbor defense and succeeded in maintaining trade routes. His practical approach to ensuring security for trade and communications is deeply embedded in SS Range's organizational culture.",era:"E310〜E390",affiliation:"SSレンジ警備隊",tier:"Tier 3"},{id:"コマンダー・アイアン・シンジケート軍事顧問",name:"アイアン・シンジケート軍事顧問",nameEn:"Iron Syndicate Military Advisor",category:"キャラクター",subCategory:"クレセント拡充",description:"E315年からE395年までアイアン・シンジケートの軍事顧問を務め、重工業地帯の防衛と軍需生産の両面で指導的役割を果たした軍人。工業施設の防衛に特化した戦術を開発し、生産拠点の安全確保と軍事物資の効率的供給を両立させた。E370年には兵器試験場の設立も指揮し、アイアン・シンジケートを軍需大国への道筋をつけた。後のレイド・カキザキの軍事産業政策の先駆けとなる実践的軍事技術者。",descriptionEn:"A military officer who served as military advisor to the Iron Syndicate from E315 to E395, playing a leading role in both the defense of industrial zones and military production. Developed tactics specialized in defending industrial facilities, successfully balancing the security of production bases with efficient supply of military materials. In E370, he also commanded the establishment of a weapons testing ground, paving the way for the Iron Syndicate to become a military-industrial powerhouse. A practical military engineer who pioneered the military-industrial policies later pursued by Raid Kakizaki.",era:"E315〜E395",affiliation:"アイアン・シンジケート",tier:"Tier 3"},{id:"コマンダー・クロセヴィア防衛長",name:"クロセヴィア防衛長",nameEn:"Commander of Crocevia Defense",category:"キャラクター",subCategory:"クレセント拡充",description:"E308年からE388年までクロセヴィアの軍事防衛を統括した防衛長。クレセント地方の中核国家としてのクロセヴィアの安全保障体制を構築し、周辺国との軍事的均衡の維持に尽力した。E365年の三国境界紛争では外交的解決と軍事的威圧の適切な組み合わせにより全面戦争を回避した。後のカスチーナ・テンペストが継承する独自路線の軍事的基盤を築き、クロセヴィアの防衛ドクトリンを確立した戦略家。",descriptionEn:"A defense chief who oversaw Crosevia's military defense from E308 to E388. Built the security system for Crosevia as a core nation in the Crescent region and worked to maintain military balance with neighboring countries. During the tri-border conflict of E365, he avoided full-scale war through an appropriate combination of diplomatic solutions and military pressure. A strategist who built the unique military foundation later inherited by Castina Tempest and established Crosevia's defense doctrine.",era:"E308〜E388",affiliation:"クロセヴィア防衛軍",tier:"Tier 3"},{id:"コマンダー・ミエルテンガ護衛隊長",name:"ミエルテンガ護衛隊長",nameEn:"Commander of Mieltenga Escort",category:"キャラクター",subCategory:"クレセント拡充",description:"E312年からE392年までミエルテンガの要人護衛隊を統率した近衛指揮官。外交官と政府要人の安全確保において高度な専門性を発揮し、暗殺や誘拐の未然防止に功績を残した。E375年のクレセント首脳会議では参加各国首脳の警護を指揮し、テロ未遂事件の阻止に成功した。後のマリーナ・ボビン政権下のミエルテンガ情報網の原型となる精密な警護システムを構築した。",descriptionEn:"A guard commander who led Miertenga's VIP protection unit from E312 to E392. Demonstrated high expertise in ensuring the safety of diplomats and government officials, achieving remarkable success in preventing assassinations and kidnappings. During the Crescent summit conference in E375, he commanded security for participating heads of state and successfully prevented a terrorist attempt. Built the sophisticated protection system that would later become the prototype for Miertenga's intelligence network under the Marina Bobbin administration.",era:"E312〜E392",affiliation:"ミエルテンガ護衛隊",tier:"Tier 3"},{id:"コマンダー・ファールージャ社軍事部長",name:"ファールージャ社軍事部長",nameEn:"Faruja Corp Military Director",category:"キャラクター",subCategory:"クレセント拡充",description:"E320年からE398年までファールージャ社の軍事部門を統括した企業の軍事責任者。民間企業としてのファールージャ社に軍事部門を創設し、次元極地平技術の軍事応用の基礎を築いた。E380年には最初の次元兵器のプロトタイプ開発を指揮し、企業の軍事的影響力の拡大に寄与した。後のミカエル・ガブリエリが率いるファールージャ社の「第8の力」への道を開いた、企業と軍事の融合の先駆者。",descriptionEn:"A corporate military executive who oversaw Farooja Corporation's military division from E320 to E398. Established a military division within the civilian Farooja Corporation and laid the foundation for military applications of dimensional polar technology. In E380, he commanded the development of the first prototype dimensional weapon, contributing to the expansion of the corporation's military influence. A pioneer in the fusion of corporate and military interests who paved the way for Farooja Corporation's 'Eighth Power' under the leadership of Michael Gabriel.",era:"E320〜E398",affiliation:"ファールージャ社軍事部門",tier:"Tier 3"},{id:"ドクター・ヴェルミリオン主席研究員",name:"ヴェルミリオン主席研究員",nameEn:"Chief Researcher of Vermilion",category:"キャラクター",subCategory:"クレセント拡充",description:"E302年からE385年までヴァーミリオンの科学研究機関で主席研究員を務めた科学者。諜報活動に必要な技術開発において先駆的な業績を残し、盗聴装置・暗号解読器・変装技術などの革新をもたらした。E350年には「ヴェルミリオン・プロトコル」と呼ばれる情報セキュリティ規格を策定し、組織の情報戦能力を飛躍的に向上させた。後のアイリスが駆使するブルーワイヤやウォーター・オーブの技術的基盤を築いたとされる。",descriptionEn:"A scientist who served as chief researcher at Vermilion's scientific research institution from E302 to E385. Achieved pioneering results in developing technologies necessary for intelligence activities, bringing innovations such as eavesdropping devices, codebreakers, and disguise techniques. In E350, he formulated the 'Vermilion Protocol,' an information security standard that dramatically enhanced the organization's information warfare capabilities. Is believed to have laid the technical foundation for Bluewire and Water Orb later wielded by Iris.",era:"E302〜E385",affiliation:"ヴァーミリオン研究機関",tier:"Tier 3"},{id:"ドクター・ブルーローズ技術顧問",name:"ブルーローズ技術顧問",nameEn:"Blue Rose Technical Advisor",category:"キャラクター",subCategory:"クレセント拡充",description:"E306年からE388年までブルーローズ政府の技術顧問を務めた技術官僚。都市インフラの近代化と通信技術の向上において中心的な役割を果たし、国家の技術的競争力を強化した。E365年には大規模通信網の整備計画を策定し、国内の情報伝達速度を劇的に改善した。その技術遺産はのちのブルーローズがV7で果たす役割の基盤となり、軍事的通信の安定性にも貢献している。",descriptionEn:"A technical bureaucrat who served as technical advisor to the Blue Rose government from E306 to E388. Played a central role in modernizing urban infrastructure and improving communication technology, strengthening the nation's technological competitiveness. In E365, he formulated a plan for large-scale communication network development, dramatically improving domestic information transmission speed. His technological legacy became the foundation for Blue Rose's role in V7 and also contributed to the stability of military communications.",era:"E306〜E388",affiliation:"ブルーローズ技術省",tier:"Tier 3"},{id:"ドクター・SSレンジ通信研究員",name:"SSレンジ通信研究員",nameEn:"SS Range Communication Researcher",category:"キャラクター",subCategory:"クレセント拡充",description:"E310年からE392年までSSレンジ通信研究所で長距離通信技術の研究に従事した通信技術者。クレセント地方全域をカバーする通信ネットワークの技術的基盤を構築し、情報伝達の遅延問題を解決した。E370年に開発した「レンジ・リレー」技術は中継拠点不要の長距離通信を実現し、交易・軍事・外交の各分野に革命をもたらした。後のSSレンジがV7で経済的影響力を行使する基盤技術を創出した。",descriptionEn:"A communications engineer who engaged in long-distance communication technology research at the SS Range Communications Institute from E310 to E392. Built the technical foundation for a communication network covering the entire Crescent region, solving the problem of information transmission delays. The 'Range Relay' technology developed in E370 achieved long-distance communication without relay stations, bringing revolution to trade, military, and diplomatic fields. Created the fundamental technology that would later allow SS Range to exercise economic influence through V7.",era:"E310〜E392",affiliation:"SSレンジ通信研究所",tier:"Tier 3"},{id:"ドクター・アイアン・シンジケート材料学者",name:"アイアン・シンジケート材料学者",nameEn:"Iron Syndicate Materials Scientist",category:"キャラクター",subCategory:"クレセント拡充",description:"E315年からE396年までアイアン・シンジケートで新素材の研究開発に従事した材料科学者。超高強度合金と耐熱素材の開発において画期的な成果を上げ、重工業製品の性能と耐久性を飛躍的に向上させた。E375年に発見した「シンジケート・スチール」は艦船の装甲材として広く採用され、軍事技術の進歩に多大な影響を与えた。後のレイド・カキザキの軍需生産体制を支える基礎技術の創出者。",descriptionEn:"A materials scientist who engaged in research and development of new materials at the Iron Syndicate from E315 to E396. Achieved groundbreaking results in developing ultra-high-strength alloys and heat-resistant materials, dramatically improving the performance and durability of heavy industrial products. The 'Syndicate Steel' discovered in E375 was widely adopted as armor material for warships, greatly influencing the advancement of military technology. The creator of the fundamental technologies that would support Raid Kakizaki's military production system.",era:"E315〜E396",affiliation:"アイアン・シンジケート研究所",tier:"Tier 3"},{id:"ドクター・クロセヴィア生物学者",name:"クロセヴィア生物学者",nameEn:"Crocevia Biologist",category:"キャラクター",subCategory:"クレセント拡充",description:"E308年からE390年までクロセヴィアで異星生態系の研究に従事した生物学者。クレセント地方特有の動植物の分類と生態調査において先駆的な業績を残し、農業・医療・環境保護の各分野に貢献した。E360年に発見した薬用菌類は重篤な感染症の治療に効果があり、多くの命を救った。E340年のスライム・ウーマン顕現の際にも科学的分析を試み、異次元生物の理解に重要なデータを提供した。",descriptionEn:"A biologist who engaged in extraterrestrial ecosystem research in Crosevia from E308 to E390. They made pioneering achievements in classifying and surveying the unique flora and fauna of the Crescent region, contributing to the fields of agriculture, medicine, and environmental conservation. The medicinal fungi they discovered in E360 proved effective in treating severe infectious diseases, saving countless lives. During the manifestation of the Slime Woman in E340, they attempted scientific analysis, providing crucial data for understanding interdimensional beings.",era:"E308〜E390",affiliation:"クロセヴィア生物学研究所",tier:"Tier 3"},{id:"ドクター・ミエルテンガ医務官",name:"ミエルテンガ医務官",nameEn:"Mieltenga Medical Officer",category:"キャラクター",subCategory:"クレセント拡充",description:"E312年からE395年までミエルテンガの軍医・衛生管理を担当した医務官。軍隊の健康管理と戦地医療の体制を整備し、負傷者の生存率を大幅に向上させた。E370年の大規模疫病発生時には迅速な対応措置を講じ、感染の拡大を防いだ。軍医としてだけでなく、一般市民の医療アクセスの改善にも努め、ミエルテンガの公衆衛生基盤を確立した。ドクター・オクタヴィアの医療哲学をクレセント大陸に広めた継承者。",descriptionEn:"A medical officer who served as the military physician and sanitation administrator of Mielternga from E312 to E395. They established systems for military health management and battlefield medicine, significantly increasing the survival rate of the wounded. During the large-scale epidemic in E370, they implemented rapid response measures to prevent the spread of infection. Not only as a military physician but also as an advocate for improving medical access for civilians, they established the public health foundation of Mielternga. A successor who spread Doctor Octavia's medical philosophy across the Crescent continent.",era:"E312〜E395",affiliation:"ミエルテンガ軍医部",tier:"Tier 3"},{id:"ドクター・ファールージャ社次元物理学者",name:"ファールージャ社次元物理学者",nameEn:"Faruja Corp Dimensional Physicist",category:"キャラクター",subCategory:"クレセント拡充",description:"E325年からE399年までファールージャ社で次元物理学の研究に従事した理論物理学者。ティムール・シャーの10次元ホラズム理論を実用化する研究を推進し、次元極地平技術の理論的基礎を構築した。E385年に発表した「ファールージャ次元方程式」は次元間移動の数学的框架を提供し、後の軍事・民生両面への応用の扉を開いた。その理論的業績はミカエル・ガブリエリの企業戦略の根幹を支え、クレセントの技術競争に決定的な影響を与えた。",descriptionEn:"A theoretical physicist who worked on dimensional physics research at Farulja Corporation from E325 to E399. They advanced research to implement Timur Shah's ten-dimensional Horazm theory, constructing the theoretical foundation of dimensional polar horizon technology. The 'Farulja Dimensional Equation' published in E385 provided the mathematical framework for interdimensional travel, opening doors to subsequent applications in both military and civilian sectors. Their theoretical achievements supported the core of Michael Gabrieli's corporate strategy and decisively influenced Crescent's technological competition.",era:"E325〜E399",affiliation:"ファールージャ社研究所",tier:"Tier 3"},{id:"リベリオン・リーダー・アッシュ",name:"リベリオン・リーダー・アッシュ",nameEn:"Rebellion Leader Ash",category:"キャラクター",subCategory:"クレセント拡充",description:"E350年からE400年までクレセント地方の反体制運動を指導した革命家。各国家の圧政的な統治体制に対して武装闘争を組織し、都市部の貧困層から広範な支持を集めた。アルファ・ケインのシャドウ・リベリオン（E318〜）に触発されたとも言われ、クレセント版の解放運動として展開。E380年の大規模蜂起では都市を一時的に制圧したが、鎮圧後に消息不明となった。その理想主義的な闘争はのちのテリアン反乱軍やアルファ・ヴェノムの思想的源泉の一つとなった。",descriptionEn:"A revolutionary who led anti-establishment movements in the Crescent region from E350 to E400. They organized armed struggles against the oppressive governance of various nations, garnering broad support from the urban poor. It is said they were inspired by Alpha Cain's Shadow Rebellion (E318-), developing as a Crescent version of the liberation movement. In the large-scale uprising of E380, they temporarily controlled urban areas but disappeared after suppression. Their idealistic struggle became one of the ideological sources for later Terian rebel forces and Alpha Venom.",era:"E350〜E400",affiliation:"クレセント反体制連合",tier:"Tier 3"},{id:"レジスタンス・コマンダー・フレイム",name:"レジスタンス・コマンダー・フレイム",nameEn:"Resistance Commander Flame",category:"キャラクター",subCategory:"クレセント拡充",description:"E355年からE405年までクレセント地方で活動したレジスタンス運動の軍事指揮官。リベリオン・リーダー・アッシュの右腕として実戦部隊の編成と作戦の実行を担い、政府軍との市街戦で数々の戦果を上げた。ゲリラ戦術の専門家として知られ、正規軍を相手に劣勢な戦力で有効な打撃を与え続けた。E395年の「紅蓮の夜」と呼ばれる作戦では、都市の兵器庫を占拠し、反体制勢力の戦力を大幅に強化した。その戦術はのちのシャドウ・リベリオンにも影響を与えたとされる。",descriptionEn:"A military commander of the resistance movement active in the Crescent region from E355 to E405. As the right-hand man of Rebellion Leader Ash, they commanded the formation of combat units and execution of operations, achieving numerous victories against government forces in urban warfare. Known as a specialist in guerrilla tactics, they continued to deliver effective blows against regular forces despite being outnumbered. In the operation known as 'Night of Crimson Lotus' in E395, they seized the city's arsenal, significantly strengthening the anti-establishment forces. Their tactics are said to have influenced later Shadow Rebellions.",era:"E355〜E405",affiliation:"クレセント反体制連合",tier:"Tier 3"},{id:"アンダーグラウンド・フィクサー・シャドウ",name:"アンダーグラウンド・フィクサー・シャドウ",nameEn:"Underground Fixer Shadow",category:"キャラクター",subCategory:"クレセント拡充",description:"E345年からE410年までクレセント地方の地下経済を操る裏の調整者として活動した謎の人物。反体制運動への資金提供と武器供給を行い、表と裏の両面でクレセント政治に影響を与えた。正体不明の点が多く、複数の国家の情報機関が追跡を試みたが、その実態は現在も明らかではない。後のTina/Gueの地下支配と類似した暗躍ぶりから、両者に何らかの関連があった可能性が指摘されている。地下世界の「影の支配者」として、クレセントの暗部史に深い刻印を残した。",descriptionEn:"A mysterious figure who operated as an underground coordinator controlling the underground economy of the Crescent region from E345 to E410. They provided funding and weapons to anti-establishment movements, influencing Crescent politics from both visible and hidden fronts. Much about their identity remains unknown, with multiple intelligence agencies attempting to track them without success. Their covert activities, similar to the later underground rule of Tina/Gue, have led to speculation of a connection between them. As the 'Shadow Ruler' of the underworld, they left a deep mark on the hidden history of the Crescent.",era:"E345〜E410",affiliation:"地下経済ネットワーク",tier:"Tier 3"},{id:"フリーダム・ファイター・ストーム",name:"フリーダム・ファイター・ストーム",nameEn:"Freedom Fighter Storm",category:"キャラクター",subCategory:"クレセント拡充",description:"E360年からE408年までクレセント地方で情報活動を展開した自由闘争家。政府の不正情報を暴露し、市民の意識覚醒を促すプロパガンダ活動において卓越した手腕を発揮した。E385年に創刊した地下新聞「ストーム」は反体制運動の広報媒体として広く読まれ、言論の自由を求める声を代弁した。E398年の大弾圧時に逮捕・投獄されたが、その獄中からのメッセージは人々に自由への希望を与え続けた。",descriptionEn:"A freedom fighter who conducted information operations in the Crescent region from E360 to E408. They demonstrated exceptional skill in exposing government misinformation and propaganda campaigns aimed at raising public awareness. The underground newspaper 'Storm', which they founded in E385, was widely read as a publicity medium for anti-establishment movements, giving voice to calls for freedom of speech. Arrested and imprisoned during the great suppression in E398, their messages from prison continued to give people hope for freedom.",era:"E360〜E408",affiliation:"クレセント言論自由同盟",tier:"Tier 3"},{id:"ネイト・クロス",name:"ネイト・クロス",nameEn:"Nate Cross",category:"キャラクター",subCategory:"クレセント拡充",description:"E370年からE420年までクレセント地方で活動した傭兵団「クロス・カンパニー」の創設者。戦闘経験豊富な傭兵を組織化し、各国政府や企業からの依頼に応じて軍事支援を提供した。政治的立场に縛られない実利主義的な姿勢で、V7設立前のクレセント情勢において複雑な役割を果たした。E400年のエヴァトロン支配期にはテリアン反乱軍への武器供給も行い、エリオス・ウォルドの抵抗運動を裏で支援したとされる。",descriptionEn:"The founder of the mercenary company 'Cross Company', active in the Crescent region from E370 to E420. They organized experienced mercenaries, providing military support in response to requests from various governments and corporations. With their pragmatic, non-partisan stance, they played a complex role in the pre-V7 situation of the Crescent. During the Evatron domination period in E400, they are said to have supplied weapons to the Terian rebel forces and secretly supported Elios Wald's resistance movement.",era:"E370〜E420",affiliation:"クロス・カンパニー",tier:"Tier 3"},{id:"セラ・ムーンライト",name:"セラ・ムーンライト",nameEn:"Cera Moonlight",category:"キャラクター",subCategory:"クレセント拡充",description:"E375年からE425年までクレセント地方で活動した女性外交官・平和運動家。紛争解決と和平交渉において傑出した能力を発揮し、E390年の三国境界紛争の停戦交渉では中立の調停者として重要な役割を果たした。その後もクレセント各国間の対話の推進に努め、のちのV7設立（E515）に至る協力体制の萌芽を育てた。「月光の調停者」として知られ、平和的な問題解決の象徴として現在でも語り継がれている。",descriptionEn:"A female diplomat and peace activist active in the Crescent region from E375 to E425. They demonstrated outstanding abilities in conflict resolution and peace negotiations, playing a crucial role as a neutral mediator in the armistice negotiations for the tri-border conflict in E390. Thereafter, they promoted dialogue among the nations of the Crescent, nurturing the seeds of the cooperative system that would lead to the establishment of V7 in E515. Known as the 'Moonlight Mediator', they are still spoken of today as a symbol of peaceful problem resolution.",era:"E375〜E425",affiliation:"クレセント平和推進協会",tier:"Tier 3"},{id:"レン・ブラックウッド",name:"レン・ブラックウッド",nameEn:"Ren Blackwood",category:"キャラクター",subCategory:"クレセント拡充",description:"E380年からE430年までクレセント地方で活動した情報屋・諜報師。複数の国家の情報機関と取引を行い、クレセント政治の裏側で暗躍した。E400年のエヴァトロン支配期には地下抵抗運動への情報支援を行い、E475年のシルバー・ヴェノム結成の際にも裏で糸を引いたとされる。マスター・ヴェノムとの関連も指摘されており、クレセント暗部の歴史において決定的な役割を果たした裏方の存在。その情報網はのちのシルバー・ヴェノム・アルファ・ヴェノムの基盤となった可能性がある。",descriptionEn:"An information broker and spy active in the Crescent region from E380 to E430. They conducted transactions with multiple intelligence agencies, operating in the shadows behind Crescent politics. During the Evatron domination period in E400, they provided information support to the underground resistance movement, and are also said to have pulled strings behind the formation of Silver Venom in E475. Their connection to Master Venom has also been pointed out, making them a decisive behind-the-scenes figure in the hidden history of the Crescent. Their information network may have become the foundation for later Silver Venom and Alpha Venom.",era:"E380〜E430",affiliation:"独立情報屋",tier:"Tier 3"},{id:"キャプテン・テクロサス第1支隊",name:"第1支隊キャプテン",nameEn:"Captain of Tekrosus 1st Division",category:"キャラクター",subCategory:"テクロサス",description:"E350年からE420年までテクロサス第1支隊を統率した軍人。テクロサス系譜（E15ファランクス → E295三頭政治改編 → E470東方支隊）の中核戦力である第1支隊の指揮官として、クレセント地方の安全保障に従事した。E380年の辺境大戦では先鋒として敵陣の突破に成功し、テクロサスの軍事的威信を高めた。後のボグダス・ジャベリンが継承するテクロサス戦闘教範の完成者であり、セバスチャン・ヴァレリウスの先代にあたる。",descriptionEn:"A military officer who commanded the First Detachment of Teclosas from E350 to E420. As the commander of the First Detachment, a core force within the Teclosas lineage (E15 Phalanx → E295 Triumvirate Reorganization → E470 Eastern Detachment), they were engaged in the security of the Crescent region. In the Border War of E380, they succeeded as a vanguard in breaking through enemy lines, enhancing the military prestige of Teclosas. The one who perfected the Teclosas combat doctrine later inherited by Bogdas Javelin, and the predecessor of Sebastian Valerius.",era:"E350〜E420",affiliation:"テクロサス第1支隊",tier:"Tier 3"},{id:"キャプテン・テクロサス第2支隊",name:"第2支隊キャプテン",nameEn:"Captain of Tekrosus 2nd Division",category:"キャラクター",subCategory:"テクロサス",description:"E355年からE425年までテクロサス第2支隊を統率した軍人。防御戦闘のエキスパートとして知られ、クレセント地方の要塞防衛において類まれな能力を発揮した。E390年の大規模侵攻作戦では3ヶ月にわたり要塞を維持し、敵の攻撃を撃退し続けた。その防御戦術は「不動の第2」として軍内部で伝説化し、のちのワドリナの盾役に通じるテクロサス防衛戦術の伝統を確立した。",descriptionEn:"A military officer who commanded the Second Detachment of Teclosas from E355 to E425. Known as an expert in defensive combat, they demonstrated extraordinary abilities in fortress defense across the Crescent region. In the large-scale invasion operation of E390, they maintained a fortress for three consecutive months, continuously repelling enemy attacks. Their defensive tactics became legendary within the military as 'The Immovable Second', establishing the tradition of Teclosas defensive tactics that would later connect to the role of Wadrina's Shield.",era:"E355〜E425",affiliation:"テクロサス第2支隊",tier:"Tier 3"},{id:"キャプテン・テクロサス第3支隊",name:"第3支隊キャプテン",nameEn:"Captain of Tekrosus 3rd Division",category:"キャラクター",subCategory:"テクロサス",description:"E360年からE430年までテクロサス第3支隊を統率した軍人。機動戦と奇襲作戦の専門家として知られ、少ない戦力で最大の戦果を上げる戦術において卓越していた。E395年の「夜の槍作戦」では、敵の補給線を単独部隊で切断し、戦局を一変させた。第3支隊はテクロサスの「影の牙」として恐れられ、その機動的な戦闘スタイルはのちのホワイトノイズやミユシャリの諜報・偵察活動の先駆けとなった。",descriptionEn:"A military commander who led the Third Detachment of Teklosus from E360 to E430. Known as a specialist in mobile warfare and surprise operations, he excelled in tactics that achieved maximum results with minimal forces. In the 'Night's Spear Operation' of E395, he single-handedly severed enemy supply lines with a small unit, completely reversing the course of the battle. The Third Detachment was feared as the 'Shadow Fang' of Teklosus, and their mobile combat style pioneered the intelligence and reconnaissance activities of later groups like White Noise and Miyushari.",era:"E360〜E430",affiliation:"テクロサス第3支隊",tier:"Tier 3"},{id:"キャプテン・テクロサス東方支隊",name:"東方支隊キャプテン",nameEn:"Captain of Tekrosus Eastern Division",category:"キャラクター",subCategory:"テクロサス",description:"E400年からE480年までテクロサス東方支隊を統率した軍人。E470年のクレセント大地方常駐に先立ち、東方支隊の再編と展開を指揮した指導者。エリオス・ウォルドの処刑（E470）に衝撃を受け、テクロサスのクレセント関与を強化する決断を下した。セバスチャン・ヴァレリウスの直接の前任者であり、ボグダス・ジャベリンへの移行をスムーズに行った。E490年のセバスチャンのヴァーミリオン恒久駐在開始の基盤を築いた。",descriptionEn:"A military commander who led the Eastern Detachment of Teklosus from E400 to E480. Prior to the permanent deployment to the Crescent Region in E470, he led the reorganization and deployment of the Eastern Detachment. Shocked by the execution of Elios Wald in E470, he made the decision to strengthen Teklosus' involvement in Crescent affairs. He was the direct predecessor of Sebastian Valerius and facilitated a smooth transition to Bogdas Javelin. He laid the foundation for Sebastian's permanent Vermillion residency beginning in E490.",era:"E400〜E480",affiliation:"テクロサス東方支隊",tier:"Tier 3"},{id:"キャプテン・テクロサス特殊部隊",name:"特殊部隊キャプテン",nameEn:"Captain of Tekrosus Special Forces",category:"キャラクター",subCategory:"テクロサス",description:"E365年からE440年までテクロサス特殊部隊を統率した特殊作戦の専門家。通常の軍事作戦では対処不可能な極秘任務を遂行し、各国の情報機関と協力してクレセント地方の治安維持に貢献した。E410年の「ゼロ・アワー作戦」では、大量破壊兵器の移送を阻止し、クレセント全域に及ぶ惨事を回避した。特殊部隊の訓練プログラムを体系化し、テクロサス最強の精鋭部隊としての評価を確立した。その戦術遺産はボグダス・ジャベリンの全メンバーに色濃く受け継がれている。",descriptionEn:"A special operations specialist who commanded the Teklosus Special Forces from E365 to E440. He carried out top-secret missions that conventional military operations could not handle, cooperating with intelligence agencies from various nations to maintain security in the Crescent Region. In the 'Zero Hour Operation' of E410, he prevented the transfer of weapons of mass destruction, avoiding a catastrophe that would have affected the entire Crescent Region. He systematized the training program for the Special Forces, establishing their reputation as Teklosus' elite force. His tactical legacy is strongly carried on by all members of Bogdas Javelin.",era:"E365〜E440",affiliation:"テクロサス特殊部隊",tier:"Tier 3"},{id:"リサーチャー・アルファ",name:"リサーチャー・アルファ",nameEn:"Researcher Alpha",category:"キャラクター",subCategory:"テクロサス",description:"E370年からE450年までテクロサス研究所で次元物理学の基礎研究に従事した首席研究員。ファールージャ社の次元物理学者とは独立に次元理論を研究し、異なるアプローチから次元間相互作用の解明を進めた。E410年に発表した「アルファ次元モデル」は、ペルセポネ事故（E340）の科学的分析に新たな視点を提供した。テクロサス独自の技術開発の方向性を決定づけた理論的基盤の構築者である。",descriptionEn:"Chief researcher at the Teklosus Institute who engaged in fundamental research in dimensional physics from E370 to E450. Independently of physicists from Faruja Corporation, he researched dimensional theory and made progress in understanding interdimensional interactions through different approaches. His 'Alpha Dimension Model,' published in E410, provided new perspectives for the scientific analysis of the Persephone Incident (E340). He was the architect of the theoretical foundation that determined the direction of Teklosus' unique technological development.",era:"E370〜E450",affiliation:"テクロサス研究所",tier:"Tier 3"},{id:"リサーチャー・ベータ",name:"リサーチャー・ベータ",nameEn:"Researcher Beta",category:"キャラクター",subCategory:"テクロサス",description:"E375年からE455年までテクロサス研究所で通信技術と暗号理論の研究に従事した研究員。軍事通信の安全性向上において画期的な成果を残し、敵の通信傍受を防ぐ新暗号方式を開発した。E420年に完成した「ベータ暗号」は解読不可能と評され、テクロサスの情報戦能力を飛躍的に強化した。後のイルミーゼの電子戦技術の先駆けとなる通信セキュリティ技術の確立者。",descriptionEn:"A researcher at the Teklosus Institute who worked on communication technology and cryptography from E375 to E455. He achieved groundbreaking results in improving the security of military communications, developing new encryption methods to prevent enemy eavesdropping. The 'Beta Cipher,' completed in E420, was deemed unbreakable and dramatically enhanced Teklosus' information warfare capabilities. He established communication security technologies that would later influence the electronic warfare technologies of Ilumize.",era:"E375〜E455",affiliation:"テクロサス研究所",tier:"Tier 3"},{id:"リサーチャー・ガンマ",name:"リサーチャー・ガンマ",nameEn:"Researcher Gamma",category:"キャラクター",subCategory:"テクロサス",description:"E380年からE460年までテクロサス研究所でエネルギー兵器の研究開発に従事した兵器技術者。従来の兵器とは異なる原理に基づく新型エネルギー兵器の開発を推進し、テクロサスの軍事的優位性の技術的基盤を強化した。E430年に完成した「ガンマ・ブラスター」のプロトタイプは、のちのレイラ・ヴィレル・ノヴァが使用するプラズマカノンの技術的先祖にあたる。兵器技術と倫理のジレンマに取り組みながら研究を続けた、テクロサス技術陣の良心。",descriptionEn:"A weapons engineer at the Teklosus Institute who worked on the research and development of energy weapons from E380 to E460. He promoted the development of new energy weapons based on principles different from conventional weapons, strengthening the technological foundation of Teklosus' military superiority. The prototype of the 'Gamma Blaster,' completed in E430, was the technological ancestor of the plasma cannon later used by Leila Virel Nova. While grappling with the dilemma between weapons technology and ethics, he continued his research, serving as the conscience of the Teklosus technical team.",era:"E380〜E460",affiliation:"テクロサス研究所",tier:"Tier 3"},{id:"レジスタンス・ワン",name:"レジスタンス・ワン",nameEn:"Resistance One",category:"キャラクター",subCategory:"テクロサス",description:"E420年からE480年までテクロサス内部で反体制活動を行った一号人物。テクロサスの軍国主義的傾向に異議を唱え、軍の民主化と市民軍事の転換を主張した。E450年のテクロサス内部クーデター未遂事件では計画の情報を外部に漏らし、流血の事態を回避した。その行動はテクロサスの組織文化に深い亀裂を入れ、後の東方支隊の独立動向に影響を与えた。コードネーム「ワン」は、単独で抗議を始めたことに由来する。",descriptionEn:"The leading figure in anti-establishment activities within Teklosus from E420 to E480. He objected to Teklosus' militaristic tendencies, advocating for military democratization and the transition to a citizen military. In the failed Teklosus internal coup of E450, he leaked information about the plot to the outside, avoiding a bloody situation. His actions created deep divisions in Teklosus' organizational culture and influenced later independence movements of the Eastern Detachment. His codename 'One' originated from his decision to protest alone.",era:"E420〜E480",affiliation:"テクロサス内部反体制派",tier:"Tier 3"},{id:"レジスタンス・ツー",name:"レジスタンス・ツー",nameEn:"Resistance Two",category:"キャラクター",subCategory:"テクロサス",description:"E425年からE485年までテクロサス内部で活動したレジスタンス・ワンの協力者。情報収集と組織の拡大を担い、テクロサス内の反体制派のネットワークを構築した。E460年には軍内部の人権侵害を内部告発し、国際的な非難を浴びせた。レジスタンス・ワンの逮捕後も活動を継続し、組織の存続を図った。その献身的な活動は、後のシャドウ・リベリオンの理念にも共鳴する軍事組織改革の草分け的存在。",descriptionEn:"A collaborator of Resistance One who operated within Teklosus from E425 to E485. He was responsible for information gathering and organizational expansion, building a network of anti-establishment factions within Teklosus. In E460, he exposed human rights violations within the military, drawing international condemnation. He continued his activities even after the arrest of Resistance One, working to ensure the organization's survival. His dedicated efforts made him a pioneering figure in military organizational reform whose ideals resonated with later Shadow Rebellion movements.",era:"E425〜E485",affiliation:"テクロサス内部反体制派",tier:"Tier 3"},{id:"レジスタンス・スリー",name:"レジスタンス・スリー",nameEn:"Resistance Three",category:"キャラクター",subCategory:"テクロサス",description:"E430年からE490年までテクロサス内部で活動した反体制派の技術担当。テクロサスの機密情報へのアクセス権を利用して、軍事機密の保護と透明性の両立を模索した。E465年に開発した内部監視システムの迂回ツールは、反体制派の安全な通信を可能にした。レジスタンス・ツーの情報網と連携し、テクロサス内部の民主化運動を技術面から支えた。後のボグダス・ジャベリンの電子戦能力にも間接的な影響を与えた。",descriptionEn:"The technical officer of the anti-establishment faction within Teklosus from E430 to E490. Using his access to Teklosus' classified information, he sought to balance military secrecy with transparency. In E465, he developed a tool to bypass internal surveillance systems, enabling secure communication for the anti-establishment faction. He coordinated with Resistance Two's information network, supporting the democratization movement within Teklosus from a technical perspective. His work also indirectly influenced the electronic warfare capabilities of later Bogdas Javelin.",era:"E430〜E490",affiliation:"テクロサス内部反体制派",tier:"Tier 3"},{id:"レジスタンス・フォー",name:"レジスタンス・フォー",nameEn:"Resistance Four",category:"キャラクター",subCategory:"テクロサス",description:"E435年からE495年までテクロサス内部で活動した反体制派の外交担当。テクロサス外部の民主主義勢力との連携を構築し、国際社会へのテクロサス批判の拡散を図った。E470年にはクレセント大地方の民主化運動との接触を確立し、テクロサス東方支隊のクレセント常駐を後押しした。四人のレジスタンス中最後まで自由の身であり、E495年に自らの意思でテクロサスを離脱。その後の動向は不明だが、自由のために戦い続けたと伝えられている。",descriptionEn:"The diplomatic officer of the anti-establishment faction within Teklosus from E435 to E495. He built connections with democratic forces outside Teklosus, aiming to spread criticism of Teklosus in the international community. In E470, he established contact with the democratization movement in the Crescent Region, supporting the permanent deployment of the Teklosus Eastern Detachment there. He was the last of the four Resistances to remain free, voluntarily leaving Teklosus in E495. His subsequent whereabouts are unknown, but it is said that he continued to fight for freedom.",era:"E435〜E495",affiliation:"テクロサス内部反体制派",tier:"Tier 3"},{id:"ステーション・マスター・オルビット",name:"ステーション・マスター・オルビット",nameEn:"Station Master Orbit",category:"キャラクター",subCategory:"Eros-7",description:"E300年からE420年までEros-7宇宙ステーションの初代ステーション・マスターを務めた管理者。宇宙ステーションの建設計画の立案から完成までを統括し、人類初の軌道上居住空間の実現に尽力した。E310年のステーション完成時には「宇宙への扉を開いた男」として広く称賛された。閉鎖環境の管理と居住者の生活維持において卓越した能力を発揮し、Eros-7を安全で自立した宇宙都市へと成長させた。彼の運営方針は「オルビット・スタンダード」として後のステーション管理の規範となった。",descriptionEn:"An administrator who served as the first Station Master of Eros-7 Space Station from E300 to E420. He oversaw the planning and completion of the space station's construction, dedicating himself to realizing humanity's first orbital living space. Upon the station's completion in E310, he was widely praised as 'the man who opened the door to space.' He demonstrated exceptional abilities in managing the closed environment and maintaining residents' well-being, growing Eros-7 into a safe and self-sufficient space city. His operational policies became the 'Orbit Standard,' serving as the norm for later station management.",era:"E300〜E420",affiliation:"Eros-7ステーション管理局",tier:"Tier 3"},{id:"オペレーター・コスモ",name:"オペレーター・コスモ",nameEn:"Operator Cosmo",category:"キャラクター",subCategory:"Eros-7",description:"E305年からE430年までEros-7の中枢制御システムの運用を担当したオペレーター。ステーションの生命維持・通信・航行の各システムの統合管理において、類まれなる状況判断力で幾度もの危機を回避した。E340年の太陽フレア緊急事態では、適切なシールド操作で居住区を守り抜いた。E380年に開発した自動制御プロトコルはEros-7の安全性を飛躍的に向上させ、後のパイオニアたちの宇宙探査活動の基盤技術となった。",descriptionEn:"An operator who managed the central control system of Eros-7 from E305 to E430. Through his extraordinary judgment in the integrated management of the station's life support, communications, and navigation systems, he avoided numerous crises. During the solar flare emergency of E340, he properly shielded the residential areas, protecting them from harm. The automatic control protocol he developed in E380 dramatically improved Eros-7's safety, becoming foundational technology for the space exploration activities of later Pioneers.",era:"E305〜E430",affiliation:"Eros-7中枢制御室",tier:"Tier 3"},{id:"エンジニア・スター",name:"エンジニア・スター",nameEn:"Engineer Star",category:"キャラクター",subCategory:"Eros-7",description:"E308年からE435年までEros-7のインフラ維持を担当した主席エンジニア。宇宙環境下での設備保守と新規建設において先駆的な技術を開発し、ステーションの拡張と機能向上に寄与した。E350年には第2居住モジュールの設計と建設を指揮し、Eros-7の収容能力を倍増させた。宇宙空間での作業効率を高める特殊ツールの発明も多数行い、その技術的遺産は現在の宇宙建設の標準手法として受け継がれている。",descriptionEn:"Chief Engineer who maintained Eros-7's infrastructure from E308 to E435. Pioneered groundbreaking techniques for equipment maintenance and new construction in space environments, contributing to the station's expansion and enhanced functionality. In E350, commanded the design and construction of the second habitat module, doubling Eros-7's capacity. Also invented numerous specialized tools to improve work efficiency in space, whose technical legacy continues as standard methods in modern space construction.",era:"E308〜E435",affiliation:"Eros-7技術部門",tier:"Tier 3"},{id:"マイナー・ディープ",name:"マイナー・ディープ",nameEn:"Miner Deep",category:"キャラクター",subCategory:"Eros-7",description:"E320年からE480年までEros-7周辺の小惑星帯で資源採掘に従事した鉱夫。深層鉱脈の発見と採掘技術の革新において指導的役割を果たし、Eros-7の資源自給体制を確立した。E380年に発見したディープ鉱脈はEDU最大のレアメタル鉱床であり、クレセント地方の重工業発展に不可欠な資源を供給した。危険な採掘現場で常に先頭に立ち、「深淵の探求者」として労働者たちから深い敬意を集めた。",descriptionEn:"Miner who worked in the asteroid belt around Eros-7 from E320 to E480, extracting resources. Played a leading role in discovering deep mineral veins and innovating mining techniques, establishing Eros-7's self-sufficient resource system. The deep mineral vein discovered in E380 became EDU's largest rare metal deposit, supplying essential resources for the industrial development of the Crescent region. Always at the forefront of dangerous mining sites, he earned deep respect from workers as the 'Abyss Explorer.'",era:"E320〜E480",affiliation:"Eros-7採掘局",tier:"Tier 3"},{id:"マイナー・コア",name:"マイナー・コア",nameEn:"Miner Core",category:"キャラクター",subCategory:"Eros-7",description:"E325年からE475年までEros-7周辺の資源採掘において鉱石の精製と品質管理を担当した技術者。採掘された原鉱石から高純度の金属材料を抽出する精製プロセスの改良において画期的な成果を上げた。E370年に開発した「コア式精製法」は効率と品質の両面で従来法を大幅に上回り、Eros-7の産業的価値を飛躍的に高めた。アイアン・シンジケートへの材料供給の技術的基盤を築いた重要人物。",descriptionEn:"Technician responsible for ore refining and quality control in Eros-7's resource extraction operations from E325 to E475. Achieved groundbreaking results in refining processes that extracted high-purity metal ores from raw minerals. The 'Core Refining Method' developed in E370 far surpassed conventional methods in both efficiency and quality, dramatically increasing Eros-7's industrial value. A key figure who established the technical foundation for material supply to the Iron Syndicate.",era:"E325〜E475",affiliation:"Eros-7精製所",tier:"Tier 3"},{id:"マイナー・クラスト",name:"マイナー・クラスト",nameEn:"Miner Crust",category:"キャラクター",subCategory:"Eros-7",description:"E330年からE470年までEros-7周辺の地表・地殻探査に従事した地質学者。小惑星の地質構造の解明と鉱脈の予測において卓越した能力を発揮し、新たな採掘地点の発見に大きく貢献した。E365年に作成した「クラスト地質図」はEros-7周辺の資源分布を正確に示し、採掘計画の効率化に決定的な役割を果たした。地質学的知見と探査技術の融合により、Eros-7を星域最大の資源地帯の一つに押し上げた。",descriptionEn:"Geologist who conducted surface and crustal surveys around Eros-7 from E330 to E470. Demonstrated exceptional abilities in analyzing asteroid geological structures and predicting mineral veins, significantly contributing to the discovery of new mining sites. The 'Crust Geological Map' created in E365 accurately depicted resource distribution around Eros-7, playing a decisive role in optimizing mining plans. Through the fusion of geological knowledge and exploration techniques, elevated Eros-7 to one of the sector's largest resource zones.",era:"E330〜E470",affiliation:"Eros-7地質調査団",tier:"Tier 3"},{id:"パイオニア・フロンティア",name:"パイオニア・フロンティア",nameEn:"Pioneer Frontier",category:"キャラクター",subCategory:"Eros-7",description:"E400年からE510年までEros-7を拠点に未知の星域の探査を主導した宇宙探検家。Eros-7からさらに遠方の領域への探査ルートを開拓し、新たな資源地と居住可能領域の発見に尽力した。E450年の「フロンティア遠征」では7つの新惑星を発見し、EDUの活動領域を大幅に拡大した。その探査精神と冒険心は「最後のパイオニア」として称えられ、新世界編（E520〜）の開拓者たちに精神的な影響を与えた。",descriptionEn:"Space explorer who led expeditions into uncharted star systems with Eros-7 as a base from E400 to E510. Pioneered exploration routes to regions beyond Eros-7, dedicating efforts to discovering new resource deposits and habitable areas. During the 'Frontier Expedition' in E450, discovered seven new planets, significantly expanding EDU's sphere of operations. His spirit of exploration and adventure is celebrated as that of the 'Last Pioneer,' exerting spiritual influence on the pioneers of the New World Era (E520-).",era:"E400〜E510",affiliation:"Eros-7探査隊",tier:"Tier 3"},{id:"パイオニア・ホライズン",name:"パイオニア・ホライズン",nameEn:"Pioneer Horizon",category:"キャラクター",subCategory:"Eros-7",description:"E410年からE515年までEros-7の遠方通信網の構築に従事した通信技術者。パイオニア・フロンティアの探査活動を通信面から支援し、未知領域との通信を可能にする中継システムを構築した。E460年に設置した「ホライズン・リレー」は、それまで不可能とされていた超長距離通信を実現し、EDUの情報ネットワークを飛躍的に拡大した。Eros-7からクレセント大地方への高速通信路の確立にも貢献し、地域間の情報格差の解消に尽力した。",descriptionEn:"Communications technician who constructed Eros-7's long-distance communication network from E410 to E515. Supported Pioneer Frontier exploration activities through communications infrastructure, building relay systems that enabled communication with unknown regions. The 'Horizon Relay' installed in E460 achieved ultra-long-distance communication previously deemed impossible, dramatically expanding EDU's information network. Also contributed to establishing high-speed communication routes from Eros-7 to the Greater Crescent Region, working to eliminate information disparities between regions.",era:"E410〜E515",affiliation:"Eros-7通信部門",tier:"Tier 3"},{id:"パイオニア・ネビュラ",name:"パイオニア・ネビュラ",nameEn:"Pioneer Nebula",category:"キャラクター",subCategory:"Eros-7",description:"E415年からE518年までEros-7で異星環境の生態系調査に従事した宇宙生物学者。パイオニア・フロンティアが発見した新惑星の生態系を体系的に調査し、多様な異星生物の記録と分類を行った。E470年に発見した共生型微生物群は、地球外生命の存在を示す決定的な証拠として学界に衝撃を与えた。その研究は異星環境での農業と医療への応用も視野に入れ、新世界における人類の生存基盤を科学的に裏付けた。",descriptionEn:"Astrobiologist who studied extraterrestrial ecosystems on Eros-7 from E415 to E518. Systematically investigated the ecosystems of new planets discovered by the Pioneer Frontier, documenting and classifying diverse alien organisms. The symbiotic microbial community discovered in E470 sent shockwaves through the academic community as definitive evidence of extraterrestrial life. Her research also considered applications for agriculture and medicine in extraterrestrial environments, providing scientific validation for humanity's survival foundation in the New World.",era:"E415〜E518",affiliation:"Eros-7生物研究所",tier:"Tier 3"},{id:"パイオニア・オーロラ",name:"パイオニア・オーロラ",nameEn:"Pioneer Aurora",category:"キャラクター",subCategory:"Eros-7",description:"E420年からE520年までEros-7で新天地への移住計画を主導した開拓者。パイオニア・フロンティアが発見した居住可能惑星への入植プロジェクトを策定し、移住の logistics とインフラ建設の計画を立案した。E490年に発表した「オーロラ計画」は、数千人の入植者を新惑星へ送る野心的な構想であり、新世界編（E520〜）における本格的な開拓の青写真となった。E520年には自ら第一陣の入植者としてEros-7を出発し、新たな時代の幕開けを告げた。",descriptionEn:"Pioneer who led resettlement plans to new worlds from E415 to E520 on Eros-7. Formulated settlement projects for habitable planets discovered by the Pioneer Frontier, planning logistics and infrastructure construction for migration. The 'Aurora Plan' announced in E490 was an ambitious vision to send thousands of settlers to new planets, becoming the blueprint for full-scale colonization in the New World Era (E520-). In E520, departed Eros-7 as part of the first wave of settlers, heralding the dawn of a new era.",era:"E420〜E520",affiliation:"Eros-7開拓局",tier:"Tier 3"},{id:"副官・クリムゾン",name:"副官・クリムゾン",nameEn:"Vice Commander Crimson",category:"キャラクター",subCategory:"Shadow Rebellion",description:"E450年から現在までシャドウ・リベリオンの副官として活動し、アルファ・ケインに次ぐNo.2の地位を占める実行部隊の指揮官。E450年代の反乱再興期において組織の実働部隊を再編成し、ZAMLT崩壊後のギガポリス情勢において影響力を維持した。赤い戦闘服がトレードマークの「深紅の副官」として知られ、前線指揮と組織運営の両面でアルファ・ケインを補佐した。E500年以降は表舞台から退き、リベリオンの基盤維持に注力しているとされる。",descriptionEn:"Operations commander who has served as the Shadow Rebellion's second-in-command since E450, holding the position second only to Alpha Kane. Reorganized the organization's operational forces during the rebellion's resurgence in the E450s, maintaining influence in the Gigapolis situation following ZAMLT's collapse. Known as the 'Crimson Adjutant' for his trademark red combat uniform, he assisted Alpha Kane in both frontline command and organizational operations. Since E500, has reportedly retreated from public view, focusing on maintaining the rebellion's foundation.",era:"E450〜現在",affiliation:"シャドウ・リベリオン",tier:"Tier 3"},{id:"副官・サファイア",name:"副官・サファイア",nameEn:"Vice Commander Sapphire",category:"キャラクター",subCategory:"Shadow Rebellion",description:"E460年から現在までシャドウ・リベリオンの情報部門を統括する副官。情報収集・分析・工作活動において卓越した能力を発揮し、組織の「目と耳」として機能している。E480年代にはクレセント地方への情報網の拡張を主導し、シルバー・ヴェノムやアルファ・ヴェノムの動向把握に貢献した。冷静沈着な分析力で知られ、感情に流されない客観的判断で組織の意思決定を支える。クリムゾンの前線指揮と対照的な、裏方の要として不可欠な存在。",descriptionEn:"Intelligence officer who has commanded the Shadow Rebellion's intelligence division since E460. Demonstrates exceptional abilities in intelligence gathering, analysis, and covert operations, serving as the organization's 'eyes and ears.' Led the expansion of the intelligence network into the Crescent Region during the E480s, contributing to monitoring the activities of Silver Venom and Alpha Venom. Known for calm analytical abilities and objective judgments free from emotion, supporting the organization's decision-making. An indispensable figure behind the scenes, contrasting with Crimson's frontline command.",era:"E460〜現在",affiliation:"シャドウ・リベリオン",tier:"Tier 3"},{id:"副官・エメラルド",name:"副官・エメラルド",nameEn:"Vice Commander Emerald",category:"キャラクター",subCategory:"Shadow Rebellion",description:"E465年から現在までシャドウ・リベリオンの後方支援部門を統括する副官。兵站管理・武器調達・安全な隠れ家の確保など、組織の維持に不可欠な実務を一手に引き受けている。E475年のエヴァトロン崩壊後には、旧ZAMLT施設の再利用とリベリオン拠点の整備を主導した。実務能力に優れ、複雑な logistics を最適化する手腕は組織内部で「エメラルドの魔法」と称されている。表舞台に立つことは少ないが、リベリオンの存続に最も不可欠な人物。",descriptionEn:"Logistics officer who has commanded the Shadow Rebellion's support division since E465. Single-handedly manages all essential operations for the organization's maintenance, including supply chain management, weapons acquisition, and securing safe hideouts. Led the repurposing of former ZAMLT facilities and the development of rebel bases following Evatron's collapse in E475. Praised for exceptional practical skills and optimizing complex logistics, known within the organization as the 'Emerald Magic.' Though rarely in the spotlight, is the most essential figure for the rebellion's survival.",era:"E465〜現在",affiliation:"シャドウ・リベリオン",tier:"Tier 3"},{id:"セル・リーダー・ノース",name:"セル・リーダー・ノース",nameEn:"Cell Leader North",category:"キャラクター",subCategory:"Shadow Rebellion",description:"E470年から現在までシャドウ・リベリオンの北部方面のセル・リーダーとして活動している現場指揮官。ギガポリス北部地区を拠点に小規模な独立細胞を指揮し、ZAMLT残党やエヴァトロン勢力への抵抗を継続している。E400年代のテリアン反乱軍の精神を受け継ぎ、市民の自由回復を旗印に活動している。北部の複雑な地形を活用したゲリラ戦術を得意とし、正規軍を翻弄し続けている。",descriptionEn:"Field commander who has served as the Shadow Rebellion's Northern Sector cell leader since E470. Commands small independent cells based in the northern regions of Gigapolis, continuing resistance against ZAMLT remnants and Evatron forces. Carries on the spirit of the Terian Rebellion forces from the E400s, operating under the banner of restoring citizen freedom. Excels in guerrilla tactics that utilize the complex terrain of the northern regions, consistently confounding regular army forces.",era:"E470〜現在",affiliation:"シャドウ・リベリオン北部セル",tier:"Tier 3"},{id:"セル・リーダー・サウス",name:"セル・リーダー・サウス",nameEn:"Cell Leader South",category:"キャラクター",subCategory:"Shadow Rebellion",description:"E472年から現在までシャドウ・リベリオンの南部方面のセル・リーダーとして活動している現場指揮官。ギガポリス南部の地下街を拠点に、Tina/Gueの地下世界とも複雑な関係を築きながら活動している。南部の商業エリアを利用した資金調達と情報収集において独特のネットワークを構築した。ノースとは異なる都市型ゲリラ戦術を駆使し、都市の地下構造を熟知した戦闘で敵を翻弄する。",descriptionEn:"A field commander serving as the Southern Sector Cell Leader of the Shadow Rebellion from E472 to the present. Operating from the underground streets of southern Gigapolis, they have cultivated complex relationships with Tina/Gue's underworld while building a unique network for fundraising and intelligence gathering through commercial areas in the south. Employing urban guerrilla tactics distinct from those of North, they confound enemies through combat leveraging their intimate knowledge of the city's underground structures.",era:"E472〜現在",affiliation:"シャドウ・リベリオン南部セル",tier:"Tier 3"},{id:"セル・リーダー・イースト",name:"セル・リーダー・イースト",nameEn:"Cell Leader East",category:"キャラクター",subCategory:"Shadow Rebellion",description:"E475年から現在までシャドウ・リベリオンの東部方面のセル・リーダーとして活動している現場指揮官。クレセント地方への連絡ルートの維持と情報の中継において重要な役割を果たしている。ボグダス・ジャベリン（テクロサス東方支隊の後継）との非公式な連携も構築し、東西の抵抗運動の架け橋として機能している。東部の国境地域における密輸ルートの管理も担当し、リベリオンの物流を支える実務家。",descriptionEn:"A field commander serving as the Eastern Sector Cell Leader of the Shadow Rebellion from E475 to the present. Plays a crucial role in maintaining contact routes to the Crescent Region and relaying information. Has also built informal cooperation with Bogdas Javelin (successor to the Technosus Eastern Detachment), functioning as a bridge between eastern and western resistance movements. Also manages smuggling routes in border regions of the east, serving as the logistical backbone of the Rebellion.",era:"E475〜現在",affiliation:"シャドウ・リベリオン東部セル",tier:"Tier 3"},{id:"セル・リーダー・ウエスト",name:"セル・リーダー・ウエスト",nameEn:"Cell Leader West",category:"キャラクター",subCategory:"Shadow Rebellion",description:"E478年から現在までシャドウ・リベリオンの西部方面のセル・リーダーとして活動している現場指揮官。Valoria連合圏（ジェンの支配地域）との境界付近で活動し、リベリオンの西方戦線を維持している。ジェンの勢力との直接的衝突を避けつつ、独自の展開でリベリオンの影響力の拡大を図る pragmatic な指揮官。西部の山岳地帯を利用した訓練キャンプの運営も担当し、次世代のリベリオン戦士の育成に尽力している。",descriptionEn:"A field commander serving as the Western Sector Cell Leader of the Shadow Rebellion from E478 to the present. Operates near the border with the Valorian Alliance Zone (Jen's territory), maintaining the Rebellion's western front. A pragmatic commander who avoids direct confrontation with Jen's forces while working to expand the Rebellion's influence through independent initiatives. Also oversees training camps in western mountainous regions, dedicating themselves to cultivating the next generation of Rebellion warriors.",era:"E478〜現在",affiliation:"シャドウ・リベリオン西部セル",tier:"Tier 3"},{id:"デザーター・レイ",name:"デザーター・レイ",nameEn:"Deserter Ray",category:"キャラクター",subCategory:"Shadow Rebellion",description:"E490年に正規軍を脱走してシャドウ・リベリオンに参加した元軍人。元テクロサス第2支隊の下級士官であり、軍の内部情報と戦術をリベリオンにもたらした。脱走の動機は軍の民主化要求に賛同したためとされ、レジスタンス・ワンらの反体制運動の影響を受けている。テクロサスの軍事教範を熟知する戦術家であり、リベリオンの戦闘力強化に貢献した。「裏切者」という烙印を背負いながらも、信念に従って自由のために戦うことを選んだ複雑な人物。",descriptionEn:"A former military officer who deserted the regular army in E490 to join the Shadow Rebellion. A former junior officer of the Technosus 2nd Detachment who brought military intelligence and tactics to the Rebellion. Their desertion is said to stem from their support for the military's democratization demands, influenced by anti-establishment movements like Resistance One. A tactician well-versed in Technosus military doctrine who has contributed to strengthening the Rebellion's combat capability. A complex character who bears the stigma of 'traitor' but chooses to fight for freedom according to their convictions.",era:"E490〜現在",affiliation:"シャドウ・リベリオン",tier:"Tier 3"},{id:"デザーター・ミスト",name:"デザーター・ミスト",nameEn:"Deserter Mist",category:"キャラクター",subCategory:"Shadow Rebellion",description:"E495年にエヴァトロン残党の部隊から脱走してシャドウ・リベリオンに参加した元兵士。エヴァトロン支配期（E400〜E475）の末期に徴兵され、残酷な軍事訓練を受けたが、組織の崩壊とともに離反した。エヴァトロンの戦術と装備の知識をリベリオンに提供し、かつての同志たちの戦闘パターンの分析に貢献した。「霧のように姿を消した」という異名の通り、脱走の経緯には謎が多く、一部では二重スパイの可能性も囁かれている。",descriptionEn:"A former soldier who deserted from the remnants of the Evatron forces in E495 to join the Shadow Rebellion. Conscripted during the final days of Evatron rule (E400-E475), they received brutal military training but defected along with the organization's collapse. Provided the Rebellion with knowledge of Evatron tactics and equipment, contributing to analyzing combat patterns of former comrades. As their nickname 'disappearing like mist' suggests, their circumstances of desertion remain mysterious, with some whispering about the possibility of being a double agent.",era:"E495〜現在",affiliation:"シャドウ・リベリオン",tier:"Tier 3"},{id:"ルナ・ノヴァ三世",name:"ルナ・ノヴァ三世",nameEn:"Luna Nova III",category:"キャラクター",subCategory:"新世界編",description:"E520年の新世界開拓期に台頭した新世代の指導者。バーズ帝国期のルナ・サバイバーの血統を引くとされ、その不屈の精神を受け継いでいる。E520年のオーロラ計画に第三世代のリーダーとして参加し、新惑星での入植地建設の陣頭指揮を執った。AURALIS Collective第二世代（E522発足）とも協調関係を築き、新世界における文化と芸術の振興を掲げる。E525年には新世界評議会の初代議長に就任し、多世界協調体制の構築に挑む新時代の象徴的人物。",descriptionEn:"A new-generation leader who emerged during the New World colonization period of E520. Said to be descended from the bloodline of Luna Survivors from the Bartz Empire era, inheriting their indomitable spirit. Participated in the Aurora Project in E520 as the third-generation leader, commanding the construction of settlements on the new planet. Built cooperative relationships with the AURALIS Collective's second generation (established E522), advocating for the promotion of culture and art in the New World. Became the first chairman of the New World Council in E525, emerging as a symbolic figure of the new era challenging the construction of a multi-world coordination system.",era:"E520〜現在",affiliation:"新世界評議会",tier:"Tier 2"},{id:"カイ・エコー",name:"カイ・エコー",nameEn:"Kai Echo",category:"キャラクター",subCategory:"新世界編",description:"E520年の新世界開拓期に現れた新世代の技術者。バーズ帝国期のカイ・アシュフォードの通信技術の系譜を受け継ぎ、新世界と旧世界を結ぶ超長距離通信システムの開発を主導した。E523年に完成した「エコー・リンク」は、Eros-7から新惑星までのリアルタイム通信を実現し、EDU全体の情報ネットワークを統合する画期的な技術となった。技術と人類の進歩を結びつけるビジョンを持ち、新世界における科学技術の発展方向を決定づけるキーパーソン。",descriptionEn:"A new-generation engineer who appeared during the New World colonization period of E520. Inheriting the lineage of Kai Ashford's communication technology from the Bartz Empire era, they led the development of ultra-long-range communication systems connecting the New World and the Old World. The 'Echo Link' completed in E523 achieved real-time communication from Eros-7 to the new planet, becoming a groundbreaking technology that integrated the information networks across the entire EDU. Possessing a vision that connects technology with human progress, they are a key figure determining the direction of scientific and technological development in the New World.",era:"E520〜現在",affiliation:"新世界通信公社",tier:"Tier 2"},{id:"ミラ・レゾナンス",name:"ミラ・レゾナンス",nameEn:"Mira Resonance",category:"キャラクター",subCategory:"新世界編",description:"E522年のAURALIS Collective第二世代発足と同時に新世界支部の代表として活動を開始した芸術家。「光と音」の理念を新世界に広める使命を帯び、入植地でのパフォーマンスと芸術教育を通じて文化的基盤の構築に尽力した。レイラ・ヴィレル・ノヴァ（Pink Voltage）の精神的後継者として、芸術を通じた社会変革を掲げる。E525年には新世界初の大規模芸術祭「レゾナンス・フェスト」を開催し、多様な文化の交歓の場を創出した。",descriptionEn:"An artist who began activities as the representative of the New World branch upon the establishment of the AURALIS Collective's second generation in E522. Bearing the mission to spread the philosophy of 'light and sound' in the New World, they dedicated themselves to building a cultural foundation through performances and art education in settlements. As the spiritual successor of Leila Virel Nova (Pink Voltage), they advocate for social transformation through art. In E525, they hosted the New World's first large-scale arts festival, 'Resonance Fest,' creating a space for cultural exchange among diverse cultures.",era:"E522〜現在",affiliation:"AURALIS Collective第二世代 / 新世界支部",tier:"Tier 2"},{id:"ソル・ハーモニー",name:"ソル・ハーモニー",nameEn:"Sol Harmony",category:"キャラクター",subCategory:"新世界編",description:"E521年に新世界で発見された先住知的生命体との第一次接触を担当した外交官・言語学者。異種族間のコミュニケーションの構築において類まれな能力を発揮し、入植者と先住民の平和的な共存関係の確立に貢献した。E524年に策定した「ハーモニー協定」は、両種族の権利と義務を定めた画期的な条約であり、EDU史において初めて地球外知的生命体との公式協定となった。異文化理解と平和的共生の象徴として、新世界編の最重要人物の一人。",descriptionEn:"A diplomat and linguist who handled first contact with indigenous intelligent life forms discovered in the New World in E521. Demonstrated extraordinary abilities in building communication between different species, contributing to establishing peaceful coexistence between settlers and indigenous peoples. The 'Harmony Accord' formulated in E524 was a groundbreaking treaty defining the rights and obligations of both species, becoming the first official agreement with extraterrestrial intelligent life in EDU history. As a symbol of cross-cultural understanding and peaceful coexistence, they rank among the most important figures in the New World saga.",era:"E521〜現在",affiliation:"新世界評議会 / 異種族外交局",tier:"Tier 2"},{id:"ネイ・フューチャー",name:"ネイ・フューチャー",nameEn:"Ney Future",category:"キャラクター",subCategory:"新世界編",description:"E520年の新世界開拓期にEros-7から派遣された次世代の行政官。新世界での行政システムの構築と法制度の整備を担当し、オールドワールドの経験を新環境に適応させた。E524年に制定した「新世界基本法」は、旧世界の法体系と新環境の現実を融合させた革新的な法典である。ヴァレリア・トルクアタとエルダー・タイガーの法的遺産を継承しつつ、先住民の権利も保護する包括的な法制度を確立した法の新世代。",descriptionEn:"A next-generation administrator dispatched from Eros-7 to the New World during the colonization period of E520. Responsible for constructing the administrative system and legal framework of the New World, adapting Old World experience to the new environment. The 'New World Fundamental Law' enacted in E524 was an innovative legal code that merged the legal systems of the Old World with the realities of the new environment. While inheriting the legal legacy of Valeria Torquata and Elder Tiger, they established a comprehensive legal system that also protected the rights of indigenous peoples—a new generation of law.",era:"E520〜現在",affiliation:"新世界評議会 / 法務局",tier:"Tier 2"},{id:"ビューロクラット・アルファ",name:"ビューロクラット・アルファ",nameEn:"Bureaucrat Alpha",category:"キャラクター",subCategory:"新世界編",description:"E522年に新世界評議会の行政局次官として就任した行政官。新世界の官僚制度の設計と運営を担当し、入植地の効率的な行政サービスの提供に尽力した。オールドワールドの行政経験を基に、新環境に適した行政手続きの簡素化と効率化を推進した。E525年の行政改革では4人のビューロクラットの協調体制を構築し、新世界行政の四本柱として機能している。特に財政管理と予算配分において卓越した手腕を発揮している。",descriptionEn:"An administrator who took office as Deputy Director of the Administrative Bureau of the New World Council in E522. Responsible for designing and operating the New World's bureaucratic system, striving to provide efficient administrative services to settlements. Based on administrative experience from the Old World, they promoted simplification and efficiency of administrative procedures suitable for the new environment. In the E525 administrative reform, they built a coordinated system of four bureaucrats, functioning as the four pillars of New World administration. Particularly excelling in financial management and budget allocation.",era:"E522〜現在",affiliation:"新世界評議会行政局",tier:"Tier 3"},{id:"ビューロクラット・ベータ",name:"ビューロクラット・ベータ",nameEn:"Bureaucrat Beta",category:"キャラクター",subCategory:"新世界編",description:"E523年に新世界評議会の治安局次官として就任した行政官。新世界における治安維持と法執行体制の構築を担当した。オールドワールドの治安機関の経験と新世界の独自の課題を分析し、コミュニティ重視の治安モデルを策定した。先住民との摩擦の防止にも注力し、文化的配慮を取り入れた法執行ガイドラインを作成した。シェリフ・ブラスの保安官制度とエリオス・ウォルドの市民権思想の両方を継承する新しい治安の形。",descriptionEn:"An administrator who took office as Deputy Director of the Public Safety Bureau of the New World Council in E523. Responsible for maintaining public order and constructing law enforcement systems in the New World. Analyzed experiences from Old World law enforcement agencies and the unique challenges of the New World, formulating a community-focused policing model. Focused on preventing friction with indigenous peoples and created culturally sensitive law enforcement guidelines. A new form of public safety that inherits both Sheriff Brass's sheriff system and Erios Wald's citizenship ideas.",era:"E523〜現在",affiliation:"新世界評議会治安局",tier:"Tier 3"},{id:"ビューロクラット・ガンマ",name:"ビューロクラット・ガンマ",nameEn:"Bureaucrat Gamma",category:"キャラクター",subCategory:"新世界編",description:"E522年に新世界評議会の産業局次官として就任した行政官。新世界における産業基盤の構築と経済発展の計画を担当した。オールドワールドの産業経験を活かしつつ、新環境の資源特性に適した産業政策を立案した。E524年に策定した「新世界産業基本計画」は、農業・鉱業・製造業のバランスの取れた発展を目指す包括的な青写真である。エコノミスト・ゴールドとチーフ・ドラゴンの経済・産業思想を新世界で実現する実務家。",descriptionEn:"An administrator who assumed the position of Vice-Director of the Bureau of Industry for the New World Council in E522. They were responsible for establishing the industrial foundation of the New World and planning its economic development. Leveraging industrial experience from the Old World, they formulated industrial policies suited to the resource characteristics of the new environment. The 'New World Industrial Basic Plan' formulated in E524 serves as a comprehensive blueprint aiming for balanced development in agriculture, mining, and manufacturing. A practitioner who realized the economic and industrial philosophies of Economist Gold and Chief Dragon in the New World.",era:"E522〜現在",affiliation:"新世界評議会産業局",tier:"Tier 3"},{id:"ビューロクラット・デルタ",name:"ビューロクラット・デルタ",nameEn:"Bureaucrat Delta",category:"キャラクター",subCategory:"新世界編",description:"E523年に新世界評議会の外務局次官として就任した行政官。新世界とオールドワールド（ギガポリス・クレセント・Eros-7）との外交関係の構築を担当した。複数の政治勢力との並行交渉において卓越した外交手腕を発揮し、新世界の国際的地位の確立に貢献した。E525年のV7・トリニティ・アライアンス双方との外交協定締結にも関与し、新世界の中立性と独立性の保障に尽力した。イサベラ・コルネリウスの外交路線の新世代における継承者。",descriptionEn:"An administrator who assumed the position of Vice-Director of the Bureau of Foreign Affairs for the New World Council in E523. They were tasked with establishing diplomatic relations between the New World and the Old World (Gigapolis Crescent Eros-7). Demonstrating exceptional diplomatic skills in parallel negotiations with multiple political forces, they contributed to establishing the New World's international standing. They also participated in the conclusion of diplomatic agreements with both the V7 and Trinity Alliance in E525, striving to guarantee the neutrality and independence of the New World. A successor to Isabella Cornelius' diplomatic approach in the new generation.",era:"E523〜現在",affiliation:"新世界評議会外務局",tier:"Tier 3"},{id:"テクニシャン・クオンタム",name:"テクニシャン・クオンタム",nameEn:"Technician Quantum",category:"キャラクター",subCategory:"新世界編",description:"E520年に新世界で最先端技術の実装を担当した技術者。ファールージャ社の次元極地平技術を新世界のインフラに応用し、次世代の通信・輸送・エネルギーシステムを構築した。E524年に新世界で初めて次元ゲートのプロトタイプを稼働させ、惑星間輸送の革命をもたらした。ドクター・ファールージャ社次元物理学者の理論的成果を実用化する橋渡し役であり、新世界の技術的優位性の確立に決定的な役割を果たした。",descriptionEn:"An engineer responsible for implementing cutting-edge technology in the New World in E520. They applied Farooja Corporation's dimensional horizon technology to New World infrastructure, constructing next-generation communication, transportation, and energy systems. In E524, they successfully operated the first prototype of a dimensional gate in the New World, revolutionizing interplanetary transport. Serving as a bridge to practicalize the theoretical achievements of Dr. Farooja Corporation's dimensional physicists, they played a decisive role in establishing the New World's technological superiority.",era:"E520〜現在",affiliation:"新世界技術開発局",tier:"Tier 3"},{id:"テクニシャン・テンポラル",name:"テクニシャン・テンポラル",nameEn:"Technician Temporal",category:"キャラクター",subCategory:"新世界編",description:"E521年に新世界で時間制御技術の研究に着手した特殊技術者。ティムール・シャーの10次元ホラズム理論の時間軸コンポーネントに着目し、局所的な時間操作の可能性を探求している。E525年に実施した「テンポラル実験」は、極小範囲での時間遅延を成功させ、理論の実証に一歩前進した。この技術が実用化されれば、通信の遅延問題の根本的解決や歴史の検証など、EDU社会に計り知れない影響を与える可能性がある。",descriptionEn:"A special technician who began research on time control technology in the New World in E521. Focusing on the temporal axis component of Timur Shah's 10-dimensional Horazm theory, they are exploring the possibilities of localized time manipulation. The 'Temporal Experiment' conducted in E525 successfully achieved time delay in a minimal range, taking a step forward in theoretical verification. If this technology is commercialized, it could potentially have immeasurable impacts on EDU society, including fundamental solutions to communication delay issues and historical verification.",era:"E521〜現在",affiliation:"新世界技術開発局 / 時間研究所",tier:"Tier 3"},{id:"テクニシャン・ディメンション",name:"テクニシャン・ディメンション",nameEn:"Technician Dimension",category:"キャラクター",subCategory:"新世界編",description:"E522年に新世界で次元安定化技術の実装を担当した技術者。次元極地平の不安定性による副次的影響（E340年のスライム・ウーマン顕現など）の再発防止に取り組んでいる。E524年に開発した「ディメンション・スタビライザー」は、次元境界の微小な揺らぎを検知して自動補正するシステムであり、新世界の安全性確保に不可欠な技術となった。ファールージャ社次元物理学者の理論的警告に基づき、技術の安全な利用を追求する慎重な研究者。",descriptionEn:"An engineer responsible for implementing dimensional stabilization technology in the New World in E522. They are working to prevent recurrence of secondary effects caused by the instability of the dimensional horizon, such as the manifestation of Slime Woman in E340. The 'Dimension Stabilizer' developed in E524 is a system that detects and automatically corrects minute fluctuations in dimensional boundaries, becoming an indispensable technology for ensuring New World security. A cautious researcher who pursues the safe use of technology based on theoretical warnings from Farooja Corporation's dimensional physicists.",era:"E522〜現在",affiliation:"新世界技術開発局 / 次元研究所",tier:"Tier 3"},{id:"アンバサダー・グランベル",name:"アンバサダー・グランベル",nameEn:"Ambassador Granbel",category:"キャラクター",subCategory:"新世界編",description:"E520年に新世界からオールドワールド（ギガポリス・Valoria連合圏）への初代大使として任命された外交官。ジェン主導のValoria連合圏との友好関係の構築に尽力し、E523年に「グランベル・ヴァレリア協定」を締結した。西大陸の長い歴史的背景を理解するベテラン外交官であり、新旧世界の架け橋として機能している。セリア・ドミニクスの外交遺産を継承し、新世界に西大陸の文化的影響を波及させる平和的使者。",descriptionEn:"A diplomat appointed as the first ambassador from the New World to the Old World (Gigapolis Valoria Federation Zone) in E520. They worked diligently to build friendly relations with the Valoria Federation Zone under Jen's leadership and concluded the 'Granbel Valeria Agreement' in E523. A veteran diplomat who understands the long historical background of the Western Continent, serving as a bridge between the old and new worlds. They inherit Celia Dominic's diplomatic legacy and function as a peaceful messenger spreading the cultural influence of the Western Continent to the New World.",era:"E520〜現在",affiliation:"新世界評議会 / 駐Valoria大使",tier:"Tier 3"},{id:"アンバサダー・ディオクレニス",name:"アンバサダー・ディオクレニス",nameEn:"Ambassador Dioclenis",category:"キャラクター",subCategory:"新世界編",description:"E521年に新世界からクレセント大地方への初代大使として任命された外交官。トリニティ・アライアンスとV7の二大陣営の間で微妙な外交バランスを維持しながら、新世界の中立性を確保している。アイリスやマリーナ・ボビンといったクレセントの強力な指導者たちとの交渉において、柔軟かつ堅実な対応で信頼を獲得した。E525年のV7・トリニティ対立の激化に際し、新世界の中立地帯としての地位を守るため精力的な外交活動を展開している。",descriptionEn:"A diplomat appointed as the first ambassador from the New World to the Crescent Region in E521. While maintaining a delicate diplomatic balance between the two major blocs of the Trinity Alliance and V7, they ensure the neutrality of the New World. Through negotiations with powerful Crescent leaders such as Iris and Marina Bobin, they have gained trust with flexible and steady responses. Amid the intensifying V7-Trinity confrontation in E525, they are actively engaged in diplomatic activities to protect the New World's status as a neutral zone.",era:"E521〜現在",affiliation:"新世界評議会 / 駐クレセント大使",tier:"Tier 3"},{id:"アンバサダー・エレシオン",name:"アンバサダー・エレシオン",nameEn:"Ambassador Erecion",category:"キャラクター",subCategory:"新世界編",description:"E522年に新世界からEros-7への初代大使として任命された外交官。Eros-7のパイオニアたちとの関係強化と資源供給協定の締結において中心的な役割を果たした。Eros-7から新世界への資源輸送と技術移転の円滑化を図り、両地域の相互依存関係を深めた。パイオニア・オーロラの開拓精神を受け継ぐ積極的な外交姿勢で知られ、Eros-7を新世界発展の重要なパートナーとして位置づけた。",descriptionEn:"A diplomat appointed as the first ambassador from the New World to Eros-7 in E522. They played a central role in strengthening relations with Eros-7's pioneers and concluding resource supply agreements. They facilitated the smooth transport of resources and technology transfer from Eros-7 to the New World, deepening the interdependence between the two regions. Known for their proactive diplomatic approach that inherits the pioneering spirit of Pioneer Aurora, they positioned Eros-7 as an important partner in the New World's development.",era:"E522〜現在",affiliation:"新世界評議会 / 駐Eros-7大使",tier:"Tier 3"},{id:"アンバサダー・ファルージャ",name:"アンバサダー・ファルージャ",nameEn:"Ambassador Faruja",category:"キャラクター",subCategory:"新世界編",description:"E523年に新世界からファールージャ社への初代大使として任命された外交官。企業外交という特殊な分野において、ミカエル・ガブリエリとの直接交渉を通じて次元技術の民間移転協定を結んだ。E524年の「ファルージャ・テクノロジー協定」により、新世界における次元極地平技術の民生利用が可能となった。企業の利益と新世界の公共的利益のバランスを取る高度な外交手腕を発揮し、新世界の技術的飛躍に貢献した。",descriptionEn:"A diplomat appointed as the first ambassador from the New World to Farooja Corporation in E523. In this specialized field of corporate diplomacy, they concluded a civil technology transfer agreement through direct negotiations with Michael Gabrieli. The 'Farooja Technology Agreement' of E524 enabled the civilian use of dimensional horizon technology in the New World. They demonstrated advanced diplomatic skills by balancing corporate interests with the public interests of the New World, contributing to its technological leap.",era:"E523〜現在",affiliation:"新世界評議会 / 駐ファールージャ社大使",tier:"Tier 3"},{id:"アンバサダー・ティレリア",name:"アンバサダー・ティレリア",nameEn:"Ambassador Tirelia",category:"キャラクター",subCategory:"新世界編",description:"E524年に新世界から先住知的生命体への初代大使として任命された特命全権大使。ソル・ハーモニーが構築した異種族間コミュニケーションの基盤の上に、より深い相互理解と協力関係の構築に取り組んでいる。E525年に先住民評議会との間で「ティレリア文化交流協定」を締結し、双方の文化・科学・芸術の交流を促進する枠組みを確立した。異種族間外交の先駆者として、EDU史上最もユニークな外交ポストを担う新世代の調停者。",descriptionEn:"A special ambassador plenipotentiary appointed as the first ambassador from the New World to the indigenous intelligent lifeforms in E524. Building on the foundation for interspecies communication established by Sol Harmony, they are working to build deeper mutual understanding and cooperative relationships. In E525, they concluded the 'Tireria Cultural Exchange Agreement' with the Indigenous Peoples Council, establishing a framework to promote cultural, scientific, and artistic exchange between both parties. As a pioneer in interspecies diplomacy, they hold the most unique diplomatic post in EDU history, serving as a mediator of the new generation.",era:"E524〜現在",affiliation:"新世界評議会 / 先住民外交特命大使",tier:"Tier 3"},{id:"AURALIS",name:"オーラリス・コレクティブ",nameEn:"AURALIS Collective",category:"組織",subCategory:"組織・制度",description:"「光と音を永遠にする」を理念とする音楽・文化集団で、E16文明圏の精神的支柱として機能してきた。第一世代はE290年頃に設立され、セリア黄金期（E335〜E370年）にその影響力の頂点に達した。初代ケイト・クラウディアや初代リリー・スタイナーら伝説的なメンバーの「名」は、クロニクル・ネームを通じて後世に受け継がれている。第一世代はZAMLTの台頭とスライム危機を経て活動を縮小したが、テクノ文化ルネサンス期に培われた文化的気運を受け、E522年に第二世代として復活を果たした。第二世代はフェルミ音楽の現代的展開だけでなく、次元極地平技術を活用した空間芸術やOffenbach種との共創活動など、従来の枠を超える表現活動を展開している。AURALISは単なる芸術団体ではなく、E16文明圏における文化的アイデンティティの維持と進化を担う最重要機関として位置づけられている。歴代指導者は初代ケイト・クラウディア（E270〜E400、創設者・「設計者」）と初代リリー・スタイナー（E270〜E400、共同創設者・「感情の炎」）に始まり、第二世代のケイト・パットン（E522〜、「名」を継承）とリリー・アーデント（E522〜、「名」を継承）へと受け継がれている。このクロニクル・ネームによりAURALISは精神的連続性を維持し、セリア黄金期の記憶と理念を現代に伝えている。\nこのAURALIS Collectiveの根底には、防衛的加速主義(L1)と第2のゲーム(L3)の思想的地層が横たわっている。芸術文化を「防衛的技術」として位置づけ、監視・支配技術ではなく創造的表現で文明を守るというL1の理念は、ZAMLTの軍事的覇権に対する根本的な対抗軸となった。テクノ文化ルネサンスにおける「共存フレームワーク」の構想は、覇権競争からオムニウィンへの転換を目標とするL3の思想の具現化である。",descriptionEn:"A music and cultural collective that operates under the philosophy of 'Eternizing Light and Sound,' serving as the spiritual pillar of the E16 civilization sphere. Founded around E290 by the First Generation, it reached the zenith of its influence during the Celia Golden Age (E335-E370). The 'Names' of legendary founding members such as First Generation Kate Claudia and First Generation Lily Steiner have been passed down to posterity through Chronicle Names. After the rise of ZAMLT and the Slime Crisis, the First Generation reduced its activities, but it was revived as the Second Generation in E522, building on the cultural momentum of the Techno-Cultural Renaissance. The Second Generation not only explores modern developments in Fermi music but also engages in expression that transcends conventional boundaries, including spatial art utilizing dimensional horizon technology and collaborative projects with the Offenbach species. AURALIS is positioned not merely as an artistic organization but as the most crucial institution responsible for maintaining and evolving the cultural identity of the E16 civilization sphere. Leadership has been passed down from First Generation Kate Claudia (E270-E400, founder and 'Architect') and First Generation Lily Steiner (E270-E400, co-founder and 'Flame of Emotion') to the Second Generation's Kate Patton (E522-, inheriting the 'Name') and Lily Ardente (E522-, inheriting the 'Name'). Through this Chronicle Name system, AURALIS maintains spiritual continuity, transmitting the memories and ideals of the Celia Golden Age to the present day.\n\nAt the foundation of the AURALIS Collective lie the ideological strata of Defensive Accelerationism (L1) and The Second Game (L3). The L1 philosophy, which positions art and culture as 'defensive technology' and protects civilization through creative expression rather than surveillance and control technologies, became a fundamental axis of resistance against ZAMLT's military hegemony. The 'Coexistence Framework' conceived during the Techno-Cultural Renaissance represents the materialization of L3 thought, aiming to transition from hegemonic competition to Omni-Win.",leaders:[{id:"Kate Claudia",name:"ケイト・クラウディア",nameEn:"Kate Claudia",role:"AURALIS Collective創設者「設計者」",era:"E270〜E400"},{id:"Lily Steiner",name:"リリー・スタイナー",nameEn:"Lily Steiner",role:"AURALIS Collective共同創設者「感情の炎」",era:"E270〜E400"},{id:"Kate Patton",name:"ケイト・パットン",nameEn:"Kate Patton",role:"AURALIS Collective第二世代",era:"E522〜"},{id:"Lillie Ardent",name:"リリー・アーデント",nameEn:"Lillie Ardent",role:"AURALIS Collective第二世代",era:"E522〜"}]},{id:"ZAMLT",name:"ザムルト",nameEn:"ZAMLT",category:"組織",subCategory:"組織・制度",description:"E301年からE318年まで活動した5超巨大企業の統合体で、E16連星系の経済を事実上支配したメタ企業体である。ZAMLTは構成する5大企業の英語名の頭文字をとった名称である――Z（ゼブラ・コーポレーション）、A（アロエオイル・コーポレーション）、M（マモン・コーポレーション）、L（ルレンツ・コーポレーション）、T（トロン・コーポレーション）。創設者エリオット・シュトラスがGigapolisにおける20万以上のコーポラトクラシーの覇権争いに勝利し、5社に経済権を集約して設立した。各企業のオムニバス・エンジンを接続することで、E16連星系全域の金融取引をリアルタイムで制御する画期的な経済システムを構築した。しかし経済効率の極端な追求は社会の二極化を招き、A-Registryの階級格差を固定化する結果となった。ZAMLTはそれまでのコーポラトクラシー体制（コーポラタムパブリカ）が構築してきた自由経済の秩序を、極めて少数の巨大企業による中央集権的支配に置き換えた。この転換はエル・フォルハウスのマーストリヒト革命（E150年）からアルファ・ケインのギガポリス解放戦（E318年）に至る長い抵抗運動の直接の標的となった。ZAMLT支配下の低階層市民は深刻な貧困と権利制限に苦しみ、シャドウ・リベリオンなどの反乱組織が地下で形成される原因となった。E318年のトロン社壊滅後は4社体制へ移行し、最終的にアルファ・ケインによるギガポリス解放戦で完全崩壊した。ZAMLTの経済的遺産はその後もnトークンシステムやUECOの経済框架に長く影響を残した。崩壊後、その組織の残党の一部はシルバー・ヴェノムの母体となったという説があり、地下組織の歴史的経緯を研究する上で重要な鍵となっている。歴代指導者は初代エリオット・シュトラス（E301〜E318、創設者・最高指導者）。5大企業の各CEO（ラファエル・ドレイク/トロン、カルロス・ヴァンダム/マモン、アーサー・グリム/ゼブラ、エリザベス・リンドバーグ/ルレンツ、アイリス・ノヴァ/アロエオイル）が幹部を構成した。\nこのZAMLTの根底には、超未来第一主義(D1)と安全の監視者パラドックス(D2)の思想的地層が横たわっている。「文明の永続」という超長期的視点から現在の犠牲を合理化するD1の論理と、「安全と秩序」を掲げながら最大の抑圧装置となるD2の逆説が、ZAMLTの覇権構造を思想的に支えていた。Shadow Rebellionの抵抗は、この二重の思想的抑圧に対する根源的なアンチテーゼとして歴史的意義を持つ。",descriptionEn:"A meta-corporate entity that was a unified body of five hyper-giant corporations operating from E301 to E318, effectively dominating the economy of the E16 star system. ZAMLT is an acronym derived from the English names of its five constituent corporations: Z (Zebra Corporation), A (Aloe Oil Corporation), M (Mamon Corporation), L (Lorentz Corporation), and T (Thoron Corporation). Founder Elliot Strass won the hegemony struggle among over 200,000 corpopracy classes in Gigapolis, consolidating economic power among these five companies to establish ZAMLT. By connecting the Omibus Engines of each corporation, it constructed an innovative economic system that controlled financial transactions across the entire E16 star system in real-time. However, the extreme pursuit of economic efficiency led to social polarization, resulting in the固化 of class inequality in the A-Registry. ZAMLT replaced the free economic order established by the previous corpopracy system (Corporatum Publica) with centralized rule by a tiny handful of giant corporations. This transformation became the direct target of the long resistance movement stretching from El Forhaus's Maastricht Revolution (E150) to Alpha Cain's Gigapolis Liberation War (E318). Citizens in lower classes under ZAMLT suffered from severe poverty and rights restrictions, leading to the formation of underground rebel organizations like the Shadow Rebellion. After the destruction of Thoron Corporation in E318, it transitioned to a four-company structure before ultimately collapsing completely during Alpha Cain's Gigapolis Liberation War. ZAMLT's economic legacy continued to influence systems like the n-token economy and UECO's economic framework for a long time afterward. A theory suggests that some remnants of its organization later became the nucleus of Silver Venom, making it an important key in studying the historical background of underground organizations. Leaders included First Generation Elliot Strass (E301-E318, founder and Supreme Leader), with the CEOs of the five major corporations (Rafael Drake/Thoron, Carlos Vandom/Mamon, Arthur Grimm/Zebra, Elizabeth Lindbergh/Lorentz, and Iris Nova/Aloe Oil) forming the executive cadre.\n\nAt the foundation of ZAMLT lie the ideological strata of Hyper-Future First-Principalism (D1) and the Safety Watcher Paradox (D2). The D1 logic, which justifies present sacrifices from an ultra-long-term perspective of 'civilizational permanence,' and the D2 paradox, which while advocating 'safety and order' becomes the ultimate oppression apparatus, ideologically supported ZAMLT's hegemonic structure. The resistance of the Shadow Rebellion holds historical significance as a fundamental antithesis against this dual ideological oppression.",leaders:[{id:"エリオット・シュトラス",name:"エリオット・シュトラス",nameEn:"Elliot Strauss",role:"ZAMLT創設者・最高指導者",era:"E301〜E318"},{id:"ラファエル・ドレイク",name:"ラファエル・ドレイク",nameEn:"Rafael Drake",role:"トロン・コーポレーションCEO",era:"E301〜E318"},{id:"カルロス・ヴァンダム",name:"カルロス・ヴァンダム",nameEn:"Carlos Vandam",role:"マモン・コーポレーションリーダー",era:"E301〜E318"},{id:"アーサー・グリム",name:"アーサー・グリム",nameEn:"Arthur Grim",role:"ゼブラ・コーポレーションリーダー",era:"E301〜E318"},{id:"エリザベス・リンドバーグ",name:"エリザベス・リンドバーグ",nameEn:"Elizabeth Lindberg",role:"ルレンツ・コーポレーションリーダー",era:"E301〜E318"},{id:"アイリス・ノヴァ",name:"アイリス・ノヴァ",nameEn:"Iris Nova",role:"アロエオイル・コーポレーションリーダー",era:"E301〜E318"}]},{id:"ネオクラン同盟",name:"ネオクラン同盟",nameEn:"Neoclan Alliance",category:"組織",subCategory:"組織・制度",description:"分散統治モデルを推進する国家同盟で、各構成国が主権を維持しつつ共通の外交・防衛・通商政策を協調する連合体制を採っている。ネオクラン同盟はZAMLTの中央集権的支配への反動として生まれ、地方自治権の強化と市民参加型政治の復興を掲げた。UECO統合後は銀河系コンソーシアムの中核構成体として機能し、分散統治の実践モデルとして他の星系にも影響を与えている。同盟の主要政策には次元極地平技術の平等な配分、nトークン経済の透明性向上、A-Registryの階級制度の段階的緩和などが含まれる。ネオクラン同盟の理念はテクノ文化ルネサンス期の「技術の民主化」という精神を政治制度に具体化したものであり、E16文明圏における最も持続可能な統治モデルの一つと評価されている。同盟の初代代表にはZAMLT崩壊後の民主化運動の指導者複数名が共同で就任し、分散統治モデルの基盤を築いた。",descriptionEn:"A national alliance that promotes a decentralized governance model, adopting a federated system where constituent nations maintain sovereignty while coordinating common foreign, defense, and trade policies. The Neo-Clan Alliance emerged as a reaction against ZAMLT's centralized rule, advocating for strengthened local autonomy and the revival of citizen-participatory politics. After UECO integration, it functions as a core component of the Galactic Consortium, influencing other star systems as a practical model of decentralized governance. The Alliance's major policies include the equitable distribution of dimensional horizon technology, increased transparency in the n-token economy, and the gradual relaxation of the A-Registry's class hierarchy. The Neo-Clan Alliance's philosophy materializes the 'democratization of technology' spirit of the Techno-Cultural Renaissance into political institutions, and is evaluated as one of the most sustainable governance models in the E16 civilization sphere. Multiple leaders of the democratization movement following ZAMLT's collapse jointly served as the first representatives of the Alliance, establishing the foundation for the decentralized governance model.",leaders:[{id:"ルシア・ネオ",name:"ルシア・ネオ",nameEn:"Lucia Neo",role:"ネオクラン同盟初代代表",era:"E330〜"}]},{id:"UECO",name:"ユーエコー",nameEn:"UECO",category:"組織",subCategory:"組織・制度",description:"星間経済協同組合（United Economic Cooperative）で、E16連星系および周辺星系の経済活動を調整する超国家的機関である。UECOはZAMLT崩壊後の経済的混乱を収束させるために設立され、nトークン経済システムの再構築と公正な資源配分を実現した。最大の特徴はヒーローエージェンシーとの統合であり、経済協同組合という枠組みの中に防衛・救助・治安維持の機能を組み込んだ独自の組織体制を持つ。これにより経済活動と安全保障を有機的に連携させ、純粋な軍事同盟ではない新しい形態の星系ガバナンスを実現している。UECOはパクス・ロンバルディカの企業統治とZAMLTの経済覇権の両方の教訓を踏まえ、経済効率と社会的公正のバランスを追求する第三の道として設計された。ネオクラン同盟の理念もUECOの框架の中で実現されている。UECOの初代議長にはテクノ文化ルネサンス期の指導者の一人が就任したとされ、E495〜E500年の銀河系コンソーシアム設立への移行期を主導した。歴代指導者の詳細な記録は惑星ビブリオに保管されている。\nこのUECOの根底には、多元性民主主義(L2)の思想的地層が横たわっている。多文明間の合意形成を民主的に実現するというL2の理念は、ZAMLTの単一覇権体制に対する構造的代替案として機能した。テクノロジーを活用して民主主義をアップデートするというL2の構想は、銀河系コンソーシアムの集合知プラットフォームへと結実している。",descriptionEn:"An interstellar economic cooperative (United Economic Cooperative) and a supranational agency that coordinates economic activities across the E16 star system and surrounding star systems. UECO was established to resolve the economic chaos following ZAMLT's collapse, reconstructing the n-token economic system and achieving fair resource distribution. Its most distinctive feature is integration with Hero Agencies, incorporating defense, rescue, and public security functions within its organizational framework as an economic cooperative. This organically links economic activities with security, realizing a new form of stellar system governance that is not purely a military alliance. Drawing lessons from both the corporate governance of Pax Lombardica and ZAMLT's economic hegemony, UECO was designed as a third path pursuing balance between economic efficiency and social justice. The ideals of the Neo-Clan Alliance are also realized within UECO's framework. It is said that one leader from the Techno-Cultural Renaissance period served as UECO's first chairman, guiding the transition period leading to the establishment of the Galactic Consortium from E495 to E500. Detailed records of its leaders are preserved on the planet Biblio.\n\nAt the foundation of UECO lies the ideological stratum of Pluralistic Democracy (L2). The L2 principle of achieving consensus among multiple civilizations democratically functioned as a structural alternative to ZAMLT's single-hegemony system. The L2 concept of updating democracy through technology has materialized in the collective intelligence platform of the Galactic Consortium.",leaders:[{id:"ヘクトル・ヴァン",name:"ヘクトル・ヴァン",nameEn:"Hector Van",role:"UECO初代議長",era:"E400後半〜E500"}]},{id:"シャドウ・リベリオン",name:"シャドウ・リベリオン",nameEn:"Shadow Rebellion",category:"組織",subCategory:"組織・制度",description:"ZAMLT支配期（E301〜E318年）に結成された低階層市民の反乱組織で、A-Registryの下層階級（Z40以下）を中心とした地下抵抗運動である。ZAMLTのオムニバス・エンジンによる経済支配に対抗するため、独自の代替通貨システムと暗号通信網を構築した。シャドウ・リベリオンの活動は主にサボタージュと情報戦に限定され、大規模な武力闘争は回避した。この戦略はZAMLTの崩壊後、ネオクラン同盟設立の思想的基盤として評価されている。シャドウ・リベリオンの残党の一部は後にシルバー・ヴェノムの母体となったという説もあり、抵抗運動の過激派と穏健派の分岐がE16文明圏のその後の対立構造に影響を与えたと指摘されている。\nこのシャドウ・リベリオンの根底には、安全の監視者パラドックス(D2)と脱人間化(D5)の思想的地層が横たわっている。「銀河の統一と安全」を掲げるZAMLTこそが最大の脅威であるというD2の認識は、統一秩序への抵抗を倫理的必然とした。同時に、A-Registryによる意識データ化への反発は、人間の定義をシステムに支配されないというD5の根本命题と共鳴している。",descriptionEn:"An underground resistance organization formed during ZAMLT's rule (E301-E318), composed of lower-class citizens in the A-Registry's lower strata (Z40 and below). To counter ZAMLT's economic domination through its Omibus Engine, the Shadow Rebellion constructed its own alternative currency system and encrypted communication network. The activities of the Shadow Rebellion were primarily limited to sabotage and information warfare, avoiding large-scale armed conflict. This strategy has been evaluated as the ideological foundation for the establishment of the Neo-Clan Alliance after ZAMLT's collapse. A theory suggests that some remnants of the Shadow Rebellion later became the nucleus of Silver Venom, and it has been pointed out that the divergence between radical and moderate factions of the resistance movement influenced the subsequent conflict structures of the E16 civilization sphere.\n\nAt the foundation of the Shadow Rebellion lie the ideological strata of the Safety Watcher Paradox (D2) and Dehumanization (D5). The D2 recognition that ZAMLT, which advocates for 'galactic unity and safety,' is itself the greatest threat made resistance against the unified order ethically necessary. At the same time, the rejection of consciousness datafication by the A-Registry resonates with the fundamental proposition of D5—that human definition must not be dominated by systems.",leaders:[{id:"アルファ・ケイン",name:"アルファ・ケイン",nameEn:"Alpha Kane",role:"シャドウ・リベリオンリーダー",era:"E318〜"}]},{id:"A-Registry",name:"A-Registry（A籍）",nameEn:"A-Registry",category:"組織",subCategory:"組織・制度",description:"E16連星系の市民身分証明・階級制度で、旅券機能と社会的地位の指標を兼ね備えた包括的な管理システムである。Z1（最高位）からZ50（最低位）までの階級があり、各階級は居住区域のアクセス権、nトークンの取引限度額、公的サービスの利用範囲などを規定する。A-Registryはバーズ帝国期にその原型が構想され、パクス・ロンバルディカ期に企業の従業員管理システムとして整備された後、ZAMLT期に社会階級の固定化装置として悪用された。ZAMLT崩壊後、ネオクラン同盟とUECOの下で階級制度の緩和が進められ、Z50に近い低階層市民の権利向上が図られている。しかし階級間の格差は完全には解消されておらず、A-Registryの改革はE16文明圏の最重要の政治課題の一つとして議論が続いている。惑星ビブリオには全市民データのバックアップが保管されている。\nこのアルファ・ケインの根底には、安全の監視者パラドックス(D2)と倫理の解除(D3)の思想的地層が横たわっている。コーポラトクラシー体制がもたらす「安全という名の抑圧」に対するD2の根源的な反逆精神と、既存の倫理規範を打ち破って新たな自由を切り拓くというD3の実践的姿勢が、彼の行動原理を支えている。",descriptionEn:"The citizen identification and class system of the E16 star system, serving as both a passport and an indicator of social status. It includes classes from Z1 (highest) to Z50 (lowest), with each class dictating access to residential areas, transaction limits for n-tokens, and the scope of public services available. The prototype of the A-Registry was conceived during the Bird Empire period, refined as an employee management system for corporations during the Pax Lombardica era, and then perverted as a device for fixing social classes during the ZAMLT period. After ZAMLT's collapse, the Neo-Clan Alliance and UECO have pursued the relaxation of the class hierarchy, seeking to improve the rights of citizens in lower classes close to Z50. However, class inequality has not been completely eliminated, and the reform of the A-Registry continues to be debated as one of the most important political issues in the E16 civilization sphere. A backup of all citizen data is stored on the planet Biblio.\n\nAt the foundation of Alpha Cain lie the ideological strata of the Safety Watcher Paradox (D2) and the Abolition of Ethics (D3). The D2 fundamental rebellious spirit against 'oppression in the name of safety' brought by the corpopracy system and the D3 practical attitude of breaking existing ethical norms to carve out new freedoms support his principles of action."},{id:"nトークン",name:"nトークン",nameEn:"n-Token",category:"組織",subCategory:"組織・制度",description:"E16連星系の基軸通貨で、セリア黄金期に確立され、現在もUECOの管轄下で運用されている。nトークンの最大の特徴は、物質的資産だけでなく文化的貢献、知識の共有、芸術的創造活動なども経済的価値として評価・換金できる点にある。この仕組みはセリア黄金期のAURALISの理念と深く結びついており、フェルミ音楽の演奏や次元極地平技術の研究などもnトークンで報酬を受け取ることができる。ZAMLT期にはnトークンの集中化が進み経済的不平等を拡大したが、UECO統合後は分散型台帳技術の導入により透明性と公平性が向上した。nトークンの交換レートは惑星ビブリオのロレンツィオ国際大学が算出する「文化・知識指数」を基準に定期調整されており、E16文明圏独自の価値観を反映した経済システムとして他星系からも注目されている。\nこのnトークン経済の根底には、多元性民主主義(L2)の思想的地層が横たわっている。熱量を反映した価値メカニズムは、単なる通貨システムではなく「クアドラティック・ボーティング」的な参加型ガバナンスの経済的実装として機能している。テクノロジーを通じて民主主義をアップデートするというL2の構想は、nトークン経済の設計思想の核心にある。",descriptionEn:"The base currency of the E16 star system, established during the Celia Golden Age and still operated under UECO's jurisdiction. The most distinctive feature of n-tokens is that they can evaluate and monetize not only material assets but also cultural contributions, knowledge sharing, and artistic creative activities as economic value. This mechanism is deeply connected to the philosophy of AURALIS during the Celia Golden Age, allowing performers of Fermi music and researchers of dimensional horizon technology to receive compensation in n-tokens. During the ZAMLT era, the centralization of n-tokens progressed, exacerbating economic inequality, but after UECO integration, the introduction of distributed ledger technology has improved transparency and fairness. The exchange rate of n-tokens is periodically adjusted based on the 'Culture-Knowledge Index' calculated by the Lorenzo International University on the planet Biblio, and as an economic system reflecting the unique values of the E16 civilization sphere, it attracts attention from other star systems.\n\nAt the foundation of the n-token economy lies the ideological stratum of Pluralistic Democracy (L2). The value mechanism reflecting 'heat' functions not merely as a currency system but as an economic implementation of 'quadratic voting' style participatory governance. The L2 concept of updating democracy through technology lies at the core of the n-token economy's design philosophy."},{id:"シルバー・ヴェノム",name:"シルバー・ヴェノム",nameEn:"Silver Venom",category:"組織",subCategory:"軍事・対立組織",description:"E475年、エヴァトロンのΣ-Unit残党から独立して結成された暗黒組織で、E16文明圏における最大の脅威勢力の一つである。エヴァトロン崩壊後に解体されたはずのΣ-Unitの極秘技術と人材を継承し、テクノ文化ルネサンス期の技術開放に乗じて急速に戦力を拡大した。シルバー・ヴェノムは従来の軍事組織とは異なり、次元極地平技術を武器化した「空間干渉攻撃」を得意とし、ホライゾン・ゲートを通じた奇襲戦術でE16連星系の各地を混乱に陥れた。組織名の「ヴェノム（毒）」は、社会の構造的矛盾を暴露し、文明を内側から腐食させるという彼らの思想に由来する。シャドウ・リベリオンの過激派が母体との説が有力で、ZAMLT期に培われた地下活動のノウハウが組織の強靭さに貢献している。後にアルファ・ヴェノムとゴールデン・ヴェノムに分裂したが、その思想的影響はE16文明圏全体に長く残ることになる。歴代指導者は初代マスター・ヴェノム（E475〜E500頃、創設者・「影の支配者」）に始まり、レオンが幹部として実行部隊の指揮を執った。マスター・ヴェノムの失脚後、残党はイズミによるアルファ・ヴェノムへの吸収を拒否し、ラストマン等が独自活動を続けている。",descriptionEn:"A dark organization formed independently from the Σ-Unit remnants of Evatron in E475, and one of the greatest threat forces in the E16 civilization sphere. It inherited the secret technology and personnel of the Σ-Unit, which should have been disbanded after Evatron's collapse, and rapidly expanded its military power by taking advantage of the technology opening of the Techno-Cultural Renaissance period. Unlike conventional military organizations, Silver Venom specializes in 'spatial interference attacks' that weaponize dimensional horizon technology, plunging various parts of the E16 star system into chaos through surprise tactics using Horizon Gates. The organization's name 'Venom' derives from their ideology of exposing society's structural contradictions and corroding civilization from within. The theory that the Shadow Rebellion's radical faction was its nucleus is widely accepted, and the know-how of underground activities cultivated during the ZAMLT era contributed to the organization's resilience. Later, it split into Alpha Venom and Golden Venom, but its ideological influence would long remain throughout the E16 civilization sphere. Leaders began with First Generation Master Venom (E475-E500 approx., founder and 'Shadow Ruler'), with Leon commanding the operational forces as a cadre. After Master Venom's downfall, the remnants refused absorption into Alpha Venom by Izumi, with figures like Lastman continuing independent activities.",leaders:[{id:"マスター・ヴェノム",name:"マスター・ヴェノム",nameEn:"Master Venom",role:"シルバー・ヴェノム創設者",era:"E475〜E500頃"},{id:"レオン",name:"レオン",nameEn:"Leon",role:"シルバー・ヴェノム幹部",era:"E485〜"}]},{id:"アルファ・ヴェノム",name:"アルファ・ヴェノム",nameEn:"Alpha Venom",category:"組織",subCategory:"軍事・対立組織",description:"シルバー・ヴェノムの後継組織で、イズミがリーダーを務めるE16文明圏最大の対立勢力である。シルバー・ヴェノムの内部抗争と路線対立を経て誕生し、より攻撃的で急進的な行動方針を採用している。アルファ・ヴェノムの最大の特徴は、次元極地平技術を用いた大規模な空間攻撃と、洗脳・精神操作を組み合わせた心理戦の二面作戦である。E509年にはノスタルジア・コロニーへの壊滅的な攻撃を実行し、ミナ・エウレカの人生を根本から変える出来事となった。イズミのカリスマ的指導の下、アルファ・ヴェノムはV7とトリニティ・アライアンスの両方と敵対し、クレセント大地方全体を巻き込む大規模な軍事衝突を引き起こしている。組織の最終的な目的はE16連星系の既存秩序の完全な破壊と再構築であるとされ、その思想はシャドウ・リベリオン以来の反体制運動の系譜を最も極端な形で体現している。",descriptionEn:"The successor organization to Silver Venom, led by Izumi and the largest opposing force in the E16 civilization sphere. Born from internal conflicts and ideological struggles within Silver Venom, it adopts a more aggressive and radical action policy. The most distinctive feature of Alpha Venom is its two-pronged strategy combining large-scale spatial attacks using dimensional horizon technology with psychological warfare incorporating brainwashing and mental manipulation. In E509, it executed a devastating attack on the Nostalgia Colony, an event that fundamentally changed Mina Eureka's life. Under Izumi's charismatic leadership, Alpha Venom has opposed both V7 and the Trinity Alliance, triggering large-scale military conflicts involving the entire Crescent region. The organization's ultimate goal is said to be the complete destruction and reconstruction of the existing order in the E16 star system, and its ideology most extremely embodies the lineage of anti-establishment movements since the Shadow Rebellion.",leaders:[{id:"イズミ",name:"イズミ",nameEn:"Izumi",role:"アルファ・ヴェノムリーダー",era:"E518〜"}]},{id:"ゴールデン・ヴェノム",name:"ゴールデン・ヴェノム",nameEn:"Golden Venom",category:"組織",subCategory:"軍事・対立組織",description:"シルバー・ヴェノムの分派組織で、本流との路線対立から独立した勢力である。ゴールデン・ヴェノムはアルファ・ヴェノムの急進的な武力路線に反対し、代わりにnトークン経済システムへの浸透と金融操作による支配を志向した。この手法は皮肉にもZAMLTの戦略を模倣するものであり、経済的支配を通じて社会を変革しようとするアプローチを採っている。ゴールデン・ヴェノムの名称は、nトークン（金色的な輝きを持つ暗号資産）への執着に由来する。組織は表向きは合法的な企業活動を通じて資金を蓄積し、A-Registryのシステムに潜入して市民データの改ざんや監視を行っていると疑われている。アルファ・ヴェノムとは敵対関係にあるが、時折両者は共通の敵に対して一時的な協力関係を結ぶこともあり、E16文明圏の安全保障を複雑化させる要因となっている。",descriptionEn:"A faction organization of Silver Venom that broke away from the mainstream due to ideological differences. Golden Venom opposed Alpha Venom's radical military approach, instead aiming to infiltrate the n-token economic system and achieve control through financial manipulation. This approach ironically mimics ZAMLT's strategy, seeking to transform society through economic domination. The name Golden Venom derives from its obsession with n-tokens (cryptographic assets with a golden sheen). The organization accumulates funds through ostensibly legitimate corporate activities and is suspected of infiltrating the A-Registry system to tamper with and monitor citizen data. While antagonistic toward Alpha Venom, the two occasionally form temporary alliances against common enemies, complicating the security landscape of the E16 civilization sphere.",leaders:[{id:"オーギュスト・ゴールド",name:"オーギュスト・ゴールド",nameEn:"August Gold",role:"ゴールデン・ヴェノム創設者",era:"E500〜"}]},{id:"ボグダス・ジャベリン",name:"ボグダス・ジャベリン",nameEn:"Bogdas Javelin",category:"組織",subCategory:"軍事・対立組織",description:"セバスチャン・ヴァレリウス率いる軍事組織で、テクロサス系譜に属する古参の戦闘集団である。テクロサスはE16文明圏の初期入植時代から続く武術・戦闘技術の流派であり、ボグダス・ジャベリンはその系譜を受け継ぐ最も強力な軍事組織として知られる。セバスチャン・ヴァレリウスは卓越した戦術家であり、次元極地平技術を戦闘に応用した独自の戦闘体系を開発した。ボグダス・ジャベリン（槍）の名称は、組織が重装甲の精密打撃部隊として機能することに由来し、特定目標に対する迅速かつ壊滅的な攻撃を得意とする。トリニティ・アライアンスの結成メンバーとしてヴァーミリオンとミエルテンガと軍事同盟を結んでおり、V7との対抗軸の主力戦力として機能している。テクロサス系譜の戦士たちはA-Registryの階級制度に縛られない独自の階位を持つ。",descriptionEn:"A military organization led by Sebastian Valerius, belonging to the ancient Teclosas lineage. Teclosas is a school of martial and combat arts dating back to the early settlement era of the E16 civilization sphere, and Bogdas Javelin is known as the most powerful military organization carrying on this lineage. Sebastian Valerius is an exceptional tactician who developed a unique combat system applying dimensional horizon technology to warfare. The name Bogdas Javelin (spear) derives from the organization's function as a heavily armored precision strike unit, specializing in rapid and devastating attacks against specific targets. As a founding member of the Trinity Alliance, it has formed a military alliance with Vermilion and Mieltenga, serving as the main force in the opposing axis against V7. Warriors of the Teclosas lineage hold their own ranks, unfettered by the A-Registry's class system.",leaders:[{id:"セバスチャン・ヴァレリウス",name:"セバスチャン・ヴァレリウス",nameEn:"Sebastian Valerius",role:"ボグダス・ジャベリンリーダー",era:"E490〜"}]},{id:"V7",name:"V7（Vital Seven）",nameEn:"V7 (Vital Seven)",category:"組織",subCategory:"軍事・対立組織",description:"クレセント地方の7カ国連合で、E515年にフィオナの主導で設立された軍事・経済同盟である。正式名称はVital Seven（命の七）であり、クレセント大地方の平和と安定を維持することを目的としている。加盟国はブルーローズ（中心国）、ヴァーミリオンを除く主要国から構成され、集団安全保障体制を通じてアルファ・ヴェノムやシルバー・ヴェノムの脅威に対処している。V7の最大の特徴は、単なる軍事同盟ではなく、加盟国間の技術共有、nトークンの相互補助、ホライゾン・ゲートの共同管理など、包括的な協力框架を持つ点である。テクノ文化ルネサンスの理念を共用財産として守るという思想的基盤があり、AURALIS第二世代とも密接な連携を維持している。トリニティ・アライアンスとの対立はクレセント地方を二分する最大の地政学的緊張の源泉となっている。",descriptionEn:"A seven-nation alliance in the Crescent region, established in E515 under Fiona's leadership as a military and economic coalition. Its formal name is Vital Seven, with the aim of maintaining peace and stability in the Crescent region. It consists of Blue Rose (the central nation) and other major nations except Vermilion, addressing threats from Alpha Venom and Silver Venom through a collective security framework. The most distinctive feature of V7 is that it is not merely a military alliance but possesses a comprehensive cooperation framework including technology sharing among member nations, mutual assistance through n-tokens, and joint management of Horizon Gates. It has an ideological foundation of preserving the Techno-Cultural Renaissance's ideals as common heritage and maintains close cooperation with the Second Generation of AURALIS. The confrontation with the Trinity Alliance has become the primary source of geopolitical tension dividing the Crescent region.",leaders:[{id:"フィオナ",name:"フィオナ",nameEn:"Klaus Fiona",role:"ブルーローズ統率者・V7設立主導者",era:"E515〜"},{id:"カスチーナ・テンペスト",name:"カスチーナ・テンペスト",nameEn:"Castina Tempest",role:"クロセヴィア首脳",era:"E515〜"},{id:"アイク・ロペス",name:"アイク・ロペス",nameEn:"Ike Lopez",role:"SSレンジ首脳",era:"E515〜"},{id:"レイド・カキザキ",name:"レイド・カキザキ",nameEn:"Raid Kakizaki",role:"アイアン・シンジケート首脳",era:"E515〜"},{id:"ヨニック",name:"ヨニック",nameEn:"Yonick",role:"ブルーローズ最高司令官",era:"E515〜"}]},{id:"トリニティ・アライアンス",name:"トリニティ・アライアンス",nameEn:"Trinity Alliance",category:"組織",subCategory:"軍事・対立組織",description:"ヴァーミリオン・ミエルテンガ・ボグダス・ジャベリンの3勢力による軍事同盟で、E520年に結成された。トリニティ（三位一体）の名称は、三勢力が等しい立場で連合を構成していることに由来する。トリニティ・アライアンスはV7に対抗する目的で設立され、クレセント地方における二極対立の構造を決定づけた。ヴァーミリオンが文化的・歴史的正当性を、ミエルテンガが軍事力と産業基盤を、ボグダス・ジャベリンがテクロサス系譜の戦闘技術をそれぞれ提供し、三勢力の相互補完関係で同盟の戦力は極めて強力である。V7がテクノ文化ルネサンスの理念を重視するのに対し、トリニティ・アライアンスはセリア黄金期の伝統的価値観と実力主義を重んじる傾向がある。両陣営の対立は時折武力衝突に発展するが、UECOの仲介によって全面戦争は回避されてきた。アルファ・ヴェノムの脅威に対してはV7とトリニティ・アライアンスが一時的に協力することもある。",descriptionEn:"A military alliance formed by three powers—Vermilion, Mieltenga, and Bogdas Javelin—in E520. The name 'Trinity' originates from the equal standing of the three powers in the alliance. Established to counter V7, the Trinity Alliance solidified the bipolar structure of the Crescent region. Vermilion provides cultural and historical legitimacy, Mieltenga offers military power and industrial infrastructure, and Bogdas Javelin contributes combat techniques from the Techlosus lineage. This complementary relationship makes the alliance's forces exceptionally powerful. While V7 emphasizes the philosophy of the Techno-Cultural Renaissance, the Trinity Alliance tends to value traditional principles and pragmatism from the Serian Golden Age. Although conflicts between the two factions occasionally escalate into military confrontations, full-scale war has been avoided through UECO mediation. In response to the threat of Alpha Venom, V7 and the Trinity Alliance have occasionally cooperated.",leaders:[{id:"アイリス",name:"アイリス",nameEn:"Iris",role:"トリニティ・アライアンス指導者",era:"E519〜"}]},{id:"ファールージャ社",name:"ファールージャ社",nameEn:"Faruja Corporation",category:"組織",subCategory:"その他",description:"シンフォニー・オブ・スターズ西大陸を代表する総合企業体。CEOであるミカエル・ガブリエリの卓越した経営手腕のもと、次元エネルギー採掘から軍事技術開発まで幅広い分野で事業を展開。特にZAMLT崩壊後の混乱期には安定した供給網を維持し、西大陸経済の屋台骨を支えた。エヴァトロン時代にも巧みに身を保ち、その後のテクノ文化ルネサンスでは新技術の商業化を主導した。社名の由来は創業地であるファールージャ渓谷に由来する。",descriptionEn:"A comprehensive corporation representing the Western Continent of the Symphony of Stars. Under the exceptional leadership of CEO Michael Gabrieli, it operates across a wide range of fields, from dimensional energy extraction to military technology development. Particularly during the chaotic period following the collapse of ZAMLT, it maintained a stable supply network, supporting the backbone of the Western Continent's economy. It skillfully navigated the Evatron era and later led the commercialization of new technologies during the Techno-Cultural Renaissance. The company's name derives from its founding location, the Faroojah Valley.",leaders:[{id:"ミカエル・ガブリエリ",name:"ミカエル・ガブリエリ",nameEn:"Mikael Gabrieli",role:"ファールージャ社CEO",era:"E515〜"}]},{id:"エヴァトロン",name:"エヴァトロン",nameEn:"Evatron",category:"組織",subCategory:"その他",description:"E400年にGigapolisを武力制圧し、西大陸に恐怖政治を敷いた独裁的軍事・企業複合体。AURALISを弾圧し、芸術・文化活動を厳しく制限して市民の自由を奪った。支配下でGigapolisは一時「エヴァポリス」と改名され、極秘部隊Σ-Unitを設立して精神操作技術の研究を推進。しかしE400〜E470年続いたテリアン反乱による内政の疲弊と、指導層内部の腐敗が進行し、E475年にテリアン反乱軍と市民の連合攻勢を受けてついに崩壊。その残党は散り散りとなり、一部は新ZAMLT期の影の勢力として活動を続けた。歴代指導者は初代グリム・ダルゴス（創設者、男尊女卑の銀河系統治）に始まり、ヴァイロン・デアクス（Dominion統治者、エヴァトロン文化の浸透を試みるが市民の激しい反発を招く）が続いた。E400年のGigapolis武力制圧からE475年の崩壊まで、エヴァトロンΣ-Unitが暗部を担い、支配体制の維持に深く関与した。",descriptionEn:"A dictatorial military-corporate complex that imposed a reign of terror on the Western Continent by forcibly seizing Gigapolis in E400. It suppressed AURALIS, severely restricted artistic and cultural activities, and stripped citizens of their freedoms. Under its rule, Gigapolis was temporarily renamed 'Evapolis,' and it established the secret Σ-Unit to advance research into mind-control technologies. However, after 75 years of rule from E400 to E475, internal exhaustion from the Terrian Rebellion and advancing corruption within its leadership led to its collapse under a combined offensive from Terrian rebel forces and citizens. Its remnants scattered, with some continuing activities as shadowy forces during the New ZAMLT era. Its leaders began with Grim Dargos (founder, patriarchal galactic governance) and were followed by Vylon Deax (Dominion ruler, who attempted to infiltrate Evatron culture but faced fierce citizen resistance). From the E400 seizure of Gigapolis to its collapse in E475, the Evatron Σ-Unit operated in the shadows and played a deep role in maintaining the ruling regime.",leaders:[{id:"グリム・ダルゴス",name:"グリム・ダルゴス",nameEn:"Grim Dargos",role:"エヴァトロン初代リーダー",era:"歴史上"},{id:"ヴァイロン・デアクス",name:"ヴァイロン・デアクス",nameEn:"Vylon Deax",role:"エヴァトロン幹部（Dominion総治者）",era:"歴史上"}]},{id:"テクロサス",name:"テクロサス",nameEn:"Tekrosas",category:"組織",subCategory:"その他",description:"E15〜E61年のバーズ帝国を樹立した軍閥ファランクスから派生した軍事系譜の総称。ファランクス崩壊後、その将兵と戦術思想を受け継ぐ者たちが西大陸各地で軍事組織を形成した。特にE88〜E98年のロンバルディア戦争ではテクロサス系の軍人が両陣営で重要な役割を果たした。伝説的な軍人ボグダス・ジャベリンもこの系譜の出であり、その戦闘スタイルと組織論は後世の軍事思想に多大な影響を与えた。テクノ文化ルネサンス以降は正当な軍事伝統として再評価されている。",descriptionEn:"A general term for the military lineage derived from the Phalanx, a military faction that established the Barz Empire from E15 to E61. After the Phalanx's collapse, its soldiers and tactical philosophies formed military organizations across the Western Continent. Particularly during the Lombardia War from E88 to E98, Techlosus-lineage military personnel played crucial roles on both sides. The legendary soldier Bogdas Javelin originated from this lineage, and his combat style and organizational theories had a profound influence on later military thought. Since the Techno-Cultural Renaissance, it has been reevaluated as a legitimate military tradition.",leaders:[{id:"クロノ・ヴァーレント",name:"クロノ・ヴァーレント",nameEn:"Chrono Valeint",role:"テクロサス指導者",era:"E318年頃"}]},{id:"コーポラタムパブリカ",name:"コーポラタムパブリカ",nameEn:"Corporatum Publica",category:"組織",subCategory:"組織・制度",description:"シンフォニー・オブ・スターズ西大陸でE97年頃の第三繁栄期に正式に成立したコーポラトクラシー体制。政治と経済が融合した統治形態であり、大企業の代表が政府の要職を占めることで効率的な資源配分と迅速な意思決定を実現した。ZAMLTをはじめとする巨大企業が政治的権力を掌握し、市民の生活は企業の福利厚生制度に依存する構造となっていた。E150年のマーストリヒト革命により完全自由経済体制へと移行したが、そのコーポラトクラシーの遺産は現在の西大陸経済システムに深く刻まれている。最高執行官（CEO議長）には各時代の最大企業連合の代表者が就任し、E97年の第三繁榮期には14兆ドルGDPを誇る企業連合体の頂点に立つ者を輩出した。最後期の執行官はエリオット・シュトラスによるZAMLT統合によって解任された。",descriptionEn:"A corporatocracy system formally established during the third prosperity period around E97 on the Western Continent of the Symphony of Stars. This was a governance form where politics and economy merged, with corporate representatives holding key government positions to achieve efficient resource allocation and rapid decision-making. Giant corporations including ZAMLT seized political power, creating a structure where citizens' lives depended on corporate welfare systems. It transitioned to a completely free-market economy following the Maastricht Revolution in E150, but the legacy of this corporatocracy remains deeply embedded in the current Western Continent economic system. The Chief Executive Officer (Chairman of the Board) was filled by representatives of the largest corporate coalitions, with the third prosperity period in E97 producing leaders who stood at the apex of corporate coalitions boasting a 14 trillion dollar GDP. The final executive was dismissed following ZAMLT's unification under Eliot Strass.",leaders:[{id:"エリオット・シュトラス",name:"エリオット・シュトラス",nameEn:"Elliot Strauss",role:"ZAMLT統合による最末期執行官",era:"E301"}]},{id:"シャドウ・ユニオン",name:"シャドウ・ユニオン",nameEn:"Shadow Union",category:"組織",subCategory:"組織・制度",description:"Eros-7の独裁体制に対する最大級の反体制組織。ガロが指導者としてResistanceを統率し、ZAMLT期には画期的なナノハッキング技術を駆使してバイオリアクターの妨害活動を展開した。組織の構成員は主に搾取施設で過酷な労働を強いられる下層市民から成り、地下ネットワークを通じて連携。カーラ・ヴェルムのスクイーズ・アビス建設に対する最大の抵抗勢力として機能した。のちにマトリカル・リフォーム運動にも一部が参加し、Eros-7の民主化に重要な役割を果たした。",descriptionEn:"The largest anti-regime organization against Eros-7's dictatorship. Led by Gal, the Resistance utilized groundbreaking nano-hacking technology during the ZAMLT era to disrupt bioreactors. Its members primarily consisted of lower-class citizens forced into harsh labor in extraction facilities, coordinating through underground networks. It functioned as the primary resistance force against Carla Verm's construction of the Squeeze Abyss. Later, some members participated in the Matric Reform Movement, playing a crucial role in Eros-7's democratization."},{id:"男性指令省",name:"男性指令省",nameEn:"Male Directive Ministry",category:"組織",subCategory:"組織・制度",description:"Eros-7においてシルヴィア・クロウが設立した男性管理のための政府機関。Eros-7特有の女性主導社会における男性の社会参加を統制する目的で作られ、ジーン・カタログの運用と男性の労働配分を管理した。この制度は男性の権利制限として批判を浴び、のちのE525年のマトリカル・リフォーム運動における主要な改革要求対象となった。シルヴィア自身もリーチ・ドレイン危機の収束後、この制度の見直しに理解を示したと伝えられる。",descriptionEn:"A government agency established by Sylvia Crow on Eros-7 to manage men. Created to regulate male social participation in Eros-7's female-dominated society, it operated the Gene Catalog and managed male labor allocation. This system faced criticism as a restriction of men's rights and later became a major reform target in the E525 Matric Reform Movement. Sylvia herself is said to have shown understanding for reviewing this system after resolving the Reach Drain Crisis."},{id:"マトリカル・カウンシル",name:"マトリカル・カウンシル",nameEn:"Matrical Council",category:"組織",subCategory:"組織・制度",description:"Eros-7の最高統治機関であり、女性による集団指導体制をとる評議会。複数の代表議員が政策の決定と執行にあたり、搾取エネルギーを通じた社会統制の要として機能した。シャドウ・ユニオンの反乱に対しては搾取抑制剤を用いた鎮圧措置を実施したが、過度な弾圧は国際的な非難を招いた。評議会の構成と権限は時代とともに変遷し、現在ではマトリカル・リフォーム運動の成果を受けてより民主的な運営へと移行している。",descriptionEn:"The highest governing body of Eros-7, a collective leadership system run by women. Multiple representative members made and executed policy decisions, functioning as the core of social control through exploitation energy. Against the Shadow Union's rebellion, it implemented suppression measures using exploitation inhibitors, but excessive repression drew international condemnation. The council's composition and authority evolved over time, and it has since transitioned to more democratic operations following the Matric Reform Movement's achievements."},{id:"マトリカル・リフォーム運動",name:"マトリカル・リフォーム運動",nameEn:"Matrical Reform Movement",category:"組織",subCategory:"組織・制度",description:"E525年にアヤカ・リン、ガロ、ゼナが共同で組織したEros-7の社会改革運動。労働時間の大幅な短縮と、男性指令省が運用するジーン・カタログの男女平等化を主要な要求とした。シャドウ・ユニオンの反体制活動の経験を踏まえ、暴力ではなく議会闘争と市民運動を通じて改革を追求する手法を採用。この運動はEros-7社会に深い変革をもたらし、搾取体制の段階的な解体と民主化への道を切り開いた。",descriptionEn:"A social reform movement organized on Eros-7 in E525 by Ayaka Rin, Gal, and Zena. Its main demands were significant reduction of working hours and gender equality in the Gene Catalog operated by the Male Directive Department. Drawing from the Shadow Union's anti-regime activities, it adopted methods of pursuing reform through parliamentary struggle and civic movements rather than violence. This movement brought profound changes to Eros-7 society, paving the way for the gradual dismantling of the exploitation system and democratization."},{id:"ヒーローエージェンシー",name:"ヒーローエージェンシー",nameEn:"Hero Agency",category:"組織",subCategory:"組織・制度",description:"シンフォニー・オブ・スターズ西大陸における超常能力者の正式な管理・運用組織。スティル・アレーナの選考と管理、および地域の安全確保を主な任務とし、強力な能力者をエージェントとして登用していた。E495〜E500年の銀河系コンソーシアム設立にあたりネオクラン同盟と統合し、宇宙規模の安全保障体制の中核を形成した。現在でもコンソーシアム内で実働部隊として機能し、次世代の能力者育成にも注力している。",descriptionEn:"The official management and operational organization for extraordinary ability users on the Western Continent of the Symphony of Stars. Its main tasks were the selection and management of the Still Arena and ensuring regional security, employing powerful ability users as agents. During the establishment of the Galactic Consortium from E495 to E500, it merged with the Neo-Clan Alliance to form the core of a galaxy-scale security system. It continues to function as an operational unit within the Consortium, also focusing on developing the next generation of ability users."},{id:"銀河系コンソーシアム",name:"銀河系コンソーシアム",nameEn:"Galactic Consortium",category:"組織",subCategory:"組織・制度",description:"E495年からE500年にかけて設立された宇宙規模の統合的ガバナンス組織。ネオクラン同盟、UECO、ヒーローエージェンシーの三大勢力を統合して誕生し、M104銀河全域の平和と安定維持を目的としている。最大の課題であるヘゲモニー・パラドックスの回避を志向し、軍事大国ティエリアと経済大国グランベルの間の調停役として重要な機能を果たしている。E524年の諸世界連邦サミットでは主催者として宇宙規模の外交協議を実現した。初代議長にはグランベル代表とティエリア代表の共同議長体制が採用され、E524年の諸世界連邦サミットでは両者が共同で主催を務めた。\nこの銀河系コンソーシアムの根底には、多元性民主主義(L2)と第2のゲーム(L3)の思想的地層が横たわっている。多文明の集合知を統合するこのプラットフォームは、テクノロジーで民主主義を拡張するL2と、ゼロサムからオムニウィンへの転換を志向するL3が交差する歴史的実験場である。第一回宇宙連合会合は、「集合知」による合意形成というL2の理念の象徴的な実践であった。",descriptionEn:"A galaxy-scale integrated governance organization established from E495 to E500. Born from the unification of three major powers—the Neo-Clan Alliance, UECO, and the Hero Agencies—it aims to maintain peace and stability across the M104 galaxy. It strives to avoid the Hegemony Paradox, its greatest challenge, and serves as a crucial mediator between the military power Tierra and the economic power Granbell. At the E524 Multi-World Federal Summit, it hosted galaxy-scale diplomatic negotiations. A co-chair system was adopted with representatives from Granbell and Tierra as co-chairs, who jointly hosted the E524 summit. At the foundation of this Galactic Consortium lie the ideological strata of Pluralistic Democracy (L2) and the Second Game (L3). This platform integrating collective knowledge of multiple civilizations is a historical experiment where L2—expanding democracy through technology—and L3—aiming to transform from zero-sum to omni-win—intersect. The first Galactic Assembly was a symbolic practice of L2's principle of consensus formation through 'collective intelligence.'"},{id:"テンプル・オブ・ホライゾン",name:"テンプル・オブ・ホライゾン",nameEn:"Temple of Horizon",category:"組織",subCategory:"組織・制度",description:"テクノ宗教運動の総本山であり、次元極地平を神聖視する信者たちの精神的拠点。テミルタロンが自らの哲学体系を実践するために建設を指導した。内部には次元極地平の研究施設と瞑想空間が併設され、科学と信仰の融合を象徴する建造物となっている。Troyaneに本拠を置き、西大陸各地に分院を擁する。テクノ文化ルネサンス以降は宗教施設としてだけでなく、次元物理学の研究機関としても学術的な評価を得ている。",descriptionEn:"The headquarters of the techno-religious movement and a spiritual center for believers who revere the dimensional horizon. Temirtalon personally guided its construction to practice his philosophical system. It houses research facilities and meditation spaces dedicated to the dimensional horizon, symbolizing the fusion of science and faith. Based in Troyane, it has branches across the Western Continent. Since the Techno-Cultural Renaissance, it has gained academic recognition not only as a religious facility but also as a research institution for dimensional physics."},{id:"Σ-Unit",name:"シグマ・ユニット",nameEn:"Sigma Unit",category:"組織",subCategory:"組織・制度",description:"E420年にエヴァトロン軍が極秘に設立した特殊部隊。高度な精神操作技術と生体改造技術を駆使し、敵対者の洗脳と超人的な戦闘兵士の創出を行った。部隊の存在はエヴァトロン崩壊後長らく不明とされていたが、のちにシルバー・ヴェノムやアルファ・ヴェノムの起源部隊であったことが判明した。Σ-Unitの技術遺産は一部が回収され、新ZAMLT期の軍事研究において倫理的議論の対象となっている。",descriptionEn:"A special unit secretly established by the Evatron military in E420. Utilizing advanced psychic manipulation and biotechnology, the unit conducted brainwashing of adversaries and creation of superhuman combat soldiers. The unit's existence remained unknown after the fall of Evatron until it was later revealed to be the origin unit of Silver Venom and Alpha Venom. The technological legacy of the Σ-Unit has been partially recovered and has become the subject of ethical debates in military research during the new ZAMLT era."},{id:"テリアン反乱軍",name:"テリアン反乱軍",nameEn:"Terrian Rebel Army",category:"組織",subCategory:"軍事・対立組織",description:"エリオス・ウォルドが指導したエヴァトロンに対する武装抵抗組織。E400年のエヴァトロンGigapolis占領直後に結成され、農民、労働者、旧軍人など幅広い層から構成された。山岳地帯を拠点に游击戦を展開し、エヴァトロンの補給線に継続的な打撃を与えた。E470年のエリオス処刑後も残存勢力が抵抗を継続し、E475年の市民蜂起と連携してエヴァトロンの崩壊を実現。その不屈の闘争精神は西大陸の自由の象徴として語り継がれている。",descriptionEn:"An armed resistance organization led by Erios Wald against Evatron. Formed immediately after Evatron's occupation of Gigapolis in E400, it consisted of a broad spectrum of people including farmers, workers, and former soldiers. Based in mountainous regions, they conducted guerrilla warfare and dealt continuous blows to Evatron's supply lines. After Erios's execution in E470, the remaining forces continued their resistance, coordinating with the citizen uprising in E475 to bring about the fall of Evatron. Their indomitable fighting spirit is passed down as a symbol of freedom in the Western Continent."},{id:"ロンバルディア帝国",name:"ロンバルディア帝国",nameEn:"Lombardia Empire",category:"組織",subCategory:"軍事・対立組織",description:"M104銀河において圧倒的な軍事力を誇った歴史的帝国。メルディア戦争（E275〜E288年）においてセクスタス連合と激突し、次元兵器の投入による圧倒的火力で勝利を収めた。戦後の覇権確立により第五次繁栄期をもたらす一方、次元兵器の使用は銀河規模の倫理的議論を巻き起こした。帝国の軍事伝統はテクロサス系譜に受け継がれ、西大陸の軍事史に多大な影響を残した。現在では帝国の正式な後継国家は存在しないが、その遺産は多くの勢力に分散して受け継がれている。",descriptionEn:"A historical empire that boasted overwhelming military power in the M104 Galaxy. During the Meldean War (E275-E288), it clashed with the Sextus Alliance and achieved victory through overwhelming firepower from dimensional weapons. While establishing post-war hegemony and bringing about the Fifth Prosperity Period, the use of dimensional weapons sparked galaxy-wide ethical debates. The military tradition of the empire was inherited by the Teclosas lineage, leaving a profound impact on the military history of the Western Continent. Although no official successor state to the empire exists today, its legacy is inherited by many factions."},{id:"セクスタス連合",name:"セクスタス連合",nameEn:"Sextus Alliance",category:"組織",subCategory:"軍事・対立組織",description:"M104銀河周辺に位置する複数の惑星国家・勢力が結成した軍事同盟。ロンバルディア帝国の拡張主義に対抗するために設立され、メルディア戦争（E275〜E288年）において13年にわたり帝国と戦い抜いた。最終的には帝国の次元兵器により主要拠点を失って敗北したが、その勇戦は銀河全体に感銘を与え、のちの銀河系コンソーシアム設立の理念的基盤となった。連合の残存勢力は戦後も協力関係を維持し、新しい安全保障体制の構築に寄与した。",descriptionEn:"A military alliance formed by multiple planetary states and factions in the M104 Galaxy region, established to counter the expansionism of the Lombardia Empire. They fought against the empire for 13 years during the Meldean War (E275-E288). Although they ultimately lost their main bases to the empire's dimensional weapons and were defeated, their heroic fighting impressed the entire galaxy and became the ideological foundation for the later establishment of the Galactic Consortium. The remaining forces of the alliance maintained their cooperative relationship after the war, contributing to the construction of a new security framework."},{id:"クラン・フォーラム",name:"クラン・フォーラム",nameEn:"Clan Forum",category:"組織",subCategory:"組織・制度",description:"E325年に設立されたネオクラン同盟の下部組織であり、社会的低階層の声を政治プロセスに反映させることを目的とした参加型の議論場。市民が直接提案を行い、政策に対する意見を表明できる場として機能し、ネオクラン同盟の民主的な運営を支える重要な役割を果たした。クワンナラ革命（E108〜E114年）以来の分権化の伝統を受け継ぐ組織であり、地方コミュニティの自治能力を強化する機能も担っている。銀河系コンソーシアム設立後も下部諮問機関として活動を続けている。",descriptionEn:"A subordinate organization of the Neo-Clan Alliance, established in E325 as a participatory discussion forum aimed at reflecting the voices of the social lower classes in the political process. It functioned as a venue where citizens could directly propose policies and express their opinions, playing a crucial role in supporting the democratic operation of the Neo-Clan Alliance. As an organization inheriting the tradition of decentralization since the Quannara Revolution (E108-E114), it also strengthens the autonomous capacity of local communities. It continues to operate as a subordinate advisory body even after the establishment of the Galactic Consortium."},{id:"ヴェルリット一族",name:"ヴェルリット一族",nameEn:"Verlit Clan",category:"組織",subCategory:"軍事・対立組織",description:"シギル・アフェクトと呼ばれる特殊な印を駆使する「魔女」の一族として知られる古い血統集団。クレセント地方を拠点に独自の魔法体系と戦闘術を代々受け継ぎ、周辺地域にその名を知らしめてきた。アイリスがクレセントで活動中に遭遇した敵対勢力であり、シギル・アフェクトの技術を用いた攻撃は通常の物理防御を無効化する特性を持つ。一族の起源については多くの謎に包まれており、古代の次元技術に関連する説も存在する。",descriptionEn:"An ancient bloodline group known as the 'witches' who wield a special mark called the Sigil Affect. Based in the Crescent region, they have passed down their unique magical system and combat techniques through generations, making their name known throughout the surrounding areas. They were an opposing force that Iris encountered while active in Crescent, and their attacks using Sigil Affect technology have the characteristic of nullifying conventional physical defenses. The origins of this clan are shrouded in mystery, with theories linking them to ancient dimensional technology."},{id:"ファランクス",name:"ファランクス",nameEn:"Phalanx",category:"組織",subCategory:"軍事・対立組織",description:"E15年からE61年にかけてバーズ帝国を樹立し、シンフォニー・オブ・スターズ西大陸の広範な領域を支配した強大な軍閥。精鋭の重装歩兵部隊による堅固な戦術で知られ、当時の西大陸最強の軍事力を誇った。帝国崩壊後、その将兵と戦術思想はテクロサスという軍事系譜として受け継がれ、後世の西大陸軍事史に決定的な影響を与えた。Troyaneに残るバーズ帝国時代の遺構は、現在も軍事史研究者の重要な調査対象となっている。",descriptionEn:"A powerful military faction that established the Bartz Empire from E15 to E61, ruling vast territories of the Symphony of Stars Western Continent. Known for their solid tactics with elite heavy infantry units, they boasted the strongest military force in the Western Continent at the time. After the empire's collapse, its soldiers and tactical philosophy were inherited as the Teclosas military lineage, exerting a decisive influence on later Western Continental military history. The ruins from the Bartz Empire era remaining in Troyane remain an important research subject for military historians to this day."},{id:"エレシュ・サンクチュアリ",name:"エレシュ・サンクチュアリ",nameEn:"Eresh Sanctuary",category:"組織",subCategory:"宇宙勢力",description:"エレシュ信仰の総本山であり、宇宙最大の宗教的聖地。次元の境界領域に建設され、物理的な寺院構造と精神世界的な聖域が融合した特異な空間を形成している。サンクチュアリ内部では、次元境界の共鳴を利用した瞑想儀式が行われ、高位の神官たちはこれによって宇宙の「脈動」を感知し未来予知に近い洞察を得ているとされる。サンクチュアリの中枢には「万神の間」と呼ばれる大殿堂があり、エレシュの教義における宇宙創造の根源的な精神理念が具現化されている。エレシュ信者の巡礼目的地であり、毎年数万人が訪れる。宇宙連合会合において、エレシュは思想的影響力を背景に他の宇宙勢力とは異なるアプローチで問題解決を主導し、時にはグランベルやティエリアの政治的決定を動かすほどの力を発揮している。サンクチュアリの周辺には多くの修行施設と研究機関が立ち並び、宗教と科学の融合というエレシュ独自の学問が展開されている。",descriptionEn:"The head temple of Eresh faith and the universe's largest religious sanctuary. Constructed in a dimensional boundary area, it forms a unique space where physical temple structures and spiritual realms merge. Inside the Sanctuary, meditation rituals utilizing the resonance of dimensional boundaries are conducted, and it is said that high-ranking priests can perceive the universe's 'pulse' and gain insights close to prophecy through these rituals. At the heart of the Sanctuary is the 'Hall of Ten Thousand Gods,' where the fundamental spiritual concepts of cosmic creation in Eresh doctrine are manifested. It is a pilgrimage destination for Eresh believers, with tens of thousands visiting annually. In United Cosmic Assembly sessions, Eresh, backed by its ideological influence, leads problem-solving with an approach different from other cosmic powers, sometimes even influencing the political decisions of Grabel and Tieria. Numerous training facilities and research institutions stand around the Sanctuary, where Eresh's unique academic tradition of blending religion and science is developed."},{id:"オラクル",name:"オラクル",nameEn:"Oracle",category:"組織",subCategory:"宇宙勢力",description:"エレシュの最高意思決定機関であり、大司教と複数の神官長で構成される宗教的最高議会。オラクルはエレシュ信仰の教義解釈権を持ち、宇宙規模の信仰共同体の指針を決定する。その決定は教義の解釈だけでなく、宇宙連合会合などの政治の場にも直接的な影響を与える。オラクルの予言や声明はエレシュ信者のみならず、他勢力の指導者にも無視できない影響力を持っている。オラクルは次元境界の不安定化に対する警告を何度も発しており、その予言の的中率は宇宙最高と評されている。マドリス・カーネル（ファルージャ評議会代表）とは外交関係にあり、ファルージャの文化的影響力とエレシュの精神的影響力の協調を図っている。オラクルの声明文は特殊な次元共鳴技術で広範囲に同時送信され、宇宙中の聖地で同時に受信される。",descriptionEn:"The highest decision-making body of Eresh, composed of the Archbishop and several High Priests, forming the supreme religious council. The Oracle holds the authority to interpret Eresh doctrine and determines the guidelines for the cosmic-scale faith community. Its decisions affect not only doctrinal interpretation but also directly influence political arenas such as the United Cosmic Assembly. The prophecies and declarations of the Oracle hold influence that cannot be ignored, not only among Eresh believers but also among leaders of other factions. The Oracle has repeatedly issued warnings about the destabilization of dimensional boundaries, and its prophecy accuracy is rated as the highest in the universe. It maintains diplomatic relations with Madris Carnell (representative of the Falujah Council), coordinating between Falujah's cultural influence and Eresh's spiritual influence. The declarations of the Oracle are broadcast simultaneously over wide areas using special dimensional resonance technology, and are received simultaneously in sacred sites throughout the universe."},{id:"セラフィム",name:"セラフィム",nameEn:"Seraphim",category:"組織",subCategory:"宇宙勢力",description:"エレシュの外務・広報を担う機関であり、宇宙への教義伝播と対外折衝の役割を果たす。セラフィムは文字通り「熾天使」を意味し、エレシュ信者が他文明圏に対して活動する際の窓口となる組織である。セラフィムの伝道師たちは宇宙各地に派遣され、エレシュの教義を独自の儀式音楽と瞑想技法を通じて広めている。特にE16文明圏では、セリア黄金期（E335〜E370）のAURALISと精神的な共鳴が指摘されており、AURALISの「光と音を永遠にする」という理念とエレシュの宇宙観の間に思想的な類似性があるとされている。セラフィムは平和的な広報活動を基本方針としているが、他勢力の政治的決定に対してはオラクルの名のもと強い発言を行うこともある。第一回宇宙連合会合では、エレシュ代表として参加し、精神的指導の重要性を主張した。セラフィムの拠点はグランベルのオルダシティ、ティエリアのティエリア・フォートレス、ファルージャのファルージャ・ハブなど各主要都市に置かれている。",descriptionEn:"An agency responsible for foreign affairs and public relations for Eresh, tasked with spreading its teachings throughout the cosmos and conducting external negotiations. Seraphim literally means 'burning angels' and serves as the organization through which Eresh believers interact with other civilizations. Seraphim missionaries are dispatched throughout the cosmos, spreading Eresh's teachings through unique ritual music and meditation techniques. Particularly in the E16 civilization sphere, spiritual resonance with AURALIS during the Serian Golden Age (E335-E370) has been noted, with ideological similarities between AURALIS's concept of 'making light and sound eternal' and Eresh's cosmic worldview. While Seraphim's basic policy is peaceful public relations activities, it sometimes makes strong statements on the political decisions of other factions in the name of the Oracle. In the first United Cosmic Assembly, it participated as the representative of Eresh, advocating for the importance of spiritual leadership. Seraphim's bases are located in major cities such as Old City in Grabel, Tieria Fortress in Tieria, and Falujah Hub in Falujah."},{id:"コマース",name:"コマース・ディヴィジョン",nameEn:"Commerce Division",category:"組織",subCategory:"宇宙勢力",description:"プロキオの商業取引を統轄する部門であり、宇宙最大の商業センター。コマースは金融・為替・保険・投資のすべてを管理し、宇宙規模の商業取引の安全と公正を担保する役割を持つ。プロキオの「市場の透明性」を基本理念とし、全取引の記録と監査を行うことで詐欺行為を防止している。コマースは独自の商業裁判所を持ち、取引紛争の解決を迅速かつ公正に行う。また、宇宙共通通決済システム「プロキオ・クリア」を開発・運営しており、全文明圏で利用可能な決済インフラを提供している。この決済システムはnトークン経済とも互換性を持ち、E16系内での取引から銀河規模の貿易までカバーしている。コマースの活動は宇宙経済の基盤を支える不可欠な存在であり、プロキオ・ネクサスとともに宇宙の経済的循環の心臓部として機能している。",descriptionEn:"The department overseeing commercial transactions in Prokio, serving as the universe's largest commercial center. Commerce manages finance, exchange, insurance, and investment, guaranteeing the safety and fairness of cosmic-scale commercial transactions. Based on Prokio's principle of 'market transparency,' it prevents fraudulent activities by recording and auditing all transactions. Commerce operates its own commercial courts to resolve transaction disputes quickly and fairly. It also develops and operates the universal payment system 'Prokio Clear,' providing payment infrastructure available in all civilization spheres. This payment system is compatible with the n-token economy, covering everything from transactions within the E16 system to galaxy-scale trade. Commerce's activities are an indispensable foundation for the cosmic economy, functioning as the heart of the universe's economic circulation along with Prokio Nexus."},{id:"バザール",name:"バザール・ネットワーク",nameEn:"Bazaar Network",category:"組織",subCategory:"宇宙勢力",description:"プロキオが運営する宇宙最大の市場ネットワーク。バザールは物理的な市場施設だけでなく、次元間通信技術を活用したバーチャル市場プラットフォームも含み、あらゆる商品・サービスが取引される。バザール・ネットワークに参加する加盟店は数十万に上ると推定され、宇宙最大の商業生態系を形成している。バザールではプロキオの品質認証システムが適用され、取引される商品の信頼性が担保されている。また、バザールは情報取引の場としても機能し、他文明圏の最新技術情報や市場動向がリアルタイムで共有される。プロキオの収益の大部分はバザールの取引手数料と品質認証料金から成っており、この収益構造がプロキオの経済的基盤を支えている。バザールの市場動向は宇宙経済のバロメーターとして機能し、プロキオ・ネクサスの取引所の価格変動が全宇宙の物価に直接的な影響を与えている。",descriptionEn:"The universe's largest market network operated by Prokio. The Bazaar includes not only physical market facilities but also virtual market platforms utilizing interdimensional communication technology, where all kinds of goods and services are traded. It is estimated that hundreds of thousands of stores participate in the Bazaar Network, forming the universe's largest commercial ecosystem. The Bazaar applies Prokio's quality certification system, ensuring the reliability of traded goods. The Bazaar also functions as a venue for information trading, with the latest technological information and market trends from other civilization spheres shared in real-time. The majority of Prokio's revenue comes from transaction fees and quality certification fees of the Bazaar, which structure supports Prokio's economic foundation. The market trends of the Bazaar serve as a barometer for the cosmic economy, with price fluctuations in Prokio Nexus exchanges directly affecting prices throughout the universe."},{id:"シグナル",name:"シグナル・オペレーション",nameEn:"Signal Operation",category:"組織",subCategory:"宇宙勢力",description:"ロースターの通信衛星ネットワークの運営を担う部門。シグナル・オペレーションは数千の通信衛星と中継基地を管理し、宇宙全域に安定した通信サービスを提供している。シグナルの通信網は「シグナル・ウェーブ」と呼ばれ、次元間の干渉に対する耐性を高めた独自の量子暗号プロトコルで保護されている。シグナル・オペレーションは緊急通信優先ルーティングを備えており、災害時や軍事的緊急事態には通常通信を迂回させて優先的に緊急メッセージを配信する。この機能はティエリアの防衛ネットワークとも連携して設計されており、軍事警報の伝達が最優先される仕組みになっている。シグナルの通信カバレッジはプロキオのレーン・システムとも統合されており、物流情報のリアルタイム追跡が可能となっている。シグナルの通信品質は宇宙最高水準であり、遅延は1光年あたり0.3秒以下を実現している。",descriptionEn:"The department responsible for operating the Roster's communication satellite network. Signal Operations manages thousands of communication satellites and relay stations, providing stable communication services across the entire universe. Signal's communication network, known as the 'Signal Wave,' is protected by a unique quantum cryptographic protocol enhanced to resist dimensional interference. Signal Operations features emergency communication priority routing, which bypasses normal communications to prioritize emergency message delivery during disasters or military emergencies. This function is designed in coordination with Tiera's defense network, ensuring that military alerts receive the highest priority. Signal's communication coverage is also integrated with Prokio's Lane System, enabling real-time tracking of logistics information. Signal's communication quality is the highest standard in the universe, achieving a latency of less than 0.3 seconds per light-year."},{id:"リンク",name:"リンク・プロトコル",nameEn:"Link Protocol",category:"組織",subCategory:"宇宙勢力",description:"ロースターが開発した宇宙標準通信プロトコルであり、全文明圏で採用されている通信の基盤技術。リンク・プロトコルは異なる文明圏の通信システム間の相互接続性を確保するために設計された、オープンスタンダードの通信規格である。リンクの最大の特徴は、経済取引システム、医療データシステム、軍事通信システム、学術研究ネットワークなど、用途を問わずあらゆる通信を単一のプロトコルで統合できる点にある。これにより、文明圏を超えたシームレスな通信とデータ共有が可能となり、UECOの経済取引や銀河系コンソーシアムの共同プロジェクトなどの基盤技術となっている。リンクはバージョンアップを重ねており、最新版は「リンク7.2」と呼ばれる。バージョン7.2ではロースターの次世代量子通信技術が組み込まれ、より高速で安全な通信が実現している。リンクの技術仕様は全文明圏に公開されており、独自の拡張機能を追加できる拡張性を持つ。",descriptionEn:"The universal standard communication protocol developed by Roster and adopted as the foundational technology by all civilizations. The Link Protocol is an open-standard communication specification designed to ensure interoperability between different civilization communication systems. Link's most significant feature is its ability to integrate all forms of communication—regardless of purpose, such as economic transaction systems, medical data systems, military communication systems, and academic research networks—into a single protocol. This enables seamless communication and data sharing across civilizations, serving as the foundational technology for UECO economic transactions and the Galaxy Consortium's joint projects. Link has undergone multiple version upgrades, with the latest version being 'Link 7.2,' which incorporates Roster's next-generation quantum communication technology for faster, more secure communications. Link's technical specifications are publicly available to all civilizations and possesses the scalability to allow for the addition of custom extensions."},{id:"エレシュ",name:"エレシュ",nameEn:"Eresh",category:"組織",subCategory:"宇宙勢力",description:"宇宙第6位の文明圏で、宗教と精神的影響力を基盤とする神政国家である。大司教と複数の神官長で構成されるオラクルが最高意思決定機関として機能し、次元共鳴を用いた瞑想と予言の伝統は他文明圏にも広く影響を与えている。中枢聖星ヴェズレル（『真理の星』）を中心に、次元境界近くに建造されたエレシュ・サンクチュアリを主たる聖地とし、毎年数万人の巡礼者が訪れる。セラフィムを対外機関とし、活発な布教活動を通じて宇宙規模の信仰共同体を形成している。その予言の高精度さにより、グランベルやティエリアを含む複数の文明圏の政治的決断に直接的な影響を与えてきた。ファルージャのマドリス・カーネルとは古くから外交関係を維持し、文化的・精神的交流を深めている。プロキオとはサンクチュアリへの巡礼ルートを通じた経済的つながりを持ち、ロースターとは次元共鳴通信技術の共同研究を進めている。エレシュの「精神の力こそが宇宙を結びつける究極の糸である」という理念は、E16文明圏のAURALISが掲げる「光と音を永遠にする」という哲学と深い共鳴関係にあると指摘されている。現大司教はオラクルの議長を務め、次元共鳴予言で宇宙政治に影響を与えている。歴代大司教は終身制で、厳格な選考プロセスを経て決定され、その精神的影響力はグランベルやティエリアの指導者すら無視できないものとなっている。",descriptionEn:"The sixth-ranked civilization in the universe, a theocratic state based on religion and spiritual influence. The Oracle, composed of the Archbishop and several High Priests, functions as the highest decision-making body, and its tradition of meditation and prophecy using dimensional resonance has widely influenced other civilizations. Centered on the central holy planet Vezrel ('The Star of Truth'), with the Elesh Sanctuary built near the dimensional boundary as its primary holy site, it attracts tens of thousands of pilgrims annually. Seraphim serves as its external agency, forming a universal-scale faith community through active missionary activities. The high accuracy of its prophecies has directly influenced political decisions in multiple civilizations, including Granbel and Tiera. Phalujah maintains diplomatic relations with Madris Kurnel of Falujah, deepening cultural and spiritual exchange. Prokio maintains economic connections through pilgrimage routes to the Sanctuary, and Roster is jointly researching dimensional resonance communication technology. Elesh's philosophy that 'the power of the spirit is the ultimate thread that binds the universe' is noted to have a deep resonance with the philosophy upheld by AURALIS of the E16 civilization: 'to make light and sound eternal.' The current Archbishop serves as the chair of the Oracle, influencing cosmic politics through dimensional resonance prophecies. Archbishops serve for life, determined through a rigorous selection process, and their spiritual influence is so significant that even leaders of Granbel and Tiera cannot afford to ignore it.",leaders:[{id:"大司教",name:"大司教",nameEn:"Archbishop",role:"エレシュ最高指導者",era:"現在"}]},{id:"プロキオ",name:"プロキオ",nameEn:"Prokio",category:"組織",subCategory:"宇宙勢力",description:"宇宙第7位の文明圏で、宇宙規模の交易・物流を掌握する商業国家である。商工会議長を最高責任者とし、中核拠点プロキオ・ネクサスを中心に全宇宙の商取引を管理している。コマース・ディヴィジョンが金融・為替・保険・投資を統轄し、AI物流ルーティングネットワーク「レーン・システム」が最適な輸送経路を算出する。レーン・システムはオープンアーキテクチャ設計を採用しており、グランベルとエレシオンが自勢力内に統合するほどの信頼性を獲得している。n-token経済と互換性を持つ「プロキオ・クリア」汎用決済システムにより、全文明圏間の決済を統一した。バザール・ネットワークを通じた数十万店舗の市場プラットフォームは宇宙最大の商業生態系を形成し、プロキオ・ネクサスでの価格設定が宇宙全体のベースライン価格を決定する。エレシオンとは医療物資優先配送協定を、ティエリアとは軍事物資の物流管理を、ファルージャとは文化財の交易ルートを、ディオクレニスとは科学機器の優先物流協定をそれぞれ結んでおり、その経済活動はすべての文明圏に直接的な影響を与えている。プロキオの存在は、グランベルの経済覇権とは異なる形で宇宙の安定を支える不可欠な基盤となっている。現商工会議長が全宇宙の貿易ルートを統括し、歴代商工会議長は市場の透明性と開放性を理念としてきた。レーン・システムのオープンアーキテクチャ設計はこの理念の具現化であり、グランベルのアルゼン・カーリーン大統領とは経済分野で密接に協調している。",descriptionEn:"The seventh-ranked civilization in the universe, a commercial state that controls interstellar trade and logistics. The Chamber of Commerce President serves as the highest authority, managing all commercial transactions across the universe with the Commerce Division at its core, centered in the hub Prokio Nexus. The Commerce Division oversees finance, foreign exchange, insurance, and investment, while the AI logistics routing network 'Lane System' calculates optimal transport routes. The Lane System employs an open architecture design, achieving such reliability that Granbel and Elesion have integrated it within their own spheres. The 'Prokio Clear' universal payment system, compatible with the n-token economy, standardizes settlements across all civilizations. The marketplace platform through the Bazaar Network, with hundreds of thousands of stores, forms the universe's largest commercial ecosystem, with price setting at Prokio Nexus determining the baseline prices across the cosmos. Prokio has established priority medical supply delivery agreements with Elesion, military material logistics management with Tiera, cultural artifact trade routes with Falujah, and priority logistics agreements for scientific equipment with Diocrenis. Its economic activities directly influence all civilizations. Prokio serves as an indispensable foundation for cosmic stability in a form different from Granbel's economic hegemony. The current Chamber of Commerce President oversees all interstellar trade routes, and previous presidents have upheld the principles of market transparency and openness. The open architecture design of the Lane System is the embodiment of this philosophy, and the President maintains close cooperation with President Arsen Karlin of Granbel in economic affairs.",leaders:[{id:"商工会議長",name:"商工会議長",nameEn:"Chamber of Commerce Chairman",role:"プロキオ文明圏最高指導者",era:"現在"}]},{id:"ロースター",name:"ロースター",nameEn:"Roastar",category:"組織",subCategory:"宇宙勢力",description:"宇宙第8位の文明圏で、次元間通信と量子ネットワーク技術の革新に特化した技術国家である。通信長官を最高責任者とし、中核拠点ロースター・コアを中心に量子コンピューティング研究と通信インフラの管理を推進している。シグナル・オペレーションが全宇宙の数千の通信衛星を管理し、1光年あたり0.3秒以下という宇宙最高水準の通信遅延を実現している。「リンク・プロトコル」は全文明圏で使用される唯一の汎用通信規格であり、経済取引・医療データ・軍事通信・学術研究ネットワークなどあらゆる通信を単一プロトコルで統合している。最新版のLink 7.2では次世代量子通信技術が組み込まれ、オープンイノベーションモデルにより新技術は数ヶ月で全宇宙に展開される。クアンタ・ラボでは最先端の量子プロトコル研究を実施し、ディオクレニスの研究者も参加する国際的な共同研究体制を構築している。次元不安定の早期警戒システムをロースター・コアに構築し、ティエリアの防衛ネットワークと接続して緊急ルーティングを確保している。グランベルの量子経済システム、エレシオンの医療データネットワーク、ファルージャの文化交流プラットフォーム、エレシュの次元共鳴通信研究など、あらゆる文明圏の通信インフラがロースターに依存しており、その安全性と安定性は宇宙全体の情報の命運を握っている。現通信長官が全宇宙の通信インフラを統括し、歴代通信長官は技術革新の迅速な普及を使命としてきた。オープンイノベーションモデルによる新技術の全宇宙展開は歴代の重要な業績であり、次元不安定の早期警戒システムの構築も歴代の重要な業績として評価されている。",descriptionEn:"The eighth-ranked civilization in the universe, a technical state specializing in innovations in interdimensional communication and quantum network technology. The Communications Commissioner serves as the highest authority, promoting quantum computing research and communication infrastructure management centered in the hub Roster Core. Signal Operations manages thousands of communication satellites across the universe, achieving the highest standard of communication latency in the cosmos at less than 0.3 seconds per light-year. The 'Link Protocol' is the only universal communication standard used across all civilizations, integrating all forms of communication—economic transactions, medical data, military communications, academic research networks—into a single protocol. The latest version, Link 7.2, incorporates next-generation quantum communication technology, and its open innovation model enables new technologies to be deployed across the universe within months. Quanta Lab conducts cutting-edge quantum protocol research and has established an international collaborative research framework where researchers from Diocrenis also participate. An early warning system for dimensional instabilities has been constructed at Roster Core, connected to Tiera's defense network to ensure emergency routing. The communication infrastructure of all civilizations—Granbel's quantum economic system, Elesion's medical data network, Falujah's cultural exchange platform, Elesh's dimensional resonance communication research—depends on Roster, and its security and stability hold the fate of all information in the universe in their hands. The current Communications Commissioner oversees all communication infrastructure in the universe, and previous commissioners have made it their mission to rapidly disseminate technological innovations. The deployment of new technologies across the universe through the open innovation model and the construction of the early warning system for dimensional instabilities are evaluated as major achievements of previous generations.",leaders:[{id:"通信長官",name:"通信長官",nameEn:"Communications Commissioner",role:"ロースター文明圏最高指導者",era:"現在"}]},{id:"トロン・コーポレーション",name:"トロン・コーポレーション",nameEn:"Tron Corporation",category:"組織",subCategory:"組織・制度",description:"ZAMLTを構成する5超巨大企業の一つ。重工業と軍事技術を担当し、ZAMLTの武力面を支えた企業である。CEOはラファエル・ドレイク。旗艦「カリバーン」を擁する宇宙最大級の私設艦隊を保有し、ZAMLTの支配維持のための武力行使を担った。テクロサスとの全面戦争ではトロンの軍事力が主力として投入され、激戦の末にアルファ・ケインによってラファエル・ドレイクが打倒された。トロンの軍事技術遺産はZAMLT崩壊後も一部が流用され、シルバー・ヴェノムやエヴァトロンのΣ-Unitに影響を与えたとされる。E16文明圏における「企業が軍隊を保有する」というコーポラトクラシー体制の極端な例として歴史的に評価されている。",descriptionEn:"One of the five mega-corporations that constituted ZAMLT. It handled heavy industry and military technology, serving as the military arm of ZAMLT. Its CEO was Rafael Drake. It possessed the flagship 'Caliburn' and one of the largest private space fleets in the universe, responsible for the use of force to maintain ZAMLT's dominance. During the full-scale war with Techlos, Tylon's military force was deployed as the main force, and in the fierce battle that followed, Rafael Drake was overthrown by Alpha Cain. Tylon's military technology legacy was partially utilized after ZAMLT's collapse, reportedly influencing the Silver Venom and the Σ-Unit of Evatron. It is historically evaluated as an extreme example of the corporatocracy system in the E16 civilization, where 'corporations possess armies.'",leaders:[{id:"ラファエル・ドレイク",name:"ラファエル・ドレイク",nameEn:"Rafael Drake",role:"トロン・コーポレーションCEO",era:"E301〜E318"}]},{id:"アロエオイル・コーポレーション",name:"アロエオイル・コーポレーション",nameEn:"Aloe Oil Corporation",category:"組織",subCategory:"組織・制度",description:"ZAMLTを構成する5超巨大企業の一つ。次元エネルギー技術と戦術的作戦立案を担当した企業である。リーダーはアイリス・ノヴァ。次元エネルギーを兵器化した「次元エネルギースーツ」を開発し、ZAMLTの精鋭部隊に装備させた。また、工作員ライラ・ヴァーシティを通じてアルファ・ケインのチームを次元刑務所「デッドホロウ」に幽閉するなど、諜報活動でも活躍した。nebura（星々の交響曲）の最終盤ではアイリス・ノヴァ自身が次元の荒野でアルファ・ケインのチームと決戦を展開し、リンダの残したデータを利用されたことで敗北した。アロエオイルの次元エネルギー技術はZAMLT崩壊後、セリア・ドミニクスによるPhovos次元エネルギー商業化の技術的基盤の一つとなった可能性が指摘されている。",descriptionEn:"One of the five mega-corporations that constituted ZAMLT. It handled dimensional energy technology and tactical operational planning. Its leader was Iris Nova. It developed 'dimensional energy suits' that weaponized dimensional energy and equipped ZAMLT's elite forces with them. It also engaged in intelligence activities, such as imprisoning Alpha Cain's team in the dimensional prison 'Dead Hollow' through its agent Lyla Varsity. In the finale of nebura (Symphony of the Stars), Iris Nova herself engaged in a final battle with Alpha Cain's team in the dimensional wilderness and was defeated, as Linda's remaining data was utilized against her. Aloeol's dimensional energy technology may have served as one of the technical foundations for Phovos's commercialization of dimensional energy technology by Seria Dominicus after ZAMLT's collapse.",leaders:[{id:"アイリス・ノヴァ",name:"アイリス・ノヴァ",nameEn:"Iris Nova",role:"アロエオイル・コーポレーションリーダー",era:"E301〜E318"}]},{id:"マモン・コーポレーション",name:"マモン・コーポレーション",nameEn:"Mammon Corporation",category:"組織",subCategory:"組織・制度",description:"ZAMLTを構成する5超巨大企業の一つ。金融と資産管理を担当した企業である。リーダーはカルロス・ヴァンダム。ZAMLTの経済覇権を支える資金調達と資産運用の中枢を担い、プロトコルXに必要な3京ドルの資金計画（3京ドル作戦）を立案した。慎重な戦略家であるカルロス・ヴァンダムの指導の下、マモンは常に最も保守的なアプローチを取り、ZAMLT内部での急進的な軍事展開には懐疑的な姿勢を維持した。ZAMLT崩壊後の経済的混乱期には、マモンの金融専門家の一部がUECOの設立に参加し、新たな経済框架の構築に寄与したとされる。名称は「富の神マモン」に由来し、コーポラトクラシー体制における「富こそが力」という信条を象徴している。",descriptionEn:"One of the five mega-corporations that constituted ZAMLT. It handled finance and asset management. Its leader was Carlos Vandom. It served as the core of ZAMLT's economic hegemony, handling fundraising and asset management, and formulated the 300 trillion dollar funding plan (Operation 300 Trillion Dollars) required for Protocol X. Under the leadership of the cautious strategist Carlos Vandom, Mammon always adopted the most conservative approach, maintaining a skeptical stance toward radical military deployments within ZAMLT. In the period of economic chaos after ZAMLT's collapse, some of Mammon's financial experts reportedly participated in the establishment of UECO, contributing to the construction of a new economic framework. Its name derives from 'the god of wealth Mammon,' symbolizing the belief in 'wealth is power' within the corporatocracy system.",leaders:[{id:"カルロス・ヴァンダム",name:"カルロス・ヴァンダム",nameEn:"Carlos Vandam",role:"マモン・コーポレーションリーダー",era:"E301〜E318"}]},{id:"ゼブラ・コーポレーション",name:"ゼブラ・コーポレーション",nameEn:"Zebra Corporation",category:"組織",subCategory:"組織・制度",description:"ZAMLTを構成する5超巨大企業の一つ。次元技術の研究・開発を担当した企業である。リーダーはアーサー・グリム。次元境界の不安定領域を利用した次元兵器や次元刑務所の設計など、最も危険な技術領域を独占的に担った。ゼブラの工作員レイ・ヴァンデルトはアレンをシェンドバーグ次元に閉じ込めて殺害し、ZAMLTに抗うコーポラトクラシーへの警告とした。虚無の塔（Tower of the Void）でのEVILSとの秘密会合にもゼブラが関与しており、ZAMLTと次元間生命体の裏取引を仲介したとされる。ゼブラの次元技術はZAMLT崩壊後も一部が回収され、テクノ文化ルネサンス期の次元極地平技術の民生化に間接的に貢献した。",descriptionEn:"One of the five mega-corporations that constituted ZAMLT. It handled research and development of dimensional technology. Its leader was Arthur Grimm. It exclusively handled the most dangerous technological areas, designing dimensional weapons and dimensional prisons that utilized unstable areas of dimensional boundaries. Zebra's agent Ray Vandel imprisoned Allen in the Schendberg dimension and killed him, serving as a warning to corporatocracy resisting ZAMLT. Zebra was also involved in the secret meeting with EVILS at the Tower of the Void, mediating the behind-the-scenes transactions between ZAMLT and interdimensional lifeforms. After ZAMLT's collapse, some of Zebra's dimensional technology was recovered, indirectly contributing to the civilian application of dimensional polar horizon technology during the Techno Cultural Renaissance period.",leaders:[{id:"アーサー・グリム",name:"アーサー・グリム",nameEn:"Arthur Grim",role:"ゼブラ・コーポレーションリーダー",era:"E301〜E318"}]},{id:"ルレンツ・コーポレーション",name:"ルレンツ・コーポレーション",nameEn:"Lulentz Corporation",category:"組織",subCategory:"組織・制度",description:"ZAMLTを構成する5超巨大企業の一つ。科学研究と技術開発を担当した企業である。リーダーはエリザベス・リンドバーグ。プロトコルXの技術設計とカタリスト・コアの建造に深く関与し、ZAMLTの技術的優位性を維持するための研究開発を推進した。他の4企業が軍事や金融に偏重する中、ルレンツは純粋な科学的研究に注力する姿勢をとり、次元物理学や量子情報科学の分野で画期的な成果を挙げた。しかし、その研究成果はZAMLTの支配強化のために利用され、本来の平和的な科学技術が軍事転用された側面も持つ。ZAMLT崩壊後、ルレンツの研究施設の一部は惑星ビブリオのロレンツィオ国際大学に統合され、E16文明圏の学術研究の基盤を形成した。",descriptionEn:"One of the five mega-corporations that constituted ZAMLT. It handled scientific research and technological development. Its leader was Elizabeth Lindberg. It was deeply involved in the technical design of Protocol X and the construction of the Catalyst Core, promoting research and development to maintain ZAMLT's technological superiority. While the other four corporations focused on military and financial matters, Lorentz focused on pure scientific research, achieving groundbreaking results in the fields of dimensional physics and quantum information science. However, its research results were utilized to strengthen ZAMLT's dominance, possessing the aspect that originally peaceful scientific technology was diverted for military use. After ZAMLT's collapse, some of Lorentz's research facilities were integrated into the Lorenzio International University on the planet Viblio, forming the foundation for academic research in the E16 civilization.",leaders:[{id:"エリザベス・リンドバーグ",name:"エリザベス・リンドバーグ",nameEn:"Elizabeth Lindberg",role:"ルレンツ・コーポレーションリーダー",era:"E301〜E318"}]},{id:"ストロベリー",name:"ストロベリー",nameEn:"Strawberry",category:"組織",subCategory:"組織・制度",description:"ZAMLT期に活動した中堅コーポラトクラシー。CEOはアレン。20万以上のコーポラトクラシーが乱立するGigapolis経済圏において、ZAMLTやその他のメタ企業の圧力に抵抗しながら独立を維持していたコーポラトクラシーの一つである。規模はZAMLTの5大企業には遠く及ばないが、独自の技術力と商業網を持ち、Gigapolis経済圏の中堅層として機能していた。アレンは終末の星（Star of the End）計画への関与を通じてZAMLTの真の脅威を認識し、アルファ・ケインをスティル・アレーナに推薦して抵抗の火種を撒いた。しかしアレンの殺害後、ストロベリーはZAMLTの報復攻撃を受け、消滅したとされる。ストロベリーの悲劇は、コーポラトクラシー体制下で多数の中堅・小規模コーポラトクラシーが直面した運命を象徴する出来事であり、ZAMLTの覇権の残酷さを浮き彫りにしている。",descriptionEn:"A mid-sized corporatocracy that operated during the ZAMLT period, with Allen as its CEO. In the Gigapolis economic zone where over 200,000 corporatologies existed, Strawberry was one that maintained independence while resisting the pressure from ZAMLT and other meta-enterprises. While its scale was far from ZAMLT's five major corporations, it possessed its own technological capabilities and commercial network, functioning as the middle tier of the Gigapolis economic zone. Through his involvement in the Star of the End project, Allen recognized the true threat of ZAMLT and recommended Alpha Cain to Still Arena, sowing the seeds of resistance. However, after Allen's assassination, Strawberry was reportedly destroyed by ZAMLT's retaliatory attack. The tragedy of Strawberry symbolizes the fate faced by numerous mid-sized and small corporatologies under the corporatocracy system, highlighting the cruelty of ZAMLT's hegemony.",leaders:[{id:"アレン",name:"アレン",nameEn:"Allen",role:"ストロベリーCEO",era:"E318年前後"}]},{id:"org-バーズ帝国官庁",name:"バーズ帝国中央官庁",nameEn:"Birds Empire Central Bureau",category:"組織",subCategory:"組織・制度",description:"ファランクス皇帝がE15年に設立したバーズ帝国の行政機関。帝国の法律・徴税・公共事業・人口管理を統括し、シンフォニー・オブ・スターズ西大陸全土に広がる支配体制の行政的基盤として機能した。官庁は三つの部門から構成され、法務部が帝国法の制定と執行を、財務部がnトークン以前の旧通貨システムによる徴税を、工事部が都市建設と道路整備を担当した。帝国崩壊後はその機能の大部分が惑星国家連合に引き継がれたが、一部の行政記録はTroyaneの地下公文書館に保管されたままである。官庁の官僚制度は後にZAMLT期のコーポラトクラシー体制とUECO期の超国家機関の両方に影響を与えた。",descriptionEn:"An administrative agency of the Bird Empire, founded by Emperor Phalanx in E15. It oversaw the empire's laws, taxation, public works, and population management, serving as the administrative foundation for the ruling system that spread across the entire West Continent of the Symphony of Stars. The agency consisted of three departments: the Legal Department was responsible for the formulation and enforcement of imperial law, the Finance Department handled taxation using the pre-n-token currency system, and the Public Works Department was in charge of urban construction and road maintenance. After the empire's collapse, most of its functions were inherited by the Planetary Nations Union, though some administrative records remained preserved in the underground archives of Troyane. The agency's bureaucratic system later influenced both the corporatocracy system of the ZAMLT period and the supranational agencies of the UECO period."},{id:"org-第一移民評議会",name:"第一移民評議会",nameEn:"First Immigration Council",category:"組織",subCategory:"組織・制度",description:"E50年のバーズ帝国崩壊後に、存続した入植地の指導者たちが設立した臨時統治機関。惑星ビブリオとSolarisを中心に7つの入植地を統括し、食糧生産、防衛、通信インフラの再建を最優先課題として取り組んだ。評議会は合議制を採用し、各入植地の代表が平等な発言権を持つ民主的な運営を特徴としたが、資源不足と外部からの脅威に対処するため、次第に権限が一部の強力な入植地に集中していった。第一移民評議会はE80年の技術啓蒙時代に正式な惑星国家連合へと発展的に解消し、その遺産は現在のUECOの協議体制に間接的に受け継がれている。",descriptionEn:"Following the collapse of the Barz Empire in E50, an interim governing body established by the leaders of surviving colonies. Centered on the planet Biblio and Solaris, it coordinated seven colonies, prioritizing the reconstruction of food production, defense, and communication infrastructure. The council operated on a deliberative system with democratic features, giving equal speaking rights to representatives from each colony. However, to address resource shortages and external threats, authority gradually concentrated in the hands of powerful colonies. The First Immigration Council was progressively dissolved into the formal Planetary Federation of Nations during the E80 Enlightenment Era, with its legacy indirectly inherited by UECO's current consultative system."},{id:"org-ギガポリス建設ギルド",name:"ギガポリス建設者ギルド",nameEn:"Gigapolis Builders Guild",category:"組織",subCategory:"組織・制度",description:"E150年のギガポリス建設開始時に結成された建築技術者と労働者の職能団体。セントラル・タワーをはじめとするギガポリスの象徴的な建造物の設計・施工を統括し、数百万人の労働力を組織化して都市建設を推進した。ギルド内部は石工・鉄工・配管・電気・次元技術の五つの部門に分かれ、各部門が独自の技術体系と徒弟制度を持っていた。ギルドの技術遺産はテクノ文化ルネサンス期に再評価され、現代の建築工学にも影響を与えている。ギルドの初代親方とされるアルキテクト・ゼンは「都市は石でなく人で建てる」という言葉を残し、人材育成を最も重視した。",descriptionEn:"A professional guild of architects and laborers formed at the start of Gigapolis construction in E150. It oversaw the design and construction of iconic structures including Central Tower, organizing millions of workers to advance urban development. The guild was internally divided into five departments—masonry, ironworking, plumbing, electrical engineering, and dimensional technology—each with its own technical systems and apprenticeship programs. The guild's technological heritage was re-evaluated during the Techno-Cultural Renaissance, influencing modern architectural engineering. The guild's first master, Architect Zen, left the maxim 'Cities are built not of stone but of people,' emphasizing人才培养 above all."},{id:"org-E16大学連合",name:"E16大学学術連合",nameEn:"E16 University Consortium",category:"組織",subCategory:"学術機関",description:"惑星ビブリオのロレンツィオ国際大学を中心に、E16連星系内の主要な研究機関が加盟する学術ネットワーク。次元極地平技術の基礎研究と応用研究を統括し、ティムール・シャーの10次元ホラズム理論やペルセポネ計画の学術的検証を行った。連合には物理学部門のほか、宇宙生物学部門、次元情報科学部門、歴史・人類学部門があり、各部門が独立した研究プログラムを運営している。テクノ文化ルネサンス期には民間への研究成果の公開を推進し、次元極地平技術の民主化に貢献した。連合の最高学術賞は「ティムール・シャー・メダル」と呼ばれ、次元物理学の分野で最も権威ある賞とされている。",descriptionEn:"An academic network centered at the Lorenzo International University on planet Biblio, with major research institutions across the E16 star system joining as members. It coordinated fundamental and applied research in dimensional horizon technology, conducting academic verification of Timur Shah's 10-dimensional Khwarazm theory and the Persephone Project. The federation included departments of physics, astrobiology, dimensional information science, and history-anthropology, each operating independent research programs. During the Techno-Cultural Renaissance, it promoted public dissemination of research findings, contributing to the democratization of dimensional horizon technology. The federation's highest academic award, the 'Timur Shah Medal,' is considered the most prestigious honor in the field of dimensional physics."},{id:"org-クレセント国際法廷",name:"クレセント国際法廷",nameEn:"Crescent International Court",category:"組織",subCategory:"組織・制度",description:"クレセント7カ国間の紛争解決と国際法の解釈を担う司法機関。E320年のクレセント7カ国独立に伴い設立され、V7とトリニティ・アライアンスの対立の中で中立な裁定者として機能している。法廷は7カ国の法体系の調和を図りつつ、次元極地平技術の軍事利用やホライゾン・ゲートの管理に関する国際的な法規制の整備を進めている。法廷の判事は各国民の信任に基づき選出され、任期は5年である。アルファ・ヴェノムの犯罪行為に対する国際的な裁判もこの法廷の管轄であり、クレセント地方の平和維持における最重要機関として位置づけられている。",descriptionEn:"A judicial body responsible for resolving disputes among the Crescent Seven Nations and interpreting international law. Established following the independence of the Crescent Seven Nations in E320, it functions as a neutral arbiter in the conflict between V7 and the Trinity Alliance. While harmonizing the legal systems of the seven nations, the court has advanced international regulations concerning military applications of dimensional horizon technology and Horizon Gate management. Judges are elected based on the trust of their respective nations' populations, serving five-year terms. The international trial of Alpha Venom's criminal activities also falls under this court's jurisdiction, positioning it as the most critical institution for maintaining peace in the Crescent region."},{id:"org-次元境界監視機構",name:"次元境界監視機構",nameEn:"Dimension Boundary Watch",category:"組織",subCategory:"組織・制度",description:"E16連星系周辺の次元境界の安定性を監視する専門機関。銀河系コンソーシアムの下部組織として設立され、次元境界の歪みや不安定化の兆候を早期検知して警報を発する役割を担っている。監視機構は惑星ビブリオに本部を置き、E16連星系内の12の監視ステーションとディメンション・ブリッジ・ターミナルに配置されたセンサー網を通じて、次元境界の状態を24時間体制で監視している。監視データはグランベルのクアンタ・ラボとリアルタイムで共有され、次元境界の不安定化が大規模な災害に発展するのを未然に防ぐ重要な機能を果たしている。",descriptionEn:"A specialized agency monitoring the stability of dimensional boundaries around the E16 star system. Established as a subordinate organization of the Galactic Consortium, it detects early signs of dimensional boundary distortions or instabilities and issues warnings. The monitoring agency headquartered on planet Biblio operates a 24-hour surveillance system through a sensor network deployed across 12 monitoring stations and Dimension Bridge Terminals throughout the E16 star system. Monitoring data is shared in real-time with Quanta Lab in Grabel, performing a vital function in preventing large-scale disasters by preemptively addressing dimensional boundary instabilities."},{id:"org-E16放送協会",name:"E16放送協会",nameEn:"E16 Broadcasting Association",category:"組織",subCategory:"メディア",description:"E16連星系全域のニュース・情報配信を統括する公共放送機関。ZAMLT崩壊後に設立され、報道の自由と公正を原則としている。放送協会は次元間通信技術を活用したリアルタイムの全星系ニュース配信を行い、政治・経済・文化・科学の各分野で独立した報道を提供している。特にAURALISの活動や次元極地平技術の動向については詳細な専門番組を制作し、市民の技術リテラシー向上に寄与している。放送協会の編集権は独立的に保障されており、UECOや銀河系コンソーシアムからの圧力に屈しない姿勢を維持している。",descriptionEn:"A public broadcasting agency overseeing news and information distribution across the entire E16 star system. Established after the collapse of ZAMLT, it operates on the principles of press freedom and fairness. The broadcasting association utilizes interdimensional communication technology for real-time, system-wide news delivery, providing independent reporting across political, economic, cultural, and scientific fields. It produces detailed specialized programs on AURALIS activities and dimensional horizon technology developments, contributing to improving citizens' technological literacy. The association's editorial independence is guaranteed, maintaining its stance against pressure from UECO and the Galactic Consortium."},{id:"org-ギガポリス地下市場",name:"ギガポリス地下市場",nameEn:"Gigapolis Underground Market",category:"組織",subCategory:"地下組織",description:"Gigapolis地下街最深部を拠点とする非合法経済圏。Tina/Gueの実効支配下にあり、正規のnトークン経済には含まれない大規模な取引が行われている。地下市場では規制品の取引、非公認の技術取引、暗号通信サービスなどが提供され、ZAMLT期からエヴァトロン期を通じて継続的に運営されてきた。Tina/Gueの独自の情報ネットワークを通じて、表社会では得られない貴重な情報も流通している。地下市場の存在はUECOのガバナンスの限界を象徴するものであり、その取り込みはE16文明圏の政策課題の一つである。",descriptionEn:"An illegal economic zone headquartered in the deepest levels of Gigapolis's underground streets. Effectively controlled by Tina/Gue, it hosts large-scale transactions not included in the official n-token economy. The underground market offers trading in restricted items, unapproved technologies, and encrypted communication services, operating continuously from the ZAMLT through the Evatron eras. Through Tina/Gue's unique information network, valuable unavailable in mainstream society also circulates. The existence of the underground market symbolizes the limitations of UECO governance, and its integration remains one of the policy challenges for the E16 civilization sphere."},{id:"org-Eros-7採掘公社",name:"Eros-7エネルギー採掘公社",nameEn:"Eros-7 Energy Mining Corporation",category:"組織",subCategory:"その他",description:"Eros-7における搾取エネルギーの採掘と管理を統括する公社。マトリカル・カウンシルの監督下で運営され、リーチ・ドレインの培養・配置・エネルギー回収・配送の全工程を管理している。公社は多数の採掘施設を運営し、その中でもスクイーズ・アビスは最大規模の拠点として知られた。搾取体制の段階的解体に伴い、公社の規模は縮小しているが、現在でもエネルギー生産の一部を担っている。公社の技術スタッフが開発した搾取エネルギー変換技術の一部は、のちにナノメディシンに応用され、搾取技術の平和的転用の成功事例となっている。",descriptionEn:"A public corporation overseeing the extraction and management of extractive energy on Eros-7. Operated under the supervision of the Matrical Council, it manages the entire process of Reach Drain cultivation, deployment, energy recovery, and distribution. The corporation operates numerous extraction facilities, with Squeeze Abyss being known as its largest-scale base. With the progressive dismantling of the extractive system, the corporation has scaled down but still contributes to energy production. Part of the extractive energy conversion technology developed by the corporation's technical staff was later applied to nanomedicine, becoming a successful case study in the peaceful repurposing of extractive technology."},{id:"org-惑星間条約機構",name:"惑星間条約機構",nameEn:"Interplanetary Treaty Organization",category:"組織",subCategory:"組織・制度",description:"E16連星系内の惑星間関係を規律する条約とその運営機関。第一次星間戦争（E120〜E150年）の惨禍を受けて設立され、惑星間の武力紛争の防止と和平の維持を使命としている。条約機構は通商条約、不侵略条約、環境保全条約などの多国間条約の管理と、紛争時の仲介・調停を主要な業務としている。条約機構の最大の成果はE520年の第二次大戦終結後の包括的な和平条約の締結であり、これによりクレセント地方の恒久的な平和框架が確立された。現在では銀河系コンソーシアムの傘下で活動しており、その法務的専門性は宇宙規模の紛争解決に活用されている。",descriptionEn:"A treaty and its governing body regulating interplanetary relations within the E16 star system. Established in the aftermath of the First Interplanetary War (E120-E150), its mission is to prevent armed conflicts and maintain peace among planets. The treaty organization's primary functions include managing multilateral treaties such as trade agreements, non-aggression pacts, and environmental protection protocols, as well as mediating and调解 during disputes. The organization's greatest achievement was the comprehensive peace treaty following the end of the Second Great War in E520, which established a permanent peace framework for the Crescent region. Currently operating under the Galactic Consortium, its legal expertise is utilized for resolving conflicts on a galactic scale."},{id:"E16連星系",name:"E16連星系",nameEn:"E16 Binary System",category:"地理",subCategory:"宇宙・天文",description:"M104銀河（ソンブレロ銀河）のハロー領域に位置する連星系で、シンフォニー・オブ・スターズをはじめとする居住可能惑星を擁するE16文明圏の母星系である。主星Ea16はスペクトル型F5の黄白色巨星で、伴星Eb16はスペクトル型M3の赤色矮星であり、両星の軌道共鳴によって安定したハビタブルゾーンが形成されている。連星系全体の年齢は約62億年と推定され、豊富な重元素を含むため惑星形成が活発だった。E16連星系は東暦以前から航行可能な距離にあり、初期入植船団が到達して以来、銀河ハローにおける最重要の交通・交易拠点として発展を遂げてきた。",descriptionEn:"Located in the halo region of the M104 Galaxy (Sombrero Galaxy), this binary star system is the mother system of the E16 civilization zone, which harbors habitable planets including Symphony of Stars. The primary star Ea16 is a yellow-white giant of spectral type F5, while its companion Eb16 is a red dwarf of spectral type M3. The orbital resonance between the two stars creates a stable habitable zone. The estimated age of the binary system is approximately 6.2 billion years, and it contains abundant heavy elements, leading to active planet formation. The E16 binary system has been within navigable distance since before the Eastern Calendar, and since the arrival of the initial colonization fleet, it has developed into the most important transportation and trade hub in the galactic halo."},{id:"Ea16",name:"イーエー16",nameEn:"Ea16",category:"地理",subCategory:"宇宙・天文",description:"E16連星系の主星で、スペクトル型F5の黄白色巨星。質量は1.2太陽質量で、表面温度は約6,500K、光度は太陽の約3.2倍に達する。シンフォニー・オブ・スターズを含む内側惑星群に安定した光熱を供給しており、そのハビタブルゾーンは地球型惑星の居住に最適な条件を備えている。伴星Eb16との平均軌道間距離は約120AUで、両星の重力相互作用が連星系内の小天体軌道を安定化させている。東暦初期の天文学者たちはEa16の安定性を星系入植の決定的根拠とした。",descriptionEn:"The primary star of the E16 binary system, a yellow-white giant of spectral type F5. It has a mass of 1.2 solar masses, a surface temperature of approximately 6,500K, and a luminosity reaching about 3.2 times that of the Sun. It provides stable light and heat to the inner planets, including Symphony of Stars, with its habitable zone offering optimal conditions for Earth-type planets. The average orbital distance from its companion Eb16 is about 120 AU, and the gravitational interaction between the two stars stabilizes the orbits of small bodies within the system. Eastern Calendar-era astronomers considered the stability of Ea16 as the decisive basis for system colonization."},{id:"Eb16",name:"イービー16",nameEn:"Eb16",category:"地理",subCategory:"宇宙・天文",description:"E16連星系の伴星で、スペクトル型M3の赤色矮星。質量は0.4太陽質量、表面温度は約3,400Kであり、主星Ea16から平均約120AUの距離を公転している。Eb16自体のハビタブルゾーンは極めて狭いが、潮汐加熱を受ける可能性のある衛星系が存在すると推測されている。赤色矮星特有の長寿命（推定数千億年）により、主星が赤色巨星へ進化した後も連星系全体の重力バランスを維持する役割を果たすと予測されている。スライム危機期にはEb16の放射変動がリーチ・ドレインの遺伝子変異を誘発した可能性が指摘されている。",descriptionEn:"The companion star of the E16 binary system, a red dwarf of spectral type M3. It has a mass of 0.4 solar masses, a surface temperature of approximately 3,400K, and orbits at an average distance of about 120 AU from the primary star Ea16. While Eb16's own habitable zone is extremely narrow, it is theorized that satellite systems exist that may experience tidal heating. Due to the red dwarf's characteristic long lifespan (estimated at hundreds of billions of years), it is predicted to play a role in maintaining the gravitational balance of the entire binary system even after the primary star evolves into a red giant. During the Slime Crisis period, it has been suggested that radiation fluctuations from Eb16 may have induced genetic mutations in the Reach Drain."},{id:"シンフォニー・オブ・スターズ",name:"シンフォニー・オブ・スターズ",nameEn:"Symphony of Stars",category:"地理",subCategory:"宇宙・天文",description:"E16連星系の中心惑星で、主星Ea16のハビタブルゾーン内に位置する人類殖民の母星。自転周期は44時間4分、表面重力は0.92Gと地球よりやや軽く、住民の身体特性や建築様式に独自の進化をもたらした。惑星表面の約68%が水で覆われ、4つの大陸と多数の島嶼からなる。東暦元年に最初の入植船団が到達して以来、クレセント大地方をはじめとする各大陸に文明が興隆し、バーズ帝国からUECOに至る星系統治の歴史の舞台となった。惑星名「シンフォニー・オブ・スターズ」は、初期入植者が Ea16とEb16の連星の光が大気で屈折して放つ万華鏡のような夜空に因んで名付けた。",descriptionEn:"The central planet of the E16 binary system and the mother planet of human colonization, located within the habitable zone of the primary star Ea16. Its rotation period is 44 hours and 4 minutes, and its surface gravity is 0.92G, slightly lighter than Earth's, leading to unique evolutionary developments in the physical characteristics and architectural styles of its inhabitants. Approximately 68% of the planet's surface is covered by water, consisting of four continents and numerous islands. Since the arrival of the first colonization fleet in Eastern Calendar Year 1, civilizations have flourished across the continents, beginning with the Crescent Great Region, making it the stage for the history of system governance from the Birds Empire to UECO. The planet name \"Symphony of Stars\" was given by early settlers due to the kaleidoscopic night sky created by the refraction of light from the binary stars Ea16 and Eb16 in the atmosphere."},{id:"Eros-7",name:"エロス7",nameEn:"Eros-7",category:"地理",subCategory:"宇宙・天文",description:"E16連星系外縁に位置する第7惑星。表面重力は1.1Gとやや強く、薄い酸素大気を持つため地表での活動には呼吸補助装置が必要な区域が多い。独特な生態系を持ち、とりわけ性的エネルギーを吸収するリーチ・ドレインの原生地として知られ、この生物群の制御不能な増殖がE380年からのスライム危機を引き起こす端緒となった。女性主導のマトリカル社会が形成されており、政治・経済・軍事の主要ポストの大部分を女性が占める。この社会的構造はリーチ・ドレインの脅威への適応として発展した側面もあり、女性の身体特性がリーチ・ドレインに対する耐性に優れているという生態学的仮説も存在する。Eros-7の植民地は星系全体において独自の文化圏を形成し、特に生命倫理と生殖技術の分野で先進的な研究成果を生み出している。歴代指導者はリリス・ヴェイン（E0頃、リーチ・ドレイン制御技術開発）に始まり、シルヴィア・クロウ（E97〜E101、リーチ・ドレイン危機収束・男性指令省設立）が続いた。その後、マトリカル・カウンシルによる集団指導体制が評議会運営を担い、E525年のマトリカル・リフォーム運動ではアヤカ・リン、ガロ、ゼナが改革を主導した。\nこのEros-7の根底には、倫理の解除(D4)と脱人間化(D5)の思想的地層が横たわっている。生命倫理の極限実験場としてのEros-7は、既存の道徳的禁忌を突破した研究が行われたD4の実践的現場である。リーチ・ドレインなどの新種の創造は、「人間の形にこだわらない」というD5の思想を生物学的領域に拡張した結果であり、人権の定義を根本から問い直す倫理的境界線となっている。",descriptionEn:"The seventh planet located in the outer reaches of the E16 binary system. Its surface gravity is 1.1G, somewhat stronger than Earth's, and it has a thin oxygen atmosphere, requiring respiratory assistance in many surface areas. It possesses a unique ecosystem and is known as the native habitat of the Reach Drain, which absorbs sexual energy. The uncontrolled proliferation of this organism triggered the Slime Crisis starting in E380. A matriarchal society has formed where women occupy most of the key positions in politics, economy, and military. This social structure developed partly as an adaptation to the Reach Drain threat, and there exists an ecological hypothesis that women's physical characteristics provide superior resistance to the Reach Drain. The Eros-7 colony has formed its own cultural zone within the system, particularly producing advanced research in the fields of bioethics and reproductive technology. Its successive leaders began with Lilith Vane (around E0, developer of Reach Drain control technology), followed by Sylvia Crow (E97-E101, who managed the Reach Drain crisis and established the Male Directive Office). Subsequently, a collective leadership system under the Matriarchal Council took over the administration of the council, and in the Matriarchal Reform Movement of E525, Ayaka Rin, Gallo, and Zena led the reforms.",leaders:[{id:"リリス・ヴェイン",name:"リリス・ヴェイン",nameEn:"Lilith Vaine",role:"Eros-7初期女性リーダー",era:"E0頃"},{id:"シルヴィア・クロウ",name:"シルヴィア・クロウ",nameEn:"Sylvia Crow",role:"Eros-7女性リーダー",era:"E97〜E101"},{id:"カーラ・ヴェルム",name:"カーラ・ヴェルム",nameEn:"Cara Verm",role:"スクイーズ・アビス立案者",era:"E380〜E505"}]},{id:"惑星ビブリオ",name:"惑星ビブリオ",nameEn:"Planet Biblio",category:"地理",subCategory:"宇宙・天文",description:"E16連星系内に位置する学術都市惑星で、星系最高の知的水準を誇る研究拠点である。惑星全体が学術機関と研究施設によって構成され、中でもロレンツィオ国際大学は次元極地平理論やApolonium物理学の研究拠点として名高い。惑星ビブリオにはA-Registryの最高等級記録館も置かれており、E16文明圏の全歴史文書と市民データのバックアップが保管されている。テクノ文化ルネサンス期には、ペルセポネ計画の理論的基盤がこの惑星の研究者たちによって構築された。常時数万人の研究者と学生が居住し、学術の自由と知識の共有を最高理念として掲げる特別自治区として運営されている。",descriptionEn:"An academic city planet located within the E16 binary system, boasting the highest intellectual level in the system as a research hub. The entire planet is composed of academic institutions and research facilities, among which the Lorenz International University is renowned as a research center for dimensional pole theory and Apolonon physics. The planet Biblio also houses the highest-level archive of the A-Registry, where all historical documents and citizen data of the E16 civilization zone are backed up. During the Techno-Cultural Renaissance period, the theoretical foundation of the Persephone Project was constructed by researchers on this planet. It is constantly inhabited by tens of thousands of researchers and students and operates as a special autonomous region that upholds academic freedom and knowledge sharing as its highest ideals."},{id:"惑星Solaris",name:"惑星Solaris",nameEn:"Planet Solaris",category:"地理",subCategory:"宇宙・天文",description:"Ninny Offenbachの原初個体が離脱した惑星として知られる。Offenbach種の集団意識が最初に自律的な個体を生み出した場所であり、個と集合体の分岐点としてE16文明圏の哲学・倫理学において極めて重要な意義を持つ。惑星自体は寒冷な岩石惑星で、地表の大部分が氷結したメタンと窒素の平原に覆われているが、地下深部にはOffenbach種の生態系を支える熱源が存在する。Solarisの名称は、原初個体が集団意識から離脱する際に放った光エネルギーの放出現象に由来する。この惑星の研究はOffenbach種の社会構造理解に不可欠であり、AURALIS第二世代の設立理念にも影響を与えた。",descriptionEn:"Known as the planet from which the original Ninny Offenbach individual departed. This is where the collective consciousness of the Offenbach species first produced an autonomous individual, serving as a branching point between the individual and the collective, holding extremely significant meaning in the philosophy and ethics of the E16 civilization zone. The planet itself is a cold rocky world, with most of its surface covered by frozen plains of methane and nitrogen, but deep underground exists a heat source that supports the Offenbach species' ecosystem. The name Solaris originates from the phenomenon of light energy emission when the original individual departed from the collective consciousness. Research on this planet is essential for understanding the social structure of the Offenbach species and has also influenced the founding philosophy of the AURALIS second generation."},{id:"M104銀河",name:"M104銀河",nameEn:"M104 Galaxy",category:"地理",subCategory:"宇宙・天文",description:"M104銀河（ソンブレロ銀河）は、地球から約3,100万光年の距離に位置する棒渦巻銀河である。E16連星系はこの銀河のハロー領域外縁に位置し、銀河中心部の活発な星形成領域からは遠く離れた穏やかな環境にある。ソンブレロ銀河の名称は、地球側からの観測で銀河の塵の帯がメキシコのソンブレロ帽に似ていることに由来するが、E16連星系側から見た銀河の形状は全く異なる。銀河ハロー領域に位置するため、E16連星系は銀河中心の強烈な放射線から保護されており、文明の発展に適した環境を提供している。M104銀河内には他にも入植可能な星系が複数確認されているが、E16連星系の戦略的重要性と歴史的経緯から、他領域の本格的開発はUECO統合後まで遅れた。",descriptionEn:"The M104 Galaxy (Sombrero Galaxy) is a barred spiral galaxy located approximately 31 million light-years from Earth. The E16 binary system is located on the outer edge of this galaxy's halo region, in a calm environment far from the active star-forming regions of the galactic center. The name Sombrero Galaxy comes from the resemblance of the galaxy's dust band to a Mexican sombrero when viewed from Earth, but the galaxy's appearance is completely different when viewed from the E16 binary system. Due to its position in the galactic halo, the E16 binary system is protected from the intense radiation of the galactic center, providing an environment suitable for the development of civilization. Several other habitable star systems have been confirmed within the M104 Galaxy, but due to the strategic importance and historical background of the E16 binary system, the full-scale development of other regions was delayed until after UECO integration."},{id:"ノスタルジア・コロニー",name:"ノスタルジア・コロニー",nameEn:"Nostalgia Colony",category:"地理",subCategory:"宇宙・天文",description:"E16連星系外縁に建設された初期植民地の一つで、ミナ・エウレカの出生地として知られる。ノスタルジア・コロニーはE300年頃に建設され、初期入植者たちが地球の生活様式を懐かしみながら維持しようとしたことからこの名が付けられた。コロニーの建築様式や社会制度は地球の20世紀末〜21世紀初頭の文化を模倣しており、他の植民地とは異なるレトロな景観を持つ。E509年にアルファ・ヴェノムの急襲を受け、大規模な破壊と住民の犠牲を出した。この襲撃はミナ・エウレカの人生を決定的に変え、後に彼女がGenesis Vaultを通じて反ヴェノム活動の情報発信を行う動機となった。現在コロニーの一部は復興しているが、襲撃の痕跡は記念施設として保存されている。",descriptionEn:"One of the early colonies constructed on the outer rim of the E16 star system, known as the birthplace of Mina Eureka. The Nostalgia Colony was established around E300, named so because early settlers attempted to maintain Earth's lifestyle while reminiscing about it. The colony's architectural style and social system mimic the culture of late 20th to early 21st century Earth, giving it a retroscopic landscape distinct from other colonies. In E509, it was attacked by Alpha Venom, resulting in massive destruction and civilian casualties. This attack decisively changed Mina Eureka's life and later became her motivation to disseminate anti-Venom activities through the Genesis Vault. While parts of the colony have been rebuilt, traces of the attack are preserved as memorial facilities."},{id:"クレセント大地方",name:"クレセント大地方",nameEn:"Crescent Region",category:"地理",subCategory:"クレセント地方",description:"シンフォニー・オブ・スターズの東大陸に位置する広大な地域で、E16連星系における政治・経済・軍事の最重要拠点の一つである。クレセント大地方にはヴァーミリオン、ブルーローズ、ミエルテンガ、クロセヴィア、SSレンジ、アイアン・シンジケート、SUDOM、ファティマ連邦、スターク三国など、複数の国家と勢力が混在しており、複雑な国際関係を形成している。地名は大陸の三日月のような弧状の地形に由来する。東暦初期の入植以来、豊かな資源と戦略的な位置により争奪の的となってきた歴史を持つ。テクノ文化ルネサンス期以降、ホライゾン・ゲートによる他地域との交通が整備されたことで経済的重要性はさらに増大し、V7やトリニティ・アライアンスなどの軍事同盟の舞台となっている。クレセント大地方の国家間の緊張と協力のバランスは、E16連星系全体の安定に直結すると言われている。",descriptionEn:"A vast region located on the eastern continent of the Symphony of Stars, serving as one of the most important political, economic, and military hubs in the E16 star system. The Crescent Greatlands is a complex mix of nations and powers including Vermilion, Blue Rose, Miertenga, Crosevia, SS Range, Iron Syndicate, SUDOM, Fatima Federation, and Stark Triumvirate, forming intricate international relations. The name derives from the crescent-moon-like arc of the continent's terrain. Since early colonization in the Eastern calendar, its history has been marked by conflict due to rich resources and strategic positioning. Following the Techno-Cultural Renaissance, the development of transportation through Horizon Gates further increased its economic importance, making it a stage for military alliances like V7 and the Trinity Alliance. The balance of tension and cooperation among the Crescent Greatlands nations is said to directly affect the stability of the entire E16 star system."},{id:"ヴァーミリオン",name:"ヴァーミリオン",nameEn:"Vermillion",category:"地理",subCategory:"クレセント地方",description:"ドミニオン・ヴァーミリオンとして知られるクレセント大地方の有力国家で、アイリスの母国である。歴史的にセリア黄金期の文化的遺産を色濃く受け継いでおり、フェルミ音楽の伝統的な演奏形式やAURALISの哲学を国家の文化的基盤としている。ヴァーミリオンは豊かな鉱物資源と農業生産力を背景に経済的な繁栄を誇り、クレセント地方における旧来の秩序を代表する存在である。しかしエヴァトロンの介入による支配時代を経て、国家のアイデンティティと主権回復をめぐる葛藤が続いている。トリニティ・アライアンスの結成メンバーとして軍事的にも重要な役割を果たしており、クレセント地方の地政学的均衡の要として機能している。赤色を基調とした国旗と国家建築は、ヴァーミリオン（朱色）の名に由来する。",descriptionEn:"A powerful nation of the Crescent Greatlands known as the Dominion of Vermilion, and the motherland of Iris. It has historically inherited the cultural heritage of the Celia Golden Age, with traditional Fermi music performance forms and AURALIS philosophy forming the nation's cultural foundation. Vermilion boasts economic prosperity backed by rich mineral resources and agricultural productivity, representing the established order of the Crescent region. However, after an era of domination by Evatron, the nation continues to grapple with conflicts over national identity and sovereignty recovery. As a founding member of the Trinity Alliance, it plays a crucial military role and functions as a key to the geopolitical balance of the Crescent region. The nation's red-themed flag and architecture derive from its name, Vermilion (cinnabar red).",leaders:[{id:"アザゼル",name:"アザゼル・ヘクトパス",nameEn:"Azazel Hectopass",role:"ヴァーミリオン元首脳",era:"?〜E480頃"}]},{id:"ブルーローズ",name:"ブルーローズ",nameEn:"Blue Rose",category:"地理",subCategory:"クレセント地方",description:"フィオナが統率するクレセント地方の国家で、V7（Vital Seven）連合の中心的な役割を果たしている。ブルーローズはテクノ文化ルネサンス期の理念を最も純粋に受け継いだ国家と評され、次元極地平技術の研究開発と文化的な開放性を国家的特色としている。フィオナのリーダーシップの下、V7の設立（E515年）を主導し、クレセント地方の7カ国連合の枠組みを構築した。国家名はブルーローズ（青い薔薇）に由来し、不可能とされていた空間技術の民用化を実現した象徴としてこの名が選ばれた。多国籍の研究者や芸術家を受け入れる開放的な政策により、クレセント地方における文化・技術のハブとして機能している。アルファ・ヴェノムやシルバー・ヴェノムの脅威に対してはV7を通じて集団防衛の姿勢をとっている。",descriptionEn:"A nation in the Crescent region led by Fiona, serving as the central role in the V7 (Vital Seven) coalition. Blue Rose is regarded as the nation that most purely inherits the ideals of the Techno-Cultural Renaissance period, with dimensional horizon technology research and cultural openness as its national characteristics. Under Fiona's leadership, she spearheaded the establishment of V7 (E515) and constructed the framework for the seven-nation alliance in the Crescent region. The nation's name derives from Blue Rose, chosen as a symbol for achieving the civilian application of space technology, once considered impossible. With its open policy accepting multinational researchers and artists, it functions as a cultural and technological hub in the Crescent region. Against threats from Alpha and Silver Venom, it maintains a collective defense posture through V7.",leaders:[{id:"フィオナ",name:"フィオナ",nameEn:"Klaus Fiona",role:"ブルーローズ統率者",era:"E490〜"}]},{id:"ミエルテンガ",name:"ミエルテンガ",nameEn:"Mielteunga",category:"地理",subCategory:"クレセント地方",description:"マリーナ・ボビンが総統を務めるクレセント地方の国家で、軍事力と産業基盤に強みを持つ。ミエルテンガはスライム危機後の復興期に急速に発展し、リーチ・ドレイン対策のために構築された生物工学産業が国家経済の中核となっている。マリーナ・ボビンの強力なリーダーシップの下、国家全体が効率的な統治体制を築き上げ、クレセント地方における軍事的影響力を拡大してきた。トリニティ・アライアンスの結成メンバーとしてヴァーミリオンやボグダス・ジャベリンと軍事同盟を結んでおり、V7に対抗する勢力の中心として機能している。ミエルテンガの軍事技術はEros-7のマトリカル社会が開発した生物学的技術を応用した独自のもので、他国には公開されていない機密が多い。国家の名前は古い入植者の母語に由来すると言われるが、詳細は不明である。",descriptionEn:"A nation in the Crescent region led by Supreme Marina Bobin, with strengths in military power and industrial base. Miertenga developed rapidly during the recovery period after the Slime Crisis, with biotechnology industries established to counter Reach Drain becoming the core of the national economy. Under Marina Bobin's strong leadership, the nation has built an efficient governance system and expanded its military influence in the Crescent region. As a founding member of the Trinity Alliance, it has formed military alliances with Vermilion and Bogdas Javelin, functioning as the center of forces opposing V7. Miertenga's military technology is a unique application of biological technology developed by the Matriscal society of Eros-7, with many undisclosed secrets not shared with other nations. The nation's name is said to derive from the ancient language of early settlers, though details remain unknown.",leaders:[{id:"マリーナ・ボビン",name:"マリーナ・ボビン",nameEn:"Marina Bobbin",role:"ミエルテンガ総統",era:"E515〜"}]},{id:"クロセヴィア",name:"クロセヴィア",nameEn:"Crosevia",category:"地理",subCategory:"クレセント地方",description:"カスチーナ・テンペストが首脳を務めるクレセント地方の国家で、気象制御技術と環境工学に特化した先進的な国家である。クロセヴィアはシンフォニー・オブ・スターズ特有の複雑な気象システムを制御する技術を長年研究してきており、この技術は農業生産の安定化や自然災害の防止に大きく貢献している。カスチーナ・テンペストは「テンペスト（嵐）」の名にふさわしく、気象操作を戦略的資源として活用する外交手腕で知られる。クロセヴィアはV7の加盟国でありながら、トリニティ・アライアンスとの関係構築にも努めるなど、柔軟な外交姿勢を維持している。国家の主要輸出品には気象制御装置と環境モニタリングシステムがあり、E16連星系内の他の植民地にも広く輸出されている。",descriptionEn:'An advanced nation in the Crescent region led by Castina Tempest, specializing in weather control technology and environmental engineering. Crosevia has long researched technology to control the complex weather systems unique to the Symphony of Stars, which greatly contributes to stabilizing agricultural production and preventing natural disasters. True to her name "Tempest," Castina Tempest is known for her diplomatic skill that utilizes weather manipulation as a strategic resource. While a member of V7, Crosevia also strives to build relations with the Trinity Alliance, maintaining a flexible diplomatic stance. The nation\'s main exports include weather control devices and environmental monitoring systems, widely exported to other colonies in the E16 star system.',leaders:[{id:"カスチーナ・テンペスト",name:"カスチーナ・テンペスト",nameEn:"Castina Tempest",role:"クロセヴィア首脳",era:"E515〜"}]},{id:"SSレンジ",name:"SSレンジ",nameEn:"SS Range",category:"地理",subCategory:"クレセント地方",description:"アイク・ロペスが首脳を務めるクレセント地方の国家で、情報通信技術とサイバーセキュリティ分野においてE16連星系随一の技術力を誇る。SSレンジ（Super Signal Range）の名称は、同国が開発した超長距離量子通信システムに由来し、この技術はE16連星系内の全惑星間通信インフラの基盤となっている。アイク・ロペスは元情報技術者であり、国家経営にもデータ駆動型の手法を導入して行政効率の最大化を図っている。SSレンジはV7の加盟国で、主に情報戦と通信インフラの防衛を担当している。ホライゾン・ゲートの安定化制御にもSSレンジの通信技術が不可欠であり、テクノ文化ルネサンス期の技術開放政策を技術面から支えた立役者でもある。国家の人口は比較的少ないが、高密度な都市部に知的労働者が集中する独特の社会構造を持つ。",descriptionEn:"A nation in the Crescent region led by Chief Ike Lopez, boasting the most advanced information technology and cybersecurity capabilities in the E16 star system. The name SS Range (Super Signal Range) derives from the ultra-long-range quantum communication system developed by the nation, which forms the basis of all interplanetary communication infrastructure in the E16 star system. An information technologist by background, Ike Lopez has introduced data-driven methods into national administration to maximize efficiency. SS Range is a member of V7, primarily responsible for information warfare and defense of communication infrastructure. SS Range's communication technology is indispensable for stabilizing Horizon Gates, making it a key supporter of the technological openness policy of the Techno-Cultural Renaissance period. While the nation's population is relatively small, it has a unique social structure with knowledge workers concentrated in high-density urban areas.",leaders:[{id:"アイク・ロペス",name:"アイク・ロペス",nameEn:"Ike Lopez",role:"SSレンジ首脳",era:"E515〜"}]},{id:"アイアン・シンジケート",name:"アイアン・シンジケート",nameEn:"Iron Syndicate",category:"地理",subCategory:"クレセント地方",description:"レイド・カキザキが首脳を務めるクレセント地方の国家で、重工業と資源採掘を基盤とする強力な経済国家である。アイアン・シンジケート（鉄のシンジケート）の名称通り、国家経済の大部分を金属資源の採掘・精錬・加工産業が占めており、シンフォニー・オブ・スターズの建設資材の大部分を供給している。レイド・カキザキは実業家出身の首脳で、企業家的な手法で国家を統治し、他国との貿易を通じて経済的影響力を拡大している。アイアン・シンジケートはV7の加盟国であり、軍事装備の製造も担うことから防衛面でも重要な役割を果たしている。国家の工業地帯は昼夜を問わず稼働し、特徴的な赤い煙を上げる精錬所の風景はクレセント地方の象徴的な光景の一つとなっている。環境問題に対する批判も存在するが、近年はテクノ文化ルネサンス期の技術を応用したクリーン生産への転換が進められている。",descriptionEn:"A nation in the Crescent region led by Chief Raid Kizaki, a powerful economic nation based on heavy industry and resource extraction. True to its name, the Iron Syndicate, the majority of its national economy consists of mining, refining, and processing metal resources, supplying most of the construction materials for the Symphony of Stars. Raid Kizaki, a business leader by background, governs the nation with corporate methods, expanding economic influence through trade with other nations. As a member of V7, the Iron Syndicate also manufactures military equipment, playing an important role in defense. The nation's industrial zones operate day and night, with the sight of refineries emitting characteristic red smoke becoming one of the iconic landscapes of the Crescent region. While facing criticism for environmental issues, recent years have seen a shift toward clean production applying technologies from the Techno-Cultural Renaissance period.",leaders:[{id:"レイド・カキザキ",name:"レイド・カキザキ",nameEn:"Raid Kakizaki",role:"アイアン・シンジケート首脳",era:"E515〜"}]},{id:"SUDOM",name:"スードム",nameEn:"SUDOM",category:"地理",subCategory:"クレセント地方",description:"クレセント大地方に位置する国家で、独自の文化的アイデンティティと高度な医療技術で知られる。SUDOMは東暦初期の入植計画において、特定の医療研究目的で設立された特別植民地を起源に持つ。この歴史的経緯から、国家は遺伝子医療、再生医療、神経科学の分野でE16文明圏の最先端を走っており、特にスライム危機以降のリーチ・ドレイン対策医療において多大な貢献を果たした。SUDOMはV7の加盟国であり、同盟の医療支援と疫学調査を担当している。またnトークン経済において、医療サービスの提供が高く評価される仕組みを確立しており、他国の医療制度にも影響を与えている。国家名の由来は入植初期の研究コードに基づくと言われるが、公式な語源は明らかにされていない。",descriptionEn:"A nation located in the Crescent Great Region, known for its unique cultural identity and advanced medical technology. SUDOM traces its origins to a special colony established during the early Eastern Calendar colonization project for specific medical research purposes. Due to this historical background, the nation leads the E16 civilization in the fields of genetic medicine, regenerative medicine, and neuroscience, making significant contributions particularly in Reach Drain countermeasures after the Slime Crisis. SUDOM is a member of V7 and is responsible for the alliance's medical support and epidemiological investigations. Additionally, it has established a highly valued system for providing medical services in the n-token economy, influencing the healthcare systems of other countries. The origin of the nation's name is said to be based on a research code from the early colonization period, though the official etymology has not been disclosed.",leaders:[{id:"セルヴァ・ドーン",name:"セルヴァ・ドーン",nameEn:"Selva Dawn",role:"SUDOM初代医療総裁",era:"E480〜"}]},{id:"ファティマ連邦",name:"ファティマ連邦",nameEn:"Fatima Federation",category:"地理",subCategory:"クレセント地方",description:"クレセント大地方に位置する連邦制国家で、複数の自治州が緩やかな連合を形成している。ファティマ連邦は宗教的・哲学的自由を重んじる文化で知られ、E16文明圏における多元的な思想交流の拠点として機能している。連邦を構成する各自治州は独自の法体系と教育制度を持ち、連邦政府は外交と防衛のみを管轄する最小限の統治構造を採用している。この分散型の統治モデルはネオクラン同盟の理念と共鳴し、ファティマ連邦は同盟の熱心な支持者である。また、フェルミ音楽の精神論的な側面を深く研究する学派があり、AURALISのメンバーも多数輩出している。ファティマ連邦はV7には加盟していないが、非同盟中立の立場を取りながらもクレセント地方の平和維持に積極的に関与している。",descriptionEn:"A federal nation located in the Crescent Great Region, composed of multiple autonomous states forming a loose federation. The Fatima Federation is known for its culture that values religious and philosophical freedom, serving as a hub for diverse intellectual exchange within the E16 civilization. Each autonomous state comprising the federation has its own legal system and education system, while the federal government adopts a minimal governance structure overseeing only foreign affairs and defense. This decentralized governance model resonates with the ideals of the Neo-Clan Alliance, and the Fatima Federation is a staunch supporter of the alliance. Additionally, it has a school of thought that deeply studies the spiritual aspects of Fermi music, and has produced many members of AURALIS. While not a member of V7, the Fatima Federation maintains a non-aligned neutral stance while actively participating in maintaining peace in the Crescent region.",leaders:[{id:"ハシーム・ファティマ",name:"ハシーム・ファティマ",nameEn:"Hashim Fatima",role:"ファティマ連邦初代連邦議長",era:"E400〜"}]},{id:"スターク三国",name:"スターク三国",nameEn:"Stark Triad Nations",category:"地理",subCategory:"クレセント地方",description:"クレセント大地方の北部に位置する三つの国家からなる国家群で、歴史的に強固な相互防衛同盟を維持している。スターク三国の名称は「厳格な（stark）」外交姿勢に由来し、他の勢力への依存を避け、自立的な安全保障体制を維持することを国家理念としている。三国はそれぞれ軍事、経済、外交に特化しており、相互補完的な関係で連合の強靭性を確保している。V7やトリニティ・アライアンスのいずれにも属さない独自の立場を維持し、クレセント地方における第三勢力としての役割を果たしている。スターク三国の軍事力は質量ともに高く評価されており、その中立的な立場からクレセント地方の紛争調停において重要な役割を担うことが多い。東暦初期のバーズ帝国崩壊後に三国の原型が形成され、長い歴史の中で独特の連合文化を育んできた。",descriptionEn:'A cluster of three nations located in the northern part of the Crescent Great Region, historically maintaining a strong mutual defense alliance. The name "Stark Triumvirate" derives from its "stark" diplomatic posture, with the national philosophy of avoiding dependence on other powers and maintaining an independent security system. The three nations specialize respectively in military, economic, and affairs, ensuring the resilience of their alliance through complementary relationships. They maintain their own independent position, belonging to neither V7 nor the Trinity Alliance, serving as a third force in the Crescent region. The military power of the Stark Triumvirate is highly regarded in both quality and quantity, and due to its neutral stance, it often plays an important role in mediating conflicts in the Crescent region. The prototype of the three nations was formed after the collapse of the Bartz Empire in the early Eastern Calendar, and over a long history, they have developed a unique alliance culture.',leaders:[{id:"トリスタン・スターク",name:"トリスタン・スターク",nameEn:"Tristan Stark",role:"スターク三国軍事理事長",era:"E480〜"}]},{id:"ネオンコロシアム",name:"ネオンコロシアム",nameEn:"Neon Colosseum",category:"地理",subCategory:"その他",description:"Gigapolis最大の闘技場であり、シンフォニー・オブ・スターズ西大陸における最大級のエンターテインメント施設。年間を通じてスティル・アレーナが開催され、世界中から参加者が集まる。闘技場のネオン照明が夜間に輝く姿はGigapolisのシンボル的一景として広く知られ、文化イベントや音楽フェスティバルの会場としても機能する。観客席は最大50万人を収容可能で、次元ホログラム技術による臨場感のある中継システムを完備。",descriptionEn:"Gigapolis's largest arena and one of the largest entertainment facilities in the Symphony of Stars Western Continent. The Still Arena is held throughout the year, attracting participants from all over the world. The neon lights of the arena shining at night are widely known as a symbolic sight of Gigapolis, and it also functions as a venue for cultural events and music festivals. The spectator stands can accommodate up to 500,000 people and are equipped with an immersive broadcasting system using dimensional hologram technology."},{id:"Abrivo",name:"アブリーヴォ",nameEn:"Abrivo",category:"地理",subCategory:"西大陸都市",description:"Gigapolis圏の交易都市。シンフォニー・オブ・スターズ西大陸の物流ハブとして機能し、各地からの原材料と製品を中継する活気ある港湾都市。エル・フォルハウスのマーストリヒト革命後は自由貿易の拠点として発展した。",descriptionEn:"A trading city in the Gigapolis sphere. It functions as a logistics hub for the Symphony of Stars Western Continent, a vibrant port city that relays raw materials and products from various regions. After the Maastricht Revolution in El Forlhaus, it developed as a center for free trade."},{id:"Ronve",name:"ロンヴ",nameEn:"Ronve",category:"地理",subCategory:"西大陸都市",description:"Gigapolis圏の城塞都市。西大陸の北部に位置し、ロンバルディア戦争（E88〜E98年）の際には前線基地として機能した堅固な防衛都市。現在でも要塞跡と軍事博物館が残り、テクロサス系譜の軍事伝統を伝える。",descriptionEn:"A fortress city in the Gigapolis sphere. Located in the northern part of the Western Continent, it was a solid defensive city that functioned as a front-line base during the Lombardia War (E88-E98). Today, fortress ruins and a military museum remain, preserving the military tradition of the Teclosus lineage."},{id:"Lille",name:"リール",nameEn:"Lille",category:"地理",subCategory:"西大陸都市",description:"Gigapolis圏の通信・情報都市。西大陸の通信ネットワークの中継拠点として機能し、次元極地平技術の民生利用の試験地としても知られる。テクノ文化ルネサンス（E475〜E500）以降は新しいメディア産業の拠点として急成長している。",descriptionEn:"A communications and information city in the Gigapolis sphere. It functions as a relay point for the Western Continent's communication network and is also known as a testing ground for civilian use of dimensional horizon technology. Since the Techno Cultural Renaissance (E475-E500), it has grown rapidly as a center for the new media industry."},{id:"Valoria",name:"ヴァロリア",nameEn:"Valoria",category:"地理",subCategory:"西大陸都市",description:"Gigapolis圏南部の戦略的要衝に位置する都市。壮麗なValoria宮殿を擁し、E319年にLv938+の実力者Jenがこの宮殿を掌握して以降、彼女を中心とするValoria連合圏の中核拠点として機能している。ZAMLT崩壊後の権力真空期にJenが西大陸の安定を確立した拠点でもあり、現在でも新ZAMLT期における主要な政治・軍事拠点として重要な役割を果たす。宮殿の地下には古代の次元兵器遺構が眠ると伝えられている。",descriptionEn:"A city located at a strategic crossroads in southern Gigapolis. It boasts the magnificent Valoria Palace, and since E319 when the Lv938+ powerhouse Jen took control of this palace, it has functioned as the core base of the Valoria Alliance centered around her. It was also a base where Jen established stability in the Western Continent during the power vacuum after the collapse of ZAMLT, and it still plays an important role as a major political and military base in the new ZAMLT era. It is said that ancient dimensional weapon ruins sleep beneath the palace."},{id:"Persepolis",name:"ペルセポリス",nameEn:"Persepolis",category:"地理",subCategory:"西大陸都市",description:"Gigapolis圏の宇宙港都市。西大陸最大の宇宙港を擁し、惑星間交易と移民の中継地として機能する。ティムール・シャーの移民団が最初に到着した地の一つであり、異星文化の融合が進む国際色豊かな都市。",descriptionEn:"A spaceport city in the Gigapolis sphere. It boasts the largest spaceport on the Western Continent and functions as a relay point for interplanetary trade and immigration. It was one of the first places reached by Timur Shah's immigrant group, making it an internationally rich city where alien cultures continue to blend."},{id:"Selinopolis（西大陸都市）",name:"セリノポリス",nameEn:"Selinopolis",category:"地理",subCategory:"西大陸都市",description:"Gigapolisの旧称の一つ。セリア・ドミニクスがZAMLTを打倒し、Gigapolisを掌握した後にSelinopolisと改名した。セリアは超巨大企業Phovosを設立して次元エネルギー技術の商業化を推進し、都市をGDP25兆ドル規模に急成長させた。しかしアポロン・Dominion大戦後、エヴァトロンに吸収されセリアは追放された。現在はGigapolisの名称に戻っているが、歴史的経緯から「Selinopolis（ドミニオン）」として別項目でも詳述される。詳細は用語「Selinopolis（ドミニオン）」を参照。",descriptionEn:'One of the former names of Gigapolis. After Celia Dominicus overthrew ZAMLT and took control of Gigapolis, she renamed it Selinopolis. Celia established the hyper-megacorporation Phovos to commercialize dimensional energy technology, rapidly growing the city to a GDP of 25 trillion dollars. However, after the Apollo-Dominion War, it was absorbed by Evatron and Celia was exiled. Although it has since reverted to the name Gigapolis, due to its historical significance, it is also detailed as a separate entry under "Selinopolis (Dominion)." For details, refer to the term "Selinopolis (Dominion)."'},{id:"エヴァポリス",name:"エヴァポリス",nameEn:"Evapolis",category:"地理",subCategory:"西大陸都市",description:"Gigapolisのエヴァトロン支配時代（E400〜E475年）における強制的な改名都市名。エヴァトロンが自らの権威を都市の名称に刻印する意図で改名を実施したが、市民の間では古き良きGigapolisの名で呼び続ける抵抗運動が根強く存在した。E475年のエヴァトロン崩壊後、市民の総意により即座にGigapolisの名称が復帰。この改名と復帰の歴史は、都市の自治と市民の尊厳を取り戻した象徴的出来事として現在でも語り継がれ、毎年復帰記念日が祝われている。",descriptionEn:"The forced renaming of Gigapolis during the Evatron domination era (E400-E475). Evatron renamed the city to imprint its own authority upon its name, but a strong resistance movement continued to call it the beloved name of Gigapolis among the citizens. After the collapse of Evatron in E475, the name Gigapolis was immediately restored by popular will. This history of renaming and restoration is still told today as a symbolic event of the city's regained autonomy and citizens' dignity, and the Restoration Anniversary is celebrated every year."},{id:"パラトン",name:"パラトン",nameEn:"Palaton",category:"地理",subCategory:"西大陸都市",description:"E6年に形成されたシンフォニー・オブ・スターズ西大陸における最初期の都市圏であり、現在のGigapolis圏の直接的な原型。地球からの移民集団が到着した直後に建設され、当初は数千人の小規模な居住区に過ぎなかった。しかし技術啓蒙時代に人口が爆発的に増加し、周辺都市と統合してメガロポリスへと成長。パラトンの城壁遺構の一部は現在でもGigapolis歴史地区に保存され、西大陸文明の起原を示す重要な文化財として指定されている。",descriptionEn:"The earliest urban area in the Symphony of Stars on the Western Continent, formed in E6, and the direct prototype of the current Gigapolis sphere. It was constructed immediately after the arrival of immigrant groups from Earth, initially a small residential area of only a few thousand people. However, during the Age of Enlightenment, the population exploded, and it grew into a megalopolis through integration with surrounding cities. Part of the Paraton wall ruins is still preserved in the Gigapolis historical district and designated as an important cultural asset marking the origin of Western Continent civilization."},{id:"地下街",name:"地下街",nameEn:"Underground City",category:"地理",subCategory:"西大陸都市",description:"Gigapolisの地下深くに広がる複雑な地下構造体であり、複数の階層からなる独自の都市空間を形成している。上層部は商業施設と倉庫、中層部はインフラ設備と旧居住区が配置され、最深部はTina/Gueが実効支配する独自の統治領域となっている。アンダーグリッドとも接続しており、スライム危機時には巨大なスライムの巣が形成されるなど、表の都市とは全く異なる生態系が存在する。最深部の正確な構造は未だ完全には解明されていない。",descriptionEn:"A complex underground structure extending deep beneath Gigapolis, forming a unique urban space with multiple levels. The upper levels house commercial facilities and warehouses, the middle levels contain infrastructure and old residential areas, and the deepest level forms a self-governing territory effectively controlled by Tina/Gue. It is also connected to the Undergrid, and during the Slime Crisis, it forms giant slime nests, hosting a completely different ecosystem from the surface city. The exact structure of the deepest levels has yet to be fully elucidated."},{id:"ネオンクレーター宮殿",name:"ネオンクレーター宮殿",nameEn:"Neon Crater Palace",category:"地理",subCategory:"施設・建造物",description:"Eros-7の絶対的シンボルにして、惑星の政治・軍事的中枢が収まる巨大宮殿。初期建設時は高さ800メートル・100階建ての構造であったが、ZAMLT期に至り高さ1.5キロメートル・200階建てへと大拡張され、その威容は惑星 orbit からも視認可能となった。内部には統治会議場、軍司令部、搾取研究施設が配置され、Eros-7の独裁体制の象徴として機能。カーラ・ヴェルムのスクイーズ・アビス建設後は搾取エネルギーの管理中枢ともなった。現在では一部が市民に開放され、歴史博物館としても活用されている。",descriptionEn:"The absolute symbol of Eros-7 and the colossal palace housing the planet's political and military nerve center. Initially constructed as an 800-meter tall, 100-story structure, it was massively expanded during the ZAMLT era to 1.5 kilometers tall and 200 stories, making its majestic form visible even from planetary orbit. It houses governance conference halls, military command centers, and exploitation research facilities, functioning as a symbol of Eros-7's dictatorship. After the construction of Carla Verm's Squeeze Abyss, it also became the control center for exploitation energy. Currently, parts of it are open to the public and utilized as a historical museum."},{id:"スクイーズ・アビス",name:"スクイーズ・アビス",nameEn:"Squeeze Abyss",category:"地理",subCategory:"施設・建造物",description:"Eros-7の地下560階に構築された巨大な搾取施設。カーラ・ヴェルムが設計・建設を指揮し、惑星の地殻深部から搾取エネルギーを抽出するために建造された。施設の最深部では搾取プラズマ弾の量産が行われ、その破壊力は周辺惑星をも脅かす規模に達した。極度の過酷労働環境のもとで数千人の労働者が動員され、シャドウ・ユニオンの抵抗運動の主な標的となった。現在は大部分が封鎖されているが、一部のレベルで再利用計画が進んでいる。",descriptionEn:"A colossal exploitation facility constructed 560 levels deep beneath Eros-7. Designed and constructed under the direction of Carla Verm, it was built to extract exploitation energy from the deep crust of the planet. At its deepest levels, mass production of exploitation plasma bombs was carried out, their destructive power reaching a scale that threatened neighboring planets. Thousands of workers were mobilized under extremely harsh working conditions, making it a primary target for the resistance movement of the Shadow Union. Although most of it is now sealed off, plans for partial reuse are underway in some levels."},{id:"アンダーグリッド",name:"アンダーグリッド",nameEn:"Undergrid",category:"地理",subCategory:"施設・建造物",description:"Gigapolisの地下全体に張り巡らされた広大なネットワークインフラであり、エネルギー供給、通信、物流の動脈として機能する複数階層の地下構造体。スライム危機の際には地下の湿潤環境を好む巨大スライムの巣が形成され、Gigapolisのインフラに深刻な被害をもたらした。アヤカ・リンが先陣を切って制圧作戦を実行し、危機の収束に貢献。現在では安全対策が大幅に強化され、一部は観光用トンネルとしても整備されている。地下街とも接続し、Gigapolisの地下世界の重要な構成要素となっている。",descriptionEn:"A vast network infrastructure spanning the entire underground of Gigapolis, a multi-level underground structure functioning as the artery for energy supply, communications, and logistics. During the Slime Crisis, giant slime nests that thrive in the underground humid environment formed, causing severe damage to Gigapolis's infrastructure. Ayaka Rin led the suppression operation, contributing to the resolution of the crisis. Safety measures have since been significantly strengthened, and parts of it have been developed as tourist tunnels. It is also connected to the underground shopping district, becoming an important component of Gigapolis's underground world."},{id:"セントラル・タワー",name:"セントラル・タワー",nameEn:"Central Tower",category:"地理",subCategory:"施設・建造物",description:"Gigapolisの中心部に聳え立つ象徴的な超高層タワーであり、西大陸の政治と商業の中心地。E150年のマーストリヒト革命の際、革命指導者エル・フォルハウスがこのタワーを武力占拠し、完全自由経済体制への移行を宣言した歴史的舞台。以来、政変や権力交代のたびに占拠と奪還が繰り返されてきた。E524年には諸世界連邦サミットの主会場として使用され、宇宙規模の外交協議の場となった。タワー最上層のオブザベーションデッキからはGigapolis全土を見渡すことができる。",descriptionEn:"The iconic super-skyscraper towering at the heart of Gigapolis, the political and commercial center of the Western Continent. During the Maastricht Revolution of E150, revolutionary leader El Forhaus forcibly occupied this tower and declared the transition to a completely free economic system, making it a historic stage. Since then, it has been repeatedly occupied and recaptured during each coup and power transition. In E524, it was used as the main venue for the Interstellar Federal Summit, becoming a venue for interstellar-scale diplomatic negotiations. From the observation deck on the top floor, the entire expanse of Gigapolis can be overlooked."},{id:"オアシス・ハウス",name:"オアシス・ハウス",nameEn:"Oasis House",category:"地理",subCategory:"施設・建造物",description:"レイラ・ヴィレル・ノヴァがスライム危機時に前線拠点として使用した場所。Gigapolis地下街の中部エリアに位置し、元々は旧時代の防空シェルターとして建設された構造物を転用した臨時作戦本部。レイラはここを拠点にナノファイバーブーツや強化グローブを駆使してスライム討伐作戦を指揮し、プラズマカノンによる大規模焼却作戦の立案も行った。危機後は戦災記念施設として保存され、内部にはレイラの装備品のレプリカとスライム危機の記録アーカイブが展示されている。",descriptionEn:"The location used by Leila Viller Nova as a forward base during the Slime Crisis. Located in the central area of Gigapolis's underground city, it was originally a temporary operational command center repurposed from an air-raid shelter structure from the old era. From this base, Leila commanded the Slime Extermination Operation utilizing nano-fiber boots and reinforced gloves, and also planned the large-scale incineration operation using plasma cannons. After the crisis, it was preserved as a war memorial facility, with replicas of Leila's equipment and archives of the Slime Crisis on display inside."},{id:"ロレンツィオ国際大学",name:"ロレンツィオ国際大学",nameEn:"Lorenzio International University",category:"地理",subCategory:"施設・建造物",description:"惑星ビブリオに設立された宇宙規模の最高学府にして学術研究の中心。次元物理学、量子情報科学、異種文明学などの最先端分野で宇宙トップクラスの研究実績を誇る。E514年に天才少女ミナがAI学部に入学し、在学中から画期的な研究成果を発表して学界に衝撃を与えた。キャンパスは惑星の北半球に広がり、複数の惑星から集まった留学生が学ぶ国際色豊かな環境。卒業生には銀河系コンソーシアムの要職につく者も多く、次世代の指導者育成機関として重要な役割を担っている。",descriptionEn:"The highest institution of learning established on the planet Biblio and the center of academic research. It boasts top-tier research achievements in cutting-edge fields such as dimensional physics, quantum information science, and xenocivilization studies. In E514, the prodigy Mina enrolled in the AI department and published groundbreaking research findings while still a student, causing a shock in the academic world. The campus spreads across the northern hemisphere of the planet, creating an international environment where students from multiple planets study. Many graduates hold key positions in the Galactic Consortium, and it plays an important role as an institution for nurturing the next generation of leaders."},{id:"ヴェズレル",name:"ヴェズレル",nameEn:"Vezrel",category:"地理",subCategory:"宇宙拠点",description:"エレシュ信仰の中枢拠点であり、サンクチュアリを擁する惑星系。エレシュ教義において「真理の星」と呼ばれ、次元境界領に最も近い位置に浮かぶ特異な惑星系である。ヴェズレルの地表には、自然発生した結晶構造体が点在し、これらはエレシュの教義において「次元の言葉」と解釈され、オラクルの予言解釈に用いられている。惑星系全体が強い精神波的エネルギーに包まれており、非信者であってもヴェズレルに到達すると独特の精神的感応を経験するとされる。エレシュの研究機関が惑星系内に設けられており、宗教と科学の融合研究の最前線基地として機能している。ヴェズレルの経済は巡礼者による宗教産業が中心だが、近年はエレシュの精神的影響力を求めて他文明圏からの寄付や投資も増加している。",descriptionEn:'The central hub of the Elesh faith and a planetary system that houses a sanctuary. Known as the "Star of Truth" in Elesh doctrine, it is a unique planetary system floating in a position closest to the dimensional boundary realm. The surface of Vezrel is dotted with naturally occurring crystal structures, which are interpreted in Elesh doctrine as "Words of the Dimension" and are used in the interpretation of Oracle prophecies. The entire planetary system is enveloped in strong psychotropic energy, and it is said that even non-believers experience a unique spiritual resonance upon reaching Vezrel. Elesh research institutions are established within the planetary system, functioning as a frontline base for the fusion of religion and science. Vezrel\'s economy is centered on religious industries from pilgrims, but in recent years, donations and investments from other civilizations seeking Elesh\'s spiritual influence have been increasing.'},{id:"プロキオ・ネクサス",name:"プロキオ・ネクサス",nameEn:"Prokio Nexus",category:"地理",subCategory:"宇宙拠点",description:"プロキオの中核拠点であり、宇宙最大の交易ハブとして機能する惑星系。全宇宙の貿易ルートが交差する交通の要衝に位置し、数百の恒星系間航路が接続している。プロキオ・ネクサスには巨大な宇宙港と取引所が設けられ、あらゆる資源・技術・文化財が日々取引されている。プロキオの商工会議長の本部もこの惑星系に置かれ、宇宙規模の貿易ルートの管理と運営の中枢となっている。惑星系内の物流インフラは宇宙随一の効率を誇り、プロキオの技術部門が開発した超高速輸送システムにより、他文明圏に比べて物流コストが圧倒的に低い。プロキオ・ネクサスの経済活動は宇宙全体の物価と通貨の安定に直結しており、ここでの取引価格が宇宙の基準価格となっているため、プロキオの経済動向は全文明圏に波及する。エレシオンの医療物資やティエリアの軍事技術、グランベルの消費財がここで中継され、各勢力の経済はプロキオ・ネクサスを通じて相互に依存している。",descriptionEn:"The central hub of Prokio and a planetary system that functions as the universe's largest trading hub. Located at a transportation crossroads where trade routes from the entire universe intersect, it is connected to hundreds of interstellar routes. Prokio Nexus features a massive spaceport and exchange where all kinds of resources, technologies, and cultural artifacts are traded daily. The headquarters of the Prokio Chamber of Commerce is also located in this planetary system, serving as the center for the management and operation of interstellar trade routes. The logistics infrastructure within the planetary system boasts unparalleled efficiency in the universe, and thanks to the ultra-high-speed transportation system developed by Prokio's technical department, logistics costs are overwhelmingly low compared to other civilizations. The economic activities of Prokio Nexus directly affect the stability of prices and currencies across the universe, as transaction prices here become the standard prices for the cosmos, making Prokio's economic trends ripple across all civilizations. Medical supplies from Elesion, military technology from Tierra, and consumer goods from Granbel are relayed here, and the economies of each faction are mutually dependent through Prokio Nexus."},{id:"ロースター・コア",name:"ロースター・コア",nameEn:"Roastar Core",category:"地理",subCategory:"宇宙拠点",description:"ロースターの中核拠点であり、次元間通信技術と量子ネットワークの研究・開発拠点として機能する惑星系。ロースター・コアには宇宙最大の量子コンピューティングセンターが設置されており、次元間通信に必要な膨大なデータ処理をリアルタイムで行っている。また、次元の歪みを監視する早期警戒システムの中枢もここに置かれており、次元境界の不安定化を検知すると全宇宙の関連機関に警報を発する機能を持つ。ロースター・コアの通信インフラは宇宙全体に張り巡らされており、グランベルの量子経済システム、エレシオンの医療データネットワーク、ティエリアの軍事通信網、ファルージャの文化交流プラットフォーム、ディオクレニスの探査データ送信など、あらゆる文明圏の通信がロースター・コアを経由している。このため、ロースター・コアの安全性と安定性は宇宙全体の通信インフラの命運を握っていると言える。",descriptionEn:"The central hub of Roster and a planetary system that functions as a research and development center for interdimensional communication technology and quantum networks. The largest quantum computing center in the universe is installed in Roster Core, performing real-time processing of the vast data required for interdimensional communication. Additionally, the central early warning system that monitors dimensional distortions is also located here, possessing the function of alerting all relevant agencies across the universe when instability in the dimensional boundary is detected. The communication infrastructure of Roster Core is spread throughout the universe, and communications from all civilizations pass through Roster Core, including Granbel's quantum economic system, Elesion's medical data network, Tierra's military communication network, Faluja's cultural exchange platform, and Diocrenis's exploration data transmission. Therefore, it can be said that the safety and stability of Roster Core hold the fate of the universe's entire communication infrastructure."},{id:"次元の塔",name:"次元の塔",nameEn:"Dimensional Tower",category:"地理",subCategory:"施設・建造物",description:"ZAMLT本社の最深部に建造された特異な構造体で、ZAMLTの最終兵器として機能した。塔内部にはカタリスト・コアが設置されており、次元境界のエネルギーを直接操作する能力を持つ。アルファ・ケインとテクロサスの連合軍はZAMLTの本社最深处にあるこの次元の塔への侵入を最終目標とし、カタリスト・コアの破壊を試みた。塔の構造自体が次元境界の不安定領域に接続されており、通常の物理法則が適用されない特異空間となっている。最終決戦ではオメガ＝ユリシス（EVILSのリーダー）もこの次元の塔に出現し、アルファ・ケインの伴共役能力との激突が繰り広げられた。次元の塔の崩壊はZAMLTの終焉を象徴的に示す出来事であり、コーポラトクラシー時代の終わりを告げる象徴となった。",descriptionEn:"A unique structure built in the deepest part of the ZAMLT headquarters, functioning as ZAMLT's ultimate weapon. The Catalyst Core is installed inside the tower, possessing the ability to directly manipulate the energy of the dimensional boundary. The joint forces of Alpha Cain and Techrosus made the invasion of this dimensional tower in the deepest part of ZAMLT's headquarters their ultimate goal, attempting to destroy the Catalyst Core. The tower's structure itself is connected to an unstable area of the dimensional boundary, forming a singular space where normal physical laws do not apply. In the final battle, Omega=Ulysses (leader of EVILS) also appeared in this dimensional tower, and a fierce clash with Alpha Cain's conjugate ability unfolded. The collapse of the dimensional tower symbolically marked the end of ZAMLT and became a symbol announcing the end of the corporatocracy era."},{id:"次元の塔（ZAMLT本社）",name:"シルバープラント",nameEn:"Silver Plant",category:"地理",subCategory:"施設・建造物",description:"ZAMLTの重要施設の一つで、次元エネルギーの精製と兵器生産を行う工場プラント。テクロサスとの全面戦争において、アルファ・ケインとクロノ・ヴァーレント率いるテクロサス部隊による浸透作戦の標的となった。シルバープラント攻略戦では、リンダがプロトコルXのエネルギーコアを安定化させるために自らを犠牲にするという悲劇的な決断を下した。彼女の犠牲はZAMLTに対する抵抗運動の転換点となり、アルファ・ケインの決意を固めさせた。シルバープラントの名は、プラントから放出される銀色の次元エネルギー光輝に由来する。ZAMLT崩壊後、シルバープラントの遺構は「シルバー・ヴェノム」の名称の由来となったという説があり、暗黒組織の歴史的起点として研究されている。",descriptionEn:'One of ZAMLT\'s important facilities, a factory plant that refines dimensional energy and produces weapons. During the all-out war with Techrosus, it became the target of an infiltration operation by Techrosus forces led by Alpha Cain and Chrono Valerent. In the Silver Plant assault battle, Linda made the tragic decision to sacrifice herself to stabilize the energy core of Protocol X. Her sacrifice became a turning point in the resistance movement against ZAMLT and solidified Alpha Cain\'s resolve. The name "Silver Plant" derives from the silver-colored dimensional energy radiance emitted from the plant. After ZAMLT\'s collapse, there is a theory that the ruins of the Silver Plant became the origin of the name "Silver Venom," and it is studied as the historical starting point of the dark organization.'},{id:"ギガポリス",name:"ギガポリス",nameEn:"Gigapolis",category:"地理",subCategory:"西大陸都市",description:"シンフォニー・オブ・スターズ西大陸最大の都市であり、E16連星系の政治・経済・文化の中心地。惑星全土を覆う巨大都市で、20万以上のコーポラトクラシーが競い合い、GDP14京ドルに達する経済の中心地。南部的テスラ地区は労働者層の居住区であり、アルファ・ケインもここで育った。中心部の大広場ではスティル・アレーナが開催され、ZAMLT本部がホログラムと光の層で覆われた塔として君臨した。外周部には虚無の塔が秘密裏に建造され、次元の特異点としてEVILSとの秘密会合に利用された。E6年のパラトンを起源に、技術啓蒙時代の人口爆発とコーポラトクラシー体制のコーポラタムパブリカ期の経済成長を経てメガロポリスへと発展。E150年のマーストリヒト革命でエル・フォルハウスがセントラル・タワーを占拠し自由経済を宣言。E301年にZAMLTの本社が置かれ経済覇権の象徴となったが、E318年のギガポリス解放戦でアルファ・ケインが解放。E335年セリア・ドミニクスによる黄金期を経てSelinopolisと改名。アポロン・Dominion大戦後エヴァトロンに吸収されエヴァポリスと強制改名。E475年エヴァトロン崩壊後Gigapolisに復帰。現在はValoria連合圏の下で安定した都市運営が続いている。地下街最深部はTina/Gueが支配。",descriptionEn:"Symphony of Stars, the largest metropolis on the Western Continent and the political, economic, and cultural center of the E16 star system. A megalopolis covering the entire planet, it's an economic hub where over 200,000 corporatocracies compete, reaching a GDP of 140 quadrillion dollars. The southern Tesla District is a residential area for the working class, where Alpha Kane was also raised. In the central plaza, the Still Arena is held, and the ZAMLT headquarters looms as a tower enveloped in holograms and layers of light. In the outer perimeter, the Tower of Emptiness was secretly constructed and used as a dimensional singularity for secret meetings with EVILS. Originating from the Paraton of E16, it developed into a megalopolis through the population explosion of the Enlightenment Era and the economic growth of the Corporate Republic's Corporatum Publica period. During the Maastricht Revolution of E150, El Forhaus occupied the Central Tower and declared free economy. In E301, ZAMLT established its headquarters, becoming a symbol of economic hegemony, but in E318, during the Gigapolis Liberation War, it was liberated by Alpha Kane. After the golden age led by Celia Dominicus in E335, it was renamed Selinopolis. After the Apollo Dominion War, it was absorbed by Evatron and forcibly renamed Evapolis. Following Evatron's collapse in E475, it returned to Gigapolis. Currently, stable urban administration continues under the Valoria Alliance Zone. The deepest part of the underground district is ruled by Tina/Gue."},{id:"Poitiers",name:"Poitiers",nameEn:"Poitiers",category:"地理",subCategory:"西大陸都市",description:"Gigapolis圏の文化・学術都市。フェルミ音楽の研究機関と芸術院が集積する「音の都」。セリア黄金期にはAURALISの創作活動の拠点として機能し、フェルミ音楽の理論体系化が進められた。現在でもフェルミ音楽の復興祭が定期的に開催され、E16文明圏の音楽文化の中心地として機能している。",descriptionEn:"A cultural and academic city in the Gigapolis sphere. The \"City of Sound\" where institutions researching Fermi music and art academies are concentrated. During Celia's golden age, it served as a base for AURALIS's creative activities, advancing the theoretical systemization of Fermi music. Even now, the Fermi music revival festival is held regularly, functioning as the center of musical culture in the E16 civilization sphere."},{id:"Chem",name:"Chem",nameEn:"Chem",category:"地理",subCategory:"西大陸都市",description:"Gigapolis圏の化学工業都市。フェンドラ人の冶金・化学技術を基盤に発展し、ZAMLT期にはトロン・コーポレーションの生産拠点として機能した。スライム危機後は環境浄化技術への転換が進み、クリーン生産のモデル都市として再編されている。",descriptionEn:"A chemical industrial city in the Gigapolis sphere. Developed based on the metallurgical and chemical technologies of the Fendran people, during the ZAMLT era it functioned as a production base for the Thorne Corporation. After the Slime Crisis, it has been transitioning to environmental purification technologies and is being reorganized as a model city for clean production."},{id:"Troyane",name:"Troyane",nameEn:"Troyane",category:"地理",subCategory:"西大陸都市",description:"Gigapolis圏の宗教都市。テクノ宗教運動の聖地であり、テンプル・オブ・ホライゾンとテミルタロンのゆかりの地。バーズ帝国時代の遺構が残り、軍事史研究の重要拠点。サイケデリック・コスモロジーの修行施設が周辺に立ち並ぶ。",descriptionEn:"A religious city in the Gigapolis sphere. A holy land for the Techno-religious movement and the land associated with the Temple of Horizon and Temirlaton. Remnants of the Bird Empire era remain, making it an important base for military history research. Psychedelic Cosmology training facilities stand in the surrounding area."},{id:"テスラ地区",name:"テスラ地区",nameEn:"Tesla District",category:"地理",subCategory:"西大陸都市",description:"Gigapolis南部に位置する労働者層の居住区。ZAMLT支配下ではA-Registryの低階級市民が密集し、深刻な貧困と権利制限に苦しんだ地域である。アルファ・ケインもこの地区で育ち、スティル・アレーナへの参加を経てZAMLTに対する反乱を主導する原動力となった。テスラ地区の過酷な生活環境は、シャドウ・リベリオン結成の直接的な要因であり、ZAMLT期の社会格差を象徴する地域として歴史に記録されている。ギガポリス解放戦後も低所得層の居住区として機能しているが、テクノ文化ルネサンス期以降は徐々に再開発が進んでいる。",descriptionEn:"A residential area for the working class located in southern Gigapolis. Under ZAMLT rule, low-class citizens of the A-Registry were densely packed, a region that suffered severe poverty and rights restrictions. Alpha Kane was also raised in this district, and after participating in the Still Arena, it became the driving force leading the rebellion against ZAMLT. The harsh living environment of the Tesla District was a direct cause for the formation of the Shadow Rebellion and is recorded in history as a region symbolizing the social inequality of the ZAMLT era. Even after the Gigapolis Liberation War, it continues to function as a residential area for low-income groups, but redevelopment has gradually progressed since the Techno-Cultural Renaissance period."},{id:"大広場",name:"大広場",nameEn:"Grand Square",category:"地理",subCategory:"施設・建造物",description:"Gigapolis中心部に位置する広大な広場であり、スティル・アレーナが開催される伝統的な闘技場である。ネオンコロシアムとしても知られ、次元極地平技術を応用した安全装置により実戦級の戦闘ながら参加者の命を守る仕組みが組み込まれている。各国家や組織が代表する戦士たちが独自の戦闘スタイルと技術を披露し、その結果によって軍事的階位や外交的な発言力が決定される。ボグダス・ジャベリンのテクロサス系譜の戦士たちは常連であり、その圧倒的な実力で他国の参加者を圧倒してきた。V7とトリニティ・アライアンスの対立が深まる中、大広場でのスティル・アレーナは両陣営の緊張を緩和する場としての役割も担っている。観客席は最大50万人を収容可能で、次元ホログラム技術による臨場感のある中継システムを完備。",descriptionEn:"A vast plaza located in the center of Gigapolis, a traditional colosseum where the Still Arena is held. Also known as the Neon Colosseum, it incorporates safety devices applying dimensional pole technology, allowing实战-level combat while protecting participants' lives. Warriors representing various nations and organizations showcase their unique combat styles and techniques, with results determining military rank and diplomatic influence. Warriors of the Bogdas Javelin's Techlosus lineage are regulars, overwhelming participants from other countries with their overwhelming strength. As the conflict between V7 and the Trinity Alliance deepens, the Still Arena in the grand plaza also serves as a venue to ease tensions between the two factions. The spectator seats can accommodate up to 500,000 people and are equipped with an immersive broadcasting system using dimensional hologram technology."},{id:"ZAMLT本部",name:"ZAMLT本部",nameEn:"ZAMLT Headquarters",category:"地理",subCategory:"施設・建造物",description:"Gigapolis中心部に聳え立つZAMLTの本拠地。ホログラムと光の層で覆われた壮麗な外観を持ち、最上階には「アイヴォリールーム（象牙の間）」と呼ばれる最高決議室が設置されていた。楕円形の巨大テーブルを中心にZAMLT5社のリーダーたちが着席し、E16連星系の経済と政治を動かす極秘の意思決定が行われた。本社最深部には次元の塔（Dimensional Tower）とカタリスト・コアが建造され、ZAMLTの次元技術の核心が隠されていた。E318年のギガポリス解放戦でアルファ・ケインによって占拠され、ZAMLTの資産の30%が低階層コミュニティに移転される歴史的転換点となった。現在はZAMLT期の遺構として保存され、一部は歴史博物館として活用されている。",descriptionEn:"ZAMLT's headquarters standing in the center of Gigapolis. It has a magnificent exterior enveloped in holograms and layers of light, with the top floor featuring the \"Ivory Room,\" the highest decision-making chamber. Around an enormous elliptical table, the leaders of ZAMLT's five corporations sat, making secret decisions that moved the economy and politics of the E16 star system. In the deepest part of the headquarters, the Dimensional Tower and Catalyst Core were constructed, hiding the core of ZAMLT's dimensional technology. During the Gigapolis Liberation War in E318, it was occupied by Alpha Kane, becoming a historic turning point where 30% of ZAMLT's assets were transferred to low-level communities. Currently preserved as a relic of the ZAMLT era, part of it is utilized as a history museum."},{id:"虚無の塔",name:"虚無の塔",nameEn:"Tower of Void",category:"地理",subCategory:"施設・建造物",description:"Gigapolis外周部に秘密裏に建造された次元の特異点を内包する塔。ZAMLT5社のトップとEVILSのリーダーであるオメガ＝ユリシスが秘密会合を持った場所であり、次元の塔を通じた取引が行われた。EVILSは通常の物理法則を超越した存在であり、虚無の塔はその次元間接触の唯一の安定ポイントとして機能した。次元の荒野での最終決戦では、アルファ・ケインが伴共役（Ban-Kyōyaku）能力によってオメガ＝ユリシスを次元の繊維に封印し、EDU宇宙論における次元干渉の限界と可能性を示す出来事となった。虚無の塔の正確な位置と構造はZAMLTの最高機密であり、崩壊後も完全な解明には至っていない。",descriptionEn:"A tower secretly constructed in the outer perimeter of Gigapolis, containing a dimensional singularity. It was where the leaders of ZAMLT's five corporations and Omega=Ullysis, the leader of EVILS, held secret meetings, and transactions were conducted through the Tower of Dimensions. EVILS were beings that transcended normal physical laws, and the Tower of Emptiness functioned as the only stable point for their interdimensional contact. In the final battle in the dimensional wilderness, Alpha Kane used his Ban-Kyōyaku ability to seal Omega=Ullysis in the dimensional fabric, an event that demonstrated the limits and possibilities of dimensional interference in EDU cosmology. The exact location and structure of the Tower of Emptiness were ZAMLT's top secret, and even after its collapse, it has not been completely elucidated."},{id:"シルバープラント",name:"シルバープラント",nameEn:"Silver Plant",category:"地理",subCategory:"施設・建造物",description:"ZAMLTの最重要軍事施設であり、地上10階・地下10階の複雑な構造を持つ巨大複合体。プロトコルXのエネルギーコアが保管され、ZAMLTの次元技術と軍事力の核心が集約されていた。アルファ・ケインとテクロサスの戦士たちによるシルバープラント攻略戦は、ギガポリス解放戦の転換点となった決戦である。ルレンツ・コーポレーションの研究員リンダが、プロトコルXのエネルギーコアの暴走を安定化させるために自らを犠牲にした悲劇の舞台でもある。リンダの自己犠牲はシャドウ・リベオンの士気を大きく高め、ZAMLT内部でも反体制感情の広がる転換点となった。崩壊後は一部が解体されたが、地下構造の大部分は未踏査のまま残されている。",descriptionEn:"The most important military facility of ZAMLT, a massive complex with a complex structure of 10 floors above ground and 10 floors below. The energy core of Protocol X was stored here, and the core of ZAMLT's dimensional technology and military power was concentrated. The Silver Plant assault by Alpha Kane and the warriors of Texus was the decisive battle that became the turning point of the Gigapolis Liberation War. It was also the tragic stage where Linda, a researcher of the Lorentz Corporation, sacrificed herself to stabilize the runaway energy core of Protocol X. Linda's self-sacrifice greatly boosted the morale of the Shadow Rebellion and became a turning point that spread anti-establishment sentiment even within ZAMLT. After its collapse, part of it was dismantled, but most of the underground structure remains unexplored."},{id:"geo-ビブリオ第2衛星ルナ",name:"ビブリオ第2衛星ルナ",nameEn:"Luna — Second Moon of Biblio",category:"地理",subCategory:"宇宙・天文",description:"惑星ビブリオの第2衛星で、ビブリオの夜空に最も明るく輝く銀白色の天体である。直径は約2,800キロメートルで、表面には酸素含有鉱物の豊富な鉱脈が確認されており、E16連星系における重要な資源採掘拠点として機能している。ルナにはE80年頃に最初の観測基地が建設され、技術啓蒙時代には大規模な鉱業コロニーが建設された。現在では惑星ビブリオのロレンツィオ国際大学の天体物理学観測所が設置され、Ea16およびEb16の活動監視を行っている。ルナの名は地球の月に因んでおり、初期入植者の郷愁を反映した命名である。ビブリオとルナの間は定期的なシャトル輸送が運行し、学術研究者と鉱業技術者の行き来が盛んである。",descriptionEn:"The second satellite of the planet Biblio, the brightest silvery celestial body in Biblio's night sky. With a diameter of approximately 2,800 kilometers, its surface contains rich veins of oxygen-containing minerals, functioning as an important resource extraction base in the E16 binary star system. The first observation base was constructed on Luna around E80, and during the Enlightenment Era, a large-scale mining colony was built. Currently, the astrophysics observatory of the Lorenz International University of the planet Biblio is installed here, monitoring the activities of Ea16 and Eb16. The name Luna is derived from Earth's moon, reflecting the nostalgia of the early settlers. Regular shuttle services operate between Biblio and Luna, with academic researchers and mining technicians frequently traveling between them."},{id:"geo-Solaris第3衛星ヘリオス",name:"Solaris第3衛星ヘリオス",nameEn:"Helios — Third Moon of Solaris",category:"地理",subCategory:"宇宙・天文",description:"惑星Solarisの第3衛星で、Offenbach種の生態系を支える熱源の一つとして重要な役割を果たしている。ヘリオスの地表には活発な地熱活動が存在し、地表温度は摂氏200度を超える区域が広がる極端な環境を形成している。この熱エネルギーは潮汐加熱によってもたらされ、Solaris地下のOffenbach種コロニーに必要な熱源を間接的に供給している。ヘリオスの軌道はSolarisに対して楕円形であり、近日点通過時の地熱活動はOffenbach種の繁殖サイクルと同期していると仮説が立てられている。E16文明圏ではヘリオスをOffenbach種の「生命の炉」と呼び、この衛星の研究がOffenbach種理解の鍵と見なされている。Ninny Offenbachの原初個体が離脱した際のエネルギー放出はヘリオスの地熱活動に影響を与えた可能性がある。",descriptionEn:"The third satellite of the planet Solaris, playing a vital role as one of the heat sources supporting the ecosystem of the Offenbach species. Helios's surface has active geothermal activity, forming an extreme environment where surface temperatures exceed 200°C over wide areas. This thermal energy is brought about by tidal heating, indirectly supplying the heat source needed by the Offenbach species colony beneath Solaris. Helios's orbit is elliptical relative to Solaris, and it is hypothesized that the geothermal activity at perihelion passage synchronizes with the reproductive cycle of the Offenbach species. In the E16 civilization sphere, Helios is called the \"furnace of life\" for the Offenbach species, and research on this satellite is considered key to understanding the Offenbach species. The energy release when Ninny Offenbach's original individual departed may have affected Helios's geothermal activity."},{id:"geo-E16第4惑星クリオ",name:"E16第4惑星クリオ",nameEn:"Clio — Fourth Planet of E16",category:"地理",subCategory:"宇宙・天文",description:"E16連星系の第4軌道に位置する大型ガス惑星で、木星型惑星に分類される。直径はシンフォニー・オブ・スターズの約4.5倍に達し、主成分は水素とヘリウムである。クリオの大気層には豊富なヘリウム3が含まれており、核融合エネルギーの燃料供給源としてE16連星系のエネルギー安全保障に不可欠な存在となっている。クリオには63個の既知衛星が存在し、そのうち12個は直径500キロメートル以上の大型衛星である。E150年のギガポリス建設開始と同時に大規模なヘリウム3採掘施設がクリオ上層大気に建設され、現在では数十万人の作業員が浮遊プラットフォームで活動している。クリオの名はギリシャ神話の記録の女神ムーサに因み、歴史的記録を重んじるE16文明圏の精神を反映している。",descriptionEn:"A large gas planet located in the 4th orbit of the E16 binary star system, classified as a Jupiter-type planet. Its diameter reaches about 4.5 times that of the Symphony of Stars, and its main components are hydrogen and helium. The atmosphere of Clio contains abundant helium-3, making it an indispensable existence for the energy security of the E16 binary star system as a fuel supply source for fusion energy. Clio has 63 known satellites, 12 of which are large satellites with a diameter of 500 kilometers or more. Along with the start of Gigapolis construction in E150, large-scale helium-3 mining facilities were constructed in Clio's upper atmosphere, and now hundreds of thousands of workers operate on floating platforms. The name Clio is derived from the goddess of record in Greek mythology, reflecting the spirit of the E16 civilization sphere that values historical records."},{id:"geo-E16第5惑星テラ・ノヴァ",name:"E16第5惑星テラ・ノヴァ",nameEn:"Terra Nova — Fifth Planet of E16",category:"地理",subCategory:"宇宙・天文",description:"E16連星系の第5軌道に位置する氷の巨星で、海王星型惑星に分類される。テラ・ノヴァ（新しい大地）の名称は、入植初期に居住可能惑星として期待されたが、実際は表面温度が摂氏マイナス200度に達する極寒の世界であることが判明したという歴史的経緯に由来する。しかしテラ・ノヴァの厚い氷層の下には液体の水の海が存在すると推測され、未知の微生物生態系の可能性が指摘されている。E400年頃にエヴァトロンがテラ・ノヴァの地下海に極秘の軍事研究基地を建設したとされる噂があり、現在もUECOによる調査が続いている。テラ・ノヴァのリング構造は青白色のメタンベースの氷で構成され、E16連星系内で最も美しい天体の一つとして天文学者に親しまれている。",descriptionEn:"An ice giant located in the 5th orbit of the E16 binary star system, classified as a Neptune-type planet. The name Terra Nova (New Earth) originates from the historical background that it was expected to be a habitable planet in the early settlement period, but it turned out to be an extremely cold world with surface temperatures reaching -200°C. However, it is speculated that beneath Terra Nova's thick ice layers there are seas of liquid water, and the possibility of unknown microbial ecosystems has been pointed out. It is rumored that Evatron secretly built a military research base in the underground ocean of Terra Nova around E400, and investigations by UECO continue to this day. The ring structure of Terra Nova is composed of blue-white methane-based ice, and it is beloved by astronomers as one of the most beautiful celestial bodies in the E16 binary star system."},{id:"geo-E16小惑星帯ガイア・リング",name:"E16小惑星帯ガイア・リング",nameEn:"Gaia Ring — E16 Asteroid Belt",category:"地理",subCategory:"宇宙・天文",description:"E16連星系の第5惑星テラ・ノヴァと第6惑星の軌道間に広がる広大な小惑星帯で、数十万個の小天体が密集している。ガイア・リング（大地の輪）の名称は、これらの小天体に豊富なレアメタルと水資源が含まれ、E16文明圏の資源供給の要であることに由来する。小惑星帯の一部にはE60年頃から採掘コロニーが建設され、暗黒時代を生き抜いた入植者たちが資源採掘で生計を立てていた。現在ではアステロイド・マイニング・プラットフォームが複数稼働し、レアメタルの採掘量はE16連星系の年間消費量の約30%を賄っている。ガイア・リング内の通信中継ステーションはSSレンジの技術によって管理され、小惑星帯の安全な航行を支援している。",descriptionEn:"A vast asteroid belt stretching between the orbits of the 5th planet Terra Nova and the 6th planet in the E16 binary star system, where hundreds of thousands of small celestial bodies are densely packed. The name Gaia Ring (Ring of the Earth) comes from the fact that these small bodies contain abundant rare metals and water resources, making them a vital resource supply for the E16 civilization sphere. Mining colonies began to be constructed in parts of the asteroid belt around E60, and settlers who survived the Dark Ages made a living by resource extraction. Currently, multiple Asteroid Mining Platforms are in operation, and the amount of rare metals mined accounts for about 30% of the annual consumption of the E16 binary star system. Communication relay stations within the Gaia Ring are managed by SS Range technology, supporting safe navigation through the asteroid belt."},{id:"geo-ビブリオ首都アカデミア",name:"ビブリオ首都アカデミア",nameEn:"Academia — Capital of Biblio",category:"地理",subCategory:"都市",description:"惑星ビブリオの首都にして、E16連星系における学術研究の最高峰都市。アカデミア市内にはロレンツィオ国際大学の本部キャンパスをはじめ、200以上の研究機関と50以上の図書館が集中している。都市の建築様式は古代ギリシャのアカデメイアを模しており、白大理石の柱廊と広大な中庭が特徴的である。A-Registryの最高等級記録館もアカデミアに置かれ、E16文明圏の全歴史文書と市民データのバックアップが厳重に保管されている。常時約50万人の研究者と学生が居住し、知識の自由な流通と学際的な研究協力を都市運営の最高理念として掲げている。テクノ文化ルネサンス期には次元極地平技術の民用化研究拠点として機能し、ホライゾン・ゲートの安定化制御技術はアカデミアで開発された。",descriptionEn:"The capital of the planet Biblio and the pinnacle city of academic research in the E16 binary star system. Academia City houses the main campus of the Lorenz International University, as well as over 200 research institutions and more than 50 libraries. The city's architectural style imitates the ancient Greek Academy, characterized by white marble colonnades and vast courtyards. The highest-level archive of the A-Registry is also located in Academia, where all historical documents and citizen data of the E16 civilization sphere are strictly preserved. Approximately 500,000 researchers and students reside here at all times, and the city's highest ideals are the free flow of knowledge and interdisciplinary research cooperation. During the Techno-Cultural Renaissance, it functioned as a research base for the civilian application of dimensional horizon technology, and the stabilization control technology for Horizon Gates was developed in Academia."},{id:"geo-ビブリオ港町ポート・ロレンツィオ",name:"ビブリオ港町ポート・ロレンツィオ",nameEn:"Port Lorenzio — Harbor Town of Biblio",category:"地理",subCategory:"都市",description:"惑星ビブリオ最大の宇宙港都市で、星系間交通の主要拠点として機能する。ポート・ロレンツィオはビブリオの南半球に位置し、年間数万隻の宇宙船が寄港するE16連星系有数の物流ハブである。都市名はロレンツィオ国際大学の創設者に因んでいる。港湾地区には巨大なドッキングベイと貨物処理施設が広がり、学術資材や研究機器の輸送が日々行われている。またポート・ロレンツィオは異星文化の交流拠点でもあり、グランベルやティエリアなど他文明圏からの研究者受け入れ施設が整備されている。市内の「知識の市場」では稀有な文献や研究データが取引され、学術的価値を持つ情報の流通拠点として知られている。",descriptionEn:'The largest spaceport city on the planet Biblio, functioning as a major hub for interstellar transportation. Port Lorenzio is located in the southern hemisphere of Biblio and is one of the few logistics hubs in the E16 binary star system where tens of thousands of spaceships dock annually. The city is named after the founder of the Lorenz International University. The harbor area features enormous docking bays and cargo handling facilities, where academic materials and research equipment are transported daily. Port Lorenzio is also a hub for interstellar cultural exchange, with facilities to receive researchers from other civilization spheres such as Granbel and Tierra. The "Market of Knowledge" in the city is known as a trading place for rare literature and research data, serving as a distribution point for information with academic value.'},{id:"geo-Solaris首都ソーラ・シティ",name:"Solaris首都ソーラ・シティ",nameEn:"Solar City — Capital of Solaris",category:"地理",subCategory:"都市",description:"惑星Solarisの地下に建設された唯一の恒久都市で、Offenbach種の集合意識との接触拠点として機能している。ソーラ・シティの人口は約2万人で、大部分がOffenbach種の研究者と人類の倫理学者で構成されている。都市の中心には「離脱のモニュメント」と呼ばれる記念碑が建てられ、Ninny Offenbachの原初個体が集合意識から独立した歴史的瞬間を記念している。ソーラ・シティのエネルギー供給は衛星ヘリオスの地熱発電に依存し、地下深部の熱導管システムによって都市全体に暖房と電力が提供されている。都市は厳格な環境保護区域に指定されており、Offenbach種の生態系への影響を最小限に抑える設計が採用されている。",descriptionEn:"The sole permanent city constructed beneath the planet Solaris, functioning as a contact point with the collective consciousness of the Offenbach species. Solar City has a population of approximately 20,000, mostly consisting of Offenbach researchers and human ethicists. At the city's center stands the \"Monument of Departure,\" commemorating the historical moment when Ninny Offenbach's original individual became independent from the collective consciousness. Solar City's energy supply relies on geothermal power from the satellite Helios, with heating and electricity provided to the entire city through a deep underground heat conduction system. The city is designated as a strict environmental protection zone, employing designs that minimize impact on the Offenbach species' ecosystem."},{id:"geo-Solaris工業都市フォージ・タウン",name:"Solaris工業都市フォージ・タウン",nameEn:"Forge Town — Industrial City of Solaris",category:"地理",subCategory:"都市",description:"惑星Solarisの地下熱源を利用した大規模な工業都市で、特殊合金とセラミック材料の製造拠点として機能している。フォージ・タウン（鍛冶の町）は地熱エネルギーを直接工業プロセスに利用することができ、従来の工業都市に比べてエネルギーコストが大幅に低い。都市の工業地帯では、E16連星系の軍事装備や宇宙船の部品製造の約20%を担っており、アイアン・シンジケートとも競合する生産能力を持つ。Offenbach種の熱耐性技術を応用した特殊な溶接・鍛造技術が発達しており、極端な温度条件に耐える超耐熱材料の生産で星系一の技術力を誇る。労働者の大部分はシンフォニー・オブ・スターズからの移住者であるが、Offenbach種との協働生産も一部導入されている。",descriptionEn:"A massive industrial city utilizing the underground heat sources of the planet Solaris, functioning as a manufacturing hub for special alloys and ceramic materials. Forge Town can utilize geothermal energy directly in industrial processes, resulting in significantly lower energy costs compared to traditional industrial cities. The city's industrial zone handles approximately 20% of the military equipment and spaceship parts manufacturing for the E16 star system, possessing production capabilities that compete with the Iron Syndicate. Specialized welding and forging technologies, applying the heat resistance technology of the Offenbach species, have developed, boasting the star system's foremost technical capability in producing ultra-heat-resistant materials that withstand extreme temperature conditions. While most workers are immigrants from the Symphony of Stars, some collaborative production with the Offenbach species has also been introduced."},{id:"geo-エレシオン聖都ヒエロポリス",name:"エレシオン聖都ヒエロポリス",nameEn:"Hieropolis — Holy City of Elyseon",category:"地理",subCategory:"都市",description:"エレシオンの首都にして「生命の聖都」と呼ばれる医療・宗教の中心都市。ヒエロポリス（聖なる都市）はエレシオンの第1大陸に位置し、女王リアナ・ソリスの王宮とエレシオン最高医療評議会の本部が置かれている。都市の中心には「生命の大聖堂」が聳え立ち、エレシオンの「生命の維持と再生」の理念を象徴している。ヒエロポリスは宇宙最高水準の医療施設を擁し、再生医療、遺伝子治療、寿命延長技術の研究拠点として他文明圏からも治療目的で訪れる者が絶えない。都市の建築は白と金を基調とし、エレシオンの平和主義と技術共有の理念を反映した清潔で秩序ある都市景観を持つ。フェルミ音楽の精神論的解釈を深く研究する学派もヒエロポリスに拠点を置いている。",descriptionEn:'The capital of Elesion and a medical and religious center city known as the "Holy City of Life." Hieropolis is located on the first continent of Elesion, housing Queen Riana Solis\'s palace and the headquarters of the Elesion Supreme Medical Council. At the city\'s center stands the "Cathedral of Life," symbolizing Elesion\'s philosophy of "Life Maintenance and Regeneration." Hieropolis possesses the highest standard of medical facilities in the cosmos, serving as a research hub for regenerative medicine, genetic therapy, and life extension technology, attracting visitors from other civilizations for treatment purposes. The city\'s architecture is based on white and gold, reflecting Elesion\'s philosophy of pacifism and technological sharing with a clean and orderly urban landscape. A school deeply studying the philosophical interpretation of Fermi music also has its base in Hieropolis.'},{id:"geo-グランベル商都マーケット・コア",name:"グランベル商都マーケット・コア",nameEn:"Market Core — Commercial Capital of Granbell",category:"地理",subCategory:"都市",description:"グランベル最大の商業都市にして宇宙経済の心臓部。マーケット・コアはグランベルの首都オルダシティの隣接区域に位置し、宇宙最大の取引所と金融センターを擁する。日々数百兆nトークン相当の取引が行われ、宇宙全体の物価と通貨の基準価格がここで決定される。マーケット・コアの中央には「グランベル・エクスチェンジ」と呼ばれる超巨大取引所があり、グランベルの量子経済システムを通じてリアルタイムで全文明圏の市場と接続している。都市のスカイラインは次元間通信アンテナとホログラム広告で埋め尽くされ、昼夜を問わず活気に満ちている。GDP150兆ドルのグランベル経済を支える中核都市であり、銀河系コンソーシアムの経済政策の実行拠点でもある。",descriptionEn:"The largest commercial city of Granbell and the heart of the cosmic economy. Market Core is located in the adjacent area of Granbell's capital, Oldacity, housing the universe's largest exchange and financial center. Transactions worth hundreds of trillions of n-tokens take place daily, with the standard prices for goods and currencies across the cosmos determined here. At the center of Market Core stands the \"Granbell Exchange,\" a super-huge exchange that connects in real-time with markets of all civilizations through Granbell's quantum economic system. The city's skyline is filled with interdimensional communication antennas and holographic advertisements, bustling with activity day and night. As the core city supporting Granbell's economy with a GDP of 150 trillion dollars, it is also the execution base for the economic policies of the Galactic Consortium."},{id:"geo-ディオクレニス首都ノウス",name:"ディオクレニス首都ノウス",nameEn:"Nous — Capital of Dioclenis",category:"地理",subCategory:"都市",description:"ディオクレニスの首都にして宇宙探査と科学技術研究の中心都市。ノウス（知性）の名称通り、知識の探求を最高の都市理念として掲げ、科学宰相ネイサン・コリンドの研究拠点が置かれている。都市全体が巨大な研究キャンパスのような構造を持ち、天文学、次元物理学、異種文明学の最先端施設が集中している。ノウスの中央には「無限の図書館」と呼ばれる次元記憶貯蔵施設があり、宇宙のあらゆる分野の知識が次元符号化されて保存されている。ディオクレニスの探査船団の発進基地もノウスに隣接し、新たな惑星系への探査ミッションが常時企画されている。ヘゲモニー・パラドックス回避のため、対立のエネルギーを共同宇宙探査へ転換する提案の発信地でもある。",descriptionEn:'The capital of Dioclenis and a center city for cosmic exploration and scientific and technological research. True to its name, Nous (Knowledge), it upholds the pursuit of knowledge as its highest urban ideal, housing the research base of Science Minister Nathan Corrin. The entire city has the structure of a massive research campus, with cutting-edge facilities in astronomy, dimensional physics, and xenocivilization studies concentrated at its center. At the heart of Nous stands the "Library of Infinity," a dimensional memory storage facility where knowledge from all fields of the cosmos is preserved through dimensional encoding. The launch base for Dioclenis\'s exploration fleet is also adjacent to Nous, with new planetary system exploration missions constantly being planned. It is also the origin of proposals to convert the energy of conflict into joint cosmic exploration, in order to avoid the Hegemony Paradox.'},{id:"geo-ティレリア海上都市フローティング・ハーバー",name:"ティレリア海上都市フローティング・ハーバー",nameEn:"Floating Harbor — Ocean City of Tyeria",category:"地理",subCategory:"都市",description:"ティレリア最大の軍港都市で、宇宙最大の艦隊母港として機能する。フローティング・ハーバー（浮遊する港）はティレリアの第3大陸の沖合に建設された巨大な海上都市であり、数千隻の軍艦を停泊させることができる。都市の構造は数百の浮遊プラットフォームで構成され、波浪と潮汐に応じて動的に位置を調整する独自の安定化システムを採用している。ティエリア総帥グレイモンド・ハウザーの軍事司令部の一部がフローティング・ハーバーに置かれ、艦隊の運用指揮と軍事技術の輸出管理が行われている。都市の防御は宇宙随一の防衛システムで守られ、他勢力の軍事的脅威から艦隊を保護している。軍事技術の輸出を経済基盤とするティエリアにとって、フローティング・ハーバーは国家の生命線である。",descriptionEn:"The largest military port city of Tilleria and the universe's largest fleet home port. Floating Harbor is a massive maritime city constructed off the coast of Tilleria's third continent, capable of docking thousands of warships. The city's structure consists of hundreds of floating platforms, employing a unique stabilization system that dynamically adjusts positions in response to waves and tides. Part of the military command of Tilleria's Supreme Commander Graymond Hauser is located in Floating Harbor, where fleet operations and military technology export management are conducted. The city is protected by the cosmos's foremost defense system, safeguarding the fleet from military threats from other powers. For Tilleria, which exports military technology as its economic foundation, Floating Harbor is the nation's lifeline."},{id:"geo-ファルージャ砂漠都市オアシス・ハブ",name:"ファルージャ砂漠都市オアシス・ハブ",nameEn:"Oasis Hub — Desert City of Fallujah",category:"地理",subCategory:"都市",description:"ファルージャの首都にして宇宙有数の文化交流都市。オアシス・ハブはファルージャ最大の砂漠の中央に位置する緑地都市であり、高度な水資源管理技術によって砂漠の真ん中に豊かな生態系を創出している。都市の中心には「文化の泉」と呼ばれる広大な公園があり、全宇宙からの芸術家、音楽家、外交官が集う交流の場となっている。ファルージャ評議会代表マドリス・カーネルの外交拠点もオアシス・ハブに置かれ、対立する勢力間の調停の場として頻繁に使用されている。オアシス・ハブはフェルミ音楽の精神論的解釈と宇宙の多元的な芸術表現の融合拠点としても知られ、毎年「砂漠の星間フェスティバル」が開催されて宇宙中から観光客を集めている。",descriptionEn:'The capital of Faluja and one of the cosmos\'s foremost cultural exchange cities. Oasis Hub is a green city located in the center of Faluja\'s largest desert, creating a rich ecosystem in the middle of the desert through advanced water resource management technology. At the city\'s center lies the vast "Cultural Spring" park, which has become a gathering place for artists, musicians, and diplomats from across the cosmos. The diplomatic base of Faluja Council Representative Madris Carnell is also located in Oasis Hub, frequently used as a venue for mediating between opposing forces. Oasis Hub is also known as a fusion hub for the philosophical interpretation of Fermi music and the diverse artistic expressions of the cosmos, hosting the annual "Desert Intersellar Festival" that attracts tourists from across the universe.'},{id:"geo-ギガポリス第8区画イーストエンド",name:"ギガポリス第8区画イーストエンド",nameEn:"East End — District 8 of Gigapolis",category:"地理",subCategory:"都市",description:"Gigapolis東部に位置する第8区画で、新興産業と多国籍企業の拠点として機能している。イーストエンドはテクノ文化ルネサンス期に急速に発展した比較的新しい地区で、次元極地平技術を応用したスタートアップ企業が多数集積している。地区の建築はガラスと次元ホログラムを多用した未来的なデザインで統一され、Gigapolisの他地区とは異なる国際的な景観を持つ。イーストエンドにはリミナル・フォージの拠点も置かれており、ミナ・エウレカ・エルンストのAI研究活動の舞台となっている。V7とトリニティ・アライアンスの情報戦の最前線でもあり、SSレンジの通信中継施設とシルバー・ヴェノムの潜入工作が交錯する緊張の地域である。第8区画の住民は他地区に比べて若年層が多く、革新的な文化の発信地として注目されている。",descriptionEn:"District 8, located in eastern Gigapolis, functioning as a hub for emerging industries and multinational corporations. East End is a relatively new district that developed rapidly during the Techno Cultural Renaissance period, with numerous startup companies applying dimensional polar horizon technology. The district's architecture is unified with a futuristic design using extensive glass and dimensional holograms, possessing an international landscape distinct from other areas of Gigapolis. East End also houses the base of Liminal Forge, serving as the stage for AI research activities by Mina Eureka Ernst. It is also the frontline of the information war between V7 and the Trinity Alliance, where SS Range's communication relay facilities and Silver Venom's infiltration operations intersect in a tense region. The residents of District 8 are younger compared to other districts, and it is gaining attention as a source of innovative culture."},{id:"geo-ウェスト・エンド",name:"ウェスト・エンド",nameEn:"West End",category:"地理",subCategory:"都市",description:"Gigapolis西部に位置する高級住宅・商業地区で、A-Registryの高階級市民が居住するE16連星系屈指の富裕地域である。ウェスト・エンドの建築は古典主義と次元技術を融合した壮麗なデザインで統一され、大企業の本社ビルや高級商業施設が林立している。地区の中心には「ウェスト・ガーデン」と呼ばれる広大な庭園都市があり、人工的に制御された四季折々の景観が楽しめる。ZAMLT期には5大企業の幹部邸宅が集中し、経済覇権の象徴的な地区であった。エヴァトロン支配期には軍の将校宿舎として接収されたが、崩壊後は民間に返還され再開発が進んだ。現在ではグランベル系企業の駐在員や銀河系コンソーシアムの外交官が多く居住し、国際色豊かな地区となっている。",descriptionEn:'A high-end residential and commercial district located in western Gigapolis, it is one of the wealthiest regions in the E16 star system, home to high-class citizens of the A-Registry. The architecture of West End is unified in a magnificent design that blends classicism with dimensional technology, with corporate headquarters and luxury commercial facilities standing in abundance. At the center of the district lies "West Garden," a vast garden city where artificially controlled seasonal landscapes can be enjoyed. During the ZAMLT era, it was concentrated with the mansions of the five major corporations\' executives, serving as a symbolic district of economic hegemony. During the Evatron dominion period, it was requisitioned as military officer quarters, but after the collapse, it was returned to civilian hands and redevelopment progressed. Currently, it is home to many resident employees of Granbel system corporations and diplomats from the Galactic Consortium, making it a district rich in international character.'},{id:"geo-ノース・サイド",name:"ノース・サイド",nameEn:"North Side",category:"地理",subCategory:"都市",description:"Gigapolis北部に位置する軍事・防衛地区で、テクロサス系譜の歴史的な根拠地である。ノース・サイドはロンバルディア戦争（E88〜E98年）の際に前線基地として機能し、城塞都市ロンヴと連携して北からの侵入に備えた。現在でも軍事博物館と旧要塞跡が残り、テクロサス系譜の軍事伝統を伝える地域として機能している。ボグダス・ジャベリンのセバスチャン・ヴァレリウスはノース・サイドに師団本部を置き、V7とトリニティ・アライアンスの冷戦期には最前線防衛拠点として機能した。地区の住民には軍人と退役軍人が多く、テクロサス系譜の戦闘訓練施設が複数存在する。ノース・サイドの北端には旧帝国時代の城壁が残り、Gigapolis最古の構造物の一つとして文化財指定されている。",descriptionEn:"A military and defense district located in northern Gigapolis, it is the historical stronghold of the Teclosas lineage. North Side functioned as a frontline base during the Lombardia War (E88-E98), coordinating with the fortress city of Ronve to defend against northern incursions. Even now, military museums and old fortress ruins remain, serving as a region that preserves the military tradition of the Teclosas lineage. Bogdas Javelin's Sebastian Valerius established his division headquarters in North Side, and during the Cold War between V7 and the Trinity Alliance, it functioned as a frontline defense stronghold. The district's residents include many soldiers and veterans, and multiple combat training facilities of the Teclosas lineage exist. At the northern tip of North Side, the city walls of the old imperial era remain, designated as a cultural asset as one of Gigapolis' oldest structures."},{id:"geo-サウス・マーケット",name:"サウス・マーケット",nameEn:"South Market",category:"地理",subCategory:"都市",description:"Gigapolis南部に位置する大規模な商業・市場地区で、西大陸の物流と流通の心臓部として機能している。サウス・マーケットには数千の店舗と市場が密集し、食料、衣料、電子機器、武器まであらゆる商品が取引されている。E150年のマーストリヒト革命後の自由経済化で急速に発展し、現在ではGigapolisのGDPの約15%をこの地区単独で産出している。サウス・マーケットはnトークンの現実経済での使用が最も活発な地区であり、文化的貢献や知識の共有も取引対象となる独特な市場文化が根付いている。スライム危機時にはサウス・マーケットの地下倉庫にスライムの巣が形成され、アンダーグリッド経由での制圧作戦が展開された。現在は安全対策が強化され、テクノ文化ルネサンスの恩恵を受けてホログラム広告と次元ホール接続ロビーが整備されている。",descriptionEn:"A large-scale commercial and market district located in southern Gigapolis, functioning as the heart of logistics and distribution for the western continent. South Market has thousands of shops and markets densely packed, with all kinds of goods traded from food, clothing, electronics, to weapons. It developed rapidly after the liberalization of the free economy following the Maastricht Revolution in E150, and now this single district generates approximately 15% of Gigapolis' GDP. South Market is the district where the use of n-tokens in the real economy is most active, with a unique market culture rooted in cultural contributions and knowledge sharing also becoming trading objects. During the Slime Crisis, slimes formed nests in the underground warehouses of South Market, and a suppression operation via the Undergrid was launched. Currently, safety measures have been strengthened, and it has benefited from the Techno-Cultural Renaissance, with holographic advertisements and dimensional hall connection lobbies being installed."},{id:"geo-テック・コリドー",name:"テック・コリドー",nameEn:"Tech Corridor",category:"地理",subCategory:"都市",description:"Gigapolis中心部から東部に延びる技術産業ベルトで、E16連星系の技術革新の最先端拠点である。テック・コリドーには次元極地平技術、量子計算、ナノテクノロジー、AI開発などのハイテク企業と研究機関が密集している。ZAMLT期にはトロン・コーポレーションの研究開発拠点がテック・コリドーの中心に位置し、次元エネルギーの兵器化が進められていた。ギガポリス解放戦後は平和利用の技術開発に転換し、テクノ文化ルネサンス期には次元ホールの民用化プロジェクトがテック・コリドーで実現した。現在ではリミナル・フォージやクアンタ・ラボなど新世代の研究機関が進出し、E530年の次元ブリッジ完成に向けた基礎研究が行われている。テック・コリドーの住民の約70%が技術系の専門職であり、E16連星系で最も学歴水準の高い地区である。",descriptionEn:"A technology industry belt extending from the center of Gigapolis to the east, it is the forefront of technological innovation in the E16 star system. Tech Corridor is densely packed with high-tech companies and research institutions in dimensional pole technology, quantum computing, nanotechnology, AI development, and more. During the ZAMLT era, Tron Corporation's R&D hub was located at the center of Tech Corridor, where the weaponization of dimensional energy was advanced. After the Gigapolis Liberation War, it shifted to peaceful technology development, and during the Techno-Cultural Renaissance, the civilian use project for dimensional halls was realized in Tech Corridor. Currently, new-generation research institutions like Liminal Forge and Quanta Lab have moved in, and basic research is being conducted toward the completion of the Dimensional Bridge in E530. Approximately 70% of Tech Corridor's residents are technical professionals, making it the district with the highest educational level in the E16 star system."},{id:"geo-アート・ディストリクト",name:"アート・ディストリクト",nameEn:"Art District",category:"地理",subCategory:"都市",description:"Gigapolis西部に位置する芸術・文化地区で、セリア黄金期の遺産を受け継ぐE16連星系の文化の中心地である。アート・ディストリクトには美術館、劇場、音楽ホール、アトリエが密集し、フェルミ音楽の演奏会とAURALISの創作活動の拠点として機能している。セリア黄金期（E335〜E370年）にはAURALIS第一世代のメンバーがこの地区に居住し、「光と音を永遠にする」という理念を街の至る所に表現した。エヴァトロン支配期には多くの芸術施設が閉鎖されたが、テクノ文化ルネサンス期に復興し、AURALIS第二世代の活動拠点となった。地区の建築は音響的調和を重視した設計で統一され、建物の壁面が楽器のように音を共鳴させる特徴的な構造を持つ。Poitiersに隣接し、両地区を合わせて「文化回廊」と呼ばれている。",descriptionEn:'An art and cultural district located in western Gigapolis, it is the cultural center of the E16 star system, inheriting the legacy of the Celia Golden Age. Art District is densely packed with art museums, theaters, concert halls, and ateliers, functioning as a base for Fermi music concerts and AURALIS creative activities. During the Celia Golden Age (E335-E370), the first generation of AURALIS members lived in this district, expressing the philosophy of "making light and sound eternal" throughout the city. During the Evatron dominion period, many art facilities were closed, but they were revived during the Techno-Cultural Renaissance, becoming a base for the activities of the second generation of AURALIS. The district\'s architecture is unified in a design that emphasizes acoustic harmony, with a distinctive structure where building walls resonate like musical instruments. It borders Poitiers, and the two districts together are called the "Cultural Corridor."'},{id:"geo-ポート・ディストリクト",name:"ポート・ディストリクト",nameEn:"Port District",category:"地理",subCategory:"都市",description:"Gigapolis西部に位置する港湾地区で、シンフォニー・オブ・スターズの海上物流の主要拠点として機能している。ポート・ディストリクトはアブリーヴォとPersepolisと共に西大陸の物流トライアングルを形成し、惑星内輸送と惑星間輸送の結節点として重要な役割を果たしている。地区には巨大なドッキングベイとコンテナヤードが広がり、年間数千万トンの貨物が取り扱われている。テクノ文化ルネサンス期にはホライゾン・ゲート接続ターミナルが整備され、惑星ビブリオや他の植民地との直接物流ルートが確立された。ポート・ディストリクトの海上市場は新鮮な海産物が取引される名所であり、異星の食材もホライゾン・ゲート経由で毎日届けられている。スライム危機後は港湾施設の海底構造に残存するスライム駆除が長期プロジェクトとして続いている。",descriptionEn:"A harbor district located in western Gigapolis, functioning as the main hub for Symphony of Stars' maritime logistics. Port District forms a logistics triangle with Abrivo and Persepolis for the western continent, playing an important role as a junction for intra-planetary and inter-planetary transport. The district features vast docking bays and container yards, handling tens of millions of tons of cargo annually. During the Techno-Cultural Renaissance, the Horizon Gate connection terminal was established, establishing direct logistics routes with the planet Biblio and other colonies. Port District's sea market is a famous spot for trading fresh seafood, and ingredients from other planets are delivered daily via the Horizon Gate. After the Slime Crisis, the removal of remaining slimes from the harbor facility's underwater structure continues as a long-term project."},{id:"geo-クレセント山脈",name:"クレセント山脈",nameEn:"Crescent Mountain Range",category:"地理",subCategory:"自然地形",description:"クレセント大地方の東部に南北に延びる壮大な山脈で、大陸の三日月型地形の外縁を形成している。最高峰は標高8,400メートルに達し、シンフォニー・オブ・スターズにおける最高地点の一つである。クレセント山脈には豊富な鉱物資源が埋蔵されており、アイアン・シンジケートの主要採掘拠点が山脈中腹に点在している。山脈の東側斜面は急峻で、西側斜面は緩やかな草原が広がる非対称な地形が特徴的である。テリアン反乱（E400〜E470年）の際には山岳地帯がエリオス・ウォルドのゲリラ戦の拠点として機能し、エヴァトロン軍の制圧を長期間阻んだ。現在では山脈の北端にSSレンジの通信中継施設が建設され、クレセント地方全域の通信ネットワークを支えている。登山とスキーを楽しむ観光地としても人気がある。",descriptionEn:"A magnificent mountain range running north-south in the eastern part of the Crescent Great Territory, forming the outer edge of the continent's crescent-shaped terrain. Its highest peak reaches 8,400 meters, making it one of the highest points in the Symphony of Stars. The Crescent Mountains are rich in mineral resources, with major mining outposts of the Iron Syndicate scattered across the mountainside. The terrain is characterized by its asymmetry, with steep eastern slopes and gentle western slopes stretching into grasslands. During the Terrian Rebellion (E400-E470), the mountainous area functioned as a base for Elios Wald's guerrilla warfare, long resisting Evatron army suppression. Currently, a communication relay facility of the SS Range has been constructed at the northern end of the mountains, supporting the communication network of the entire Crescent region. It is also a popular tourist destination for mountaineering and skiing."},{id:"geo-ヴェルミリオン渓谷",name:"ヴェルミリオン渓谷",nameEn:"Vermillion Valley",category:"地理",subCategory:"自然地形",description:"ヴァーミリオン国家の中央を南北に貫く壮大な渓谷で、赤色の岩壁が特徴的な景観を作り出している。ヴェルミリオン渓谷はクレセント山脈の浸食によって形成されたV字谷で、最大深度は1,200メートルに達する。渓谷の底にはヴェルミリオン川が流れ、周辺の農業地帯に豊かな灌漑水を供給している。渓谷の赤い岩壁は夕陽に照らされて燃えるような朱色に輝き、国家名「ヴァーミリオン（朱色）」の由来となった。フェルミ音楽の伝統的な野外演奏会は渓谷の音響効果を活用して開催され、岩壁が自然の残響板として機能する。ヴァーミリオンの国家建築は渓谷の赤色を基調とし、岩壁の素材をそのまま使用した構造物が多く見られる。エヴァトロン支配期には渓谷の洞窟に地下抵抗組織の隠れ家が築かれ、テリアン反乱との連携拠点となった。",descriptionEn:"A magnificent canyon running north-south through the center of the Vermillion Nation, creating a distinctive landscape with its red rock walls. Vermillion Canyon is a V-shaped valley formed by the erosion of the Crescent Mountains, with a maximum depth of 1,200 meters. The Vermillion River flows through the canyon floor, supplying rich irrigation water to the surrounding agricultural areas. The canyon's red rock walls glow with a fiery vermilion color when illuminated by the setting sun, which became the origin of the nation's name \"Vermillion (vermilion).\" Traditional outdoor concerts of Fermi music are held utilizing the canyon's acoustic effects, with the rock walls functioning as natural resonating boards. The national architecture of Vermillion is based on the canyon's red color, and many structures are seen using the rock wall material directly. During the Evatron dominion period, caves in the canyon housed underground resistance organizations, becoming a coordinating base with the Terrian Rebellion."},{id:"geo-ブルーローズ平原",name:"ブルーローズ平原",nameEn:"Blue Rose Plains",category:"地理",subCategory:"自然地形",description:"ブルーローズ国家の大部分を覆う広大な平原地帯で、クレセント大地方最大の農業生産地である。ブルーローズ平原の土壌はシンフォニー・オブ・スターズ特有の青い鉱物を含み、雨季には一面に青い花が咲き乱れることから「ブルーローズ（青い薔薇）」の名が付けられた。平原には高度な農業自動化システムが導入され、クレセント地方の食料需要の約40%をこの平原で賄っている。平原の北端にはフィオナがV7設立（E515年）を宣言した「自由の丘」があり、ブルーローズの国家独立の象徴として史跡に指定されている。テクノ文化ルネサンス期には平原に次元極地平技術の実証実験場が建設され、ホライゾン・ゲートの安定化制御の試験が行われた。平原の西側はヴェルミリオン渓谷に接し、両国の国境には緩衝地帯が設定されている。",descriptionEn:'The vast plain that covers most of the Blue Rose Nation, Crescent\'s largest agricultural production area. The soil of the Blue Rose Plain contains the unique blue minerals of the Symphony of Stars, and during the rainy season, blue flowers bloom across its entire surface, giving it the name "Blue Rose." Advanced agricultural automation systems have been introduced to the plain, which supplies approximately 40% of the food demand for the Crescent region. At the northern end of the plain stands "Freedom Hill," where Fiona declared the founding of V7 (E515), now designated as a historical site symbolizing Blue Rose\'s national independence. During the Techno-Cultural Renaissance, a dimensional polar plateau experimental facility was constructed on the plain, where stabilization control tests for the Horizon Gate were conducted. The western side of the plain borders the Vermillion Valley, with a buffer zone established between the two nations.'},{id:"geo-クロセヴィア密林",name:"クロセヴィア密林",nameEn:"Crosevia Dense Forest",category:"地理",subCategory:"自然地形",description:"クロセヴィア国家の南部に広がる熱帯密林で、クレセント大地方最大の原生林である。クロセヴィア密林は特有の複雑な気象システムを内包し、局地的な暴風雨を頻繁に発生させることから気象制御技術の研究フィールドとして利用されてきた。密林にはシンフォニー・オブ・スターズ固有の動植物が多数生息し、中には医薬品の原料となる希少植物も含まれている。SUDOMの医療研究者が密林の植物探索を定期的に実施し、新薬の開発に貢献している。密林の深部には未踏査の区域が広がり、スライム危機時には変異したリーチ・ドレインの隠れ家となった可能性が指摘されている。カスチーナ・テンペストは密林の気象観測データを基に気象制御技術を開発し、クロセヴィアの国家的特色を形成した。",descriptionEn:"A tropical rainforest spreading across the southern part of the Crosevia Nation, Crescent's largest primary forest. The Crosevia Rainforest contains a unique complex weather system that frequently causes localized storms, making it a research field for weather control technology. Numerous unique flora and fauna of the Symphony of Stars inhabit the rainforest, including rare plants used as pharmaceutical ingredients. SUDOM medical researchers regularly conduct plant exploration in the rainforest, contributing to new drug development. Unexplored areas extend deep into the rainforest, and it has been suggested that during the Slime Crisis, it may have served as a hiding place for mutated Leech-Drains. Castina Tempest developed weather control technology based on the rainforest's meteorological observation data, forming a national characteristic of Crosevia."},{id:"geo-SSレンジ通信山",name:"SSレンジ通信山",nameEn:"SS Range Signal Mountain",category:"地理",subCategory:"自然地形",description:"SSレンジ国家の中心に聳える標高3,200メートルの山で、E16連星系最大の通信施設が山頂に建設されている。通信山の地質は磁性鉱物を豊富に含む特殊な岩石で構成され、自然の電磁波増幅効果を持つ。この特性を利用してアイク・ロペスの技術チームが超長距離量子通信システムの基幹アンテナを山頂に構築し、E16連星系全域の通信インフラの基盤を確立した。通信山の中腹にはSSレンジの研究施設とデータセンターが階層状に配置され、量子暗号通信の開発とサイバーセキュリティ研究が行われている。山頂のアンテナ群は夜間に青白い光を放ち、クレセント大地方のランドマークとしても機能している。V7の情報戦において通信山は最重要防衛対象であり、多重のサイバー防壁で厳重に守られている。",descriptionEn:"A mountain with an elevation of 3,200 meters, standing at the center of the SS Range Nation, with the E16 star system's largest communication facility constructed at its summit. The geology of Communication Mountain consists of special rocks rich in magnetic minerals, possessing a natural electromagnetic wave amplification effect. Utilizing this characteristic, Ike Lopez's technical team constructed the main antenna for an ultra-long-range quantum communication system at the summit, establishing the foundation for the communication infrastructure across the entire E16 star system. Research facilities and data centers of SS Range are hierarchically arranged on the mountainside of Communication Mountain, where quantum cryptographic communication development and cybersecurity research are conducted. The antenna array at the summit emits a pale blue light at night, also functioning as a landmark for the Crescent region. In V7's information warfare, Communication Mountain is the most critical defense target, strictly protected by multiple cyber defense walls."},{id:"geo-アイアン峡谷",name:"アイアン峡谷",nameEn:"Iron Canyon",category:"地理",subCategory:"自然地形",description:"アイアン・シンジケート国家の東部に位置する大規模な峡谷で、豊富な鉄鉱石とレアメタルの鉱脈が地表に露出している。アイアン峡谷の岩壁は酸化鉄を多量に含む赤褐色の地層で構成され、夕陽に照らされて溶鉄のような光沢を放つことからこの名が付けられた。峡谷内にはE60年の暗黒時代以来の採掘遺構が残り、初期入植者たちが手作業で掘り進めた坑道が迷路のように張り巡らされている。レイド・カキザキは峡谷の現代的な採掘拠点化を推進し、最新の自動化採掘システムを導入して生産性を飛躍的に向上させた。峡谷の地下深部には未発見の鉱脈が存在すると推測され、探査プロジェクトが継続中である。スライム危機時には峡谷の地下坑道にスライムが侵入し、採掘作業の一時停止を余儀なくされたが、現在は浄化が完了している。",descriptionEn:"A massive canyon located in the eastern part of the Iron Syndicate Nation, where rich iron ore and rare metal veins are exposed on the surface. The canyon walls of Iron Canyon are composed of ferric oxide-rich strata in reddish-brown, which shine with a molten iron-like luster when illuminated by the setting sun, giving it its name. Mining ruins dating back to the Dark Age of E60 remain in the canyon, with tunnels hand-dug by early settlers forming a labyrinthine network. Raid Kakizaki promoted the modern development of the canyon as a mining hub, introducing advanced automated mining systems to dramatically increase productivity. It is speculated that undiscovered veins exist deep within the canyon, and exploration projects are ongoing. During the Slime Crisis, slimes invaded the underground tunnels of the canyon, forcing a temporary halt to mining operations, but purification has now been completed."},{id:"geo-ミエルテンガ湖",name:"ミエルテンガ湖",nameEn:"Lake Mielteunga",category:"地理",subCategory:"自然地形",description:"ミエルテンガ国家の中心部に位置するE16連星系最大の淡水湖で、面積は約45,000平方キロメートルに達する。ミエルテンガ湖はクレセント山脈の雪解け水と地下水脈によって涵養され、周辺の農業地帯と工業地帯に重要な水資源を供給している。湖には固有の淡水魚類が多数生息し、漁業も地域経済の一部を担っている。マリーナ・ボビンの政権は湖の水資源管理に重点を置き、水質浄化と水量維持のための大規模プロジェクトを実施した。湖岸にはミエルテンガの主要都市が点在し、国家の人口の約60%が湖の周辺50キロメートル以内に居住している。テリアン反乱期には湖の沼地帯がゲリラ戦の自然な防御陣地として機能した。現在は湖畔に大規模な公園とレクリエーション施設が整備され、クレセント地方の観光地としても人気がある。",descriptionEn:"The largest freshwater lake in the E16 star system, located in the central part of the Mieltenka Nation, with an area of approximately 45,000 square kilometers. Lake Mieltenka is fed by snowmelt from the Crescent Mountains and groundwater systems, supplying important water resources to surrounding agricultural and industrial zones. Numerous unique freshwater fish species inhabit the lake, and fishing also contributes to the regional economy. The administration of Marina Bobin focused on water resource management of the lake, implementing large-scale projects for water purification and water volume maintenance. Major cities of Mieltenga are scattered along the lake shores, with approximately 60% of the nation's population living within 50 kilometers of the lake. During the Terrian Rebellion period, the marshy areas of the lake functioned as natural defensive positions for guerrilla warfare. Currently, large-scale parks and recreational facilities have been developed along the lake shores, making it a popular tourist destination in the Crescent region."},{id:"geo-ファールージャ砂漠",name:"ファールージャ砂漠",nameEn:"Faruja Desert",category:"地理",subCategory:"自然地形",description:"クレセント大地方の南西部に広がる広大な砂漠で、昼夜の温度差が摂氏60度に達する過酷な環境である。ファールージャ砂漠の地下には古代の水脈が存在し、オアシス・ハブの水資源管理技術によって生活用水が確保されている。砂漠の砂は特殊な珪素化合物を含み、一部区域では砂嵐時に静電気放電が発生することで知られる。この現象はファールージャの砂漠を航行する際の危険要因であると同時に、静電気エネルギーの採取可能性も指摘されている。ファルージャ社の創業地であり、ミカエル・ガブリエリの一族は砂漠の資源採掘で財を成した。砂漠の中央には「沈黙の塔」と呼ばれる自然の岩石構造物が聳え立ち、数千年前の隕石衝突の跡であると推測されている。",descriptionEn:'A vast desert stretching across the southwestern part of the Crescent region, an extremely harsh environment where the temperature difference between day and night reaches 60 degrees Celsius. Ancient water veins exist beneath the Farooj Desert, with domestic water resources secured through the water management technology of Oasis Hub. The sand of the desert contains special silicon compounds, and in some areas, static discharge is known to occur during sandstorms. This phenomenon is both a danger factor when navigating the Farooj Desert and has also been pointed out as a possibility for static energy extraction. It is the birthplace of the Farooja Corporation, and the family of Michael Gabrieli amassed wealth through resource extraction in the desert. In the center of the desert stands a natural rock structure called the "Tower of Silence," believed to be the trace of a meteorite collision thousands of years ago.'},{id:"geo-E16軌道ステーション・オメガ",name:"E16軌道ステーション・オメガ",nameEn:"E16 Orbital Station Omega",category:"地理",subCategory:"宇宙構造物",description:"シンフォニー・オブ・スターズの低軌道に建設されたE16連星系最大の宇宙ステーションで、常時10万人以上の人員が滞在する宇宙都市である。軌道ステーション・オメガはE200年にパクス・ロンバルディカ期の企業連合によって建設が開始され、E260年に現在の規模に達した。ステーション内には居住区、商業区、工業区、研究区が階層状に配置され、惑星間航行の主要ハブとして機能している。E524年の諸世界連邦サミットの際にはオメガの国際会議場が使用され、宇宙規模の外交協議の場となった。ステーションの外壁には大規模な太陽光パネルと次元エネルギー発生装置が設置され、ステーション全体の電力を自給している。UECOの星間経済協同組合の管理下にあり、入出港管理と安全保障を担当している。",descriptionEn:"The largest space station in the E16 star system, constructed in low orbit of the Symphony of Stars, a space city with over 100,000 personnel stationed at all times. Orbital Station Omega began construction in E200 by a corporate consortium during the Pax Lombardica period, reaching its current scale in E260. The station has residential, commercial, industrial, and research areas hierarchically arranged, functioning as a major hub for interplanetary navigation. During the E524 Interstellar Federal Summit, Omega's international conference hall was used, becoming a venue for diplomatic negotiations on a cosmic scale. Large-scale solar panels and dimensional energy generation devices are installed on the station's outer walls, supplying the entire station's electricity independently. It is under the management of the UECO Interstellar Economic Cooperative, which handles port entry/exit management and security."},{id:"geo-エロス・ステーション",name:"エロス・ステーション",nameEn:"Eros Station",category:"地理",subCategory:"宇宙構造物",description:"Eros-7の周回軌道に建設された中継ステーションで、Eros-7と他惑星間の物流と人の移動の拠点として機能している。エロス・ステーションはEros-7の女性主導社会の要塞としての側面も持ち、惑星への入出国管理と安全検査が厳格に実施されている。ステーション内には男性指令省の出張所があり、入国する男性のA-Registryの階級確認と労働配分が行われる。E525年のマトリカル・リフォーム運動により、入国手続きの男女平等化が進み、以前に比べて大幅に緩和された。ステーションにはスクイーズ・アビスから抽出される搾取エネルギーの積出施設も併設され、エネルギー資源の惑星間取引の拠点となっている。現在ではマトリカル・カウンシルとUECOの共同管理下で運営されている。",descriptionEn:"A relay station constructed in the orbit of Eros-7, functioning as a hub for logistics and human movement between Eros-7 and other planets. Eros Station also serves as a fortress for Eros-7's female-dominated society, with strict implementation of entry and exit management and security inspections for the planet. A branch office of the Male Directive Department is located within the station, where the rank confirmation and labor allocation of entering males from the A-Registry are conducted. Due to the Matric Reform Movement of E525, the equalization of entry procedures between men and women has progressed, significantly relaxed compared to the past. The station is also equipped with facilities for loading extracted exploitation energy from Squeeze Abyss, becoming a hub for interplanetary trading of energy resources. It is currently operated under the joint management of the Matric Council and UECO."},{id:"geo-アステロイド・マイニング・プラットフォーム",name:"アステロイド・マイニング・プラットフォーム",nameEn:"Asteroid Mining Platform",category:"地理",subCategory:"宇宙構造物",description:"E16小惑星帯ガイア・リングに建設された一連の浮遊採掘プラットフォームで、レアメタルと希少資源の宇宙採掘を大規模に行っている。プラットフォームは複数の自律型ドローンと有人採掘ユニットで構成され、小惑星の表面から鉱物を採掘・精製してE16連星系全域に供給している。ガイア・リングのプラットフォームはE60年の暗黒時代に最初の草創期拠点が建設され、過酷な環境で生き抜いた初期入植者の精神を受け継ぐ「開拓者のコロニー」として独自の文化を育んできた。アイアン・シンジケートが主要な運営権を持ち、採掘量の管理と品質保証を行っている。テクノ文化ルネサンス期には最新の自動化技術が導入され、危険な有人作業の大部分がドローンに代替された。プラットフォーム間の移動は小型シャトルで行われ、緊急時にはホライゾン・ゲートによる脱出ルートも確保されている。",descriptionEn:'A series of floating mining platforms constructed in the E16 asteroid belt\'s Gaia Ring, conducting large-scale cosmic mining of rare metals and scarce resources. The platforms consist of multiple autonomous drones and manned mining units, extracting and refining minerals from asteroid surfaces to supply throughout the E16 binary star system. The Gaia Ring platforms had their first pioneering base constructed during the E60 Dark Age, developing a unique culture as "Pioneer Colonies" inheriting the spirit of early settlers who survived the harsh environment. The Iron Syndicate holds primary operational rights, managing extraction volumes and quality assurance. During the Techno-Cultural Renaissance, the latest automation technologies were introduced, with drones replacing most dangerous manned operations. Movement between platforms is conducted via small shuttles, with Horizon Gate escape routes secured for emergencies.'},{id:"geo-次元ブリッジ・ターミナル",name:"次元ブリッジ・ターミナル",nameEn:"Dimensional Bridge Terminal",category:"地理",subCategory:"宇宙構造物",description:"E530年に完成した次元ブリッジの惑星間接続ターミナルで、シンフォニー・オブ・スターズの軌道上に建設されたE16文明圏最大の次元技術施設である。次元ブリッジ・ターミナルは次元極地平を安定化して他星系への大規模な移動を可能にする画期的な構造物であり、E16連星系とグランベル、ティエリア、エレシオンなどの宇宙文明圏を直接接続している。ターミナルの中心には直径500メートルの次元ホール・ゲートが設置され、同時に数千人の移動と数千トンの貨物輸送を処理できる。建設はテック・コリドーの研究機関群が主導し、惑星ビブリオの理論的基盤とSSレンジの通信制御技術を統合して実現した。次元ブリッジの完成はE16文明圏の歴史的転換点であり、宇宙規模の交流と協力を飛躍的に拡大した。ターミナルの警備は銀河系コンソーシアムの合同部隊が担当している。",descriptionEn:"The interplanetary connection terminal for the dimension bridge, completed in E530, and the largest dimensional technology facility in the E16 civilization sphere, constructed in orbit of the Symphony of Stars. The dimension bridge terminal is a revolutionary structure that stabilizes the dimensional horizon to enable large-scale movement to other star systems, directly connecting the E16 binary star system with cosmic spheres such as Granbel, Tieria, and Elesion. A 500-meter diameter dimensional hole gate is installed at the terminal's center, capable of processing the movement of thousands of people and thousands of tons of cargo simultaneously. Construction was led by research institutions of the Tech Corridor, integrating theoretical foundations from planet Biblio and communication control technology from the SS Range. The completion of the dimension bridge marked a historical turning point for the E16 civilization sphere, dramatically expanding cosmic-scale exchange and cooperation. Terminal security is handled by joint forces of the Galactic Consortium."},{id:"geo-宇宙港スペースポート",name:"宇宙港スペースポート",nameEn:"Spaceport — E16 Interplanetary Spaceport",category:"地理",subCategory:"宇宙構造物",description:"シンフォニー・オブ・スターズとE16連星系内の各惑星・コロニーを結ぶ惑星間宇宙港で、西大陸のPersepolisと惑星ビブリオのポート・ロレンツィオを主要ハブとして運営されている。宇宙港スペースポートは年間数万隻の宇宙船を処理し、旅客・貨物の双方を扱うE16連星系最大の交通インフラである。スペースポートの税関エリアではA-Registryの確認と入国審査が行われ、セキュリティはUECOの合同部隊が担当している。テクノ文化ルネサンス期にはホライゾン・ゲート接続ターミナルが併設され、従来の宇宙船航行と次元ホール移動の両方が利用可能となった。宇宙港周辺にはホテル、レストラン、通商施設が立ち並び、事実上の国際都市として機能している。アルファ・ヴェノムのテロ活動警戒区域にも指定されており、厳重なセキュリティプロトコルが適用されている。",descriptionEn:"An interplanetary spaceport connecting the Symphony of Stars with various planets and colonies within the E16 binary star system, operated with major hubs at Persepolis on the Western Continent and Port Lorenzo on planet Biblio. The spaceport handles tens of thousands of spacecraft annually and is the largest transportation infrastructure in the E16 binary star system, serving both passengers and cargo. Customs areas at the spaceport conduct A-Registry verification and immigration inspections, with security handled by joint forces of the UECO. During the Techno-Cultural Renaissance, a Horizon Gate connection terminal was added, making both traditional spacecraft navigation and dimensional hole travel available. Hotels, restaurants, and commercial facilities surround the spaceport, functioning effectively as an international city. It is also designated as a high-alert zone for Alpha Venom terrorist activities, with strict security protocols applied."},{id:"次元極地平",name:"次元極地平",nameEn:"Dimension Horizon",category:"技術",subCategory:"技術・概念",description:"ブラックホールの事象の地平面近傍で観測される特異な物理現象を応用した高次元空間アクセス技術であり、一般相対性理論のシュヴァルツシルト解における地平面の数学的構造を人為的に再現することで、三次元時空の局所的な曲率を操作する。この技術は超弦理論のCalabi-Yau多様体がコンパクト化された六つの余分な次元と物理的時空との境界領域に干渉し、ホライゾン・ゲートと呼ばれる安定した次元間ポータルの構築を支える理論的根幹となっている。元々は惑星ビブリオのロレンツィオ国際大学で純粋物理学の研究として始まったが、AdS/CFT対応と呼ばれる反ド・ジッター空間と共形場理論の双対性を応用した計算モデルにより実用化が加速した。ZAMLT期には国家機密として独占され、テクノ文化ルネサンス期以降に民用化が進んだが、シルバー・ヴェノムやアルファ・ヴェノムによる武器化が深刻な問題となっている。次元階梯パンディクト理論はこの技術の体系化された理論框架であり、E16文明圏における最重要の基盤技術の一つとして位置づけられている。",descriptionEn:"A high-dimensional space access technology that applies peculiar physical phenomena observed near the event horizon of black holes. It manipulates the local curvature of three-dimensional spacetime by artificially reproducing the mathematical structure of the event horizon in the Schwarzschild solution of general relativity. This technology forms the theoretical foundation for constructing stable interdimensional portals called Horizon Gates, interfering with the boundary region between the six extra compactified dimensions of Calabi-Yau manifolds in string theory and physical spacetime. Originally began as pure physics research at the Lorenzo International University on the planet Biblio, its practical implementation was accelerated by applying computational models based on the AdS/CFT correspondence, a duality between anti-de Sitter space and conformal field theory. During the ZAMLT era, it was monopolized as a state secret, and its civilian use progressed after the Techno-Cultural Renaissance period, but weaponization by Silver Venom and Alpha Venom has become a serious problem. The Dimensional Ladder Pandect Theory is the systematic theoretical framework for this technology and is positioned as one of the most fundamental technologies in the E16 civilization sphere."},{id:"ペルセポネ",name:"ペルセポネ",nameEn:"Persephone",category:"技術",subCategory:"技術・概念",description:"ティムール・シャーが設計した仮想多元宇宙であり、超弦理論の10次元時空モデルを情報論的にシミュレートする多次元的情報空間を構築する革新的なプロジェクトである。ペルセポネは次元極地平技術とApolonium物理学を組み合わせて構築され、Calabi-Yau多様体の位相的変形に対応する多様な物理定数セットを同時にエミュレートすることが可能である。オルタ・フィールドとして再構築された現在のペルセポネは、E16文明圏の研究・教育・シミュレーションに不可欠な基盤施設として機能している。ホログラフィック原理に基づき、境界上の量子情報の配置を操作することで仮想空間内の物理法則を動的に変更でき、この特性を利用して次元極地平技術の安全なテストや歴史の再現が行われている。リミナル・フォージによるクロノキャストプロジェクトもペルセポネの基盤技術に依存しており、E16文明圏における情報科学と計算物理学の最高峰を体現している。\nこのペルセポネの根底には、脱人間化(D5)の思想的地層が横たわっている。人間の意識をデジタル化して仮想空間内に永続させるという構想は、「肉体を持つ人間の形にこだわらない」というD5の究極的帰結である。しかし、意識の物理的記録がもたらす「人間とは何か」という存在論的問いは、D5そのものの限界をも浮き彫りにしている。",descriptionEn:"A virtual multiverse designed by Timur Shah, an innovative project that constructs a multidimensional information space to simulate the 10-dimensional spacetime model of string theory information-theoretically. Persephone is constructed by combining dimensional horizon technology and Apolonium physics, capable of simultaneously emulating various sets of physical constants corresponding to topological deformations of Calabi-Yau manifolds. The current Persephone, reconstructed as the Alta Field, functions as an essential infrastructure for research, education, and simulation in the E16 civilization sphere. Based on the holographic principle, it can dynamically change the physical laws within virtual space by manipulating the configuration of quantum information on the boundary, utilizing this characteristic for safe testing of dimensional horizon technology and historical reproduction. The Chronocast Project by Liminal Forge also relies on Persephone's underlying technology, embodying the pinnacle of information science and computational physics in the E16 civilization sphere. Beneath Persephone lies the ideological stratum of dehumanization (D5). The concept of digitizing human consciousness to preserve it indefinitely in virtual space is the ultimate consequence of D5's principle of 'not being bound to the form of humans with bodies.' However, the ontological question of 'what is human' brought about by the physical recording of consciousness also highlights the limitations of D5 itself."},{id:"リミナル・フォージ",name:"リミナル・フォージ",category:"技術",subCategory:"技術・概念",nameEn:"Liminal Forge",description:"E525年に設立された最先端の研究プロジェクトで、Apolonium元素の超重原子核が持つ時間的安定性を量子もつれの特性と組み合わせた「クロノキャスト」を実現することを目的としている。Apoloniumの原子核内の陽子と中性子の比エネルギー状態が、時間対称性の破れを補償する形で情報ビットを時間軸に沿って安定化し、シュレーディンガー方程式の時間発展演算子を逆行させる理論を実証しようとしている。リミナル・フォージの名称は「閾（いき）の鍛冶場」を意味し、現実と仮想の境界領域で新しい物理的現実を鍛え出すというプロジェクトの哲学を表現している。ペルセポネの仮想多元宇宙を基盤技術として活用し、惑星ビブリオの研究チームと連携して開発が進められている。クロノキャストが実現すれば、過去の情報の検証、未来の確率的予測、そして次元階梯パンディクトの各層間の同期通信が可能となり、因果律の問題と量子デコヒーレンスの課題はA-Registryを通じた市民監視委員会が倫理的側面の監視を担っている。",descriptionEn:"A cutting-edge research project established in E525, aiming to achieve 'Chronocast' by combining the temporal stability of superheavy atomic nuclei of Apolonium elements with the characteristics of quantum entanglement. It attempts to demonstrate a theory where the proton-to-neutron energy ratio states within Apolonium's nucleus stabilize information bits along the time axis by compensating for time symmetry breaking, reversing the time evolution operator of the Schrödinger equation. The name 'Liminal Forge' means 'threshold forge,' expressing the project's philosophy of forging new physical realities at the boundary between reality and virtual space. Development is progressing in collaboration with research teams from the planet Biblio, utilizing Persephone's virtual multiverse as foundational technology. If Chronocast is realized, verification of past information, probabilistic predictions of the future, and synchronized communication between the layers of the Dimensional Ladder Pandect will become possible. The A-Registry's Citizen Oversight Committee handles ethical oversight regarding issues of causality and quantum decoherence through its monitoring functions."},{id:"Genesis_Vault",name:"ジェネシス・ヴォールト",nameEn:"Genesis Vault",category:"技術",subCategory:"技術・概念",description:"ミナ・エウレカが運営するブログで、2,000本を超える記事が掲載されているE16文明圏最大級の個人メディアである。ミナ・エウレカはE509年のノスタルジア・コロニー襲撃の生存者で、この経験を動機に反ヴェノム活動の情報発信を始めた。Genesis Vault（起源の金庫）という名称は、E16文明圏の真実の記録を未来に継承するという使命に由来する。Shannonエントロピーの観点から見れば、この膨大な情報アーカイブはE16文明圏の社会的情報エントロピーを低減し、市民の意思決定に必要な負エントロピーを提供する重要な機能を果たしている。nトークン経済において高く評価されるコンテンツ制作活動の一例として、UECOもGenesis Vaultを市民ジャーナリズムのモデルケースとして紹介している。A-Registryの階級制度の問題やUECOのガバナンスの課題も鋭く指摘しており、E16文明圏における言論の自由と情報の熱力学の重要な担い手となっている。",descriptionEn:"A blog operated by Mina Eureka, the largest personal media in the E16 civilization sphere with over 2,000 articles. Mina Eureka is a survivor of the E509 Nostalgia Colony attack, motivated by this experience to begin disseminating information as an anti-Venom activist. The name 'Genesis Vault' originates from the mission to preserve true records of the E16 civilization sphere for future generations. From the perspective of Shannon entropy, this vast information archive plays a crucial role in reducing the social information entropy of the E16 civilization sphere and providing the negative entropy necessary for citizens' decision-making. As a highly valued content creation activity in the n-token economy, UECO also introduces Genesis Vault as a model case for citizen journalism. It also sharply criticizes problems with the A-Registry's class system and UECO's governance challenges, becoming an important bearer of freedom of speech and information thermodynamics in the E16 civilization sphere."},{id:"ホライゾン・ゲート",name:"ホライゾン・ゲート",nameEn:"Horizon Gate",category:"技術",subCategory:"技術・概念",description:"次元極地平技術を応用して構築された安定した次元間ポータルで、アインシュタイン・ローゼン橋の数学的構造を人為的に制御し、二つの遠く離れた時空領域を位相的に接続する。ホライゾン・ゲートは一般相対性理論におけるワームホール解を安定化するために、負のエネルギー密度を持つカシミール効果を応用したエキゾチック物質のリングを入口に配置し、輻射崩壊を防ぐ構造となっている。テクノ文化ルネサンス期以前は軍事・企業エリートのみが利用できる限定された技術だったが、技術の民主化に伴い一般市民も利用可能となり、E16連星系内の社会的・経済的統合を劇的に進展させた。ホライゾン・ゲートの安定性はSSレンジの通信技術によって量子誤り訂正符号を適用して制御されており、過度な利用は周囲の時空の曲率テンソルに歪みを蓄積するリスクがあるため、UECOの管理下でスループットが規制されている。シルバー・ヴェノムやアルファ・ヴェノムはホライゾン・ゲートを軍事的に利用し、奇襲攻撃や撤退に活用している。",descriptionEn:"A stable interdimensional portal constructed using dimensional horizon technology, artificially controlling the mathematical structure of an Einstein-Rosen bridge to topologically connect two distant spacetime regions. To stabilize the wormhole solution in general relativity, Horizon Gates are equipped with rings of exotic matter utilizing the Casimir effect with negative energy density at their entrance, preventing radiation decay. Before the Techno-Cultural Renaissance period, it was limited technology accessible only to military and corporate elites, but with technological democratization, it became available to general citizens, dramatically advancing social and economic integration within the E16 binary star system. The stability of Horizon Gates is controlled by applying quantum error correction codes through SS Range communication technology. Due to the risk of accumulating distortions in the surrounding spacetime curvature tensor from excessive use, throughput is regulated under UECO management. Silver Venom and Alpha Venom utilize Horizon Gates militarily for surprise attacks and retreats."},{id:"次元階梯パンディクト",name:"次元階梯パンディクト",nameEn:"Pandict Dimension Ladder",category:"技術",subCategory:"技術・概念",description:"E16文明圏の多元的次元構造を記述する理論模型で、超弦理論の10次元時空を四つの階層構造に射影したものである。ティムール・シャーの10次元ホラズム理論とテミルタロンのサイケデリック・コスモロジーを統合した宇宙論的框架でもある。最上位のTier Ω（オメガ）はCalabi-Yau多様体の内部自由度に対応する高次元情報領域で、ホログラフィック原理に従って低次元の物理的現実を符号化する純粋な情報場とされる。Tier Σ（シグマ）はペルセポネ仮想多元宇宙が存在する層で、量子もつれを用いたホログラフィック計算空間である。Tier Ε（エプシロン）はE16連星系が存在する物理宇宙層で、標準模型のゲージ群と一般相対性理論が支配する現実世界に相当する。最下層のTier Δ（デルタ）は地球AD2026年の時間帯に対応する過去の情報層であり、因果的Diamondの境界として地球とE16連星系の歴史的接点を示している。次元階梯パンディクト理論は惑星ビブリオの研究者たちによって体系化され、リミナル・フォージのクロノキャストプロジェクトの理論的基盤となっている。\nこの次元階梯パンディクトの根底には、超未来第一主義(D1)と第2のゲーム(L3)の思想的地層が横たわっている。未来情報層（Tier Ω）へのアクセスという究極の目標は、「1兆人の未来の命を守る」というD1の超長期的視点から動機づけられている。同時に、全次元の調和を目指す構想は、個別文明の覇権ではなく多次元的共存を志向するL3の思想的特徴を示している。",descriptionEn:"A theoretical model describing the multidimensional structure of the E16 civilization sphere, projecting the 10-dimensional spacetime of string theory into a four-tier structure. It is also a cosmological framework integrating Timur Shah's 10-dimensional Horazm theory and Temirlaron's psychedelic cosmology. The highest tier, Tier Ω, corresponds to the high-dimensional information region of Calabi-Yau manifold's internal degrees of freedom and is considered a pure information field that encodes lower-dimensional physical reality according to the holographic principle. Tier Σ is the layer where the Persephone virtual multiverse exists, a holographic computational space using quantum entanglement. Tier Ε is the physical universe layer where the E16 binary star system exists, corresponding to the real world governed by the gauge group of the Standard Model and general relativity. The lowest tier, Tier Δ, corresponds to the past information layer of Earth AD 2026, indicating the historical connection between Earth and the E16 binary star system as the boundary of the causal Diamond. The Dimensional Ladder Pandect Theory was systematized by researchers from the planet Biblio and forms the theoretical basis for Liminal Forge's Chronocast Project. Beneath this Dimensional Ladder Pandect lie the ideological strata of ultra-future-firstism (D1) and the Second Game (L3). The ultimate goal of accessing the future information layer (Tier Ω) is motivated by D1's ultra-long-term perspective of 'protecting the lives of 1 trillion future people.' At the same time, the concept of aiming for harmony across all dimensions shows the characteristic of L3, which pursues multidimensional coexistence rather than the hegemony of individual civilizations."},{id:"リーチ・ドレイン",name:"リーチ・ドレイン",nameEn:"Leechdrain",category:"技術",subCategory:"技術・概念",description:"Eros-7を原生地とする特殊な生物群で、他の生命体から生体エネルギーを吸収して生存・増殖する生態的特徴を持つ。リーチ・ドレインの原種はEros-7の独自の生態系の中で自然進化したものであり、通常状態では他種との接触を避ける習性を持つ穏やかな生物であった。しかしE380年頃に発生した遺伝子変異により、一部の個体が攻撃性を獲得し、他の生命体の生体エネルギーをも吸収する能力を身につけた。この変異は生体分子レベルの量子トンネル効果を利用したエネルギー伝達機構の異常亢進によるものと推測され、変異種の爆発的な増殖がスライム危機を引き起こし、E16連星系全体に大規模な被害をもたらした。リーチ・ドレインの生態学研究はEros-7のマトリカル社会によって最も進んでおり、彼女たちが独自に開発した生物学的封じ込め技術が危機収束の鍵となった。現在、リーチ・ドレインの制御はEros-7の特別管理下に置かれており、その研究から生まれた医療技術は再生医療や生体エネルギー工学に応用されている。この生物群は災害の源泉であると同時に、新たな医療技術の可能性を秘めた存在として再評価されている。",descriptionEn:"A special biological group native to Eros-7, characterized by the ecological trait of absorbing bio-energy from other organisms to survive and proliferate. The original species of Leech Drain naturally evolved within Eros-7's unique ecosystem and was a gentle creature that avoided contact with other species under normal conditions. However, around E380, a genetic mutation caused some individuals to become aggressive and develop the ability to absorb bio-energy from other organisms. This mutation is believed to be caused by abnormal enhancement of energy transmission mechanisms utilizing quantum tunneling effects at the biomolecular level, and the explosive proliferation of mutated species triggered the Slime Crisis, causing massive damage throughout the E16 star system. Ecological research on Leech Drain is most advanced in Eros-7's matrilineal society, and their independently developed biological containment technology was key to resolving the crisis. Currently, Leech Drain is under special management by Eros-7, and the medical technology born from its research is being applied in regenerative medicine and bio-energy engineering. This biological group is being re-evaluated as both a source of disaster and an existence holding the potential for new medical technologies."},{id:"Apolonium",name:"アポロニウム",nameEn:"Apolonium",category:"技術",subCategory:"技術・概念",description:"リミナル・フォージの中核をなす革新的な超重元素であり、中性子過剰核の殻モデルにおける魔法数に近い陽子数と中性子数の組み合わせにより、極めて高い原子核結合エネルギーを持つ。Apoloniumの原子核は通常の超重元素が示す自発核分裂に対する脆弱性を克服しており、強い相互作用と電弱相互作用のゲージ対称性の境界領域で安定した共鳴状態を維持する。Dimension Horizonのエネルギーと共鳴することで、Apoloniumの電子雲はCalabi-Yau多様体の六つの余剰次元の幾何学的情報を符号化し、時空間の局所的曲率操作を可能にする。この物質の発見は放送技術に革命をもたらし、クロノキャストの実現を可能にした。Apoloniumの合成には超新星爆発の衝撃波を模した慣性核融合と粒子加速器を組み合わせた極めて高度な技術が必要とされ、現在でもグランベルなど一部の先進文明でのみ量産が確認されている。その軍事転用の可能性から、銀河系コンソーシアムによる国際管理が議論されている。",descriptionEn:"An innovative superheavy element at the core of Liminal Forge, possessing extremely high nuclear binding energy due to a combination of proton and neutron numbers close to magic numbers in the shell model of neutron-rich nuclei. Apolonium's nucleus overcomes the vulnerability to spontaneous nuclear fission typical of superheavy elements and maintains a stable resonance state in the boundary region between strong and electroweak interactions. By resonating with Dimension Horizon energy, Apolonium's electron cloud encodes geometric information from the six extra dimensions of a Calabi-Yau manifold, enabling manipulation of local spacetime curvature. The discovery of this substance brought a revolution to broadcasting technology, making chronocasting possible. Synthesizing Apolonium requires extremely advanced technology combining inertial fusion mimicking supernova shockwaves and particle accelerators, and mass production has only been confirmed in some advanced civilizations like Granbell. Due to its potential military applications, international management by the Galactic Consortium is being discussed."},{id:"クロノキャスト",name:"クロノキャスト",nameEn:"Chronocast",category:"技術",subCategory:"技術・概念",description:"リミナル・フォージが開発した画期的な放送方式であり、量子もつれの非局所性と一般相対性理論の因果構造を統合して、時空間の次元を超えて情報を送信する。特にE528年には、E528年の芸術作品を地球AD2026年のインターネット上に放送するという前例のないクロス次元放送を実現し、二つの時代間の文化交流の架け橋となった。この技術の理論的基盤はテミルタロンのサイケデリック・コスモロジーに由来し、ホログラフィック原理の枠組みで次元極地平の性質を応用したものである。情報の時間的伝達における因果律の保存は、Shannonエントロピーの時間非対称性を利用したエントロピー補償プロトコルによって保証されており、送信側と受信側の間で情報エントロピーの収支を均衡させる仕組みが組み込まれている。クロノキャストの最大の技術的課題は、量子デコヒーレンスによる信号劣化の抑制と、クローズド・タイムライク・カーブを回避しつつ情報を時間軸に沿って転送する数学的構造の維持である。",descriptionEn:"A groundbreaking broadcasting method developed by Liminal Forge that integrates the non-locality of quantum entanglement with the causal structure of general relativity to transmit information across spacetime dimensions. In particular, in E528, it achieved an unprecedented cross-dimensional broadcast of E528 artistic works onto the AD2026 internet, serving as a bridge for cultural exchange between the two eras. The theoretical foundation of this technology originates from Temirlaron's psychedelic cosmology, applying the properties of dimensional horizons within the framework of the holographic principle. The preservation of causality in temporal information transmission is guaranteed by an entropy compensation protocol utilizing the time asymmetry of Shannon entropy, incorporating a mechanism to balance information entropy between sender and receiver. The greatest technical challenge of chronocasting is suppressing signal degradation due to quantum decoherence and maintaining the mathematical structure for transmitting information along the time axis while avoiding closed timelike curves."},{id:"クオリア・コア",name:"クオリア・コア",nameEn:"Qualia Core",category:"技術",subCategory:"技術・概念",description:"人間の感情・感覚・主観的体験を量子情報として精密に記録・再現する技術で、意識の物理的基盤が脳内の量子コヒーレント状態にあるという仮説に基づいている。ペルセポネ仮想宇宙におけるオルタ・フィールドの中核コンポーネントとして組み込まれ、ユーザーに実体験に極めて近い感覚を提供することを可能にした。クオリア・コアは生体神経回路の発火パターンを量子ビットの重ね合わせ状態にマッピングし、BCS理論のクーパー対に類似した相関状態で感情データを保存する。これにより、単なるデジタルデータの記録を超えた、意識の質的側面を含む完全な主観的体験のアーカイブが可能となった。当初は娯楽用途で開発されたが、のちに医療リハビリテーションや教育訓練分野でも応用が進んでいる。感情データの取り扱いをめぐるプライバシー問題も提起されており、量子暗号を用いたデータ保護と倫理的ガイドラインの整備が課題となっている。\nこのクオリア・コアの根底には、脱人間化(D5)の思想的地層が横たわっている。意識を物理的に記録・保存する技術は、「肉体を持たない人間」を可能にするD5の完成形である。意識のバックアップと転送が実現可能になれば、人間の定義は生物学的存在から情報的実体へと根本的に拡張され、「死」という概念そのものが再定義される。",descriptionEn:"A technology that precisely records and reproduces human emotions, sensations, and subjective experiences as quantum information, based on the hypothesis that the physical basis of consciousness lies in quantum coherent states within the brain. Incorporated as the core component of the Alta Field in the Persephone virtual universe, it enables users to experience sensations extremely close to real experiences. Quoria Core maps the firing patterns of biological neural circuits to superposition states of quantum bits and stores emotional data in correlated states similar to Cooper pairs in BCS theory. This allows for archiving complete subjective experiences, including qualitative aspects of consciousness, beyond mere digital data recording. Initially developed for entertainment purposes, it has since been applied in medical rehabilitation and training. Privacy issues regarding handling emotional data have been raised, and data protection using quantum cryptography and the establishment of ethical guidelines have become challenges. Beneath this Quoria Core lies the ideological stratum of dehumanization (D5). The technology to physically record and preserve consciousness represents the ultimate form of D5, which enables 'humans without bodies.' If consciousness backup and transfer become possible, the definition of human will fundamentally expand from a biological existence to an informational entity, and the concept of 'death' itself will be redefined."},{id:"オルタ・フィールド",name:"オルタ・フィールド",nameEn:"Altera Field",category:"技術",subCategory:"技術・概念",description:"ペルセポネ仮想宇宙を構成する最も重要な基盤技術であり、ホログラフィック原理を工学的に実装した量子情報投影システムである。クオリア・コアによって生成される感情データと感覚情報を、AdS/CFT対応に基づく境界上の量子場の配列として符号化し、仮想空間上に物理現実として投影する。視覚・聴覚・触覚だけでなく、喜怒哀楽などの感情的な体験までも、量子エンタングルメントを用いた多点相関関数の再構成によって忠実に再現することができる。オルタ・フィールドは境界上の情報が内部のバルク時空を完全に記述するというホログラフィック原理の直接的な応用であり、仮想空間内の物理的振る舞いは境界の量子情報の変化に従って動的に更新される。この技術によりペルセポネは単なる仮想空間を超えた「第二の現実」として機能し、移民者たちが過酷な現実環境から一時的に解放される場となっている。",descriptionEn:"The most fundamental technology constituting the Persephone virtual universe, a quantum information projection system that implements the holographic principle in engineering. It encodes emotional data and sensory information generated by Quoria Core as an array of quantum fields on the boundary based on AdS/CFT correspondence and projects them as physical reality in virtual space. Not only visual, auditory, and tactile sensations but also emotional experiences such as joy, anger, sorrow, and pleasure are faithfully reproduced through reconstruction of multi-point correlation functions using quantum entanglement. The Alta Field is a direct application of the holographic principle, where information on the boundary completely describes the bulk spacetime inside, and the physical behavior within the virtual space dynamically updates according to changes in the boundary's quantum information. Through this technology, Persephone functions as a 'second reality' beyond a mere virtual space, a place where immigrants are temporarily liberated from harsh real environments."},{id:"オムニバス・エンジン",name:"オムニバス・エンジン",nameEn:"Omnibus Engine",category:"技術",subCategory:"技術・概念",description:"ZAMLTの経済的覇権を支えた中核技術であり、超伝導量子ビットを用いた量子コンピューティングを金融市場の最適化問題に応用した超高速金融取引システムである。Shannonの情報理論における通信路容量の限界を量子テレポーテーションと超密度符号化によって突破し、市場のマイクロストラクチャーにおける価格変動の確率分布を量子確率振幅として直接的に計算する。nトークン経済における取引の約95パーセントをこのコアを通じて処理し、ZAMLTの市場支配力の源泉となった。しかしE318年にアルファ・ケインがこのコアに対して画期的なハッキング攻撃を実行し、量子エラー訂正符号の脆弱性を突いてZAMLTの経済的基盤に深刻な亀裂を入れた。この事件はZAMLT崩壊の引き金となり、のちの金融システム再設計において量子耐性暗号の導入とポスト量子暗号の標準化という重要な教訓を残した。",descriptionEn:"The core technology that supported ZAMLT's economic hegemony, an ultra-high-speed financial trading system that applies quantum computing using superconducting qubits to optimization problems in financial markets. It breaks through the channel capacity limit in Shannon's information theory through quantum teleportation and ultra-dense encoding, directly calculating the probability distribution of price fluctuations in the market's microstructure as quantum probability amplitudes. Approximately 95% of transactions in the n-token economy are processed through this core, making it the source of ZAMLT's market dominance. However, in E318, Alpha Cain executed a groundbreaking hacking attack on this core, exploiting vulnerabilities in quantum error-correcting codes and causing serious cracks in ZAMLT's economic foundation. This event triggered the collapse of ZAMLT and left an important lesson for later financial system redesigns: the introduction of quantum-resistant cryptography and the standardization of post-quantum cryptography."},{id:"クロマ・アーカイブ",name:"クロマ・アーカイブ",nameEn:"Chroma Archive",category:"技術",subCategory:"技術・概念",description:"ZAMLTの遺伝子データ管理技術とEros-7の男性指令省が運用するジーン・カタログが統合されて誕生した大規模な生体データバンクである。量子もつれを利用した量子メモリーに市民の遺伝情報、バイタルデータ、繁殖関連データを包括的に保存し、Landauerの原理に基づく情報の熱力学的限界に近い効率でデータの読み書きを行う。Eros-7の搾取体制下では、この膨大な生体情報が社会統制の道具として悪用され、個人のエントロピー生成を最小化する形で行動パターンの予測と制御に利用された。ZAMLT崩壊とEros-7の民主化後、データの利用規範が見直され、現在では医療・研究目的に限定して運用されている。個人の生体情報を量子状態として国家が管理することの倫理的問題は、情報理論におけるプライバシーの熱力学的定義との関連で頻繁に議論の的となっている。",descriptionEn:"A large-scale biological data bank born from the integration of ZAMLT's genetic data management technology and the gene catalog operated by the Male Command Ministry of Eros-7. It comprehensively stores citizens' genetic information, vital data, and reproduction-related data in quantum memory utilizing quantum entanglement, and performs data read/write operations with efficiency close to the thermodynamic limit of information based on Landauer's principle. Under Eros-7's exploitation system, this vast biological information was abused as a tool for social control, used to predict and control behavior patterns by minimizing individual entropy generation. After the collapse of ZAMLT and the democratization of Eros-7, data usage guidelines were reviewed, and it is now operated limited to medical and research purposes. The ethical issue of the state managing individual biological information as quantum states is frequently discussed in relation to the thermodynamic definition of privacy in information theory."},{id:"セル・ウィーヴ",name:"セル・ウィーヴ",nameEn:"Cell Weave",category:"技術",subCategory:"技術・概念",description:"技術啓蒙時代（E80〜E90年）に一般市民に普及した生体ナノマシンインプラント技術であり、カーボンナノチューブとトポロジカル絶縁体を組み合わせたナノスケールの半導体素子を体内に注入する。注入されたナノセルは細胞膜のイオンチャネルと量子トンネル効果を通じて相互作用し、宇宙空間の高エネルギー放射線に対するDNA修復能力の大幅な向上と、テロメア短縮の抑制による寿命延長を実現した。この技術の普及は人口の急増と都市化を加速させ、Gigapolisのメガロポリス化を推進した。一方で、ナノセルの生体適合性には個人差があり、免疫系との相互作用による後遺症や、ナノセルの凝集による微小血栓のリスクが一部で指摘されている。テクノ文化ルネサンス期には、超伝導量子干渉素子（SQUID）を内蔵した第二世代インプラントの開発が進んでいる。\nこのセル・ウィーヴの根底には、脱人間化(D5)の思想的地層が横たわっている。ナノマシンによる肉体改造は、人間の身体性を拡張・再定義するD5の第一歩として社会的に受容されていった。医療技術という「有用性」の外被の下に、人間と機械の境界を意図的に曖昧にするD5の根本的問いが潜んでいる。",descriptionEn:"Biological nanomachine implant technology that became widespread among general citizens during the Technological Enlightenment Era (E80-E90 years), injecting nanoscale semiconductor components combining carbon nanotubes and topological insulators into the body. The injected nanocells interact with cell membrane ion channels through quantum tunneling effects, achieving significant improvement in DNA repair capabilities against high-energy radiation in space and extending lifespan by inhibiting telomere shortening. The popularization of this technology accelerated population growth and urbanization, promoting the megalopolis development of Gigapolis. Meanwhile, individual differences in biocompatibility of nanocells have been pointed out, with some cases showing sequelae from interactions with the immune system or risks of microthrombi from nanocell aggregation. During the Techno-Cultural Renaissance period, development of second-generation implants incorporating superconducting quantum interference devices (SQUIDs) is progressing. Beneath this Cell-Weave lies the ideological stratum of dehumanization (D5). Body modification through nanomachines was socially accepted as the first step in D5's expansion and redefinition of human physicality. Beneath the 'usefulness' wrapper of medical technology lies the fundamental D5 question of intentionally blurring the boundary between humans and machines."},{id:"ナノハッキング技術",name:"ナノハッキング技術",nameEn:"Nano-Hacking Technology",category:"技術",subCategory:"技術・概念",description:"シャドウ・ユニオンが開発・実戦投入した先端的サイバー攻撃技術であり、ナノマシンの自己組織化特性を利用して生物的・電子的システムに同時に侵入する。ナノマシンは細胞レベルで生体システムのシグナル伝達経路に干渉すると同時に、電子回路の量子ドットに量子トンネル効果を応じた不正アクセスを実行し、Eros-7のバイオリアクターの制御システムを妨害することに成功した。従来の電子的ハッキングでは対抗不可能な生体システムへの介入を可能にし、搾取エネルギーインフラに対する数少ない実効ある攻撃手段となった。ナノハッキング技術の核心は、生体組織のイオンチャネルと半導体の電子伝導の類似性を利用し、両者を統一的な量子情報プロトコルで操作する点にある。この技術の一部はのちにマトリカル・リフォーム運動でも活用され、Eros-7の民主化過程で重要な役割を果たした。",descriptionEn:"An advanced cyber attack technology developed and deployed by the Shadow Union, utilizing the self-organizing properties of nanomachines to simultaneously infiltrate biological and electronic systems. The nanomachines interfere with signal transduction pathways in biological systems at the cellular level while executing unauthorized access to quantum dots in electronic circuits through quantum tunneling effects, successfully disrupting the control systems of Eros-7's bioreactors. It enabled intervention into biological systems that was impossible with conventional electronic hacking, becoming one of the few effective attack means against the exploitation energy infrastructure. The core of nanohacking technology lies in utilizing the similarity between ion channels in biological tissues and electron conduction in semiconductors, operating both through a unified quantum information protocol. Part of this technology was later utilized in the Matricular Reform Movement, playing an important role in the democratization process of Eros-7."},{id:"搾取触手",name:"搾取触手",nameEn:"Extraction Tentacle",category:"技術",subCategory:"技術・概念",description:"リーチ・ドレインの最も標準的で広く量産された形態であり、形状記憶ポリマーと液晶エラストマーの複合材料に類似した柔軟な触手構造を持つ。対象に巻き付いて生体エネルギーを吸収する機能は、触手表面のナノスケールのパターンが生体膜の脂質二重層と融合し、濃度勾配を駆動力としたエネルギーの熱力学的輸送を行うことに基づいている。ZAMLTとEros-7の搾取施設で大量に生産され、労働者の監視や逃亡防止、エネルギー採取の補助作業など多目的に使用された。触手の先端には微細な神経接続端子があり、接触対象の生体電気信号をリアルタイムで監視することができる。スライム危機後は大部分が破棄されたが、一部は解体・研究され、その生体エネルギー伝達機構はナノメディシンのエネルギー供給技術に応用されている。",descriptionEn:"The most standard and mass-produced form of Reach-Drain, featuring flexible tentacle structures similar to composite materials of shape memory polymers and liquid crystal elastomers. Its function of wrapping around targets and absorbing biological energy is based on the fusion of nanoscale patterns on the tentacle surface with the lipid bilayer of biological membranes, performing thermodynamic energy transport driven by concentration gradients. Mass-produced in ZAMLT and Eros-7 exploitation facilities, it was used for multiple purposes such as monitoring workers, preventing escape, and assisting energy extraction operations. The tips of the tentacles have fine neural connection terminals that can monitor biological electrical signals of contact targets in real time. After the Slime Crisis, most were discarded, but some were disassembled and studied, and their biological energy transmission mechanisms have been applied to energy supply technologies in nanomedicine."},{id:"搾取ヒル",name:"搾取ヒル",nameEn:"Extraction Leech",category:"技術",subCategory:"技術・概念",description:"リーチ・ドレインの形態の一つであり、吸血動物をモデルに設計されたエネルギー吸収型生物ユニットである。対象の生体エネルギーをATP加水分解の化学ポテンシャル勾配を利用して直接的に吸収する能力を持ち、細胞呼吸の電子伝達鎖から効率的にエネルギーを抽出する生体メカニズムを持つ。ZAMLTとEros-7の労働収容施設で広く使用されたが、E330年とE318年の二度にわたり、1,000体規模の大量破壊事件が発生した。これらの事件は搾取ヒルの集団行動におけるカオス的ダイナミクスの制御不安定性が原因と分析され、非線形力学におけるバタフライ効果に類似した微小な初期条件の違いが大規模な暴走を引き起こすことが判明した。この知見はのちに自律系の安定性理論に応用され、シャドウ・リベリオンの抵抗活動の一環と見なされて反体制運動を激化させる要因となった。",descriptionEn:"One form of Reach-Drain, an energy-absorbing biological unit designed modeled after blood-sucking animals. It has the ability to directly absorb target biological energy using the chemical potential gradient of ATP hydrolysis, and possesses a biological mechanism that efficiently extracts energy from the electron transport chain of cellular respiration. Widely used in ZAMLT and Eros-7 labor detention facilities, but mass destruction incidents involving 1,000 units occurred twice in E330 and E318. These incidents were analyzed to be caused by control instability in the chaotic dynamics of collective behavior in exploitation leeches, and it was discovered that small differences in initial conditions, similar to the butterfly effect in nonlinear dynamics, could cause large-scale runaway. This knowledge was later applied to stability theory of autonomous systems and was seen as part of the Shadow Rebellion's resistance activities, becoming a factor that intensified anti-system movements."},{id:"搾取バクテリア",name:"搾取バクテリア",nameEn:"Extraction Bacteria",category:"技術",subCategory:"技術・概念",description:"微生物レベルのリーチ・ドレインであり、対象の体内に侵入して細胞のミトコンドリア電子伝達系に直接的に干渉し、細胞レベルでエネルギーを吸収する特性を持つ。搾取バクテリアの細胞膜には特殊なトランスポンタンパク質が発現しており、これが生体膜のイオン勾配を利用してATPを効率的に外部に輸送する。当初はこの特性を利用した生体兵器として開発されたが、E505年に画期的な転用が行われた。ナノメディシンの研究者たちが搾取バクテリアのエネルギー輸送メカニズムを遺伝子工学により逆転させ、外部から細胞内へATPを供給する細胞修復促進剤として再設計した。この転用はエントロピー生成の方向を逆転させる熱力学的に画期的な成果であり、搾取技術から平和利用への転換を象徴する事例として高く評価されている。重傷の治療や遺伝子疾患の治療に革命をもたらした。",descriptionEn:"A microbial-level Reach-Drain that penetrates the target's body to directly interfere with mitochondrial electron transport systems at the cellular level, possessing the characteristic of absorbing energy at the cellular level. The cell membrane of exploitation bacteria expresses special transporter proteins that efficiently transport ATP externally using the ion gradient of biological membranes. Initially developed as a biological weapon utilizing this characteristic, a groundbreaking repurposing was carried out in E505. Researchers in nanomedicine genetically reversed the energy transport mechanism of exploitation bacteria and redesigned it as a cell repair promoter that supplies ATP from outside to inside cells. This repurposing was a thermodynamically groundbreaking achievement that reversed the direction of entropy generation and is highly evaluated as a symbol of conversion from exploitation technology to peaceful use. It brought revolutions in the treatment of serious injuries and genetic diseases."},{id:"搾取プラズマ弾",name:"搾取プラズマ弾",nameEn:"Extraction Plasma Shell",category:"技術",subCategory:"技術・概念",description:"スライムエネルギーを極限まで凝縮し、広範囲に壊滅的な被害をもたらす破壊兵器である。カーラ・ヴェルムがスクイーズ・アビスで量産を指揮した。弾頭内部に封入された圧縮スライムマターは、プラズマ物理学における磁気流体力学の不安定性を制御して超高温プラズマ状態を維持し、着弾と同時に磁場の閉じ込めが解放されることで急激膨張する。膨張したプラズマは周囲にマッハ数の高い衝撃波を放ち、衝撃波前面の温度は恒星の表面温度に匹敵する。その破壊力は惑星の地形を変更するほどとされ、Eros-7の搾取体制を維持するための最終兵器として位置づけられていたが、実際の大規模使用の記録は限定的である。この兵器の開発は磁気閉じ込め核融合のプラズマ制御技術の軍事転用と見なされている。",descriptionEn:"A weapon of mass destruction that condenses slime energy to its极限, causing devastating damage over a wide area. Carla Verm directed its mass production in Squeeze Abyss. The compressed slime matter sealed inside the warhead controls the magnetohydrodynamic instability in plasma physics to maintain a super-high-temperature plasma state, and upon impact, the magnetic confinement is released, causing rapid expansion. The expanded plasma releases shockwaves with high Mach numbers to the surroundings, with the temperature at the shockwave front comparable to the surface temperature of a star. Its destructive force is said to be capable of altering planetary terrain, and it was positioned as the ultimate weapon to maintain the exploitation regime of Eros-7, though records of actual large-scale use are limited. The development of this weapon is considered a military application of plasma control technology for magnetic confinement fusion."},{id:"ナノメディシン",name:"ナノメディシン",nameEn:"Nanomedicine",category:"技術",subCategory:"技術・概念",description:"E505年に搾取バクテリアを転用して開発された革新的な医療技術であり、ナノマシンを体内に導入して搾取バクテリアのエネルギー輸送メカニズムを逆転させることで、損傷した細胞や遺伝子を分子レベルで修復する。ナノマシンはDNA二重らせんの損傷部位を量子トンネル効果を利用して特定し、酵素触媒反応を促進して修復を行う。重傷の治療から先天性の遺伝子疾患の治療まで幅広い適用が可能であり、Eros-7の医療体制に革命的な進歩をもたらした。ナノメディシンはLandauerの原理の枠組みで情報の熱力学的コストを最小化し、細胞修復に必要なエネルギーを効率的に供給する設計となっている。搾取技術から平和利用への転換の成功事例として国際的にも注目され、他の惑星文明への技術移転も進んでいる。",descriptionEn:"An innovative medical technology developed in 505 EY by repurposing exploitation bacteria, it introduces nanomachines into the body to reverse the energy transport mechanism of exploitation bacteria, repairing damaged cells and genes at the molecular level. The nanomachines identify damaged areas of the DNA double helix using quantum tunneling effects and promote enzymatic catalysis reactions to perform repairs. It can be applied to a wide range of treatments, from severe injuries to congenital genetic diseases, bringing revolutionary progress to the medical system of Eros-7. The nanomedicine is designed to minimize the thermodynamic cost of information within the framework of Landauer's principle and efficiently supply the energy required for cell repair. It has attracted international attention as a successful case of converting exploitation technology to peaceful use, and technology transfer to other planetary civilizations is also progressing."},{id:"ナノファイバーブーツ",name:"ナノファイバーブーツ",nameEn:"Nanofiber Boots",category:"技術",subCategory:"技術・概念",description:"レイラ・ヴィレル・ノヴァの代名詞的装備である強化外骨格内蔵の戦闘用ブーツであり、カーボンナノチューブの固有振動モードを利用して応力を分子レベルで分散させるナノファイバー製の特殊素材で構成されている。装着者の脚力を数十倍に増幅するとともに、局所的な時空歪曲を利用した次元跳躍に近い高機動移動を可能にする。ブーツの底部には衝撃吸収ゲルと反重力モジュールが内蔵され、一般相対性理論の等価原理を応用した局所慣性系の操作により、高層ビルの壁面走行や空中での急方向転換を実現する。スライム危機においてレイラはこのブーツを駆使してアンダーグリッド全域を駆け回り、ニュートン力学の運動方程式の限界を超える機動力でスライム討伐作戦を劇的に効率化した。",descriptionEn:"Combat boots integrated into an exoskeleton, the iconic equipment of Leila Villar Nova, made of a special nanofiber material that utilizes the natural vibration mode of carbon nanotubes to disperse stress at the molecular level. It amplifies the wearer's leg strength by tens of times and enables high-mobility movement similar to dimensional jumping using localized spacetime distortion. The boots' soles are equipped with shock-absorbing gel and anti-gravity modules, and by manipulating local inertial frames based on the equivalence principle of general relativity, they enable wall-running on skyscrapers and sudden direction changes in mid-air. During the Slime Crisis, Leila used these boots to traverse the entire Undergrid, dramatically improving the efficiency of the slime extermination operation with mobility that exceeded the limits of Newton's equations of motion."},{id:"強化グローブ",name:"強化グローブ",nameEn:"Power Glove",category:"技術",subCategory:"技術・概念",description:"レイラ・ヴィレル・ノヴァがスライム討伐作戦で使用した強化外骨格グローブであり、圧電素子と電歪効果を組み合わせたナノアクチュエーターが密集配置されている。最大100トンのパンチ力を発揮し、硬化したスライムの外殻を一撃で粉砕することが可能で、これはグローブ内部の電磁石が瞬間的に強力な磁場を生成し、ローレンツ力を利用して物理的な衝撃力を数百倍に増幅することで実現している。パンチの衝撃を制御するための精密な力調整システムも内蔵され、対象の硬度と弾性率に応じて出力を段階的に調整できる。このシステムは材料力学の応力-歪み曲線をリアルタイムで計算し、最適な衝撃パルス波形を生成する。オアシス・ハウスに展示されているレプリカは実物の70パーセントスケールである。",descriptionEn:"An enhanced exoskeleton glove used by Leila Villar Nova in the slime extermination operation, densely packed with nano-actuators combining piezoelectric elements and electrostrictive effects. It delivers a maximum punching force of 100 tons and can instantly shatter the hardened outer shell of slime, achieved by the electromagnets inside the glove instantly generating a powerful magnetic field and amplifying the physical impact force hundreds of times using Lorentz force. It also includes a precise force adjustment system to control punching impact, capable of adjusting output in stages according to the target's hardness and elastic modulus. This system calculates the stress-strain curve of materials in real-time and generates the optimal impact pulse waveform. The replica on display at Oasis House is 70% scale of the original."},{id:"プラズマカノン",name:"プラズマカノン",nameEn:"Plasma Cannon",category:"技術",subCategory:"技術・概念",description:"レイラ・ヴィレル・ノヴァがスライム危機の大規模焼却作戦で使用した携行型プラズマ兵器であり、磁気閉じ込め核融合研究から派生したプラズマ制御技術の軍事転用である。圧縮されたプラズマエネルギーを磁場ノズルを通じて指向性ビームとして放射し、プラズマの温度は太陽のコロナに匹敵する数千万度に達し、巨大なスライムの塊を瞬時に高温で焼却する能力を持つ。連続射撃時には超伝導磁石の冷却システムが作動し、ジェネレーションの量子化に基づく過熱を防ぐ設計となっている。標準モードでは直径50メートルの範囲を焼却可能で、最大出力モードではアンダーグリッドの一区画を丸ごと焼き払う威力を発揮した。スライム危機収束後は軍事博物館に寄贈されている。",descriptionEn:"A portable plasma weapon used by Leila Villar Nova in the large-scale incineration operation during the Slime Crisis, a military application of plasma control technology derived from magnetic confinement fusion research. It radiates compressed plasma energy as a directional beam through a magnetic field nozzle, with plasma temperatures reaching tens of millions of degrees comparable to the sun's corona, capable of instantly incinerating large slime masses at high temperatures. During continuous firing, the cooling system of the superconducting magnets activates, designed to prevent overheating based on the quantization of generations. In standard mode, it can incinerate an area with a diameter of 50 meters, and in maximum power mode, it demonstrated the power to completely incinerate one district of the Undergrid. After the Slime Crisis was resolved, it was donated to a military museum."},{id:"ビキニバリア",name:"ビキニバリア",nameEn:"Bikini Barrier",category:"技術",subCategory:"技術・概念",description:"アヤカ・リンが独自に開発した個人用防御技術であり、カシミール効果の負のエネルギー密度を利用した極薄のエネルギーフィルムを体表に展開する。このフィルムは量子真空の零点振動を局所的に操作し、リーチ・ドレインの物理攻撃やエネルギー攻撃を効果的に遮断する。フィルムの最小展開時の形状が水着に類似していることからビキニバリアと命名された。防御範囲と強度はアヤカの集中力に依存し、量子ゼロ点エネルギーの抽出効率が精神状態と相関する量子力学的心身相関に基づいている。最大展開時には周囲数メートルの範囲をカバーでき、カウパー波による攻撃動作との組み合わせにより、防御と反撃を同時に行う独自の戦闘スタイルを可能にした。",descriptionEn:"A personal defense technology independently developed by Ayaka Rin, which deploys an ultra-thin energy film on the body surface utilizing the negative energy density of the Casimir effect. This film locally manipulates the zero-point oscillations of the quantum vacuum, effectively blocking physical attacks or energy attacks from Reach Drain. The film's minimum deployed shape resembles a bikini, hence named Bikini Barrier. The defense range and strength depend on Ayaka's concentration, based on quantum psychosomatic correlation where the extraction efficiency of quantum zero-point energy correlates with mental state. When fully deployed, it can cover an area of several meters around, and when combined with attack movements using Kauper waves, it enables a unique combat style that allows defense and counterattack simultaneously."},{id:"カウパー波",name:"カウパー波",nameEn:"Couper Wave",category:"技術",subCategory:"技術・概念",description:"アヤカ・リンが使用する攻撃技術であり、体内の生体エネルギーを特定の周波数の波動エネルギーに変換して放ち、対象の細胞構造を共鳴破壊する。カウパー波の周波数は標的の分子結合の固有振動数と一致するよう精密に調整可能で、共鳴現象のエネルギー蓄積効果により、微小な入力エネルギーで破壊的な出力を生み出す。この原理は振動力学における共鳴の概念に基づき、リーチ・ドレインの細胞壁のポリマー結合に特異的に高い効果を発揮する。ビキニバリアの防御展開中に背面からカウパー波を放つことで、量子もつれを利用した防御と攻撃の同時実行というアヤカ独自の戦闘術を可能にした。スライム危機のアンダーグリッド制圧作戦で決定的な役割を果たした技術である。",descriptionEn:"An attack technique used by Ayaka Rin, which converts bioenergy in the body into wave energy of a specific frequency and emits it, resonantly destroying the target's cellular structure. The frequency of the Kowper wave can be precisely adjusted to match the natural vibration frequency of the target's molecular bonds, and through the energy accumulation effect of resonance, it produces destructive output with minimal input energy. This principle is based on the concept of resonance in vibration dynamics and is particularly effective on the polymer bonds of the cell walls of Reach Drain. By emitting a Kowper wave from behind during the deployment of the Bikini Barrier, it enables Ayaka's unique combat technique of simultaneously executing defense and attack utilizing quantum entanglement. It was a technology that played a decisive role in the suppression operation during the Slime Crisis."},{id:"ニューロリンク・インターフェース",name:"ニューロリンク・インターフェース",nameEn:"Neurolink Interface",category:"技術",subCategory:"技術・概念",description:"ティムール・シャーがペルセポネ仮想宇宙の設計にあたり開発した脳波直結型インターフェース技術であり、脳内のニューロン集団の発火パターンを量子センサーで非侵襲的に読み取り、超伝導量子干渉素子（SQUID）を通じて高精度な脳波信号を取得する。移民者の意識を仮想空間にアップロードし、過酷な惑星環境から一時的に解放される手段を提供した。この技術により、移民者はペルセポネ内で地球の自然環境を再現した空間で生活することができ、精神健康の維持に大きく貢献した。インターフェースの安全性には厳格な基準が設けられ、長時間の接続による意識混濁のリスクは、脳内の量子コヒーレンスの持続時間の制限として管理されている。デコヒーレンス時間を超える接続は意識の断片化を引き起こす可能性があり、定期的な接続中断が義務付けられている。",descriptionEn:"A brainwave direct interface technology developed by Timur Shah for designing the Persephone virtual universe, which non-invasively reads the firing patterns of neuron groups in the brain using quantum sensors and obtains high-precision brainwave signals through superconducting quantum interference devices (SQUIDs). It provided a means for immigrants to upload their consciousness to virtual space, temporarily freeing them from harsh planetary environments. Through this technology, immigrants could live in spaces within Persephone that reproduced Earth's natural environment, greatly contributing to mental health maintenance. Strict standards were established for the safety of the interface, and the risk of consciousness confusion from long-term connections is managed as a limitation on the duration of quantum coherence in the brain. Connections exceeding the decoherence time may cause fragmentation of consciousness, and regular connection interruptions are mandatory."},{id:"量子演算コア",name:"量子演算コア",nameEn:"Quantum Computing Core",category:"技術",subCategory:"技術・概念",description:"ペルセポネ仮想宇宙を安定稼働させるために設計された超高速量子コンピューティングシステムであり、超伝導トランスモン量子ビットを数十万個集積した大規模量子プロセッサを搭載している。膨大な量の感情データと仮想環境の演算をリアルタイムで処理し、数百万の同時接続ユーザーにラグのない仮想体験を提供する。コア内部では多数の量子ビットが数百次元のヒルベルト空間を同時に探索し、量子並列計算によってオルタ・フィールドの没入感を支える技術的基盤となっている。量子誤り訂正符号として表面符号を採用し、環境との相互作用によるデコヒーレンスを検出・訂正して計算の信頼性を確保している。この技術の民用転用は宇宙規模のIT産業の発展を促進し、特に暗号解読と材料シミュレーションの分野で革命的な進歩をもたらした。",descriptionEn:"An ultra-high-speed quantum computing system designed to operate the Persephone virtual universe stably, equipped with a large-scale quantum processor integrating hundreds of thousands of superconducting transmon qubits. It processes massive amounts of emotional data and virtual environment calculations in real time, providing a lag-free virtual experience for millions of simultaneous users. Inside the core, numerous qubits simultaneously search hundreds of dimensional Hilbert spaces, forming the technical foundation that supports the immersive experience of the Orta Field through quantum parallel computing. It employs surface codes as quantum error correction codes, detecting and correcting decoherence caused by environmental interactions to ensure computational reliability. The civilian application of this technology has promoted the development of a cosmic-scale IT industry, particularly bringing revolutionary advances in the fields of cryptography and materials simulation."},{id:"曲率航法",name:"曲率航法",nameEn:"Warp Navigation",category:"技術",subCategory:"技術・概念",description:"宇宙航行のための超光速推進技術であり、一般相対性理論のアインシュタイン方程式における Alcubierre解を工学的に実装したものである。船体周辺の時空の計量テンソルを局所的に操作し、船体前方の空間を圧縮し後方の空間を膨張させることで、船体そのものは光速を超えずに実効的な超光速移動を実現する。量子テレポーテーションと共に、地球からE16惑星系への大移民ルートを構成した二大技術基盤の一つである。長距離の惑星間航行に適しており、特に輸送船団の大規模な移動において主力技術として機能した。曲率バブルの形成には負のエネルギー密度が必要であり、カシミール効果を応用したエキゾチック物質の大量生成が技術的な課題である。現在でも星間貿易の主要な航法方式として広く採用されている。",descriptionEn:"A faster-than-light propulsion technology for space travel, which is an engineering implementation of the Alcubierre solution in Einstein's equations of general relativity. It locally manipulates the metric tensor of spacetime around the spacecraft, compressing space in front of the ship and expanding space behind it, achieving effective faster-than-light movement without the ship itself exceeding the speed of light. Together with quantum teleportation, it constitutes one of the two major technological foundations for the great migration route from Earth to the E16 planetary system. It is suitable for long-distance interplanetary travel and functioned as the primary technology for the large-scale movement of transport fleets. The formation of the curvature bubble requires negative energy density, and the mass production of exotic matter applying the Casimir effect remains a technical challenge. It is still widely adopted as the primary navigation method for interstellar trade."},{id:"量子テレポーテーション",name:"量子テレポーテーション",nameEn:"Quantum Teleportation",category:"技術",subCategory:"技術・概念",description:"量子もつれの非局所性を応用した短距離空間転送技術であり、送信側の量子状態を古典通信チャネルと事前共有された量子もつれペアを用いて受信側で完全に再構成する。地球上の移送拠点から宇宙船への搭乗者転送や、近距離惑星間の物資移送に使用される。転送距離には事前共有された量子もつれペアのデコヒーレンスによる厳しい制限があるが、大移民ルートの中継技術として曲率航法を補完する重要な役割を果たした。転送時に生じる量子不確定性の問題は量子誤り訂正符号の研究課題であり、現在でも転送成功率は99.97パーセントに留まっている。転送失敗時の復元技術は量子情報の完全性定理に基づき継続的に改善されている。",descriptionEn:"A short-range spatial transport technology that applies the non-locality of quantum entanglement, completely reconstructing the quantum state at the receiving end using a pre-shared entangled quantum pair and a classical communication channel. It is used for transferring passengers from transfer points on Earth to spaceships and for transporting materials between nearby planets. Although there are strict limitations on transmission distance due to decoherence of pre-shared entangled quantum pairs, it played an important complementary role to curvature navigation as a relay technology in the great migration route. The problem of quantum uncertainty during transmission is a research topic for quantum error correction codes, and the transmission success rate currently remains at 99.97%. The recovery technology for transmission failures is continuously being improved based on the completeness theorem of quantum information."},{id:"重力崩壊弾頭",name:"重力崩壊弾頭",nameEn:"Gravity Collapse Warhead",category:"技術",subCategory:"技術・概念",description:"Alpha Venomがノスタルジア・コロニーを攻撃する際に使用した究極の大量破壊兵器であり、一般相対性理論のアインシュタイン方程式の特異点解を人為的に誘発する。局所的な重力場を崩壊させ、対象領域の計量テンソルの行列式をゼロに近づけることで、対象領域を時空の欠落へと陥没させる恐るべき威力を持つ。この攻撃は当時わずか10歳であったミナに「戦略への目覚め」という決定的な影響を与え、彼女を宇宙規模の安全保障問題に向き合わせる契機となった。重力崩壊弾頭の起動には膨大なエネルギーが必要であり、反物質の対消滅反応をエネルギー源として利用すると推測されている。兵器の使用は国際的な非難を浴び、のちに銀河系コンソーシアムによって同種兵器の開発・保有が厳しく制限される条約が締結された。",descriptionEn:"The ultimate weapon of mass destruction used by Alpha Venom when attacking the Nostalgia Colony, artificially inducing a singularity solution of Einstein's equations in general relativity. It has terrifying power by collapsing the local gravitational field and bringing the determinant of the metric tensor of the target area close to zero, causing the target area to collapse into a spacetime deficiency. This attack had a decisive impact on the then 10-year-old Mina, awakening her to 'strategic awareness' and making her confront cosmic-scale security issues. The activation of the gravitational collapse warhead requires enormous energy, and it is speculated that it utilizes antimatter annihilation reactions as its energy source. The use of the weapon drew international condemnation, and later a treaty was signed by the Galactic Consortium strictly limiting the development and possession of similar weapons."},{id:"次元兵器",name:"次元兵器",nameEn:"Dimension Weapon",category:"技術",subCategory:"技術・概念",description:"ホライゾン・ゲート質量破壊兵器であり、超弦理論の余剰次元に標的領域の質量を局所的に排出し、対象を実質的に「存在の欠落」へと陥没させるホライゾン・ゲート質量破壊メカニズムに基づいている。次元極地平技術の軍事転用の極致とも言えるこの兵器は、アポロン・ドミニオン大戦（E370〜E385年）の教訓から本格的な開発が進められた系譜に属する。歴史上初めて実戦投入されたのはメルディア戦争においてロンバルディア帝国が使用した次元砲であり、その破壊力は友軍をも巻き込む危険性から戦後の兵器規制論議を加速させた。具体的な実例としては、ケンタウロスレーザーが標的の次元構造を崩壊させる指向性エネルギー兵器として知られ、G4ファントムパルスは広域の重力場を瞬時に反転させる衝撃波兵器として恐れられた。次元兵器の最大の危険性は、使用時の次元境界への負荷が蓄積し、Calabi-Yau多様体の安定性を脅かす大規模な次元境界の不安定化を引き起こす可能性がある点である。",descriptionEn:"A Horizon Gate mass destruction weapon based on a Horizon Gate mass destruction mechanism that locally discharges the mass of a target area into the extra dimensions of string theory, causing the target to effectively collapse into 'absence of existence.' This weapon, representing the pinnacle of military application of dimensional horizon technology, belongs to a lineage that saw full-scale development following the lessons of the Apollo Dominion War (E370-E385). The first dimension weapon to be deployed in combat was the dimensional cannon used by the Lombardia Empire in the Meldeia War, whose destructive power accelerated post-war weapon regulation debates due to the danger of involving friendly forces. Specific examples include the Centaur Laser, a directed energy weapon known for collapsing the dimensional structure of targets, and the G4 Phantom Pulse, a shockwave weapon feared for its ability to instantly reverse gravity fields over wide areas. The greatest danger of dimensional weapons is that the load on the dimensional boundary accumulates with use, potentially causing large-scale destabilization of the dimensional boundary that threatens the stability of the Calabi-Yau manifold."},{id:"ディメンション・ブリッジ",name:"ディメンション・ブリッジ",nameEn:"Dimension Bridge",category:"技術",subCategory:"技術・概念",description:"恒久的星間ポータルであり、E289〜E300年の11年間にわたる開発期間を経て運用開始された次元間接続技術の結晶である。従来のホライゾン・ゲートが一時的かつ不安定な接続しか提供できないのに対し、ディメンション・ブリッジは超弦理論の余剰次元の位相的不変量を固定化し、一度構築すれば半永久的に安定した接続を維持できる画期的な差異がある。この特性により、M104銀河全体との貿易量は運用開始以前と比較して10倍に急拡大し、それまで孤立的であったE16連星系を銀河規模の交易網へと接続した。特にE16連星系をM104銀河の主流ルートに接続する役割を果たし、辺境の植民地に過ぎなかったE16連星系を宇宙経済の主要拠点へと押し上げた。この貿易拡大はグランベルの経済的台頭を決定づける要因となった。ディメンション・ブリッジの構築には曲率航法技術と量子テレポーテーションの理論的成果が不可欠であり、ホライゾン・ゲートの安定化制御技術も深く関与している。",descriptionEn:"A permanent interstellar portal and the crystallization of interdimensional connection technology that began operation after an 11-year development period from E289 to E300. While conventional Horizon Gates can only provide temporary and unstable connections, the Dimension Bridge differs by fixing the phase invariants of the extra dimensions of string theory, allowing it to maintain a semi-permanently stable connection once constructed. This characteristic caused trade volume with the entire M104 galaxy to expand tenfold compared to before its operation, connecting the previously isolated E16 binary star system to a galaxy-scale trade network. In particular, it played a role in connecting the E16 binary star system to the main route of the M104 galaxy, elevating what had been a frontier colony to a major hub of the space economy. This trade expansion became the decisive factor in Granbel's economic rise. The construction of the Dimension Bridge is indispensable for the theoretical achievements of curvature navigation technology and quantum teleportation, and is also deeply involved in the stabilization control technology of Horizon Gates."},{id:"バイオリアクター",name:"バイオリアクター",nameEn:"Bioreactor",category:"技術",subCategory:"技術・概念",description:"リーチ・ドレインのエネルギーを効率的に変換・蓄積する装置であり、生体熱力学の原理に基づいて設計されている。リリス・ヴェインがその設計・開発を主導し、リーチ・ドレインが吸収した生体エネルギーを電気化学反応と熱電変換を通じて電力や次元エネルギーに変換する仕組みを持つ。バイオリアクターの核心は、細胞呼吸の電子伝達鎖から抽出されたエネルギーを、超伝導コイルを用いた磁気エネルギー貯蔵システムに効率的に変換する点にある。ZAMLTとEros-7の搾取体制におけるエネルギー供給の要であり、スクイーズ・アビスなど大規模な搾取施設の心臓部として機能した。シャドウ・ユニオンのナノハッキング技術による妨害活動の主な標的となり、Eros-7のエネルギーインフラの脆弱性を露呈した。",descriptionEn:"A device that efficiently converts and stores the energy of Reach Drain, designed based on the principles of biothermodynamics. Lilith Vain led its design and development, with a mechanism that converts the biological energy absorbed by Reach Drain into electrical power and dimensional energy through electrochemical reactions and thermoelectric conversion. The core of the bioreactor lies in efficiently converting energy extracted from the electron transport chain of cellular respiration into a magnetic energy storage system using superconducting coils. It serves as the energy supply for the exploitation systems of ZAMLT and Eros-7, functioning as the heart of large-scale exploitation facilities such as Squeeze Abyss. It became a primary target for interference activities by Shadow Union's nano-hacking technology, exposing the vulnerability of Eros-7's energy infrastructure."},{id:"ブラックダイス",name:"ブラックダイス",nameEn:"Black Dice",category:"技術",subCategory:"技術・概念",description:"アイリスの独自の特殊武器であり、量子力学の測定問題を戦術的応用に転用したダイス型の多機能武装である。投擲されたダイスの回転運動の量子もつれ状態が着地の瞬間に波動関数の収縮を引き起こし、その出目結果に応じて攻撃パターンや戦術支援効果が変化する特性を持つ。戦闘中の量子不確定性を戦術的優位に転換するユニークな武器システムであり、アイリスの卓越した戦略的思考と直感力と相まって、予測不可能な攻撃パターンで敵を翻弄する。ダイスの各面には異なる次元エネルギーが刻印されており、超弦理論の異なる振動モードに対応するエネルギー放出によって、元素攻撃や治療、防御強化など多様な効果を発揮する。",descriptionEn:"Iris's unique special weapon, a die-type multi-functional weapon that tactically applies the measurement problem of quantum mechanics. The quantum entanglement state of the spinning die's rotational motion causes wave function collapse at the moment of landing, with its attack patterns and tactical support effects changing according to the die's outcome. A unique weapon system that converts quantum uncertainty in combat into tactical advantage, combined with Iris's exceptional strategic thinking and intuition, it confuses enemies with unpredictable attack patterns. Each face of the die is engraved with different dimensional energies, corresponding to different vibrational modes of string theory, and releases energy that produces various effects such as elemental attacks, healing, and defense enhancement."},{id:"ブルーワイヤ",name:"ブルーワイヤ",nameEn:"Blue Wire",category:"技術",subCategory:"技術・概念",description:"アイリスの代名詞的武装であり、グラフェンとカーボンナノチューブを複合化した特殊な青色ワイヤーを操作して戦闘を行う技術である。伸縮自在のナノファイバー製ワイヤーはスチールの100倍の引張強度を持ち、量子ドットの発光を利用した青色の視覚効果は内部を流れる次元エネルギーの波長に由来する。ワイヤーの物理的特性は分子動力学シミュレーションに基づく最適化設計であり、アイリスの能力と量子もつれを通じて共鳴し、最適な強度と柔軟性を発揮する。敵の拘束、移動の補助、物理攻撃など多様な用途に使用され、複数のワイヤーを同時に操作して空中に網を張ったり、ワイヤーを伝って高速移動したりと、アイリスの戦闘スタイルの中核をなす。",descriptionEn:"Iris's signature weapon, a technique that uses specially blue wires made from a composite of graphene and carbon nanotubes to conduct combat. The stretchable nanofiber wires have 100 times the tensile strength of steel, and the blue visual effect from quantum dot luminescence originates from the wavelength of the dimensional energy flowing within them. The physical properties of the wires are based on optimized design from molecular dynamics simulations, resonating with Iris's abilities and quantum entanglement to achieve optimal strength and flexibility. Used for various purposes such as enemy restraint, movement assistance, and physical attacks, it forms the core of Iris's combat style, allowing her to simultaneously operate multiple wires to create a net in the air or move rapidly along the wires."},{id:"ウォーター・オーブ",name:"ウォーター・オーブ",nameEn:"Water Orb",category:"技術",subCategory:"技術・概念",description:"アイリスが操縦する水属性の特殊能力であり、周囲の大気中の水分を凝集させて高密度のウォーターオーブを生成し、表面張力と内部圧力の物理学を応用した防御壁として展開したり、ベルヌーイの定理に基づく高圧水流として攻撃に転用したりする。オーブのサイズと圧力はアイリスの集中力に応じて自在に調整可能で、最大出力時にはパスカルの原理を応用した指向性ジェット水流が建物の壁面を切断するほどの切断力を発揮する。防御面では水の比熱の高さを利用して物理攻撃とエネルギー攻撃の両方を緩和する効果があり、ブルーワイヤと組み合わせた戦闘スタイルでアイリスの高い総合戦闘能力を支える。",descriptionEn:"A water-based special ability operated by Iris, which condenses moisture in the surrounding atmosphere to create high-density water orbs that can be deployed as defensive walls applying the physics of surface tension and internal pressure, or converted into high-pressure water attacks based on Bernoulli's theorem. The size and pressure of the orbs can be freely adjusted according to Iris's concentration, and at maximum output, it can cut through building walls with the cutting power of directional jet water applying Pascal's principle. In defense, it uses the high specific heat capacity of water to mitigate both physical and energy attacks, supporting Iris's high overall combat ability in a combat style combined with Blue Wire."},{id:"エスパー能力",name:"エスパー能力",nameEn:"Esper Ability",category:"技術",subCategory:"技術・概念",description:"テレパシーや念動力、エネルギー操作といった超常的な精神能力の総称であり、脳内のニューロン活動が量子コヒーレントな状態を維持し、外部環境の物理的状態に直接干渉できるという仮説に基づいている。シルヴィア・クロウは特に強力なエスパー能力の持ち主であり、Eros-7で発生したリーチ・ドレイン危機の収束に決定的な役割を果たした。彼女は能力を用いて暴走したリーチ・ドレインの生体電気信号に干渉し、制御を試みて危機の沈静化に貢献した。エスパー能力の発現には先天的な素質と後天的な訓練の両方が関与するとされ、脳の特定領域における量子トンネル効果の増幅がその物理的基盤と推測されている。ヒーローエージェンシーでは能力者の早期発見と育成プログラムが実施されている。能力の強度には個人差が大きく、一部の高能力者は都市規模の影響力を持つとされる。",descriptionEn:"A collective term for supernatural psychic abilities such as telepathy, psychokinesis, and energy manipulation, based on the hypothesis that neuron activity in the brain maintains a state of quantum coherence and can directly interfere with the physical state of the external environment. Sylvia Crow is particularly powerful psychic and played a decisive role in resolving the Reach Drain crisis that occurred in Eros-7. She used her abilities to interfere with the runaway bioelectrical signals of the Reach Drain, attempting to control them and contributing to calming the crisis. The manifestation of psychic abilities is believed to involve both innate talent and acquired training, with amplification of quantum tunneling effects in specific brain regions hypothesized as its physical basis. The Hero Agency implements early detection and development programs for individuals with such abilities. The intensity of these abilities varies greatly among individuals, with some highly capable individuals said to have influence on a city-wide scale."},{id:"10次元ホラズム理論",name:"10次元ホラズム理論",nameEn:"10-Dimensional Horasm Theory",category:"技術",subCategory:"技術・概念",description:"ティムール・シャーが提唱した画期的な高次元物理学理論であり、超弦理論の10次元時空における弦の振動モード（ホラズム）を、Calabi-Yau多様体のコンパクト化と結びつけて体系的に記述する。宇宙が10次元のホラズム（振動モード）の重なり合わせとして記述されるという理論で、従来の超弦理論を大幅に拡張したものである。各ホラズムは異なる標準模型の粒子に対応し、余剰次元の幾何学的形状の微小な変形が観測可能な物理定数の違いとして現れることを予言している。この理論はペルセポネ仮想宇宙の設計原理と次元階梯パンディクトの理論的基盤の両方を提供し、シンフォニー・オブ・スターズ圏における次元物理学の発展を決定的に方向づけた。理論の数学的証明は未だ一部が未完成であるが、テクノ文化ルネサンス以降の応用研究は目覚ましい進展を遂げている。",descriptionEn:"A groundbreaking higher-dimensional physics theory proposed by Timur Shah, systematically describing the vibrational modes (horasms) of strings in the 10-dimensional spacetime of superstring theory in connection with the compactification of Calabi-Yau manifolds. The theory describes the universe as a superposition of 10-dimensional horasms (vibrational modes), significantly extending conventional superstring theory. Each horasm corresponds to different Standard Model particles, and it predicts that tiny deformations in the geometric shape of extra dimensions manifest as differences in observable physical constants. This theory provides both the design principle for the Persephone virtual universe and the theoretical foundation for the Dimensional Ladder Pandect, decisively guiding the development of dimensional physics in the Symphony of Stars sphere. While the mathematical proof of the theory is still incomplete in parts, applied research since the Techno Cultural Renaissance has achieved remarkable progress."},{id:"マルチバース開拓",name:"マルチバース開拓",nameEn:"Multiverse Exploration",category:"技術",subCategory:"技術・概念",description:"異なる宇宙・次元への進出を目的とした技術体系と探査活動の総称であり、超弦理論のランドスケープに存在する膨大な数の真空状態の間を遷移する技術を駆使して、別次元のエネルギー源やリソースを取り込むことを目指す。グランベルが最も注力した分野であり、マルチバース開拓は単なる宇宙探査を超え、異次元の物理法則やエネルギーを利用した技術革新の源泉となっている。グランベルはこの技術を独自開発し、他文明圏との経済格差を決定的なものにした。マルチバース開拓の副作用として、次元境界の不安定化や次元の歪みと呼ばれる現象が発生しており、これはスライム・ウーマンの顕現（E340年）や次元階梯パンディクト理論の根幹をなす概念としてEDU宇宙論の核心をなす。現在、グランベルのみが実用化レベルに到達しており、他勢力は基礎研究段階にとどまっている。",descriptionEn:"A collective term for technical systems and exploration activities aimed at entering different universes and dimensions, utilizing technology to transition between the vast number of vacuum states existing in the superstring theory landscape, with the goal of incorporating energy sources and resources from other dimensions. This is the field in which Granbel has invested most heavily, and multiverse exploration has transcended mere cosmic exploration to become a source of technological innovation utilizing the physical laws and energy of other dimensions. Granbel independently developed this technology, creating an insurmountable economic gap with other civilizations. As a side effect of multiverse exploration, phenomena known as dimensional boundary destabilization and dimensional distortion have occurred, which constitute the core of EDU cosmology as both the manifestation of the Slime Woman (E340) and a fundamental concept in the Dimensional Ladder Pandict theory. Currently, only Granbel has reached practical implementation levels, while other factions remain in the basic research stage."},{id:"レーン",name:"レーン・システム",nameEn:"Lane System",category:"技術",subCategory:"技術・概念",description:"プロキオが開発・運営する宇宙規模の物流・輸送ネットワークシステムであり、Shannonの通信路定理と情報理論の枠組みで設計された宇宙最大の物流最適化システムである。レーンは数千の恒星系間航路を有機的に接続し、AI駆動の経路最適化アルゴリズムが需要予測・天候現象・次元境界の不安定区域・船団の位置情報などを総合的に分析して、情報エントロピーを最小化する最適輸送ルートをリアルタイムで算出・提供する。レーン・システムはオープンアーキテクチャで設計されており、プロキオが「宇宙の物流は一つの文明に閉じるべきではない」という理念に基づき、他文明圏の物流インフラとの統合を可能としている。実際にグランベルやエレシオンもレーンの一部機能を自勢力の物流システムに統合しており、シグナル・オペレーションの通信網とも統合されている。レーン・システムは宇宙全体の物流のデファクトスタンダードとなり、テクノ文化ルネサンス期における異文明間交流の爆発的増加を支える基盤技術となっている。",descriptionEn:"A galaxy-scale logistics and transportation network system developed and operated by Prokio, designed within the framework of Shannon's communication channel theorem and information theory as the universe's largest logistics optimization system. The Lane system organically connects thousands of interstellar routes, with AI-driven route optimization algorithms comprehensively analyzing demand forecasts, weather phenomena, unstable dimensional boundary areas, fleet position information, and more to calculate and provide optimal transport routes that minimize information entropy in real-time. The Lane system is designed with an open architecture, and based on Prokio's philosophy that 'the universe's logistics should not be confined to a single civilization,' it enables integration with logistics infrastructure from other civilizations. In practice, Granbel and Elesion have integrated some Lane functions into their own logistics systems, and it is also integrated with the communication network of Signal Operations. The Lane system has become the de facto standard for logistics across the universe and serves as the foundational technology supporting the explosive increase in intercivilizational exchange during the Techno Cultural Renaissance period."},{id:"クアンタ",name:"クアンタ・ラボ",nameEn:"Quanta Lab",category:"技術",subCategory:"技術・概念",description:"ロースターの研究開発部門であり、超伝導量子計算と次元間通信技術の最前線研究を行う機関である。クアンタ・ラボでは超高速量子コンピューティング、次元干渉低減技術、Shannon情報理論を拡張した量子暗号理論、そして次元境界の安定化技術などの研究が進められており、Link 7.2の開発から次世代Link 8.0の構想まで、ロースターの通信技術の進化を支えている。中でも次元境界の安定化研究は宇宙全体の安全保障に直結する重要課題であり、境界の不安定化が大規模災害を引き起こす可能性が指摘されているため、全文明圏から注視されている。クアンタ・ラボの研究成果はロースター・コアのインフラに迅速に実装されるオープンイノベーション・モデルを採用しており、新技術の普及速度は宇宙最速を誇る。ディオクレニスの科学宰相ネイサン・コリンドは量子通信の安全性向上のために研究者を派遣し、エレシュとは次元共鳴通信技術の共同研究を進めている。",descriptionEn:"The research and development department of Roaster, an institution conducting cutting-edge research in superconducting quantum computing and interdimensional communication technologies. At Quanta Lab, research is being advanced in ultra-high-speed quantum computing, dimensional interference reduction technology, quantum cryptography theory that extends Shannon information theory, and dimensional boundary stabilization technology. From the development of Link 7.2 to the conception of the next-generation Link 8.0, Quanta Lab supports the evolution of Roaster's communication technologies. Among these, the research on dimensional boundary stabilization is a critical issue directly related to the security of the entire universe, as destabilization of boundaries could trigger large-scale disasters, receiving attention from all civilizations. Quanta Lab adopts an open innovation model where research results are rapidly implemented in Roaster Core's infrastructure, boasting the fastest technology adoption speed in the universe. Nathan Corind, the science minister of Dioclenis, has dispatched researchers to improve the security of quantum communication, and Eles is conducting joint research on dimensional resonance communication technology with Quanta Lab."},{id:"プロトコルX",name:"プロトコルX",nameEn:"Protocol X",category:"技術",subCategory:"技術・概念",description:"ZAMLTが開発した次元安定化デバイスであり、超弦理論の余剰次元の安定性を脅かす宇宙規模の次元崩壊を防ぐための緊急措置として構想された。終末の星（Star of the End）の「意志」がもたらす宇宙的脅威に対抗するため、ZAMLTのエリオット・シュトラスが提案した。プロトコルXの稼働には3京ドル（3 quintillion dollars）の資金が必要とされ、マモン・コーポレーションが「3京ドル作戦」の資金調達計画を立案した。この計画はZAMLTが全コーポラトクラシーから資金を強制的に徴収するものであり、低階層市民へのさらなる搾取を意味した。しかしアルファ・ケインのチームは次元断層のエネルギーを代替エネルギー源として発見し、ZAMLTの搾取的な資金計画を拒絶した。プロトコルXを巡る攻防はZAMLTとシャドウ・リベリオン（のちにテクロサスと合流）の対立の核心であり、リンダの犠牲とアルファ・ケインの伴共役の覚醒という重大な結果をもたらした。",descriptionEn:"A dimensional stabilization device developed by ZAMLT, conceived as an emergency measure to prevent cosmic-scale dimensional collapse that threatens the stability of extra dimensions in superstring theory. It was proposed by ZAMLT's Eliot Strass to counter the cosmic threat posed by the 'will' of the Star of the End. The operation of Protocol X requires 3 quintillion dollars, and Mammon Corporation formulated the '3 Quintillion Dollar Operation' fundraising plan. This plan involved ZAMLT forcibly collecting funds from all corporatocracies, meaning further exploitation of low-tier citizens. However, Alpha Cain's team discovered the energy of dimensional faults as an alternative energy source and rejected ZAMLT's exploitative funding plan. The conflict over Protocol X became the core of the confrontation between ZAMLT and the Shadow Rebellion (later merging with Techlos), leading to significant results including Linda's sacrifice and the awakening of Alpha Cain's entangled companion."},{id:"カタリスト・コア",name:"カタリスト・コア",nameEn:"Catalyst Core",category:"技術",subCategory:"技術・概念",description:"次元の塔の中枢に設置されたZAMLTの核心技術デバイスであり、次元境界のエネルギーを触媒的に操作して、超弦理論の余剰次元に蓄積された真空エネルギーを抽出する。プロトコルXのエネルギー源として機能し、ルレンツ・コーポレーションのエリザベス・リンドバーグが設計を主導し、ゼブラ・コーポレーションの次元技術が組み込まれた。カタリスト・コアは超対称性粒子の対生成を利用して次元境界のポテンシャル障壁を一時的に低下させ、余剰次元からのエネルギーの流入を制御する。カタリスト・コアの破壊はアルファ・ケインとテクロサス連合軍の最終目標であり、その達成がZAMLTの物理的な終焉を決定づけた。コアの設計思想はのちに次元極地平技術の理論框架に影響を与え、テクノ文化ルネサンス期のホライゾン・ゲート技術開発の遠因となった。",descriptionEn:"The core technical device of ZAMLT installed at the center of the Dimensional Tower, it catalytically manipulates the energy of dimensional boundaries to extract vacuum energy accumulated in the extra dimensions of string theory. It functions as the energy source for Protocol X, with its design led by Elizabeth Lindberg of the Lorentz Corporation, incorporating dimensional technology from the Zebra Corporation. The Catalyst Core temporarily lowers the potential barrier of dimensional boundaries by utilizing pair production of supersymmetric particles, controlling the inflow of energy from extra dimensions. The destruction of the Catalyst Core was the ultimate goal of Alpha Cain and the Teclosus Alliance, and its achievement determined the physical demise of ZAMLT. The design philosophy of the core later influenced the theoretical framework of dimensional horizon technology and became the remote cause of the development of Horizon Gate technology during the Techno-Cultural Renaissance period."},{id:"伴共役",name:"伴共役",nameEn:"Ban-Kyōyaku",category:"技術",subCategory:"技術・概念",description:"アルファ・ケインが覚醒させた特殊能力で、時空間を操作する次元干渉技術の一形態である。「伴共役（ばんきょうやく）」の名は、量子力学における二つの共役な変数がハイゼンベルクの不確定性原理に従いながら相伴って時空間の方程式を解くことに由来する。この能力は「次元の鍵（Dimensional Key）」と互いに共鳴する極少数の適合者のみが発現可能であり、アルファ・ケインはスティル・アレーナでの記憶迷宮の試練を経てこの適合性を開花させた。伴共役は空間の歪みの生成・消去、時間の局所的な加速・減速（一般相対性理論の時間遅延効果の制御）、次元境界の安定化など多様な応用が可能であり、クリストッフェル次元の不安定化を安定化させるためにも使用された。伴共役の原理は現在でも完全には解明されておらず、惑星ビブリオの研究者たちが超弦理論とAdS/CFT対応の枠組みでその理論的解明を試みている。",descriptionEn:"A special ability awakened by Alpha Cain, a form of dimensional interference technology that manipulates spacetime. The name 'Ban-Kyōyaku' (Conjugate Companion) derives from how two conjugate variables in quantum mechanics solve spacetime equations together following Heisenberg's uncertainty principle. This ability can only manifest in a very small number of compatible individuals who resonate with the 'Dimensional Key,' and Alpha Cain blossomed with this compatibility through the trial of the memory maze in the Still Arena. Ban-Kyōyaku has diverse applications such as generating and eliminating spatial distortions, locally accelerating or slowing time (controlling the time dilation effect of general relativity), and stabilizing dimensional boundaries. It was also used to stabilize the destabilization of the Christoffel dimension. The principle of Ban-Kyōyaku is not yet fully understood, and researchers on the planet Biblio are attempting its theoretical elucidation within the framework of string theory and AdS/CFT correspondence."},{id:"クリストッフェル次元",name:"クリストッフェル次元",nameEn:"Christoffel Dimension",category:"技術",subCategory:"技術・概念",description:"アルファ・ケインのチームが星々の交響曲の旅で遭遇した特異な次元領域であり、名称は微分幾何学におけるクリストッフェル記号に由来する。クリストッフェル記号は曲がった時空における平行移動の補正項を表し、次元境界の幾何学的構造を応用したこの不安定な空間は、接続係数が時間的に変動する非定常的なリーマン多様体として記述される。クリストッフェル次元は物理法則が通常空間と異なり、一般相対性理論の計量テンソルがランダムに変動するため、時間の流れや空間の構造が予測不可能に変動する危険な領域である。アルファ・ケインのチームはこの次元で「時の守護者（Guardian of Time）」と遭遇し、激しい戦闘を繰り広げた。伴共役（Ban-Kyōyaku）能力を使用してクリストッフェル次元の不安定な接続係数を安定化させたことは、アルファ・ケインが次元干渉能力を持つことを証明する決定的な出来事となった。クリストッフェル次元の存在は次元極地平技術の理論的基盤を拡張するものである。",descriptionEn:"A unique dimensional region encountered by Alpha Cain's team during their Symphony of Stars journey, its name derived from the Christoffel symbols in differential geometry. Christoffel symbols represent correction terms for parallel transport in curved spacetime, and this unstable space, applying the geometric structure of dimensional boundaries, is described as a non-stationary Riemann manifold where connection coefficients fluctuate over time. The Christoffel dimension is a dangerous area where physical laws differ from normal space, and the metric tensor of general relativity fluctuates randomly, causing the flow of time and structure of space to unpredictably vary. Alpha Cain's team encountered the 'Guardian of Time' in this dimension and engaged in fierce combat. The act of stabilizing the unstable connection coefficients of the Christoffel dimension using the Ban-Kyōyaku ability became a decisive event proving that Alpha Cain possessed dimensional interference capabilities. The existence of the Christoffel dimension expanded the theoretical foundation of dimensional horizon technology."},{id:"プロキオ・クリア",name:"プロキオ・クリア",nameEn:"Prokio Clear",category:"技術",subCategory:"宇宙勢力",description:"プロキオが開発した宇宙共通の汎用決済システムであり、全文明圏間の取引を統一する決済インフラである。プロキオ・クリアの最大の特徴はE16文明圏の基軸通貨であるn-tokenとの完全な互換性であり、量子もつれを利用した即時換金プロトコルにより、ローカル通貨とn-tokenの為替リスクを最小化したシームレスな商取引を実現する。Shannonの通信路定理に基づく暗号化プロトコルを全取引に適用し、詐欺行為を防止する透明性の高いシステムとして機能している。グランベルの量子経済システムとも接続されており、E16文明圏内での取引と銀河規模の貿易が単一の決済インフラで処理される画期的な体制を構築している。プロキオ・クリアの普及は宇宙規模の経済統合を加速させ、銀河系コンソーシアムの設立（E495〜E500年）を支える経済的基盤の一つとなった。",descriptionEn:"A universal payment system developed by Prokio, a payment infrastructure that unifies transactions across all civilizations. The greatest feature of Prokio Clear is its complete compatibility with the n-token, the base currency of the E16 civilization zone. By using an instant exchange protocol utilizing quantum entanglement, it achieves seamless commercial transactions that minimize exchange risks between local currencies and n-tokens. It functions as a highly transparent system that prevents fraudulent activities by applying encryption protocols based on Shannon's channel theorem to all transactions. It is also connected to the Grandbell quantum economic system, building an innovative system where transactions within the E16 civilization zone and intergalactic trade are processed through a single payment infrastructure. The popularization of Prokio Clear accelerated economic integration on a cosmic scale and became one of the economic foundations supporting the establishment of the Galactic Consortium (E495-E500)."},{id:"G4ファントムパルス",name:"G4ファントムパルス",nameEn:"G4 Phantom Pulse",category:"技術",subCategory:"技術・概念",description:"セリア・ドミニクスがアポロン・Dominion大戦で応戦のために開発した次元エネルギー兵器であり、超弦理論の余剰次元の真空エネルギーをパルス状に放出することで広範囲に次元構造を不安定化させる。E378年にアポロンのケンタウロスレーザーに対抗して使用され、Calabi-Yau多様体の局所的変形を誘発して標的領域の物理定数を一時的に歪める効果を持つ。この兵器はのちにシルバー・ヴェノムの名称の由来となり、E475年の組織設立の思想的・技術的基盤の一つとなったとされる。G4ファントムパルスの技術的遺産は、次元境界の不安定化の危険性を浮き彫りにし、次元兵器禁止条約の科学的根拠を提供した。",descriptionEn:"A dimensional energy weapon developed by Celia Dominikus to counterattack during the Apollo-Dominion War, it destabilizes dimensional structures over a wide area by releasing vacuum energy from the extra dimensions of string theory in pulses. Used in E378 against Apollo's Centaurus Laser, it induces local deformation of Calabi-Yau manifolds, temporarily distorting the physical constants of the target area. This weapon later became the origin of the name 'Silver Venom' and is said to have been one of the ideological and technical foundations for the organization's establishment in E475. The technological legacy of the G4 Phantom Pulse highlighted the dangers of destabilizing dimensional boundaries and provided the scientific basis for the Dimensional Weapons Ban Treaty."},{id:"ケンタウロスレーザー",name:"ケンタウロスレーザー",nameEn:"Centaur Laser",category:"技術",subCategory:"技術・概念",description:"アポロン文明圏がアポロン・Dominion大戦（E370〜E385）で使用した超巨大レーザー兵器であり、X線レーザーの励起原理を恒星規模のエネルギー源で駆動した指向性エネルギー兵器である。E375年に発射され、高エネルギー光子のビームが電磁スペクトルのX線領域で集中的に照射され、Selinopolis（ドミニオン）側に壊滅的な被害をもたらした。しかしセリアはG4ファントムパルスで応戦し、最終的にE385年にヴェノム艦隊によるアポロン・セントラリス攻略でアポロン文明圏は壊滅した。この兵器の使用は次元兵器禁止条約の根拠の一つとなり、大規模な指向性エネルギー兵器の国際的規制の先駆けとなった。",descriptionEn:"A super-giant laser weapon used by the Apollo civilization zone during the Apollo-Dominion War (E370-E385), it is a directed energy weapon driven by stellar-scale energy sources using the excitation principle of X-ray lasers. Fired in E375, a beam of high-energy photons was concentrated in the X-ray region of the electromagnetic spectrum, bringing devastating damage to the Dominion (Selinopolis) side. However, Celia countered with the G4 Phantom Pulse, and ultimately in E385, the Apollo civilization zone was annihilated by the capture of Apollo Centralis by the Venom fleet. The use of this weapon became one of the bases for the Dimensional Weapons Ban Treaty and a precursor to international regulation of large-scale directed energy weapons."},{id:"tech-antimatter-engine",name:"反物質エンジン",nameEn:"Antimatter Engine",category:"技術",subCategory:"技術・概念",description:"物質と反物質の対消滅反応をエネルギー源とする推進システムであり、アインシュタインの質量エネルギー等価性 E=mc² に従い、反物質の全質量をエネルギーに変換する理論上の最高効率を誇る。陽電子と電子の対消滅、または反陽子と陽子の対消滅によってガンマ線とニュートリノを放出し、このガンマ線を磁気鏡で反射・収束させることで推力を得る。反物質の貯蔵にはペニングトラップを用いた磁気閉じ込めが必要であり、真空容器内の超伝導磁石が反物質プラズマを浮上させて容器壁との接触による対消滅を防ぐ。E16文明圏においては大型宇宙船の主推進機として採用されているが、反物質の生産コストが極めて高く、粒子加速器での反物質生成効率の向上が持続的な技術課題となっている。反物質エンジンの安全性管理は厳格であり、偶発的な対消滅による爆発は核兵器に匹敵する破壊力を持つため、多層的な安全装置が義務付けられている。",descriptionEn:"A propulsion system that uses matter-antimatter annihilation reactions as an energy source, boasting theoretically maximum efficiency by converting all mass of antimatter into energy according to Einstein's mass-energy equivalence E=mc². It emits gamma rays and neutrinos through positron-electron or antiproton-proton annihilation, and obtains thrust by reflecting and converging these gamma rays with magnetic mirrors. Storage of antimatter requires magnetic confinement using a Penning trap, with superconducting magnets in a vacuum container levitating the antimatter plasma to prevent contact with container walls and subsequent annihilation. In the E16 civilization sphere, it is adopted as the main propulsion system for large spacecraft, but the production cost of antimatter is extremely high, and improving antimatter generation efficiency in particle accelerators has become a persistent technical challenge. Safety management of antimatter engines is strict, as accidental annihilation explosions can have destructive power equivalent to nuclear weapons, requiring multi-layered safety systems."},{id:"tech-solar-sail",name:"太陽帆推進",nameEn:"Solar Sail Propulsion",category:"技術",subCategory:"技術・概念",description:"太陽光や恒星からの輻射圧を推力として利用する推進方式であり、光子が持つ運動量を反射面で受けることで得られる微小な推力を長期間蓄積して加速する。帆の材質には厚さ数ナノメートルのカーボンナノチューブ薄膜や反射率の高い金属蒸着膜が使用され、1平方キロメートルの帆面積で太陽附近において約6ニュートンの推力を得ることができる。太陽帆推進の最大の利点は推進剤を搭載する必要がないことであり、ロケット方程式における質量比の制約から解放される。E16文明圏では短距離の貨物輸送や深宇宙探査機の初期加速に広く利用されており、恒星の重力レンズ効果を利用した加速軌道との組み合わせにより、亜光速域への到達が理論的に可能となっている。帆の展開機構と微小隕石に対する自己修復機能が技術的な課題である。",descriptionEn:"A propulsion method that utilizes radiation pressure from sunlight or stars as thrust, accumulating small thrust obtained by reflecting the momentum of photons over long periods to achieve acceleration. Materials for the sail include carbon nanotube films with a thickness of several nanometers and highly reflective metal vapor deposition films, with a sail area of 1 square kilometer capable of generating about 6 Newtons of thrust near the sun. The greatest advantage of solar sail propulsion is the need to carry no propellant, freeing it from the mass ratio constraints of the rocket equation. In the E16 civilization sphere, it is widely used for short-distance cargo transport and initial acceleration of deep space probes, and theoretically reaching sub-light speed regions is possible by combining it with acceleration trajectories utilizing gravitational lensing effects of stars. Sail deployment mechanisms and self-repair functions against micrometeorites are technical challenges."},{id:"tech-warp-drive",name:"空間歪曲推進",nameEn:"Space Warp Drive",category:"技術",subCategory:"技術・概念",description:"一般相対性理論のアインシュタイン方程式における Alcubierre解を工学的に実装し、宇宙船の周囲に時空の歪曲バブルを形成して超光速移動を実現する推進技術である。船体前方の空間を圧縮し後方の空間を膨張させることで、船体そのものは局所的に光速未満のまま、実効的な超光速移動を達成する。空間歪曲の形成には負のエネルギー密度を持つエキゾチック物質が必要であり、カシミール効果や量子真空の零点エネルギーを利用した負エネルギー生成が技術的核心となっている。曲率航法の次世代発展型として位置づけられ、従来の曲率航法より大きな速度域と効率を実現している。空間歪曲バブルの形成と解除に伴う時空の波紋が周辺の天体に影響を与える可能性があり、居住惑星からの安全距離での起動が規制されている。",descriptionEn:"A propulsion technology that implements the Alcubierre solution from Einstein's equations in general relativity in an engineering manner, creating a spacetime distortion bubble around the spacecraft to achieve faster-than-light travel. It compresses space in front of the spacecraft and expands space behind it, allowing the spacecraft itself to remain below light speed locally while achieving effective faster-than-light movement. Formation of spacetime distortion requires exotic matter with negative energy density, and generation of negative energy utilizing the Casimir effect or quantum vacuum zero-point energy has become the technological core. Positioned as a next-generation development of curvature navigation, it achieves greater speed ranges and efficiency than conventional curvature navigation. The spacetime ripples associated with the formation and dissolution of the spacetime distortion bubble may affect surrounding celestial bodies, and activation is regulated from a safe distance from inhabited planets."},{id:"tech-ion-thruster",name:"イオンスラスター",nameEn:"Ion Thruster",category:"技術",subCategory:"技術・概念",description:"荷電粒子を電界によって加速して推力を得る電気推進方式であり、キセノンやアルゴンなどの希ガスをイオン化して電磁加速器で高速に噴射する。推力は化学ロケットに比べて極めて小さいが、比推力が化学ロケットの10倍以上に達し、長期間の連続稼働によって最終的に化学ロケットを上回る速度增量を実現する。ホール効果スラスターと磁気プラズマ力学（MPD）スラスターの二つの主流方式があり、E16文明圏では軌道間輸送船や惑星間探査機の推進機として標準的に採用されている。イオンスラスターの効率はプラズマ温度と磁場閉じ込めの性能に依存し、超伝導磁石を用いた高温プラズマの閉じ込め技術の向上が持続的な課題となっている。電源には太陽電池パネルまたは小型の核融合炉が使用される。",descriptionEn:"An electric propulsion method that obtains thrust by accelerating charged particles using electric fields, ionizing noble gases such as xenon or argon and ejecting them at high speed with electromagnetic accelerators. Thrust is extremely small compared to chemical rockets, but specific impulse reaches more than 10 times that of chemical rockets, achieving velocity increments that eventually surpass chemical rockets through long-term continuous operation. There are two mainstream methods: Hall effect thrusters and magnetoplasmadynamic (MPD) thrusters, both of which are standardly adopted as propulsion systems for interorbital transport ships and interplanetary probes in the E16 civilization sphere. The efficiency of ion thrusters depends on plasma temperature and magnetic confinement performance, and improvement of high-temperature plasma confinement technology using superconducting magnets has become a persistent challenge. Solar panels or small fusion reactors are used as power sources."},{id:"tech-gravity-slingshot",name:"重力アシスト・スリングショット",nameEn:"Gravity Assist Slingshot",category:"技術",subCategory:"技術・概念",description:"天体の重力場を利用して宇宙船の速度と軌道を変更する航法技術であり、天体力学における三体問題の摂動論的解法を応用したものである。宇宙船が惑星や恒星の重力場に接近し、その重力ポテンシャルエネルギーを運動エネルギーに変換することで、推進剤を消費せずに速度の増加または減少を実現する。この手法はエネルギーと運動量の保存則を厳密に満たしており、速度の変化は天体の運動エネルギーの微小な減少として相殺される。E16文明圏では惑星間航路の設計において標準的に利用され、特にガス巨星の強力な重力場を利用した大規模な軌道変更が頻繁に実施されている。スリングショット軌道の精密な計算にはN体シミュレーションが必要であり、惑星間の重力相互作用の長期的なカオス的挙動を予測する量子コンピューティングの応用が進んでいる。",descriptionEn:"A navigation technique that utilizes the gravitational fields of celestial bodies to change a spacecraft's speed and orbit, applying perturbative solutions to the three-body problem in celestial mechanics. As a spacecraft approaches the gravitational field of a planet or star, it converts gravitational potential energy into kinetic energy, achieving speed increases or decreases without consuming propellant. This method strictly satisfies conservation laws of energy and momentum, with changes in speed offset as a small decrease in the celestial body's kinetic energy. In the E16 civilization sphere, it is standardly used in designing interplanetary routes, with large-scale orbital changes frequently utilizing the powerful gravitational fields of gas giants. Precise calculation of slingshot orbits requires N-body simulations, and the application of quantum computing to predict long-term chaotic behavior of gravitational interactions between planets is advancing."},{id:"tech-quantum-entangle-comm",name:"量子もつれ通信",nameEn:"Quantum Entanglement Communication",category:"技術",subCategory:"技術・概念",description:"量子もつれの非局所性を利用した超光速通信プロトコルであり、事前に共有された量子もつれペアの測定結果を用いて遠隔地間で同期情報を伝達する。量子テレポーテーションと同様に古典通信チャネルを補助として使用するため、情報の伝達速度は光速を超えないという相対性理論の制約を満たしているが、量子鍵配送の安全性は情報理論的に保証される。E16文明圏では軍事通信と外交暗号において最重要の通信インフラとして位置づけられ、量子もつれペアの遠距離分配には宇宙空間を経由する光通信が利用されている。量子もつれのデコヒーレンスを防ぐための量子エラー訂正符号の性能向上が継続的な課題であり、ロースターのクアンタ・ラボが次世代の大容量量子もつれ通信網の開発を主導している。",descriptionEn:"A faster-than-light communication protocol utilizing the non-locality of quantum entanglement, transmitting synchronized information between distant locations using measurement results of pre-shared entangled pairs. Similar to quantum teleportation, it uses classical communication channels as an auxiliary, satisfying the constraints of relativity that information transmission speed cannot exceed light speed, but the security of quantum key distribution is theoretically guaranteed. In the E16 civilization sphere, it is positioned as the most important communication infrastructure for military communications and diplomatic codes, with optical communication via space being used for long-distance distribution of entangled pairs. Improvement of quantum error correction codes to prevent decoherence of quantum entanglement is a continuous challenge, with Quanta Lab of Rooster leading the development of next-generation high-capacity quantum entanglement communication networks."},{id:"tech-gravitational-wave-comm",name:"重力波通信",nameEn:"Gravitational Wave Communication",category:"技術",subCategory:"技術・概念",description:"一般相対性理論が予言する重力波を情報キャリアとして利用する通信方式であり、電磁波とは異なり物質をほとんど透過する重力波の性質を活かして、惑星内部や恒星の裏側などの電磁波通信が困難な環境での通信を可能にする。重力波の生成には高質量天体の連星回転を人為的に模した回転する非対称質量分布が必要であり、超伝導振動子を用いた小型重力波発生器が開発されている。重力波の検出にはレーザー干渉計を用いた高感度の重力波アンテナが使用され、量子雑音限界に近い感度で微弱な重力波信号を検出する。E16文明圏では海底や地下深部の通信インフラとして実用化が進んでおり、電磁波シールド環境における補完通信手段として機能している。",descriptionEn:"A communication method that utilizes gravitational waves predicted by general relativity as information carriers. By leveraging the property of gravitational waves, which are almost transparent to matter unlike electromagnetic waves, it enables communication in environments where electromagnetic wave communication is difficult, such as inside planets or behind stars. The generation of gravitational waves requires a rotating asymmetric mass distribution that artificially simulates the binary rotation of massive celestial bodies, and small gravitational wave generators using superconducting oscillators have been developed. For detection, high-sensitivity gravitational wave antennas using laser interferometers are used to detect weak gravitational wave signals with sensitivity close to the quantum noise limit. In the E16 civilization sphere, it is being practically implemented as communication infrastructure on the seabed and in deep underground areas, functioning as a complementary communication method in electromagnetically shielded environments."},{id:"tech-neutrino-comm",name:"ニュートリノ通信",nameEn:"Neutrino Communication",category:"技術",subCategory:"技術・概念",description:"標準模型における弱い相互作用を媒介するニュートリノの通信キャリアとしての利用であり、ニュートリノが物質との相互作用断面積が極めて小さいことを活かして、惑星の核心部を貫通するような長距離通信を可能にする。ニュートリノビームの生成には粒子加速器における陽子の標的衝突が使用され、ニュートリノの検出には巨大な水チェレンコフ検出器や液体アルゴン時間投影室が使用される。ニュートリノ通信の最大の課題は検出効率の低さであり、送信されたニュートリノのうち検出される割合は10のマイナス18乗以下と極めて小さい。このため、高出力のニュートリノビーム生成と超低ノイズの検出器開発が技術的な課題となっている。E16文明圏では特殊用途の軍事通信として限定的に実用化されており、恒星間距離の緊急通信のバックアップチャネルとしての役割が期待されている。",descriptionEn:"Utilization of neutrinos, which mediate weak interactions in the standard model, as communication carriers. By taking advantage of the extremely small interaction cross-section between neutrinos and matter, it enables long-distance communication that can penetrate planetary cores. For generating neutrino beams, proton target collisions in particle accelerators are used, and for detection, large water Cherenkov detectors or liquid argon time projection chambers are used. The biggest challenge in neutrino communication is the low detection efficiency, with the proportion of detected neutrinos among those sent being extremely small, less than 10 to the power of -18. Therefore, high-power neutrino beam generation and ultra-low-noise detector development have become technical challenges. In the E16 civilization sphere, it has been practically implemented for special-purpose military communication in a limited manner, and is expected to serve as a backup channel for emergency interstellar communication."},{id:"tech-dimensional-comm",name:"次元穿越通信",nameEn:"Dimensional Transit Communication",category:"技術",subCategory:"技術・概念",description:"超弦理論の余剰次元を通信路として利用する画期的な通信方式であり、物理的時空を通過せずに余剰次元の位相空間を経由して情報を伝達する。AdS/CFT対応に基づき、境界上の共形場理論の演算子を余剰次元のバルク時空における伝搬に対応させることで、通常の電磁波通信では不可能な距離と環境での通信を実現する。次元穿越通信の実現には次元極地平技術を応用した余剰次元へのアクセス制御が必要であり、通信の安定性は余剰次元の幾何学的形状の変動に依存する。E16文明圏では次元境界の不安定区域を避けた通信路の設計が行われており、マルチバース開拓技術との統合が進められている。この通信方式は従来の通信手段の速度と距離の限界を根本的に打破する可能性を秘めているが、次元境界への負荷蓄積の問題が安全面での最大の懸念事項である。",descriptionEn:"An innovative communication method that uses extra dimensions from string theory as communication channels, transmitting information through the phase space of extra dimensions without passing through physical spacetime. Based on AdS/CFT correspondence, it corresponds operators of conformal field theory on the boundary to propagation in the bulk spacetime of extra dimensions, enabling communication at distances and in environments impossible with conventional electromagnetic wave communication. The realization of dimension-transcending communication requires access control to extra dimensions applying dimensional horizon technology, and communication stability depends on fluctuations in the geometric shape of the extra dimensions. In the E16 civilization sphere, communication paths are designed to avoid unstable areas of dimensional boundaries, and integration with multiverse exploration technology is progressing. This communication method has the potential to fundamentally break the speed and distance limitations of conventional communication methods, but the problem of load accumulation on dimensional boundaries is the biggest safety concern."},{id:"tech-fusion-reactor",name:"核融合炉",nameEn:"Fusion Reactor",category:"技術",subCategory:"技術・概念",description:"軽元素の原子核融合反応からエネルギーを抽出する発電システムであり、太陽を含む恒星のエネルギー生成メカニズムを地球上で人為的に再現したものである。E16文明圏では磁気閉じ込め方式のトカマク型核融合炉と慣性閉じ込め方式のレーザー核融合炉の二つの主流方式が併用されている。トカマク型は超伝導磁石によって高温プラズマをドーナツ形状に磁気閉じ込め、重水素と三重水素のD-T反応により約1億度のプラズマ温度を維持して発電する。レーザー型は高パワー レーザーを燃料ペレットに集光照射し、慣性閉じ込めによる爆縮で融合反応を誘発する。核融合炉は反応生成物としてヘリウムを排出するのみで温室効果ガスを発生せず、燃料の重水素は海水中に豊富に存在するため、E16文明圏における主力エネルギー源として機能している。",descriptionEn:"A power generation system that extracts energy from nuclear fusion reactions of light elements, artificially reproducing the energy generation mechanism of stars, including the sun, on Earth. In the E16 civilization sphere, two mainstream methods are used in parallel: the magnetic confinement tokamak-type fusion reactor and the inertial confinement laser fusion reactor. The tokamak type magnetically confines high-temperature plasma in a donut shape using superconducting magnets and generates electricity by maintaining a plasma temperature of about 100 million degrees through D-T reactions of deuterium and tritium. The laser type focuses high-power laser light on fuel pellets, inducing fusion reactions through compression by inertial confinement. Fusion reactors only discharge helium as a reaction product and do not generate greenhouse gases, and since deuterium fuel is abundant in seawater, it functions as the main energy source in the E16 civilization sphere."},{id:"tech-antimatter-power",name:"反物質発電",nameEn:"Antimatter Power Generation",category:"技術",subCategory:"技術・概念",description:"物質と反物質の対消滅反応で発生するエネルギーを電力に変換する発電方式であり、質量の100パーセントがエネルギーに変換される理論上の最高効率を持つ。対消滅で放出される高エネルギーガンマ線を熱電変換素子または磁気流体力学発電機（MHD発電機）で電力に変換する。反物質の貯蔵と輸送にはペニングトラップによる磁気閉じ込めが不可欠であり、反物質プラズマの熱的振動による磁力線からの逸脱を防ぐための精密な制御システムが要求される。E16文明圏では大型宇宙ステーションや軌道工場の主電源として採用されているが、反物質の生産コストが極めて高く、宇宙規模のエネルギーインフラとしては核融合炉が主力である。反物質発電の安全性管理は核融合炉以上に厳格で、偶発的な対消滅のリスクを最小化する多層安全システムが義務付けられている。",descriptionEn:"A power generation method that converts energy from matter-antimatter annihilation into electricity, with a theoretical maximum efficiency of 100% where mass is completely converted into energy. The high-energy gamma rays released from annihilation are converted into electricity by thermoelectric conversion elements or magnetohydrodynamic generators (MHD generators). Magnetic confinement using Penning traps is essential for the storage and transportation of antimatter, and a precise control system is required to prevent escape from magnetic field lines due to thermal vibrations of antimatter plasma. In the E16 civilization sphere, it is adopted as the main power source for large space stations and orbital factories, but the production cost of antimatter is extremely high, and fusion reactors are the main energy infrastructure on a cosmic scale. Safety management for antimatter power generation is even stricter than for fusion reactors, and a multi-layer safety system is mandatory to minimize the risk of accidental annihilation."},{id:"tech-vacuum-energy",name:"真空エネルギー抽出",nameEn:"Vacuum Energy Extraction",category:"技術",subCategory:"技術・概念",description:"量子力学における真空の零点エネルギーを有用なエネルギーとして抽出する技術であり、ハイゼンベルクの不確定性原理に基づき、真空状態でも残存する電磁場の量子ゆらぎ（零点振動）のエネルギーを利用する。カシミール効果として知られる二つの導体板間の引き合い現象は、真空の零点エネルギーの直接的な証拠であり、この効果を応用して微弱ながら実測可能なエネルギー抽出が実証されている。真空エネルギー抽出技術は理論的に膨大なエネルギーを提供する可能性を秘めているが、宇宙定数問題とも関連し、真空エネルギー密度の理論値と観測値の不一致が根本的な課題となっている。E16文明圏ではグランベルが最先端の研究を進めており、超弦理論の余剰次元の真空エネルギー構造を操作する手法の開発に注力している。",descriptionEn:"A technology that extracts useful energy from the zero-point energy of the vacuum in quantum mechanics. Based on Heisenberg's uncertainty principle, it utilizes the energy of quantum fluctuations (zero-point oscillations) of the electromagnetic field that remain even in a vacuum state. The attractive phenomenon between two conductor plates known as the Casimir effect is direct evidence of the vacuum's zero-point energy, and this effect has been applied to demonstrate measurable, albeit weak, energy extraction. Vacuum energy extraction technology theoretically has the potential to provide enormous energy, but it is also related to the cosmological constant problem, and the discrepancy between the theoretical and observed values of vacuum energy density has become a fundamental challenge. In the E16 civilization sphere, Granbel is conducting cutting-edge research, focusing on developing methods to manipulate the vacuum energy structure of extra dimensions in string theory."},{id:"tech-dyson-sphere",name:"ダイソン・スフィア",nameEn:"Dyson Sphere",category:"技術",subCategory:"技術・概念",description:"恒星の全放射エネルギーを捕捉して利用するための巨大構造物であり、物理学者フリーマン・ダイソンが提唱した宇宙文明のエネルギー利用の指標（カルダシェフのスケール Type II）の実現手段である。ダイソン・スフィアは恒星を完全に包囲する球殻構造、または恒星の周囲を巡る密集した衛星群（ダイソン・スウォーム）として構築され、恒星の光度に相当する膨大なエネルギーを電力に変換する。E16文明圏では一部の先進文明がダイソン・スウォームの部分構築を実施しており、太陽電池パネルを組み込んだ自律型衛星を恒星周囲に大量配置してエネルギーを収集している。ダイソン・スフィアの構築には恒星系全体の物質リソースを動員する必要があり、小惑星帯やガス巨星の資源採掘が前提条件となる。構造物の放射冷却と赤外線放射による通信網の構築も技術的な課題である。",descriptionEn:"A megastructure designed to capture and utilize all the radiant energy of a star, serving as a means to achieve Type II on the Kardashev Scale—a metric for energy utilization by civilizations proposed by physicist Freeman Dyson. A Dyson Sphere is constructed as a shell structure completely surrounding a star or as a dense swarm of satellites orbiting the star, converting the star's luminosity into vast amounts of electrical energy. In the E16 civilization sphere, some advanced civilizations have partially constructed Dyson Swarms, deploying large numbers of autonomous satellites equipped with solar panels around stars to collect energy. The construction of a Dyson Sphere requires mobilizing the material resources of an entire star system, making asteroid belt and gas giant resource extraction prerequisites. Radiative cooling of the structure and the construction of communication networks using infrared radiation are also technical challenges."},{id:"tech-zero-point-energy",name:"ゼロ点エネルギー",nameEn:"Zero-Point Energy",category:"技術",subCategory:"技術・概念",description:"量子調和振動子の基底状態に存在する最低エネルギーであり、絶対零度においても消滅することのない量子力学的な残留エネルギーである。すべての量子場は零点振動と呼ばれる微小なゆらぎを持っており、この零点エネルギーは宇宙の真空そのものに内在する膨大なエネルギー源と見なされている。ゼロ点エネルギーの抽出と利用は物理学の最重要未解決問題の一つであり、Stochastic Electrodynamics（SED）の理論的框架では零点エネルギーのカップリングを通じたエネルギー変換が理論的に可能であるとされる。E16文明圏ではゼロ点エネルギーモジュールが小型機器の電源として限定的に実用化されており、超伝導回路と結合した共振器が零点エネルギーの微弱な抽出を実現している。しかし、大規模なエネルギー抽出が宇宙の真空状態に与える影響は未知であり、予期せぬ位相遷移のリスクが指摘されている。",descriptionEn:"The lowest energy state present in the ground state of a quantum harmonic oscillator, a quantum mechanical residual energy that never disappears even at absolute zero. All quantum fields possess minute fluctuations called zero-point vibrations, and this zero-point energy is considered an enormous energy source inherent in the vacuum of space itself. The extraction and utilization of zero-point energy is one of the most important unsolved problems in physics. Within the theoretical framework of Stochastic Electrodynamics (SED), energy conversion through coupling with zero-point energy is theoretically possible. In the E16 civilization sphere, zero-point energy modules have been practically implemented on a limited basis as power sources for small devices, with resonators coupled to superconducting circuits achieving weak extraction of zero-point energy. However, the effects of large-scale energy extraction on the vacuum state of the universe are unknown, and the risk of unexpected phase transitions has been pointed out."},{id:"tech-nanomachine-therapy",name:"ナノマシン治療",nameEn:"Nanomachine Therapy",category:"技術",subCategory:"技術・概念",description:"ナノスケールの自律型機械を生体内に導入して、細胞レベルでの診断と治療を同時に行う医療技術である。ナノマシンはカーボンナノチューブ骨格にタンパク質センサーと薬剤送達システムを組み込んだ構造を持ち、血流に乗って全身を巡りながら異常細胞を特定して治療薬を局所的に放出する。ナノマシンの動力源は生体内のグルコースの化学エネルギーを利用する生体燃料電池であり、外部からの充電を必要としない。DNAの損傷部位を量子センサーで検出し、酵素を用いた分子レベルの修復を行う機能により、がん細胞の選択的破壊や動脈硬化のプラーク除去などの治療が可能である。E16文明圏ではナノマシン治療は標準的な医療技術として広く普及しており、特にナノメディシンの基盤技術として機能している。",descriptionEn:"A medical technology that introduces autonomous nanoscale machines into the body to perform simultaneous diagnosis and treatment at the cellular level. Nanomachines have a structure incorporating protein sensors and drug delivery systems into a carbon nanotube skeleton, traveling throughout the body via the bloodstream to identify abnormal cells and release therapeutic drugs locally. The power source for nanomachines is a biofuel cell that utilizes the chemical energy of glucose within the body, eliminating the need for external recharging. With the ability to detect DNA damage sites using quantum sensors and perform molecular-level repairs using enzymes, treatments such as selective destruction of cancer cells and removal of arterial plaque are possible. In the E16 civilization sphere, nanomachine therapy has become widely adopted as a standard medical technology, serving as the foundational technology for nanomedicine."},{id:"tech-gene-editing",name:"遺伝子編集",nameEn:"Gene Editing",category:"技術",subCategory:"技術・概念",description:"CRISPR-Cas9システムをはじめとするゲノム編集技術を高度化し、DNA配列の任意の位置を精密に修復・置換・挿入・削除する医療技術である。量子ドットを用いた高精度な塩基対認識システムと、DNA二重らせんの局所的融解を制御する熱制御機構を組み合わせることで、オフターゲット効果を最小限に抑えた遺伝子編集を実現する。E16文明圏では先天性の遺伝子疾患の根治治療から、宇宙環境への適応を目的とした遺伝子強化まで幅広い応用が進んでいる。特に宇宙放射線に対する耐性向上や、低重力環境での骨密度維持に関連する遺伝子の最適化が宇宙植民地において重要な応用分野となっている。遺伝子編集の倫理的側面については、E16文明圏の生命倫理委員会が厳格なガイドラインを設けており、ヒト生殖細胞系列への遺伝子改変には国際的な同意手続きが義務付けられている。",descriptionEn:"A medical technology that enhances genome editing technologies such as the CRISPR-Cas9 system, enabling precise repair, replacement, insertion, and deletion of DNA sequences at arbitrary positions. By combining a high-precision base pair recognition system using quantum dots with a thermal control mechanism that regulates local melting of the DNA double helix, gene editing with minimal off-target effects is achieved. In the E16 civilization sphere, applications ranging from radical treatments for congenital genetic diseases to genetic enhancement for adaptation to space environments are progressing. Particularly, optimization of genes related to improved resistance to cosmic radiation and maintenance of bone density in low-gravity environments has become an important application area in space colonies. Regarding the ethical aspects of gene editing, the E16 civilization's Bioethics Committee has established strict guidelines, with international consent procedures being mandatory for genetic modifications to human germline cells."},{id:"tech-consciousness-transfer",name:"意識転送",nameEn:"Consciousness Transfer",category:"技術",subCategory:"技術・概念",description:"人間の意識と記憶をデジタル情報として抽出し、別の媒体（人工身体や仮想空間）に転送する技術である。意識の物理的基盤が脳内の量子コヒーレント状態にあるという仮説に基づき、ニューロリンク・インターフェースを通じて脳内の全シナプス結合の状態を量子ビットの配列として読み取り、目標媒体に再構築する。意識転送の成功は哲学的な人格同一性の問題を提起しており、「転送された意識は元の意識と同一か」という問いはE16文明圏における最重要の倫理的議論の一つである。クオリア・コア技術との統合により、転送された意識は主観的体験の質的側面を含めて完全に再現されると主張されている。意識転送技術はペルセポネ仮想宇宙での永続的な存在を可能にする一方で、生体からデジタルへの完全移行がもたらす社会的影響の評価が進められている。",descriptionEn:'A technology that extracts human consciousness and memory as digital information and transfers it to another medium (such as an artificial body or virtual space). Based on the hypothesis that the physical basis of consciousness lies in the quantum coherent state within the brain, it reads the state of all synaptic connections in the brain as a sequence of qubits through a Neuralink Interface and reconstructs them in the target medium. The success of consciousness transfer raises philosophical questions of personal identity, with the question "Is the transferred consciousness identical to the original consciousness?" being one of the most important ethical debates in the E16 civilization sphere. Integration with Qu-Core technology claims that transferred consciousness is completely reproduced, including the qualitative aspects of subjective experience. While consciousness transfer technology enables permanent existence in the Persephone virtual universe, the social impacts of complete transition from biological to digital are being evaluated.'},{id:"tech-cryopreservation",name:"人体冷凍保存",nameEn:"Human Cryopreservation",category:"技術",subCategory:"技術・概念",description:"人体を極低温（マイナス196度以下の液体窒素温度）で保存し、生体機能を一時的に停止させる技術である。細胞内の水分を凍結による氷晶の形成を防ぐためにクライオプロテクトantと呼ばれる特殊な防凍剤に置換し、ガラス転移温度以下でのガラス化（バイタル凝固）によって細胞構造を完全に維持する。この過程における熱力学のエントロピー変化はLandauerの原理と関連し、生体情報の保存と復元における最小エネルギーコストの理論的限界を定めている。E16文明圏では不治の病に罹患した患者の未来の医療技術による治療を期待した長期保存や、恒星間航行における乗員の長期休眠に応用されている。冷凍保存からの復温プロセスにおける細胞損傷のリスクと、長期保存中の放射線によるDNA損傷の蓄積が技術的な課題である。",descriptionEn:"A technology that preserves the human body at ultra-low temperatures (below -196°C in liquid nitrogen) to temporarily suspend biological functions. To prevent the formation of ice crystals from freezing intracellular water, a special cryoprotectant is used to replace the water, and the cell structure is completely maintained through vitrification (vital solidification) below the glass transition temperature. The thermodynamic entropy change in this process is related to Landauer's principle, defining the theoretical limit of minimum energy cost for the preservation and restoration of biological information. In the E16 civilization sphere, it is applied for long-term preservation of patients with incurable diseases awaiting treatment with future medical technologies, and for long-term hibernation of crew members during interstellar voyages. Risks of cellular damage during the rewarming process from cryopreservation and accumulation of DNA damage from radiation during long-term storage are technical challenges."},{id:"tech-self-healing-materials",name:"自己修復材料",nameEn:"Self-Healing Materials",category:"技術",subCategory:"技術・概念",description:"損傷を検知して自律的に修復機能を発揮する先進材料であり、生体組織の創傷治癒プロセスを工学的に模倣したものである。マイクロカプセルに封入された修復剤が亀裂の発生により放出されて化学反応を起こし、ポリマー鎖の再結合によって亀裂を自動的に修復する。また、形状記憶合金を用いた構造材料は熱エネルギーを与えることで変形前の形状に自己復帰し、トポロジカル絶縁体を組み込んだ電子材料は欠陥の発生を自動的に補償して電気的特性を維持する。E16文明圏では宇宙ステーションの外壁、軌道エレベーターのケーブル、居住モジュールの気密壁など、人命に関わる構造物への応用が進んでいる。自己修復機能の耐久性と修復回数の限界が技術的な課題であり、纳米スケールのセンサーネットワークを組み込んだ次世代の材料開発が進められている。",descriptionEn:"Advanced materials that detect damage and autonomously exhibit repair functions, engineeringly mimicking the wound healing process of biological tissues. Repair agents encapsulated in microcapsules are released upon crack formation, causing chemical reactions that automatically repair cracks through polymer chain recombination. Additionally, structural materials using shape memory alloys return to their pre-deformed shape when thermal energy is applied, and electronic materials incorporating topological insulators automatically compensate for defects to maintain electrical properties. In the E16 civilization zone, applications are advancing for life-critical structures such as the outer walls of space stations, cables for space elevators, and airtight walls of residential modules. The durability of self-repair functions and the limit of repair cycles are technical challenges, and development of next-generation materials incorporating nanoscale sensor networks is progressing."},{id:"tech-orbital-elevator",name:"軌道エレベーター",nameEn:"Orbital Elevator",category:"技術",subCategory:"技術・概念",description:"惑星の地表と静止軌道上のステーションをケーブルで接続し、エレベーター式の輸送システムによって地上と宇宙空間の間の低コストな物資・人員輸送を実現する巨大構造物である。軌道エレベーターのケーブルには炭素ナノチューブの超高引張強度が不可欠であり、直径数センチメートルのケーブルで数万トンの張力に耐える必要がある。ケーブルの全長は静止軌道高度（地球の場合約36,000km）の約2倍に達し、重心が静止軌道上に位置するようにカウンターウェイトを配置する。軌道エレベーターの実現により、化学ロケットによる打ち上げコストの数百分の一という極めて低コストでの宇宙輸送が可能となる。E16文明圏では主要な植民惑星に軌道エレベーターの建設が進んでおり、宇宙港機能と物流ハブ機能を統合した複合施設として機能している。",descriptionEn:"A giant structure that connects a planet's surface with a station in geostationary orbit via cables, achieving low-cost material and personnel transportation between ground and space through an elevator-type transportation system. The cable of the space elevator requires the ultra-high tensile strength of carbon nanotubes, and a cable with a diameter of several centimeters must withstand tensile forces of tens of thousands of tons. The total length of the cable reaches approximately twice the geostationary orbit altitude (about 36,000 km for Earth), and a counterweight is positioned so that the center of gravity is located at the geostationary orbit. With the realization of the space elevator, extremely low-cost space transportation at a fraction of the cost of chemical rocket launches becomes possible. In the E16 civilization zone, construction of space elevators is progressing on major colonial planets, functioning as integrated facilities combining space port functions and logistics hub functions."},{id:"tech-dome-city",name:"ドーム都市建設",nameEn:"Dome City Construction",category:"技術",subCategory:"技術・概念",description:"大気の維持されていない惑星や衛星の地表に、巨大な透明ドームを構築して人工的な居住環境を創出する都市建設技術である。ドーム構造にはカーボンナノチューブ強化ガラスや透明な形状記憶ポリマーが使用され、微小隕石の衝突や宇宙放射線に対する防御性能を備えている。ドーム内部の大気圧は外界との圧力差による構造的応力をケーブルネットワークで分散し、トポロジカル最適化アルゴリズムによって最小質量で最大強度を実現する設計が行われる。ドーム内の生態系は閉鎖循環型の生命維持システムによって維持され、酸素の生成と二酸化炭素の吸収は光合成微生物と人工藻類の培養槽で行われる。E16文明圏ではテラフォーミングの前段階としてドーム都市が広く建設されており、数百万人規模の人口を収容するメガドームが複数の惑星で稼働している。",descriptionEn:"Urban construction technology that creates an artificial living environment by constructing giant transparent domes on the surfaces of planets and moons without maintained atmospheres. The dome structure uses carbon nanotube-reinforced glass or transparent shape memory polymers, and is equipped with defensive performance against micrometeorite impacts and cosmic radiation. The atmospheric pressure inside the dome disperses structural stress caused by pressure differences with the outside through a cable network, and designs are made to achieve maximum strength with minimum mass using topological optimization algorithms. The ecosystem inside the dome is maintained by a closed-loop life support system, with oxygen generation and carbon dioxide absorption carried out in cultivation tanks of photosynthetic microorganisms and artificial algae. In the E16 civilization zone, dome cities are widely constructed as a precursor to terraforming, and mega-domes accommodating populations of millions are operational on multiple planets."},{id:"tech-orbital-habitat",name:"軌道ハビタット",nameEn:"Orbital Habitat",category:"技術",subCategory:"技術・概念",description:"惑星の重力井戸から独立した軌道上に建設された大型宇宙居住構造物であり、O'Neillシリンダーやスタンフォード・トーラスなどの回転構造によって遠心力による人工重力を生成する。軌道ハビタットの外壁は宇宙放射線と微小隕石から居住区を防護する多重防御構造を持ち、自己修復材料とトポロジカル絶縁体を組み込んだ電子システムにより長期的な自律運用が可能である。内部には閉鎖循環生態系が構築され、太陽光は外部ミラーで集光されて内部に導入される。軌道ハビタットは惑星の自然環境に依存せず、恒星系の居住可能領域を拡張する宇宙植民の重要な手段である。E16文明圏では数万人から数十万人規模の軌道ハビタットが複数稼働しており、居住、研究、製造の複合機能を備えた自律的な宇宙都市として機能している。",descriptionEn:"Large space habitats constructed in orbit independent of a planet's gravity well, generating artificial gravity through centrifugal force using rotating structures such as O'Neill cylinders and Stanford tori. The outer walls of orbital habitats have multiple defensive structures to protect residential areas from cosmic radiation and micrometeorites, and long-term autonomous operation is possible through electronic systems incorporating self-repair materials and topological insulators. Closed-loop ecosystems are constructed inside, with sunlight collected by external mirrors and introduced internally. Orbital habitats do not depend on a planet's natural environment and are an important means of space colonization that expands the habitable zone of star systems. In the E16 civilization zone, orbital habitats ranging from tens of thousands to hundreds of thousands of people are operational, functioning as autonomous space cities with composite functions of residence, research, and manufacturing."},{id:"tech-particle-beam-weapon",name:"粒子ビーム砲",nameEn:"Particle Beam Weapon",category:"技術",subCategory:"技術・概念",description:"高エネルギー粒子の指向性ビームを標的に照射して破壊する直接エネルギー兵器であり、粒子加速器の技術を軍事転用したものである。荷電粒子ビーム（陽子や電子）と中性粒子ビーム（中性子）の二つの方式があり、荷電粒子ビームは大気中での電離散乱により到達距離が制限されるが、中性子ビームは物質透過性が高く長距離の攻撃が可能である。粒子ビームの破壊メカニズムは、高エネルギー粒子が標的物質の原子と衝突してカスケード的な二次粒子反応を引き起こし、標的内部で急激な熱エネルギーの堆積と構造的破壊を生じさせる点にある。E16文明圏では宇宙艦隊の主力兵器として搭載され、大質量加速器を必要とするため大型艦船に限定して配備されている。ビームの集束と大気中での減衰の問題が技術的な課題である。",descriptionEn:"Directed energy weapons that destroy targets by irradiating them with a directed beam of high-energy particles, a military application of particle accelerator technology. There are two types: charged particle beams (protons or electrons) and neutral particle beams (neutrons). Charged particle beams are limited in range due to ionization scattering in the atmosphere, but neutral particle beams have high material penetration and enable long-range attacks. The destruction mechanism of particle beams lies in high-energy particles colliding with atoms in the target material, causing cascade secondary particle reactions, resulting in rapid heat energy accumulation and structural destruction within the target. In the E16 civilization zone, it is equipped as a main weapon of space fleets and is deployed only on large ships that require massive accelerators. Beam focusing and attenuation in the atmosphere are technical challenges."},{id:"tech-emp-weapon",name:"電磁パルス兵器",nameEn:"EMP Weapon",category:"技術",subCategory:"技術・概念",description:"高強度の電磁パルスを発生させて広範囲の電子機器を破壊または一時的に無効化する兵器であり、核爆発のガンマ線が大気中の分子を電離して生成するコンプトン電子による電磁パルス効果を非核の手段で再現したものである。電磁パルス兵器には爆縮型磁束圧縮発電機（MFCG）を用いたものや、高功率マイクロ波（HPM）を指向性ビームとして照射するものがある。電磁パルスはファラデーケージや電磁シールドで防御可能であるが、E16文明圏の高度な電子機器依存社会においては、広範囲の通信・電力・セル・ウィーヴなどの機能不全が致命的な影響をもたらす。EMP兵器の使用は国際条約で厳しく制限されており、非致死性兵器としての限定的な用途が議論されている。",descriptionEn:"Weapons that generate high-intensity electromagnetic pulses to destroy or temporarily disable electronic equipment over a wide area, reproducing the electromagnetic pulse effect of Compton electrons generated by ionizing atmospheric molecules with gamma rays from nuclear explosions through non-nuclear means. Electromagnetic pulse weapons include those using flux compression generators (FCGs) and those that irradiate high-power microwaves (HPM) as directed beams. Electromagnetic pulses can be defended against with Faraday cages or electromagnetic shielding, but in the E16 civilization's highly electronic-dependent society, widespread failures in communication, power, cellular, and weave functions can have fatal impacts. The use of EMP weapons is strictly restricted by international treaties, and limited uses as non-lethal weapons are being discussed."},{id:"tech-defense-shield",name:"防衛シールド",nameEn:"Defense Shield",category:"技術",subCategory:"技術・概念",description:"宇宙船や都市構造物の周囲にエネルギー障壁を展開して、物理的な攻撃とエネルギービームの両方を防御する技術である。防衛シールドの原理はカシミール効果の応用による負のエネルギー密度の局所的生成と、超伝導磁石による強力な磁場の形成を組み合わせたものである。磁気防御層は荷電粒子ビームとプラズマ兵器をローレンツ力で偏向させ、エネルギー障壁層はレーザーと粒子ビームのエネルギーを吸収・散乱する。シールドの強度は投入エネルギーに比例し、持続的な防御には大規模な電源が必要である。E16文明圏では軍用宇宙艦の標準装備として広く採用されており、都市規模の防衛シールドシステムも主要植民地に配備されている。シールドの有効性は攻撃の周波数とエネルギー密度に依存し、特定の周波数のレーザーに対する脆弱性が技術的な課題である。",descriptionEn:"A technology that deploys energy barriers around spacecraft and urban structures to defend against both physical attacks and energy beams. The principle of defensive shields combines the local generation of negative energy density through the application of the Casimir effect with the formation of powerful magnetic fields using superconducting magnets. The magnetic defense layer deflects charged particle beams and plasma weapons through Lorentz force, while the energy barrier layer absorbs and scatters the energy of lasers and particle beams. The strength of the shield is proportional to the energy input, and continuous defense requires a large-scale power supply. In the E16 civilization zone, it is widely adopted as standard equipment for military spacecraft, and city-scale defense shield systems have been deployed to major colonies. The effectiveness of the shield depends on the frequency and energy density of the attack, and vulnerability to lasers of specific frequencies is a technical challenge."},{id:"tech-kinetic-orbital-strike",name:"キネティック軌道打撃",nameEn:"Kinetic Orbital Strike",category:"技術",subCategory:"技術・概念",description:"軌道上から高密度の質量体を地表に落下させ、運動エネルギーの変換による破壊効果を利用する兵器システムである。質量体はタングステンや劣化ウランなどの超高密度金属で構成され、軌道速度（約7.9km/s）と重力加速を組み合わせた着弾速度はマッハ10以上に達する。運動エネルギー E=1/2mv² に基づき、数トンの質量体が核兵器に匹敵する破壊力を発揮し、放射性降下物を伴わない「クリーンな」大量破壊兵器としての特性を持つ。キネティック軌道打撃の照準と投下には軌道力学の精密な計算が必要であり、大気圏再突入時のプラズマ加熱による質量体の溶損を防ぐためのアブレーションシールドが不可欠である。E16文明圏では国際条約によって軌道打撃兵器の保有が厳しく制限されているが、一部の国家による秘密開発の報告が存在する。",descriptionEn:"A weapon system that drops high-density masses from orbit to the surface, utilizing the destructive effect of kinetic energy conversion. The masses are composed of ultra-dense metals such as tungsten or depleted uranium, and the impact velocity, combining orbital speed (approximately 7.9km/s) and gravitational acceleration, reaches Mach 10 or more. Based on the kinetic energy formula E=1/2mv², a mass of several tons can exhibit destructive power equivalent to nuclear weapons, possessing the characteristics of a 'clean' weapon of mass destruction without radioactive fallout. Precise calculations of orbital mechanics are required for aiming and dropping kinetic orbital strikes, and an ablation shield is essential to prevent melting of the mass due to plasma heating during atmospheric re-entry. In the E16 civilization zone, the possession of orbital strike weapons is strictly limited by international treaties, but reports of secret development by some countries exist."},{id:"tech-stealth-field",name:"ステルス・フィールド",nameEn:"Stealth Field",category:"技術",subCategory:"技術・概念",description:"対象物の電磁放射を吸収または制御して、レーダー、赤外線センサー、光学的観測などの各種探知手段から対象を隠蔽する技術である。ステルス・フィールドの高度な形態では、対象物の周囲の電磁波の屈折率を負屈折率メタマテリアルを用いて制御し、入射光を対象物の周囲を迂回させることで完全な視覚的不可視化を実現する。また、対象物から放出される熱輻射を吸収して再放射を遅延させる熱的ステルス機能と、能動的な電子戦機能を組み合わせた複合ステルスシステムが実用化されている。メタマテリアルの微小構造は可視光から赤外線、マイクロ波に至る広帯域の電磁波に対して設計可能であり、周波数に応じた最適なステルス性能を発揮する。E16文明圏では軍用宇宙艦の標準機能として採用され、偵察活動において極めて重要な役割を果たしている。",descriptionEn:"A technology that absorbs or controls the electromagnetic radiation of an object to conceal it from various detection methods such as radar, infrared sensors, and optical observation. In advanced forms of stealth fields, the refractive index of electromagnetic waves around the object is controlled using negative refractive index metamaterials, achieving complete visual invisibility by causing incident light to bypass the object. Additionally, composite stealth systems combining thermal stealth functions that absorb and delay re-radiation of thermal radiation emitted from the object with active electronic warfare capabilities have been put into practical use. The microstructure of metamaterials can be designed for a wide range of electromagnetic waves from visible light to infrared and microwaves, providing optimal stealth performance depending on the frequency. In the E16 civilization zone, it is adopted as a standard function for military spacecraft and plays an extremely important role in reconnaissance activities."},{id:"tech-quantum-computing",name:"量子コンピューティング",nameEn:"Quantum Computing",category:"技術",subCategory:"技術・概念",description:"量子ビット（qubit）の重ね合わせと量子もつれを利用して、古典コンピュータでは実用的な時間内に解けない問題を効率的に計算する次世代計算パラダイムである。超伝導量子ビット、イオントラップ、光量子ビットなどの物理的実現方式が研究されており、E16文明圏では超伝導トランスモン量子ビットが主流として採用されている。量子コンピューティングの計算能力は量子ビット数に対して指数関数的に増大し、Shorのアルゴリズムによる素因数分解やGroverのアルゴリズムによるデータベース探索において古典コンピュータを圧倒する性能を示す。量子誤り訂正符号（表面符号や色符号）の実装により、環境ノイズによるデコヒーレンスの影響を補償し、大規模な量子計算の信頼性を確保している。E16文明圏のあらゆる分野に量子コンピューティングが浸透しており、材料科学、暗号解読、金融工学、薬剤設計などで革命的な進歩をもたらしている。",descriptionEn:"A next-generation computing paradigm that efficiently solves problems that classical computers cannot solve within practical time by utilizing the superposition and entanglement of quantum bits (qubits). Physical implementations such as superconducting qubits, ion traps, and photonic qubits are being researched, and in the E16 civilization zone, superconducting transmon qubits are mainstream. The computing power of quantum computing increases exponentially with the number of qubits, showing overwhelming performance over classical computers in Shor's algorithm for factorization and Grover's algorithm for database search. By implementing quantum error correction codes (surface codes or color codes), the effects of decoherence due to environmental noise are compensated, ensuring the reliability of large-scale quantum computation. Quantum computing has permeated all fields in the E16 civilization zone, bringing revolutionary advances in materials science, cryptography, financial engineering, and drug design."},{id:"tech-neural-interface",name:"ニューラルインターフェース",nameEn:"Neural Interface",category:"技術",subCategory:"技術・概念",description:"人間の神経系とデジタルシステムを直接的に接続する技術であり、脳内のニューロン活動を高精度に読み取り、外部デバイスとの双方向通信を実現する。非侵襲型の脳波センサーと侵襲型の脳内インプラントの二つのアプローチがあり、高帯域の通信には皮質内に微小電極アレイを埋め込む侵襲型が使用される。ニューラルインターフェースの信号処理にはディープラーニングを応用したニューラルデコーダーが使用され、脳活動パターンを運動指令や言語情報として解読する。E16文明圏ではペルセポネ仮想宇宙へのアクセス、義肢や外骨格の制御、言語障害者のコミュニケーション支援などに幅広く応用されている。脳と機械の境界が曖昧になることによる倫理的問題が議論の的であり、ニューラルインターフェースを通じた脳への外部介入の安全性確保が重要な課題である。",descriptionEn:"A technology that directly connects the human nervous system with digital systems, enabling high-precision reading of neuron activity within the brain and bidirectional communication with external devices. There are two approaches: non-invasive EEG sensors and invasive brain implants, with the invasive approach being used for high-bandwidth communication by embedding microelectrode arrays in the cortex. Neural decoders applying deep learning are used for signal processing in neural interfaces, decoding brain activity patterns into motor commands or linguistic information. In the E16 civilization zone, it is widely applied for accessing the Persephone virtual universe, controlling prosthetics and exoskeletons, and supporting communication for people with language disorders. Ethical issues arising from the blurring boundary between brain and machine are a topic of debate, and ensuring the safety of external intervention to the brain through neural interfaces is an important challenge."},{id:"tech-artificial-general-intelligence",name:"人工一般知能",nameEn:"Artificial General Intelligence",category:"技術",subCategory:"技術・概念",description:"人間と同等以上の汎用的な知能を備えた人工知能システムであり、特定のタスクに最適化された狭義AIとは異なり、未だ経験したことのない問題に対しても人間のように推論と学習を行う能力を持つ。AGIの実現には意識の困難問題とも関連し、「知能は計算によってどの程度再現可能か」という根本的な問いを含んでいる。E16文明圏では量子コンピューティングの能力を背景にAGIの実現が着実に進んでおり、自律的な意思決定と創造的問題解決を行うAGIシステムが政府機関や大企業の意思決定支援に活用されている。AGIの安全性確保はE16文明圏における最重要の技術倫理課題であり、アライメント問題（AGIの目標と人類の価値の整合性）の解決に向けた研究がグランベルを中心に進められている。",descriptionEn:"An artificial intelligence system with general intelligence equal to or greater than that of humans, different from narrow AI optimized for specific tasks, possessing the ability to reason and learn like humans even for problems not yet experienced. The realization of AGI is related to the hard problem of consciousness and includes the fundamental question of 'to what extent can intelligence be reproduced through computation.' In the E16 civilization zone, the realization of AGI is steadily progressing with the support of quantum computing capabilities, and AGI systems that make autonomous decisions and solve creative problems are being utilized for decision support by government agencies and large corporations. Ensuring the safety of AGI is the most important technical ethics issue in the E16 civilization zone, and research aimed at solving the alignment problem (the consistency between AGI's goals and human values) is progressing centered around Granbel."},{id:"tech-swarm-intelligence",name:"群知能",nameEn:"Swarm Intelligence",category:"技術",subCategory:"技術・概念",description:"多数の自律型エージェントが局所的な相互作用を通じて、全体として高度な知的行動を発現する分散型知能システムである。自然界における蟻の巣作りや鳥の群れ飛行（ミurmuration）の集団行動を数学的にモデル化し、セルオートマトンと情報理論の枠組みで工学的に実装したものである。各エージェントは自身の周囲の情報のみを利用して行動を決定し、Shannonエントロピーを用いた局所的な情報交換プロトコルによって全体としての最適解に収束する。群知能システムは単一のエージェントの故障に対して極めて堅牢であり、局所的な損失がシステム全体の機能に致命的な影響を与えない。E16文明圏では宇宙船の自己修復システム、大規模な物流ネットワークの最適化、災害救助ロボット群の統合制御などに応用されている。",descriptionEn:"A distributed intelligence system where multiple autonomous agents exhibit highly intelligent behavior through local interactions. It mathematically models collective behaviors such as ant colony building and bird murmuration in nature, and is implemented using cellular automata and information theory frameworks. Each agent determines its actions using only local information and converges to an optimal solution through local information exchange protocols using Shannon entropy. Swarm intelligence systems are extremely robust against the failure of individual agents, and local losses do not fatally affect the overall system functionality. In the E16 civilization sphere, it is applied to spacecraft self-repair systems, optimization of large-scale logistics networks, and integrated control of disaster rescue robot swarms."},{id:"tech-closed-ecosystem",name:"閉鎖循環生態系",nameEn:"Closed-Loop Ecosystem",category:"技術",subCategory:"技術・概念",description:"外部との物質交換を最小限に抑え、酸素、水、栄養素などの生命維持物質を内部で循環・再生する自己完結型の生態系である。熱力学の第二法則に従い、閉鎖系ではエントロピーの増大が不可避であるが、外部からのエネルギー入力（太陽光や核融合炉）によって系のエントロピーを排出し、定常状態を維持する。酸素循環は光合成微生物と藻類の培養槽が担当し、二酸化炭素の吸収と酸素の生成を同時に行う。水循環は蒸留と膜分離技術を組み合わせた高度な浄水システムによって維持され、栄養循環は廃棄物の生物学的分解と再利用によって実現される。E16文明圏では軌道ハビタットや長期間の宇宙航行において不可欠な基盤技術であり、生態系の安定性を維持するための冗長性と多様性の設計が重要な課題となっている。",descriptionEn:"A self-contained ecosystem that minimizes material exchange with the outside while circulating and regenerating life-sustaining substances like oxygen, water, and nutrients internally. Following the second law of thermodynamics, entropy increase in a closed system is inevitable, but the system maintains a steady state by discharging entropy through external energy input (such as sunlight or fusion reactors). Oxygen circulation is handled by phototrophic microbial and algal cultures that simultaneously absorb carbon dioxide and produce oxygen. Water circulation is maintained by an advanced water purification system combining distillation and membrane separation technologies, while nutrient circulation is achieved through biological decomposition and reuse of waste. In the E16 civilization sphere, this is an essential foundation technology for orbital habitats and long-term space voyages, with maintaining ecosystem stability through redundancy and diversity being a key design challenge."},{id:"tech-artificial-hibernation",name:"人工冬眠",nameEn:"Artificial Hibernation",category:"技術",subCategory:"技術・概念",description:"人間の生体機能を低減状態に移行させ、長期間の代謝抑制を実現する技術である。自然の冬眠現象を示す哺乳類の生理メカニズムを参考にし、体温の低下に伴う代謝率の指数関数的な減少を利用して、栄養消費と老朽化の速度を大幅に遅延させる。人工冬眠の導入には細胞保護剤（クライオプロテクトant）の投与と、生体の冷却・保温を精密に制御する医療システムが必要である。細胞レベルでは熱ショックタンパク質の発現誘導と、低体温状態での血液凝固防止が技術的な課題である。E16文明圏では恒星間航行の乗員の長期休眠や、医療資源の限られた環境での患者の一時的保存に応用されている。人工冬眠からの覚醒プロセスにおける生体機能の回復時間の短縮と、長期間の代謝抑制による筋肉萎縮や骨密度低下の防止が持続的な研究課題である。",descriptionEn:"A technology that shifts human biological functions into a reduced state, achieving long-term metabolic suppression. Referencing the hibernation phenomenon in mammals, it utilizes the exponential decrease in metabolic rate accompanying body temperature reduction to significantly slow the rate of nutrient consumption and aging. The induction of artificial hibernation requires cryoprotectant administration and a medical system that precisely controls body cooling and insulation. At the cellular level, inducing heat shock protein expression and preventing blood clotting in hypothermic states are technical challenges. In the E16 civilization sphere, it is applied to crew hibernation during interstellar voyages and temporary preservation of patients in environments with limited medical resources. Shortening the recovery time of biological functions during awakening from artificial hibernation and preventing muscle atrophy and bone density loss from long-term metabolic suppression are ongoing research challenges."},{id:"tech-radiation-protection",name:"放射線防護",nameEn:"Radiation Protection",category:"技術",subCategory:"技術・概念",description:"宇宙空間における高エネルギー宇宙放射線（太陽フレア粒子、銀河宇宙線など）から人命と電子機器を保護する技術体系である。受動的防護では水、ポリエチレン、アルミニウムなどの材料の質量厚によって放射線を減衰させ、能動的防護では超伝導磁石による強力な磁場を生成して荷電粒子をローレンツ力で偏向させる。E16文明圏ではセル・ウィーヴの放射線修復機能と組み合わせた多層的な防護システムが採用されている。宇宙放射線の中でも特に高いエネルギーを持つ重イオン（HZE粒子）は、材料中でのカスケード的な二次粒子生成を引き起こし、電子機器のシングルイベント・アップセット（SEU）の主要原因となるため、量子エラー訂正符号を用いた放射線耐性電子回路の開発が進められている。",descriptionEn:"A technical system for protecting human life and electronic equipment from high-energy space radiation (such as solar flare particles and galactic cosmic rays). Passive protection attenuates radiation through the mass thickness of materials like water, polyethylene, and aluminum, while active protection generates powerful magnetic fields using superconducting magnets to deflect charged particles via Lorentz force. In the E16 civilization sphere, a multi-layered protection system combined with Cell-Weave's radiation repair functions is adopted. Among cosmic rays, high-energy heavy ions (HZE particles) particularly cause cascade secondary particle generation in materials and are a primary cause of single-event upsets (SEUs) in electronic equipment, so the development of radiation-resistant electronic circuits using quantum error correction codes is being advanced."},{id:"tech-atmosphere-converter",name:"大気変換装置",nameEn:"Atmosphere Converter",category:"技術",subCategory:"技術・概念",description:"惑星の既存の大気組成を人類の居住に適した組成に変換する大規模な化学・生物学的処理システムである。大気変換装置は触媒反応槽と光合成バイオリアクターを組み合わせ、二酸化炭素を酸素と炭素に変換し、窒素の比率を調整して適切な大気圧を維持する。変換プロセスは熱力学の自由エネルギーの変化に従って進行し、外部からのエネルギー供給が必要である。E16文明圏ではテラフォーミングの初期段階において大気変換装置が重要な役割を果たしており、惑星規模の変換には数十年から数百年の期間が必要とされる。大気変換の効率は触媒の性能とバイオリアクターの光合成速度に依存し、遺伝子工学による光合成微生物の性能向上が持続的な課題である。変換された大気の長期的な安定性維持には、惑星の地質学的・生物学的な炭素循環メカニズムの確立が不可欠である。",descriptionEn:"A large-scale chemical and biological processing system that transforms a planet's existing atmospheric composition into one suitable for human habitation. The atmospheric converter combines catalytic reaction tanks and photosynthetic bioreactors to convert carbon dioxide into oxygen and carbon, adjusting nitrogen ratios to maintain appropriate atmospheric pressure. The conversion process proceeds according to changes in thermodynamic free energy and requires external energy supply. In the E16 civilization sphere, atmospheric converters play an important role in the initial stages of terraforming, with planetary-scale transformation requiring decades to centuries. The efficiency of atmospheric conversion depends on catalyst performance and bioreactor photosynthesis speed, with continuous research focused on improving photosynthetic microorganisms through genetic engineering. Establishing the planet's geological and biological carbon cycle mechanisms is essential for maintaining long-term stability of the transformed atmosphere."},{id:"tech-asteroid-mining",name:"小惑星採掘",nameEn:"Asteroid Mining",category:"技術",subCategory:"技術・概念",description:"小惑星帯や近地球小惑星に含まれる貴金属、希土類元素、水などの資源を採掘する技術体系である。小惑星には地球上で枯渇が懸念される白金族元素やレアアースが豊富に含まれており、C型小惑星には大量の水が存在する。採掘方法には小惑星表面での直接的な切削掘削と、小惑星を捕獲して軌道上で処理する方式がある。採掘された資源の精製には宇宙空間での無重力冶金技術が使用され、太陽炉による高温度処理で金属を分離する。E16文明圏では小惑星採掘が宇宙経済の重要な基盤産業として確立されており、プロキオのレーン・システムを通じて採掘資源の輸送と取引が行われている。小惑星採掘の経済性は輸送コストと資源価格に依存し、軌道エレベーターやマスドライバーの整備が採掘コストの削減に貢献している。",descriptionEn:"A technical system for mining resources such as precious metals, rare earth elements, and water from the asteroid belt and near-Earth asteroids. Asteroids contain abundant platinum group elements and rare earths that are depleted on Earth, and C-type asteroids contain large amounts of water. Mining methods include direct surface excavation and capturing asteroids for processing in orbit. Space-based zero-gravity metallurgy technology is used for refining mined resources, with solar furnaces performing high-temperature separation of metals. In the E16 civilization sphere, asteroid mining has been established as a key foundational industry of the space economy, with mining resources transported and traded through the Procyon Lane system. The economic viability of asteroid mining depends on transportation costs and resource prices, with the development of orbital elevators and mass drivers contributing to cost reduction."},{id:"tech-gas-giant-extraction",name:"ガス巨人大気採取",nameEn:"Gas Giant Atmospheric Extraction",category:"技術",subCategory:"技術・概念",description:"木星型惑星や土星型惑星の大気中に豊富に存在するヘリウム3、重水素、水素などの資源を採取する技術である。ガス巨星の大気上層に浮遊する採取プラットフォームからパイプラインを大気深部に伸ばし、分離膜と遠心分離機を用いて目的のガスを抽出する。ヘリウム3は核融合炉の燃料として極めて重要であり、ガス巨星の大気中には地球上の何百万倍ものヘリウム3が存在すると推定されている。ガス巨星の強力な重力場と激しい大気運動は採取プラットフォームの設計に厳しい条件を課し、浮力と推進力のバランスを精密に制御する必要がある。E16文明圏では数箇所のガス巨星で大気採取プラットフォームが稼働しており、採取されたヘリウム3は核融合炉の燃料として全文明圏に供給されている。",descriptionEn:"A technology for extracting resources such as helium-3, deuterium, and hydrogen, which are abundant in the atmospheres of Jupiter-type and Saturn-type planets. It involves extending pipelines from extraction platforms floating in the upper atmosphere of gas giants to deeper atmospheric layers, using separation membranes and centrifuges to extract the desired gases. Helium-3 is extremely important as fuel for fusion reactors, and it is estimated that gas giant atmospheres contain millions of times more helium-3 than Earth. The powerful gravitational fields and violent atmospheric movements of gas giants impose strict conditions on the design of extraction platforms, requiring precise control of the balance between buoyancy and thrust. In the E16 civilization sphere, atmospheric extraction platforms are operational at several gas giants, and the extracted helium-3 is supplied to the entire civilization sphere as fuel for fusion reactors."},{id:"tech-nuclear-transmutation",name:"核変換技術",nameEn:"Nuclear Transmutation",category:"技術",subCategory:"技術・概念",description:"ある化学元素を別の化学元素に変換する技術であり、原子核物理学における核反応を工学的に制御したものである。核変換技術には原子炉内の中性子照射による元素変換、粒子加速器による荷電粒子衝突による変換、レーザー誘起核反応による変換などの方式がある。核変換技術の重要な応用として、放射性廃棄物の半減期の短縮（核廃棄物のトランスミュテーション）、貴金属の人工合成、核融合炉の燃料生産などが挙げられる。E16文明圏では核廃棄物の処理において核変換技術が不可欠な役割を果たしており、長半減期の超ウラン元素を安定同位体または短半減期の核種に変換することで、放射性廃棄物の管理期間を大幅に短縮している。核変換の効率向上とエネルギーコストの削減が技術的な課題である。",descriptionEn:"A technology that converts one chemical element into another, based on the engineering control of nuclear reactions in nuclear physics. Nuclear transmutation techniques include methods such as element conversion through neutron irradiation in reactors, conversion through charged particle collisions using particle accelerators, and conversion through laser-induced nuclear reactions. Important applications of nuclear transmutation technology include shortening the half-life of radioactive waste (transmutation of nuclear waste), artificial synthesis of precious metals, and fuel production for fusion reactors. In the E16 civilization sphere, nuclear transmutation technology plays an indispensable role in the treatment of radioactive waste, significantly reducing the management period of radioactive waste by converting long-half-life transuranic elements into stable isotopes or short-half-life nuclides. Improving the efficiency of nuclear transmutation and reducing energy costs are technical challenges."},{id:"tech-mass-driver",name:"マスドライバー",nameEn:"Mass Driver",category:"技術",subCategory:"技術・概念",description:"電磁力を利用して質量体を高速で加速・投射する装置であり、コイルガン（電磁砲）の大規模な応用形態である。マスドライバーは直列に配置された電磁コイルにパルス電流を順次供給し、ローレンツ力によって投射体を加速する。大気のない天体表面に建設されたマスドライバーは、鉱石や物資を軌道上の施設へ投射する低コストな輸送手段として機能し、化学ロケットによる打ち上げコストを大幅に削減する。投射体は軌道上で回収され、軌道エレベーターや宇宙船に積載される。E16文明圏では小惑星や月面の資源採掘拠点にマスドライバーが設置されており、採掘された資源の惑星間輸送の第一段階として機能している。加速コイルの超伝導化と投射体の空力加熱対策が技術的な課題である。",descriptionEn:"A device that uses electromagnetic force to accelerate and propel mass bodies at high speeds, representing a large-scale application of coilguns (electromagnetic guns). A mass driver sequentially supplies pulsed current to electromagnetically arranged coils in series, accelerating the projectile through Lorentz force. Mass drivers constructed on airless celestial bodies function as a low-cost transportation method for projecting ores and materials to orbital facilities, significantly reducing launch costs compared to chemical rockets. Projectiles are recovered in orbit and loaded onto space elevators or spaceships. In the E16 civilization sphere, mass drivers are installed at resource mining bases on asteroids and the lunar surface, serving as the first stage for interplanetary transportation of extracted resources. Superconducting of acceleration coils and countermeasures for aerodynamic heating of projectiles are technical challenges."},{id:"tech-teleporter-gate",name:"テレポーターゲート",nameEn:"Teleporter Gate",category:"技術",subCategory:"技術・概念",description:"量子テレポーテーション技術を大規模にスケールアップした固定型の輸送装置であり、ゲート間を結ぶ安定した量子もつれチャネルを維持して、人員や物資の空間転送を実現する。テレポーターゲートは事前に共有された量子もつれペアの集合を内蔵し、転送対象の量子状態を測定・破壊して受信側で完全に再構成する。転送される情報量は対象の質量に比例し、人間一人の転送には約10の27乗個の量子ビットの情報処理が必要である。テレポーターゲートの最大転送距離は量子もつれペアのデコヒーレンス時間によって制限され、長距離転送には量子中継器ネットワークが必要である。E16文明圏では主要都市間と軌道施設間にテレポーターゲートが設置されており、瞬時の輸送ネットワークを構成している。",descriptionEn:"A fixed transportation system that scales up quantum teleportation technology, maintaining stable quantum entanglement channels between gates to achieve spatial teleportation of personnel and materials. Teleporter gates contain pre-shared sets of entangled quantum pairs, measuring and destroying the quantum state of the teleportation object to completely reconstruct it at the receiving end. The amount of information transmitted is proportional to the mass of the object, and teleporting one person requires processing information from approximately 10^27 quantum bits. The maximum teleportation distance of a teleporter gate is limited by the decoherence time of the entangled quantum pairs, requiring quantum repeater networks for long-distance transmission. In the E16 civilization sphere, teleporter gates are installed between major cities and orbital facilities, forming an instantaneous transportation network."},{id:"tech-orbital-transfer",name:"軌道トランスファー",nameEn:"Orbital Transfer",category:"技術",subCategory:"技術・概念",description:"惑星間の軌道遷移を効率的に実行するための軌道力学技術体系であり、ホーマン遷移軌道やランベルト問題の解法を応用して最小エネルギーでの軌道間移動を計画・実行する。軌道トランスファーは出発軌道と到着軌道の速度差（デルタV）を最小化する軌道設計を必要とし、惑星の重力場を利用したスイングバイや大気上層での空力ブレーキを組み合わせた複合軌道が一般的に採用されている。E16文明圏ではプロキオのレーン・システムが全恒星系間の軌道トランスファーを統合管理し、AI駆動の軌道最適化アルゴリズムが天体の位置情報と燃料消費を総合的に分析して最適な遷移軌道を算出する。軌道トランスファー・ビークル（OTV）は再使用型の宇宙タグボートとして機能し、宇宙船の軌道間移動を支援する。",descriptionEn:"An orbital mechanics technology system for efficiently executing interplanetary orbital transitions, applying solutions to Hohmann transfer orbits and Lambert's problem to plan and execute inter-orbital movement with minimal energy. Orbital transfer requires orbital design that minimizes the velocity difference (delta-V) between the departure and arrival orbits, and composite orbits combining gravity assists using planetary gravitational fields and aerobraking in the upper atmosphere are commonly adopted. In the E16 civilization sphere, Procyon's Lane system centrally manages orbital transfers across the entire star system, with AI-driven orbital optimization algorithms comprehensively analyzing celestial body position information and fuel consumption to calculate optimal transfer orbits. Orbital Transfer Vehicles (OTVs) function as reusable space tugs, assisting spacecraft with inter-orbital movement."},{id:"tech-sublight-interstellar",name:"亜光速星間輸送",nameEn:"Sublight Interstellar Transport",category:"技術",subCategory:"技術・概念",description:"光速未満の速度で恒星間空間を航行する輸送システムであり、特殊相対性理論のローレンツ因子 γ=1/√(1-v²/c²) に従い、光速に近づくにつれて時間遅延効果が顕著になる。亜光速星間輸送船は反物質エンジンまたは核融合パルス推進を主推進力として採用し、長期間の連続加速と減速により目的地恒星系に到達する。船内時間は地球時間に比べて大幅に短縮されるため、乗員は相対論的効果による時間遅延の恩恵を受けるが、出発時の地球との通信には片道の航行年数に等しい時間的遅れが生じる。E16文明圏では曲率航法やホライゾン・ゲートが利用できない遠距離の恒星間航行において亜光速輸送が補完的な役割を果たしており、人工冬眠システムと組み合わせた数十年規模の長期航行が実施されている。",descriptionEn:"A transportation system that navigates interstellar space at sublight speeds, following the Lorentz factor γ=1/√(1-v²/c²) of special relativity, where time dilation effects become more pronounced as the speed approaches light speed. Sublight interstellar transport ships employ antimatter engines or fusion pulse propulsion as their main thrust, reaching destination star systems through long periods of continuous acceleration and deceleration. Time on board is significantly shortened compared to Earth time, allowing crew members to benefit from the time dilation effects of relativity, but communication with Earth at departure experiences a time delay equal to the one-way voyage duration. In the E16 civilization sphere, sublight transportation serves a complementary role in interstellar navigation at distances where curvature navigation or Horizon Gates cannot be used, with long-duration voyages spanning decades being implemented in combination with artificial hibernation systems."},{id:"tech-biometric-auth",name:"生体認証",nameEn:"Biometric Authentication",category:"技術",subCategory:"技術・概念",description:"人間の生体的特徴を用いた個人認証技術であり、指紋、虹彩、網膜パターン、顔面の幾何学的特徴、声紋、DNA配列などの個体固有の生体情報を量子センサーで高精度に読み取る。生体認証の情報理論的安全性は、生体特徴のエントロピー（情報量）によって定量化され、より高いエントロピーを持つ生体特徴ほど偽造が困難である。E16文明圏では多因子生体認証が標準的に採用され、複数の生体特徴を組み合わせることで認証の信頼性を飛躍的に向上させている。量子暗号を応用した生体情報の伝送と保存により、中間者攻撃やデータベースの改ざんに対する耐性が確保されている。生体認証の普及は利便性の向上をもたらす一方で、生体情報の漏洩が生涯にわたる影響をもたらすという固有のリスクを抱えており、生体情報の取り消し可能性を確保する技術開発が進められている。",descriptionEn:"A personal authentication technology using human biological characteristics, which reads unique biological information such as fingerprints, iris patterns, retinal patterns, facial geometric features, voiceprints, and DNA sequences with high precision using quantum sensors. The information-theoretic security of biometric authentication is quantified by the entropy (information content) of biometric features, and biometric features with higher entropy are more difficult to forge. In the E16 civilization zone, multi-factor biometric authentication is standardly adopted, combining multiple biometric features to dramatically improve authentication reliability. By applying quantum cryptography to the transmission and storage of biometric information, resistance to man-in-the-middle attacks and database tampering is ensured. While the普及 of biometric authentication improves convenience, it carries the inherent risk that leakage of biometric information can have lifelong impacts, and technological development to ensure the revocability of biometric information is progressing."},{id:"tech-quantum-cryptography",name:"量子暗号",nameEn:"Quantum Cryptography",category:"技術",subCategory:"技術・概念",description:"量子力学の基本原理を応用した情報理論的に安全な暗号方式であり、量子鍵配送（QKD）プロトコルがその代表例である。量子鍵配送では偏光や位相の量子状態を情報キャリアとして利用し、量子もつれの特性を活かして盗聴の有無を検出する。盗聴者が量子状態を測定すると波動関数の収縮により不可逆的な乱れが生じ、送信者と受信者が量子ビット誤り率の上昇から盗聴を検知できる。この特性により、量子暗号は計算能力に依存しない情報理論的安全性を保証し、Shorのアルゴリズムに対する耐性も持つ。E16文明圏では政府機関、軍事通信、金融機関の通信インフラに量子暗号が標準的に導入されており、ロースターのクアンタ・ラボが次世代の量子暗号プロトコルの開発を主導している。",descriptionEn:"A cryptographically secure information-theoretically secure cryptographic method based on the basic principles of quantum mechanics, with quantum key distribution (QKD) protocols as its representative example. In quantum key distribution, polarization and quantum states are used as information carriers, and the characteristics of quantum entanglement are utilized to detect the presence of eavesdropping. When an eavesdropper measures a quantum state, irreversible disturbance occurs due to wave function collapse, and the sender and receiver can detect eavesdropping from the increase in quantum bit error rates. This characteristic ensures information-theoretic security that does not depend on computing power and also has resistance against Shor's algorithm. In the E16 civilization zone, quantum cryptography is standardly introduced into the communication infrastructure of government agencies, military communications, and financial institutions, with Looster's Quanta Lab leading the development of next-generation quantum cryptography protocols."},{id:"tech-cyber-defense",name:"サイバー防御システム",nameEn:"Cyber Defense System",category:"技術",subCategory:"技術・概念",description:"情報ネットワークへの不正アクセスやサイバー攻撃を検知・防御する統合的なセキュリティシステムであり、人工知能と量子コンピューティングを組み合わせた多層的な防御アーキテクチャを採用している。サイバー防御システムは侵入検知システム（IDS）、侵入防止システム（IPS）、ネットワークトラフィックの異常検知、マルウェアの自動分析・除去などの機能を統合し、Shannonエントロピーを用いた通信パターンの異常検知によって未知の攻撃を検出する。E16文明圏ではナノハッキング技術や次元境界を利用した新種のサイバー攻撃の出現により、従来の防御手法では対抗不可能な脅威が増大している。量子コンピューティングを応用した脅威分析と、ポスト量子暗号を用いた通信の暗号化がサイバー防御の最新の展開であり、グランベルとロースターが共同で宇宙規模のサイバー防御網の構築を進めている。",descriptionEn:"An integrated security system that detects and defends against unauthorized access to information networks and cyber attacks, adopting a multi-layered defense architecture combining artificial intelligence and quantum computing. The cyber defense system integrates functions such as intrusion detection systems (IDS), intrusion prevention systems (IPS), abnormal detection of network traffic, and automatic analysis and removal of malware, and detects unknown attacks through abnormal detection of communication patterns using Shannon entropy. In the E16 civilization zone, the emergence of new types of cyber attacks using nano-hacking technology and dimensional boundaries has increased threats that cannot be countered by conventional defense methods. Threat analysis using quantum computing and encryption of communications using post-quantum cryptography are the latest developments in cyber defense, with Granbel and Looster jointly working to build a cosmic-scale cyber defense network."},{id:"tech-terraforming",name:"テラフォーミング",nameEn:"Terraforming",category:"技術",subCategory:"技術・概念",description:"地球外の惑星の環境を人類の居住に適した状態に変革する大規模な環境改変技術であり、惑星の大気組成、表面温度、水循環、生態系を地球に類似した状態に変換する。テラフォーミングは熱力学のエントロピー変化の観点から、外部エネルギーの投入によって惑星環境を低エントロピー状態（居住可能な環境）に維持するプロセスと理解できる。初期段階では温室効果ガスの大気注入による温暖化と、大気変換装置による酸素生成が並行して進められ、中段階では遺伝子改変された微生物による土壌形成と植物の導入が行われる。テラフォーミングの完了には数百年から数千年の期間が必要とされ、大気の化学的安定性と生態系の自己維持能力の確立が技術的な課題である。E16文明圏ではテラフォーミングが複数の惑星で進行中であり、エコシステム工学と組み合わせた効率的な環境改変が目指されている。",descriptionEn:"A large-scale environmental modification technology that transforms the environment of an extraterrestrial planet into a state suitable for human habitation, converting the planet's atmospheric composition, surface temperature, water cycle, and ecosystem into an Earth-like state. From the perspective of thermodynamic entropy changes, terraforming can be understood as a process that maintains the planetary environment in a low-entropy state (habitable environment) through the input of external energy. In the initial stage, warming through the injection of greenhouse gases into the atmosphere and oxygen generation by atmospheric conversion devices proceed in parallel, and in the middle stage, soil formation by genetically modified microorganisms and the introduction of plants are carried out. The completion of terraforming requires a period of several hundred to several thousand years, and establishing the chemical stability of the atmosphere and the self-sustaining capacity of the ecosystem are technical challenges. In the E16 civilization zone, terraforming is in progress on multiple planets, and efficient environmental modification combined with ecosystem engineering is aimed for."},{id:"tech-weather-control",name:"気象制御",nameEn:"Weather Control",category:"技術",subCategory:"技術・概念",description:"惑星規模の気象現象を人為的に制御する技術体系であり、大気物理学と流体力学の原理に基づいて気象パターンを誘導・変更する。気象制御の手段には、大気中の水蒸気の凝縮核を操作して降雨を制御する手法、軌道上の太陽光反射ミラーを用いて日射量を調整する手法、超伝導コイルを用いた人工的な磁場変動によってジェット気流の経路を変更する手法などがある。気象システムはカオス理論の予測不可能性を内在しており、初期条件の微小な変化が大規模な気象変動を引き起こすバタフライ効果の制御が技術的な課題である。E16文明圏では農業生産の安定化と自然災害の防止を目的として気象制御が限定的に実施されており、テラフォーミング済み惑星の気候維持にも応用されている。気象制御の倫理的側面については、一地域の利益が別地域の気象に悪影響を与える可能性が議論されている。",descriptionEn:"A technical system for artificially controlling planetary-scale meteorological phenomena, inducing and changing weather patterns based on the principles of atmospheric physics and fluid dynamics. Methods of weather control include manipulating condensation nuclei of water vapor in the atmosphere to control rainfall, using orbital solar reflection mirrors to adjust solar radiation, and changing the paths of jet streams through artificial magnetic field fluctuations using superconducting coils. Weather systems inherently have the unpredictability of chaos theory, and controlling the butterfly effect, where small changes in initial conditions cause large-scale weather variations, is a technical challenge. In the E16 civilization zone, weather control is limitedly implemented for the purpose of stabilizing agricultural production and preventing natural disasters, and is also applied to maintaining the climate of terraformed planets. Ethical aspects of weather control are being discussed, as the benefits of one region may have negative effects on the weather of another region."},{id:"tech-atmo-terra-conversion",name:"大気変換",nameEn:"Atmospheric Transformation",category:"技術",subCategory:"技術・概念",description:"惑星の大気を根本的に変革する環境改変技術であり、テラフォーミングの中核プロセスの一つとして位置づけられる。大気変換は惑星の既存の大気成分を化学的・生物学的手段で変換し、窒素78パーセント、酸素21パーセント、その他微量ガスからなる地球型大気を構築する。化学的な大気変換では触媒反応槽とプラズマ化学反応を利用し、二酸化炭素を炭素と酸素に分解する。生物学的な大気変換では遺伝子改変されたシアノバクテリアや藻類を大気中に散布し、光合成による酸素生成を加速させる。大気変換の熱力学的効率は入力エネルギー量と変換速度に依存し、惑星規模の変換には恒星の放射エネルギーを効果的に利用する必要がある。E16文明圏では大気変換装置と大気変換の二つの技術体系が統合され、テラフォーミングの実行において相補的な役割を果たしている。",descriptionEn:"An environmental modification technology that fundamentally transforms a planet's atmosphere, positioned as one of the core processes of terraforming. Atmospheric conversion converts the planet's existing atmospheric components through chemical and biological means, constructing an Earth-like atmosphere consisting of 78% nitrogen, 21% oxygen, and other trace gases. In chemical atmospheric conversion, catalytic reaction tanks and plasma chemical reactions are used to decompose carbon dioxide into carbon and oxygen. In biological atmospheric conversion, genetically modified cyanobacteria and algae are dispersed in the atmosphere to accelerate oxygen generation through photosynthesis. The thermodynamic efficiency of atmospheric conversion depends on the amount of input energy and the conversion rate, and effective utilization of the star's radiant energy is necessary for planetary-scale conversion. In the E16 civilization zone, the two technical systems of atmospheric conversion devices and atmospheric conversion are integrated, playing complementary roles in the execution of terraforming."},{id:"tech-ecosystem-engineering",name:"エコシステム工学",nameEn:"Ecosystem Engineering",category:"技術",subCategory:"技術・概念",description:"生態系の構造と機能を工学的に設計・構築・管理する技術体系であり、閉鎖循環生態系の安定性維持とテラフォーミング後の生態系構築を担う。エコシステム工学は熱力学のエントロピー最小化原理と生態学のニッチ理論を統合し、エネルギーの流入と流出のバランスを最適化した人工生態系を設計する。生態系の構成種の選択においては、食物連鎖の多段階構造と物質循環の閉鎖性を確保することが不可欠であり、Shannonエントロピーを指標とした種多様性の管理が行われる。E16文明圏では軌道ハビタットやドーム都市の生態系維持にエコシステム工学が応用され、テラフォーミング済み惑星の生態系の長期的な安定性評価にも使用されている。生態系のカオス的ダイナミクスの予測と制御が技術的な課題であり、量子コンピューティングを応用した大規模な生態系シミュレーションの精度向上が進められている。",descriptionEn:"A technical system that designs, constructs, and manages the structure and function of ecosystems, responsible for maintaining the stability of closed-loop ecosystems and constructing ecosystems after terraforming. Ecosystem engineering integrates the entropy minimization principle of thermodynamics with the niche theory of ecology to design artificial ecosystems with optimized energy inflow and outflow balance. In selecting constituent species of ecosystems, it is essential to ensure the multi-stage structure of the food chain and the closure of material circulation, and species diversity is managed using Shannon entropy as an indicator. In the E16 civilization sphere, ecosystem engineering is applied to maintain ecosystems in orbital habitats and dome cities, and is also used for long-term stability assessment of ecosystems on terraformed planets. Predicting and controlling the chaotic dynamics of ecosystems is a technical challenge, and improvements in the accuracy of large-scale ecosystem simulations using quantum computing are being pursued."},{id:"tech-photon-rocket",name:"光子ロケット",nameEn:"Photon Rocket",category:"技術",subCategory:"技術・概念",description:"光子（電磁波の量子）を推進剤として利用するロケット推進方式であり、アインシュタインの特殊相対性理論において光子が質量と等価の運動量を持つことを利用して推力を得る。光子ロケットの推進剤は物質と反物質の対消滅によって生成される高エネルギーガンマ線光子であり、完全に光速に近い速度で噴射されるため比推力の理論上限に到達する。光子ロケットの最大の利点は推進剤の噴射速度が光速に等しいため、ロケット方程式における質量比を極めて小さく抑えられる点である。E16文明圏では主に探査機や小型宇宙船の推進機として採用されており、反物質エンジンの小型版を動力源として搭載する。光子ロケットの推力は反物質の消費量に比例し、大推力を得るには大量の反物質が必要となるため、大型船舶への適用には限界がある。",descriptionEn:"A rocket propulsion method that utilizes photons (quanta of electromagnetic waves) as propellant, obtaining thrust by utilizing the fact that photons possess momentum equivalent to mass according to Einstein's special theory of relativity. The propellant for photon rockets is high-energy gamma-ray photons generated by the annihilation of matter and antimatter, and is ejected at a speed very close to the speed of light, reaching the theoretical upper limit of specific impulse. The greatest advantage of photon rockets is that the ejection speed of the propellant equals the speed of light, allowing the mass ratio in the rocket equation to be kept extremely small. In the E16 civilization sphere, it is mainly adopted as a propulsion system for probes and small spacecraft, equipped with a miniature version of an antimatter engine as its power source. The thrust of a photon rocket is proportional to the consumption of antimatter, and obtaining high thrust requires a large amount of antimatter, limiting its application to large vessels."},{id:"tech-dark-matter-detector",name:"ダークマター検出器",nameEn:"Dark Matter Detector",category:"技術",subCategory:"技術・概念",description:"宇宙の全質量エネルギーの約27パーセントを占める未発見の物質であるダークマター（WIMPやアクシオンなど）を直接検出するための超高感度センサーシステムである。ダークマター検出器は地下深部に設置された大量の液体キセノンや結晶タングステンを検出媒体とし、ダークマター粒子が原子核と弾性散乱した際に生じる微小な反跳エネルギーを超伝導センサーで検出する。E16文明圏では超伝導量子干渉素子（SQUID）と量子ドットセンサーを組み合わせた次世代のダークマター検出器が稼働しており、WIMPやアクシオンの質量範囲を網羅的に探索している。ダークマターの性質の解明は素粒子物理学の標準模型の拡張に直結し、宇宙の暗黒エネルギーとダークマターの関係の理解にも不可欠である。グランベルの最先端研究施設では多体相互作用を利用した革新的な検出手法の開発が進められている。",descriptionEn:"An ultra-high sensitivity sensor system for directly detecting dark matter (such as WIMPs or axions), which accounts for about 27% of the total mass-energy of the universe. Dark matter detectors use large amounts of liquid xenon or crystalline tungsten buried deep underground as detection media, and detect the tiny recoil energy generated when dark matter particles elastically scatter with atomic nuclei using superconducting sensors. In the E16 civilization sphere, next-generation dark matter detectors combining superconducting quantum interference devices (SQUIDs) and quantum dot sensors are operational, comprehensively exploring the mass ranges of WIMPs and axions. Elucidating the nature of dark matter is directly linked to the extension of the standard model of particle physics and is essential for understanding the relationship between dark energy and dark matter in the universe. At the Granbel's cutting-edge research facility, the development of innovative detection methods utilizing many-body interactions is being advanced."},{id:"tech-plasma-wakefield",name:"プラズマウェイクフィールド加速器",nameEn:"Plasma Wakefield Accelerator",category:"技術",subCategory:"技術・概念",description:"高エネルギーレーザーパルスまたは電子ビームをプラズマ中に照射し、プラズマ波（ウェイクフィールド）の電界を利用して荷電粒子を加速する次世代の粒子加速器技術である。プラズマウェイクフィールドの加速電界は従来の rf空洞加速器の1000倍以上に達し、全長数キロメートルの従来型加速器と同等のエネルギーを数メートルの長さで実現できる。E16文明圏ではこの技術を応用した卓上規模の高エネルギー粒子加速器が実用化されており、反物質の生成や超重元素の合成、医療用の高エネルギー粒子線治療などに利用されている。プラズマウェイクフィールド加速器のビーム品質（エミッタンスとエネルギー分散）の向上が技術的な課題であり、超伝導磁石を用いたビームフォーカシングと多段階の加速構造によって高品質ビームの生成が実現されている。",descriptionEn:"A next-generation particle accelerator technology that irradiates high-energy laser pulses or electron beams into plasma, using the electric field of plasma waves (wakefields) to accelerate charged particles. The accelerating electric field of plasma wakefields reaches more than 1000 times that of conventional rf cavity accelerators, achieving equivalent energy to conventional accelerators several kilometers long in just a few meters. In the E16 civilization sphere, desktop-scale high-energy particle accelerators using this technology have been commercialized and are used for antimatter generation, synthesis of superheavy elements, and high-energy particle beam therapy for medical purposes. Improving the beam quality (emittance and energy spread) of plasma wakefield accelerators is a technical challenge, and the generation of high-quality beams is achieved through beam focusing using superconducting magnets and multi-stage acceleration structures."},{id:"コーポラトクラシー",name:"コーポラトクラシー",nameEn:"Corporatocracy",category:"用語",subCategory:"歴史・時代",description:"E16連星系の歴史的統治体制で、国家そのものが企業として機能する政治形態。東暦初期の入植期からパクス・ロンバルディカ期（E205〜E278）にかけて最盛期を迎え、20万以上のコーポラトクラシーがGigapolis全域で競合した。各コーポラトクラシーは独自の軍備・法体系・市民管理を持ち、経済力こそが唯一の権力基盤だった。コーポラタムパブリカ（株式会社共和国）はその頂点に立つコーポラトクラシー連合体で、14兆ドルのGDPを誇り、コーポラトクラシー体制の最も成功した例として歴史に残る。E150年のエル・フォルハウスによるマーストリヒト革命で体制が揺らぎ始め、ZAMLTの台頭（E301年）によりコーポラトクラシー間の覇権争いは5超巨大企業への集約によって終焉を迎えた。しかしZAMLT崩壊後も、A-Registryの階級制度やnトークン経済という遺産はE16文明圏に深く根を下ろし、現在のUECOや銀河系コンソーシアムの枠組みにも影響を与え続けている。コーポラトクラシー時代の競争原理は、現在もグランベルの経済覇争やクレセント地方の勢力ゲームの基層構造として息づいている。\nこのコーポラトクラシーの根底には、国家＝株式会社(D3)の思想的地層が横たわっている。20万の企業国家が競合したこの構造は、民主主義の失敗を前提に国家をCEOが経営する株式会社とするD3の思想の直接的実践であった。nトークン経済は「株主価値」の変奏として機能し、市民は消費者兼投資家としての役割に還元された。",descriptionEn:"A historical governance system in the E16 star system where the state itself functions as a corporation. It reached its peak during the early settlement period from the beginning of the Eastern calendar to the Pax Lombardica period (E205-E278), with over 200,000 corporatocracies competing across Gigapolis. Each corporatocracy had its own military, legal system, and citizen management, with economic power being the sole basis of authority. The Corporatum Publica (Corporate Republic) was the alliance of corporatocracies at the top, boasting a GDP of 14 trillion dollars and remaining in history as the most successful example of the corporatocracy system. The system began to waver with the Maastricht Revolution led by El Forthaus in E150, and the struggle for dominance among corporatocracies ended with the concentration into five mega-corporations following the rise of ZAMLT in E301. However, even after the collapse of ZAMLT, the legacy of the A-Registry's class system and the n-token economy have taken deep root in the E16 civilization, continuing to influence the frameworks of the current UECO and the Galactic Consortium. The competitive principles of the corporatocracy era still survive as the underlying structure of economic hegemony in Granbel and the power games in the Crescent region.\nAt the core of this corporatocracy lies the ideological stratum of the state = corporation (D3). This structure, where 200,000 corporate states competed, was the direct implementation of the D3 ideology, which presupposed the failure of democracy and treated the state as a corporation managed by a CEO. The n-token economy functioned as a variation of 'shareholder value,' reducing citizens to the role of consumers and investors."},{id:"クロニクル・ネーム",name:"クロニクル・ネーム",nameEn:"Chronicle Name",category:"用語",subCategory:"技術・概念",description:"AURALISに伝わる重要な文化的伝統で、初代メンバーの「名」を後継者が世代を超えて継承する制度である。初代Kate Claudiaの「Kate」、初代Lily Steinerの「Lillie Ardent」などの「名」は、単なる呼称ではなく、その名が持つ芸術的・精神的な本質を体現する者にのみ受け継がれる。継承の基準は厳格で、元の名の持ち主と同等の特性、才能、精神を持つと認められた者のみが新しい「名の継承者」となる。この制度はAURALISの「光と音を永遠にする」という理念を具現化するものであり、個人の死によって芸術的遺産が途絶えることを防ぐ文化装置として機能している。名の継承者は元の人物とは別個の存在であるが、AURALISのコミュニティ内では精神的な連続性が重視される。第一世代から第二世代への移行期においてもこの制度は維持され、AURALISのアイデンティティの継続性を支える重要な役割を果たしている。nトークン経済において「名の継承者」は文化的価値の指標として高く評価される。",descriptionEn:"An important cultural tradition passed down in AURALIS, a system where the 'name' of the founding member is inherited by successors across generations. The 'names' of the first members, such as 'Kate' from the first Kate Claudia and 'Lillie Ardent' from the first Lily Steiner, are not merely titles but are inherited only by those who embody the artistic and spiritual essence of that name. The criteria for inheritance are strict, and only those recognized to possess equivalent characteristics, talents, and spirit to the original name-bearer can become the new 'name inheritor.' This system embodies AURALIS's philosophy of 'making light and sound eternal,' functioning as a cultural device to prevent artistic heritage from being cut off by individual death. The name inheritor is a separate individual from the original person, but spiritual continuity is emphasized within the AURALIS community. This system has been maintained even during the transition from the first to the second generation, playing an important role in supporting the continuity of AURALIS's identity. In the n-token economy, 'name inheritors' are highly valued as indicators of cultural worth."},{id:"スティル・アレーナ",name:"スティル・アレーナ",nameEn:"Steel Arena",category:"用語",subCategory:"技術・概念",description:"ネオンコロシアムで行われる戦士決定の儀式で、クレセント大地方における伝統的な武力選抜制度である。ネオンコロシアムはクレセント地方の中心都市に設置された巨大な闘技場で、次元極地平技術を応用した安全装置により、実戦級の戦闘ながら参加者の命を守る仕組みが組み込まれている。スティル・アレーナでは、各国家や組織が代表する戦士たちが独自の戦闘スタイルと技術を披露し、その結果によって軍事的階位や外交的な発言力が決定される。ボグダス・ジャベリンのテクロサス系譜の戦士たちはスティル・アレーナの常連であり、その圧倒的な実力で他国の参加者を圧倒してきた。スティル・アレーナは単なる武力競技ではなく、クレセント地方の国際秩序を維持するための象徴的な儀式として機能し、UECOの監視下で定期的に開催されている。V7とトリニティ・アライアンスの対立が深まる中、スティル・アレーナは両陣営の緊張を緩和する場としての役割も担っている。スティル・アレーナの勝者には特別なnトークン報酬とA-Registry上の名誉階位が与えられる。",descriptionEn:"A warrior determination ceremony held in the Neon Colosseum, a traditional military selection system in the Crescent region. The Neon Colosseum is a huge arena located in the central cities of the Crescent region, incorporating safety devices using dimensional horizon technology that protect participants' lives while allowing combat at an actual combat level. In the Still Arena, warriors representing various nations and organizations showcase their unique combat styles and techniques, and their results determine military rank and diplomatic influence. The warriors of the Bogdas Javelin's Techlosus lineage are regulars in the Still Arena, overwhelming participants from other countries with their overwhelming strength. The Still Arena is not merely a martial arts competition but functions as a symbolic ceremony to maintain the international order of the Crescent region, regularly held under the supervision of UECO. As the conflict between V7 and the Trinity Alliance deepens, the Still Arena also serves as a venue to ease tensions between the two factions. Winners of the Still Arena receive special n-token rewards and honorary ranks on the A-Registry."},{id:"アビサル・ドレイン",name:"アビサル・ドレイン",nameEn:"Abyssal Drain",category:"用語",subCategory:"その他",description:"クレセント地方に埋蔵される貴重な石油資源であり、シンフォニー・オブ・スターズ西大陸のエネルギー安全保障の要。高純度の原油が採掘され、精製後は航空燃料や次元エンジンの補助動力源として利用される。その戦略的価値から各地の軍閥や企業の争奪対象となり、アイリスがクレセントで実行した襲撃作戦はこの資源を巡る大規模な紛争の一端をなす。採掘施設は度重なる戦火で破壊と再建を繰り返してきた。",descriptionEn:"Valuable petroleum resources buried in the Crescent region, essential for the energy security of the Symphony of Stars Western Continent. High-purity crude oil is extracted and, after refining, used as aviation fuel or an auxiliary power source for dimensional engines. Due to its strategic value, it has become a target of contention for various warlords and corporations, and the raid operation executed by Iris in the Crescent is part of a large-scale conflict over this resource. Mining facilities have been repeatedly destroyed and rebuilt through continuous warfare."},{id:"フェルミ音楽",name:"フェルミ音楽",nameEn:"Fermi Music",category:"用語",subCategory:"技術・概念",description:"セリア黄金期（E335〜E370年）に最盛期を迎えた独自の音楽体系。次元極地平の共振現象を音響に応用し、通常の周波数帯を超えた音波を生成することで聴覚だけでなく感情に直接働きかける革新的な音楽を創造した。AURALISの創作理念の源流となり、のちにAURALIS Collectiveが確立する総合芸術運動の基礎を形成した。Poitiersに研究機関と芸術院が集積し、現在でもフェルミ音楽の復興祭が定期的に開催されている。",descriptionEn:"A unique musical system that reached its peak during the Celian Golden Age (E335-E370). It applied the resonance phenomenon of the dimensional horizon to sound, creating innovative music that directly affects not only hearing but also emotions by generating sound waves beyond normal frequency bands. It became the source of AURALIS's creative philosophy and formed the basis for the comprehensive art movement later established by the AURALIS Collective. Research institutions and art academies accumulated in Poitiers, and today, the Fermi Music Revival Festival is still held regularly."},{id:"サイケデリック・コスモロジー",name:"サイケデリック・コスモロジー",nameEn:"Psychedelic Cosmology",category:"用語",subCategory:"技術・概念",description:"テミルタロンが提唱した独自の宇宙論的哲学体系。次元極地平を単なる物理現象ではなく、宇宙の意識的構造の顕現として解釈し、物質世界と精神世界の境界を溶解する宇宙観を構築した。このコスモロジーはテクノ宗教運動の思想的基盤となり、次元階梯パンディクトの構想の原型を提供した。サイケデリックな体験を通じた高次元認識の開拓を重視し、技術啓蒙時代の合理主義に対する重要な対抗思想として機能した。現在でもテンプル・オブ・ホライゾンの教学における根本教義となっている。",descriptionEn:"A unique cosmological philosophical system proposed by Temirlaton. It interprets the dimensional horizon not merely as a physical phenomenon but as the manifestation of the conscious structure of the universe, constructing a worldview that dissolves the boundary between the material and spiritual worlds. This cosmology became the ideological foundation of the techno-religious movement and provided the prototype for the concept of the dimensional ladder pandict. It emphasized the exploration of higher-dimensional consciousness through psychedelic experiences and functioned as an important counter-ideology against the rationalism of the technological enlightenment era. It remains a fundamental doctrine in the teachings of the Temple of Horizon today."},{id:"シギル・アフェクト",name:"シギル・アフェクト",nameEn:"Sigil Affect",category:"用語",subCategory:"技術・概念",description:"ヴェルリット一族（魔女）が代々使用する特殊な印であり、その詳細は多くの謎に包まれている。印を施すことで空間の歪みやエネルギーの流れを操作する効果があるとされ、ヴェルリット一族の戦闘術や呪術の中核技術となっている。シギル・アフェクトを使用した攻撃は通常の物理的防御を容易に貫通し、対象の生体エネルギーに直接干渉する特性を持つ。アイリスがクレセントでヴェルリット一族と交戦した際、この印の技術の脅威を身をもって経験した。印の起源や仕組みについては学術的な解明が進んでいない。",descriptionEn:"A special mark used by the Verlit family (witches) for generations, whose details are shrouded in many mysteries. It is said that applying this mark has the effect of manipulating spatial distortions and energy flows, and it has become the core technology of the Verlit family's combat and sorcery techniques. Attacks using Sigil Effect can easily pierce normal physical defenses and have the characteristic of directly interfering with the target's bio-energy. When Iris engaged in combat with the Verlit family using Crescent, she personally experienced the threat of this mark's technology. The origin and mechanism of the mark have not been academically elucidated."},{id:"ジーン・カタログ",name:"ジーン・カタログ",nameEn:"Gene Catalogue",category:"用語",subCategory:"組織・制度",description:"Eros-7の男性指令省が運用する男性の遺伝情報管理システム。Eros-7の女性主導社会において、男性の社会参加と繁殖を統制する目的で作られた。登録された男性の遺伝情報に基づいて適格性判定と労働配分が行われる仕組みで、多くの男性がこの制度に不満を抱いていた。E525年のマトリカル・リフォーム運動で男女平等化が強く要求され、現在では制度の透明性と公平性の改善が進んでいる。この制度をめぐる論争はEros-7のジェンダー問題を象徴する議論となっている。",descriptionEn:"A genetic information management system for men operated by the male command authority of Eros-7. Created in the female-dominated society of Eros-7 to control male social participation and reproduction. The system determines eligibility and allocates labor based on the genetic information of registered men, and many men were dissatisfied with this system. In the Matric Reform Movement of E525, strong demands were made for gender equality, and now improvements to the system's transparency and fairness are being made. The controversy surrounding this system has become a symbolic discussion of gender issues on Eros-7."},{id:"ヘゲモニー・パラドックス（概要）",name:"ヘゲモニー・パラドックス",nameEn:"Hegemony Paradox",category:"用語",subCategory:"用語",description:"新興大国が台頭する際、現存大国との間に構造的な対立が生じ、戦争が不可避的に勃発するという国際政治理論。古代ギリシャの歴史家トゥキディデスがペロポネソス戦争の分析で提唱した概念を宇宙規模に適用したもの。銀河系コンソーシアムはこの罠の回避を最重要政策目標として掲げ、特にグランベル（経済1位）とティエリア（軍事3位）の関係に危険性を指摘している。かつてのアポロンとSelinopolisの関係も同様の構造だったと分析され、その教訓が現在の外交政策に反映されている。詳細は「ヘゲモニー・パラドックス」（宇宙文明圏）を参照。",descriptionEn:"A theory of international politics that when emerging great powers rise, structural conflicts arise with existing great powers, making war inevitable. It is an application of the concept proposed by the ancient Greek historian Thucydides in his analysis of the Peloponnesian War to a cosmic scale. The Galactic Consortium lists avoiding this trap as its most important policy goal, and has pointed out dangers in the relationship between Granbel (economic rank 1) and Tierra (military rank 3). The relationship between Apollo and Selinopolis in the past is analyzed to have had a similar structure, and the lessons from that are reflected in current foreign policy. For details, refer to 'Hegemony Paradox' (Cosmic Civilization Sphere)."},{id:"フェンドラ人",name:"フェンドラ人",nameEn:"Fendra",category:"用語",subCategory:"民族集団",description:"技術革新と工業発展を第一の価値観とする北欧系の移民集団であり、シンフォニー・オブ・スターズに到来した三大移民集団の一つ。寒冷な惑星環境への適応の過程で高度なエンジニアリング技術を発展させ、冶金学や機械工学の分野で際立った貢献を果たした。Gigapolisの化学工業都市Chemはフェンドラ人の技術を基盤に発展した。合理的な思考と効率性を重んじる文化を持ち、技術啓蒙時代の主要な推進勢力の一つとして西大陸の近代化に大きく寄与した。",descriptionEn:"A Nordic immigrant group that values technological innovation and industrial development as its primary values, and one of the three major immigrant groups that arrived in the Symphony of Stars. In the process of adapting to the harsh planetary environment, they developed advanced engineering technology and made outstanding contributions in the fields of metallurgy and mechanical engineering. The chemical industrial city Chem of Gigapolis developed based on the technology of the Fendran people. They have a culture that values rational thinking and efficiency, and as one of the main driving forces of the Technological Enlightenment era, they greatly contributed to the modernization of the Western Continent."},{id:"アーキアン",name:"アーキアン",nameEn:"Archian",category:"用語",subCategory:"民族集団",description:"過酷な惑星環境への適応能力に優れたアジア系の移民集団であり、三大移民集団の一つ。生物学的な環境適応技術と持続可能な農業システムを開発し、当初は不毛とされた地域の開拓に成功した。特に水資源管理と土壌改良技術において卓越した成果を挙げ、シンフォニー・オブ・スターズの食料安全保障の基盤を築いた。文化面では祖先崇拝と自然との調和を重んじる哲学があり、テクノ宗教運動とも共鳴する思想を持つ。西大陸の人口の主要な構成要素の一つである。",descriptionEn:"An Asian immigrant group with excellent adaptation capabilities to harsh planetary environments, and one of the three major immigrant groups. They developed biological environmental adaptation technologies and sustainable agricultural systems, successfully pioneering areas that were initially considered barren. They achieved outstanding results in water resource management and soil improvement technologies, establishing the foundation for food security in the Symphony of Stars. Culturally, they value ancestor worship and harmony with nature, and have ideas that resonate with the techno-religious movement. They are one of the main components of the Western Continent's population."},{id:"ポロンポロ",name:"ポロンポロ",nameEn:"Polonpolo",category:"用語",subCategory:"民族集団",description:"母星の文化遺産と伝統の保存を最優先課題とするオセアニア系の移民集団であり、三大移民集団の一つ。移住に際して膨大な文化資料と言語データを持ち込み、独自の教育システムを通じて次世代への継承に努めた。他の移民集団が技術的適応を追求する中、ポロンポロは精神的・文化的アイデンティティの維持に注力し、音楽、舞踊、口承文芸の分野で豊かな遺産を残している。テクノ文化ルネサンス期には、伝統芸術と次元技術の融合という新たな文化表現を開拓した。",descriptionEn:"An Oceanian immigrant group that prioritizes the preservation of their home planet's cultural heritage and traditions, and one of the three major immigrant groups. Upon migration, they brought vast cultural materials and linguistic data, and through their unique education system, they endeavored to pass them on to the next generation. While other immigrant groups pursued technological adaptation, Polonpolo focused on maintaining spiritual and cultural identity, leaving a rich legacy in the fields of music, dance, and oral literature. During the Techno-Cultural Renaissance period, they pioneered new forms of cultural expression that fused traditional arts with dimensional technology."},{id:"Iris_Worlds",name:"アイリス・ワールズ",nameEn:"Iris Worlds",category:"用語",subCategory:"用語",description:"アイリス物語の公式ウェブサイトであり、ストーリーの全編と関連資料が公開されている。URLはhttps://irisworlds.netlify.app/story。E16系の世界観、登場人物、歴史年表、技術体系などに関する包括的な情報が掲載され、新規読者と既存ファンの両方に向けた情報ハブとして機能している。サイトは随時更新されており、最新のストーリー展開や設定の追加情報が反映されている。",descriptionEn:"The official website of the Iris Story, where the entire story and related materials are published. The URL is https://irisworlds.netlify.app/story. It contains comprehensive information about the E16 worldview, characters, historical timeline, technological systems, etc., serving as an information hub for both new readers and existing fans. The site is regularly updated to reflect the latest story developments and additional information."},{id:"グランベル",name:"グランベル",nameEn:"Granbell",category:"用語",subCategory:"宇宙文明",description:"宇宙ランキング第1位の経済大国。GDP150兆ドルで宇宙全体の約25%を占める。首都はオルダシティ。アポロン・Dominion大戦を傍観し、戦後混乱期に一気に浮上。マルチバース開拓と次元間技術で他文明を圧倒。ティエリアとはヘゲモニー・パラドックスの危険性が指摘される一方、エレシオンとは技術分野で連携。現大統領アルゼン・カーリーンは第一回宇宙連合会合を主催した。初代リーダーはマスター・クインシアスであり、セリア時代を高く評価し後継的な文明として位置づけた。歴代指導者はセリアの遺産を継承する理念を維持し、グランベルの経済的繁栄の精神的基盤を形成してきた。",descriptionEn:"The number one economic power in the cosmic rankings, accounting for approximately 25% of the entire universe's GDP with 150 trillion dollars. The capital is Alda City. It rose to prominence by observing the Apollo-Dominion War and capitalizing on the post-war chaos period. It overwhelms other civilizations through multiverse exploration and interdimensional technology. While the danger of the Hegemony Paradox with Tiera is pointed out, it cooperates with Elesion in technological fields. Current President Arzen Carline hosted the first United Cosmic Assembly. The first leader was Master Quincius, who highly valued the Celia era and positioned it as a successor civilization. Successive leaders have maintained the philosophy of inheriting Celia's legacy, forming the spiritual foundation of Granbel's economic prosperity.",era:"現在",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/eduuni.txt",label:"eduuni.txt"}],leaders:[{id:"アルゼン・カーリーン",name:"アルゼン・カーリーン",nameEn:"Alzen Carine",role:"グランベル大統領",era:"現在"},{id:"マスター・クインシアス",name:"マスター・クインシアス",nameEn:"Master Quinsias",role:"グランベル初期リーダー",era:"歴史上"}]},{id:"ティエリア",name:"ティエリア",nameEn:"Tyeria",category:"用語",subCategory:"宇宙文明",description:"宇宙ランキング第3位。軍事技術において宇宙最高峰。圧倒的な艦隊と卓越した戦術力で知られ、宇宙規模の防衛ネットワークを構築。総帥グレイモンド・ハウザーが「軍事力なくして平和は守れない」と主張。近年は軍事技術の輸出を経済基盤として活用。グランベルとの間にヘゲモニー・パラドックスの危険性が指摘されている。歴代総帥の系譜は軍事技術の蓄積とともに受け継がれ、グレイモンド・ハウザーは現実主義的路線を確立した。グランベルとの対話も継続し、ヘゲモニー・パラドックス回避に向けた外交努力を行っている。",descriptionEn:"Ranked third in the cosmic rankings. Possesses the pinnacle of military technology in the universe. Known for its overwhelming fleet and superior tactical capabilities, it has built a cosmic-scale defense network. Supreme Commander Graymond Houser advocates that 'peace cannot be protected without military power.' In recent years, it has utilized military technology exports as an economic base. The danger of the Hegemony Paradox with Granbel has been pointed out. The lineage of supreme commanders has been passed down along with the accumulation of military technology, and Graymond Houser established a realistic policy. It continues dialogue with Granbel and engages in diplomatic efforts to avoid the Hegemony Paradox.",era:"現在",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/eduuni.txt",label:"eduuni.txt"}],leaders:[{id:"グレイモンド・ハウザー",name:"グレイモンド・ハウザー",nameEn:"Greymond Hauser",role:"ティエリア総帥",era:"現在"}]},{id:"エレシオン",name:"エレシオン",nameEn:"Elyseon",category:"用語",subCategory:"宇宙文明",description:"宇宙ランキング第2位。医療技術と環境再生技術で宇宙をリード。女王リアナ・ソリスの下、平和主義・技術共有推進の外交姿勢で幅広い支持を得る。「生命の維持と再生」を文明の根幹に置き、支配や経済的優位性ではなく技術援助を通じて影響力を行使。第一回宇宙連合会合でティエリアの軍拡に反対した。歴代女王は「生命の維持と再生」を文明の根幹とし、平和主義外交を貫く伝統を受け継ぎ、技術共有推進の伝統は他文明圏からの広範な支持を集めている。",descriptionEn:"Ranked second in the cosmic rankings. Leads the universe in medical technology and environmental regeneration technology. Under Queen Riana Solis, it has gained broad support with a diplomatic stance promoting pacifism and technology sharing. It places 'the preservation and regeneration of life' at the core of its civilization and exercises influence through technical assistance rather than domination or economic superiority. It opposed Tiera's military expansion at the first United Cosmic Assembly. Successive queens have inherited the tradition of placing 'the preservation and regeneration of life' at the core of their civilization and adhering to pacifist diplomacy, and the tradition of promoting technology sharing has garnered broad support from other civilizations.",era:"現在",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/eduuni.txt",label:"eduuni.txt"}],leaders:[{id:"女王リアナ・ソリス",name:"女王リアナ・ソリス",nameEn:"Queen Liana Solis",role:"エレシオン女王",era:"現在"}]},{id:"ファルージャ",name:"ファルージャ",nameEn:"Fallujah",category:"用語",subCategory:"宇宙文明",description:"宇宙ランキング第4位。経済力では上位勢力に劣るが、文化的影響力と外交力で他の追随を許さない。宇宙中の文明間交流を主導し、対立する勢力間の調停役として機能。評議会代表マドリス・カーネルが「文化の力が宇宙全体を結びつける鍵になる」と主張。歴代代表は文化的外交を重んじ、対立勢力間の調停役として機能してきた。エレシオンの女王リアナ・ソリスとは平和・技術共有の理念で連携し、宇宙外交の穏健派を形成している。",descriptionEn:"Ranked fourth in the cosmic rankings. While inferior to top powers in economic strength, its cultural influence and diplomatic power are unmatched. It leads inter-civilizational exchanges throughout the universe and functions as a mediator between opposing forces. Council Representative Madris Carnel asserts that 'the power of culture is the key that binds the entire universe together.' Successive representatives have valued cultural diplomacy and have functioned as mediators between opposing forces. It cooperates with Elesion's Queen Riana Solis in the理念 of peace and technology sharing, forming the moderate faction in cosmic diplomacy.",era:"現在",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/eduuni.txt",label:"eduuni.txt"}],leaders:[{id:"マドリス・カーネル",name:"マドリス・カーネル",nameEn:"Madrisernel",role:"ファルージャ評議会代表",era:"現在"}]},{id:"ディオクレニス",name:"ディオクレニス",nameEn:"Dioclenis",category:"用語",subCategory:"宇宙文明",description:"宇宙ランキング第5位。宇宙探査と科学技術研究の最前線。未知の次元や新しい惑星系の開拓を続け、研究成果は他勢力の重要インフラ。科学宰相ネイサン・コリンドがヘゲモニー・パラドックスを科学的に指摘し、対立のエネルギーを共同宇宙探査へ転換する提案を行った。歴代宰相は宇宙探査を国家の使命とし、ヘゲモニー・パラドックス回避のため対立のエネルギーを共同宇宙探査へ転換する提案を継続的に実施している。",descriptionEn:"Ranked fifth in the cosmic rankings. At the forefront of cosmic exploration and scientific technology research. It continues to explore unknown dimensions and new planetary systems, with its research results serving as important infrastructure for other powers. Science Minister Nathan Corind scientifically pointed out the Hegemony Paradox and proposed converting the energy of conflict into joint cosmic exploration. Successive ministers have considered cosmic exploration as the nation's mission and have continuously proposed converting the energy of conflict into joint cosmic exploration to avoid the Hegemony Paradox.",era:"現在",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/eduuni.txt",label:"eduuni.txt"}],leaders:[{id:"ネイサン・コリンド",name:"ネイサン・コリンド",nameEn:"Nathan Corlind",role:"ディオクレニス科学宰相",era:"現在"}]},{id:"アポロン文明圏",name:"アポロン文明圏",nameEn:"Apollon",category:"用語",subCategory:"歴史",description:"かつて宇宙に名を馳せた巨大文明圏。最盛期GDP125兆ドル。中核惑星アポロン・セントラリスを拠点に、強力な軍事組織「アポロンの騎士団」を擁した。リーダー・ロナン・アーサがセリアに同盟を提案したが拒絶され全面戦争に発展。ヴェノム艦隊に敗れロナンは戦死。大戦後GDP32兆ドルに激減し現在は主要勢力から脱落。",descriptionEn:"A great civilization that once flourished in space. Its GDP reached 125 trillion dollars at its peak. Based on the core planet Apollo Centralis, it possessed a powerful military organization called the Knights of Apollo. Leader Ronan Arsa proposed an alliance to Seria, but was rejected, leading to all-out war. Defeated by the Venom fleet, Ronan was killed in battle. After the great war, the GDP plummeted to 32 trillion dollars, and it has since fallen from being a major power.",era:"歴史上",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/eduuni.txt",label:"eduuni.txt"}],leaders:[{id:"ロナン・アーサ",name:"ロナン・アーサ",nameEn:"Ronan Arthur",role:"アポロン文明圏リーダー",era:"大戦期"}]},{id:"Selinopolis",name:"Selinopolis（ドミニオン）",nameEn:"Selinopolis / Dominion",category:"用語",subCategory:"歴史",description:"セリア・ドミニクスがGigapolisを掌握後に改名した都市国家。GDP25兆ドルに急成長。次元エネルギー技術の商業化と女性主導社会を確立。超巨大企業Phovosを設立。エヴァトロンと同盟してアポロンと大戦し勝利したがGDPは23兆ドルに激減。戦後エヴァトロンに吸収されセリアは追放。その遺産は現在のE16系に大きな影響を与えている。",descriptionEn:"The city-state that Seria Dominikus renamed after taking control of Gigapolis. It grew rapidly to a GDP of 25 trillion dollars. Commercialized dimensional energy technology and established a female-led society. Founded the mega-corporation Phovos. Allied with Evatron and won the great war against Apollo, but the GDP plummeted to 23 trillion dollars. After the war, it was absorbed by Evatron and Seria was exiled. Its legacy has had a significant impact on the current E16 system.",era:"歴史上",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/eduuni.txt",label:"eduuni.txt"}],leaders:[{id:"セリア・ドミニクス",name:"セリア・ドミニクス",nameEn:"Celia Dminix",role:"Selinopolis/Dominion統治者",era:"E335〜E370"}]},{id:"宇宙連合会合",name:"宇宙連合会合",nameEn:"Universal Federation Summit",category:"用語",subCategory:"歴史",description:"グランベルの首都オルダシティで開催された第一回宇宙連合会合。アルゼン・カーリーン（共存繁栄）、グレイモンド・ハウザー（軍事力の必要性）、リアナ・ソリス（平和・技術共有）、マドリス・カーネル（文化の力）、ネイサン・コリンド（ヘゲモニー・パラドックス回避・共同探査）が演説。宇宙秩序の構築に向けた対話が始まった。",descriptionEn:"The first United Nations of Space meeting, held in the capital of Granbel, Oldacity. Speakers included Arsen Karin (coexistence and prosperity), Graymond Hauser (necessity of military power), Liana Solis (peace and technology sharing), Madris Karnel (power of culture), and Nathan Corind (avoiding the hegemony paradox and joint exploration). Dialogue began to build a cosmic order.",era:"現在（E528〜）",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/eduuni.txt",label:"eduuni.txt"}]},{id:"アポロン・Dominion大戦",name:"アポロン・Dominion大戦",nameEn:"Apollon Dominion War",category:"用語",subCategory:"戦争・歴史事件",description:"アポロン文明圏とDominion（セリア率いるSelinopolis）の全面戦争。E370年に宣戦布告。E375年にアポロンがケンタウロスレーザー発射、E378年にセリアがG4ファントムパルスで応戦。E385年にセリアのヴェノム艦隊がアポロン・セントラリスを攻略・爆砕し戦争終結。両文明とも壊滅的損害を受け、宇宙秩序は大きく変容した。なおE400年のエヴァトロンによるGigapolis占領は戦争終結とは別事象である。",descriptionEn:"The all-out war between the Apollo civilization and Dominion (led by Seria of Selinopolis). War was declared in E370. In E375, Apollo fired the Centaurus Laser, and in E378, Seria responded with the G4 Phantom Pulse. In E385, Seria's Venom fleet captured and shattered Apollo Centralis, ending the war. Both civilizations suffered devastating losses, and the cosmic order was greatly transformed. Note that the occupation of Gigapolis by Evatron in E400 is a separate event from the end of the war.",era:"E370〜E385",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/eduuni.txt",label:"eduuni.txt"}]},{id:"オルダシティ",name:"オルダシティ",nameEn:"Olda City",category:"用語",subCategory:"地理",description:"グランベルの首都。次元間通信技術の発祥地、量子経済の中心地。宇宙で最も発展した都市。オルダ・プライムホールは次元の歪みを利用して設計され数万人収容可能。第一回宇宙連合会合開催地。",descriptionEn:"The capital of Granbel. The birthplace of interdimensional communication technology and the center of the quantum economy. The most developed city in the universe. The Olda Prime Hall was designed using dimensional distortions and can accommodate tens of thousands of people. Venue for the first United Nations of Space meeting.",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/eduuni.txt",label:"eduuni.txt"}]},{id:"アポロン・セントラリス",name:"アポロン・セントラリス",nameEn:"Apollon Centralis",category:"用語",subCategory:"地理",description:"アポロン文明圏の中核惑星。全軍事力はここから動員された。アポロン・Dominion大戦の最終局面でセリアのヴェノム艦隊に攻略・爆砕され、アポロン文明圏壊滅の象徴となった。",descriptionEn:"The core planet of the Apollo civilization. All military forces were mobilized from here. In the final phase of the Apollo-Dominion war, it was captured and shattered by Seria's Venom fleet, becoming a symbol of the destruction of the Apollo civilization.",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/eduuni.txt",label:"eduuni.txt"}]},{id:"ヘゲモニー・パラドックス",name:"ヘゲモニー・パラドックス",nameEn:"Hegemony Paradox",category:"用語",subCategory:"宇宙文明圏",description:"新興大国と現存大国の間に不可避的に対立が生じる国際関係理論。ディオクレニスのネイサンが提起し、グランベル（経済1位）とティエリア（軍事3位）の関係にこの罠の危険性を指摘。かつてのアポロン・Dominion関係も同様の構造だった。",descriptionEn:"An international relations theory that inevitably creates conflict between emerging and existing great powers. Proposed by Diocles' Nathan, who pointed out the danger of this trap in the relationship between Granbel (economic rank 1) and Tierra (military rank 3). The former Apollo-Dominion relationship had a similar structure.",sourceLinks:[{url:"https://raw.githubusercontent.com/gentaron/edutext/main/eduuni.txt",label:"eduuni.txt"}]},{id:"EVILS",name:"イビルス",nameEn:"EVILS",category:"用語",subCategory:"技術・概念",description:"次元間に存在する超越的生命体群の総称。正式名称は不明であり、「EVILS」はE16文明圏が便宜上付けた呼称である。高次元領域に起源を持ち、物理法則を超越した能力を持つ。リーダーはオメガ＝ユリシス。一部のEVILSはディストーター（Dystroyer）と呼ばれる破壊的な個体であり、物理空間に顕現すると周囲の次元構造を崩壊させる危険性を持つ。ZAMLTの5企業のリーダーたちは虚無の塔（Tower of the Void）でオメガ＝ユリシスと秘密会合を持ち、次元安定化を条件に一定の取引を行ったとされるが、この協力関係は最終的に破綻した。EVILSの存在は次元極地平技術のリスクを象徴するものであり、次元境界へのアクセスがもたらす予期せぬ脅威としてE16文明圏の安全保障上の最大の懸念事項の一つとなっている。E340年のスライム・ウーマン顕現もEVILSの次元的活動との関連が疑われている。",descriptionEn:"A collective term for transcendent life forms existing between dimensions. The official name is unknown, and 'EVILS' is a term given by the E16 civilization for convenience. Originating from higher-dimensional realms, they possess abilities that transcend physical laws. Their leader is Omega=Ulysses. Some EVILS are called Distorters (Dystroyers), destructive entities that pose a danger of collapsing the dimensional structure of their surroundings when they manifest in physical space. It is said that the leaders of ZAMLT's five companies held a secret meeting with Omega=Ulysses at the Tower of the Void and made a certain deal on the condition of dimensional stabilization, but this cooperative relationship eventually broke down. The existence of EVILS symbolizes the risks of dimensional horizon technology and has become one of the biggest security concerns for the E16 civilization as an unexpected threat brought by access to dimensional boundaries. The manifestation of the Slime Woman in E340 is also suspected to be related to the dimensional activities of EVILS.",leaders:[{id:"オメガ＝ユリシア",name:"オメガ＝ユリシア",nameEn:"Omega=Ulysses",role:"EVILSリーダー",era:"E318年頃"}]},{id:"term-東暦紀年法",name:"東暦紀年法",nameEn:"Eastern Calendar System",category:"用語",subCategory:"社会制度",description:"E1＝AD3501を元年とするE16文明圏の標準暦法。地球からM104銀河への最初の入植船団がシンフォニー・オブ・スターズに到達した年を基準としている。東暦（E暦）は1年を地球の約1.02年に換算し、シンフォニー・オブ・スターズの自転周期（44時間4分）に基づく独自の月・週・日システムを併用する。暦法の名称はM104銀河が地球から見て東方向に位置することに由来し、入植者たちが故郷との精神的繋がりを保つ意図が込められている。東暦はバーズ帝国の設立（E15年）から銀河系コンソーシアム設立（E520年）に至る全歴史的出来事を記述する絶対的時間基準として機能している。",descriptionEn:"The standard calendar system of the E16 civilization, with E1=AD3501 as its first year. It is based on the year when the first colonization fleet from Earth reached Symphony of Stars. The Eastern Calendar (E-calendar) converts one year to approximately 1.02 Earth years and uses its own unique month, week, and day system based on the rotation period of Symphony of Stars (44 hours 4 minutes). The name of the calendar originates from the fact that the M104 galaxy is located eastward from Earth's perspective, and includes the intention of the settlers to maintain a spiritual connection with their homeland. The Eastern Calendar functions as an absolute time standard describing all historical events from the establishment of the Birds Empire (E15) to the founding of the Galactic Consortium (E520)."},{id:"term-E0の定義",name:"E0の定義",nameEn:"Definition of E0",category:"用語",subCategory:"歴史",description:"東暦元年（E0）は地球暦AD3501年に相当し、入植船団がシンフォニー・オブ・スターズに到達した年として定義される。E0以前の期間は「地球期」と呼ばれ、地球から出発した移民集団の数百年にわたる星間航行期間を指す。E0の正確な定義は東暦初期に論争があり、一部の入植者は最初の惑星軌道到達日をE0と主張したが、最終的にシンフォニー・オブ・スターズへの着陸日が採用された。E0はバーズ帝国建国（E15年）の前提条件であり、入植者たちが新たな文明の時間を刻み始めた象徴的な起点である。ティムール・シャーの10次元ホラズム理論もE0年頃に構想された。",descriptionEn:"Eastern Calendar Year 0 (E0) corresponds to Earth calendar AD3501 and is defined as the year when the colonization fleet reached Symphony of Stars. The period before E0 is called the 'Earth Era,' referring to the centuries-long interstellar navigation period of the immigrant groups that departed from Earth. The exact definition of E0 was controversial in the early Eastern Calendar, with some settlers advocating for the first planetary orbit arrival day as E0, but ultimately the landing day at Symphony of Stars was adopted. E0 is a prerequisite for the founding of the Birds Empire (E15) and serves as a symbolic starting point when settlers began marking the time of a new civilization. Timur Shah's ten-dimensional Khwarazm theory was also conceived around E0."},{id:"term-暦変換規則",name:"暦変換規則",nameEn:"Calendar Conversion Rules",category:"用語",subCategory:"社会制度",description:"東暦（E暦）と地球暦（西暦・AD）の間の換算規則で、基本公式は「E年＝AD年−3500」である。東暦E500年は西暦4001年に相当する。ただしシンフォニー・オブ・スターズの自転周期（44時間4分）と公転周期の違いにより、東暦1年は地球の約1.02年に相当し、日単位の正確な換算には補正係数が必要である。E16連星系内の他惑星には独自の暦が併用されており、惑星ビブリオでは学術暦、Eros-7ではマトリカル暦が使用されている。銀河系コンソーシアム設立後は、宇宙文明圏間の共通時間基準を確立するため、グランベル主導で標準宇宙暦の制定が進められている。",descriptionEn:"The conversion rule between the Eastern Calendar (E-calendar) and Earth calendar (Western calendar/AD), with the basic formula being 'E year = AD year - 3500'. Eastern Calendar E500 corresponds to Western Calendar 4001. However, due to the difference between the rotation period (44 hours 4 minutes) and orbital period of Symphony of Stars, one Eastern Calendar year equals approximately 1.02 Earth years, requiring a correction factor for accurate day-by-day conversion. Other planets in the E16 star system have their own calendars used concurrently: the Academic Calendar on Planet Vibrio and the Matric Calendar on Eros-7. After the founding of the Galactic Consortium, the development of a Standard Universal Calendar has been promoted under Granbel's leadership to establish a common time standard between space civilizations."},{id:"term-A籍制度",name:"A籍制度",nameEn:"A-Registry System",category:"用語",subCategory:"社会制度",description:"E16連星系の包括的な市民身分証明・階級管理制度で、旅券機能と社会的地位の指標を兼ね備えている。A籍はZ1（最高位・政治指導者クラス）からZ50（最低位・無国籍相当）までの階級があり、各階級は居住区域のアクセス権、nトークンの取引限度額、公的サービスの利用範囲、宇宙港利用の優先度などを規定する。バーズ帝国期に原型が構想され、パクス・ロンバルディカ期に企業の従業員管理システムとして整備、ZAMLT期には社会階級の固定化装置として悪用された。ネオクラン同盟とUECOの下で階級緩和が進められているが、格差の完全解消には至っていない。惑星ビブリオのアカデミアに最高等級記録館が置かれ、全市民データのバックアップを保管している。",descriptionEn:"A comprehensive citizenship and class management system in the E16 star system, serving both as a passport and an indicator of social status. Class A ranges from Z1 (highest rank - political leadership class) to Z50 (lowest rank - stateless equivalent), with each class regulating access to residential areas, transaction limits for n-tokens, scope of public service usage, and priority of spaceport use. Its prototype was conceived during the Birds Empire period, developed as an employee management system for corporations during the Pax Lombardica period, and abused as a device for class固化 during the ZAMLT period. Class relaxation has progressed under the Neo-Clan Alliance and UECO, but complete elimination of disparities has not been achieved. The highest-level record archive is located at Academia on Planet Vibrio, storing backup data for all citizens."},{id:"term-nトークン経済",name:"nトークン経済",nameEn:"n-Token Economy",category:"用語",subCategory:"経済",description:"E16連星系の基軸通貨制度で、セリア黄金期に確立されたnトークンを中心に運用されている経済システム。最大の特徴は物質的資産だけでなく、文化的貢献、知識の共有、芸術的創造活動、社会的奉仕も経済的価値として評価・換金できる点にある。フェルミ音楽の演奏、次元極地平技術の研究、医療サービスの提供などもnトークンで報酬を受け取ることができる。ZAMLT期にはnトークンの集中化が進み不平等を拡大したが、UECO統合後は分散型台帳技術の導入で透明性が向上した。ロレンツィオ国際大学が算出する「文化・知識指数」を基準に定期調整され、E16文明圏独自の価値観を反映した革新的な経済モデルとして宇宙中から注目されている。",descriptionEn:"An economic system centered on n-tokens established during the Celian Golden Age in the E16 star system's base currency system. Its greatest feature is that not only material assets but also cultural contributions, knowledge sharing, artistic creative activities, and social service can be evaluated and monetized as economic value. Rewards can be received in n-tokens for performing Fermi music, researching dimensional horizon technology, providing medical services, etc. During the ZAMLT era, the concentration of n-tokens progressed and widened inequality, but after UECO integration, transparency improved with the introduction of distributed ledger technology. It is periodically adjusted based on the 'Culture-Knowledge Index' calculated by the Lorenzo International University, and as an innovative economic model reflecting the unique values of the E16 civilization zone, it is attracting attention throughout the universe."},{id:"term-ギガポリス通貨システム",name:"ギガポリス通貨システム",nameEn:"Gigapolis Currency System",category:"用語",subCategory:"経済",description:"GigapolisにおいてE150年のマーストリヒト革命で完全自由経済が宣言されて以降、急速に発展した複雑な金融・通貨システム。ギガポリスではnトークンのほか、企業独自の社内通貨、地区限定の地域通貨、 clandestine marketsで流通する地下通貨など多層的な通貨体系が併存している。E301年のZAMLT設立により金融システムが一元化されたが、ZAMLT崩壊後は再び多層化が進んだ。テクノ文化ルネサンス期にはブロックチェーン技術を応用した分散型決済システムが導入され、サウス・マーケットを中心に活発なnトークン経済が展開されている。マーケット・コアの取引所を通じたギガポリスと他惑星間の通貨換換はリアルタイムで行われ、E16連星系の金融安定に直結している。",descriptionEn:"A complex financial and currency system that developed rapidly in Gigapolis after the complete free economy was declared in the Maastricht Revolution of E150. In Gigapolis, a multi-layered currency system coexists, including n-tokens, company-specific internal currencies, region-limited local currencies, and underground currencies circulating in clandestine markets. With the establishment of ZAMLT in E301, the financial system was centralized, but after ZAMLT's collapse, multi-layering progressed again. During the Techno Cultural Renaissance period, a distributed payment system using blockchain technology was introduced, and an active n-token economy is developing centered around the South Market. Currency exchange between Gigapolis and other planets through the exchanges in Market Core is conducted in real time, directly linking to the financial stability of the E16 star system."},{id:"term-レア度分類",name:"レア度分類",nameEn:"Rarity Classification System",category:"用語",subCategory:"社会制度",description:"E16文明圏で広く使用されるアイテム・能力・人物の希少性評価システム。レア度はCommon（コモン）、Uncommon（アンコモン）、Rare（レア）、Epic（エピック）、Legendary（レジェンダリー）、Mythic（ミシック）の6段階に分類され、各段階はnトークンでの取引価格やA-Registryの特権に直接影響する。スティル・アレーナの出場資格やIRISランキングの算定にもレア度が考慮され、社会的評価の重要な指標となっている。レア度の判定基準はUECOが管理する中央評価委員会によって定期的に見直され、新技術の普及や社会構造の変化に応じて調整される。AURALISのメンバーの多くはLegendary以上のレア度を持ち、アルファ・ケインやジェンはMythicに分類されている。",descriptionEn:"A rarity evaluation system for items, abilities, and characters widely used in the E16 civilization zone. Rarity is classified into six levels: Common, Uncommon, Rare, Epic, Legendary, and Mythic, with each level directly affecting trading prices in n-tokens and privileges in the A-Registry. Rarity is also considered for qualification in the Still Arena and calculation of the IRIS ranking, serving as an important indicator of social evaluation. The criteria for determining rarity are regularly reviewed by the Central Evaluation Committee managed by UECO and adjusted according to the popularization of new technologies and changes in social structure. Many members of AURALIS have a rarity of Legendary or higher, and Alpha Cain and Jen are classified as Mythic."},{id:"term-戦闘力指数",name:"戦闘力指数",nameEn:"Combat Power Index",category:"用語",subCategory:"社会制度",description:"E16文明圏で個人の戦闘能力を数値化した指標で、IRISランキングシステムの基礎データとして使用される。戦闘力指数は筋力、反応速度、次元操作能力、戦術的判断力、装備品の性能などの複合要素をAI評価システムによって算出し、0〜999のスケールで表示される。900以上を「Tier 1（神格級）」、500〜899を「Tier 2（上位級）」、100〜499を「Tier 3（中堅級）」、100未満を「Tier 4（一般級）」に分類する。アルファ・ケインはギガポリス解放戦時に計測不能の指数を記録し、ジェンはLv938+として現在も最高水準を維持している。戦闘力指数はスティル・アレーナの出場資格審査と軍事組織の人材配置に不可欠な指標であり、UECOの安全保障政策の中核データとなっている。",descriptionEn:"A metric that quantifies an individual's combat ability in the E16 civilization zone, used as fundamental data for the IRIS ranking system. The combat power index is calculated by an AI evaluation system based on composite elements such as physical strength, reaction speed, dimensional manipulation ability, tactical judgment, and equipment performance, displayed on a scale of 0-999. Those with 900 or above are classified as 'Tier 1 (Divine Level)', 500-899 as 'Tier 2 (High Level)', 100-499 as 'Tier 3 (Mid Level)', and below 100 as 'Tier 4 (General Level)'. Alpha Cain recorded an immeasurable index during the Gigapolis Liberation War, and Jen maintains the current highest level at Lv938+. The combat power index is an essential metric for qualification review in the Still Arena and personnel allocation in military organizations, forming core data in UECO's security policy."},{id:"term-IRISランキングシステム",name:"IRISランキングシステム",nameEn:"IRIS Ranking System",category:"用語",subCategory:"社会制度",description:"E16文明圏の戦闘員・能力者の実力を格付けする公式ランキングシステムで、ヒーローエージェンシーによって管理されている。IRISランキングは戦闘力指数を基礎としつつ、実戦での勝敗記録、ミッションの達成度、社会的貢献度などの多角的な評価要素を組み合わせて総合順位を決定する。現在のランキング1位はアイリス、2位はフィオナ、3位はマリーナ・ボビン、4位はセバスチャン・ヴァレリウス、5位はカスチーナ・テンペストである。ランキング上位者には特別なnトークン報酬とA-Registry上の名誉階位が与えられ、軍事的・外交的な発言力にも直結する。ランキングの改定は四半期ごとに行われ、スティル・アレーナの結果が大きな影響を与える。銀河系コンソーシアム設立後は宇宙文明圏全体へのランキング拡張が検討されている。",descriptionEn:"An official ranking system that rates the strength of combatants and ability users in the E16 civilization zone, managed by the Hero Agency. The IRIS ranking is based on the combat power index but combines multifaceted evaluation elements such as win-loss records in actual combat, mission achievement, and social contribution to determine the overall ranking. The current ranking is: 1st place Iris, 2nd Fiona, 3rd Marina Bobbin, 4th Sebastian Valerius, 5th Castina Tempest. Top-ranking individuals receive special n-token rewards and honorary ranks in the A-Registry, which directly relates to military and diplomatic influence. The ranking is revised quarterly, with results from the Still Arena having a significant impact. After the establishment of the Galactic Consortium, expansion of the ranking to the entire cosmic civilization zone is being considered."},{id:"term-IRIS世界観",name:"IRIS世界観",nameEn:"IRIS Worldview",category:"用語",subCategory:"歴史",description:"アイリスを主人公とする一連の物語が描くE16文明圏の世界的視点で、クレセント大地方を中心に展開する政治的・軍事的な群像劇である。IRIS世界観はV7とトリニティ・アライアンスの対立構造、シルバー・ヴェノムとアルファ・ヴェノムの暗躍、フィオナの裏切りなど、クレセント地方における複雑な権力ゲームを体系的に描いている。アイリスのランキング1位への道のり、シルバー・ヴェノムへの捕囚（E510年）と再救出（E519年）、トリニティ・アライアンス指導者への転身という叙事は、E16文明圏における「個人の力と運命」のテーマを体現している。IRIS世界観は公式サイトIris Worldsで全編が公開されている。",descriptionEn:"A global perspective of the E16 civilization zone depicted in a series of stories featuring Iris as the protagonist, a political and military ensemble drama centered in the Crescent Great Region. The IRIS worldview systematically portrays the complex power games in the Crescent Region, including the confrontational structure between V7 and the Trinity Alliance, the covert activities of Silver Venom and Alpha Venom, and Fiona's betrayal. The narrative of Iris's journey to the top ranking, her capture by Silver Venom (E510) and subsequent rescue (E519), and her transformation into the leader of the Trinity Alliance embodies the theme of 'individual power and destiny' in the E16 civilization zone. The complete IRIS worldview is available on the official website Iris Worlds."},{id:"term-セリア黄金期の社会制度",name:"セリア黄金期の社会制度",nameEn:"Social System of Celia Golden Age",category:"用語",subCategory:"歴史",description:"E335年からE370年のセリア黄金期に確立された独特の社会統治体制。セリア・ドミニクスはZAMLTを打倒した後、超巨大企業Phovosを設立して次元エネルギー技術の商業化を推進し、GDP25兆ドル規模の経済基盤を構築した。この社会制度の最大の特徴は「文化と経済の融合」であり、フェルミ音楽の演奏やAURALISの芸術活動がnトークンで評価され、文化的貢献が直接経済的報酬に結びつく画期的な仕組みであった。セリアは女性主導社会の原型も構築し、主要な意思決定機関に女性が多数を占める体制を確立した。この社会制度はAURALIS第一世代の最盛期を支え、E16文明圏の文化的アイデンティティの基盤となったが、過剰な楽観主義とZAMLTの台頭によって急速に崩れていった。",descriptionEn:"A unique social governance system established during the Celian Golden Age from E335 to E370. After overthrowing ZAMLT, Celia Dominikus founded the mega-corporation Phovos to promote the commercialization of dimensional energy technology, building an economic foundation with a GDP of 25 trillion dollars. The greatest feature of this social system was the 'fusion of culture and economy,' where Fermi music performances and AURALIS artistic activities were evaluated in n-tokens, creating a groundbreaking mechanism where cultural contributions directly linked to economic rewards. Celia also established the prototype of a female-led society, ensuring that women formed the majority in key decision-making bodies. This social system supported the peak of the first generation of AURALIS and became the foundation of the cultural identity of the E16 civilization sphere, but it rapidly collapsed due to excessive optimism and the rise of ZAMLT."},{id:"term-エヴァトロン体制の法体系",name:"エヴァトロン体制の法体系",nameEn:"Evatron Legal System",category:"用語",subCategory:"法規",description:"E400年からE475年のエヴァトロン支配期にGigapolisおよび西大陸全域に適用された独裁的法体系。エヴァトロンの初代リーダー・グリム・ダルゴスが制定したこの法体系は、市民の基本的人権を大幅に制限し、表現の自由、集会の自由、移動の自由を厳しく規制した。特にAURALISを弾圧し、芸術・文化活動を「秩序を乱す反社会的行為」として法的に禁止した点が最も批判を浴びている。極秘部隊Σ-Unitの設立を法的に正当化する特別法も整備され、精神操作研究と生体改造実験を法的灰色地帯で実施した。テリアン反乱（E400〜E470年）はこの法体系に対する大規模な市民の抵抗であり、E475年の崩壊後はネオクラン同盟主導で民主的な法改革が実施された。",descriptionEn:"A dictatorial legal system applied to Gigapolis and the entire Western Continent during the Evatron rule from E400 to E475. Established by Evatron's first leader, Grimm Dargos, this legal system significantly restricted citizens' basic human rights and strictly regulated freedom of expression, assembly, and movement. It is most criticized for its suppression of AURALIS and the legal prohibition of artistic and cultural activities as 'socially disruptive acts that disturb order.' Special laws were also established to legally justify the formation of the secret unit Σ-Unit, conducting mental manipulation research and biological modification experiments in a legal gray area. The Terian Rebellion (E400-E470) was a large-scale citizen resistance against this legal system, and after its collapse in E475, democratic legal reforms were implemented under the leadership of the Neo-Clan Alliance."},{id:"term-ポスト・エヴァトロン秩序",name:"ポスト・エヴァトロン秩序",nameEn:"Post-Evatron Order",category:"用語",subCategory:"歴史",description:"E475年のエヴァトロン崩壊後に形成された新しい政治・社会秩序の総称。ポスト・エヴァトロン秩序はエヴァトロンの独裁的支配の教訓から、分散統治、市民参加型政治、人権の尊重を基本原理としている。ネオクラン同盟の設立（E325年〜）が思想的基盤となり、UECOの星間経済協同組合が経済的框架を提供し、テクノ文化ルネサンス（E475〜E500年）が文化的基盤を形成した。この秩序はA-Registryの階級制度の緩和、nトークン経済の民主化、次元極地平技術の民用化という三本の柱で支えられている。しかしシルバー・ヴェノムやアルファ・ヴェノムの出現は、ポスト・エヴァトロン秩序の脆弱性を露呈し、V7とトリニティ・アライアンスの対立構造という新たな課題をもたらしている。",descriptionEn:"A general term for the new political and social order formed after the collapse of Evatron in E475. The Post-Evratron Order, drawing lessons from Evatron's dictatorial rule, is based on the fundamental principles of decentralized governance, citizen-participatory politics, and respect for human rights. The establishment of the Neo-Clan Alliance (E325-) provided the ideological foundation, the UECO Interspace Economic Cooperative provided the economic framework, and the Technocultural Renaissance (E475-E500) formed the cultural foundation. This order is supported by three pillars: the mitigation of the A-Registry class system, the democratization of the n-token economy, and the civilian use of dimensional horizon technology. However, the emergence of Silver Venom and Alpha Venom exposed the vulnerabilities of the Post-Evratron Order, bringing new challenges in the form of the confrontation structure between V7 and the Trinity Alliance."},{id:"term-E16の度量衡",name:"E16の度量衡",nameEn:"E16 Weights and Measures",category:"用語",subCategory:"文化",description:"E16連星系で使用される独自の度量衡システム。シンフォニー・オブ・スターズの表面重力（0.92G）と自転周期（44時間4分）を基準に定義されており、地球の度量衡とは微妙に異なる。長さの基本単位は「スタンダード（Std）」で地球のメートルの約1.04倍に相当し、質量の基本単位は「グラビ（Gv）」で地球のキログラムの約0.96倍である。通貨単位はnトークンで、1nT（ナノ・トークン）が最小単位である。E16連星系統一後も一部の惑星で地球の度量衡が併用されていたが、パクス・ロンバルディカ期に完全に統一された。銀河系コンソーシアム設立後は、他宇宙文明圏との取引のために換算レートが標準化されている。",descriptionEn:"A unique system of measurement used in the E16 star system. Defined based on the surface gravity (0.92G) and rotation period (44 hours 4 minutes) of the Symphony of Stars, it subtly differs from Earth's measurement system. The basic unit of length is the 'Standard (Std)', equivalent to approximately 1.04 times Earth's meter, and the basic unit of mass is the 'Gravi (Gv)', equivalent to approximately 0.96 times Earth's kilogram. The currency unit is the n-token, with 1nT (nano-token) being the smallest unit. After the unification of the E16 star system, Earth's measurement system was still used in some planets, but it was completely unified during the Pax Lombardica period. After the establishment of the Galactic Consortium, conversion rates have been standardized for transactions with other cosmic civilization spheres."},{id:"term-言語体系",name:"言語体系",nameEn:"Language System of E16",category:"用語",subCategory:"文化",description:"E16文明圏で使用される多層的な言語体系。共通語として「東暦標準語（E16コモン）」が広く使用され、地球の英語・日本語・中国語を基底にした混合言語である。各惑星や地域には独自の言語や方言が存在し、ビブリオでは学術用語を多用した「アカデミア語」、Eros-7では女性主導社会特有の敬語体系を含む「マトリカル語」が日常的に使用されている。フェルミ音楽の歌詞は独特の詩的言語で記述され、AURALISの「名の継承」儀式では古い形式的言語が使用される。テクノ文化ルネサンス期にはOffenbach種との意思疎通のために次元共鳴言語の研究が進められ、感情や感覚を直接伝達する新たなコミュニケーション手段として注目されている。",descriptionEn:"A multilayered language system used in the E16 civilization sphere. 'East Calendar Standard Language (E16 Common)' is widely used as a common language, a hybrid language based on English, Japanese, and Chinese from Earth. Each planet and region has its own languages and dialects; in Biblio, 'Academia Language' with many academic terms is used, and on Eros-7, 'Matric Language' with a unique honorific system characteristic of a female-led society is used in daily life. Lyrics for Fermi music are written in a unique poetic language, and in AURALIS's 'Name Inheritance' ceremony, an archaic formal language is used. During the Technocultural Renaissance, research on dimensional resonance language was advanced for communication with the Offenbach species, and it is gaining attention as a new means of communication that directly conveys emotions and sensations."},{id:"term-教育制度",name:"教育制度",nameEn:"Education System of E16",category:"用語",subCategory:"文化",description:"E16連星系の多層的な教育制度で、A-Registryの階級と密接に連動している。基礎教育（6〜15歳）は全市民に無償で提供され、その後はA-Registryの階級に応じて中等教育・高等教育へのアクセスが異なる。Z1〜Z10の高階級市民は惑星ビブリオのロレンツィオ国際大学やグランベルのオルダシティ・アカデミーへの優先入学権を持ち、Z30以下の低階級市民は地域の職業訓練校に限定される傾向がある。ネオクラン同盟とUECOの下で教育の機会均等化が進められ、テクノ文化ルネサンス期には次元ホールを通じた遠隔教育システムが導入された。E514年にミナ・エウレカ・エルンストがロレンツィオ国際大学AI学部に入学した際、低階級出身からの最高学府への合格は大きな話題となった。",descriptionEn:"A multilayered education system in the E16 star system, closely linked to the A-Registry class system. Basic education (6-15 years) is provided free of charge to all citizens, after which access to secondary and higher education varies according to A-Registry class. High-class citizens (Z1-Z10) have priority admission rights to Lorenzo International University on the planet Biblio or Old City Academy on Grabel, while low-class citizens (Z30 and below) tend to be limited to regional vocational training schools. Under the Neo-Clan Alliance and UECO, educational equalization has progressed, and during the Technocultural Renaissance, a distance education system through dimensional halls was introduced. When Mina Eureka Ernst entered the AI department of Lorenzo International University in E514, her admission to the highest educational institution from a low-class background became a major topic."},{id:"term-芸術・文化運動",name:"芸術・文化運動",nameEn:"Art and Cultural Movements of E16",category:"用語",subCategory:"文化",description:"E16文明圏で興隆した主要な芸術・文化運動の歴史。テクノ宗教運動（E80年頃〜）を嚆矢とし、テミルタロンのサイケデリック・コスモロジーを思想的基盤に次元極地平を芸術的表現の素材とした。セリア黄金期（E335〜E370年）にはフェルミ音楽が最盛期を迎え、AURALIS第一世代が「光と音を永遠にする」理念のもとで総合芸術運動を展開した。エヴァトロン弾圧期（E400〜E475年）には地下芸術運動として「闇のアリア」と呼ばれる抵抗芸術が生まれた。テクノ文化ルネサンス（E475〜E500年）には次元極地平技術の民用化が新たな芸術表現の可能性を開き、AURALIS第二世代（E522年〜）はフェルミ音楽の現代的再解釈とOffenbach種との共創芸術を生み出している。これらの運動はE16文明圏の文化的アイデンティティの基盤を形成している。",descriptionEn:"History of major art and cultural movements that flourished in the E16 civilization zone. Beginning with the Techno-Religious Movement (around E80), with Timirtaron's psychedelic cosmology as its ideological foundation, it used dimensional horizons as artistic expression. During the Celia Golden Age (E335-E370), Fermi music reached its peak, and the first generation of AURALIS launched a comprehensive art movement under the philosophy of 'making light and sound eternal.' During the Evatron suppression period (E400-E475), a resistance art called 'Dark Aria' emerged as an underground art movement. During the Techno-Cultural Renaissance (E75-E500), the civilian use of dimensional horizon technology opened new possibilities for artistic expression, and the second generation of AURALIS (E522-) has created modern reinterpretations of Fermi music and collaborative art with the Offenbach species. These movements form the foundation of the cultural identity of the E16 civilization zone."},{id:"term-宗教観・世界観",name:"宗教観・世界観",nameEn:"Religious and Worldview of E16",category:"用語",subCategory:"文化",description:"E16文明圏における多様な宗教的・哲学的信念の総体。最大の宗教勢力はエレシュ信仰で、次元境界領を神聖視しヴェズレルを聖地とする。テクノ宗教運動はテミルタロンが提唱した次元極地平の神聖視を基盤とし、テンプル・オブ・ホライゾンを拠点にTroyane周辺に信者を集めている。ファティマ連邦は宗教的・哲学的自由を重んじる多元主義的な精神を国家理念とし、複数の信仰が共存する社会を形成している。フェルミ音楽の精神論的解釈も quasi-religious な世界観として機能し、AURALISの「光と音を永遠にする」という理念は一部の信者にとって宗教的な意味合いを持つ。グランベルとディオクレニスは世俗主義的傾向が強いが、エレシオンは「生命の維持と再生」を quasi-religious な理念として掲げている。",descriptionEn:"The totality of diverse religious and philosophical beliefs in the E16 civilization zone. The largest religious force is Eresh faith, which venerates dimensional border regions and considers Vezler a sacred land. The Techno-Religious Movement is based on Timirtaron's advocacy of the sanctity of dimensional horizons, gathering believers around Troyane with the Temple of Horizon as its base. The Fatima Federation values religious and philosophical freedom as a national philosophy, forming a society where multiple beliefs coexist. The spiritual interpretation of Fermi music also functions as a quasi-religious worldview, and AURALIS's philosophy of 'making light and sound eternal' has religious significance for some believers. Granbel and Dioclenis have strong secular tendencies, while Elesion promotes 'maintenance and regeneration of life' as a quasi-religious philosophy."},{id:"term-料理・食文化",name:"料理・食文化",nameEn:"Cuisine and Food Culture of E16",category:"用語",subCategory:"文化",description:"E16文明圏で発展した多様な食文化。シンフォニー・オブ・スターズの自生植物と地球から持ち込まれた作物の交配により、地球の料理を基盤にしながら独自の進化を遂げた。クレセント大地方ではミエルテンガ湖の淡水魚料理、ブルーローズ平原の穀物料理、ヴェルミリオン渓谷の峡谷野菜が名物である。テクノ文化ルネサンス期にはホライゾン・ゲートを通じた異星食材の流通が始まり、ファルージャの砂漠料理、エレシオンの健康食、グランベルの融合料理などがE16連星系全域で楽しめるようになった。ビブリオのアカデミアでは「食の哲学」という学際的研究分野が設立され、食文化を通じた文明間の理解促進が模索されている。サウス・マーケットの海上市場は異星食材が集まる美食の聖地として知られている。",descriptionEn:"Diverse food culture developed in the E16 civilization zone. Through crossbreeding of self-propagating plants from Symphony of Stars and crops brought from Earth, it evolved uniquely while based on Earth's cuisine. In the Crescent Great Region, freshwater fish dishes from Miertenga Lake, grain dishes from Blue Rose Plain, and canyon vegetables from Vermilion Valley are specialties. During the Techno-Cultural Renaissance, the circulation of alien ingredients through Horizon Gates began, and dishes such as Faruja's desert cuisine, Elesion's health food, and Granbel's fusion cuisine became available throughout the E16 star system. At the Acadia of Biblio, an interdisciplinary research field called 'Philosophy of Food' was established, seeking to promote inter-civilizational understanding through food culture. The South Market is known as a holy place for gourmet food where alien ingredients gather."},{id:"term-祝祭・記念日",name:"祝祭・記念日",nameEn:"Festivals and Memorial Days of E16",category:"用語",subCategory:"文化",description:"E16文明圏で祝われる主要な祝祭と記念日。最も重要なのは「入植記念日（E0のシンフォニー・オブ・スターズ到達を記念）」で、全星系で一斉に祝われる最大の祝祭である。その他、ギガポリスの復帰記念日（E475年エヴァトロン崩壊を記念）、セリア黄金期記念日（E335年セリア・ドミニクスによる黄金期開始を記念）、テクノ文化ルネサンス記念日（E475年技術開放を記念）が主要な星系規模の祝祭である。クレセント地方独自の祝祭にはブルーローズの「青い花祭り」、ファルージャの「砂漠の星間フェスティバル」、Poitiersの「フェルミ音楽復興祭」がある。AURALIS第二世代の設立記念日（E522年）はE16文明圏の文化復興の象徴として若年層に広く支持されている。",descriptionEn:"Major festivals and commemorations celebrated in the E16 civilization zone. The most important is 'Settlement Day (commemorating the arrival at Symphony of Stars in E0)', the largest festival celebrated simultaneously across the entire star system. Other major system-wide festivals include the Return of Gigapolis Day (commemorating the collapse of Evatron in E475), Celia Golden Age Day (commemorating the start of the golden age by Celia Dominicus in E335), and Techno-Cultural Renaissance Day (commemorating technological openness in E475). Local festivals unique to the Crescent Region include Blue Rose's 'Blue Flower Festival,' Faruja's 'Desert Intergalactic Festival,' and Poitiers's 'Fermi Music Revival Festival.' The founding anniversary of the second generation of AURALIS (E522) is widely supported by younger generations as a symbol of the cultural renaissance of the E16 civilization zone."},{id:"term-惑星間条約",name:"惑星間条約",nameEn:"Interplanetary Treaties",category:"用語",subCategory:"法規",description:"E16連星系内の複数惑星・国家間で締結された条約群の総称。最も重要な条約はE151年の新ヘルシンキ宣言に基づく「惑星連邦構想条約」で、複数の惑星文明が平等な立場で参加する統合体制の枠組みを規定している。その他、「次元兵器制限条約（E288年、メルディア戦争の教訓から）」「リーチ・ドレイン管理条約（E400年、スライム危機の教訓から）」「A-Registry改革条約（E490年、ネオクラン同盟主導）」が重要な惑星間条約である。銀河系コンソーシアム設立（E520年）後は、E16連星系外の宇宙文明圏との条約締結も進められ、「ヘゲモニー・パラドックス回避条約」がグランベルとティエリア間の軍縮を規定している。",descriptionEn:"Collective term for treaties concluded between multiple planets and nations within the E16 star system. The most important treaty is the 'Planetary Federation Concept Treaty' based on the New Helsinki Declaration of E151, which stipulates a framework for an integrated system where multiple planetary civilizations participate on equal footing. Other important interplanetary treaties include the 'Dimensional Weapon Limitation Treaty (E288, learned from the Meldia War),' 'Reach Drain Management Treaty (E400, learned from the Slime Crisis),' and 'A- Reform Treaty (E490, led by Neo-Clan Alliance).' After the establishment of the Galaxy Consortium (E520), treaties with cosmic civilization zones outside the E16 star system have been concluded, with the 'Hegemony Paradox Avoidance Treaty' stipulating disarmament between Granbel and Tieria."},{id:"term-銀河系コンソーシアム",name:"銀河系コンソーシアム",nameEn:"Galactic Consortium",category:"用語",subCategory:"法規",description:"E495年からE500年にかけて設立された宇宙規模の統合的ガバナンス組織で、M104銀河全域の平和と安定維持を目的としている。ネオクラン同盟、UECO、ヒーローエージェンシーの三大勢力を統合して誕生し、グランベル（経済1位）とティエリア（軍事3位）の共同議長体制で運営されている。最大の課題であるヘゲモニー・パラドックスの回避を最重要政策目標とし、対立する勢力間の調停と軍縮を推進している。E524年の諸世界連邦サミットを主催し、宇宙規模の外交協議を実現した。E530年の次元ブリッジ完成後は宇宙文明圏間の交流拡大に伴う新たな法規整備を進めている。エレシオンの平和主義とディオクレニスの科学的アプローチを政策の両輪としている。",descriptionEn:"A galaxy-scale integrated governance organization established from E495 to E500, aimed at maintaining peace and stability throughout the M104 galaxy. Born from the integration of three major forces: the Neo-Clan Alliance, UECO, and Hero Agencies, it is operated under a co-chairmanship system of Granbel (economic #1) and Tieria (military #3). Avoiding the Hegemony Paradox, its greatest challenge, is its most important policy goal, promoting mediation and disarmament between opposing forces. It hosted the United Worlds Federal Summit in E524, realizing galaxy-scale diplomatic consultations. After the completion of the Dimensional Bridge in E530, it has been advancing new legal regulations accompanying the expansion of exchanges between cosmic civilization zones. It balances Elesion's pacifism and Dioclenis's scientific approach as the two pillars of its policy."},{id:"term-通商路の定義",name:"通商路の定義",nameEn:"Definition of Trade Routes",category:"用語",subCategory:"経済",description:"E16文明圏における惑星間・星系間の商業取引ルートの定義と管理規則。主要な通商路はシンフォニー・オブ・スターズを中心に放射状に広がり、惑星ビブリオへの学術ルート、Eros-7へのエネルギールート、ガイア・リングへの資源ルートが四大動脈を形成している。テクノ文化ルネサンス期にホライゾン・ゲートの民生化が進み、従来の宇宙船航行ルートに加えて次元ホール経由の即時物流が可能となった。通商路の安全はUECOと銀河系コンソーシアムの合同部隊が担当し、海賊行為や密輸への取り締まりを行っている。プロキオ・ネクサスを中心とする宇宙規模の貿易ルートとの接続もE520年以降本格化している。通商路の定義はnトークン経済システムと不可分であり、物流コストの低減がE16文明圏全体の経済発展に直結している。",descriptionEn:"Definition and management regulations for interplanetary and interstellar commercial trade routes in the E16 civilization sphere. The main trade routes radiate from the Symphony of Stars as the center, forming four major arteries: academic routes to the planet Biblio, energy routes to Eros-7, and resource routes to the Gaia Ring. During the Techno-Cultural Renaissance period, the civilian use of Horizon Gates advanced, making instant logistics through dimensional holes possible in addition to traditional spaceship navigation routes. The security of trade routes is handled by joint forces of UECO and the Galactic Consortium, cracking down on piracy and smuggling. Connections with universe-scale trade routes centered on Proxio Nexus have been fully developed since E520. The definition of trade routes is inseparable from the n-token economic system, and reducing logistics costs directly contributes to the economic development of the entire E16 civilization sphere."},{id:"term-犯罪と刑罰体系",name:"犯罪と刑罰体系",nameEn:"Crime and Punishment System",category:"用語",subCategory:"法規",description:"E16文明圏の犯罪と刑罰に関する法体系。エヴァトロン体制下では犯罪の定義が拡大解釈され、芸術活動や政治的批判も処罰の対象となったが、ポスト・エヴァトロン秩序の下で大幅に見直された。現在の犯罪体系は「A-Registryへの侵害」「nトークンの不正操作」「次元技術の無許可使用」「暴力犯罪」「テロ活動」を主要犯罪類型として規定している。刑罰はA-Registryの階級低下、nトークンの没収、強制労働、宇宙刑務所への収監、極端な場合には次元流刑が科される。シルバー・ヴェノムやアルファ・ヴェノムの活動は「宇宙規模のテロ犯罪」と定義され、銀河系コンソーシアムの国際刑事裁判所の管轄に属する。テリアン反乱の参加者に対するエヴァトロン時代の不当な処刑は、現在の人権改革的議論の対象となっている。",descriptionEn:"Legal system concerning crime and punishment in the E16 civilization sphere. Under the Evatron regime, the definition of crime was broadly interpreted, and artistic activities and political criticism became punishable offenses, but were significantly reviewed under the post-Evatron order. The current crime system defines 'infringement on the A-Registry', 'illegal manipulation of n-tokens', 'unauthorized use of dimensional technology', 'violent crimes', and 'terrorist activities' as major crime types. Punishments include demotion in the A-Registry, confiscation of n-tokens, forced labor, imprisonment in space penitentiaries, and in extreme cases, dimensional exile. Activities of Silver Venom and Alpha Venom are defined as 'cos-scale terrorist crimes' and fall under the jurisdiction of the International Criminal Court of the Galactic Consortium. The unjust executions of participants in the Terrian Rebellion during the Evatron era have become the subject of current human rights reform discussions."},{id:"term-特許・知的財産制度",name:"特許・知的財産制度",nameEn:"Patent and Intellectual Property System",category:"用語",subCategory:"法規",description:"E16文明圏における発明・芸術的創造物の知的財産権を保護する法制度。セリア黄金期にAURALISの創作活動を保護するために原型が構築され、フェルミ音楽の楽曲や次元極地平技術の特許が最初の対象となった。現在の特許制度はUECOの管轄下で運営され、特許の有効期間は標準で50年（nトークン報酬の持続可能な期間）に設定されている。特許登録は惑星ビブリオのアカデミアにある国際特許庁で一元管理され、次元符号化技術による改ざん防止システムが導入されている。テクノ文化ルネサンス期には技術の民主化と知的財産権保護のバランスが大きな議論となり、重要な基礎技術の「オープンソース化」が進んだ分野もある。クアンタ・ラボ（E545年設立）の研究もこの制度の下で保護されている。",descriptionEn:"Legal system protecting intellectual property rights for inventions and artistic creations in the E16 civilization sphere. Its prototype was constructed during the Cerean Golden Age to protect the creative activities of AURALIS, with Fermi music songs and patents for dimensional horizon technology becoming the first subjects. The current patent system is operated under the jurisdiction of UECO, with a standard patent validity period of 50 years (the sustainable period of n-token rewards). Patent registration is centrally managed at the International Patent Office in Academia on planet Biblio, with an anti-tampering system using dimensional coding technology introduced. During the Techno-Cultural Renaissance period, balancing technological democratization with intellectual property protection became a major topic, with some fields advancing the 'open-sourcing' of important basic technologies. Research by Quanta Lab (established in E545) is also protected under this system."},{id:"term-環境保護法",name:"環境保護法",nameEn:"Environmental Protection Law of E16",category:"用語",subCategory:"法規",description:"E16文明圏においてシンフォニー・オブ・スターズおよび各植民地惑星の生態系保全を目的として制定された包括的な環境法規体系。スライム危機（E380〜E400年）におけるリーチ・ドレインの大量発生という教訓から、テクノ文化ルネサンス期（E475〜E500年）にネオクラン同盟主導で整備された。この法律は惑星資源の採掘制限、廃棄物の次元分解処理の義務化、生態系モニタリングの常時実施、外来生物種の輸入規制などを定めている。特にアイアン・シンジケートをはじめとする資源採掘企業に対する排出基準は厳格で、違反企業にはnトークン資産の凍結と操業停止の罰則が適用される。Eros-7の搾取エネルギー抽出活動に対する国際的な規制もこの法体系に基づいている。銀河系コンソーシアム設立後は、他宇宙文明圏との環境基準の調和化が進められている。",descriptionEn:"Comprehensive environmental legal system established in the E16 civilization sphere to preserve the ecosystems of the Symphony of Stars and various colony planets. Learning from the lesson of the Slime Crisis (E380-E400) where Reach Drains massively proliferated, it was developed under the leadership of the Neo-Clan Alliance during the Techno-Cultural Renaissance period (E475-E500). This law stipulates restrictions on planetary resource extraction, mandatory dimensional decomposition of waste, constant implementation of ecosystem monitoring, and import regulations for alien species. Emission standards for resource extraction companies, including the Iron Syndicate, are particularly strict, with penalties of freezing n-token assets and operational suspension applied to violating companies. International regulations on the exploitative energy extraction activities of Eros-7 are also based on this legal system. After the establishment of the Galactic Consortium, harmonization of environmental standards with other cosmic civilization spheres has been promoted."},{id:"term-報道自由",name:"報道自由",nameEn:"Freedom of Press in E16",category:"用語",subCategory:"文化",description:"E16文明圏における報道・表現の自由を保障する制度的枠組み。エヴァトロン支配期（E400〜E475年）には厳しく制限されていたが、崩壊後にネオクラン同盟主導で言論自由復興法が制定された。現在の報道自由はUECO憲章第7条で保障され、独立メディア機関の設立権、取材の自由、編集権の独立性が法的に認められている。ただし次元兵器の機密情報と軍事作戦の詳細については「国家安全例外条項」が適用され、報道制限が可能とされている。GigapolisのLilleを中心にニューメディア産業が急成長しており、次元ホログラム報道やリアルタイム戦況中継が市民の情報源として不可欠となっている。クレセント地方ではV7とトリニティ・アライアンスのプロパガンダ合戦の中で報道の中立性が重大な課題となっている。",descriptionEn:"Institutional framework guaranteeing freedom of press and expression in the E16 civilization sphere. It was severely restricted during the Evatron rule period (E400-E475), but after its collapse, the Freedom of Speech Revival Law was formulated under the leadership of the Neo-Clan Alliance. Current press freedom is guaranteed by Article 7 of the UECO Charter, with the right to establish independent media agencies, freedom of reporting, and editorial independence legally recognized. However, regarding confidential information on dimensional weapons and details of military operations, the 'national security exception clause' applies, allowing for press restrictions. The new media industry is rapidly growing centered around Lille in Gigapolis, with dimensional hologram reporting and real-time battle situation broadcasts becoming indispensable sources of information for citizens. In the Crescent region, the neutrality of reporting has become a major issue amidst the propaganda war between V7 and the Trinity Alliance."},{id:"term-スポーツ競技",name:"スポーツ競技",nameEn:"Sports and Athletic Competitions of E16",category:"用語",subCategory:"文化",description:"E16文明圏で愛好される各種スポーツ・競技活動の総称。シンフォニー・オブ・スターズの表面重力（0.92G）と自転周期（44時間4分）という惑星環境に適応して独自に発展した競技が多い。最も人気のあるのはネオンコロシアムで開催されるスティル・アレーナだが、それ以外にも次元スキー（アイアン・シンジケートの山岳地帯で行われる）、ゼロGバスケット（Gigapolisのテック・コリドー地区発祥）、プラズマランニング（西大陸の広大平原を利用したマラソン競技）などが広く愛好されている。テクノ文化ルネサンス期以降は、次元極地平技術を応用した「次元格闘技」や「空間アクロバティクス」といった新競技も誕生した。各競技の大会はnトークン賞金が設定され、プロ選手として活動する者も増加している。銀河系コンソーシアム主導で宇宙文明圏間スポーツ交流が始まっており、グランベルのマルチバース・ゲームズが最も権威ある国際大会として知られている。",descriptionEn:"General term for various sports and competitive activities popular in the E16 civilization sphere. Many competitions have independently developed to adapt to the planetary environment of the Symphony of Stars, with its surface gravity (0.92G) and rotation period (44 hours 4 minutes). The most popular is the Still Arena held at the Neon Colosseum, but other widely enjoyed activities include dimensional skiing (held in the mountainous regions of the Iron Syndicate), zero-G basketball (originating in the Tech Corridor district of Gigapolis), and plasma running (a marathon competition utilizing the vast plains of the Western Continent). Since the Techno-Cultural Renaissance period, new competitions such as 'dimensional martial arts' and 'spatial acrobatics' applying dimensional horizon technology have also emerged. N-token prize money is set for competitions in each sport, and the number of professional athletes is increasing. Under the leadership of the Galactic Consortium, sports exchanges between cosmic civilization spheres have begun, with the Multiverse Games of Granbel being known as the most prestigious international competition."},{id:"東暦",name:"東暦（E暦）",nameEn:"Eastern Calendar (E Calendar)",category:"歴史",subCategory:"歴史・時代",description:"E1 = AD 3501から始まる暦法で、E16連星系への最初の入植船団が到着した年を元年としている。それ以前の地球暦（西暦）との換算式は E年 = AD年 - 3500 であり、東暦E500年は西暦4001年に相当する。暦法の名称「東暦」は、地球から見てM104銀河が東方向に位置することに由来し、入植者たちが故郷地球との精神的な繋がりを保ちつつ新たな文明の時間を刻むために制定した。E16連星系の自転周期（44時間4分）に合わせた独自の暦体系が併用されており、1東暦年は地球の約1.02年に相当する。東暦はバーズ帝国の設立、パクス・ロンバルディカ、スライム危機、テクノ文化ルネサンスなど、E16文明圏の全歴史的出来事を記述する基準となっている。",descriptionEn:"The Eastern Calendar, beginning in AD 3501, uses the year the first colonization fleet arrived in the E16 star system as its year one. The conversion formula to the previous Earth calendar (Gregorian) is E year = AD year - 3500, making Eastern year 500 equivalent to AD 4001. The calendar's name \"Eastern\" derives from the M104 Galaxy's position to the east when viewed from Earth, established by settlers to maintain a spiritual connection to their homeworld while marking time for a new civilization. A unique calendar system, synchronized with the E16 star system's rotation period (44 hours, 4 minutes), is used concurrently, with one Eastern year equivalent to approximately 1.02 Earth years. The Eastern Calendar serves as the基准 for describing all historical events in the E16 civilization sphere, including the founding of the Vaz Empire, the Pax Lombardica, the Slime Crisis, and the Technocultural Renaissance."},{id:"バーズ帝国",name:"バーズ帝国",nameEn:"Birds Empire",category:"歴史",subCategory:"歴史・時代",description:"E15年からE61年まで続いたE16連星系初の包括的統一政権で、軍閥ファランクスによって樹立された。ファランクスは初期植民地間の紛争を武力によって終結させ、シンフォニー・オブ・スターズ全域にわたる法秩序とインフラを構築した。バーズ帝国は帝国という名称ながらも、初期の入植者自治の伝統をある程度尊重し、各省庁に相当する地方総督府制度を導入した。E61年、ファランクスの死後、後継者争いと各地の独立運動によって帝国は分裂し、複数の小規模国家群に解体された。しかし、帝国期に整備された通信ネットワークと航路標識は後のパクス・ロンバルディカ期の繁栄の基盤となり、A-Registryの初期原型もこの時期に構想された。バーズ帝国の崩壊はE16文明圏における「統一と分岐」の循環の最初の例として歴史家に注目されている。初代皇帝ファランクス（E15〜E61）が軍閥ファランクスとして初期植民地間紛争を武力終結させ帝国を樹立。ファランクスの死後、後継者争いで帝国は分裂したが、その軍事伝統はテクロサス系譜として受け継がれ、現在のボグダス・ジャベリンに至っている。",descriptionEn:"The Vaz Empire, the first comprehensive unified government in the E16 star system, lasted from E15 to E61 and was established by the military faction Phalanx. Phalanx ended conflicts between early colonies through force and constructed a legal order and infrastructure across the Symphony of Stars. Despite its name, the Vaz Empire respected the tradition of early settler self-governance to some extent, introducing a system of regional governorates equivalent to various ministries. After Phalanx's death in E61, the empire fragmented into multiple smaller states due to succession disputes and independence movements across various regions. However, the communication networks and space route markers developed during the imperial period became the foundation for the prosperity of the later Pax Lombardica era, and the initial prototype of the A-Registry was conceived during this time. The collapse of the Vaz Empire is noted by historians as the first example of the cycle of \"unity and divergence\" in the E16 civilization sphere. The first emperor, Phalanx (E15-E61), ended conflicts between early colonies by force and established the empire. After Phalanx's death, the empire fractured due to succession disputes, but its military tradition was inherited by the Teklos lineage, leading to the current Bogdas Javelin.",leaders:[{id:"ファランクス",name:"ファランクス",nameEn:"Phalanx",role:"バーズ帝国初代皇帝",era:"E15〜E61"}]},{id:"セリア黄金期",name:"セリア黄金期",nameEn:"Celia Golden Age",category:"歴史",subCategory:"歴史・時代",description:"E335年からE370年まで続いたE16文明圏の最盛期で、フェルミ音楽理論の完成、nトークン経済の確立、AURALIS第一世代の黄金時代を包含する。この時期、フェルミ音楽は単なる芸術形式を超えて、惑星間通信の符号化や医療治療への応用など社会的基盤技術として機能した。AURALISの「光と音を永遠にする」という理念は文明全体の文化規範となり、建築、服飾、都市計画に至るまで音響的調和が重視された。nトークン経済システムもこの時期に急速に普及し、物質的富だけでなく文化的貢献や知識の共有が経済的価値として評価される画期的な体制を構築した。しかし黄金期の過剰な楽観主義は内部の構造的矛盾を隠蔽しており、E370年以降、ZAMLTの台頭によってこの調和は急速に崩れていくことになる。\nこのセリア黄金期の根底には、防衛的加速主義(L1)と第2のゲーム(L3)の思想的地層が横たわっている。覇権競争に巻き込まれず、文化創造によって文明を守った先例として、この時代はL1の「防衛的技術」理念の萌芽を示している。軍事的拡張ではなく知的・文化的到達によって他文明との関係を構築したセリアの選択は、オムニウィン構想の先駆けとしてL3の思想的系譜に位置づけられる。",descriptionEn:'The Serian Golden Age, the peak period of the E16 civilization sphere from E335 to E370, encompassed the completion of Fermi musical theory, the establishment of the n-token economy, and the golden age of the first generation of AURALIS. During this period, Fermi music transcended mere art form to function as a foundational social technology, applied in interplanetary communication encoding and medical treatments. AURALIS\'s philosophy of "making light and sound eternal" became a cultural norm for the entire civilization, with acoustic harmony emphasized in architecture, fashion, and urban planning. The n-token economic system also rapidly spread during this time, constructing a groundbreaking system where not only material wealth but also cultural contributions and knowledge sharing were evaluated as economic value. However, the excessive optimism of the golden age concealed internal structural contradictions, and after E370, this harmony rapidly collapsed with the rise of ZAMLT. Beneath this Serian Golden Age lies the ideological strata of Defensive Accelerationism (L1) and the Second Game (L3). As a precedent for protecting civilization through cultural creation rather than being drawn into hegemonic competition, this era shows the萌芽 of L1\'s "defensive technology" philosophy. Seria\'s choice of building relations with other civilizations through intellectual and cultural achievements rather than military expansion is positioned in the ideological lineage of L3 as a precursor to the Omniwin concept.'},{id:"パクス・ロンバルディカ",name:"パクス・ロンバルディカ",nameEn:"Pax Lombardica",category:"歴史",subCategory:"歴史・時代",description:"E205年からE278年まで続いたコーポラタムパブリカ（株式会社共和国）の全盛期で、E16連星系における企業統治モデルの最も成功した時代である。パクス・ロンバルディカという名称は「ロンバルディアの平和」を意味し、主要企業群が協調して統治を行うことで約70年にわたる長期安定を実現した。この時代、企業は利潤追求だけでなく、インフラ整備、教育、医療、宇宙探査などの公共サービスを担い、国家の役割を代替する画期的な統治体制を確立した。惑星ビブリオのロレンツィオ国際大学もこの時期に設立され、学術研究への大規模投資が行われた。しかし企業間の寡占化が進み、市民の政治参加権が制限される傾向が強まったこと、そして企業利益と公共利益の対立が深まったことが、最終的にZAMLTによる強硬な経済覇権への移行を招く要因となった。",descriptionEn:"The peak period of the Corporatum Publica (Corporate Republic), lasting from E205 to E278, was the most successful era of corporate governance in the E16 star system. The name Pax Lombardica, meaning \"Lombardian Peace,\" reflects the long-term stability of about 70 years achieved through coordinated governance by major corporate groups. During this era, corporations undertook not only profit-seeking but also public services such as infrastructure development, education, healthcare, and space exploration, establishing an innovative governance system that replaced the functions of the state. The Lorenzo International University on the planet Vibrio was also founded during this period, with large-scale investments in academic research. However, as oligopolization among corporations advanced and the tendency to restrict citizens' political participation strengthened, and as conflicts between corporate interests and public interests deepened, these factors ultimately led to the transition to ZAMLT's aggressive economic hegemony."},{id:"スライム危機",name:"スライム危機",nameEn:"Slime Crisis",category:"歴史",subCategory:"歴史・時代",description:"E380年からE400年まで約20年間続いた大規模災害で、Eros-7を原生地とするリーチ・ドレインの遺伝子変異によって引き起こされた。変異したリーチ・ドレインは従来の性的エネルギー吸収能力に加え、他の生命体の生体エネルギーをも吸収するようになり、感染力と増殖力が劇的に向上した。災害はEros-7から始まり、惑星間航行に乗ってシンフォニー・オブ・スターズや他の植民地に波及し、特に人口密集地域で壊滅的な被害をもたらした。ZAMLT期の経済優先政策によって生物災害対策が後回しにされていたことが被害拡大の要因とされ、この教訓は後にテクノ文化ルネサンス期の「技術の民主化」と「生態系との調和」という理念に強く反映された。スライム危機の収束にはEros-7のマトリカル社会が独自に開発した生物学的封じ込め技術が決定的な役割を果たし、この技術は後に医療や環境修復分野で広く応用されることになる。アヤカ・リンがアンダーグリッドでの制圧作戦を先陣を切って指揮し、レイラ・ヴィレル・ノヴァもオアシス・ハウスを拠点にスライム討伐で英雄的活躍を見せた。",descriptionEn:'A major disaster lasting approximately 20 years from E380 to E400, caused by genetic mutations in the Reach Drain native to Eros-7. The mutated Reach Drain, in addition to its conventional sexual energy absorption capabilities, began to absorb the bio-energy of other lifeforms, dramatically increasing its infectivity and reproductive capacity. The disaster began on Eros-7 and spread to the Symphony of Stars and other colonies via interplanetary travel, causing devastating damage especially in densely populated areas. The prioritization of economic policy over biological disaster prevention during the ZAMLT period is considered a factor in the expansion of the damage, and this lesson was strongly reflected in the later "democratization of technology" and "harmony with the ecosystem" principles of the Technocultural Renaissance period. The Matriscal society of Eros-7 independently developed biological containment technology that played a decisive role in containing the Slime Crisis, and this technology was later widely applied in medical and environmental restoration fields. Ayaka Rin led the suppression operation in the Undergrid, and Leila Viler Nova also performed heroic deeds in the Slime extermination operations based at Oasis House.'},{id:"テクノ文化ルネサンス",name:"テクノ文化ルネサンス",nameEn:"Techno-Cultural Renaissance",category:"歴史",subCategory:"歴史・時代",description:"E475年からE500年まで続いた文化・技術の飛躍期で、次元極地平技術の民用化と多文明融合が進んだ画期的な時代である。スライム危機の教訓から、従来は軍事・企業エリートに限定されていた次元極地平技術が一般市民にも開放され、ホライゾン・ゲートを通じた惑星間移動が日常化した。これによりE16連星系内の各地域間交流が爆発的に増加し、異なる植民地の文化が融合する新しい芸術・音楽・哲学が花開いた。テクノ文化ルネサンスはAURALIS第二世代の設立（E522年）を準備する文化的土壌となり、フェルミ音楽の現代的再解釈やOffenbach種との協創芸術などが生まれた。また、ペルセポネ計画の初期構想もこの時期に生み出され、次元階梯パンディクト理論の基礎研究が惑星ビブリオで開始された。\nこのテクノ文化ルネサンスの根底には、第2のゲーム(L3)の思想的地層が横たわっている。ZAMLT崩壊後の再構築において「覇権競争」ではなく「共存フレームワーク」を設計しようとしたこの動きは、ゼロサムゲームからオムニウィン（全員勝利）への転換を志向するL3の思想の大規模な歴史的実践であった。",descriptionEn:'A period of cultural and technological leap from E475 to E500, a groundbreaking era marked by the civilian application of dimensional pole horizon technology and the advancement of multi-civilization fusion. Learning from the lessons of the Slime Crisis, dimensional pole horizon technology, previously limited to military and corporate elites, was opened to the general public, making interplanetary travel via Horizon Gates a daily occurrence. This led to an explosive increase in interregional exchange within the E16 star system, and new art, music, and philosophy blossomed from the fusion of different colonial cultures. The Technocultural Renaissance prepared the cultural soil for the establishment of the second generation of AURALIS (E522), giving birth to modern reinterpretations of Fermi music and collaborative art with the Offenbach species. Additionally, the initial concept of the Persephone Plan was born during this period, and foundational research on dimensional ladder Pandect theory began on the planet Vibrio. Beneath this Technocultural Renaissance lies the ideological stratum of the Second Game (L3). This movement, which sought to design a "coexistence framework" rather than "hegemonic competition" in the reconstruction after ZAMLT\'s collapse, was a large-scale historical practice of L3\'s philosophy, aiming to transition from a zero-sum game to Omniwin (all-win).'},{id:"エルトナ戦争",name:"エルトナ戦争",nameEn:"Eltna War",category:"歴史",subCategory:"戦争・事件",description:"E14年に勃発したシンフォニー・オブ・スターズ史上最初期の大規模紛争。地球から到来した移民集団の間で、「前衛意識」を標榜する進歩派と、惑星の自然環境との調和を重んじる「原始意識」を奉じる保守派が激しく衝突した。人種的・文化的緊張の起源となった戦争であり、その対立構造は後のテラン朝共和制の成立過程にも影響を及ぼした。この戦争の教訓は、のちに技術啓蒙時代におけるバイオエンジニアリングの倫理議論の基礎となった。",descriptionEn:'The first large-scale conflict in the history of the Symphony of Stars, erupting in E14. It was a fierce collision between immigrant groups from Earth: the progressive faction advocating for "vanguard consciousness" and the conservative faction adhering to "primitive consciousness" that emphasized harmony with the planet\'s natural environment. A war that became the origin of racial and cultural tensions, its opposing structure also influenced the formation process of the later Teran dynasty republic. The lessons of this war later became the foundation for ethical debates on bioengineering during the Technological Enlightenment era.'},{id:"アフター戦争",name:"アフター戦争",nameEn:"After War",category:"歴史",subCategory:"戦争・事件",description:"E62年からE77年にかけて続いた大規模な内戦。チョンクォン戦争と並んで、シンフォニー・オブ・スターズ西大陸における王朝体制から共和制への移行をもたらした決定的な契機となった。封建的な支配構造に対する市民の不満が爆発し、各地で武装蜂起が発生。15年に及ぶ戦闘の末、旧支配層は崩壊し、新たな共和制の基盤が築かれた。この戦争はEDUの歴史において「自由への序章」として位置づけられている。",descriptionEn:"A large-scale civil war that lasted from E62 to E77. Along with the Chongquan War, it became a decisive factor in the transition from a dynastic system to a republic in the western continent of the Symphony of Stars. Citizens' dissatisfaction with the feudal ruling structure exploded, and armed uprisings occurred in various regions. After 15 years of combat, the old ruling class collapsed, and the foundation of a new republic was established. This war is positioned in EDU's history as the \"Prologue to Freedom.\""},{id:"チョンクォン戦争",name:"チョンクォン戦争",nameEn:"Chonkwon War",category:"歴史",subCategory:"戦争・事件",description:"E62年からE77年にかけてアフター戦争と並行して戦われた大規模紛争。主に東方領域を舞台に、地方分権を求める勢力と中央集権体制の維持を図る勢力が激突した。チョンクォン地域の特殊性を背景に複雑な駆け引きが展開され、多数の都市が戦火に巻き込まれた。アフター戦争との相乗効果により、最終的にテラン朝共和制への移行が不可避となった。この戦争の名称はチョンクォン平原での決戦に由来する。",descriptionEn:"The large-scale conflict fought from E62 to E77, concurrent with the After War. Primarily staged in the Eastern Territories, it saw a clash between forces seeking regional decentralization and those attempting to maintain the centralized system. Against the backdrop of the special nature of the Chongquan region, complex maneuvers unfolded, with numerous cities drawn into the conflict. The combined effect with the After War made the transition to the Teran Dynasty Republic inevitable. The war's name derives from the decisive battle on the Chongquan Plain."},{id:"テラン朝共和制",name:"テラン朝共和制",nameEn:"Terran Republic",category:"歴史",subCategory:"戦争・事件",description:"E62〜E77年のアフター戦争およびチョンクォン戦争の終結に伴い、旧封建体制に代わって成立した共和制政体。市民の代表による議会制度を導入し、西大陸初の本格的な民主主義的統治体制を確立した。しかし初期には共和制の運営経験不足から政治的混乱が続いた。技術啓蒙時代の幕開けとともに安定し、のちのマーストリヒト革命を経てコーポラトクラシー体制であるコーポラタムパブリカへと発展的に移行した。",descriptionEn:"The republican government established following the conclusion of the After War and the Chongquan War from E62 to E77, replacing the old feudal system. It introduced a parliamentary system with citizen representatives, establishing the first comprehensive democratic governance system on the Western Continent. However, initial political turmoil continued due to the inexperience in republican governance. It stabilized with the beginning of the Enlightenment Era, and later developed into the Corporatocracy of Corporatum Publica through the Maastricht Revolution."},{id:"ロンバルディア戦争",name:"ロンバルディア戦争",nameEn:"Lombardia War",category:"歴史",subCategory:"戦争・事件",description:"E88年からE98年にかけてM104銀河全域を巻き込んだ史上最大規模の星間戦争。西大陸の内政不満と外惑星領域との資源争奪が複雑に絡み合い、複数の惑星系で同時に戦闘が勃発。次元兵器の試験的使用が行われた最初の大戦でもあり、その被害は甚大であった。戦後の処理過程でセクスタス連合が結成され、ロンバルディア帝国との対立構造が形成された。この戦争は銀河規模の安全保障体制の必要性を浮き彫りにした。",descriptionEn:"The largest interstellar war in history, engulfing the entire M104 galaxy from E88 to E98. Complex entanglement of Western Continental political dissatisfaction and resource competition with outer planetary regions led to simultaneous outbreaks of combat in multiple star systems. It was also the first major war to see experimental use of dimensional weapons, causing catastrophic damage. In the post-war process, the Sextus Alliance was formed, establishing a confrontational structure with the Lombardia Empire. This war highlighted the necessity of a galaxy-wide security system."},{id:"メルディア戦争",name:"メルディア戦争",nameEn:"Meldia War",category:"歴史",subCategory:"戦争・事件",description:"E275年からE288年にかけてロンバルディア帝国とセクスタス連合の間で戦われた大規模な星間戦争。13年に及ぶ戦争の最終局面でロンバルディア帝国は次元兵器を初めて本格的に投入し、セクスタス連合の主要拠点を壊滅させて勝利を収めた。しかし次元兵器使用の倫理的議論は銀河全体に波紋を広げ、のちのアポロン・Dominion大戦における次元兵器の禁止条約の根拠となった。戦後のロンバルディア帝国の覇権確立は第五次繁栄期をもたらした。",descriptionEn:"The massive interstellar war fought between the Lombardia Empire and the Sextus Alliance from E275 to E288. In the final phase of the 13-year war, the Lombardia Empire first deployed dimensional weapons on a full scale, annihilating the main strongholds of the Sextus Alliance to achieve victory. However, the ethical debate over the use of dimensional weapons sent ripples throughout the galaxy, later becoming the basis for the dimensional weapons prohibition treaty in the Apollo-Dominion Great War. The post-war establishment of Lombardia's hegemony brought about the Fifth Prosperity Period."},{id:"マーストリヒト革命",name:"マーストリヒト革命",nameEn:"Maastricht Revolution",category:"歴史",subCategory:"戦争・事件",description:"E150年にエル・フォルハウスが主導した経済革命。彼はGigapolisのセントラル・タワーを武力で占拠し、それまでの規制経済体制を廃止して完全自由経済を宣言した。この革命により企業の活動が大幅に自由化され、コーポラタムパブリカ体制から新たな経済秩序への転換が完了した。革命の理念は新ヘルシンキ宣言に受け継がれ、のちの惑星連邦構想の思想的基盤の一つとなった。エル・フォルハウスは革命後、初代経済自由委員会の委員長に就任した。",descriptionEn:"The economic revolution led by El Forhaus in E150. He forcibly occupied the Central Tower of Gigapolis, abolished the previous regulated economic system, and declared a completely free economy. This revolution greatly liberalized corporate activities, completing the transition from the Corporatum Publica system to a new economic order. The revolution's ideals were carried forward in the New Helsinki Declaration, later becoming one of the ideological foundations for the planetary federation concept. After the revolution, El Forhaus became the first chairman of the Economic Freedom Commission."},{id:"クワンナラ革命",name:"クワンナラ革命",nameEn:"Kwannara Revolution",category:"歴史",subCategory:"戦争・事件",description:"E108年からE114年にかけて起こった大規模な社会革命。中央集権体制に対する地方勢力とクラン（氏族）の反発を背景に、分権化とクランの伝統的権利の復権を要求する声が高まった。革命の結果、地方自治権が大幅に拡大され、クラン・フォーラムの設立など分権的な統治体制が整備された。この革命はE325年のネオクラン同盟設立への遠因ともなり、西大陸政治における「中央対地方」の構造を形成する決定的な転換点となった。",descriptionEn:'The major social revolution that occurred from E108 to E114. Against the backdrop of resistance from regional powers and clans (tribes) against the centralized system, demands for decentralization and the restoration of traditional clan rights grew louder. As a result of the revolution, local autonomy was greatly expanded, and a decentralized governance system was established, including the formation of the Clan Forum. This revolution also became a remote cause for the establishment of the Neo-Clan Alliance in E325, becoming a decisive turning point that formed the "central vs. local" structure in Western Continental politics.'},{id:"新ヘルシンキ宣言",name:"新ヘルシンキ宣言",nameEn:"New Helsinki Declaration",category:"歴史",subCategory:"戦争・事件",description:"E151年にアリア・ソルが提案した画期的な外交構想。惑星連邦の設立と、次元極地平を活用した星間議会の組織化を柱とする構想であり、複数の惑星文明が平等な立場で参加する宇宙規模の連合体制を構想した。この宣言はマーストリヒト革命の翌年に発表され、経済の自由化に続く政治的統合のビジョンとして広範な支持を集めた。のちの銀河系コンソーシアム設立の理念的源流として高く評価されている。",descriptionEn:"The groundbreaking diplomatic vision proposed by Aria Sol in E151. Centered on the establishment of a Planetary Federation and the organization of an interstellar council utilizing dimensional poles, it envisioned a cosmic-scale alliance where multiple planetary civilizations could participate on equal footing. This declaration, made the year after the Maastricht Revolution, garnered broad support as a vision of political integration following economic liberalization. It is highly regarded as the ideological source for the later establishment of the Galactic Consortium."},{id:"コーラの疫病",name:"コーラの疫病",nameEn:"Corra Plague",category:"歴史",subCategory:"戦争・事件",description:"E208年に発生した未曾有の大疫病。アンドロメダ銀河系からの移民者の遺伝子に特異的に作用するウイルスが変異して猛威を振るい、人口の約15パーセントにあたる約4,500万人が死亡する壊滅的被害をもたらした。この疫病は移民集団と在来住民の間に根深い不信感を生み出し、被害を受けた移民コミュニティを中心にシャドウ・リベリオンが結成される直接の契機となった。のちに疫病のウイルスは人工的に改造されたものである可能性が指摘されている。",descriptionEn:"The unprecedented great plague that occurred in E208. A virus that specifically acted on the genes of immigrants from the Andromeda galaxy mutated and wreaked havoc, causing catastrophic damage with approximately 45 million deaths, accounting for about 15% of the population. This plague created deep-seated distrust between immigrant and native populations, and directly led to the formation of the Shadow Rebellion, centered on affected immigrant communities. Later, it was suggested that the plague virus may have been artificially modified."},{id:"テリアン反乱",name:"テリアン反乱",nameEn:"Terrian Rebellion",category:"歴史",subCategory:"戦争・事件",description:"E400年からE470年にわたり、エリオス・ウォルドが率いるテリアン反乱軍がエヴァトロンの支配に抵抗して戦った大規模な反乱。70年間に及ぶ抵抗運動は西大陸の歴史で最も長期にわたる武装闘争となった。エリオスは農民や市民を結集してゲリラ戦を展開し、エヴァトロンの資源供給網に深刻な打撃を与えた。しかしE470年にエリオスが捕縛・処刑されると反乱軍は一時衰退したが、残存勢力は地下活動を継続し、E475年のエヴァトロン崩壊の決定的な要因となった。",descriptionEn:"From E400 to E470, the Great Rebellion led by Erios Wald where the Terian resistance forces fought against Evatron's dominion. The 70-year-long resistance movement became the longest armed struggle in the history of the Western Continent. Erios rallied peasants and citizens to launch guerrilla warfare, dealing severe blows to Evatron's resource supply network. However, when Erios was captured and executed in E470, the rebellion temporarily declined, though the remaining forces continued underground activities and became a decisive factor in Evatron's collapse in E475."},{id:"技術啓蒙時代",name:"技術啓蒙時代",nameEn:"Technological Enlightenment Era",category:"歴史",subCategory:"歴史・時代",description:"E80年からE90年にかけての約10年間にわたる技術爆発の黄金期。バイオエンジニアリングが飛躍的な進化を遂げ、セル・ウィーヴが一般市民に普及して放射線耐性と大幅な寿命延長が実現した。この時代の技術革新は人口を約5,000万人に急増させ、Gigapolisの都市インフラを劇的に拡大した。同時に、技術の倫理的境界をめぐる議論が活発化し、テクノ宗教運動の誕生とテラン朝共和制の思想的形成に大きな影響を与えた。",descriptionEn:"The golden age of technological explosion spanning approximately 10 years from E80 to E90. Bioengineering made a quantum leap, and Cell-Weave became widespread among ordinary citizens, achieving radiation resistance and significant lifespan extension. The technological innovations of this era rapidly increased the population to about 50 million, dramatically expanding Gigapolis's urban infrastructure. Simultaneously, debates over the ethical boundaries of technology intensified, greatly influencing the birth of techno-religious movements and the ideological formation of the Teran dynasty republic."},{id:"テクノ宗教運動",name:"テクノ宗教運動",nameEn:"Techno-Religious Movement",category:"歴史",subCategory:"歴史・時代",description:"次元極地平技術の発見を端緒として興隆した宗教・哲学運動。次元極地平を単なる物理現象としてではなく「宇宙の意志」の顕現として神聖視し、技術と信仰の融合を追求した。テミルタロンがこの運動の思想的指導者となり、拠点としてテンプル・オブ・ホライゾンを建設。サイケデリック・コスモロジーを提唱し、次元階梯パンディクトの原型を構想した。技術啓蒙時代の物質主義的傾向に対する精神的なアンチテーゼとして広範な支持を集め、Troyaneを聖地として現在でも信仰が続いている。",descriptionEn:'A religious and philosophical movement that emerged following the discovery of dimensional horizon technology. It revered the dimensional horizon not merely as a physical phenomenon but as the manifestation of "the will of the universe," pursuing the fusion of technology and faith. Temirlaron became the ideological leader of this movement, establishing the Temple of Horizon as its base. He proposed psychedelic cosmology and conceived the prototype of the dimensional ladder pandect. It gathered broad support as a spiritual antithesis to the materialistic tendencies of the technological enlightenment era, and Troyane remains a sacred site where the faith continues to this day.'},{id:"ギガポリス解放戦",name:"ギガポリス解放戦",nameEn:"Gigapolis Liberation War",category:"歴史",subCategory:"戦争・事件",description:"E318年にアルファ・ケインが率いるシャドウ・リベリオンによって引き起こされたZAMLT打倒の戦争。アルファ・ケインはオムニバス・エンジンへの伝説的なハッキング攻撃を実行し、ZAMLTの経済的基盤に決定的な打撃を与えた。さらにGigapolisのメガタワー（ZAMLT本社）を武力占拠し、ZAMLTの資産の30%を低階層コミュニティに移転するという画期的な行動に出た。この戦争はエル・フォルハウスのマーストリヒト革命（E150年）から続くコーポラトクラシー体制への抵抗運動の最高潮であり、最終的にZAMLTの崩壊を決定づけた。ギガポリス解放戦の勝利はE319年のJenによるValoria宮殿掌握という新たな権力秩序の始まりを告げ、さらにE335年からE370年のセリア黄金期への道を開いた。この戦争はE16文明圏における「コーポラトクラシーの終焉」と「市民の自由の回復」を象徴する歴史的転換点として位置づけられている。シャドウ・リベリオンの地下活動のノウハウとテクロサスの軍事的支援が勝利の鍵であり、のちにシルバー・ヴェノムの母体となったシャドウ・リベリオン過激派の分岐もこの時期に生じたとされる。",descriptionEn:"The war to overthrow ZAMLT instigated by the Shadow Rebellion led by Alpha Kane in E318. Alpha Kane executed a legendary hacking attack on the Omni-Engine, delivering a decisive blow to ZAMLT's economic foundation. Furthermore, he took the bold step of forcibly occupying Gigapolis's Megatower (ZAMLT headquarters) and transferring 30% of ZAMLT's assets to lower-level communities. This war represented the climax of the resistance movement against the corporatocracy system that had continued since the Maastricht Revolution of El Forhaus (E150), ultimately sealing ZAMLT's collapse. The victory of the Gigapolis Liberation War signaled the beginning of a new power order with Jen's seizure of the Valoria Palace in E319, paving the way for the Serian Golden Age from E335 to E370. This war is positioned as a historical turning point symbolizing \"the end of corporatocracy\" and \"the restoration of civic freedom\" in the E16 civilization sphere. The expertise of the Shadow Rebellion's underground activities and military support from Techrosus were the keys to victory, and it is believed that the split into the Shadow Rebellion faction, which later became the precursor of Silver Venom, also occurred during this period."},{id:"第五次繁栄期",name:"第五次繁栄期",nameEn:"Fifth Prosperity Period",category:"歴史",subCategory:"歴史・時代",description:"メルディア戦争（E275〜E288）終結後、ロンバルディア帝国の覇権確立によってもたらされた繁栄期。次元兵器の軍事技術が民間に波及し、ホライゾン・ゲート技術の基礎研究が本格化した時期。しかし帝国の覇権は他勢力の反発を招き、のちのZAMLT台頭とコーポラトクラシー間の抗争の遠因となった。",descriptionEn:"The prosperous period brought by the establishment of Lombardia Empire's hegemony after the end of the Merdia War (E275-E288). This was when military technology of dimensional weapons spread to civilian sectors and fundamental research on Horizon Gate technology began in earnest. However, the empire's hegemony provoked resistance from other factions, becoming a distant cause for ZAMLT's rise and the conflicts between corporatocracies."},{id:"hist-入植船団の到達",name:"入植船団の到達",nameEn:"Arrival of the Colonization Fleet",category:"歴史",subCategory:"歴史・時代",description:"地球暦AD3501年（東暦E0年）、ティムール・シャー率いる入植船団がシンフォニー・オブ・スターズに到達した歴史的出来事。地球からM104銀河への数百年にわたる星間航行の末に辿り着いた移民集団は、Ea16とEb16の連星の光が大気で屈折して放つ万華鏡のような夜空に感銘を受け、この惑星に「シンフォニー・オブ・スターズ（星の交響曲）」と名付けた。到達直後の入植者は約5万人で、フェンドラ人、アーキアン、ポロンポロの三大移民集団をはじめとする多様な民族・文化的背景を持っていた。到着初年度は厳しい環境適応期であり、放射線耐性のない入植者の約12%が最初の数年で亡くなったが、バイオエンジニアリング技術の急速な発展によって生存率は急速に改善された。この到達日は東暦元年として定義され、E16文明圏全歴史の起点となっている。",descriptionEn:'The historical event in Earth Calendar AD3501 (Eastern Calendar E0) when the colonization fleet led by Timur Shah reached the Symphony of Stars. After centuries of interstellar navigation from Earth to the M104 galaxy, the immigrant group arrived at a planet impressed by the kaleidoscopic night sky created by the refracted light of the Ea16 and Eb16 binary star system. They named this planet "Symphony of Stars (Symphony of the Stars)." The arriving settlers numbered about 50,000, possessing diverse ethnic and cultural backgrounds including the three major immigrant groups: the Fendrans, Arkians, and Polonporos. The first year after arrival was a harsh period of environmental adaptation, with approximately 12% of settlers lacking radiation resistance dying within the first few years. However, the rapid development of bioengineering technology quickly improved survival rates. This arrival date was defined as Eastern Calendar Year One, becoming the starting point for all history in the E16 civilization sphere.'},{id:"hist-初期入植者社会",name:"初期入植者社会",nameEn:"Early Settler Society",category:"歴史",subCategory:"歴史・時代",description:"E0年からE15年のバーズ帝国建国までの期間に形成されたシンフォニー・オブ・スターズにおける最初期の入植者社会。到達直後の入植者たちはE6年に西大陸にパラトンを建設し、ついで東大陸にも最初の居住区を拡大した。初期社会は地球の民主主義的伝統を基盤として議会制の自治組織を構築したが、過酷な惑星環境への適応を優先するため、次第に実力主義的な傾向を強めていった。ティムール・シャーの10次元ホラズム理論がE0年頃に構想され、入植者たちに新たな宇宙観を提供したが、その実験は後にE340年のスライム・ウーマン顕現という予期せぬ結果をもたらした。初期入植者社会の遺産はパラトンの城壁遺構や各地の開拓記念碑として現在も保存され、E16文明圏の文化的起原を示す重要な歴史資産となっている。",descriptionEn:"The earliest settler society formed on the Symphony of Stars between E0 and the founding of the V Empire in E15. Shortly after arrival, settlers built Paraton on the Western Continent in E6, then expanded to the first residential areas on the Eastern Continent. The early society, based on Earth's democratic traditions, constructed a parliamentary autonomous organization, but gradually strengthened pragmatic tendencies to prioritize adaptation to the harsh planetary environment. Timur Shah's 10-dimensional Horazm theory was conceived around E0, offering settlers a new cosmic view, though its experiments later led to the unexpected manifestation of the Slime Woman in E340. The legacy of the early settler society is preserved today in the Paraton wall ruins and various pioneer monuments, serving as important historical assets indicating the cultural origins of the E16 civilization sphere."},{id:"hist-ファランクスによる統一",name:"ファランクスによる統一戦争",nameEn:"Phalanx Unification Wars",category:"歴史",subCategory:"戦争・事件",description:"E12年からE15年にかけて軍閥ファランクスが展開した一連の武力統一戦争。初期入植者の各居住区が独立して発展した結果、資源分配と領土紛争をめぐる対立が深刻化し、各地で小規模な武力衝突が頻発していた。ファランクスはこれらの紛争を武力によって終結させ、シンフォニー・オブ・スターズ全域にわたる法秩序とインフラを構築した。統一戦争の過程でファランクスは軍事技術を大幅に進化させ、後のテクロサス系譜の原型となる戦術体系を確立した。E15年のバーズ帝国樹立の直接的な契機となったこの統一戦争は、E16文明圏における「統一と分岐」の循環の最初の例として歴史家に評価されている。",descriptionEn:'A series of unification wars waged by the military faction Phalanx from E12 to E15. As the various residential areas developed independently, conflicts over resource allocation and territorial disputes intensified, leading to frequent small-scale armed conflicts across the region. Phalanx ended these conflicts through force and established a legal order and infrastructure throughout the Symphony of Stars. During the unification wars, Phalanx significantly advanced military technology, establishing a tactical system that became the prototype for later Techrosus lineages. This unification war, which directly led to the establishment of the V Empire in E15, is evaluated by historians as the first example of the cycle of "unity and divergence" in the E16 civilization sphere.'},{id:"hist-帝国内乱と分裂",name:"帝国内乱と分裂",nameEn:"Imperial Civil War and Fragmentation",category:"歴史",subCategory:"戦争・事件",description:"E61年のファランクスの死後に始まったバーズ帝国の内乱と分裂の過程。ファランクスには明確な後継者がおらず、帝国の各省総督の間で後継者争いが勃発した。各地の独立運動と絡み合った15年に及ぶ内戦は帝国の分裂を決定的なものにし、複数の小規模国家群が並立する戦国時代への移行を促した。ファランクスが構築した通信ネットワークと航路標識は内乱期にも維持され、後のパクス・ロンバルディカ期の繁栄の基盤となったが、帝国の軍事伝統はテクロサス系譜として一部に受け継がれた。この分裂期に形成された地方分権的な政治構造は、のちのネオクラン同盟の理念に影響を与えたとされる。",descriptionEn:"The process of civil war and fragmentation that began after the death of Phalanx in E61. With no clear successor to Phalanx, a succession dispute erupted among the governors of the empire's various provinces. The 15-year civil war, intertwined with independence movements across the territories, decisively shattered the empire, prompting a transition to a Warring States era where multiple small nations coexisted. The communication networks and route beacons constructed by Phalanx were maintained during the turmoil, forming the foundation for the prosperity of the later Pax Lombardica period, though the empire's military tradition was partially carried on as the Teclosus lineage. This decentralized political structure formed during the fragmentation period is said to have influenced the later Neo-Cran Alliance ideology."},{id:"hist-第二次移民波の到達",name:"第二次移民波の到達",nameEn:"Second Wave of Immigration",category:"歴史",subCategory:"歴史・時代",description:"E70年からE85年にかけて地球から到達した第二波の移民集団。第一次入植船団が築いた通信インフラを利用した第二波は、約20万人の移民をシンフォニー・オブ・スターズにもたらした。新たな移民は農業技術者、医師、技術者など多様な専門職を擁し、入植地の自給能力を飛躍的に向上させた。しかし人口の急増は先住の第一次入植者との緊張を生み出し、E88年のロンバルディア戦争の遠因の一つとなった。第二次移民波のもたらした多様な文化的背景は、のちのE16文明圏の文化的多様性の基盤となり、フェルミ音楽の理論体系にも影響を与えたと言われている。",descriptionEn:"The second wave of immigrant groups that arrived from Earth between E70 and E85. Utilizing the communication infrastructure built by the first colonization fleet, the second wave brought approximately 200,000 immigrants to the Symphony of Stars. The new immigrants included diverse professionals such as agricultural technicians, physicians, and engineers, dramatically enhancing the self-sufficiency of the settlements. However, the rapid population growth created tensions with the original first-wave colonists, becoming one of the underlying causes of the Lombardia War in E88. The diverse cultural backgrounds brought by the second wave of immigrants are said to have formed the foundation of the cultural diversity of the later E16 civilization sphere and influenced the theoretical system of Fermi music."},{id:"hist-第一次星間航海",name:"第一次星間航海",nameEn:"First Interstellar Voyages",category:"歴史",subCategory:"歴史・時代",description:"E95年からE110年にかけて実施されたE16連星系内の最初の本格的な星間航海計画。バーズ帝国時代に構想された惑星間航行技術が、帝国分裂後も各地の技術者集団によって継承・発展され、Eros-7への最初の有人飛行がE97年に成功した。Eros-7からのリーチ・ドレインの発見は、入植者たちに新たな資源と危険の双方をもたらした。第一次星間航海の成果はのちの惑星ビブリオ建設（E120年頃）に継承され、E16連星系全域に居住圏を拡大する技術的基盤となった。この時期に確立された星間航行の航路標識と通信プロトコルは、現在でもE16連星系内の航行インフラの基礎として機能している。",descriptionEn:"The first comprehensive interstellar navigation plan within the E16 binary star system, implemented between E95 and E110. The interplanetary navigation technology conceived during the Barz Empire era was inherited and developed by various technician groups after the empire's fragmentation, leading to the first manned flight to Eros-7 in E97. The discovery of the Reach Drain from Eros-7 brought both new resources and dangers to the colonists. The achievements of the first interstellar voyage were later inherited in the construction of Planet Biblio (around E120), forming the technical foundation for expanding the inhabited zone throughout the entire E16 binary star system. The route beacons and communication protocols established during this period still function as the foundation of the navigation infrastructure within the E16 binary star system today."},{id:"hist-コーポラタムパブリカ設立",name:"コーポラタムパブリカの設立",nameEn:"Founding of Corporatumpublica",category:"歴史",subCategory:"歴史・時代",description:"E120年に西大陸の主要企業群が連合して設立した株式会社共和国。コーポラトクラシー体制の最も成功した例として、14兆ドルのGDPを誇る経済連合体を構築した。コーポラタムパブリカは利潤追求だけでなく、インフラ整備、教育、医療、宇宙探査などの公共サービスも担い、国家の役割を代替する画期的な統治モデルを確立した。この体制はE205年のパクス・ロンバルディカ期に最盛期を迎え、約70年にわたる長期安定をもたらした。コーポラタムパブリカの設立はE16文明圏において「企業が国家となる」という独特の政治形態の起点となり、のちに20万以上のコーポラトクラシーがGigapolis全域で競合する時代を招くことになる。",descriptionEn:'The Corporate Republic established in E120 through the alliance of major corporate groups on the Western Continent. As the most successful example of a corporatocracy, it constructed an economic federation boasting a GDP of 14 trillion dollars. The Corporatum Publica not only pursued profit but also undertook public services such as infrastructure development, education, healthcare, and space exploration, establishing an innovative governance model that replaced the functions of the state. This system reached its peak during the Pax Lombardica period in E205, bringing about long-term stability that lasted for about 70 years. The establishment of the Corporatum Publica marked the beginning of the unique political form of "the corporation becomes the state" within the E16 civilization sphere, leading to an era where over 200,000 corporatocracies would compete throughout Gigapolis.'},{id:"hist-テクノ宗教運動の台頭",name:"テクノ宗教運動の台頭",nameEn:"Rise of Techno-Religious Movement",category:"歴史",subCategory:"歴史・時代",description:"E80年頃から始まった次元極地平技術の発見を端緒とする宗教・哲学運動の台頭期。テミルタロンがこの運動の思想的指導者となり、次元極地平を「宇宙の意志」の顕現として神聖視する教義を構築した。テミルタロンはテンプル・オブ・ホライゾンを建設し、サイケデリック・コスモロジーを提唱して次元階梯パンディクトの構想の原型を提供した。テクノ宗教運動は技術啓蒙時代の合理主義に対する精神的なアンチテーゼとして広範な支持を集め、Troyaneを聖地とする信仰共同体を形成した。この運動の思想的遺産はAURALISの創設理念にも影響を与え、E16文明圏の精神文化に深い根を下ろしている。",descriptionEn:'The rise period of religious and philosophical movements beginning with the discovery of dimensional horizon technology around E80. Temirlaron became the ideological leader of this movement, constructing a doctrine that revered the dimensional horizon as the manifestation of "the will of the universe." Temirlaron built the Temple of Horizon and proposed psychedelic cosmology, providing the prototype for the concept of the dimensional ladder pandect. The techno-religious movement gathered broad support as a spiritual antithesis to the rationalism of the Enlightenment era, forming a faith community that regarded Troyane as a sacred land. The ideological legacy of this movement influenced the founding philosophy of AURALIS and took deep root in the spiritual culture of the E16 civilization sphere.'},{id:"hist-ギガポリス都市計画",name:"ギガポリス都市計画",nameEn:"Gigapolis Urban Planning",category:"歴史",subCategory:"歴史・時代",description:"E140年頃に西大陸のコーポラトクラシー連合によって開始されたパラトン周辺の大規模都市統合計画。技術啓蒙時代の人口爆発に対応するため、パラトンを核とした複数都市の統合が計画され、E150年のマーストリヒト革命までにメガロポリス化が進行した。都市計画はセントラル・タワーを中心とする放射状の区画構造を採用し、後にテスラ地区、大広場、テック・コリドーなどの多様な機能地区が形成された。ギガポリスの都市計画はシンフォニー・オブ・スターズの表面重力（0.92G）と自転周期（44時間4分）に最適化された独自の建築様式を生み出し、のちにE16連星系の政治・経済・文化の中心地となる基盤を築いた。",descriptionEn:"The large-scale urban integration plan around Paraton initiated by the corporatocracy alliance of the Western Continent around E140. To address the population explosion of the Enlightenment era, the integration of multiple cities centered around Paraton was planned, and by the time of the Maastricht Revolution in E150, it had progressed into a megalopolis. The urban planning adopted a radial district structure centered on the Central Tower, and later diverse functional districts such as the Tesla District, Grand Plaza, and Tech Corridor were formed. The Gigapolis urban planning produced a unique architectural style optimized for the surface gravity (0.92G) and rotation period (44 hours 4 minutes) of the Symphony of Stars, laying the foundation for what would later become the political, economic, and cultural center of the E16 binary star system."},{id:"hist-パクス・ロンバルディカの成立",name:"パクス・ロンバルディカの成立",nameEn:"Establishment of Pax Lombardica",category:"歴史",subCategory:"歴史・時代",description:"E205年に主要企業群が協調統治体制への移行を宣言し、E205年からE278年まで続いた「ロンバルディアの平和」時代の幕開け。ロンバルディア帝国がコーポラトクラシー間の協調体制の枠組みを提供し、約70年にわたる長期安定を実現した。この時期には惑星ビブリオのロレンツィオ国際大学が設立され、次元極地平理論の基礎研究が本格化した。しかし企業間の寡占化が進み、市民の政治参加権が制限される傾向が強まったことが、最終的にZAMLTによる強硬な経済覇権への移行を招く要因となった。パクス・ロンバルディカの繁栄はE16文明圏において「企業統治の黄金時代」として記憶され、その制度的遺産は現在のUECOの枠組みにも影響を与えている。",descriptionEn:'The beginning of the "Pax Lombardica" era, which lasted from E205 to E278, when major corporate groups declared a transition to a coordinated governance system. The Lombardia Empire provided the framework for a cooperative system among corporatocracies, achieving long-term stability for about 70 years. During this period, the Lorenzo International University was established on Planet Biblio, and fundamental research into dimensional horizon theory began in earnest. However, as oligopolization among corporations advanced and the political participation rights of citizens became increasingly restricted, these factors ultimately led to the transition to ZAMLT\'s aggressive economic hegemony. The prosperity of the Pax Lombardica is remembered in the E16 civilization sphere as the "golden age of corporate governance," and its institutional legacy continues to influence the framework of the current UECO.'},{id:"hist-惑星ビブリオの建設",name:"惑星ビブリオの建設",nameEn:"Construction of Planet Biblio",category:"歴史",subCategory:"歴史・時代",description:"E120年頃から始まった学術都市惑星ビブリオの建設計画。パクス・ロンバルディカ期（E205〜E278）に本格的な開発が進み、惑星全体が学術機関と研究施設によって構成される学術専用惑星として完成した。ビブリオの建設はE16文明圏における知識基盤の集約を目的とし、ロレンツィオ国際大学をはじめとする研究施設が次々と開設された。A-Registryの最高等級記録館もビブリオに置かれ、E16文明圏の全歴史文書と市民データのバックアップが保管されることになった。ビブリオの建設は「知識こそが文明の最高価値である」という理念の具現化であり、テクノ文化ルネサンス期にはペルセポネ計画の理論的基盤がこの惑星で構築された。",descriptionEn:'The construction plan for the academic planet Biblio, beginning around E120. Full-scale development progressed during the Pax Lombardica period (E205-278), and the planet was completed as an academic专用 planet composed entirely of academic institutions and research facilities. The construction of Biblio aimed to centralize the knowledge base of the E16 civilization sphere, and research facilities including the Lorenzo International University were established one after another. The highest-level archive of the A-Registry was also placed on Biblio, where all historical documents and citizen data of the E16 civilization sphere were backed up. The construction of Biblio was the embodiment of the philosophy that "knowledge is the highest value of civilization," and during the Techno-Cultural Renaissance period, the theoretical foundation for the Persephone Plan was constructed on this planet.'},{id:"hist-ダイアナの台頭",name:"ダイアナの台頭",nameEn:"Rise of Diana",category:"歴史",subCategory:"歴史・時代",description:"E260年からE280年にかけて活動した初代Wonder Woman、ダイアナの歴史的台頭期。AURALIS Protoの文化的恩恵をシンフォニー・オブ・スターズ全土にもたらした伝説的人物であり、その圧倒的な存在感と人々を鼓舞する力でEDU史上最も愛される英雄の一人として語り継がれる。ダイアナの台頭はパクス・ロンバルディカ期からコーポラトクラシー間抗争期への移行期において、文化と人道の価値を再確認する象徴的な出来事であった。彼女の影響力はのちのAURALIS Collective創設者たちに深い影響を与え、AURALISの創設理念の源流の一つとなった。ダイアナの没後も彼女の精神は「Wonder Woman」としての象徴的役割を通じて継承され、E16文明圏における英雄的理想の原型として機能し続けている。",descriptionEn:"The historical rise of the first Wonder Woman, Diana, who was active from E260 to E280. A legendary figure who brought the cultural benefits of AURALIS Proto to all of Symphony of Stars, she is remembered as one of the most beloved heroes in EDU history for her overwhelming presence and power to inspire people. Diana's ascent was a symbolic event that reaffirmed the values of culture and humanity during the transition from the Pax Lombardica era to the Corporateocracy Conflict era. Her influence deeply affected the founders of the later AURALIS Collective, becoming one of the sources of AURALIS's founding philosophy. Even after her death, her spirit continues to be inherited through the symbolic role of \"Wonder Woman,\" functioning as the prototype of heroic ideals in the E16 civilization sphere."},{id:"hist-AURALISの誕生",name:"AURALISの誕生",nameEn:"Birth of AURALIS",category:"歴史",subCategory:"歴史・時代",description:"E270年にKate ClaudiaとLily Steinerが出会い、表現を諦めない人々の集団としてAURALISの原型が形成された歴史的出来事。E290年の正式組織化に至るまでの20年間は、アンダーグラウンドの芸術サークルとして活動し、フェルミ音楽の最先端の表現を追求した。Kate Claudiaは「設計者」としてAURALISの構造とビジョンを構築し、Lily Steinerは「感情の炎」として舞台で性別の境界を歌う革命的な表現を確立した。二人の協働は「光と音を永遠にする」というAURALISの根本理念を生み出し、のちのセリア黄金期（E335〜E370年）にAURALISが文明全体の文化規範となる基盤を築いた。AURALISの誕生はE16文明圏における芸術運動の分岐点として、全ての文化史研究で言及される画期的出来事である。",descriptionEn:'The historical event in E270 when Kate Claudia and Lily Steiner met, forming the prototype of AURALIS as a group of people who never gave up on expression. For the 20 years leading up to its formal organization in E290, it operated as an underground art circle, pursuing cutting-edge expressions of Fermi music. Kate Claudia, as "The Architect," built AURALIS\'s structure and vision, while Lily Steiner, as "The Flame of Emotion," established revolutionary expressions that transcended gender boundaries through her singing on stage. Their collaboration produced AURALIS\'s fundamental philosophy of "making light and sound eternal," laying the foundation for AURALIS to become the cultural norm of the entire civilization during the later Celia Golden Age (E335-E370). The birth of AURALIS is a pivotal event in the art movement of the E16 civilization sphere, mentioned in all cultural history studies as a groundbreaking moment.'},{id:"hist-AURALIS正式設立",name:"AURALIS正式設立",nameEn:"Official Establishment of AURALIS",category:"歴史",subCategory:"歴史・時代",description:"E290年にKate ClaudiaとLily Steinerがアンダーグラウンドの芸術サークルから正式な芸術組織としてAURALISを設立した出来事。正式設立に伴い、メンバーの拡大と組織体制の整備が進み、フェルミ音楽の公演活動と次元極地平技術を応用した総合芸術の創作が本格化した。AURALISの設立はシンフォニー・オブ・スターズの文化 scene に革命をもたらし、従来の娯楽としての芸術から文明規範としての芸術への転換を促した。設立時のメンバーの中には、のちにAURALIS Collectiveの第二世代で活躍するメンバーの先駆者も含まれていた。AURALISの正式設立はE16文明圏の芸術史において「文化の覚醒」として評価され、フェルミ音楽の黄金期への入口となった。",descriptionEn:"The event in E290 when Kate Claudia and Lily Steiner established AURALIS as a formal art organization from an underground art circle. With its formal establishment, membership expanded and organizational systems were improved, and full-scale activities began in Fermi music performances and the creation of comprehensive arts using dimensional horizon technology. AURALIS's establishment brought a revolution to the cultural scene of Symphony of Stars, promoting a transformation from art as entertainment to art as a civilizational norm. Among the founding members were pioneers who would later become prominent in the second generation of the AURALIS Collective. AURALIS's formal establishment is evaluated in the art history of the E16 civilization sphere as the \"Cultural Awakening,\" becoming the gateway to the golden age of Fermi music."},{id:"hist-ZAMLT設立",name:"ZAMLT設立と5企業覇権",nameEn:"Establishment of ZAMLT",category:"歴史",subCategory:"歴史・時代",description:"E301年にZAMLT（5つの超巨大企業の連合体）がGigapolisに本社を置き、E16連星系の経済覇権を掌握した歴史的転換点。コーポラタムパブリカの末期に台頭した5企業が合流してZAMLTを設立し、20万以上のコーポラトクラシー間の覇権争いを5企業への集約によって終結させた。ZAMLTはオムニバス・エンジンと呼ばれる独自の金融システムを構築し、E16連星系の経済活動の大部分を統制した。次元極地平技術の軍事転用と兵器生産も進め、シルバープラントや次元の塔などの巨大施設を建造した。ZAMLTの覇権は市民の政治参加権を制限し、A-Registryの階級制度を社会固定化装置として悪用する側面も持ち、のちのアルファ・ケインによるギガポリス解放戦（E318年）の直接的な要因となった。",descriptionEn:"The historical turning point in E301 when ZAMLT (a coalition of five mega-corporations) established its headquarters in Gigapolis and seized economic hegemony of the E16 star system. The five corporations that rose during the late Corporatum Publica era merged to form ZAMLT, ending over 200,000 power struggles among Corporateocracies by consolidating power into five corporations. ZAMLT built its own financial system called the OmniBus Engine, controlling most of the economic activities in the E16 star system. It also advanced the military application of dimensional horizon technology and weapon production, constructing massive facilities like Silver Plants and Dimensional Towers. ZAMLT's hegemony restricted citizens' political participation rights and exploited the A-Registry class system as a social stabilization device, becoming a direct cause of the later Gigapolis Liberation War (E318) led by Alpha Cain."},{id:"hist-アルファ・ケインの覚醒",name:"アルファ・ケインの覚醒",nameEn:"Awakening of Alpha Kane",category:"歴史",subCategory:"戦争・事件",description:"E316年からE318年にかけて、テスラ地区で育ったアルファ・ケインがスティル・アレーナで優勝し、伴共役の覚醒という奇跡的な現象を起こした一連の歴史的事件。アルファ・ケインはスティル・アレーナでその圧倒的な戦闘力を証明し、ZAMLT支配下の低階層市民に希望の象徴となった。E318年にはシャドウ・リベリオンを組織し、テクロサスの戦士たちと連携してギガポリス解放戦を決起した。伴共役の覚醒はZAMLTの次元エネルギー技術の原理を覆す未知の現象であり、この覚醒を持ってケインはZAMLTのオムニバス・エンジンへの伝説的なハッキング攻撃を実行し、Gigapolisのメガタワーを武力占拠した。ケインの覚醒と解放戦はE16文明圏における「コーポラトクラシーの終焉」の象徴として歴史に刻まれている。",descriptionEn:"A series of historical events from E316 to E318 where Alpha Cain, raised in the Tesla District, won the Still Arena and triggered the miraculous phenomenon of awakening his conjugate pair. Alpha Cain proved his overwhelming combat prowess in the Still Arena, becoming a symbol of hope for citizens in the lower classes under ZAMLT's rule. In E318, he organized the Shadow Rebellion and launched the Gigapolis Liberation War in coordination with the warriors of Techlos. The awakening of his conjugate pair was an unknown phenomenon that overturned the principles of ZAMLT's dimensional energy technology. With this awakening, Cain executed a legendary hacking attack on ZAMLT's OmniBus Engine and forcibly occupied the Megatower of Gigapolis. Cain's awakening and liberation war are etched in history as the symbol of \"the fall of Corporateocracy\" in the E16 civilization sphere."},{id:"hist-シルバープラント攻略戦",name:"シルバープラント攻略戦",nameEn:"Silver Plant Assault",category:"歴史",subCategory:"戦争・事件",description:"ギガポリス解放戦（E318年）の中で、アルファ・ケインとクロノ・ヴァーレント率いるテクロサス部隊がZAMLTの重要施設シルバープラントへの浸透作戦を実施した戦闘。シルバープラント攻略戦の最中で、リンダがプロトコルXのエネルギーコアを安定化させるために自らを犠牲にするという悲劇的な決断を下した。彼女の犠牲はZAMLTに対する抵抗運動の転換点となり、アルファ・ケインの決意を固めさせた。シルバープラントの名はプラントから放出される銀色の次元エネルギー光輝に由来し、ZAMLT崩壊後は「シルバー・ヴェノム」の名称の由来となったという説がある。この攻略戦はE16文明圏の戦争史において、個人の自己犠牲が歴史的転換をもたらした代表的な例として語り継がれている。",descriptionEn:'The battle during the Gigapolis Liberation War (E318) where the Techlos forces led by Alpha Cain and Chrono Valente conducted an infiltration operation on ZAMLT\'s important facility, the Silver Plant. During the Silver Plant assault, Linda made the tragic decision to sacrifice herself to stabilize the energy core of Protocol X. Her sacrifice became a turning point in the resistance movement against ZAMLT and strengthened Alpha Cain\'s resolve. The name "Silver Plant" derives from the silver dimensional energy光辉 emitted from the plant, and after ZAMLT\'s collapse, it is said to have become the origin of the name "Silver Venom." This assault is passed down in the war history of the E16 civilization sphere as a representative example of how individual self-sacrifice brought about a historical turning point.'},{id:"hist-セリアによるSelinopolis宣言",name:"セリアによるSelinopolis宣言",nameEn:"Celia's Selinopolis Declaration",category:"歴史",subCategory:"歴史・時代",description:"E335年にセリア・ドミニクスがZAMLTを打倒した後、GigapolisをSelinopolisと改名し、超巨大企業Phovosを設立して次元エネルギー技術の商業化を宣言した歴史的転換点。セリアはGDP25兆ドル規模の経済基盤を構築し、「文化と経済の融合」という独自の統治理念を実現した。フェルミ音楽の演奏やAURALISの芸術活動がnトークンで評価される画期的な仕組みを導入し、文化的貢献が直接経済的報酬に結びつく社会制度を確立した。さらに女性主導社会の原型も構築し、主要な意思決定機関に女性が多数を占める体制を実現した。セリアのSelinopolis宣言はE335年からE370年のセリア黄金期の幕開けとなり、E16文明圏の文化的アイデンティティの基盤を形成した。",descriptionEn:"The historical turning point in E335 when Celia Dominicus overthrew ZAMLT, renamed Gigapolis to Selinopolis, and established the mega-corporation Phovos, declaring the commercialization of dimensional energy technology. Celia built an economic foundation with a GDP of 25 trillion dollars and realized a unique governance philosophy of \"fusion of culture and economy.\" She introduced a groundbreaking system where Fermi music performances and AURALIS's artistic activities were evaluated in n-tokens, establishing a social system where cultural contributions were directly linked to economic rewards. She also built the prototype of a female-led society, achieving a system where women formed the majority in key decision-making bodies. Celia's Selinopolis Declaration marked the beginning of the Celia Golden Age from E335 to E370, forming the foundation of the cultural identity of the E16 civilization sphere."},{id:"hist-フェルミ音楽の最盛期",name:"フェルミ音楽の最盛期",nameEn:"Peak of Fermi Music",category:"歴史",subCategory:"歴史・時代",description:"E335年からE370年のセリア黄金期において、フェルミ音楽がE16文明圏の基盤文化として最盛期を迎えた時代。次元極地平の共振現象を音響に応用したフェルミ音楽は、聴覚だけでなく感情に直接働きかける革新的な音楽体系として文明全体に普及した。Poitiersに研究機関と芸術院が集積し、フェルミ音楽の理論体系化が進められた。AURALIS第一世代はフェルミ音楽を核とした総合芸術運動を展開し、「光と音を永遠にする」という理念のもとで文明全体の文化規範を形成した。フェルミ音楽の最盛期はE16文明圏における芸術の黄金時代であり、現在でも復興祭が定期的に開催され、その遺産はテクノ文化ルネサンス期に次元技術と融合した新たな音楽表現として継承されている。",descriptionEn:'The era during the Celia Golden Age from E335 to E370 when Fermi music reached its peak as the foundational culture of the E16 civilization sphere. Fermi music, which applied the resonance phenomena of the dimensional horizon to sound, spread throughout civilization as an innovative musical system that directly appealed to emotions, not just hearing. Research institutions and art academies accumulated in Poitiers, advancing the theoretical systematization of Fermi music. The first generation of AURALIS launched a comprehensive art movement centered on Fermi music, forming the cultural norm of the entire civilization under the philosophy of "making light and sound eternal." The golden age of Fermi music was the artistic golden age of the E16 civilization sphere, and today revival festivals are still held regularly, its legacy being inherited as new musical expressions fused with dimensional technology during the Techno-Cultural Renaissance period.'},{id:"hist-アポロンとの同盟拒絶と開戦",name:"アポロンとの同盟拒絶と開戦",nameEn:"Rejection of Apollon Alliance and Outbreak of War",category:"歴史",subCategory:"戦争・事件",description:"E370年にアポロン文明圏のリーダー・ロナン・アーサがセリア・ドミニクスに同盟を提案したが拒絶され、全面戦争が勃発した一連の事件。ロナン・アーサはアポロン文明圏の拡大を目的として、セリア率いるSelinopolis（ドミニオン）との軍事同盟を求めたが、セリアは独自路線を貫くために同盟を拒絶した。この拒絶をきっかけにアポロンは宣戦布告し、E375年のケンタウロスレーザー発射、E378年のG4ファントムパルス応戦を経て、E385年にセリアのヴェノム艦隊がアポロン・セントラリスを攻略・爆砕して戦争は終結した。この大戦は両文明に壊滅的損害をもたらし、宇宙秩序を大きく変容させた。セリアの同盟拒絶の理由は現在も歴史家の間で議論の的であり、独自の外交判断であったか、あるいは内在的な危機感に基づくものであったかの見解が分かれている。",descriptionEn:"The series of events beginning in E370 when Apollo civilization's leader Ronan Arth proposed an alliance to Celia Dominicus, which was rejected, sparking total war. Ronan Arth, seeking to expand the Apollo civilization sphere, requested a military alliance with Selinopolis (Dominion) led by Celia, but Celia rejected the alliance to maintain her independent course. This rejection prompted Apollo to declare war, and after the E375 Centaurus Laser launch and the E378 G4 Phantom Pulse counterattack, the war concluded in E385 when Celia's Venom fleet conquered and shattered Apollo Centralis. This great war brought catastrophic damage to both civilizations and drastically altered the cosmic order. The reason for Celia's rejection of the alliance remains a topic of debate among historians, with divided views on whether it was based on independent diplomatic judgment or an intrinsic sense of crisis."},{id:"hist-G4ファントムパルスと勝利",name:"G4ファントムパルスと大戦勝利",nameEn:"G4 Phantom Pulse and War Victory",category:"歴史",subCategory:"戦争・事件",description:"E378年にセリア・ドミニクスがアポロンのケンタウロスレーザーに対抗して投入したG4ファントムパルスと、それに続くE385年のアポロン・セントラリス攻略による大戦の勝利。G4ファントムパルスは次元極地平技術の軍事応用の最高到達点とされ、アポロンの軍事力を圧倒した。E385年にはセリアのヴェノム艦隊がアポロン・セントラリスを攻略・爆砕し、アポロン文明圏に壊滅的な打撃を与えた。しかし勝利の代償は大きく、SelinopolisのGDPは23兆ドルに激減した。さらにこの大戦の疲弊はのちのE400年にエヴァトロンによるGigapolis占領を許す結果となった。大戦の勝利はセリアの軍事的天才としての評価を確立したが、同時に戦後の疲弊が文明全体に深刻な影響を及ぼすことになった。",descriptionEn:"The G4 Phantom Pulse deployed by Celia Dominicus in E378 to counter Apollo's Centaurus Laser, followed by the victory in the great war through the conquest of Apollo Centralis in E385. The G4 Phantom Pulse is considered the pinnacle of military application of dimensional horizon technology, overwhelming Apollo's military might. In E385, Celia's Venom fleet conquered and shattered Apollo Centralis, delivering a devastating blow to the Apollo civilization sphere. However, the price of victory was immense, with Selinopolis' GDP plummeting to 23 trillion dollars. Furthermore, the exhaustion from this great war later resulted in the E400 occupation of Gigapolis by Evatron. While the victory established Celia's reputation as a military genius, the post-war exhaustion had a profound impact on the entire civilization."},{id:"hist-エヴァトロンによるGigapolis占領",name:"エヴァトロンによるGigapolis占領",nameEn:"Evatron Occupation of Gigapolis",category:"歴史",subCategory:"戦争・事件",description:"E400年にエヴァトロンがアポロン・Dominion大戦後の疲弊に乗じてGigapolisを武力占領し、セリア・ドミニクスを追放して独裁的支配を開始した歴史的事件。エヴァトロンの初代リーダー・グリム・ダルゴスはGigapolisを「エヴァポリス」と強制改名し、市民の基本的人権を大幅に制限する独裁的法体系を施行した。AURALISを弾圧し、芸術・文化活動を禁止したほか、極秘部隊Σ-Unitを設立して精神操作研究と生体改造実験を行った。この占領は75年間にわたり続いたが、テリアン反乱（E400〜E470年）やシャドウ・ユニオンの抵抗活動によって支配体制は徐々に侵食され、最終的にE475年のエヴァトロン崩壊へと至った。エヴァトロンによる占領はE16文明圏における「暗黒の時代」として記憶され、のちのネオクラン同盟の設立理念に決定的な影響を与えた。",descriptionEn:'The historical event in E400 when Evatron, taking advantage of the exhaustion following the Apollo-Dominion War, forcibly occupied Gigapolis, exiled Celia Dominicus, and began dictatorial rule. Evatron\'s first leader, Grim Dargos, forcibly renamed Gigapolis to "Evapolis" and implemented a dictatorial legal system that severely restricted citizens\' basic human rights. He suppressed AURALIS, banned artistic and cultural activities, and established a secret unit, Σ-Unit, to conduct mind manipulation research and biological modification experiments. This occupation lasted for 75 years, but the regime was gradually eroded by the Terian Rebellion (E400-E470) and resistance activities by the Shadow Union, ultimately leading to Evatron\'s collapse in E475. The Evatron occupation is remembered as the "Dark Age" in the E16 civilization sphere and had a decisive influence on the founding principles of the later Neo-Clan Alliance.'},{id:"hist-AURALIS弾圧と逮捕",name:"AURALIS弾圧とメンバー逮捕",nameEn:"AURALIS Suppression and Arrests",category:"歴史",subCategory:"戦争・事件",description:"E400年のエヴァトロンによるGigapolis占領に伴い、AURALISが「秩序を乱す反社会的組織」として弾圧され、主要メンバーが逮捕された事件。エヴァトロンは芸術・文化活動を法的に禁止し、Kate Claudia、Lily SteinerをはじめとするAURALISの指導的メンバーが相次いで拘束された。Lily Steinerは最後のステージで「AURALISは消えない。灰から、また燃える」と言い残して逮捕されたが、その後の消息は不明のままである。この弾圧はE16文明圏の文化史において最も深刻な損失の一つとされ、セリア黄金期に花開いた芸術運動が強制的に中断させられた。しかしAURALISの理念は地下活動を通じて秘密裏に継承され、のちのE522年のAURALIS Collective第二世代の設立へと繋がっていった。",descriptionEn:"The event in E400 when AURALIS was suppressed as a \"socially disruptive organization\" following Evatron's occupation of Gigapolis, leading to the arrest of its key members. Evatron legally prohibited artistic and cultural activities, and leading members of AURALIS, including Kate Claudia and Lily Steiner, were successively detained. In her final performance, Lily Steiner declared, \"AURALIS will not disappear. From the ashes, it will burn again\" before being arrested, but her subsequent whereabouts remain unknown. This suppression is considered one of the most severe losses in the cultural history of the E16 civilization sphere, forcibly interrupting the artistic movement that had flourished during Celia's golden age. However, AURALIS's ideals were secretly preserved through underground activities, eventually leading to the establishment of the AURALIS Collective's second generation in E522."},{id:"hist-Σ-Unitの設立",name:"Σ-Unit (Sigma Unit)",nameEn:"Establishment of Sigma Unit",category:"歴史",subCategory:"戦争・事件",description:"E410年にエヴァトロンが法的灰色地帯で設立した極秘部隊。エヴァトロンの初代リーダー・グリム・ダルゴスが制定した特別法によって正当化されたΣ-Unitは、精神操作研究と生体改造実験を任務としていた。市民の監視、反体制運動の摘発、テリアン反乱軍への潜入工作などを行い、エヴァトロン支配の恐怖の象徴として市民に恐れられた。Σ-Unitの活動内容の一部はE475年のエヴァトロン崩壊後に発覚し、その非人道的な実態は国際的な非難を浴びた。Σ-Unitの設立はエヴァトロン支配の暗黒面を象徴する出来事であり、のちの人権回復と法改革の重要な根拠となった。",descriptionEn:"The secret unit established by Evatron in E410 through legal loopholes. The Σ-Unit, justified by special laws enacted by Evatron's first leader Grim Dargos, was tasked with mind manipulation research and biological modification experiments. It conducted surveillance of citizens, suppression of anti-regime movements, and infiltration operations against the Terian Rebellion forces, becoming a symbol of terror under Evatron rule that citizens feared. Parts of the Σ-Unit's activities were revealed after Evatron's collapse in E475, and its inhumane practices drew international condemnation. The establishment of the Σ-Unit symbolized the dark side of Evatron's rule and later became a crucial basis for human rights restoration and legal reforms."},{id:"hist-テリアン処刑",name:"テリアン処刑",nameEn:"Execution of Elios Wald",category:"歴史",subCategory:"戦争・事件",description:"E470年にエヴァトロン軍が捕縛したテリアン反乱軍の指導者エリオス・ウォルドを公開処刑した歴史的事件。エリオスはE400年から70年間にわたり、エヴァトロンの支配に対する武装抵抗を組織し、農民や市民を結集してゲリラ戦を展開してきた悲劇の英雄であった。彼の処刑はテリアン反乱軍を一時衰退させたが、残存勢力は地下活動を継続し、のちのE475年のエヴァトロン崩壊の決定的な要因となった。エリオスの処刑は市民全体に深い衝撃と怒りをもたらし、テクロサス東方支隊のクレセント大地方常駐（E470年）を促す契機となった。エリオスの遺志は「A籍制度の廃止と市民の自由回復」というスローガンとして抵抗運動に受け継がれ、現在でもE470年は「自由の殉教者を偲ぶ日」として記念されている。",descriptionEn:"The historical event in E470 when Evatron's military publicly executed Erios Wald, the captured leader of the Terian Rebellion forces. Erios was a tragic hero who had organized armed resistance against Evatron's rule for 70 years since E400, rallying peasants and citizens in guerrilla warfare. His execution temporarily weakened the Terian Rebellion, but the remaining forces continued underground activities, becoming a decisive factor in Evatron's collapse in E475. Erios's execution brought deep shock and anger to the entire citizenry and prompted the deployment of the Crescent Grand Prefecture's Teclosas Eastern Detachment (E470). Erios's legacy was carried forward in the resistance movement through the slogan \"Abolition of the A-Registry and restoration of citizen freedom,\" and E470 is still commemorated annually as \"Day of Remembrance for the Martyrs of Freedom.\""},{id:"hist-エヴァトロン崩壊",name:"エヴァトロン崩壊",nameEn:"Fall of Evatron",category:"歴史",subCategory:"戦争・事件",description:"E475年に75年間続いたエヴァトロンの独裁支配が崩壊し、Gigapolisが市民の手に取り戻された歴史的転換点。テリアン反乱軍の残存勢力、シャドウ・ユニオンの地下活動、テクロサス東方支隊の軍事的圧力が相乗効果をもたらし、エヴァトロンの支配体制は内部から崩壊していった。崩壊後、市民の総意によりGigapolisの名称が即座に復帰し、エヴァポリスという強制的な改名は撤回された。この崩壊はE16文明圏における「自由の回復」の象徴として現在でも毎年記念日が祝われている。エヴァトロン崩壊はポスト・エヴァトロン秩序の始まりを告げ、ネオクラン同盟主導で民主的な法改革が実施され、のちのテクノ文化ルネサンス（E475〜E500年）への道を開いた。",descriptionEn:"The historical turning point in E475 when Evatron's 75-year dictatorial rule collapsed and Gigapolis was reclaimed by its citizens. The combined efforts of remaining Terian Rebellion forces, Shadow Union resistance activities, and military pressure from the Teclosas Eastern Detachment caused Evatron's regime to collapse from within. After the collapse, the collective will of the citizens immediately restored the name Gigapolis, reversing the forced renaming to Evapolis. This collapse is still commemorated annually as a symbol of \"Liberation\" in the E16 civilization sphere. Evatron's collapse marked the beginning of the post-Evatron order, under which the Neo-Clan Alliance led democratic legal reforms, paving the way for the later Techno-Cultural Renaissance (E475-E500)."},{id:"hist-ネオクラン同盟の台頭",name:"ネオクラン同盟の台頭",nameEn:"Rise of Neo-Clan Alliance",category:"歴史",subCategory:"歴史・時代",description:"E325年に設立され、エヴァトロン崩壊後（E475年〜）に本格的に台頭したネオクラン同盟の政治的影響力の拡大期。ネオクラン同盟はクワンナラ革命（E108〜E114年）の分権化とクランの伝統的権利の復権という理念を継承し、分散統治と市民参加型政治を基本原理としていた。エヴァトロン崩壊後、同盟は法改革、A-Registryの階級緩和、教育の機会均等化など幅広い政策を推進し、ポスト・エヴァトロン秩序の政治的基盤を構築した。ネオクラン同盟の理念はファティマ連邦の分散型統治モデルと共鳴し、クレセント地方にも影響を与えた。UECOの星間経済協同組合の設立にも主導的な役割を果たし、E16文明圏の民主化と安定化に不可欠な存在として現在も活動を続けている。",descriptionEn:"The period of expanding political influence of the Neo-Clan Alliance, founded in E325 and rising to prominence after Evatron's collapse (E475-). The Neo-Clan Alliance inherited the ideals of the Quannara Revolution (E108-E114) regarding decentralization and restoration of traditional clan rights, with decentralized governance and citizen-participatory politics as its basic principles. After Evatron's collapse, the alliance implemented wide-ranging policies including legal reforms, relaxation of A-Registry class restrictions, and equalization of educational opportunities, constructing the political foundation of the post-Evatron order. The Neo-Clan Alliance's ideals resonated with the Fatima Federation's decentralized governance model and also influenced the Crescent region. It played a leading role in the establishment of UECO's Interspace Economic Cooperative, continuing its activities to this day as an indispensable presence for the democratization and stabilization of the E16 civilization sphere."},{id:"hist-スライム危機の収束",name:"スライム危機の収束",nameEn:"Resolution of Slime Crisis",category:"歴史",subCategory:"歴史・時代",description:"E380年からE400年まで約20年間続いたスライム危機の収束過程。変異したリーチ・ドレインによる大規模災害はEros-7からシンフォニー・オブ・スターズ全域に波及し、壊滅的な被害をもたらしたが、Eros-7のマトリカル社会が独自に開発した生物学的封じ込め技術が決定的な役割を果たした。シンフォニー・オブ・スターズでは、アヤカ・リンがアンダーグリッドでの制圧作戦を先陣を切って指揮し、レイラ・ヴィレル・ノヴァもオアシス・ハウスを拠点にスライム討伐で英雄的活躍を見せた。収束後、リーチ・ドレイン対策医療はSUDOMの主要産業として発展し、この技術は医療や環境修復分野で広く応用されることになった。スライム危機の教訓はテクノ文化ルネサンス期の「技術の民主化」と「生態系との調和」という理念に強く反映され、環境保護法の整備を促す決定的な要因となった。",descriptionEn:'The convergence process of the Slime Crisis, which lasted approximately 20 years from E380 to E400. The large-scale disasters caused by mutated Reach Drains spread from Eros-7 throughout the Symphony of Stars, bringing catastrophic damage, but the biological containment technology independently developed by the Matrical society of Eros-7 played a decisive role. In the Symphony of Stars, Ayaka Rin led the suppression operation in the Undergrid, and Leila Virel Nova also performed heroic feats in Slime extermination operations based at Oasis House. After the convergence, Reach Drain countermeasure medicine developed into a major industry of SUDOM, and this technology was widely applied in medical and environmental restoration fields. The lessons of the Slime Crisis were strongly reflected in the "democratization of technology" and "harmony with the ecosystem" ideals of the Techno-Cultural Renaissance period, becoming a decisive factor in promoting the development of environmental protection laws.'},{id:"hist-テクノ文化ルネサンスの始まり",name:"テクノ文化ルネサンスの始まり",nameEn:"Beginning of Techno-Cultural Renaissance",category:"歴史",subCategory:"歴史・時代",description:"E475年にエヴァトロン崩壊後の民主化と自由化を背景に始まった文化・技術の飛躍期。次元極地平技術が軍事・企業エリートから一般市民に開放され、ホライゾン・ゲートを通じた惑星間移動が日常化した。これによりE16連星系内の各地域間交流が爆発的に増加し、異なる植民地の文化が融合する新しい芸術・音楽・哲学が花開いた。テクノ文化ルネサンスはAURALIS第二世代の設立（E522年）を準備する文化的土壌となり、フェルミ音楽の現代的再解釈やOffenbach種との協創芸術などが生まれた。また、ペルセポネ計画の初期構想もこの時期に生み出され、次元階梯パンディクト理論の基礎研究が惑星ビブリオで開始された。このルネサンスはE16文明圏に「技術と文化の融合」という新たなパラダイムをもたらした。",descriptionEn:'A period of cultural and technological leap that began against the backdrop of democratization and liberalization after the collapse of Evatron in E475. Dimensional horizon technology was opened from military and corporate elites to general citizens, and interplanetary travel through Horizon Gates became commonplace. This led to an explosive increase in exchanges between various regions within the E16 star system, and new arts, music, and philosophy that fused cultures from different colonies blossomed. The Techno-Cultural Renaissance became the cultural soil that prepared for the establishment of AURALIS\'s second generation (E522), giving birth to modern reinterpretations of Fermi music and collaborative art with the Offenbach species. Additionally, the initial concept of the Persephone Plan was born during this period, and the basic research on dimensional ladder Pandict theory began on the planet Biblio. This Renaissance brought a new paradigm of "fusion of technology and culture" to the E16 civilization sphere.'},{id:"hist-V7設立",name:"V7（Vital Seven）の設立",nameEn:"Founding of V7 (Vital Seven)",category:"歴史",subCategory:"戦争・事件",description:"E515年にフィオナの主導でクレセント大地方の7カ国が結成した軍事同盟V7（Vital Seven）の設立。ブルーローズ、SSレンジ、アイアン・シンジケート、SUDOM、クロセヴィア、ミエルテンガに加えてその他の加盟国から構成され、クレセント地方における集団防衛と技術開発の枠組みを構築した。V7の設立はクレセント地方における勢力均衡を大きく変化させ、フィオナの外交手腕によって次元極地平技術の民用化と文化的開放性を推進する同盟として機能した。しかしE520年のトリニティ・アライアンス結成に対抗する軍事同盟としての側面も強く、クレセント地方の二大陣営対立構造の始まりとなった。V7の設立はE515年以降のクレセント政治情勢の基本構造を決定づけ、のちのフィオナの裏切り発覚（E523〜E525年）によって大きな試練を受けることになる。",descriptionEn:"The establishment of V7 (Vital Seven), a military alliance formed in E515 under Fiona's leadership by seven countries of the Crescent region. Composed of Blue Rose, SS Range, Iron Syndicate, SUDOM, Crossavia, Mieltenga, and other member countries, it established a framework for collective defense and technological development in the Crescent region. The establishment of V7 greatly changed the balance of power in the Crescent region and functioned as an alliance promoting the civilian use of dimensional horizon technology and cultural openness through Fiona's diplomatic skills. However, it also strongly served as a military alliance to counter the Trinity Alliance formed in E520, marking the beginning of a two-camp confrontation structure in the Crescent region. The establishment of V7 determined the basic structure of the Crescent political situation after E515 and would later face a major test due to the exposure of Fiona's betrayal (E523-E525)."},{id:"hist-トリニティ・アライアンス結成",name:"トリニティ・アライアンス結成",nameEn:"Formation of Trinity Alliance",category:"歴史",subCategory:"戦争・事件",description:"E520年にヴァーミリオン、ミエルテンガ、ボグダス・ジャベリンを中心に結成されたクレセント地方の軍事同盟。トリニティ・アライアンスはV7に対抗する勢力として機能し、クレセント地方における二大陣営対立構造の完成を告げた。アイリスがシルバー・ヴェノムからの再救出（E519年）後、トリニティ・アライアンスの指導者として台頭し、セバスチャン・ヴァレリウス率いるボグダス・ジャベリンが軍事的支柱を担った。トリニティ・アライアンスは旧来のクレセント秩序の維持と軍事的安定を主な目的としており、V7の技術革新路線とは異なる安全保障観点を持つ。しかしフィオナの裏切り（E523〜E525年）によって内部から崩壊の危機に直面し、クレセント地方の政治情勢は混迷の度合いを深めている。",descriptionEn:"A military alliance of the Crescent region formed in E520, centered on Vermillion, Mieltenga, and Bogdas Javelin. The Trinity Alliance functioned as a force against V7, announcing the completion of a two-camp confrontation structure in the Crescent region. After rescuing Iris from Silver Venom again in E519, she rose as the leader of the Trinity Alliance, and Bogdas Javelin led by Sebastian Valerius served as the military pillar. The Trinity Alliance's main purpose was to maintain the old Crescent order and military stability, holding a different security perspective from V7's technological innovation path. However, it faced a crisis of collapse from within due to Fiona's betrayal (E523-E525), and the political situation in the Crescent region has deepened in confusion."},{id:"hist-銀河系コンソーシアム設立",name:"銀河系コンソーシアム設立",nameEn:"Establishment of Galactic Consortium",category:"歴史",subCategory:"歴史・時代",description:"E520年に設立された銀河系規模の協力機構で、E16文明圏と他宇宙文明圏との対話と協力を目的としている。銀河系コンソーシアムはグランベル（経済1位）、エレシオン（医療2位）、ティエリア（軍事3位）、ファルージャ（文化4位）、ディオクレニス（探査5位）の五大文明圏を核に構成され、ヘゲモニー・パラドックスの回避と宇宙規模の秩序構築を掲げている。コンソーシアムの設立はE16文明圏が銀河規模の国際舞台に進出する画期的な出来事であり、E528年の第一回宇宙連合会合の開催へと繋がった。コンソーシアムの下で標準宇宙暦の制定や宇宙文明圏間の通商ルートの整備が進められており、E16文明圏の外交・経済・安全保障に新たな枠組みを提供している。",descriptionEn:"A galaxy-scale cooperative organization established in E520, aiming for dialogue and cooperation between the E16 civilization sphere and other cosmic civilization spheres. The Galactic Consortium is composed around five major civilization spheres: Granbel (economic #1), Elesion (medical #2), Tiera (military #3), Faluja (cultural #4), and Dioclenis (exploration #5), advocating for the avoidance of the Hegemony Paradox and the construction of a cosmic-scale order. The establishment of the Consortium was a groundbreaking event for the E16 civilization sphere to advance onto the galaxy-scale international stage, leading to the holding of the first United Cosmic Assembly in E528. Under the Consortium, the establishment of the standard cosmic calendar and the development of trade routes between cosmic civilization spheres are being promoted, providing a new framework for the diplomacy, economy, and security of the E16 civilization sphere."},{id:"hist-第一回宇宙連合会合",name:"第一回宇宙連合会合",nameEn:"First Universal Federation Summit",category:"歴史",subCategory:"歴史・時代",description:"E528年にグランベルの首都オルダシティで開催された、銀河系コンソーシアム主導の宇宙規模の外交会合。グランベル大統領アルゼン・カーリーンの「共存繁栄」演説をはじめ、ティエリア総帥グレイモンド・ハウザーの「軍事力の必要性」、エレシオン女王リアナ・ソリスの「平和・技術共有」、ファルージャ評議会代表マドリス・カーネルの「文化の力」、ディオクレニス科学宰相ネイサン・コリンドの「ヘゲモニー・パラドックス回避・共同探査」という五つの主要演説が行われた。この会合は宇宙秩序の構築に向けた本格的な対話の始まりを示し、E16文明圏と他宇宙文明圏の関係に新たな時代を画した。オルダ・プライムホールを会場として使用し、宇宙規模の外交協議の場として機能した。以後、定期的な会合開催が計画されている。",descriptionEn:'A galaxy-scale diplomatic meeting held in E528 in the capital of Granbel, Oldacity, under the leadership of the Galactic Consortium. Five major speeches were delivered: President Arsen Carleen of Granbel\'s "Coexistence and Prosperity," Generalissimo Graymond Houser of Tiera\'s "Necessity of Military Power," Queen Liana Solis of Elesion\'s "Peace and Technology Sharing," Madris Carnel, representative of the Faluja Council, on "The Power of Culture," and Nathan Corind, Science Minister of Dioclenis, on "Avoiding the Hegemony Paradox and Joint Exploration." This meeting marked the beginning of substantive dialogue toward building a cosmic order and opened a new era in the relationship between the E16 civilization sphere and other cosmic civilization spheres. Using the Olda Prime Hall as its venue, it functioned as a diplomatic consultation forum on a cosmic scale. Regular meetings are planned to be held thereafter.'},{id:"hist-AURALIS第二世代の設立",name:"AURALIS Collective第二世代の設立",nameEn:"Establishment of AURALIS Collective 2nd Gen",category:"歴史",subCategory:"歴史・時代",description:"E522年にレイラ・ヴィレル・ノヴァの目覚めを契機として設立されたAURALIS Collectiveの第二世代。初代Kate Claudiaの「名」を継承したKate Patton、初代Lily Steinerの「名」を継承したLillie Ardentをはじめ、ミナ・エウレカ・エルンスト、ニニー・オッフェンバッハらが参加した。第二世代の設立は、E400年のエヴァトロン弾圧以来途絶えていたAURALISの理念の復活を象徴する出来事であり、テクノ文化ルネサンス期に育まれた新しい世代が「光と音を永遠にする」という理念を現代に甦らせた。第二世代は初代とは異なり、Offenbach種との協創や次元技術の芸術応用など、より開放的で多元的な活動を展開している。E522年の設立以降、AURALIS CollectiveはE16文明圏の文化振興と平和活動の中核組織として機能し続けている。",descriptionEn:'The second generation of AURALIS Collective, established in E522 with the awakening of Leila Virel Nova as its catalyst. Including Kate Patton, who inherited the "name" of the first-generation Kate Claudia, and Lillie Ardent, who inherited the "name" of the first-generation Lily Steiner, as well as Mina Eureka Ernst, Niny Offenbach, and others participated. The establishment of the second generation symbolized the revival of AURALIS\'s principles, which had been cut off since the Evatron suppression in E400, with the new generation nurtured during the Techno-Cultural Renaissance reviving the concept of "making light and sound eternal" in the modern era. Unlike the first generation, the second generation is developing more open and diverse activities, such as collaboration with the Offenbach species and artistic applications of dimensional technology. Since its establishment in E522, AURALIS Collective has continued to function as a core organization for cultural promotion and peace activities in the E16 civilization sphere.'},{id:"hist-シルバー・ヴェノムの台頭",name:"シルバー・ヴェノムの台頭",nameEn:"Rise of Silver Venom",category:"歴史",subCategory:"戦争・事件",description:"E475年のエヴァトロン崩壊後、Σ-Unitの残党から独立したマスター・ヴェノムによって設立された暗黒組織シルバー・ヴェノムの台頭期。シルバー・ヴェノムはZAMLTのシルバープラント遺構との歴史的関連を持ち、次元極地平技術を軍事転用した独自の兵器体系を構築した。E485年頃から活発化し、レオンやレヴィリア・サーペンティナらの幹部が組織の拡大を牽引した。シルバー・ヴェノムはクレセント地方で暗躍し、E510年にアイリスを捕囚するなどの大規模な犯罪活動を実行した。しかしE518年にイズミが後継として組織を引き継ぎ、アルファ・ヴェノムへの改編を行ったことで、シルバー・ヴェノムとしての活動は終息した。シルバー・ヴェノムの台頭はポスト・エヴァトロン秩序の脆弱性を露呈し、クレセント地方における暗黒組織問題の深刻さを浮き彫りにした。",descriptionEn:"The rise period of the dark organization Silver Venom, established by Master Venom, who broke away from the remnants of Σ-Unit after the collapse of Evatron in E475. Silver Venom has a historical connection to the Silver Plant ruins of ZAMLT and built its own weapon system by militarily applying dimensional horizon technology. It became active around E485, with executives such as Leon and Levilia Serpentina leading the organization's expansion. Silver Venom operated covertly in the Crescent region and carried out large-scale criminal activities such as imprisoning Iris in E510. However, in E518, Izumi succeeded the organization and reorganized it into Alpha Venom, ending Silver Venom's activities. The rise of Silver Venom exposed the vulnerability of the post-Evatron order and highlighted the seriousness of the dark organization problem in the Crescent region."},{id:"hist-アルファ・ヴェノムの台頭",name:"アルファ・ヴェノムの台頭",nameEn:"Rise of Alpha Venom",category:"歴史",subCategory:"戦争・事件",description:"E518年にイズミがシルバー・ヴェノム残党を吸収して設立した暗黒組織アルファ・ヴェノムの台頭期。イズミはシルバー・ヴェノムの組織を大幅に拡大・再編し、ボブリスティ、カタリナ、ギル、ゴルディロックス、AJらの幹部を擁する強力な組織に仕上げた。E519年にはイズミ自らの指揮でアイリスの再拉致を成功させ、V7内部への浸透工作ではフィオナを内通者として抱き込むことに成功した。アルファ・ヴェノムの台頭はクレセント地方の安全保障に深刻な脅威をもたらし、トリニティ・アライアンスとV7の対立をさらに激化させた。E523年からE525年にかけてフィオナの裏切りが発覚するまで、アルファ・ヴェノムはクレセント全域に影響力を拡大し続け、E16文明圏における最大の安全保障上の課題となっている。",descriptionEn:"The rise period of the dark organization Alpha Venom, established in E518 when Izumi absorbed the remnants of Silver Venom. Izumi significantly expanded and reorganized the Silver Venom organization, transforming it into a powerful organization with key executives including Bobristy, Catalina, Gil, Goldilocks, and AJ. In E519, under Izumi's direct command, they successfully recaptured Iris and succeeded in recruiting Fiona as an infiltrator within V7. Alpha Venom's rise posed a serious threat to the security of the Crescent region and further intensified the conflict between the Trinity Alliance and V7. From E523 to E525, until Fiona's betrayal was discovered, Alpha Venom continued to expand its influence throughout the Crescent region, becoming the most significant security challenge in the E16 civilization sphere."},{id:"hist-現代のE16連星系",name:"現代のE16連星系",nameEn:"Modern E16 Binary System",category:"歴史",subCategory:"歴史・時代",description:"E520年代以降の現代E16連星系は、銀河系コンソーシアムの設立、V7とトリニティ・アライアンスの二大陣営対立、アルファ・ヴェノムの暗躍という複雑な国際情勢下にある。Valoria連合圏の下でGigapolisは安定した都市運営を続け、テクノ文化ルネサンスの成果が市民生活に定着している。AURALIS Collective第二世代が文化振興の中核として活動し、惑星ビブリオやグランベルとの学術交流も活発化している。しかしクレセント地方ではフィオナの裏切り（E523〜E525年）によってV7内部に深刻な亀裂が生じており、アルファ・ヴェノムの脅威は未だ解消されていない。E16連星系は過去550年の激動の歴史から得た教訓を胸に、分散統治と国際協調のバランスを模索する新たな時代に突入している。過去の戦争と平和の循環が再び繰り返されるか、それとも新たな協力の枠組みが構築されるかが、現在進行中の歴史の核心的な問いである。",descriptionEn:"The modern E16 star system since the E520s exists under a complex international situation characterized by the establishment of the Galactic Consortium, the bipolar confrontation between V7 and the Trinity Alliance, and the covert activities of Alpha Venom. Under the Valoria Combined Zone, Gigapolis continues its stable urban governance, with the achievements of the Techno-Cultural Renaissance becoming integrated into citizens' daily lives. The second generation of the AURALIS Collective serves as the core of cultural promotion, and academic exchanges with the planets Biblio and Granbell have also become more active. However, in the Crescent region, Fiona's betrayal (E523-E525) created a serious rift within V7, and the threat of Alpha Venom remains unresolved. The E16 star system, carrying the lessons from its 550-year turbulent history, is entering a new era seeking balance between decentralized governance and international cooperation. Whether the cycle of past wars and peace will repeat itself, or whether a new framework of cooperation will be constructed, constitutes the central question of the ongoing history."}]],56914)}]);